insert into public.bible_verses (book_id, chapter, verse, text) values
  (42, 2, 27, 'Il vint au temple, poussé par l''Esprit. Et, comme les parents apportaient le petit enfant Jésus pour accomplir à son égard ce qu''ordonnait la loi,'),
  (42, 2, 28, 'il le reçut dans ses bras, bénit Dieu, et dit:'),
  (42, 2, 29, 'Maintenant, Seigneur, tu laisses ton serviteur S''en aller en paix, selon ta parole.'),
  (42, 2, 30, 'Car mes yeux ont vu ton salut,'),
  (42, 2, 31, 'Salut que tu as préparé devant tous les peuples,'),
  (42, 2, 32, 'Lumière pour éclairer les nations, Et gloire d''Israël, ton peuple.'),
  (42, 2, 33, 'Son père et sa mère étaient dans l''admiration des choses qu''on disait de lui.'),
  (42, 2, 34, 'Siméon les bénit, et dit à Marie, sa mère: Voici, cet enfant est destiné à amener la chute et le relèvement de plusieurs en Israël, et à devenir un signe qui provoquera la contradiction,'),
  (42, 2, 35, 'et à toi-même une épée te transpercera l''âme, afin que les pensées de beaucoup de cœurs soient dévoilées.'),
  (42, 2, 36, 'Il y avait aussi une prophétesse, Anne, fille de Phanuel, de la tribu d''Aser. Elle était fort avancée en âge, et elle avait vécu sept ans avec son mari depuis sa virginité.'),
  (42, 2, 37, 'Restée veuve, et âgée de quatre vingt-quatre ans, elle ne quittait pas le temple, et elle servait Dieu nuit et jour dans le jeûne et dans la prière.'),
  (42, 2, 38, 'Étant survenue, elle aussi, à cette même heure, elle louait Dieu, et elle parlait de Jésus à tous ceux qui attendaient la délivrance de Jérusalem.'),
  (42, 2, 39, 'Lorsqu''ils eurent accompli tout ce qu''ordonnait la loi du Seigneur, Joseph et Marie retournèrent en Galilée, à Nazareth, leur ville.'),
  (42, 2, 40, 'Or, l''enfant croissait et se fortifiait. Il était rempli de sagesse, et la grâce de Dieu était sur lui.'),
  (42, 2, 41, 'Les parents de Jésus allaient chaque année à Jérusalem, à la fête de Pâque.'),
  (42, 2, 42, 'Lorsqu''il fut âgé de douze ans, ils y montèrent, selon la coutume de la fête.'),
  (42, 2, 43, 'Puis, quand les jours furent écoulés, et qu''ils s''en retournèrent, l''enfant Jésus resta à Jérusalem. Son père et sa mère ne s''en aperçurent pas.'),
  (42, 2, 44, 'Croyant qu''il était avec leurs compagnons de voyage, ils firent une journée de chemin, et le cherchèrent parmi leurs parents et leurs connaissances.'),
  (42, 2, 45, 'Mais, ne l''ayant pas trouvé, ils retournèrent à Jérusalem pour le chercher.'),
  (42, 2, 46, 'Au bout de trois jours, ils le trouvèrent dans le temple, assis au milieu des docteurs, les écoutant et les interrogeant.'),
  (42, 2, 47, 'Tous ceux qui l''entendaient étaient frappés de son intelligence et de ses réponses.'),
  (42, 2, 48, 'Quand ses parents le virent, ils furent saisis d''étonnement, et sa mère lui dit: Mon enfant, pourquoi as-tu agi de la sorte avec nous? Voici, ton père et moi, nous te cherchions avec angoisse.'),
  (42, 2, 49, 'Il leur dit: Pourquoi me cherchiez-vous? Ne saviez-vous pas qu''il faut que je m''occupe des affaires de mon Père?'),
  (42, 2, 50, 'Mais ils ne comprirent pas ce qu''il leur disait.'),
  (42, 2, 51, 'Puis il descendit avec eux pour aller à Nazareth, et il leur était soumis. Sa mère gardait toutes ces choses dans son cœur.'),
  (42, 2, 52, 'Et Jésus croissait en sagesse, en stature, et en grâce, devant Dieu et devant les hommes.'),
  (42, 3, 1, 'La quinzième année du règne de Tibère César, -lorsque Ponce Pilate était gouverneur de la Judée, Hérode tétrarque de la Galilée, son frère Philippe tétrarque de l''Iturée et du territoire de la Trachonite, Lysanias tétrarque de l''Abilène,'),
  (42, 3, 2, 'et du temps des souverains sacrificateurs Anne et Caïphe, -la parole de Dieu fut adressée à Jean, fils de Zacharie, dans le désert.'),
  (42, 3, 3, 'Et il alla dans tout le pays des environs du Jourdain, prêchant le baptême de repentance, pour la rémission des péchés,'),
  (42, 3, 4, 'selon ce qui est écrit dans le livre des paroles d''Ésaïe, le prophète: C''est la voix de celui qui crie dans le désert: Préparez le chemin du Seigneur, Aplanissez ses sentiers.'),
  (42, 3, 5, 'Toute vallée sera comblée, Toute montagne et toute colline seront abaissées; Ce qui est tortueux sera redressé, Et les chemins raboteux seront aplanis.'),
  (42, 3, 6, 'Et toute chair verra le salut de Dieu.'),
  (42, 3, 7, 'Il disait donc à ceux qui venaient en foule pour être baptisés par lui: Races de vipères, qui vous a appris à fuir la colère à venir?'),
  (42, 3, 8, 'Produisez donc des fruits dignes de la repentance, et ne vous mettez pas à dire en vous-mêmes: Nous avons Abraham pour père! Car je vous déclare que de ces pierres Dieu peut susciter des enfants à Abraham.'),
  (42, 3, 9, 'Déjà même la cognée est mise à la racine des arbres: tout arbre donc qui ne produit pas de bons fruits sera coupé et jeté au feu.'),
  (42, 3, 10, 'La foule l''interrogeait, disant: Que devons-nous donc faire?'),
  (42, 3, 11, 'Il leur répondit: Que celui qui a deux tuniques partage avec celui qui n''en a point, et que celui qui a de quoi manger agisse de même.'),
  (42, 3, 12, 'Il vint aussi des publicains pour être baptisés, et ils lui dirent: Maître, que devons-nous faire?'),
  (42, 3, 13, 'Il leur répondit: N''exigez rien au delà de ce qui vous a été ordonné.'),
  (42, 3, 14, 'Des soldats aussi lui demandèrent: Et nous, que devons-nous faire? Il leur répondit: Ne commettez ni extorsion ni fraude envers personne, et contentez-vous de votre solde.'),
  (42, 3, 15, 'Comme le peuple était dans l''attente, et que tous se demandaient en eux-mêmes si Jean n''était pas le Christ,'),
  (42, 3, 16, 'il leur dit à tous: Moi, je vous baptise d''eau; mais il vient, celui qui est plus puissant que moi, et je ne suis pas digne de délier la courroie de ses souliers. Lui, il vous baptisera du Saint-Esprit et de feu.'),
  (42, 3, 17, 'Il a son van à la main; il nettoiera son aire, et il amassera le blé dans son grenier, mais il brûlera la paille dans un feu qui ne s''éteint point.'),
  (42, 3, 18, 'C''est ainsi que Jean annonçait la bonne nouvelle au peuple, en lui adressant encore beaucoup d''autres exhortations.'),
  (42, 3, 19, 'Mais Hérode le tétrarque, étant repris par Jean au sujet d''Hérodias, femme de son frère, et pour toutes les mauvaises actions qu''il avait commises,'),
  (42, 3, 20, 'ajouta encore à toutes les autres celle d''enfermer Jean dans la prison.'),
  (42, 3, 21, 'Tout le peuple se faisant baptiser, Jésus fut aussi baptisé; et, pendant qu''il priait, le ciel s''ouvrit,'),
  (42, 3, 22, 'et le Saint-Esprit descendit sur lui sous une forme corporelle, comme une colombe. Et une voix fit entendre du ciel ces paroles: Tu es mon Fils bien-aimé; en toi j''ai mis toute mon affection.'),
  (42, 3, 23, 'Jésus avait environ trente ans lorsqu''il commença son ministère, étant, comme on le croyait, fils de Joseph, fils d''Héli,'),
  (42, 3, 24, 'fils de Matthat, fils de Lévi, fils de Melchi, fils de Jannaï, fils de Joseph,'),
  (42, 3, 25, 'fils de Mattathias, fils d''Amos, fils de Nahum, fils d''Esli, fils de Naggaï,'),
  (42, 3, 26, 'fils de Maath, fils de Mattathias, fils de Sémeï, fils de Josech, fils de Joda,'),
  (42, 3, 27, 'fils de Joanan, fils de Rhésa, fils de Zorobabel, fils de Salathiel, fils de Néri,'),
  (42, 3, 28, 'fils de Melchi, fils d''Addi, fils de Kosam, fils d''Elmadam, fils D''Er,'),
  (42, 3, 29, 'fils de Jésus, fils d''Éliézer, fils de Jorim, fils de Matthat, fils de Lévi,'),
  (42, 3, 30, 'fils de Siméon, fils de Juda, fils de Joseph, fils de Jonam, fils d''Éliakim,'),
  (42, 3, 31, 'fils de Méléa, fils de Menna, fils de Mattatha, fils de Nathan, fils de David,'),
  (42, 3, 32, 'fils d''Isaï, fils de Jobed, fils de Booz, fils de Salmon, fils de Naasson,'),
  (42, 3, 33, 'fils d''Aminadab, fils d''Admin, fils d''Arni, fils d''Esrom, fils de Pharès, fils de Juda,'),
  (42, 3, 34, 'fils de Jacob, fils d''Isaac, fils d''Abraham, fils de Thara, fils de Nachor,'),
  (42, 3, 35, 'fils de Seruch, fils de Ragau, fils de Phalek, fils d''Éber, fils de Sala,'),
  (42, 3, 36, 'fils de Kaïnam, fils d''Arphaxad, fils de Sem, fils de Noé, fils de Lamech,'),
  (42, 3, 37, 'fils de Mathusala, fils d''Énoch, fils de Jared, fils de Maléléel, fils de Kaïnan,'),
  (42, 3, 38, 'fils d''Énos, fils de Seth, fils d''Adam, fils de Dieu.'),
  (42, 4, 1, 'Jésus, rempli du Saint-Esprit, revint du Jourdain, et il fut conduit par l''Esprit dans le désert,'),
  (42, 4, 2, 'où il fut tenté par le diable pendant quarante jours. Il ne mangea rien durant ces jours-là, et, après qu''ils furent écoulés, il eut faim.'),
  (42, 4, 3, 'Le diable lui dit: Si tu es Fils de Dieu, ordonne à cette pierre qu''elle devienne du pain.'),
  (42, 4, 4, 'Jésus lui répondit: Il est écrit: L''Homme ne vivra pas de pain seulement.'),
  (42, 4, 5, 'Le diable, l''ayant élevé, lui montra en un instant tous les royaumes de la terre,'),
  (42, 4, 6, 'et lui dit: Je te donnerai toute cette puissance, et la gloire de ces royaumes; car elle m''a été donnée, et je la donne à qui je veux.'),
  (42, 4, 7, 'Si donc tu te prosternes devant moi, elle sera toute à toi.'),
  (42, 4, 8, 'Jésus lui répondit: Il est écrit: Tu adoreras le Seigneur, ton Dieu, et tu le serviras lui seul.'),
  (42, 4, 9, 'Le diable le conduisit encore à Jérusalem, le plaça sur le haut du temple, et lui dit: Si tu es Fils de Dieu, jette-toi d''ici en bas;'),
  (42, 4, 10, 'car il est écrit: Il donnera des ordres à ses anges à ton sujet, Afin qu''ils te gardent;'),
  (42, 4, 11, 'et: Ils te porteront sur les mains, De peur que ton pied ne heurte contre une pierre.'),
  (42, 4, 12, 'Jésus lui répondit: Il est dit: Tu ne tenteras point le Seigneur, ton Dieu.'),
  (42, 4, 13, 'Après l''avoir tenté de toutes ces manières, le diable s''éloigna de lui jusqu''à un moment favorable.'),
  (42, 4, 14, 'Jésus, revêtu de la puissance de l''Esprit, retourna en Galilée, et sa renommée se répandit dans tout le pays d''alentour.'),
  (42, 4, 15, 'Il enseignait dans les synagogues, et il était glorifié par tous.'),
  (42, 4, 16, 'Il se rendit à Nazareth, où il avait été élevé, et, selon sa coutume, il entra dans la synagogue le jour du sabbat. Il se leva pour faire la lecture,'),
  (42, 4, 17, 'et on lui remit le livre du prophète Ésaïe. L''ayant déroulé, il trouva l''endroit où il était écrit:'),
  (42, 4, 18, 'L''Esprit du Seigneur est sur moi, Parce qu''il m''a oint pour annoncer une bonne nouvelle aux pauvres; Il m''a envoyé pour guérir ceux qui ont le cœur brisé, Pour proclamer aux captifs la délivrance, Et aux aveugles le recouvrement de la vue, Pour renvoyer libres les opprimés,'),
  (42, 4, 19, 'Pour publier une année de grâce du Seigneur.'),
  (42, 4, 20, 'Ensuite, il roula le livre, le remit au serviteur, et s''assit. Tous ceux qui se trouvaient dans la synagogue avaient les regards fixés sur lui.'),
  (42, 4, 21, 'Alors il commença à leur dire: Aujourd''hui cette parole de l''Écriture, que vous venez d''entendre, est accomplie.'),
  (42, 4, 22, 'Et tous lui rendaient témoignage; ils étaient étonnés des paroles de grâce qui sortaient de sa bouche, et ils disaient: N''est-ce pas le fils de Joseph?'),
  (42, 4, 23, 'Jésus leur dit: Sans doute vous m''appliquerez ce proverbe: Médecin, guéris-toi toi-même; et vous me direz: Fais ici, dans ta patrie, tout ce que nous avons appris que tu as fait à Capernaüm.'),
  (42, 4, 24, 'Mais, ajouta-t-il, je vous le dis en vérité, aucun prophète n''est bien reçu dans sa patrie.'),
  (42, 4, 25, 'Je vous le dis en vérité: il y avait plusieurs veuves en Israël du temps d''Élie, lorsque le ciel fut fermé trois ans et six mois et qu''il y eut une grande famine sur toute la terre;'),
  (42, 4, 26, 'et cependant Élie ne fut envoyé vers aucune d''elles, si ce n''est vers une femme veuve, à Sarepta, dans le pays de Sidon.'),
  (42, 4, 27, 'Il y avait aussi plusieurs lépreux en Israël du temps d''Élisée, le prophète; et cependant aucun d''eux ne fut purifié, si ce n''est Naaman le Syrien.'),
  (42, 4, 28, 'Ils furent tous remplis de colère dans la synagogue, lorsqu''ils entendirent ces choses.'),
  (42, 4, 29, 'Et s''étant levés, ils le chassèrent de la ville, et le menèrent jusqu''au sommet de la montagne sur laquelle leur ville était bâtie, afin de le précipiter en bas.'),
  (42, 4, 30, 'Mais Jésus, passant au milieu d''eux, s''en alla.'),
  (42, 4, 31, 'Il descendit à Capernaüm, ville de la Galilée; et il enseignait, le jour du sabbat.'),
  (42, 4, 32, 'On était frappé de sa doctrine; car il parlait avec autorité.'),
  (42, 4, 33, 'Il se trouva dans la synagogue un homme qui avait un esprit de démon impur, et qui s''écria d''une voix forte:'),
  (42, 4, 34, 'Ah! qu''y a-t-il entre nous et toi, Jésus de Nazareth? Tu es venu pour nous perdre. Je sais qui tu es: le Saint de Dieu.'),
  (42, 4, 35, 'Jésus le menaça, disant: Tais-toi, et sors de cet homme. Et le démon le jeta au milieu de l''assemblée, et sortit de lui, sans lui faire aucun mal.'),
  (42, 4, 36, 'Tous furent saisis de stupeur, et ils se disaient les uns aux autres: Quelle est cette parole? il commande avec autorité et puissance aux esprits impurs, et ils sortent!'),
  (42, 4, 37, 'Et sa renommée se répandit dans tous les lieux d''alentour.'),
  (42, 4, 38, 'En sortant de la synagogue, il se rendit à la maison de Simon. La belle-mère de Simon avait une violente fièvre, et ils le prièrent en sa faveur.'),
  (42, 4, 39, 'S''étant penché sur elle, il menaça la fièvre, et la fièvre la quitta. A l''instant elle se leva, et les servit.'),
  (42, 4, 40, 'Après le coucher du soleil, tous ceux qui avaient des malades atteints de diverses maladies les lui amenèrent. Il imposa les mains à chacun d''eux, et il les guérit.'),
  (42, 4, 41, 'Des démons aussi sortirent de beaucoup de personnes, en criant et en disant: Tu es le Fils de Dieu. Mais il les menaçait et ne leur permettait pas de parler, parce qu''ils savaient qu''il était le Christ.'),
  (42, 4, 42, 'Dès que le jour parut, il sortit et alla dans un lieu désert. Une foule de gens se mirent à sa recherche, et arrivèrent jusqu''à lui; ils voulaient le retenir, afin qu''il ne les quittât point.'),
  (42, 4, 43, 'Mais il leur dit: Il faut aussi que j''annonce aux autres villes la bonne nouvelle du royaume de Dieu; car c''est pour cela que j''ai été envoyé.'),
  (42, 4, 44, 'Et il prêchait dans les synagogues de la Galilée.'),
  (42, 5, 1, 'Comme Jésus se trouvait auprès du lac de Génésareth, et que la foule se pressait autour de lui pour entendre la parole de Dieu,'),
  (42, 5, 2, 'il vit au bord du lac deux barques, d''où les pêcheurs étaient descendus pour laver leurs filets.'),
  (42, 5, 3, 'Il monta dans l''une de ces barques, qui était à Simon, et il le pria de s''éloigner un peu de terre. Puis il s''assit, et de la barque il enseignait la foule.'),
  (42, 5, 4, 'Lorsqu''il eut cessé de parler, il dit à Simon: Avance en pleine eau, et jetez vos filets pour pêcher.'),
  (42, 5, 5, 'Simon lui répondit: Maître, nous avons travaillé toute la nuit sans rien prendre; mais, sur ta parole, je jetterai le filet.'),
  (42, 5, 6, 'L''ayant jeté, ils prirent une grande quantité de poissons, et leur filet se rompait.'),
  (42, 5, 7, 'Ils firent signe à leurs compagnons qui étaient dans l''autre barque de venir les aider. Ils vinrent et ils remplirent les deux barques, au point qu''elles enfonçaient.'),
  (42, 5, 8, 'Quand il vit cela, Simon Pierre tomba aux genoux de Jésus, et dit: Seigneur, retire-toi de moi, parce que je suis un homme pécheur.'),
  (42, 5, 9, 'Car l''épouvante l''avait saisi, lui et tous ceux qui étaient avec lui, à cause de la pêche qu''ils avaient faite.'),
  (42, 5, 10, 'Il en était de même de Jacques et de Jean, fils de Zébédée, les associés de Simon. Alors Jésus dit à Simon: Ne crains point; désormais tu seras pêcheur d''hommes.'),
  (42, 5, 11, 'Et, ayant ramené les barques à terre, ils laissèrent tout, et le suivirent.'),
  (42, 5, 12, 'Jésus était dans une des villes; et voici, un homme couvert de lèpre, l''ayant vu, tomba sur sa face, et lui fit cette prière: Seigneur, si tu le veux, tu peux me rendre pur.'),
  (42, 5, 13, 'Jésus étendit la main, le toucha, et dit: Je le veux, sois pur. Aussitôt la lèpre le quitta.'),
  (42, 5, 14, 'Puis il lui ordonna de n''en parler à personne. Mais, dit-il, va te montrer au sacrificateur, et offre pour ta purification ce que Moïse a prescrit, afin que cela leur serve de témoignage.'),
  (42, 5, 15, 'Sa renommée se répandait de plus en plus, et les gens venaient en foule pour l''entendre et pour être guéris de leurs maladies.'),
  (42, 5, 16, 'Et lui, il se retirait dans les déserts, et priait.'),
  (42, 5, 17, 'Un jour Jésus enseignait. Des pharisiens et des docteurs de la loi étaient là assis, venus de tous les villages de la Galilée, de la Judée et de Jérusalem; et la puissance du Seigneur se manifestait par des guérisons.'),
  (42, 5, 18, 'Et voici, des gens, portant sur un lit un homme qui était paralytique, cherchaient à le faire entrer et à le placer sous ses regards.'),
  (42, 5, 19, 'Comme ils ne savaient par où l''introduire, à cause de la foule, ils montèrent sur le toit, et ils le descendirent par une ouverture, avec son lit, au milieu de l''assemblée, devant Jésus.'),
  (42, 5, 20, 'Voyant leur foi, Jésus dit: Homme, tes péchés te sont pardonnés.'),
  (42, 5, 21, 'Les scribes et les pharisiens se mirent à raisonner et à dire: Qui est celui-ci, qui profère des blasphèmes? Qui peut pardonner les péchés, si ce n''est Dieu seul?'),
  (42, 5, 22, 'Jésus, connaissant leurs pensées, prit la parole et leur dit: Quelles pensées avez-vous dans vos cœurs?'),
  (42, 5, 23, 'Lequel est le plus aisé, de dire: Tes péchés te sont pardonnés, ou de dire: Lève-toi, et marche?'),
  (42, 5, 24, 'Or, afin que vous sachiez que le Fils de l''homme a sur la terre le pouvoir de pardonner les péchés: Je te l''ordonne, dit-il au paralytique, lève-toi, prends ton lit, et va dans ta maison.'),
  (42, 5, 25, 'Et, à l''instant, il se leva en leur présence, prit le lit sur lequel il était couché, et s''en alla dans sa maison, glorifiant Dieu.'),
  (42, 5, 26, 'Tous étaient dans l''étonnement, et glorifiaient Dieu; remplis de crainte, ils disaient: Nous avons vu aujourd''hui des choses étranges.'),
  (42, 5, 27, 'Après cela, Jésus sortit, et il vit un publicain, nommé Lévi, assis au lieu des péages. Il lui dit: Suis-moi.'),
  (42, 5, 28, 'Et, laissant tout, il se leva, et le suivit.'),
  (42, 5, 29, 'Lévi lui donna un grand festin dans sa maison, et beaucoup de publicains et d''autres personnes étaient à table avec eux.'),
  (42, 5, 30, 'Les pharisiens et les scribes murmurèrent, et dirent à ses disciples: Pourquoi mangez-vous et buvez-vous avec les publicains et les gens de mauvaise vie?'),
  (42, 5, 31, 'Jésus, prenant la parole, leur dit: Ce ne sont pas ceux qui se portent bien qui ont besoin de médecin, mais les malades.'),
  (42, 5, 32, 'Je ne suis pas venu appeler à la repentance des justes, mais des pécheurs.'),
  (42, 5, 33, 'Ils lui dirent: Les disciples de Jean, comme ceux des pharisiens, jeûnent fréquemment et font des prières, tandis que les tiens mangent et boivent.'),
  (42, 5, 34, 'Il leur répondit: Pouvez-vous faire jeûner les amis de l''époux pendant que l''époux est avec eux?'),
  (42, 5, 35, 'Les jours viendront où l''époux leur sera enlevé, alors ils jeûneront en ces jours-là.'),
  (42, 5, 36, 'Il leur dit aussi une parabole: Personne ne déchire d''un habit neuf un morceau pour le mettre à un vieil habit; car, il déchire l''habit neuf, et le morceau qu''il en a pris n''est pas assorti au vieux.'),
  (42, 5, 37, 'Et personne ne met du vin nouveau dans de vieilles outres; autrement, le vin nouveau fait rompre les outres, il se répand, et les outres sont perdues;'),
  (42, 5, 38, 'mais il faut mettre le vin nouveau dans des outres neuves.'),
  (42, 5, 39, 'Et personne, après avoir bu du vin vieux, ne veut du nouveau, car il dit: Le vieux est bon.'),
  (42, 6, 1, 'Il arriva, un jour de sabbat appelé second-premier, que Jésus traversait des champs de blé. Ses disciples arrachaient des épis et les mangeaient, après les avoir froissés dans leurs mains.'),
  (42, 6, 2, 'Quelques pharisiens leur dirent: Pourquoi faites-vous ce qu''il n''est pas permis de faire pendant le sabbat?'),
  (42, 6, 3, 'Jésus leur répondit: N''avez-vous pas lu ce que fit David, lorsqu''il eut faim, lui et ceux qui étaient avec lui;'),
  (42, 6, 4, 'comment il entra dans la maison de Dieu, prit les pains de proposition, en mangea, et en donna à ceux qui étaient avec lui, bien qu''il ne soit permis qu''aux sacrificateurs de les manger?'),
  (42, 6, 5, 'Et il leur dit: Le Fils de l''homme est maître même du sabbat.'),
  (42, 6, 6, 'Il arriva, un autre jour de sabbat, que Jésus entra dans la synagogue, et qu''il enseignait. Il s''y trouvait un homme dont la main droite était sèche.'),
  (42, 6, 7, 'Les scribes et les pharisiens observaient Jésus, pour voir s''il ferait une guérison le jour du sabbat: c''était afin d''avoir sujet de l''accuser.'),
  (42, 6, 8, 'Mais il connaissait leurs pensées, et il dit à l''homme qui avait la main sèche: Lève-toi, et tiens-toi là au milieu. Il se leva, et se tint debout.'),
  (42, 6, 9, 'Et Jésus leur dit: Je vous demande s''il est permis, le jour du sabbat, de faire du bien ou de faire du mal, de sauver une personne ou de la tuer.'),
  (42, 6, 10, 'Alors, promenant ses regards sur eux tous, il dit à l''homme: Étends ta main. Il le fit, et sa main fut guérie.'),
  (42, 6, 11, 'Ils furent remplis de fureur, et ils se consultèrent pour savoir ce qu''ils feraient à Jésus.'),
  (42, 6, 12, 'En ce temps-là, Jésus se rendit sur la montagne pour prier, et il passa toute la nuit à prier Dieu.'),
  (42, 6, 13, 'Quand le jour parut, il appela ses disciples, et il en choisit douze, auxquels il donna le nom d''apôtres:'),
  (42, 6, 14, 'Simon, qu''il nomma Pierre; André, son frère; Jacques; Jean; Philippe; Barthélemy;'),
  (42, 6, 15, 'Matthieu; Thomas; Jacques, fils d''Alphée; Simon, appelé le zélote;'),
  (42, 6, 16, 'Jude, fils de Jacques; et Judas Iscariot, qui devint traître.'),
  (42, 6, 17, 'Il descendit avec eux, et s''arrêta sur un plateau, où se trouvaient une foule de ses disciples et une multitude de peuple de toute la Judée, de Jérusalem, et de la contrée maritime de Tyr et de Sidon. Ils étaient venus pour l''entendre, et pour être guéris de leurs maladies.'),
  (42, 6, 18, 'Ceux qui étaient tourmentés par des esprits impurs étaient guéris.'),
  (42, 6, 19, 'Et toute la foule cherchait à le toucher, parce qu''une force sortait de lui et les guérissait tous.'),
  (42, 6, 20, 'Alors Jésus, levant les yeux sur ses disciples, dit: Heureux vous qui êtes pauvres, car le royaume de Dieu est à vous!'),
  (42, 6, 21, 'Heureux vous qui avez faim maintenant, car vous serez rassasiés! Heureux vous qui pleurez maintenant, car vous serez dans la joie!'),
  (42, 6, 22, 'Heureux serez-vous, lorsque les hommes vous haïront, lorsqu''on vous chassera, vous outragera, et qu''on rejettera votre nom comme infâme, à cause du Fils de l''homme!'),
  (42, 6, 23, 'Réjouissez-vous en ce jour-là et tressaillez d''allégresse, parce que votre récompense sera grande dans le ciel; car c''est ainsi que leurs pères traitaient les prophètes.'),
  (42, 6, 24, 'Mais, malheur à vous, riches, car vous avez votre consolation!'),
  (42, 6, 25, 'Malheur à vous qui êtes rassasiés, car vous aurez faim! Malheur à vous qui riez maintenant, car vous serez dans le deuil et dans les larmes!'),
  (42, 6, 26, 'Malheur, lorsque tous les hommes diront du bien de vous, car c''est ainsi qu''agissaient leurs pères à l''égard des faux prophètes!'),
  (42, 6, 27, 'Mais je vous dis, à vous qui m''écoutez: Aimez vos ennemis, faites du bien à ceux qui vous haïssent,'),
  (42, 6, 28, 'bénissez ceux qui vous maudissent, priez pour ceux qui vous maltraitent.'),
  (42, 6, 29, 'Si quelqu''un te frappe sur une joue, présente-lui aussi l''autre. Si quelqu''un prend ton manteau, ne l''empêche pas de prendre encore ta tunique.'),
  (42, 6, 30, 'Donne à quiconque te demande, et ne réclame pas ton bien à celui qui s''en empare.'),
  (42, 6, 31, 'Ce que vous voulez que les hommes fassent pour vous, faites-le de même pour eux.'),
  (42, 6, 32, 'Si vous aimez ceux qui vous aiment, quel gré vous en saura-t-on? Les pécheurs aussi aiment ceux qui les aiment.'),
  (42, 6, 33, 'Si vous faites du bien à ceux qui vous font du bien, quel gré vous en saura-t-on? Les pécheurs aussi agissent de même.'),
  (42, 6, 34, 'Et si vous prêtez à ceux de qui vous espérez recevoir, quel gré vous en saura-t-on? Les pécheurs aussi prêtent aux pécheurs, afin de recevoir la pareille.'),
  (42, 6, 35, 'Mais aimez vos ennemis, faites du bien, et prêtez sans rien espérer. Et votre récompense sera grande, et vous serez fils du Très-Haut, car il est bon pour les ingrats et pour les méchants.'),
  (42, 6, 36, 'Soyez donc miséricordieux, comme votre Père est miséricordieux.'),
  (42, 6, 37, 'Ne jugez point, et vous ne serez point jugés; ne condamnez point, et vous ne serez point condamnés; absolvez, et vous serez absous.'),
  (42, 6, 38, 'Donnez, et il vous sera donné: on versera dans votre sein une bonne mesure, serrée, secouée et qui déborde; car on vous mesurera avec la mesure dont vous vous serez servis.'),
  (42, 6, 39, 'Il leur dit aussi cette parabole: Un aveugle peut-il conduire un aveugle? Ne tomberont-ils pas tous deux dans une fosse?'),
  (42, 6, 40, 'Le disciple n''est pas plus que le maître; mais tout disciple accompli sera comme son maître.'),
  (42, 6, 41, 'Pourquoi vois-tu la paille qui est dans l''œil de ton frère, et n''aperçois-tu pas la poutre qui est dans ton œil?'),
  (42, 6, 42, 'Ou comment peux-tu dire à ton frère: Frère, laisse-moi ôter la paille qui est dans ton œil, toi qui ne vois pas la poutre qui est dans le tien? Hypocrite, ôte premièrement la poutre de ton œil, et alors tu verras comment ôter la paille qui est dans l''œil de ton frère.'),
  (42, 6, 43, 'Ce n''est pas un bon arbre qui porte du mauvais fruit, ni un mauvais arbre qui porte du bon fruit.'),
  (42, 6, 44, 'Car chaque arbre se connaît à son fruit. On ne cueille pas des figues sur des épines, et l''on ne vendange pas des raisins sur des ronces.'),
  (42, 6, 45, 'L''homme bon tire de bonnes choses du bon trésor de son cœur, et le méchant tire de mauvaises choses de son mauvais trésor; car c''est de l''abondance du cœur que la bouche parle.'),
  (42, 6, 46, 'Pourquoi m''appelez-vous Seigneur, Seigneur! et ne faites-vous pas ce que je dis?'),
  (42, 6, 47, 'Je vous montrerai à qui est semblable tout homme qui vient à moi, entend mes paroles, et les met en pratique.'),
  (42, 6, 48, 'Il est semblable à un homme qui, bâtissant une maison, a creusé, creusé profondément, et a posé le fondement sur le roc. Une inondation est venue, et le torrent s''est jeté contre cette maison, sans pouvoir l''ébranler, parce qu''elle était bien bâtie.'),
  (42, 6, 49, 'Mais celui qui entend, et ne met pas en pratique, est semblable à un homme qui a bâti une maison sur la terre, sans fondement. Le torrent s''est jeté contre elle: aussitôt elle est tombée, et la ruine de cette maison a été grande.'),
  (42, 7, 1, 'Après avoir achevé tous ces discours devant le peuple qui l''écoutait, Jésus entra dans Capernaüm.'),
  (42, 7, 2, 'Un centenier avait un serviteur auquel il était très attaché, et qui se trouvait malade, sur le point de mourir.'),
  (42, 7, 3, 'Ayant entendu parler de Jésus, il lui envoya quelques anciens des Juifs, pour le prier de venir guérir son serviteur.'),
  (42, 7, 4, 'Ils arrivèrent auprès de Jésus, et lui adressèrent d''instantes supplications, disant: Il mérite que tu lui accordes cela;'),
  (42, 7, 5, 'car il aime notre nation, et c''est lui qui a bâti notre synagogue.'),
  (42, 7, 6, 'Jésus, étant allé avec eux, n''était guère éloigné de la maison, quand le centenier envoya des amis pour lui dire: Seigneur, ne prends pas tant de peine; car je ne suis pas digne que tu entres sous mon toit.'),
  (42, 7, 7, 'C''est aussi pour cela que je ne me suis pas cru digne d''aller en personne vers toi. Mais dis un mot, et mon serviteur sera guéri.'),
  (42, 7, 8, 'Car, moi qui suis soumis à des supérieurs, j''ai des soldats sous mes ordres; et je dis à l''un: Va! et il va; à l''autre: Viens! et il vient; et à mon serviteur: Fais cela! et il le fait.'),
  (42, 7, 9, 'Lorsque Jésus entendit ces paroles, il admira le centenier, et, se tournant vers la foule qui le suivait, il dit: Je vous le dis, même en Israël je n''ai pas trouvé une aussi grande foi.'),
  (42, 7, 10, 'De retour à la maison, les gens envoyés par le centenier trouvèrent guéri le serviteur qui avait été malade.'),
  (42, 7, 11, 'Le jour suivant, Jésus alla dans une ville appelée Naïn; ses disciples et une grande foule faisaient route avec lui.'),
  (42, 7, 12, 'Lorsqu''il fut près de la porte de la ville, voici, on portait en terre un mort, fils unique de sa mère, qui était veuve; et il y avait avec elle beaucoup de gens de la ville.'),
  (42, 7, 13, 'Le Seigneur, l''ayant vue, fut ému de compassion pour elle, et lui dit: Ne pleure pas!'),
  (42, 7, 14, 'Il s''approcha, et toucha le cercueil. Ceux qui le portaient s''arrêtèrent. Il dit: Jeune homme, je te le dis, lève-toi!'),
  (42, 7, 15, 'Et le mort s''assit, et se mit à parler. Jésus le rendit à sa mère.'),
  (42, 7, 16, 'Tous furent saisis de crainte, et ils glorifiaient Dieu, disant: Un grand prophète a paru parmi nous, et Dieu a visité son peuple.'),
  (42, 7, 17, 'Cette parole sur Jésus se répandit dans toute la Judée et dans tout le pays d''alentour.'),
  (42, 7, 18, 'Jean fut informé de toutes ces choses par ses disciples.'),
  (42, 7, 19, 'Il en appela deux, et les envoya vers Jésus, pour lui dire: Es-tu celui qui doit venir, ou devons-nous en attendre un autre?'),
  (42, 7, 20, 'Arrivés auprès de Jésus, ils dirent: Jean-Baptiste nous a envoyés vers toi, pour dire: Es-tu celui qui doit venir, ou devons-nous en attendre un autre?'),
  (42, 7, 21, 'A l''heure même, Jésus guérit plusieurs personnes de maladies, d''infirmités, et d''esprits malins, et il rendit la vue à plusieurs aveugles.'),
  (42, 7, 22, 'Et il leur répondit: Allez rapporter à Jean ce que vous avez vu et entendu: les aveugles voient, les boiteux marchent, les lépreux sont purifiés, les sourds entendent, les morts ressuscitent, la bonne nouvelle est annoncée aux pauvres.'),
  (42, 7, 23, 'Heureux celui pour qui je ne serai pas une occasion de chute!'),
  (42, 7, 24, 'Lorsque les envoyés de Jean furent partis, Jésus se mit à dire à la foule, au sujet de Jean: Qu''êtes-vous allés voir au désert? un roseau agité par le vent?'),
  (42, 7, 25, 'Mais, qu''êtes-vous allés voir? un homme vêtu d''habits précieux? Voici, ceux qui portent des habits magnifiques, et qui vivent dans les délices, sont dans les maisons des rois.'),
  (42, 7, 26, 'Qu''êtes-vous donc allés voir? un prophète? Oui, vous dis-je, et plus qu''un prophète.'),
  (42, 7, 27, 'C''est celui dont il est écrit: Voici, j''envoie mon messager devant ta face, Pour préparer ton chemin devant toi.'),
  (42, 7, 28, 'Je vous le dis, parmi ceux qui sont nés de femmes, il n''y en a point de plus grand que Jean. Cependant, le plus petit dans le royaume de Dieu est plus grand que lui.'),
  (42, 7, 29, 'Et tout le peuple qui l''a entendu et même les publicains ont justifié Dieu, en se faisant baptiser du baptême de Jean;'),
  (42, 7, 30, 'mais les pharisiens et les docteurs de la loi, en ne se faisant pas baptiser par lui, ont rendu nul à leur égard le dessein de Dieu.'),
  (42, 7, 31, 'A qui donc comparerai-je les hommes de cette génération, et à qui ressemblent-ils?'),
  (42, 7, 32, 'Ils ressemblent aux enfants assis dans la place publique, et qui, se parlant les uns aux autres, disent: Nous vous avons joué de la flûte, et vous n''avez pas dansé; nous vous avons chanté des complaintes, et vous n''avez pas pleuré.'),
  (42, 7, 33, 'Car Jean-Baptiste est venu, ne mangeant pas de pain et ne buvant pas de vin, et vous dites: Il a un démon.'),
  (42, 7, 34, 'Le Fils de l''homme est venu, mangeant et buvant, et vous dites: C''est un mangeur et un buveur, un ami des publicains et des gens de mauvaise vie.'),
  (42, 7, 35, 'Mais la sagesse a été justifiée par tous ses enfants.'),
  (42, 7, 36, 'Un pharisien pria Jésus de manger avec lui. Jésus entra dans la maison du pharisien, et se mit à table.'),
  (42, 7, 37, 'Et voici, une femme pécheresse qui se trouvait dans la ville, ayant su qu''il était à table dans la maison du pharisien, apporta un vase d''albâtre plein de parfum,'),
  (42, 7, 38, 'et se tint derrière, aux pieds de Jésus. Elle pleurait; et bientôt elle lui mouilla les pieds de ses larmes, puis les essuya avec ses cheveux, les baisa, et les oignit de parfum.'),
  (42, 7, 39, 'Le pharisien qui l''avait invité, voyant cela, dit en lui-même: Si cet homme était prophète, il connaîtrait qui et de quelle espèce est la femme qui le touche, il connaîtrait que c''est une pécheresse.'),
  (42, 7, 40, 'Jésus prit la parole, et lui dit: Simon, j''ai quelque chose à te dire. - Maître, parle, répondit-il. -'),
  (42, 7, 41, 'Un créancier avait deux débiteurs: l''un devait cinq cents deniers, et l''autre cinquante.'),
  (42, 7, 42, 'Comme ils n''avaient pas de quoi payer, il leur remit à tous deux leur dette. Lequel l''aimera le plus?'),
  (42, 7, 43, 'Simon répondit: Celui, je pense, auquel il a le plus remis. Jésus lui dit: Tu as bien jugé.'),
  (42, 7, 44, 'Puis, se tournant vers la femme, il dit à Simon: Vois-tu cette femme? Je suis entré dans ta maison, et tu ne m''as point donné d''eau pour laver mes pieds; mais elle, elle les a mouillés de ses larmes, et les a essuyés avec ses cheveux.'),
  (42, 7, 45, 'Tu ne m''as point donné de baiser; mais elle, depuis que je suis entré, elle n''a point cessé de me baiser les pieds.'),
  (42, 7, 46, 'Tu n''as point versé d''huile sur ma tête; mais elle, elle a versé du parfum sur mes pieds.'),
  (42, 7, 47, 'C''est pourquoi, je te le dis, ses nombreux péchés ont été pardonnés: car elle a beaucoup aimé. Mais celui à qui on pardonne peu aime peu.'),
  (42, 7, 48, 'Et il dit à la femme: Tes péchés sont pardonnés.'),
  (42, 7, 49, 'Ceux qui étaient à table avec lui se mirent à dire en eux-mêmes: Qui est celui-ci, qui pardonne même les péchés?'),
  (42, 7, 50, 'Mais Jésus dit à la femme: Ta foi t''a sauvée, va en paix.'),
  (42, 8, 1, 'Ensuite, Jésus allait de ville en ville et de village en village, prêchant et annonçant la bonne nouvelle du royaume de Dieu.'),
  (42, 8, 2, 'Les douze étaient avec lui et quelques femmes qui avaient été guéries d''esprits malins et de maladies: Marie, dite de Magdala, de laquelle étaient sortis sept démons,'),
  (42, 8, 3, 'Jeanne, femme de Chuza, intendant d''Hérode, Susanne, et plusieurs autres, qui l''assistaient de leurs biens.'),
  (42, 8, 4, 'Une grande foule s''étant assemblée, et des gens étant venus de diverses villes auprès de lui, il dit cette parabole:'),
  (42, 8, 5, 'Un semeur sortit pour semer sa semence. Comme il semait, une partie de la semence tomba le long du chemin: elle fut foulée aux pieds, et les oiseaux du ciel la mangèrent.'),
  (42, 8, 6, 'Une autre partie tomba sur le roc: quand elle fut levée, elle sécha, parce qu''elle n''avait point d''humidité.'),
  (42, 8, 7, 'Une autre partie tomba au milieu des épines: les épines crûrent avec elle, et l''étouffèrent.'),
  (42, 8, 8, 'Une autre partie tomba dans la bonne terre: quand elle fut levée, elle donna du fruit au centuple. Après avoir ainsi parlé, Jésus dit à haute voix: Que celui qui a des oreilles pour entendre entende!'),
  (42, 8, 9, 'Ses disciples lui demandèrent ce que signifiait cette parabole.'),
  (42, 8, 10, 'Il répondit: Il vous a été donné de connaître les mystères du royaume de Dieu; mais pour les autres, cela leur est dit en paraboles, afin qu''en voyant ils ne voient point, et qu''en entendant ils ne comprennent point.'),
  (42, 8, 11, 'Voici ce que signifie cette parabole: La semence, c''est la parole de Dieu.'),
  (42, 8, 12, 'Ceux qui sont le long du chemin, ce sont ceux qui entendent; puis le diable vient, et enlève de leur cœur la parole, de peur qu''ils ne croient et soient sauvés.'),
  (42, 8, 13, 'Ceux qui sont sur le roc, ce sont ceux qui, lorsqu''ils entendent la parole, la reçoivent avec joie; mais ils n''ont point de racine, ils croient pour un temps, et ils succombent au moment de la tentation.'),
  (42, 8, 14, 'Ce qui est tombé parmi les épines, ce sont ceux qui, ayant entendu la parole, s''en vont, et la laissent étouffer par les soucis, les richesses et les plaisirs de la vie, et ils ne portent point de fruit qui vienne à maturité.'),
  (42, 8, 15, 'Ce qui est tombé dans la bonne terre, ce sont ceux qui, ayant entendu la parole avec un cœur honnête et bon, la retiennent, et portent du fruit avec persévérance.'),
  (42, 8, 16, 'Personne, après avoir allumé une lampe, ne la couvre d''un vase, ou ne la met sous un lit; mais il la met sur un chandelier, afin que ceux qui entrent voient la lumière.'),
  (42, 8, 17, 'Car il n''est rien de caché qui ne doive être découvert, rien de secret qui ne doive être connu et mis au jour.'),
  (42, 8, 18, 'Prenez donc garde à la manière dont vous écoutez; car on donnera à celui qui a, mais à celui qui n''a pas on ôtera même ce qu''il croit avoir.'),
  (42, 8, 19, 'La mère et les frères de Jésus vinrent le trouver; mais ils ne purent l''aborder, à cause de la foule.'),
  (42, 8, 20, 'On lui dit: Ta mère et tes frères sont dehors, et ils désirent te voir.'),
  (42, 8, 21, 'Mais il répondit: Ma mère et mes frères, ce sont ceux qui écoutent la parole de Dieu, et qui la mettent en pratique.'),
  (42, 8, 22, 'Un jour, Jésus monta dans une barque avec ses disciples. Il leur dit: Passons de l''autre côté du lac. Et ils partirent.'),
  (42, 8, 23, 'Pendant qu''ils naviguaient, Jésus s''endormit. Un tourbillon fondit sur le lac, la barque se remplissait d''eau, et ils étaient en péril.'),
  (42, 8, 24, 'Ils s''approchèrent et le réveillèrent, en disant: Maître, maître, nous périssons! S''étant réveillé, il menaça le vent et les flots, qui s''apaisèrent, et le calme revint.'),
  (42, 8, 25, 'Puis il leur dit: Où est votre foi? Saisis de frayeur et d''étonnement, ils se dirent les uns aux autres: Quel est donc celui-ci, qui commande même au vent et à l''eau, et à qui ils obéissent?'),
  (42, 8, 26, 'Ils abordèrent dans le pays des Géraséniens, qui est vis-à-vis de la Galilée.'),
  (42, 8, 27, 'Lorsque Jésus fut descendu à terre, il vint au-devant de lui un homme de la ville, qui était possédé de plusieurs démons. Depuis longtemps il ne portait point de vêtement, et avait sa demeure non dans une maison, mais dans les sépulcres.'),
  (42, 8, 28, 'Ayant vu Jésus, il poussa un cri, se jeta à ses pieds, et dit d''une voix forte: Qu''y a-t-il entre moi et toi, Jésus, Fils du Dieu Très-Haut? Je t''en supplie, ne me tourmente pas.'),
  (42, 8, 29, 'Car Jésus commandait à l''esprit impur de sortir de cet homme, dont il s''était emparé depuis longtemps; on le gardait lié de chaînes et les fers aux pieds, mais il rompait les liens, et il était entraîné par le démon dans les déserts.'),
  (42, 8, 30, 'Jésus lui demanda: Quel est ton nom? Légion, répondit-il. Car plusieurs démons étaient entrés en lui.'),
  (42, 8, 31, 'Et ils priaient instamment Jésus de ne pas leur ordonner d''aller dans l''abîme.'),
  (42, 8, 32, 'Il y avait là, dans la montagne, un grand troupeau de pourceaux qui paissaient. Et les démons supplièrent Jésus de leur permettre d''entrer dans ces pourceaux. Il le leur permit.'),
  (42, 8, 33, 'Les démons sortirent de cet homme, entrèrent dans les pourceaux, et le troupeau se précipita des pentes escarpées dans le lac, et se noya.'),
  (42, 8, 34, 'Ceux qui les faisaient paître, voyant ce qui était arrivé, s''enfuirent, et répandirent la nouvelle dans la ville et dans les campagnes.'),
  (42, 8, 35, 'Les gens allèrent voir ce qui était arrivé. Ils vinrent auprès de Jésus, et ils trouvèrent l''homme de qui étaient sortis les démons, assis à ses pieds, vêtu, et dans son bon sens; et ils furent saisis de frayeur.'),
  (42, 8, 36, 'Ceux qui avaient vu ce qui s''était passé leur racontèrent comment le démoniaque avait été guéri.'),
  (42, 8, 37, 'Tous les habitants du pays des Géraséniens prièrent Jésus de s''éloigner d''eux, car ils étaient saisis d''une grande crainte. Jésus monta dans la barque, et s''en retourna.'),
  (42, 8, 38, 'L''homme de qui étaient sortis les démons lui demandait la permission de rester avec lui. Mais Jésus le renvoya, en disant:'),
  (42, 8, 39, 'Retourne dans ta maison, et raconte tout ce que Dieu t''a fait. Il s''en alla, et publia par toute la ville tout ce que Jésus avait fait pour lui.'),
  (42, 8, 40, 'A son retour, Jésus fut reçu par la foule, car tous l''attendaient.'),
  (42, 8, 41, 'Et voici, il vint un homme, nommé Jaïrus, qui était chef de la synagogue. Il se jeta à ses pieds, et le supplia d''entrer dans sa maison,'),
  (42, 8, 42, 'parce qu''il avait une fille unique d''environ douze ans qui se mourait. Pendant que Jésus y allait, il était pressé par la foule.'),
  (42, 8, 43, 'Or, il y avait une femme atteinte d''une perte de sang depuis douze ans, et qui avait dépensé tout son bien pour les médecins, sans qu''aucun ait pu la guérir.'),
  (42, 8, 44, 'Elle s''approcha par derrière, et toucha le bord du vêtement de Jésus. Au même instant la perte de sang s''arrêta.'),
  (42, 8, 45, 'Et Jésus dit: Qui m''a touché? Comme tous s''en défendaient, Pierre et ceux qui étaient avec lui dirent: Maître, la foule t''entoure et te presse, et tu dis: Qui m''a touché?'),
  (42, 8, 46, 'Mais Jésus répondit: Quelqu''un m''a touché, car j''ai connu qu''une force était sortie de moi.'),
  (42, 8, 47, 'La femme, se voyant découverte, vint toute tremblante se jeter à ses pieds, et déclara devant tout le peuple pourquoi elle l''avait touché, et comment elle avait été guérie à l''instant.'),
  (42, 8, 48, 'Jésus lui dit: Ma fille, ta foi t''a sauvée; va en paix.'),
  (42, 8, 49, 'Comme il parlait encore, survint de chez le chef de la synagogue quelqu''un disant: Ta fille est morte; n''importune pas le maître.'),
  (42, 8, 50, 'Mais Jésus, ayant entendu cela, dit au chef de la synagogue: Ne crains pas, crois seulement, et elle sera sauvée.'),
  (42, 8, 51, 'Lorsqu''il fut arrivé à la maison, il ne permit à personne d''entrer avec lui, si ce n''est à Pierre, à Jean et à Jacques, et au père et à la mère de l''enfant.'),
  (42, 8, 52, 'Tous pleuraient et se lamentaient sur elle. Alors Jésus dit: Ne pleurez pas; elle n''est pas morte, mais elle dort.'),
  (42, 8, 53, 'Et ils se moquaient de lui, sachant qu''elle était morte.'),
  (42, 8, 54, 'Mais il la saisit par la main, et dit d''une voix forte: Enfant, lève-toi.'),
  (42, 8, 55, 'Et son esprit revint en elle, et à l''instant elle se leva; et Jésus ordonna qu''on lui donnât à manger.'),
  (42, 8, 56, 'Les parents de la jeune fille furent dans l''étonnement, et il leur recommanda de ne dire à personne ce qui était arrivé.'),
  (42, 9, 1, 'Jésus, ayant assemblé les douze, leur donna force et pouvoir sur tous les démons, avec la puissance de guérir les maladies.'),
  (42, 9, 2, 'Il les envoya prêcher le royaume de Dieu, et guérir les malades.'),
  (42, 9, 3, 'Ne prenez rien pour le voyage, leur dit-il, ni bâton, ni sac, ni pain, ni argent, et n''ayez pas deux tuniques.'),
  (42, 9, 4, 'Dans quelque maison que vous entriez, restez-y; et c''est de là que vous partirez.'),
  (42, 9, 5, 'Et, si les gens ne vous reçoivent pas, sortez de cette ville, et secouez la poussière de vos pieds, en témoignage contre eux.'),
  (42, 9, 6, 'Ils partirent, et ils allèrent de village en village, annonçant la bonne nouvelle et opérant partout des guérisons.'),
  (42, 9, 7, 'Hérode le tétrarque entendit parler de tout ce qui se passait, et il ne savait que penser. Car les uns disaient que Jean était ressuscité des morts;'),
  (42, 9, 8, 'd''autres, qu''Élie était apparu; et d''autres, qu''un des anciens prophètes était ressuscité.'),
  (42, 9, 9, 'Mais Hérode disait: J''ai fait décapiter Jean; qui donc est celui-ci, dont j''entends dire de telles choses? Et il cherchait à le voir.'),
  (42, 9, 10, 'Les apôtres, étant de retour, racontèrent à Jésus tout ce qu''ils avaient fait. Il les prit avec lui, et se retira à l''écart, du côté d''une ville appelée Bethsaïda.'),
  (42, 9, 11, 'Les foules, l''ayant su, le suivirent. Jésus les accueillit, et il leur parlait du royaume de Dieu; il guérit aussi ceux qui avaient besoin d''être guéris.'),
  (42, 9, 12, 'Comme le jour commençait à baisser, les douze s''approchèrent, et lui dirent: Renvoie la foule, afin qu''elle aille dans les villages et dans les campagnes des environs, pour se loger et pour trouver des vivres; car nous sommes ici dans un lieu désert.'),
  (42, 9, 13, 'Jésus leur dit: Donnez-leur vous-mêmes à manger. Mais ils répondirent: Nous n''avons que cinq pains et deux poissons, à moins que nous n''allions nous-mêmes acheter des vivres pour tout ce peuple.'),
  (42, 9, 14, 'Or, il y avait environ cinq mille hommes. Jésus dit à ses disciples: Faites-les asseoir par rangées de cinquante.'),
  (42, 9, 15, 'Ils firent ainsi, ils les firent tous asseoir.'),
  (42, 9, 16, 'Jésus prit les cinq pains et les deux poissons, et, levant les yeux vers le ciel, il les bénit. Puis, il les rompit, et les donna aux disciples, afin qu''ils les distribuassent à la foule.'),
  (42, 9, 17, 'Tous mangèrent et furent rassasiés, et l''on emporta douze paniers pleins des morceaux qui restaient.'),
  (42, 9, 18, 'Un jour que Jésus priait à l''écart, ayant avec lui ses disciples, il leur posa cette question: Qui dit-on que je suis?'),
  (42, 9, 19, 'Ils répondirent: Jean-Baptiste; les autres, Élie; les autres, qu''un des anciens prophètes est ressuscité.'),
  (42, 9, 20, 'Et vous, leur demanda-t-il, qui dites-vous que je suis? Pierre répondit: Le Christ de Dieu.'),
  (42, 9, 21, 'Jésus leur recommanda sévèrement de ne le dire à personne.'),
  (42, 9, 22, 'Il ajouta qu''il fallait que le Fils de l''homme souffrît beaucoup, qu''il fût rejeté par les anciens, par les principaux sacrificateurs et par les scribes, qu''il fût mis à mort, et qu''il ressuscitât le troisième jour.'),
  (42, 9, 23, 'Puis il dit à tous: Si quelqu''un veut venir après moi, qu''il renonce à lui-même, qu''il se charge chaque jour de sa croix, et qu''il me suive.'),
  (42, 9, 24, 'Car celui qui voudra sauver sa vie la perdra, mais celui qui la perdra à cause de moi la sauvera.'),
  (42, 9, 25, 'Et que servirait-il à un homme de gagner tout le monde, s''il se détruisait ou se perdait lui-même?'),
  (42, 9, 26, 'Car quiconque aura honte de moi et de mes paroles, le Fils de l''homme aura honte de lui, quand il viendra dans sa gloire, et dans celle du Père et des saints anges.'),
  (42, 9, 27, 'Je vous le dis en vérité, quelques-uns de ceux qui sont ici ne mourront point qu''ils n''aient vu le royaume de Dieu.'),
  (42, 9, 28, 'Environ huit jours après qu''il eut dit ces paroles, Jésus prit avec lui Pierre, Jean et Jacques, et il monta sur la montagne pour prier.'),
  (42, 9, 29, 'Pendant qu''il priait, l''aspect de son visage changea, et son vêtement devint d''une éclatante blancheur.'),
  (42, 9, 30, 'Et voici, deux hommes s''entretenaient avec lui: c''étaient Moïse et Élie,'),
  (42, 9, 31, 'qui, apparaissant dans la gloire, parlaient de son départ qu''il allait accomplir à Jérusalem.'),
  (42, 9, 32, 'Pierre et ses compagnons étaient appesantis par le sommeil; mais, s''étant tenus éveillés, ils virent la gloire de Jésus et les deux hommes qui étaient avec lui.'),
  (42, 9, 33, 'Au moment où ces hommes se séparaient de Jésus, Pierre lui dit: Maître, il est bon que nous soyons ici; dressons trois tentes, une pour toi, une pour Moïse, et une pour Élie. Il ne savait ce qu''il disait.'),
  (42, 9, 34, 'Comme il parlait ainsi, une nuée vint les couvrir; et les disciples furent saisis de frayeur en les voyant entrer dans la nuée.'),
  (42, 9, 35, 'Et de la nuée sortit une voix, qui dit: Celui-ci est mon Fils élu: écoutez-le!'),
  (42, 9, 36, 'Quand la voix se fit entendre, Jésus se trouva seul. Les disciples gardèrent le silence, et ils ne racontèrent à personne, en ce temps-là, rien de ce qu''ils avaient vu.'),
  (42, 9, 37, 'Le lendemain, lorsqu''ils furent descendus de la montagne, une grande foule vint au-devant de Jésus.'),
  (42, 9, 38, 'Et voici, du milieu de la foule un homme s''écria: Maître, je t''en prie, porte les regards sur mon fils, car c''est mon fils unique.'),
  (42, 9, 39, 'Un esprit le saisit, et aussitôt il pousse des cris; et l''esprit l''agite avec violence, le fait écumer, et a de la peine à se retirer de lui, après l''avoir tout brisé.'),
  (42, 9, 40, 'J''ai prié tes disciples de le chasser, et ils n''ont pas pu.'),
  (42, 9, 41, 'Race incrédule et perverse, répondit Jésus, jusqu''à quand serai-je avec vous, et vous supporterai-je? Amène ici ton fils.'),
  (42, 9, 42, 'Comme il approchait, le démon le jeta par terre, et l''agita avec violence. Mais Jésus menaça l''esprit impur, guérit l''enfant, et le rendit à son père.'),
  (42, 9, 43, 'Et tous furent frappés de la grandeur de Dieu. Tandis que chacun était dans l''admiration de tout ce que faisait Jésus, il dit à ses disciples:'),
  (42, 9, 44, 'Pour vous, écoutez bien ceci: Le Fils de l''homme doit être livré entre les mains des hommes.'),
  (42, 9, 45, 'Mais les disciples ne comprenaient pas cette parole; elle était voilée pour eux, afin qu''ils n''en eussent pas le sens; et ils craignaient de l''interroger à ce sujet.'),
  (42, 9, 46, 'Or, une pensée leur vint à l''esprit, savoir lequel d''entre eux était le plus grand.'),
  (42, 9, 47, 'Jésus, voyant la pensée de leur cœur, prit un petit enfant, le plaça près de lui,'),
  (42, 9, 48, 'et leur dit: Quiconque reçoit en mon nom ce petit enfant me reçoit moi-même; et quiconque me reçoit reçoit celui qui m''a envoyé. Car celui qui est le plus petit parmi vous tous, c''est celui-là qui est grand.'),
  (42, 9, 49, 'Jean prit la parole, et dit: Maître, nous avons vu un homme qui chasse des démons en ton nom; et nous l''en avons empêché, parce qu''il ne nous suit pas.'),
  (42, 9, 50, 'Ne l''en empêchez pas, lui répondit Jésus; car qui n''est pas contre vous est pour vous.'),
  (42, 9, 51, 'Lorsque le temps où il devait être enlevé du monde approcha, Jésus prit la résolution de se rendre à Jérusalem.'),
  (42, 9, 52, 'Il envoya devant lui des messagers, qui se mirent en route et entrèrent dans un bourg des Samaritains, pour lui préparer un logement.'),
  (42, 9, 53, 'Mais on ne le reçut pas, parce qu''il se dirigeait sur Jérusalem.'),
  (42, 9, 54, 'Les disciples Jacques et Jean, voyant cela, dirent: Seigneur, veux-tu que nous commandions que le feu descende du ciel et les consume?'),
  (42, 9, 55, 'Jésus se tourna vers eux, et les réprimanda, disant: Vous ne savez de quel esprit vous êtes animés.'),
  (42, 9, 56, 'Car le Fils de l''homme est venu, non pour perdre les âmes des hommes, mais pour les sauver. Et ils allèrent dans un autre bourg.'),
  (42, 9, 57, 'Pendant qu''ils étaient en chemin, un homme lui dit: Seigneur, je te suivrai partout où tu iras.'),
  (42, 9, 58, 'Jésus lui répondit: Les renards ont des tanières, et les oiseaux du ciel ont des nids: mais le Fils de l''homme n''a pas un lieu où il puisse reposer sa tête.'),
  (42, 9, 59, 'Il dit à un autre: Suis-moi. Et il répondit: Seigneur, permets-moi d''aller d''abord ensevelir mon père.'),
  (42, 9, 60, 'Mais Jésus lui dit: Laisse les morts ensevelir leurs morts; et toi, va annoncer le royaume de Dieu.'),
  (42, 9, 61, 'Un autre dit: Je te suivrai, Seigneur, mais permets-moi d''aller d''abord prendre congé de ceux de ma maison.'),
  (42, 9, 62, 'Jésus lui répondit: Quiconque met la main à la charrue, et regarde en arrière, n''est pas propre au royaume de Dieu.'),
  (42, 10, 1, 'Après cela, le Seigneur désigna encore soixante-dix autres disciples, et il les envoya deux à deux devant lui dans toutes les villes et dans tous les lieux où lui-même devait aller.'),
  (42, 10, 2, 'Il leur dit: La moisson est grande, mais il y a peu d''ouvriers. Priez donc le maître de la moisson d''envoyer des ouvriers dans sa moisson.'),
  (42, 10, 3, 'Partez; voici, je vous envoie comme des agneaux au milieu des loups.'),
  (42, 10, 4, 'Ne portez ni bourse, ni sac, ni souliers, et ne saluez personne en chemin.'),
  (42, 10, 5, 'Dans quelque maison que vous entriez, dites d''abord: Que la paix soit sur cette maison!'),
  (42, 10, 6, 'Et s''il se trouve là un enfant de paix, votre paix reposera sur lui; sinon, elle reviendra à vous.'),
  (42, 10, 7, 'Demeurez dans cette maison-là, mangeant et buvant ce qu''on vous donnera; car l''ouvrier mérite son salaire. N''allez pas de maison en maison.'),
  (42, 10, 8, 'Dans quelque ville que vous entriez, et où l''on vous recevra, mangez ce qui vous sera présenté,'),
  (42, 10, 9, 'guérissez les malades qui s''y trouveront, et dites-leur: Le royaume de Dieu s''est approché de vous.'),
  (42, 10, 10, 'Mais dans quelque ville que vous entriez, et où l''on ne vous recevra pas, allez dans ses rues, et dites:'),
  (42, 10, 11, 'Nous secouons contre vous la poussière même de votre ville qui s''est attachée à nos pieds; sachez cependant que le royaume de Dieu s''est approché.'),
  (42, 10, 12, 'Je vous dis qu''en ce jour Sodome sera traitée moins rigoureusement que cette ville-là.'),
  (42, 10, 13, 'Malheur à toi, Chorazin! malheur à toi, Bethsaïda! car, si les miracles qui ont été faits au milieu de vous avaient été faits dans Tyr et dans Sidon, il y a longtemps qu''elles se seraient repenties, en prenant le sac et la cendre.'),
  (42, 10, 14, 'C''est pourquoi, au jour du jugement, Tyr et Sidon seront traitées moins rigoureusement que vous.'),
  (42, 10, 15, 'Et toi, Capernaüm, qui as été élevée jusqu''au ciel, tu seras abaissée jusqu''au séjour des morts.'),
  (42, 10, 16, 'Celui qui vous écoute m''écoute, et celui qui vous rejette me rejette; et celui qui me rejette rejette celui qui m''a envoyé.'),
  (42, 10, 17, 'Les soixante-dix revinrent avec joie, disant: Seigneur, les démons mêmes nous sont soumis en ton nom.'),
  (42, 10, 18, 'Jésus leur dit: Je voyais Satan tomber du ciel comme un éclair.'),
  (42, 10, 19, 'Voici, je vous ai donné le pouvoir de marcher sur les serpents et les scorpions, et sur toute la puissance de l''ennemi; et rien ne pourra vous nuire.'),
  (42, 10, 20, 'Cependant, ne vous réjouissez pas de ce que les esprits vous sont soumis; mais réjouissez-vous de ce que vos noms sont écrits dans les cieux.'),
  (42, 10, 21, 'En ce moment même, Jésus tressaillit de joie par le Saint-Esprit, et il dit: Je te loue, Père, Seigneur du ciel et de la terre, de ce que tu as caché ces choses aux sages et aux intelligents, et de ce que tu les as révélées aux enfants. Oui, Père, je te loue de ce que tu l''as voulu ainsi.'),
  (42, 10, 22, 'Toutes choses m''ont été données par mon Père, et personne ne connaît qui est le Fils, si ce n''est le Père, ni qui est le Père, si ce n''est le Fils et celui à qui le Fils veut le révéler.'),
  (42, 10, 23, 'Et, se tournant vers les disciples, il leur dit en particulier: Heureux les yeux qui voient ce que vous voyez!'),
  (42, 10, 24, 'Car je vous dis que beaucoup de prophètes et de rois ont désiré voir ce que vous voyez, et ne l''ont pas vu, entendre ce que vous entendez, et ne l''ont pas entendu.'),
  (42, 10, 25, 'Un docteur de la loi se leva, et dit à Jésus, pour l''éprouver: Maître, que dois-je faire pour hériter la vie éternelle?'),
  (42, 10, 26, 'Jésus lui dit: Qu''est-il écrit dans la loi? Qu''y lis-tu?'),
  (42, 10, 27, 'Il répondit: Tu aimeras le Seigneur, ton Dieu, de tout ton cœur, de toute ton âme, de toute ta force, et de toute ta pensée; et ton prochain comme toi-même.'),
  (42, 10, 28, 'Tu as bien répondu, lui dit Jésus; fais cela, et tu vivras.'),
  (42, 10, 29, 'Mais lui, voulant se justifier, dit à Jésus: Et qui est mon prochain?'),
  (42, 10, 30, 'Jésus reprit la parole, et dit: Un homme descendait de Jérusalem à Jéricho. Il tomba au milieu des brigands, qui le dépouillèrent, le chargèrent de coups, et s''en allèrent, le laissant à demi mort.'),
  (42, 10, 31, 'Un sacrificateur, qui par hasard descendait par le même chemin, ayant vu cet homme, passa outre.'),
  (42, 10, 32, 'Un Lévite, qui arriva aussi dans ce lieu, l''ayant vu, passa outre.'),
  (42, 10, 33, 'Mais un Samaritain, qui voyageait, étant venu là, fut ému de compassion lorsqu''il le vit.'),
  (42, 10, 34, 'Il s''approcha, et banda ses plaies, en y versant de l''huile et du vin; puis il le mit sur sa propre monture, le conduisit à une hôtellerie, et prit soin de lui.'),
  (42, 10, 35, 'Le lendemain, il tira deux deniers, les donna à l''hôte, et dit: Aie soin de lui, et ce que tu dépenseras de plus, je te le rendrai à mon retour.'),
  (42, 10, 36, 'Lequel de ces trois te semble avoir été le prochain de celui qui était tombé au milieu des brigands?'),
  (42, 10, 37, 'C''est celui qui a exercé la miséricorde envers lui, répondit le docteur de la loi. Et Jésus lui dit: Va, et toi, fais de même.'),
  (42, 10, 38, 'Comme Jésus était en chemin avec ses disciples, il entra dans un village, et une femme, nommée Marthe, le reçut dans sa maison.'),
  (42, 10, 39, 'Elle avait une sœur, nommée Marie, qui, s''étant assise aux pieds du Seigneur, écoutait sa parole.'),
  (42, 10, 40, 'Marthe, occupée à divers soins domestiques, survint et dit: Seigneur, cela ne te fait-il rien que ma sœur me laisse seule pour servir? Dis-lui donc de m''aider.'),
  (42, 10, 41, 'Le Seigneur lui répondit: Marthe, Marthe, tu t''inquiètes et tu t''agites pour beaucoup de choses.'),
  (42, 10, 42, 'Une seule chose est nécessaire. Marie a choisi la bonne part, qui ne lui sera point ôtée.'),
  (42, 11, 1, 'Jésus priait un jour en un certain lieu. Lorsqu''il eut achevé, un de ses disciples lui dit: Seigneur, enseigne-nous à prier, comme Jean l''a enseigné à ses disciples.'),
  (42, 11, 2, 'Il leur dit: Quand vous priez, dites: Père! Que ton nom soit sanctifié; que ton règne vienne.'),
  (42, 11, 3, 'Donne-nous chaque jour notre pain quotidien;'),
  (42, 11, 4, 'pardonne-nous nos péchés, car nous aussi nous pardonnons à quiconque nous offense; et ne nous induis pas en tentation.'),
  (42, 11, 5, 'Il leur dit encore: Si l''un de vous a un ami, et qu''il aille le trouver au milieu de la nuit pour lui dire: Ami, prête-moi trois pains,'),
  (42, 11, 6, 'car un de mes amis est arrivé de voyage chez moi, et je n''ai rien à lui offrir,'),
  (42, 11, 7, 'et si, de l''intérieur de sa maison, cet ami lui répond: Ne m''importune pas, la porte est déjà fermée, mes enfants et moi sommes au lit, je ne puis me lever pour te donner des pains, -'),
  (42, 11, 8, 'je vous le dis, même s''il ne se levait pas pour les lui donner parce que c''est son ami, il se lèverait à cause de son importunité et lui donnerait tout ce dont il a besoin.'),
  (42, 11, 9, 'Et moi, je vous dis: Demandez, et l''on vous donnera; cherchez, et vous trouverez; frappez, et l''on vous ouvrira.'),
  (42, 11, 10, 'Car quiconque demande reçoit, celui qui cherche trouve, et l''on ouvre à celui qui frappe.'),
  (42, 11, 11, 'Quel est parmi vous le père qui donnera une pierre à son fils, s''il lui demande du pain? Ou, s''il demande un poisson, lui donnera-t-il un serpent au lieu d''un poisson?'),
  (42, 11, 12, 'Ou, s''il demande un œuf, lui donnera-t-il un scorpion?'),
  (42, 11, 13, 'Si donc, méchants comme vous l''êtes, vous savez donner de bonnes choses à vos enfants, à combien plus forte raison le Père céleste donnera-t-il le Saint-Esprit à ceux qui le lui demandent.'),
  (42, 11, 14, 'Jésus chassa un démon qui était muet. Lorsque le démon fut sorti, le muet parla, et la foule fut dans l''admiration.'),
  (42, 11, 15, 'Mais quelques-uns dirent: c''est par Béelzébul, le prince des démons, qu''il chasse les démons.'),
  (42, 11, 16, 'Et d''autres, pour l''éprouver, lui demandèrent un signe venant du ciel.'),
  (42, 11, 17, 'Comme Jésus connaissait leurs pensées, il leur dit: Tout royaume divisé contre lui-même est dévasté, et une maison s''écroule sur une autre.'),
  (42, 11, 18, 'Si donc Satan est divisé contre lui-même, comment son royaume subsistera-t-il, puisque vous dites que je chasse les démons par Béelzébul?'),
  (42, 11, 19, 'Et si moi, je chasse les démons par Béelzébul, vos fils, par qui les chassent-ils? C''est pourquoi ils seront eux-mêmes vos juges.'),
  (42, 11, 20, 'Mais, si c''est par le doigt de Dieu que je chasse les démons, le royaume de Dieu est donc venu vers vous.'),
  (42, 11, 21, 'Lorsqu''un homme fort et bien armé garde sa maison, ce qu''il possède est en sûreté.'),
  (42, 11, 22, 'Mais, si un plus fort que lui survient et le dompte, il lui enlève toutes les armes dans lesquelles il se confiait, et il distribue ses dépouilles.'),
  (42, 11, 23, 'Celui qui n''est pas avec moi est contre moi, et celui qui n''assemble pas avec moi disperse.'),
  (42, 11, 24, 'Lorsque l''esprit impur est sorti d''un homme, il va dans des lieux arides, pour chercher du repos. N''en trouvant point, il dit: Je retournerai dans ma maison d''où je suis sorti;'),
  (42, 11, 25, 'et, quand il arrive, il la trouve balayée et ornée.'),
  (42, 11, 26, 'Alors il s''en va, et il prend sept autres esprits plus méchants que lui; ils entrent dans la maison, s''y établissent, et la dernière condition de cet homme est pire que la première.'),
  (42, 11, 27, 'Tandis que Jésus parlait ainsi, une femme, élevant la voix du milieu de la foule, lui dit: Heureux le sein qui t''a porté! heureuses les mamelles qui t''ont allaité!'),
  (42, 11, 28, 'Et il répondit: Heureux plutôt ceux qui écoutent la parole de Dieu, et qui la gardent!'),
  (42, 11, 29, 'Comme le peuple s''amassait en foule, il se mit à dire: Cette génération est une génération méchante; elle demande un miracle; il ne lui sera donné d''autre miracle que celui de Jonas.'),
  (42, 11, 30, 'Car, de même que Jonas fut un signe pour les Ninivites, de même le Fils de l''homme en sera un pour cette génération.'),
  (42, 11, 31, 'La reine du Midi se lèvera, au jour du jugement, avec les hommes de cette génération et les condamnera, parce qu''elle vint des extrémités de la terre pour entendre la sagesse de Salomon; et voici, il y a ici plus que Salomon.'),
  (42, 11, 32, 'Les hommes de Ninive se lèveront, au jour du jugement, avec cette génération et la condamneront, parce qu''ils se repentirent à la prédication de Jonas; et voici, il y a ici plus que Jonas.'),
  (42, 11, 33, 'Personne n''allume une lampe pour la mettre dans un lieu caché ou sous le boisseau, mais on la met sur le chandelier, afin que ceux qui entrent voient la lumière.'),
  (42, 11, 34, 'Ton œil est la lampe de ton corps. Lorsque ton œil est en bon état, tout ton corps est éclairé; mais lorsque ton œil est en mauvais état, ton corps est dans les ténèbres.'),
  (42, 11, 35, 'Prends donc garde que la lumière qui est en toi ne soit ténèbres.'),
  (42, 11, 36, 'Si donc tout ton corps est éclairé, n''ayant aucune partie dans les ténèbres, il sera entièrement éclairé, comme lorsque la lampe t''éclaire de sa lumière.'),
  (42, 11, 37, 'Pendant que Jésus parlait, un pharisien le pria de dîner chez lui. Il entra, et se mit à table.'),
  (42, 11, 38, 'Le pharisien vit avec étonnement qu''il ne s''était pas lavé avant le repas.'),
  (42, 11, 39, 'Mais le Seigneur lui dit: Vous, pharisiens, vous nettoyez le dehors de la coupe et du plat, et à l''intérieur vous êtes pleins de rapine et de méchanceté.'),
  (42, 11, 40, 'Insensés! celui qui a fait le dehors n''a-t-il pas fait aussi le dedans?'),
  (42, 11, 41, 'Donnez plutôt en aumônes ce qui est dedans, et voici, toutes choses seront pures pour vous.'),
  (42, 11, 42, 'Mais malheur à vous, pharisiens! parce que vous payez la dîme de la menthe, de la rue, et de toutes les herbes, et que vous négligez la justice et l''amour de Dieu: c''est là ce qu''il fallait pratiquer, sans omettre les autres choses.'),
  (42, 11, 43, 'Malheur à vous, pharisiens! parce que vous aimez les premiers sièges dans les synagogues, et les salutations dans les places publiques.'),
  (42, 11, 44, 'Malheur à vous! parce que vous êtes comme les sépulcres qui ne paraissent pas, et sur lesquels on marche sans le savoir.'),
  (42, 11, 45, 'Un des docteurs de la loi prit la parole, et lui dit: Maître, en parlant de la sorte, c''est aussi nous que tu outrages.'),
  (42, 11, 46, 'Et Jésus répondit: Malheur à vous aussi, docteurs de la loi! parce que vous chargez les hommes de fardeaux difficiles à porter, et que vous ne touchez pas vous-mêmes de l''un de vos doigts.'),
  (42, 11, 47, 'Malheur à vous! parce que vous bâtissez les tombeaux des prophètes, que vos pères ont tués.'),
  (42, 11, 48, 'Vous rendez donc témoignage aux œuvres de vos pères, et vous les approuvez; car eux, ils ont tué les prophètes, et vous, vous bâtissez leurs tombeaux.'),
  (42, 11, 49, 'C''est pourquoi la sagesse de Dieu a dit: Je leur enverrai des prophètes et des apôtres; ils tueront les uns et persécuteront les autres,'),
  (42, 11, 50, 'afin qu''il soit demandé compte à cette génération du sang de tous les prophètes qui a été répandu depuis la création du monde,'),
  (42, 11, 51, 'depuis le sang d''Abel jusqu''au sang de Zacharie, tué entre l''autel et le temple; oui, je vous le dis, il en sera demandé compte à cette génération.'),
  (42, 11, 52, 'Malheur à vous, docteurs de la loi! parce que vous avez enlevé la clef de la science; vous n''êtes pas entrés vous-mêmes, et vous avez empêché d''entrer ceux qui le voulaient.'),
  (42, 11, 53, 'Quand il fut sorti de là, les scribes et les pharisiens commencèrent à le presser violemment, et à le faire parler sur beaucoup de choses,'),
  (42, 11, 54, 'lui tendant des pièges, pour surprendre quelque parole sortie de sa bouche.'),
  (42, 12, 1, 'Sur ces entrefaites, les gens s''étant rassemblés par milliers, au point de se fouler les uns les autres, Jésus se mit à dire à ses disciples: Avant tout, gardez-vous du levain des pharisiens, qui est l''hypocrisie.'),
  (42, 12, 2, 'Il n''y a rien de caché qui ne doive être découvert, ni de secret qui ne doive être connu.'),
  (42, 12, 3, 'C''est pourquoi tout ce que vous aurez dit dans les ténèbres sera entendu dans la lumière, et ce que vous aurez dit à l''oreille dans les chambres sera prêché sur les toits.'),
  (42, 12, 4, 'Je vous dis, à vous qui êtes mes amis: Ne craignez pas ceux qui tuent le corps et qui, après cela, ne peuvent rien faire de plus.'),
  (42, 12, 5, 'Je vous montrerai qui vous devez craindre. Craignez celui qui, après avoir tué, a le pouvoir de jeter dans la géhenne; oui, je vous le dis, c''est lui que vous devez craindre.'),
  (42, 12, 6, 'Ne vend-on pas cinq passereaux pour deux sous? Cependant, aucun d''eux n''est oublié devant Dieu.'),
  (42, 12, 7, 'Et même les cheveux de votre tête sont tous comptés. Ne craignez donc point: vous valez plus que beaucoup de passereaux.'),
  (42, 12, 8, 'Je vous le dis, quiconque me confessera devant les hommes, le Fils de l''homme le confessera aussi devant les anges de Dieu;'),
  (42, 12, 9, 'mais celui qui me reniera devant les hommes sera renié devant les anges de Dieu.'),
  (42, 12, 10, 'Et quiconque parlera contre le Fils de l''homme, il lui sera pardonné; mais à celui qui blasphémera contre le Saint-Esprit il ne sera point pardonné.'),
  (42, 12, 11, 'Quand on vous mènera devant les synagogues, les magistrats et les autorités, ne vous inquiétez pas de la manière dont vous vous défendrez ni de ce que vous direz;'),
  (42, 12, 12, 'car le Saint-Esprit vous enseignera à l''heure même ce qu''il faudra dire.'),
  (42, 12, 13, 'Quelqu''un dit à Jésus, du milieu de la foule: Maître, dis à mon frère de partager avec moi notre héritage.'),
  (42, 12, 14, 'Jésus lui répondit: O homme, qui m''a établi pour être votre juge, ou pour faire vos partages?'),
  (42, 12, 15, 'Puis il leur dit: Gardez-vous avec soin de toute avarice; car la vie d''un homme ne dépend pas de ses biens, fût-il dans l''abondance.'),
  (42, 12, 16, 'Et il leur dit cette parabole: Les terres d''un homme riche avaient beaucoup rapporté.'),
  (42, 12, 17, 'Et il raisonnait en lui-même, disant: Que ferai-je? car je n''ai pas de place pour serrer ma récolte.'),
  (42, 12, 18, 'Voici, dit-il, ce que je ferai: j''abattrai mes greniers, j''en bâtirai de plus grands, j''y amasserai toute ma récolte et tous mes biens;'),
  (42, 12, 19, 'et je dirai à mon âme: Mon âme, tu as beaucoup de biens en réserve pour plusieurs années; repose-toi, mange, bois, et réjouis-toi.'),
  (42, 12, 20, 'Mais Dieu lui dit: Insensé! cette nuit même ton âme te sera redemandée; et ce que tu as préparé, pour qui cela sera-t-il?'),
  (42, 12, 21, 'Il en est ainsi de celui qui amasse des trésors pour lui-même, et qui n''est pas riche pour Dieu.'),
  (42, 12, 22, 'Jésus dit ensuite à ses disciples: C''est pourquoi je vous dis: Ne vous inquiétez pas pour votre vie de ce que vous mangerez, ni pour votre corps de quoi vous serez vêtus.'),
  (42, 12, 23, 'La vie est plus que la nourriture, et le corps plus que le vêtement.'),
  (42, 12, 24, 'Considérez les corbeaux: ils ne sèment ni ne moissonnent, ils n''ont ni cellier ni grenier; et Dieu les nourrit. Combien ne valez-vous pas plus que les oiseaux!'),
  (42, 12, 25, 'Qui de vous, par ses inquiétudes, peut ajouter une coudée à la durée de sa vie?'),
  (42, 12, 26, 'Si donc vous ne pouvez pas même la moindre chose, pourquoi vous inquiétez-vous du reste?'),
  (42, 12, 27, 'Considérez comment croissent les lis: ils ne travaillent ni ne filent; cependant je vous dis que Salomon même, dans toute sa gloire, n''a pas été vêtu comme l''un d''eux.'),
  (42, 12, 28, 'Si Dieu revêt ainsi l''herbe qui est aujourd''hui dans les champs et qui demain sera jetée au four, à combien plus forte raison ne vous vêtira-t-il pas, gens de peu de foi?'),
  (42, 12, 29, 'Et vous, ne cherchez pas ce que vous mangerez et ce que vous boirez, et ne soyez pas inquiets.'),
  (42, 12, 30, 'Car toutes ces choses, ce sont les païens du monde qui les recherchent. Votre Père sait que vous en avez besoin.'),
  (42, 12, 31, 'Cherchez plutôt le royaume de Dieu; et toutes ces choses vous seront données par-dessus.'),
  (42, 12, 32, 'Ne crains point, petit troupeau; car votre Père a trouvé bon de vous donner le royaume.'),
  (42, 12, 33, 'Vendez ce que vous possédez, et donnez-le en aumônes. Faites-vous des bourses qui ne s''usent point, un trésor inépuisable dans les cieux, où le voleur n''approche point, et où la teigne ne détruit point.'),
  (42, 12, 34, 'Car là où est votre trésor, là aussi sera votre cœur.'),
  (42, 12, 35, 'Que vos reins soient ceints, et vos lampes allumées.'),
  (42, 12, 36, 'Et vous, soyez semblables à des hommes qui attendent que leur maître revienne des noces, afin de lui ouvrir dès qu''il arrivera et frappera.'),
  (42, 12, 37, 'Heureux ces serviteurs que le maître, à son arrivée, trouvera veillant! Je vous le dis en vérité, il se ceindra, les fera mettre à table, et s''approchera pour les servir.'),
  (42, 12, 38, 'Qu''il arrive à la deuxième ou à la troisième veille, heureux ces serviteurs, s''il les trouve veillant!'),
  (42, 12, 39, 'Sachez-le bien, si le maître de la maison savait à quelle heure le voleur doit venir, il veillerait et ne laisserait pas percer sa maison.'),
  (42, 12, 40, 'Vous aussi, tenez-vous prêts, car le Fils de l''homme viendra à l''heure où vous n''y penserez pas.'),
  (42, 12, 41, 'Pierre lui dit: Seigneur, est-ce à nous, ou à tous, que tu adresses cette parabole?'),
  (42, 12, 42, 'Et le Seigneur dit: Quel est donc l''économe fidèle et prudent que le maître établira sur ses gens, pour leur donner la nourriture au temps convenable?'),
  (42, 12, 43, 'Heureux ce serviteur, que son maître, à son arrivée, trouvera faisant ainsi!'),
  (42, 12, 44, 'Je vous le dis en vérité, il l''établira sur tous ses biens.'),
  (42, 12, 45, 'Mais, si ce serviteur dit en lui-même: Mon maître tarde à venir; s''il se met à battre les serviteurs et les servantes, à manger, à boire et à s''enivrer,'),
  (42, 12, 46, 'le maître de ce serviteur viendra le jour où il ne s''y attend pas et à l''heure qu''il ne connaît pas, il le mettra en pièces, et lui donnera sa part avec les infidèles.'),
  (42, 12, 47, 'Le serviteur qui, ayant connu la volonté de son maître, n''a rien préparé et n''a pas agi selon sa volonté, sera battu d''un grand nombre de coups.'),
  (42, 12, 48, 'Mais celui qui, ne l''ayant pas connue, a fait des choses dignes de châtiment, sera battu de peu de coups. On demandera beaucoup à qui l''on a beaucoup donné, et on exigera davantage de celui à qui l''on a beaucoup confié.'),
  (42, 12, 49, 'Je suis venu jeter un feu sur la terre, et qu''ai-je à désirer, s''il est déjà allumé?'),
  (42, 12, 50, 'Il est un baptême dont je dois être baptisé, et combien il me tarde qu''il soit accompli!'),
  (42, 12, 51, 'Pensez-vous que je sois venu apporter la paix sur la terre? Non, vous dis-je, mais la division.'),
  (42, 12, 52, 'Car désormais cinq dans une maison seront divisés, trois contre deux, et deux contre trois;'),
  (42, 12, 53, 'le père contre le fils et le fils contre le père, la mère contre la fille et la fille contre la mère, la belle-mère contre la belle-fille et la belle-fille contre la belle-mère.'),
  (42, 12, 54, 'Il dit encore aux foules: Quand vous voyez un nuage se lever à l''occident, vous dites aussitôt: La pluie vient. Et il arrive ainsi.'),
  (42, 12, 55, 'Et quand vous voyez souffler le vent du midi, vous dites: Il fera chaud. Et cela arrive.'),
  (42, 12, 56, 'Hypocrites! vous savez discerner l''aspect de la terre et du ciel; comment ne discernez-vous pas ce temps-ci?'),
  (42, 12, 57, 'Et pourquoi ne discernez-vous pas de vous-mêmes ce qui est juste?'),
  (42, 12, 58, 'Lorsque tu vas avec ton adversaire devant le magistrat, tâche en chemin de te dégager de lui, de peur qu''il ne te traîne devant le juge, que le juge ne te livre à l''officier de justice, et que celui-ci ne te mette en prison.'),
  (42, 12, 59, 'Je te le dis, tu ne sortiras pas de là que tu n''aies payé jusqu''à la dernière pite.'),
  (42, 13, 1, 'En ce même temps, quelques personnes qui se trouvaient là racontaient à Jésus ce qui était arrivé à des Galiléens dont Pilate avait mêlé le sang avec celui de leurs sacrifices.'),
  (42, 13, 2, 'Il leur répondit: Croyez-vous que ces Galiléens fussent de plus grands pécheurs que tous les autres Galiléens, parce qu''ils ont souffert de la sorte?'),
  (42, 13, 3, 'Non, je vous le dis. Mais si vous ne vous repentez, vous périrez tous également.'),
  (42, 13, 4, 'Ou bien, ces dix-huit personnes sur qui est tombée la tour de Siloé et qu''elle a tuées, croyez-vous qu''elles fussent plus coupables que tous les autres habitants de Jérusalem?'),
  (42, 13, 5, 'Non, je vous le dis. Mais si vous ne vous repentez, vous périrez tous également.'),
  (42, 13, 6, 'Il dit aussi cette parabole: Un homme avait un figuier planté dans sa vigne. Il vint pour y chercher du fruit, et il n''en trouva point.'),
  (42, 13, 7, 'Alors il dit au vigneron: Voilà trois ans que je viens chercher du fruit à ce figuier, et je n''en trouve point. Coupe-le: pourquoi occupe-t-il la terre inutilement?'),
  (42, 13, 8, 'Le vigneron lui répondit: Seigneur, laisse-le encore cette année; je creuserai tout autour, et j''y mettrai du fumier.'),
  (42, 13, 9, 'Peut-être à l''avenir donnera-t-il du fruit; sinon, tu le couperas.'),
  (42, 13, 10, 'Jésus enseignait dans une des synagogues, le jour du sabbat.'),
  (42, 13, 11, 'Et voici, il y avait là une femme possédée d''un esprit qui la rendait infirme depuis dix-huit ans; elle était courbée, et ne pouvait pas du tout se redresser.'),
  (42, 13, 12, 'Lorsqu''il la vit, Jésus lui adressa la parole, et lui dit: Femme, tu es délivrée de ton infirmité.'),
  (42, 13, 13, 'Et il lui imposa les mains. A l''instant elle se redressa, et glorifia Dieu.'),
  (42, 13, 14, 'Mais le chef de la synagogue, indigné de ce que Jésus avait opéré cette guérison un jour de sabbat, dit à la foule: Il y a six jours pour travailler; venez donc vous faire guérir ces jours-là, et non pas le jour du sabbat.'),
  (42, 13, 15, 'Hypocrites! lui répondit le Seigneur, est-ce que chacun de vous, le jour du sabbat, ne détache pas de la crèche son bœuf ou son âne, pour le mener boire?'),
  (42, 13, 16, 'Et cette femme, qui est une fille d''Abraham, et que Satan tenait liée depuis dix-huit ans, ne fallait-il pas la délivrer de cette chaîne le jour du sabbat?'),
  (42, 13, 17, 'Tandis qu''il parlait ainsi, tous ses adversaires étaient confus, et la foule se réjouissait de toutes les choses glorieuses qu''il faisait.'),
  (42, 13, 18, 'Il dit encore: A quoi le royaume de Dieu est-il semblable, et à quoi le comparerai-je?'),
  (42, 13, 19, 'Il est semblable à un grain de sénevé qu''un homme a pris et jeté dans son jardin; il pousse, devient un arbre, et les oiseaux du ciel habitent dans ses branches.'),
  (42, 13, 20, 'Il dit encore: A quoi comparerai-je le royaume de Dieu?'),
  (42, 13, 21, 'Il est semblable à du levain qu''une femme a pris et mis dans trois mesures de farine, pour faire lever toute la pâte.'),
  (42, 13, 22, 'Jésus traversait les villes et les villages, enseignant, et faisant route vers Jérusalem.'),
  (42, 13, 23, 'Quelqu''un lui dit: Seigneur, n''y a-t-il que peu de gens qui soient sauvés? Il leur répondit:'),
  (42, 13, 24, 'Efforcez-vous d''entrer par la porte étroite. Car, je vous le dis, beaucoup chercheront à entrer, et ne le pourront pas.'),
  (42, 13, 25, 'Quand le maître de la maison se sera levé et aura fermé la porte, et que vous, étant dehors, vous commencerez à frapper à la porte, en disant: Seigneur, Seigneur, ouvre-nous! il vous répondra: Je ne sais d''où vous êtes.'),
  (42, 13, 26, 'Alors vous vous mettrez à dire: Nous avons mangé et bu devant toi, et tu as enseigné dans nos rues.'),
  (42, 13, 27, 'Et il répondra: Je vous le dis, je ne sais d''où vous êtes; retirez-vous de moi, vous tous, ouvriers d''iniquité.'),
  (42, 13, 28, 'C''est là qu''il y aura des pleurs et des grincements de dents, quand vous verrez Abraham, Isaac et Jacob, et tous les prophètes, dans le royaume de Dieu, et que vous serez jetés dehors.'),
  (42, 13, 29, 'Il en viendra de l''orient et de l''occident, du nord et du midi; et ils se mettront à table dans le royaume de Dieu.'),
  (42, 13, 30, 'Et voici, il y en a des derniers qui seront les premiers, et des premiers qui seront les derniers.'),
  (42, 13, 31, 'Ce même jour, quelques pharisiens vinrent lui dire: Va-t''en, pars d''ici, car Hérode veut te tuer.'),
  (42, 13, 32, 'Il leur répondit: Allez, et dites à ce renard: Voici, je chasse les démons et je fais des guérisons aujourd''hui et demain, et le troisième jour j''aurai fini.'),
  (42, 13, 33, 'Mais il faut que je marche aujourd''hui, demain, et le jour suivant; car il ne convient pas qu''un prophète périsse hors de Jérusalem.'),
  (42, 13, 34, 'Jérusalem, Jérusalem, qui tues les prophètes et qui lapides ceux qui te sont envoyés, combien de fois ai-je voulu rassembler tes enfants, comme une poule rassemble sa couvée sous ses ailes, et vous ne l''avez pas voulu!'),
  (42, 13, 35, 'Voici, votre maison vous sera laissée; mais, je vous le dis, vous ne me verrez plus, jusqu''à ce que vous disiez: Béni soit celui qui vient au nom du Seigneur!'),
  (42, 14, 1, 'Jésus étant entré, un jour de sabbat, dans la maison de l''un des chefs des pharisiens, pour prendre un repas, les pharisiens l''observaient.'),
  (42, 14, 2, 'Et voici, un homme hydropique était devant lui.'),
  (42, 14, 3, 'Jésus prit la parole, et dit aux docteurs de la loi et aux pharisiens: Est-il permis, ou non, de faire une guérison le jour du sabbat?'),
  (42, 14, 4, 'Ils gardèrent le silence. Alors Jésus avança la main sur cet homme, le guérit, et le renvoya.'),
  (42, 14, 5, 'Puis il leur dit: Lequel de vous, si son fils ou son bœuf tombe dans un puits, ne l''en retirera pas aussitôt, le jour du sabbat?'),
  (42, 14, 6, 'Et ils ne purent rien répondre à cela.'),
  (42, 14, 7, 'Il adressa ensuite une parabole aux conviés, en voyant qu''ils choisissaient les premières places; et il leur dit:'),
  (42, 14, 8, 'Lorsque tu seras invité par quelqu''un à des noces, ne te mets pas à la première place, de peur qu''il n''y ait parmi les invités une personne plus considérable que toi,'),
  (42, 14, 9, 'et que celui qui vous a invités l''un et l''autre ne vienne te dire: Cède la place à cette personne-là. Tu aurais alors la honte d''aller occuper la dernière place.'),
  (42, 14, 10, 'Mais, lorsque tu seras invité, va te mettre à la dernière place, afin que, quand celui qui t''a invité viendra, il te dise: Mon ami, monte plus haut. Alors cela te fera honneur devant tous ceux qui seront à table avec toi.'),
  (42, 14, 11, 'Car quiconque s''élève sera abaissé, et quiconque s''abaisse sera élevé.'),
  (42, 14, 12, 'Il dit aussi à celui qui l''avait invité: Lorsque tu donnes à dîner ou à souper, n''invite pas tes amis, ni tes frères, ni tes parents, ni des voisins riches, de peur qu''ils ne t''invitent à leur tour et qu''on ne te rende la pareille.'),
  (42, 14, 13, 'Mais, lorsque tu donnes un festin, invite des pauvres, des estropiés, des boiteux, des aveugles.'),
  (42, 14, 14, 'Et tu seras heureux de ce qu''ils ne peuvent pas te rendre la pareille; car elle te sera rendue à la résurrection des justes.'),
  (42, 14, 15, 'Un de ceux qui étaient à table, après avoir entendu ces paroles, dit à Jésus: Heureux celui qui prendra son repas dans le royaume de Dieu!'),
  (42, 14, 16, 'Et Jésus lui répondit: Un homme donna un grand souper, et il invita beaucoup de gens.'),
  (42, 14, 17, 'A l''heure du souper, il envoya son serviteur dire aux conviés: Venez, car tout est déjà prêt.'),
  (42, 14, 18, 'Mais tous unanimement se mirent à s''excuser. Le premier lui dit: J''ai acheté un champ, et je suis obligé d''aller le voir; excuse-moi, je te prie.'),
  (42, 14, 19, 'Un autre dit: J''ai acheté cinq paires de bœufs, et je vais les essayer; excuse-moi, je te prie.'),
  (42, 14, 20, 'Un autre dit: Je viens de me marier, et c''est pourquoi je ne puis aller.'),
  (42, 14, 21, 'Le serviteur, de retour, rapporta ces choses à son maître. Alors le maître de la maison irrité dit à son serviteur: Va promptement dans les places et dans les rues de la ville, et amène ici les pauvres, les estropiés, les aveugles et les boiteux.'),
  (42, 14, 22, 'Le serviteur dit: Maître, ce que tu as ordonné a été fait, et il y a encore de la place.'),
  (42, 14, 23, 'Et le maître dit au serviteur: Va dans les chemins et le long des haies, et ceux que tu trouveras, contrains-les d''entrer, afin que ma maison soit remplie.'),
  (42, 14, 24, 'Car, je vous le dis, aucun de ces hommes qui avaient été invités ne goûtera de mon souper.'),
  (42, 14, 25, 'De grandes foules faisaient route avec Jésus. Il se retourna, et leur dit:'),
  (42, 14, 26, 'Si quelqu''un vient à moi, et s''il ne hait pas son père, sa mère, sa femme, ses enfants, ses frères, et ses sœurs, et même sa propre vie, il ne peut être mon disciple.'),
  (42, 14, 27, 'Et quiconque ne porte pas sa croix, et ne me suit pas, ne peut être mon disciple.'),
  (42, 14, 28, 'Car, lequel de vous, s''il veut bâtir une tour, ne s''assied d''abord pour calculer la dépense et voir s''il a de quoi la terminer,'),
  (42, 14, 29, 'de peur qu''après avoir posé les fondements, il ne puisse l''achever, et que tous ceux qui le verront ne se mettent à le railler,'),
  (42, 14, 30, 'en disant: Cet homme a commencé à bâtir, et il n''a pu achever?'),
  (42, 14, 31, 'Ou quel roi, s''il va faire la guerre à un autre roi, ne s''assied d''abord pour examiner s''il peut, avec dix mille hommes, marcher à la rencontre de celui qui vient l''attaquer avec vingt mille?'),
  (42, 14, 32, 'S''il ne le peut, tandis que cet autre roi est encore loin, il lui envoie une ambassade pour demander la paix.'),
  (42, 14, 33, 'Ainsi donc, quiconque d''entre vous ne renonce pas à tout ce qu''il possède ne peut être mon disciple.'),
  (42, 14, 34, 'Le sel est une bonne chose; mais si le sel perd sa saveur, avec quoi l''assaisonnera-t-on?'),
  (42, 14, 35, 'Il n''est bon ni pour la terre, ni pour le fumier; on le jette dehors. Que celui qui a des oreilles pour entendre entende.'),
  (42, 15, 1, 'Tous les publicains et les gens de mauvaise vie s''approchaient de Jésus pour l''entendre.'),
  (42, 15, 2, 'Et les pharisiens et les scribes murmuraient, disant: Cet homme accueille des gens de mauvaise vie, et mange avec eux.'),
  (42, 15, 3, 'Mais il leur dit cette parabole:'),
  (42, 15, 4, 'Quel homme d''entre vous, s''il a cent brebis, et qu''il en perde une, ne laisse les quatre-vingt-dix-neuf autres dans le désert pour aller après celle qui est perdue, jusqu''à ce qu''il la retrouve?'),
  (42, 15, 5, 'Lorsqu''il l''a retrouvée, il la met avec joie sur ses épaules,'),
  (42, 15, 6, 'et, de retour à la maison, il appelle ses amis et ses voisins, et leur dit: Réjouissez-vous avec moi, car j''ai retrouvé ma brebis qui était perdue.'),
  (42, 15, 7, 'De même, je vous le dis, il y aura plus de joie dans le ciel pour un seul pécheur qui se repent, que pour quatre-vingt-dix-neuf justes qui n''ont pas besoin de repentance.'),
  (42, 15, 8, 'Ou quelle femme, si elle a dix drachmes, et qu''elle en perde une, n''allume une lampe, ne balaie la maison, et ne cherche avec soin, jusqu''à ce qu''elle la retrouve?'),
  (42, 15, 9, 'Lorsqu''elle l''a retrouvée, elle appelle ses amies et ses voisines, et dit: Réjouissez-vous avec moi, car j''ai retrouvé la drachme que j''avais perdue.'),
  (42, 15, 10, 'De même, je vous le dis, il y a de la joie devant les anges de Dieu pour un seul pécheur qui se repent.'),
  (42, 15, 11, 'Il dit encore: Un homme avait deux fils.'),
  (42, 15, 12, 'Le plus jeune dit à son père: Mon père, donne-moi la part de bien qui doit me revenir. Et le père leur partagea son bien.'),
  (42, 15, 13, 'Peu de jours après, le plus jeune fils, ayant tout ramassé, partit pour un pays éloigné, où il dissipa son bien en vivant dans la débauche.'),
  (42, 15, 14, 'Lorsqu''il eut tout dépensé, une grande famine survint dans ce pays, et il commença à se trouver dans le besoin.'),
  (42, 15, 15, 'Il alla se mettre au service d''un des habitants du pays, qui l''envoya dans ses champs garder les pourceaux.'),
  (42, 15, 16, 'Il aurait bien voulu se rassasier des carouges que mangeaient les pourceaux, mais personne ne lui en donnait.'),
  (42, 15, 17, 'Étant rentré en lui-même, il se dit: Combien de mercenaires chez mon père ont du pain en abondance, et moi, ici, je meurs de faim!'),
  (42, 15, 18, 'Je me lèverai, j''irai vers mon père, et je lui dirai: Mon père, j''ai péché contre le ciel et contre toi,'),
  (42, 15, 19, 'je ne suis plus digne d''être appelé ton fils; traite-moi comme l''un de tes mercenaires.'),
  (42, 15, 20, 'Et il se leva, et alla vers son père. Comme il était encore loin, son père le vit et fut ému de compassion, il courut se jeter à son cou et le baisa.'),
  (42, 15, 21, 'Le fils lui dit: Mon père, j''ai péché contre le ciel et contre toi, je ne suis plus digne d''être appelé ton fils.'),
  (42, 15, 22, 'Mais le père dit à ses serviteurs: Apportez vite la plus belle robe, et l''en revêtez; mettez-lui un anneau au doigt, et des souliers aux pieds.'),
  (42, 15, 23, 'Amenez le veau gras, et tuez-le. Mangeons et réjouissons-nous;'),
  (42, 15, 24, 'car mon fils que voici était mort, et il est revenu à la vie; il était perdu, et il est retrouvé. Et ils commencèrent à se réjouir.'),
  (42, 15, 25, 'Or, le fils aîné était dans les champs. Lorsqu''il revint et approcha de la maison, il entendit la musique et les danses.'),
  (42, 15, 26, 'Il appela un des serviteurs, et lui demanda ce que c''était.'),
  (42, 15, 27, 'Ce serviteur lui dit: Ton frère est de retour, et, parce qu''il l''a retrouvé en bonne santé, ton père a tué le veau gras.'),
  (42, 15, 28, 'Il se mit en colère, et ne voulut pas entrer. Son père sortit, et le pria d''entrer.'),
  (42, 15, 29, 'Mais il répondit à son père: Voici, il y a tant d''années que je te sers, sans avoir jamais transgressé tes ordres, et jamais tu ne m''as donné un chevreau pour que je me réjouisse avec mes amis.'),
  (42, 15, 30, 'Et quand ton fils est arrivé, celui qui a mangé ton bien avec des prostituées, c''est pour lui que tu as tué le veau gras!'),
  (42, 15, 31, 'Mon enfant, lui dit le père, tu es toujours avec moi, et tout ce que j''ai est à toi;'),
  (42, 15, 32, 'mais il fallait bien s''égayer et se réjouir, parce que ton frère que voici était mort et qu''il est revenu à la vie, parce qu''il était perdu et qu''il est retrouvé.'),
  (42, 16, 1, 'Jésus dit aussi à ses disciples: Un homme riche avait un économe, qui lui fut dénoncé comme dissipant ses biens.'),
  (42, 16, 2, 'Il l''appela, et lui dit: Qu''est-ce que j''entends dire de toi? Rends compte de ton administration, car tu ne pourras plus administrer mes biens.'),
  (42, 16, 3, 'L''économe dit en lui-même: Que ferai-je, puisque mon maître m''ôte l''administration de ses biens? Travailler à la terre? je ne le puis. Mendier? j''en ai honte.'),
  (42, 16, 4, 'Je sais ce que je ferai, pour qu''il y ait des gens qui me reçoivent dans leurs maisons quand je serai destitué de mon emploi.'),
  (42, 16, 5, 'Et, faisant venir chacun des débiteurs de son maître, il dit au premier: Combien dois-tu à mon maître?'),
  (42, 16, 6, 'Cent mesures d''huile, répondit-il. Et il lui dit: Prends ton billet, assieds-toi vite, et écris cinquante.'),
  (42, 16, 7, 'Il dit ensuite à un autre: Et toi, combien dois-tu? Cent mesures de blé, répondit-il. Et il lui dit: Prends ton billet, et écris quatre-vingts.'),
  (42, 16, 8, 'Le maître loua l''économe infidèle de ce qu''il avait agi prudemment. Car les enfants de ce siècle sont plus prudents à l''égard de leurs semblables que ne le sont les enfants de lumière.'),
  (42, 16, 9, 'Et moi, je vous dis: Faites-vous des amis avec les richesses injustes, pour qu''ils vous reçoivent dans les tabernacles éternels, quand elles viendront à vous manquer.'),
  (42, 16, 10, 'Celui qui est fidèle dans les moindres choses l''est aussi dans les grandes, et celui qui est injuste dans les moindres choses l''est aussi dans les grandes.'),
  (42, 16, 11, 'Si donc vous n''avez pas été fidèles dans les richesses injustes, qui vous confiera les véritables?'),
  (42, 16, 12, 'Et si vous n''avez pas été fidèles dans ce qui est à autrui, qui vous donnera ce qui est à vous?'),
  (42, 16, 13, 'Nul serviteur ne peut servir deux maîtres. Car, ou il haïra l''un et aimera l''autre; ou il s''attachera à l''un et méprisera l''autre. Vous ne pouvez servir Dieu et Mamon.'),
  (42, 16, 14, 'Les pharisiens, qui étaient avares, écoutaient aussi tout cela, et ils se moquaient de lui.'),
  (42, 16, 15, 'Jésus leur dit: Vous, vous cherchez à paraître justes devant les hommes, mais Dieu connaît vos cœurs; car ce qui est élevé parmi les hommes est une abomination devant Dieu.'),
  (42, 16, 16, 'La loi et les prophètes ont subsisté jusqu''à Jean; depuis lors, le royaume de Dieu est annoncé, et chacun use de violence pour y entrer.'),
  (42, 16, 17, 'Il est plus facile que le ciel et la terre passent, qu''il ne l''est qu''un seul trait de lettre de la loi vienne à tomber.'),
  (42, 16, 18, 'Quiconque répudie sa femme et en épouse une autre commet un adultère, et quiconque épouse une femme répudiée par son mari commet un adultère.'),
  (42, 16, 19, 'Il y avait un homme riche, qui était vêtu de pourpre et de fin lin, et qui chaque jour menait joyeuse et brillante vie.'),
  (42, 16, 20, 'Un pauvre, nommé Lazare, était couché à sa porte, couvert d''ulcères,'),
  (42, 16, 21, 'et désireux de se rassasier des miettes qui tombaient de la table du riche; et même les chiens venaient encore lécher ses ulcères.'),
  (42, 16, 22, 'Le pauvre mourut, et il fut porté par les anges dans le sein d''Abraham. Le riche mourut aussi, et il fut enseveli.'),
  (42, 16, 23, 'Dans le séjour des morts, il leva les yeux; et, tandis qu''il était en proie aux tourments, il vit de loin Abraham, et Lazare dans son sein.'),
  (42, 16, 24, 'Il s''écria: Père Abraham, aie pitié de moi, et envoie Lazare, pour qu''il trempe le bout de son doigt dans l''eau et me rafraîchisse la langue; car je souffre cruellement dans cette flamme.'),
  (42, 16, 25, 'Abraham répondit: Mon enfant, souviens-toi que tu as reçu tes biens pendant ta vie, et que Lazare a eu les maux pendant la sienne; maintenant il est ici consolé, et toi, tu souffres.'),
  (42, 16, 26, 'D''ailleurs, il y a entre nous et vous un grand abîme, afin que ceux qui voudraient passer d''ici vers vous, ou de là vers nous, ne puissent le faire.'),
  (42, 16, 27, 'Le riche dit: Je te prie donc, père Abraham, d''envoyer Lazare dans la maison de mon père;'),
  (42, 16, 28, 'car j''ai cinq frères. C''est pour qu''il leur atteste ces choses, afin qu''ils ne viennent pas aussi dans ce lieu de tourments.'),
  (42, 16, 29, 'Abraham répondit: Ils ont Moïse et les prophètes; qu''ils les écoutent.'),
  (42, 16, 30, 'Et il dit: Non, père Abraham, mais si quelqu''un des morts va vers eux, ils se repentiront.'),
  (42, 16, 31, 'Et Abraham lui dit: S''ils n''écoutent pas Moïse et les prophètes, ils ne se laisseront pas persuader quand même quelqu''un des morts ressusciterait.'),
  (42, 17, 1, 'Jésus dit à ses disciples: Il est impossible qu''il n''arrive pas des scandales; mais malheur à celui par qui ils arrivent!'),
  (42, 17, 2, 'Il vaudrait mieux pour lui qu''on mît à son cou une pierre de moulin et qu''on le jetât dans la mer, que s''il scandalisait un de ces petits.'),
  (42, 17, 3, 'Prenez garde à vous-mêmes. Si ton frère a péché, reprends-le; et, s''il se repent, pardonne-lui.'),
  (42, 17, 4, 'Et s''il a péché contre toi sept fois dans un jour et que sept fois il revienne à toi, disant: Je me repens, -tu lui pardonneras.'),
  (42, 17, 5, 'Les apôtres dirent au Seigneur: Augmente-nous la foi.'),
  (42, 17, 6, 'Et le Seigneur dit: Si vous aviez de la foi comme un grain de sénevé, vous diriez à ce sycomore: Déracine-toi, et plante-toi dans la mer; et il vous obéirait.'),
  (42, 17, 7, 'Qui de vous, ayant un serviteur qui laboure ou paît les troupeaux, lui dira, quand il revient des champs: Approche vite, et mets-toi à table?'),
  (42, 17, 8, 'Ne lui dira-t-il pas au contraire: Prépare-moi à souper, ceins-toi, et sers-moi, jusqu''à ce que j''aie mangé et bu; après cela, toi, tu mangeras et boiras?'),
  (42, 17, 9, 'Doit-il de la reconnaissance à ce serviteur parce qu''il a fait ce qui lui était ordonné?'),
  (42, 17, 10, 'Vous de même, quand vous avez fait tout ce qui vous a été ordonné, dites: Nous sommes des serviteurs inutiles, nous avons fait ce que nous devions faire.'),
  (42, 17, 11, 'Jésus, se rendant à Jérusalem, passait entre la Samarie et la Galilée.'),
  (42, 17, 12, 'Comme il entrait dans un village, dix lépreux vinrent à sa rencontre. Se tenant à distance,'),
  (42, 17, 13, 'ils élevèrent la voix, et dirent: Jésus, maître, aie pitié de nous!'),
  (42, 17, 14, 'Dès qu''il les eut vus, il leur dit: Allez vous montrer aux sacrificateurs. Et, pendant qu''ils y allaient, il arriva qu''ils furent guéris.'),
  (42, 17, 15, 'L''un d''eux, se voyant guéri, revint sur ses pas, glorifiant Dieu à haute voix.'),
  (42, 17, 16, 'Il tomba sur sa face aux pieds de Jésus, et lui rendit grâces. C''était un Samaritain.'),
  (42, 17, 17, 'Jésus, prenant la parole, dit: Les dix n''ont-ils pas été guéris? Et les neuf autres, où sont-ils?'),
  (42, 17, 18, 'Ne s''est-il trouvé que cet étranger pour revenir et donner gloire à Dieu?'),
  (42, 17, 19, 'Puis il lui dit: Lève-toi, va; ta foi t''a sauvé.'),
  (42, 17, 20, 'Les pharisiens demandèrent à Jésus quand viendrait le royaume de Dieu. Il leur répondit: Le royaume de Dieu ne vient pas de manière à frapper les regards.'),
  (42, 17, 21, 'On ne dira point: Il est ici, ou: Il est là. Car voici, le royaume de Dieu est au milieu de vous.'),
  (42, 17, 22, 'Et il dit aux disciples: Des jours viendront où vous désirerez voir l''un des jours du Fils de l''homme, et vous ne le verrez point.'),
  (42, 17, 23, 'On vous dira: Il est ici, il est là. N''y allez pas, ne courez pas après.'),
  (42, 17, 24, 'Car, comme l''éclair resplendit et brille d''une extrémité du ciel à l''autre, ainsi sera le Fils de l''homme en son jour.'),
  (42, 17, 25, 'Mais il faut auparavant qu''il souffre beaucoup, et qu''il soit rejeté par cette génération.'),
  (42, 17, 26, 'Ce qui arriva du temps de Noé arrivera de même aux jours du Fils de l''homme.'),
  (42, 17, 27, 'Les hommes mangeaient, buvaient, se mariaient et mariaient leurs enfants, jusqu''au jour où Noé entra dans l''arche; le déluge vint, et les fit tous périr.'),
  (42, 17, 28, 'Ce qui arriva du temps de Lot arrivera pareillement. Les hommes mangeaient, buvaient, achetaient, vendaient, plantaient, bâtissaient;'),
  (42, 17, 29, 'mais le jour où Lot sortit de Sodome, une pluie de feu et de soufre tomba du ciel, et les fit tous périr.'),
  (42, 17, 30, 'Il en sera de même le jour où le Fils de l''homme paraîtra.'),
  (42, 17, 31, 'En ce jour-là, que celui qui sera sur le toit, et qui aura ses effets dans la maison, ne descende pas pour les prendre; et que celui qui sera dans les champs ne retourne pas non plus en arrière.'),
  (42, 17, 32, 'Souvenez-vous de la femme de Lot.'),
  (42, 17, 33, 'Celui qui cherchera à sauver sa vie la perdra, et celui qui la perdra la retrouvera.'),
  (42, 17, 34, 'Je vous le dis, en cette nuit-là, de deux personnes qui seront dans un même lit, l''une sera prise et l''autre laissée;'),
  (42, 17, 35, 'de deux femmes qui moudront ensemble, l''une sera prise et l''autre laissée.'),
  (42, 17, 36, 'De deux hommes qui seront dans un champ, l''un sera pris et l''autre laissé.'),
  (42, 17, 37, 'Les disciples lui dirent: Où sera-ce, Seigneur? Et il répondit: Où sera le corps, là s''assembleront les aigles.'),
  (42, 18, 1, 'Jésus leur adressa une parabole, pour montrer qu''il faut toujours prier, et ne point se relâcher.'),
  (42, 18, 2, 'Il dit: Il y avait dans une ville un juge qui ne craignait point Dieu et qui n''avait d''égard pour personne.'),
  (42, 18, 3, 'Il y avait aussi dans cette ville une veuve qui venait lui dire: Fais-moi justice de ma partie adverse.'),
  (42, 18, 4, 'Pendant longtemps il refusa. Mais ensuite il dit en lui-même: Quoique je ne craigne point Dieu et que je n''aie d''égard pour personne,'),
  (42, 18, 5, 'néanmoins, parce que cette veuve m''importune, je lui ferai justice, afin qu''elle ne vienne pas sans cesse me rompre la tête.'),
  (42, 18, 6, 'Le Seigneur ajouta: Entendez ce que dit le juge inique.'),
  (42, 18, 7, 'Et Dieu ne fera-t-il pas justice à ses élus, qui crient à lui jour et nuit, et tardera-t-il à leur égard?'),
  (42, 18, 8, 'Je vous le dis, il leur fera promptement justice. Mais, quand le Fils de l''homme viendra, trouvera-t-il la foi sur la terre?'),
  (42, 18, 9, 'Il dit encore cette parabole, en vue de certaines personnes se persuadant qu''elles étaient justes, et ne faisant aucun cas des autres:'),
  (42, 18, 10, 'Deux hommes montèrent au temple pour prier; l''un était pharisien, et l''autre publicain.'),
  (42, 18, 11, 'Le pharisien, debout, priait ainsi en lui-même: O Dieu, je te rends grâces de ce que je ne suis pas comme le reste des hommes, qui sont ravisseurs, injustes, adultères, ou même comme ce publicain;'),
  (42, 18, 12, 'je jeûne deux fois la semaine, je donne la dîme de tous mes revenus.'),
  (42, 18, 13, 'Le publicain, se tenant à distance, n''osait même pas lever les yeux au ciel; mais il se frappait la poitrine, en disant: O Dieu, sois apaisé envers moi, qui suis un pécheur.'),
  (42, 18, 14, 'Je vous le dis, celui-ci descendit dans sa maison justifié, plutôt que l''autre. Car quiconque s''élève sera abaissé, et celui qui s''abaisse sera élevé.'),
  (42, 18, 15, 'On lui amena aussi les petits enfants, afin qu''il les touchât. Mais les disciples, voyant cela, reprenaient ceux qui les amenaient.'),
  (42, 18, 16, 'Et Jésus les appela, et dit: Laissez venir à moi les petits enfants, et ne les en empêchez pas; car le royaume de Dieu est pour ceux qui leur ressemblent.'),
  (42, 18, 17, 'Je vous le dis en vérité, quiconque ne recevra pas le royaume de Dieu comme un petit enfant n''y entrera point.'),
  (42, 18, 18, 'Un chef interrogea Jésus, et dit: Bon maître, que dois-je faire pour hériter la vie éternelle?'),
  (42, 18, 19, 'Jésus lui répondit: Pourquoi m''appelles-tu bon? Il n''y a de bon que Dieu seul.'),
  (42, 18, 20, 'Tu connais les commandements: Tu ne commettras point d''adultère; tu ne tueras point; tu ne déroberas point; tu ne diras point de faux témoignage; honore ton père et ta mère.'),
  (42, 18, 21, 'J''ai, dit-il, observé toutes ces choses dès ma jeunesse.'),
  (42, 18, 22, 'Jésus, ayant entendu cela, lui dit: Il te manque encore une chose: vends tout ce que tu as, distribue-le aux pauvres, et tu auras un trésor dans les cieux. Puis, viens, et suis-moi.'),
  (42, 18, 23, 'Lorsqu''il entendit ces paroles, il devint tout triste; car il était très riche.'),
  (42, 18, 24, 'Jésus, voyant qu''il était devenu tout triste, dit: Qu''il est difficile à ceux qui ont des richesses d''entrer dans le royaume de Dieu!'),
  (42, 18, 25, 'Car il est plus facile à un chameau de passer par le trou d''une aiguille qu''à un riche d''entrer dans le royaume de Dieu.'),
  (42, 18, 26, 'Ceux qui l''écoutaient dirent: Et qui peut être sauvé?'),
  (42, 18, 27, 'Jésus répondit: Ce qui est impossible aux hommes est possible à Dieu.'),
  (42, 18, 28, 'Pierre dit alors: Voici, nous avons tout quitté, et nous t''avons suivi.'),
  (42, 18, 29, 'Et Jésus leur dit: Je vous le dis en vérité, il n''est personne qui, ayant quitté, à cause du royaume de Dieu, sa maison, ou sa femme, ou ses frères, ou ses parents, ou ses enfants,'),
  (42, 18, 30, 'ne reçoive beaucoup plus dans ce siècle-ci, et, dans le siècle à venir, la vie éternelle.'),
  (42, 18, 31, 'Jésus prit les douze auprès de lui, et leur dit: Voici, nous montons à Jérusalem, et tout ce qui a été écrit par les prophètes au sujet du Fils de l''homme s''accomplira.'),
  (42, 18, 32, 'Car il sera livré aux païens; on se moquera de lui, on l''outragera, on crachera sur lui,'),
  (42, 18, 33, 'et, après l''avoir battu de verges, on le fera mourir; et le troisième jour il ressuscitera.'),
  (42, 18, 34, 'Mais ils ne comprirent rien à cela; c''était pour eux un langage caché, des paroles dont ils ne saisissaient pas le sens.'),
  (42, 18, 35, 'Comme Jésus approchait de Jéricho, un aveugle était assis au bord du chemin, et mendiait.'),
  (42, 18, 36, 'Entendant la foule passer, il demanda ce que c''était.'),
  (42, 18, 37, 'On lui dit: C''est Jésus de Nazareth qui passe.'),
  (42, 18, 38, 'Et il cria: Jésus, Fils de David, aie pitié de moi!'),
  (42, 18, 39, 'Ceux qui marchaient devant le reprenaient, pour le faire taire; mais il criait beaucoup plus fort: Fils de David, aie pitié de moi!'),
  (42, 18, 40, 'Jésus, s''étant arrêté, ordonna qu''on le lui amène; et, quand il se fut approché, il lui demanda:'),
  (42, 18, 41, 'Que veux-tu que je te fasse? Il répondit: Seigneur, que je recouvre la vue.'),
  (42, 18, 42, 'Et Jésus lui dit: Recouvre la vue; ta foi t''a sauvé.'),
  (42, 18, 43, 'A l''instant il recouvra la vue, et suivit Jésus, en glorifiant Dieu. Tout le peuple, voyant cela, loua Dieu.'),
  (42, 19, 1, 'Jésus, étant entré dans Jéricho, traversait la ville.'),
  (42, 19, 2, 'Et voici, un homme riche, appelé Zachée, chef des publicains,'),
  (42, 19, 3, 'cherchait à voir qui était Jésus; mais il ne pouvait y parvenir, à cause de la foule, car il était de petite taille.'),
  (42, 19, 4, 'Il courut en avant, et monta sur un sycomore pour le voir, parce qu''il devait passer par là.'),
  (42, 19, 5, 'Lorsque Jésus fut arrivé à cet endroit, il leva les yeux et lui dit: Zachée, hâte-toi de descendre; car il faut que je demeure aujourd''hui dans ta maison.'),
  (42, 19, 6, 'Zachée se hâta de descendre, et le reçut avec joie.'),
  (42, 19, 7, 'Voyant cela, tous murmuraient, et disaient: Il est allé loger chez un homme pécheur.'),
  (42, 19, 8, 'Mais Zachée, se tenant devant le Seigneur, lui dit: Voici, Seigneur, je donne aux pauvres la moitié de mes biens, et, si j''ai fait tort de quelque chose à quelqu''un, je lui rends le quadruple.'),
  (42, 19, 9, 'Jésus lui dit: Le salut est entré aujourd''hui dans cette maison, parce que celui-ci est aussi un fils d''Abraham.'),
  (42, 19, 10, 'Car le Fils de l''homme est venu chercher et sauver ce qui était perdu.'),
  (42, 19, 11, 'Ils écoutaient ces choses, et Jésus ajouta une parabole, parce qu''il était près de Jérusalem, et qu''on croyait qu''à l''instant le royaume de Dieu allait paraître.'),
  (42, 19, 12, 'Il dit donc: Un homme de haute naissance s''en alla dans un pays lointain, pour se faire investir de l''autorité royale, et revenir ensuite.'),
  (42, 19, 13, 'Il appela dix de ses serviteurs, leur donna dix mines, et leur dit: Faites-les valoir jusqu''à ce que je revienne.'),
  (42, 19, 14, 'Mais ses concitoyens le haïssaient, et ils envoyèrent une ambassade après lui, pour dire: Nous ne voulons pas que cet homme règne sur nous.'),
  (42, 19, 15, 'Lorsqu''il fut de retour, après avoir été investi de l''autorité royale, il fit appeler auprès de lui les serviteurs auxquels il avait donné l''argent, afin de connaître comment chacun l''avait fait valoir.'),
  (42, 19, 16, 'Le premier vint, et dit: Seigneur, ta mine a rapporté dix mines.'),
  (42, 19, 17, 'Il lui dit: C''est bien, bon serviteur; parce que tu as été fidèle en peu de chose, reçois le gouvernement de dix villes.'),
  (42, 19, 18, 'Le second vint, et dit: Seigneur, ta mine a produit cinq mines.'),
  (42, 19, 19, 'Il lui dit: Toi aussi, sois établi sur cinq villes.'),
  (42, 19, 20, 'Un autre vint, et dit: Seigneur, voici ta mine, que j''ai gardée dans un linge;'),
  (42, 19, 21, 'car j''avais peur de toi, parce que tu es un homme sévère; tu prends ce que tu n''as pas déposé, et tu moissonnes ce que tu n''as pas semé.'),
  (42, 19, 22, 'Il lui dit: Je te juge sur tes paroles, méchant serviteur; tu savais que je suis un homme sévère, prenant ce que je n''ai pas déposé, et moissonnant ce que je n''ai pas semé;'),
  (42, 19, 23, 'pourquoi donc n''as-tu pas mis mon argent dans une banque, afin qu''à mon retour je le retirasse avec un intérêt?'),
  (42, 19, 24, 'Puis il dit à ceux qui étaient là: Otez-lui la mine, et donnez-la à celui qui a les dix mines.'),
  (42, 19, 25, 'Ils lui dirent: Seigneur, il a dix mines. -'),
  (42, 19, 26, 'Je vous le dis, on donnera à celui qui a, mais à celui qui n''a pas on ôtera même ce qu''il a.'),
  (42, 19, 27, 'Au reste, amenez ici mes ennemis, qui n''ont pas voulu que je régnasse sur eux, et tuez-les en ma présence.'),
  (42, 19, 28, 'Après avoir ainsi parlé, Jésus marcha devant la foule, pour monter à Jérusalem.'),
  (42, 19, 29, 'Lorsqu''il approcha de Bethphagé et de Béthanie, vers la montagne appelée montagne des Oliviers, Jésus envoya deux de ses disciples,'),
  (42, 19, 30, 'en disant: Allez au village qui est en face; quand vous y serez entrés, vous trouverez un ânon attaché, sur lequel aucun homme ne s''est jamais assis; détachez-le, et amenez-le.'),
  (42, 19, 31, 'Si quelqu''un vous demande: Pourquoi le détachez-vous? vous lui répondrez: Le Seigneur en a besoin.'),
  (42, 19, 32, 'Ceux qui étaient envoyés allèrent, et trouvèrent les choses comme Jésus leur avait dit.'),
  (42, 19, 33, 'Comme ils détachaient l''ânon, ses maîtres leur dirent: Pourquoi détachez-vous l''ânon?'),
  (42, 19, 34, 'Ils répondirent: Le Seigneur en a besoin.'),
  (42, 19, 35, 'Et ils amenèrent à Jésus l''ânon, sur lequel ils jetèrent leurs vêtements, et firent monter Jésus.'),
  (42, 19, 36, 'Quand il fut en marche, les gens étendirent leurs vêtements sur le chemin.'),
  (42, 19, 37, 'Et lorsque déjà il approchait de Jérusalem, vers la descente de la montagne des Oliviers, toute la multitude des disciples, saisie de joie, se mit à louer Dieu à haute voix pour tous les miracles qu''ils avaient vus.'),
  (42, 19, 38, 'Ils disaient: Béni soit le roi qui vient au nom du Seigneur! Paix dans le ciel, et gloire dans les lieux très hauts!'),
  (42, 19, 39, 'Quelques pharisiens, du milieu de la foule, dirent à Jésus: Maître, reprends tes disciples.'),
  (42, 19, 40, 'Et il répondit: Je vous le dis, s''ils se taisent, les pierres crieront!'),
  (42, 19, 41, 'Comme il approchait de la ville, Jésus, en la voyant, pleura sur elle,'),
  (42, 19, 42, 'et dit: Si toi aussi, au moins en ce jour qui t''est donné, tu connaissais les choses qui appartiennent à ta paix! Mais maintenant elles sont cachées à tes yeux.'),
  (42, 19, 43, 'Il viendra sur toi des jours où tes ennemis t''environneront de tranchées, t''enfermeront, et te serreront de toutes parts;'),
  (42, 19, 44, 'ils te détruiront, toi et tes enfants au milieu de toi, et ils ne laisseront pas en toi pierre sur pierre, parce que tu n''as pas connu le temps où tu as été visitée.'),
  (42, 19, 45, 'Il entra dans le temple, et il se mit à chasser ceux qui vendaient,'),
  (42, 19, 46, 'leur disant: Il est écrit: Ma maison sera une maison de prière. Mais vous, vous en avez fait une caverne de voleurs.'),
  (42, 19, 47, 'Il enseignait tous les jours dans le temple. Et les principaux sacrificateurs, les scribes, et les principaux du peuple cherchaient à le faire périr;'),
  (42, 19, 48, 'mais ils ne savaient comment s''y prendre, car tout le peuple l''écoutait avec admiration.'),
  (42, 20, 1, 'Un de ces jours-là, comme Jésus enseignait le peuple dans le temple et qu''il annonçait la bonne nouvelle, les principaux sacrificateurs et les scribes, avec les anciens, survinrent,'),
  (42, 20, 2, 'et lui dirent: Dis-nous, par quelle autorité fais-tu ces choses, ou qui est celui qui t''a donné cette autorité?'),
  (42, 20, 3, 'Il leur répondit: Je vous adresserai aussi une question. Dites-moi,'),
  (42, 20, 4, 'le baptême de Jean venait-il du ciel, ou des hommes?'),
  (42, 20, 5, 'Mais ils raisonnèrent ainsi entre eux: Si nous répondons: Du ciel, il dira: Pourquoi n''avez-vous pas cru en lui?'),
  (42, 20, 6, 'Et si nous répondons: Des hommes, tout le peuple nous lapidera, car il est persuadé que Jean était un prophète.'),
  (42, 20, 7, 'Alors ils répondirent qu''ils ne savaient d''où il venait.'),
  (42, 20, 8, 'Et Jésus leur dit: Moi non plus, je ne vous dirai pas par quelle autorité je fais ces choses.'),
  (42, 20, 9, 'Il se mit ensuite à dire au peuple cette parabole: Un homme planta une vigne, l''afferma à des vignerons, et quitta pour longtemps le pays.'),
  (42, 20, 10, 'Au temps de la récolte, il envoya un serviteur vers les vignerons, pour qu''ils lui donnent une part du produit de la vigne. Les vignerons le battirent, et le renvoyèrent à vide.'),
  (42, 20, 11, 'Il envoya encore un autre serviteur; ils le battirent, l''outragèrent, et le renvoyèrent à vide.'),
  (42, 20, 12, 'Il en envoya encore un troisième; ils le blessèrent, et le chassèrent.'),
  (42, 20, 13, 'Le maître de la vigne dit: Que ferai-je? J''enverrai mon fils bien-aimé; peut-être auront-ils pour lui du respect.'),
  (42, 20, 14, 'Mais, quand les vignerons le virent, ils raisonnèrent entre eux, et dirent: Voici l''héritier; tuons-le, afin que l''héritage soit à nous.'),
  (42, 20, 15, 'Et ils le jetèrent hors de la vigne, et le tuèrent. Maintenant, que leur fera le maître de la vigne?'),
  (42, 20, 16, 'Il viendra, fera périr ces vignerons, et il donnera la vigne à d''autres. Lorsqu''ils eurent entendu cela, ils dirent: A Dieu ne plaise!'),
  (42, 20, 17, 'Mais, jetant les regards sur eux, Jésus dit: Que signifie donc ce qui est écrit: La pierre qu''ont rejetée ceux qui bâtissaient Est devenue la principale de l''angle?'),
  (42, 20, 18, 'Quiconque tombera sur cette pierre s''y brisera, et celui sur qui elle tombera sera écrasé.'),
  (42, 20, 19, 'Les principaux sacrificateurs et les scribes cherchèrent à mettre la main sur lui à l''heure même, mais ils craignirent le peuple. Ils avaient compris que c''était pour eux que Jésus avait dit cette parabole.'),
  (42, 20, 20, 'Ils se mirent à observer Jésus; et ils envoyèrent des gens qui feignaient d''être justes, pour lui tendre des pièges et saisir de lui quelque parole, afin de le livrer au magistrat et à l''autorité du gouverneur.'),
  (42, 20, 21, 'Ces gens lui posèrent cette question: Maître, nous savons que tu parles et enseignes droitement, et que tu ne regardes pas à l''apparence, mais que tu enseignes la voie de Dieu selon la vérité.'),
  (42, 20, 22, 'Nous est-il permis, ou non, de payer le tribut à César?'),
  (42, 20, 23, 'Jésus, apercevant leur ruse, leur répondit:'),
  (42, 20, 24, 'Montrez-moi un denier. De qui porte-t-il l''effigie et l''inscription? De César, répondirent-ils.'),
  (42, 20, 25, 'Alors il leur dit: Rendez donc à César ce qui est à César, et à Dieu ce qui est à Dieu.'),
  (42, 20, 26, 'Ils ne purent rien reprendre dans ses paroles devant le peuple; mais, étonnés de sa réponse, ils gardèrent le silence.'),
  (42, 20, 27, 'Quelques-uns des sadducéens, qui disent qu''il n''y a point de résurrection, s''approchèrent, et posèrent à Jésus cette question:'),
  (42, 20, 28, 'Maître, voici ce que Moïse nous a prescrit: Si le frère de quelqu''un meurt, ayant une femme sans avoir d''enfants, son frère épousera la femme, et suscitera une postérité à son frère.'),
  (42, 20, 29, 'Or, il y avait sept frères. Le premier se maria, et mourut sans enfants.'),
  (42, 20, 30, 'Le second et le troisième épousèrent la veuve;'),
  (42, 20, 31, 'il en fut de même des sept, qui moururent sans laisser d''enfants.'),
  (42, 20, 32, 'Enfin, la femme mourut aussi.'),
  (42, 20, 33, 'A la résurrection, duquel d''entre eux sera-t-elle donc la femme? Car les sept l''ont eue pour femme.'),
  (42, 20, 34, 'Jésus leur répondit: Les enfants de ce siècle prennent des femmes et des maris;'),
  (42, 20, 35, 'mais ceux qui seront trouvés dignes d''avoir part au siècle à venir et à la résurrection des morts ne prendront ni femmes ni maris.'),
  (42, 20, 36, 'Car ils ne pourront plus mourir, parce qu''ils seront semblables aux anges, et qu''ils seront fils de Dieu, étant fils de la résurrection.'),
  (42, 20, 37, 'Que les morts ressuscitent, c''est ce que Moïse a fait connaître quand, à propos du buisson, il appelle le Seigneur le Dieu d''Abraham, le Dieu d''Isaac, et le Dieu de Jacob.'),
  (42, 20, 38, 'Or, Dieu n''est pas Dieu des morts, mais des vivants; car pour lui tous sont vivants.'),
  (42, 20, 39, 'Quelques-uns des scribes, prenant la parole, dirent: Maître, tu as bien parlé.'),
  (42, 20, 40, 'Et ils n''osaient plus lui faire aucune question.'),
  (42, 20, 41, 'Jésus leur dit: Comment dit-on que le Christ est fils de David?'),
  (42, 20, 42, 'David lui-même dit dans le livre des Psaumes: Le Seigneur a dit à mon Seigneur: Assieds-toi à ma droite,'),
  (42, 20, 43, 'Jusqu''à ce que je fasse de tes ennemis ton marchepied.'),
  (42, 20, 44, 'David donc l''appelle Seigneur; comment est-il son fils?'),
  (42, 20, 45, 'Tandis que tout le peuple l''écoutait, il dit à ses disciples:'),
  (42, 20, 46, 'Gardez-vous des scribes, qui aiment à se promener en robes longues, et à être salués dans les places publiques; qui recherchent les premiers sièges dans les synagogues, et les premières places dans les festins;'),
  (42, 20, 47, 'qui dévorent les maisons des veuves, et qui font pour l''apparence de longues prières. Ils seront jugés plus sévèrement.'),
  (42, 21, 1, 'Jésus, ayant levé les yeux, vit les riches qui mettaient leurs offrandes dans le tronc.'),
  (42, 21, 2, 'Il vit aussi une pauvre veuve, qui y mettait deux petites pièces.'),
  (42, 21, 3, 'Et il dit: Je vous le dis en vérité, cette pauvre veuve a mis plus que tous les autres;'),
  (42, 21, 4, 'car c''est de leur superflu que tous ceux-là ont mis des offrandes dans le tronc, mais elle a mis de son nécessaire, tout ce qu''elle avait pour vivre.'),
  (42, 21, 5, 'Comme quelques-uns parlaient des belles pierres et des offrandes qui faisaient l''ornement du temple, Jésus dit:'),
  (42, 21, 6, 'Les jours viendront où, de ce que vous voyez, il ne restera pas pierre sur pierre qui ne soit renversée.'),
  (42, 21, 7, 'Ils lui demandèrent: Maître, quand donc cela arrivera-t-il, et à quel signe connaîtra-t-on que ces choses vont arriver?'),
  (42, 21, 8, 'Jésus répondit: Prenez garde que vous ne soyez séduits. Car plusieurs viendront en mon nom, disant: C''est moi, et le temps approche. Ne les suivez pas.'),
  (42, 21, 9, 'Quand vous entendrez parler de guerres et de soulèvements, ne soyez pas effrayés, car il faut que ces choses arrivent premièrement. Mais ce ne sera pas encore la fin.'),
  (42, 21, 10, 'Alors il leur dit: Une nation s''élèvera contre une nation, et un royaume contre un royaume;'),
  (42, 21, 11, 'il y aura de grands tremblements de terre, et, en divers lieux, des pestes et des famines; il y aura des phénomènes terribles, et de grands signes dans le ciel.'),
  (42, 21, 12, 'Mais, avant tout cela, on mettra la main sur vous, et l''on vous persécutera; on vous livrera aux synagogues, on vous jettera en prison, on vous mènera devant des rois et devant des gouverneurs, à cause de mon nom.'),
  (42, 21, 13, 'Cela vous arrivera pour que vous serviez de témoignage.'),
  (42, 21, 14, 'Mettez-vous donc dans l''esprit de ne pas préméditer votre défense;'),
  (42, 21, 15, 'car je vous donnerai une bouche et une sagesse à laquelle tous vos adversaires ne pourront résister ou contredire.'),
  (42, 21, 16, 'Vous serez livrés même par vos parents, par vos frères, par vos proches et par vos amis, et ils feront mourir plusieurs d''entre vous.'),
  (42, 21, 17, 'Vous serez haïs de tous, à cause de mon nom.'),
  (42, 21, 18, 'Mais il ne se perdra pas un cheveu de votre tête;'),
  (42, 21, 19, 'par votre persévérance vous sauverez vos âmes.'),
  (42, 21, 20, 'Lorsque vous verrez Jérusalem investie par des armées, sachez alors que sa désolation est proche.'),
  (42, 21, 21, 'Alors, que ceux qui seront en Judée fuient dans les montagnes, que ceux qui seront au milieu de Jérusalem en sortent, et que ceux qui seront dans les champs n''entrent pas dans la ville.'),
  (42, 21, 22, 'Car ce seront des jours de vengeance, pour l''accomplissement de tout ce qui est écrit.'),
  (42, 21, 23, 'Malheur aux femmes qui seront enceintes et à celles qui allaiteront en ces jours-là! Car il y aura une grande détresse dans le pays, et de la colère contre ce peuple.'),
  (42, 21, 24, 'Ils tomberont sous le tranchant de l''épée, ils seront emmenés captifs parmi toutes les nations, et Jérusalem sera foulée aux pieds par les nations, jusqu''à ce que les temps des nations soient accomplis.'),
  (42, 21, 25, 'Il y aura des signes dans le soleil, dans la lune et dans les étoiles. Et sur la terre, il y aura de l''angoisse chez les nations qui ne sauront que faire, au bruit de la mer et des flots,'),
  (42, 21, 26, 'les hommes rendant l''âme de terreur dans l''attente de ce qui surviendra pour la terre; car les puissances des cieux seront ébranlées.'),
  (42, 21, 27, 'Alors on verra le Fils de l''homme venant sur une nuée avec puissance et une grande gloire.'),
  (42, 21, 28, 'Quand ces choses commenceront à arriver, redressez-vous et levez vos têtes, parce que votre délivrance approche.'),
  (42, 21, 29, 'Et il leur dit une comparaison: Voyez le figuier, et tous les arbres.'),
  (42, 21, 30, 'Dès qu''ils ont poussé, vous connaissez de vous-mêmes, en regardant, que déjà l''été est proche.'),
  (42, 21, 31, 'De même, quand vous verrez ces choses arriver, sachez que le royaume de Dieu est proche.'),
  (42, 21, 32, 'Je vous le dis en vérité, cette génération ne passera point, que tout cela n''arrive.'),
  (42, 21, 33, 'Le ciel et la terre passeront, mais mes paroles ne passeront point.'),
  (42, 21, 34, 'Prenez garde à vous-mêmes, de crainte que vos cœurs ne s''appesantissent par les excès du manger et du boire, et par les soucis de la vie, et que ce jour ne vienne sur vous à l''improviste;'),
  (42, 21, 35, 'car il viendra comme un filet sur tous ceux qui habitent sur la face de toute la terre.'),
  (42, 21, 36, 'Veillez donc et priez en tout temps, afin que vous ayez la force d''échapper à toutes ces choses qui arriveront, et de paraître debout devant le Fils de l''homme.'),
  (42, 21, 37, 'Pendant le jour, Jésus enseignait dans le temple, et il allait passer la nuit à la montagne appelée montagne des Oliviers.'),
  (42, 21, 38, 'Et tout le peuple, dès le matin, se rendait vers lui dans le temple pour l''écouter.'),
  (42, 22, 1, 'La fête des pains sans levain, appelée la Pâque, approchait.'),
  (42, 22, 2, 'Les principaux sacrificateurs et les scribes cherchaient les moyens de faire mourir Jésus; car ils craignaient le peuple.'),
  (42, 22, 3, 'Or, Satan entra dans Judas, surnommé Iscariot, qui était du nombre des douze.'),
  (42, 22, 4, 'Et Judas alla s''entendre avec les principaux sacrificateurs et les chefs des gardes, sur la manière de le leur livrer.'),
  (42, 22, 5, 'Ils furent dans la joie, et ils convinrent de lui donner de l''argent.'),
  (42, 22, 6, 'Après s''être engagé, il cherchait une occasion favorable pour leur livrer Jésus à l''insu de la foule.'),
  (42, 22, 7, 'Le jour des pains sans levain, où l''on devait immoler la Pâque, arriva,'),
  (42, 22, 8, 'et Jésus envoya Pierre et Jean, en disant: Allez nous préparer la Pâque, afin que nous la mangions.'),
  (42, 22, 9, 'Ils lui dirent: Où veux-tu que nous la préparions?'),
  (42, 22, 10, 'Il leur répondit: Voici, quand vous serez entrés dans la ville, vous rencontrerez un homme portant une cruche d''eau; suivez-le dans la maison où il entrera,'),
  (42, 22, 11, 'et vous direz au maître de la maison: Le maître te dit: Où est le lieu où je mangerai la Pâque avec mes disciples?'),
  (42, 22, 12, 'Et il vous montrera une grande chambre haute, meublée: c''est là que vous préparerez la Pâque.'),
  (42, 22, 13, 'Ils partirent, et trouvèrent les choses comme il le leur avait dit; et ils préparèrent la Pâque.'),
  (42, 22, 14, 'L''heure étant venue, il se mit à table, et les apôtres avec lui.'),
  (42, 22, 15, 'Il leur dit: J''ai désiré vivement manger cette Pâque avec vous, avant de souffrir;'),
  (42, 22, 16, 'car, je vous le dis, je ne la mangerai plus, jusqu''à ce qu''elle soit accomplie dans le royaume de Dieu.'),
  (42, 22, 17, 'Et, ayant pris une coupe et rendu grâces, il dit: Prenez cette coupe, et distribuez-la entre vous;'),
  (42, 22, 18, 'car, je vous le dis, je ne boirai plus désormais du fruit de la vigne, jusqu''à ce que le royaume de Dieu soit venu.'),
  (42, 22, 19, 'Ensuite il prit du pain; et, après avoir rendu grâces, il le rompit, et le leur donna, en disant: Ceci est mon corps, qui est donné pour vous; faites ceci en mémoire de moi.'),
  (42, 22, 20, 'Il prit de même la coupe, après le souper, et la leur donna, en disant: Cette coupe est la nouvelle alliance en mon sang, qui est répandu pour vous.'),
  (42, 22, 21, 'Cependant voici, la main de celui qui me livre est avec moi à cette table.'),
  (42, 22, 22, 'Le Fils de l''homme s''en va selon ce qui est déterminé. Mais malheur à l''homme par qui il est livré!'),
  (42, 22, 23, 'Et ils commencèrent à se demander les uns aux autres qui était celui d''entre eux qui ferait cela.'),
  (42, 22, 24, 'Il s''éleva aussi parmi les apôtres une contestation: lequel d''entre eux devait être estimé le plus grand?'),
  (42, 22, 25, 'Jésus leur dit: Les rois des nations les maîtrisent, et ceux qui les dominent sont appelés bienfaiteurs.'),
  (42, 22, 26, 'Qu''il n''en soit pas de même pour vous. Mais que le plus grand parmi vous soit comme le plus petit, et celui qui gouverne comme celui qui sert.'),
  (42, 22, 27, 'Car quel est le plus grand, celui qui est à table, ou celui qui sert? N''est-ce pas celui qui est à table? Et moi, cependant, je suis au milieu de vous comme celui qui sert.'),
  (42, 22, 28, 'Vous, vous êtes ceux qui avez persévéré avec moi dans mes épreuves;'),
  (42, 22, 29, 'c''est pourquoi je dispose du royaume en votre faveur, comme mon Père en a disposé en ma faveur,'),
  (42, 22, 30, 'afin que vous mangiez et buviez à ma table dans mon royaume, et que vous soyez assis sur des trônes, pour juger les douze tribus d''Israël.'),
  (42, 22, 31, 'Le Seigneur dit: Simon, Simon, Satan vous a réclamés, pour vous cribler comme le froment.'),
  (42, 22, 32, 'Mais j''ai prié pour toi, afin que ta foi ne défaille point; et toi, quand tu seras converti, affermis tes frères.'),
  (42, 22, 33, 'Seigneur, lui dit Pierre, je suis prêt à aller avec toi et en prison et à la mort.'),
  (42, 22, 34, 'Et Jésus dit: Pierre, je te le dis, le coq ne chantera pas aujourd''hui que tu n''aies nié trois fois de me connaître.'),
  (42, 22, 35, 'Il leur dit encore: Quand je vous ai envoyés sans bourse, sans sac, et sans souliers, avez-vous manqué de quelque chose? Ils répondirent: De rien.'),
  (42, 22, 36, 'Et il leur dit: Maintenant, au contraire, que celui qui a une bourse la prenne et que celui qui a un sac le prenne également, que celui qui n''a point d''épée vende son vêtement et achète une épée.'),
  (42, 22, 37, 'Car, je vous le dis, il faut que cette parole qui est écrite s''accomplisse en moi: Il a été mis au nombre des malfaiteurs. Et ce qui me concerne est sur le point d''arriver.'),
  (42, 22, 38, 'Ils dirent: Seigneur, voici deux épées. Et il leur dit: Cela suffit.'),
  (42, 22, 39, 'Après être sorti, il alla, selon sa coutume, à la montagne des Oliviers. Ses disciples le suivirent.'),
  (42, 22, 40, 'Lorsqu''il fut arrivé dans ce lieu, il leur dit: Priez, afin que vous ne tombiez pas en tentation.'),
  (42, 22, 41, 'Puis il s''éloigna d''eux à la distance d''environ un jet de pierre, et, s''étant mis à genoux, il pria,'),
  (42, 22, 42, 'disant: Père, si tu voulais éloigner de moi cette coupe! Toutefois, que ma volonté ne se fasse pas, mais la tienne.'),
  (42, 22, 43, 'Alors un ange lui apparut du ciel, pour le fortifier.'),
  (42, 22, 44, 'Étant en agonie, il priait plus instamment, et sa sueur devint comme des grumeaux de sang, qui tombaient à terre.'),
  (42, 22, 45, 'Après avoir prié, il se leva, et vint vers les disciples, qu''il trouva endormis de tristesse,'),
  (42, 22, 46, 'et il leur dit: Pourquoi dormez-vous? Levez-vous et priez, afin que vous ne tombiez pas en tentation.'),
  (42, 22, 47, 'Comme il parlait encore, voici, une foule arriva; et celui qui s''appelait Judas, l''un des douze, marchait devant elle. Il s''approcha de Jésus, pour le baiser.'),
  (42, 22, 48, 'Et Jésus lui dit: Judas, c''est par un baiser que tu livres le Fils de l''homme!'),
  (42, 22, 49, 'Ceux qui étaient avec Jésus, voyant ce qui allait arriver, dirent: Seigneur, frapperons-nous de l''épée?'),
  (42, 22, 50, 'Et l''un d''eux frappa le serviteur du souverain sacrificateur, et lui emporta l''oreille droite.'),
  (42, 22, 51, 'Mais Jésus, prenant la parole, dit: Laissez, arrêtez! Et, ayant touché l''oreille de cet homme, il le guérit.'),
  (42, 22, 52, 'Jésus dit ensuite aux principaux sacrificateurs, aux chefs des gardes du temple, et aux anciens, qui étaient venus contre lui: Vous êtes venus, comme après un brigand, avec des épées et des bâtons.'),
  (42, 22, 53, 'J''étais tous les jours avec vous dans le temple, et vous n''avez pas mis la main sur moi. Mais c''est ici votre heure, et la puissance des ténèbres.'),
  (42, 22, 54, 'Après avoir saisi Jésus, ils l''emmenèrent, et le conduisirent dans la maison du souverain sacrificateur. Pierre suivait de loin.'),
  (42, 22, 55, 'Ils allumèrent du feu au milieu de la cour, et ils s''assirent. Pierre s''assit parmi eux.'),
  (42, 22, 56, 'Une servante, qui le vit assis devant le feu, fixa sur lui les regards, et dit: Cet homme était aussi avec lui.'),
  (42, 22, 57, 'Mais il le nia disant: Femme, je ne le connais pas.'),
  (42, 22, 58, 'Peu après, un autre, l''ayant vu, dit: Tu es aussi de ces gens-là. Et Pierre dit: Homme, je n''en suis pas.'),
  (42, 22, 59, 'Environ une heure plus tard, un autre insistait, disant: Certainement cet homme était aussi avec lui, car il est Galiléen.'),
  (42, 22, 60, 'Pierre répondit: Homme, je ne sais ce que tu dis. Au même instant, comme il parlait encore, le coq chanta.'),
  (42, 22, 61, 'Le Seigneur, s''étant retourné, regarda Pierre. Et Pierre se souvint de la parole que le Seigneur lui avait dite: Avant que le coq chante aujourd''hui, tu me renieras trois fois.'),
  (42, 22, 62, 'Et étant sorti, il pleura amèrement.'),
  (42, 22, 63, 'Les hommes qui tenaient Jésus se moquaient de lui, et le frappaient.'),
  (42, 22, 64, 'Ils lui voilèrent le visage, et ils l''interrogeaient, en disant: Devine qui t''a frappé.'),
  (42, 22, 65, 'Et ils proféraient contre lui beaucoup d''autres injures.'),
  (42, 22, 66, 'Quand le jour fut venu, le collège des anciens du peuple, les principaux sacrificateurs et les scribes, s''assemblèrent, et firent amener Jésus dans leur sanhédrin. Ils dirent:'),
  (42, 22, 67, 'Si tu es le Christ, dis-le nous. Jésus leur répondit: Si je vous le dis, vous ne le croirez pas;'),
  (42, 22, 68, 'et, si je vous interroge, vous ne répondrez pas.'),
  (42, 22, 69, 'Désormais le Fils de l''homme sera assis à la droite de la puissance de Dieu.'),
  (42, 22, 70, 'Tous dirent: Tu es donc le Fils de Dieu? Et il leur répondit: Vous le dites, je le suis.'),
  (42, 22, 71, 'Alors ils dirent: Qu''avons-nous encore besoin de témoignage? Nous l''avons entendu nous-mêmes de sa bouche.'),
  (42, 23, 1, 'Ils se levèrent tous, et ils conduisirent Jésus devant Pilate.'),
  (42, 23, 2, 'Ils se mirent à l''accuser, disant: Nous avons trouvé cet homme excitant notre nation à la révolte, empêchant de payer le tribut à César, et se disant lui-même Christ, roi.'),
  (42, 23, 3, 'Pilate l''interrogea, en ces termes: Es-tu le roi des Juifs? Jésus lui répondit: Tu le dis.'),
  (42, 23, 4, 'Pilate dit aux principaux sacrificateurs et à la foule: Je ne trouve rien de coupable en cet homme.'),
  (42, 23, 5, 'Mais ils insistèrent, et dirent: Il soulève le peuple, en enseignant par toute la Judée, depuis la Galilée, où il a commencé, jusqu''ici.'),
  (42, 23, 6, 'Quand Pilate entendit parler de la Galilée, il demanda si cet homme était Galiléen;'),
  (42, 23, 7, 'et, ayant appris qu''il était de la juridiction d''Hérode, il le renvoya à Hérode, qui se trouvait aussi à Jérusalem en ces jours-là.'),
  (42, 23, 8, 'Lorsque Hérode vit Jésus, il en eut une grande joie; car depuis longtemps, il désirait le voir, à cause de ce qu''il avait entendu dire de lui, et il espérait qu''il le verrait faire quelque miracle.'),
  (42, 23, 9, 'Il lui adressa beaucoup de questions; mais Jésus ne lui répondit rien.'),
  (42, 23, 10, 'Les principaux sacrificateurs et les scribes étaient là, et l''accusaient avec violence.'),
  (42, 23, 11, 'Hérode, avec ses gardes, le traita avec mépris; et, après s''être moqué de lui et l''avoir revêtu d''un habit éclatant, il le renvoya à Pilate.'),
  (42, 23, 12, 'Ce jour même, Pilate et Hérode devinrent amis, d''ennemis qu''ils étaient auparavant.'),
  (42, 23, 13, 'Pilate, ayant assemblé les principaux sacrificateurs, les magistrats, et le peuple,'),
  (42, 23, 14, 'leur dit: Vous m''avez amené cet homme comme excitant le peuple à la révolte. Et voici, je l''ai interrogé devant vous, et je ne l''ai trouvé coupable d''aucune des choses dont vous l''accusez;'),
  (42, 23, 15, 'Hérode non plus, car il nous l''a renvoyé, et voici, cet homme n''a rien fait qui soit digne de mort.'),
  (42, 23, 16, 'Je le relâcherai donc, après l''avoir fait battre de verges.'),
  (42, 23, 17, 'A chaque fête, il était obligé de leur relâcher un prisonnier.'),
  (42, 23, 18, 'Ils s''écrièrent tous ensemble: Fais mourir celui-ci, et relâche-nous Barabbas.'),
  (42, 23, 19, 'Cet homme avait été mis en prison pour une sédition qui avait eu lieu dans la ville, et pour un meurtre.'),
  (42, 23, 20, 'Pilate leur parla de nouveau, dans l''intention de relâcher Jésus.'),
  (42, 23, 21, 'Et ils crièrent: Crucifie, crucifie-le!'),
  (42, 23, 22, 'Pilate leur dit pour la troisième fois: Quel mal a-t-il fait? Je n''ai rien trouvé en lui qui mérite la mort. Je le relâcherai donc, après l''avoir fait battre de verges.'),
  (42, 23, 23, 'Mais ils insistèrent à grands cris, demandant qu''il fût crucifié. Et leurs cris l''emportèrent:'),
  (42, 23, 24, 'Pilate prononça que ce qu''ils demandaient serait fait.'),
  (42, 23, 25, 'Il relâcha celui qui avait été mis en prison pour sédition et pour meurtre, et qu''ils réclamaient; et il livra Jésus à leur volonté.'),
  (42, 23, 26, 'Comme ils l''emmenaient, ils prirent un certain Simon de Cyrène, qui revenait des champs, et ils le chargèrent de la croix, pour qu''il la porte derrière Jésus.'),
  (42, 23, 27, 'Il était suivi d''une grande multitude des gens du peuple, et de femmes qui se frappaient la poitrine et se lamentaient sur lui.'),
  (42, 23, 28, 'Jésus se tourna vers elles, et dit: Filles de Jérusalem, ne pleurez pas sur moi; mais pleurez sur vous et sur vos enfants.'),
  (42, 23, 29, 'Car voici, des jours viendront où l''on dira: Heureuses les stériles, heureuses les entrailles qui n''ont point enfanté, et les mamelles qui n''ont point allaité!'),
  (42, 23, 30, 'Alors ils se mettront à dire aux montagnes: Tombez sur nous! Et aux collines: Couvrez-nous!'),
  (42, 23, 31, 'Car, si l''on fait ces choses au bois vert, qu''arrivera-t-il au bois sec?'),
  (42, 23, 32, 'On conduisait en même temps deux malfaiteurs, qui devaient être mis à mort avec Jésus.'),
  (42, 23, 33, 'Lorsqu''ils furent arrivés au lieu appelé Crâne, ils le crucifièrent là, ainsi que les deux malfaiteurs, l''un à droite, l''autre à gauche.'),
  (42, 23, 34, 'Jésus dit: Père, pardonne-leur, car ils ne savent ce qu''ils font. Ils se partagèrent ses vêtements, en tirant au sort.'),
  (42, 23, 35, 'Le peuple se tenait là, et regardait. Les magistrats se moquaient de Jésus, disant: Il a sauvé les autres; qu''il se sauve lui-même, s''il est le Christ, l''élu de Dieu!'),
  (42, 23, 36, 'Les soldats aussi se moquaient de lui; s''approchant et lui présentant du vinaigre,'),
  (42, 23, 37, 'ils disaient: Si tu es le roi des Juifs, sauve-toi toi-même!'),
  (42, 23, 38, 'Il y avait au-dessus de lui cette inscription: Celui-ci est le roi des Juifs.'),
  (42, 23, 39, 'L''un des malfaiteurs crucifiés l''injuriait, disant: N''es-tu pas le Christ? Sauve-toi toi-même, et sauve-nous!'),
  (42, 23, 40, 'Mais l''autre le reprenait, et disait: Ne crains-tu pas Dieu, toi qui subis la même condamnation?'),
  (42, 23, 41, 'Pour nous, c''est justice, car nous recevons ce qu''ont mérité nos crimes; mais celui-ci n''a rien fait de mal.'),
  (42, 23, 42, 'Et il dit à Jésus: Souviens-toi de moi, quand tu viendras dans ton règne.'),
  (42, 23, 43, 'Jésus lui répondit: Je te le dis en vérité, aujourd''hui tu seras avec moi dans le paradis.'),
  (42, 23, 44, 'Il était déjà environ la sixième heure, et il y eut des ténèbres sur toute la terre, jusqu''à la neuvième heure.'),
  (42, 23, 45, 'Le soleil s''obscurcit, et le voile du temple se déchira par le milieu.'),
  (42, 23, 46, 'Jésus s''écria d''une voix forte: Père, je remets mon esprit entre tes mains. Et, en disant ces paroles, il expira.'),
  (42, 23, 47, 'Le centenier, voyant ce qui était arrivé, glorifia Dieu, et dit: Certainement, cet homme était juste.'),
  (42, 23, 48, 'Et tous ceux qui assistaient en foule à ce spectacle, après avoir vu ce qui était arrivé, s''en retournèrent, se frappant la poitrine.'),
  (42, 23, 49, 'Tous ceux de la connaissance de Jésus, et les femmes qui l''avaient accompagné depuis la Galilée, se tenaient dans l''éloignement et regardaient ce qui se passait.'),
  (42, 23, 50, 'Il y avait un conseiller, nommé Joseph, homme bon et juste,'),
  (42, 23, 51, 'qui n''avait point participé à la décision et aux actes des autres; il était d''Arimathée, ville des Juifs, et il attendait le royaume de Dieu.'),
  (42, 23, 52, 'Cet homme se rendit vers Pilate, et demanda le corps de Jésus.'),
  (42, 23, 53, 'Il le descendit de la croix, l''enveloppa d''un linceul, et le déposa dans un sépulcre taillé dans le roc, où personne n''avait encore été mis.'),
  (42, 23, 54, 'C''était le jour de la préparation, et le sabbat allait commencer.'),
  (42, 23, 55, 'Les femmes qui étaient venues de la Galilée avec Jésus accompagnèrent Joseph, virent le sépulcre et la manière dont le corps de Jésus y fut déposé,'),
  (42, 23, 56, 'et, s''en étant retournées, elles préparèrent des aromates et des parfums. Puis elles se reposèrent le jour du sabbat, selon la loi.'),
  (42, 24, 1, 'Le premier jour de la semaine, elles se rendirent au sépulcre de grand matin, portant les aromates qu''elles avaient préparés.'),
  (42, 24, 2, 'Elles trouvèrent que la pierre avait été roulée de devant le sépulcre;'),
  (42, 24, 3, 'et, étant entrées, elles ne trouvèrent pas le corps du Seigneur Jésus.'),
  (42, 24, 4, 'Comme elles ne savaient que penser de cela, voici, deux hommes leur apparurent, en habits resplendissants.'),
  (42, 24, 5, 'Saisies de frayeur, elles baissèrent le visage contre terre; mais ils leur dirent: Pourquoi cherchez-vous parmi les morts celui qui est vivant?'),
  (42, 24, 6, 'Il n''est point ici, mais il est ressuscité. Souvenez-vous de quelle manière il vous a parlé, lorsqu''il était encore en Galilée,'),
  (42, 24, 7, 'et qu''il disait: Il faut que le Fils de l''homme soit livré entre les mains des pécheurs, qu''il soit crucifié, et qu''il ressuscite le troisième jour.'),
  (42, 24, 8, 'Et elles se ressouvinrent des paroles de Jésus.')
insert into public.bible_verses (book_id, chapter, verse, text) values
  (42, 24, 9, 'A leur retour du sépulcre, elles annoncèrent toutes ces choses aux onze, et à tous les autres.'),
  (42, 24, 10, 'Celles qui dirent ces choses aux apôtres étaient Marie de Magdala, Jeanne, Marie, mère de Jacques, et les autres qui étaient avec elles.'),
  (42, 24, 11, 'Ils tinrent ces discours pour des rêveries, et ils ne crurent pas ces femmes.'),
  (42, 24, 12, 'Mais Pierre se leva, et courut au sépulcre. S''étant baissé, il ne vit que les linges qui étaient à terre; puis il s''en alla chez lui, dans l''étonnement de ce qui était arrivé.'),
  (42, 24, 13, 'Et voici, ce même jour, deux disciples allaient à un village nommé Emmaüs, éloigné de Jérusalem de soixante stades;'),
  (42, 24, 14, 'et ils s''entretenaient de tout ce qui s''était passé.'),
  (42, 24, 15, 'Pendant qu''ils parlaient et discutaient, Jésus s''approcha, et fit route avec eux.'),
  (42, 24, 16, 'Mais leurs yeux étaient empêchés de le reconnaître.'),
  (42, 24, 17, 'Il leur dit: De quoi vous entretenez-vous en marchant, pour que vous soyez tout tristes?'),
  (42, 24, 18, 'L''un d''eux, nommé Cléopas, lui répondit: Es-tu le seul qui, séjournant à Jérusalem ne sache pas ce qui y est arrivé ces jours-ci? -'),
  (42, 24, 19, 'Quoi? leur dit-il. Et ils lui répondirent: Ce qui est arrivé au sujet de Jésus de Nazareth, qui était un prophète puissant en œuvres et en paroles devant Dieu et devant tout le peuple,'),
  (42, 24, 20, 'et comment les principaux sacrificateurs et nos magistrats l''ont livré pour le faire condamner à mort et l''ont crucifié.'),
  (42, 24, 21, 'Nous espérions que ce serait lui qui délivrerait Israël; mais avec tout cela, voici le troisième jour que ces choses se sont passées.'),
  (42, 24, 22, 'Il est vrai que quelques femmes d''entre nous nous ont fort étonnés; s''étant rendues de grand matin au sépulcre'),
  (42, 24, 23, 'et n''ayant pas trouvé son corps, elles sont venues dire que des anges leur sont apparus et ont annoncé qu''il est vivant.'),
  (42, 24, 24, 'Quelques-uns de ceux qui étaient avec nous sont allés au sépulcre, et ils ont trouvé les choses comme les femmes l''avaient dit; mais lui, ils ne l''ont point vu.'),
  (42, 24, 25, 'Alors Jésus leur dit: O hommes sans intelligence, et dont le cœur est lent à croire tout ce qu''ont dit les prophètes!'),
  (42, 24, 26, 'Ne fallait-il pas que le Christ souffrît ces choses, et qu''il entrât dans sa gloire?'),
  (42, 24, 27, 'Et, commençant par Moïse et par tous les prophètes, il leur expliqua dans toutes les Écritures ce qui le concernait.'),
  (42, 24, 28, 'Lorsqu''ils furent près du village où ils allaient, il parut vouloir aller plus loin.'),
  (42, 24, 29, 'Mais ils le pressèrent, en disant: Reste avec nous, car le soir approche, le jour est sur son déclin. Et il entra, pour rester avec eux.'),
  (42, 24, 30, 'Pendant qu''il était à table avec eux, il prit le pain; et, après avoir rendu grâces, il le rompit, et le leur donna.'),
  (42, 24, 31, 'Alors leurs yeux s''ouvrirent, et ils le reconnurent; mais il disparut de devant eux.'),
  (42, 24, 32, 'Et ils se dirent l''un à l''autre: Notre cœur ne brûlait-il pas au dedans de nous, lorsqu''il nous parlait en chemin et nous expliquait les Écritures?'),
  (42, 24, 33, 'Se levant à l''heure même, ils retournèrent à Jérusalem, et ils trouvèrent les onze, et ceux qui étaient avec eux, assemblés'),
  (42, 24, 34, 'et disant: Le Seigneur est réellement ressuscité, et il est apparu à Simon.'),
  (42, 24, 35, 'Et ils racontèrent ce qui leur était arrivé en chemin, et comment ils l''avaient reconnu au moment où il rompit le pain.'),
  (42, 24, 36, 'Tandis qu''ils parlaient de la sorte, lui-même se présenta au milieu d''eux, et leur dit: La paix soit avec vous!'),
  (42, 24, 37, 'Saisis de frayeur et d''épouvante, ils croyaient voir un esprit.'),
  (42, 24, 38, 'Mais il leur dit: Pourquoi êtes-vous troublés, et pourquoi pareilles pensées s''élèvent-elles dans vos cœurs?'),
  (42, 24, 39, 'Voyez mes mains et mes pieds, c''est bien moi; touchez-moi et voyez: un esprit n''a ni chair ni os, comme vous voyez que j''ai.'),
  (42, 24, 40, 'Et en disant cela, il leur montra ses mains et ses pieds.'),
  (42, 24, 41, 'Comme, dans leur joie, ils ne croyaient point encore, et qu''ils étaient dans l''étonnement, il leur dit: Avez-vous ici quelque chose à manger?'),
  (42, 24, 42, 'Ils lui présentèrent du poisson rôti et un rayon de miel.'),
  (42, 24, 43, 'Il en prit, et il mangea devant eux.'),
  (42, 24, 44, 'Puis il leur dit: C''est là ce que je vous disais lorsque j''étais encore avec vous, qu''il fallait que s''accomplît tout ce qui est écrit de moi dans la loi de Moïse, dans les prophètes, et dans les psaumes.'),
  (42, 24, 45, 'Alors il leur ouvrit l''esprit, afin qu''ils comprissent les Écritures.'),
  (42, 24, 46, 'Et il leur dit: Ainsi il est écrit que le Christ souffrirait, et qu''il ressusciterait des morts le troisième jour,'),
  (42, 24, 47, 'et que la repentance et le pardon des péchés seraient prêchés en son nom à toutes les nations, à commencer par Jérusalem.'),
  (42, 24, 48, 'Vous êtes témoins de ces choses.'),
  (42, 24, 49, 'Et voici, j''enverrai sur vous ce que mon Père a promis; mais vous, restez dans la ville jusqu''à ce que vous soyez revêtus de la puissance d''en haut.'),
  (42, 24, 50, 'Il les conduisit jusque vers Béthanie, et, ayant levé les mains, il les bénit.'),
  (42, 24, 51, 'Pendant qu''il les bénissait, il se sépara d''eux, et fut enlevé au ciel.'),
  (42, 24, 52, 'Pour eux, après l''avoir adoré, ils retournèrent à Jérusalem avec une grande joie;'),
  (42, 24, 53, 'et ils étaient continuellement dans le temple, louant et bénissant Dieu.'),
  (43, 1, 1, 'Au commencement était la Parole, et la Parole était avec Dieu, et la Parole était Dieu.'),
  (43, 1, 2, 'Elle était au commencement avec Dieu.'),
  (43, 1, 3, 'Toutes choses ont été faites par elle, et rien de ce qui a été fait n''a été fait sans elle.'),
  (43, 1, 4, 'En elle était la vie, et la vie était la lumière des hommes.'),
  (43, 1, 5, 'La lumière luit dans les ténèbres, et les ténèbres ne l''ont point reçue.'),
  (43, 1, 6, 'Il y eut un homme envoyé de Dieu: son nom était Jean.'),
  (43, 1, 7, 'Il vint pour servir de témoin, pour rendre témoignage à la lumière, afin que tous crussent par lui.'),
  (43, 1, 8, 'Il n''était pas la lumière, mais il parut pour rendre témoignage à la lumière.'),
  (43, 1, 9, 'Cette lumière était la véritable lumière, qui, en venant dans le monde, éclaire tout homme.'),
  (43, 1, 10, 'Elle était dans le monde, et le monde a été fait par elle, et le monde ne l''a point connue.'),
  (43, 1, 11, 'Elle est venue chez les siens, et les siens ne l''ont point reçue.'),
  (43, 1, 12, 'Mais à tous ceux qui l''ont reçue, à ceux qui croient en son nom, elle a donné le pouvoir de devenir enfants de Dieu,'),
  (43, 1, 13, 'lesquels sont nés, non du sang, ni de la volonté de la chair, ni de la volonté de l''homme, mais de Dieu.'),
  (43, 1, 14, 'Et la parole a été faite chair, et elle a habité parmi nous, pleine de grâce et de vérité; et nous avons contemplé sa gloire, une gloire comme la gloire du Fils unique venu du Père.'),
  (43, 1, 15, 'Jean lui a rendu témoignage, et s''est écrié: C''est celui dont j''ai dit: Celui qui vient après moi m''a précédé, car il était avant moi.'),
  (43, 1, 16, 'Et nous avons tous reçu de sa plénitude, et grâce pour grâce;'),
  (43, 1, 17, 'car la loi a été donnée par Moïse, la grâce et la vérité sont venues par Jésus-Christ.'),
  (43, 1, 18, 'Personne n''a jamais vu Dieu; le Fils unique, qui est dans le sein du Père, est celui qui l''a fait connaître.'),
  (43, 1, 19, 'Voici le témoignage de Jean, lorsque les Juifs envoyèrent de Jérusalem des sacrificateurs et des Lévites, pour lui demander: Toi, qui es-tu?'),
  (43, 1, 20, 'Il déclara, et ne le nia point, il déclara qu''il n''était pas le Christ.'),
  (43, 1, 21, 'Et ils lui demandèrent: Quoi donc? es-tu Élie? Et il dit: Je ne le suis point. Es-tu le prophète? Et il répondit: Non.'),
  (43, 1, 22, 'Ils lui dirent alors: Qui es-tu? afin que nous donnions une réponse à ceux qui nous ont envoyés. Que dis-tu de toi-même?'),
  (43, 1, 23, 'Moi, dit-il, je suis la voix de celui qui crie dans le désert: Aplanissez le chemin du Seigneur, comme a dit Ésaïe, le prophète.'),
  (43, 1, 24, 'Ceux qui avaient été envoyés étaient des pharisiens.'),
  (43, 1, 25, 'Ils lui firent encore cette question: Pourquoi donc baptises-tu, si tu n''es pas le Christ, ni Élie, ni le prophète?'),
  (43, 1, 26, 'Jean leur répondit: Moi, je baptise d''eau, mais au milieu de vous il y a quelqu''un que vous ne connaissez pas,'),
  (43, 1, 27, 'qui vient après moi; je ne suis pas digne de délier la courroie de ses souliers.'),
  (43, 1, 28, 'Ces choses se passèrent à Béthanie, au delà du Jourdain, où Jean baptisait.'),
  (43, 1, 29, 'Le lendemain, il vit Jésus venant à lui, et il dit: Voici l''Agneau de Dieu, qui ôte le péché du monde.'),
  (43, 1, 30, 'C''est celui dont j''ai dit: Après moi vient un homme qui m''a précédé, car il était avant moi.'),
  (43, 1, 31, 'Je ne le connaissais pas, mais c''est afin qu''il fût manifesté à Israël que je suis venu baptiser d''eau.'),
  (43, 1, 32, 'Jean rendit ce témoignage: J''ai vu l''Esprit descendre du ciel comme une colombe et s''arrêter sur lui.'),
  (43, 1, 33, 'Je ne le connaissais pas, mais celui qui m''a envoyé baptiser d''eau, celui-là m''a dit: Celui sur qui tu verras l''Esprit descendre et s''arrêter, c''est celui qui baptise du Saint-Esprit.'),
  (43, 1, 34, 'Et j''ai vu, et j''ai rendu témoignage qu''il est le Fils de Dieu.'),
  (43, 1, 35, 'Le lendemain, Jean était encore là, avec deux de ses disciples;'),
  (43, 1, 36, 'et, ayant regardé Jésus qui passait, il dit: Voilà l''Agneau de Dieu.'),
  (43, 1, 37, 'Les deux disciples l''entendirent prononcer ces paroles, et ils suivirent Jésus.'),
  (43, 1, 38, 'Jésus se retourna, et voyant qu''ils le suivaient, il leur dit: Que cherchez-vous? Ils lui répondirent: Rabbi (ce qui signifie Maître), où demeures-tu?'),
  (43, 1, 39, 'Venez, leur dit-il, et voyez. Ils allèrent, et ils virent où il demeurait; et ils restèrent auprès de lui ce jour-là. C''était environ la dixième heure.'),
  (43, 1, 40, 'André, frère de Simon Pierre, était l''un des deux qui avaient entendu les paroles de Jean, et qui avaient suivi Jésus.'),
  (43, 1, 41, 'Ce fut lui qui rencontra le premier son frère Simon, et il lui dit: Nous avons trouvé le Messie (ce qui signifie Christ).'),
  (43, 1, 42, 'Et il le conduisit vers Jésus. Jésus, l''ayant regardé, dit: Tu es Simon, fils de Jonas; tu seras appelé Céphas (ce qui signifie Pierre).'),
  (43, 1, 43, 'Le lendemain, Jésus voulut se rendre en Galilée, et il rencontra Philippe. Il lui dit: Suis-moi.'),
  (43, 1, 44, 'Philippe était de Bethsaïda, de la ville d''André et de Pierre.'),
  (43, 1, 45, 'Philippe rencontra Nathanaël, et lui dit: Nous avons trouvé celui de qui Moïse a écrit dans la loi et dont les prophètes ont parlé, Jésus de Nazareth, fils de Joseph.'),
  (43, 1, 46, 'Nathanaël lui dit: Peut-il venir de Nazareth quelque chose de bon? Philippe lui répondit: Viens, et vois.'),
  (43, 1, 47, 'Jésus, voyant venir à lui Nathanaël, dit de lui: Voici vraiment un Israélite, dans lequel il n''y a point de fraude.'),
  (43, 1, 48, 'D''où me connais-tu? lui dit Nathanaël. Jésus lui répondit: Avant que Philippe t''appelât, quand tu étais sous le figuier, je t''ai vu.'),
  (43, 1, 49, 'Nathanaël répondit et lui dit: Rabbi, tu es le Fils de Dieu, tu es le roi d''Israël.'),
  (43, 1, 50, 'Jésus lui répondit: Parce que je t''ai dit que je t''ai vu sous le figuier, tu crois; tu verras de plus grandes choses que celles-ci.'),
  (43, 1, 51, 'Et il lui dit: En vérité, en vérité, vous verrez désormais le ciel ouvert et les anges de Dieu monter et descendre sur le Fils de l''homme.'),
  (43, 2, 1, 'Trois jours après, il y eut des noces à Cana en Galilée. La mère de Jésus était là,'),
  (43, 2, 2, 'et Jésus fut aussi invité aux noces avec ses disciples.'),
  (43, 2, 3, 'Le vin ayant manqué, la mère de Jésus lui dit: Ils n''ont plus de vin.'),
  (43, 2, 4, 'Jésus lui répondit: Femme, qu''y a-t-il entre moi et toi? Mon heure n''est pas encore venue.'),
  (43, 2, 5, 'Sa mère dit aux serviteurs: Faites ce qu''il vous dira.'),
  (43, 2, 6, 'Or, il y avait là six vases de pierre, destinés aux purifications des Juifs, et contenant chacun deux ou trois mesures.'),
  (43, 2, 7, 'Jésus leur dit: Remplissez d''eau ces vases. Et ils les remplirent jusqu''au bord.'),
  (43, 2, 8, 'Puisez maintenant, leur dit-il, et portez-en à l''ordonnateur du repas. Et ils en portèrent.'),
  (43, 2, 9, 'Quand l''ordonnateur du repas eut goûté l''eau changée en vin, -ne sachant d''où venait ce vin, tandis que les serviteurs, qui avaient puisé l''eau, le savaient bien, -il appela l''époux,'),
  (43, 2, 10, 'et lui dit: Tout homme sert d''abord le bon vin, puis le moins bon après qu''on s''est enivré; toi, tu as gardé le bon vin jusqu''à présent.'),
  (43, 2, 11, 'Tel fut, à Cana en Galilée, le premier des miracles que fit Jésus. Il manifesta sa gloire, et ses disciples crurent en lui.'),
  (43, 2, 12, 'Après cela, il descendit à Capernaüm, avec sa mère, ses frères et ses disciples, et ils n''y demeurèrent que peu de jours.'),
  (43, 2, 13, 'La Pâque des Juifs était proche, et Jésus monta à Jérusalem.'),
  (43, 2, 14, 'Il trouva dans le temple les vendeurs de bœufs, de brebis et de pigeons, et les changeurs assis.'),
  (43, 2, 15, 'Ayant fait un fouet avec des cordes, il les chassa tous du temple, ainsi que les brebis et les bœufs; il dispersa la monnaie des changeurs, et renversa les tables;'),
  (43, 2, 16, 'et il dit aux vendeurs de pigeons: Otez cela d''ici, ne faites pas de la maison de mon Père une maison de trafic.'),
  (43, 2, 17, 'Ses disciples se souvinrent qu''il est écrit: Le zèle de ta maison me dévore.'),
  (43, 2, 18, 'Les Juifs, prenant la parole, lui dirent: Quel miracle nous montres-tu, pour agir de la sorte?'),
  (43, 2, 19, 'Jésus leur répondit: Détruisez ce temple, et en trois jours je le relèverai.'),
  (43, 2, 20, 'Les Juifs dirent: Il a fallu quarante-six ans pour bâtir ce temple, et toi, en trois jours tu le relèveras!'),
  (43, 2, 21, 'Mais il parlait du temple de son corps.'),
  (43, 2, 22, 'C''est pourquoi, lorsqu''il fut ressuscité des morts, ses disciples se souvinrent qu''il avait dit cela, et ils crurent à l''Écriture et à la parole que Jésus avait dite.'),
  (43, 2, 23, 'Pendant que Jésus était à Jérusalem, à la fête de Pâque, plusieurs crurent en son nom, voyant les miracles qu''il faisait.'),
  (43, 2, 24, 'Mais Jésus ne se fiait point à eux, parce qu''il les connaissait tous,'),
  (43, 2, 25, 'et parce qu''il n''avait pas besoin qu''on lui rendît témoignage d''aucun homme; car il savait lui-même ce qui était dans l''homme.'),
  (43, 3, 1, 'Mais il y eut un homme d''entre les pharisiens, nommé Nicodème, un chef des Juifs,'),
  (43, 3, 2, 'qui vint, lui, auprès de Jésus, de nuit, et lui dit: Rabbi, nous savons que tu es un docteur venu de Dieu; car personne ne peut faire ces miracles que tu fais, si Dieu n''est avec lui.'),
  (43, 3, 3, 'Jésus lui répondit: En vérité, en vérité, je te le dis, si un homme ne naît de nouveau, il ne peut voir le royaume de Dieu.'),
  (43, 3, 4, 'Nicodème lui dit: Comment un homme peut-il naître quand il est vieux? Peut-il rentrer dans le sein de sa mère et naître?'),
  (43, 3, 5, 'Jésus répondit: En vérité, en vérité, je te le dis, si un homme ne naît d''eau et d''Esprit, il ne peut entrer dans le royaume de Dieu.'),
  (43, 3, 6, 'Ce qui est né de la chair est chair, et ce qui est né de l''Esprit est esprit.'),
  (43, 3, 7, 'Ne t''étonne pas que je t''aie dit: Il faut que vous naissiez de nouveau.'),
  (43, 3, 8, 'Le vent souffle où il veut, et tu en entends le bruit; mais tu ne sais d''où il vient, ni où il va. Il en est ainsi de tout homme qui est né de l''Esprit.'),
  (43, 3, 9, 'Nicodème lui dit: Comment cela peut-il se faire?'),
  (43, 3, 10, 'Jésus lui répondit: Tu es le docteur d''Israël, et tu ne sais pas ces choses!'),
  (43, 3, 11, 'En vérité, en vérité, je te le dis, nous disons ce que nous savons, et nous rendons témoignage de ce que nous avons vu; et vous ne recevez pas notre témoignage.'),
  (43, 3, 12, 'Si vous ne croyez pas quand je vous ai parlé des choses terrestres, comment croirez-vous quand je vous parlerai des choses célestes?'),
  (43, 3, 13, 'Personne n''est monté au ciel, si ce n''est celui qui est descendu du ciel, le Fils de l''homme qui est dans le ciel.'),
  (43, 3, 14, 'Et comme Moïse éleva le serpent dans le désert, il faut de même que le Fils de l''homme soit élevé,'),
  (43, 3, 15, 'afin que quiconque croit en lui ait la vie éternelle.'),
  (43, 3, 16, 'Car Dieu a tant aimé le monde qu''il a donné son Fils unique, afin que quiconque croit en lui ne périsse point, mais qu''il ait la vie éternelle.'),
  (43, 3, 17, 'Dieu, en effet, n''a pas envoyé son Fils dans le monde pour qu''il juge le monde, mais pour que le monde soit sauvé par lui.'),
  (43, 3, 18, 'Celui qui croit en lui n''est point jugé; mais celui qui ne croit pas est déjà jugé, parce qu''il n''a pas cru au nom du Fils unique de Dieu.'),
  (43, 3, 19, 'Et ce jugement c''est que, la lumière étant venue dans le monde, les hommes ont préféré les ténèbres à la lumière, parce que leurs œuvres étaient mauvaises.'),
  (43, 3, 20, 'Car quiconque fait le mal hait la lumière, et ne vient point à la lumière, de peur que ses œuvres ne soient dévoilées;'),
  (43, 3, 21, 'mais celui qui agit selon la vérité vient à la lumière, afin que ses œuvres soient manifestées, parce qu''elles sont faites en Dieu.'),
  (43, 3, 22, 'Après cela, Jésus, accompagné de ses disciples, se rendit dans la terre de Judée; et là il demeurait avec eux, et il baptisait.'),
  (43, 3, 23, 'Jean aussi baptisait à Énon, près de Salim, parce qu''il y avait là beaucoup d''eau; et on y venait pour être baptisé.'),
  (43, 3, 24, 'Car Jean n''avait pas encore été mis en prison.'),
  (43, 3, 25, 'Or, il s''éleva de la part des disciples de Jean une dispute avec un Juif touchant la purification.'),
  (43, 3, 26, 'Ils vinrent trouver Jean, et lui dirent: Rabbi, celui qui était avec toi au delà du Jourdain, et à qui tu as rendu témoignage, voici, il baptise, et tous vont à lui.'),
  (43, 3, 27, 'Jean répondit: Un homme ne peut recevoir que ce qui lui a été donné du ciel.'),
  (43, 3, 28, 'Vous-mêmes m''êtes témoins que j''ai dit: Je ne suis pas le Christ, mais j''ai été envoyé devant lui.'),
  (43, 3, 29, 'Celui à qui appartient l''épouse, c''est l''époux; mais l''ami de l''époux, qui se tient là et qui l''entend, éprouve une grande joie à cause de la voix de l''époux: aussi cette joie, qui est la mienne, est parfaite.'),
  (43, 3, 30, 'Il faut qu''il croisse, et que je diminue.'),
  (43, 3, 31, 'Celui qui vient d''en haut est au-dessus de tous; celui qui est de la terre est de la terre, et il parle comme étant de la terre. Celui qui vient du ciel est au-dessus de tous,'),
  (43, 3, 32, 'il rend témoignage de ce qu''il a vu et entendu, et personne ne reçoit son témoignage.'),
  (43, 3, 33, 'Celui qui a reçu son témoignage a certifié que Dieu est vrai;'),
  (43, 3, 34, 'car celui que Dieu a envoyé dit les paroles de Dieu, parce que Dieu ne lui donne pas l''Esprit avec mesure.'),
  (43, 3, 35, 'Le Père aime le Fils, et il a remis toutes choses entre ses mains.'),
  (43, 3, 36, 'Celui qui croit au Fils a la vie éternelle; celui qui ne croit pas au Fils ne verra point la vie, mais la colère de Dieu demeure sur lui.'),
  (43, 4, 1, 'Le Seigneur sut que les pharisiens avaient appris qu''il faisait et baptisait plus de disciples que Jean.'),
  (43, 4, 2, 'Toutefois Jésus ne baptisait pas lui-même, mais c''étaient ses disciples.'),
  (43, 4, 3, 'Alors il quitta la Judée, et retourna en Galilée.'),
  (43, 4, 4, 'Comme il fallait qu''il passât par la Samarie,'),
  (43, 4, 5, 'il arriva dans une ville de Samarie, nommée Sychar, près du champ que Jacob avait donné à Joseph, son fils.'),
  (43, 4, 6, 'Là se trouvait le puits de Jacob. Jésus, fatigué du voyage, était assis au bord du puits. C''était environ la sixième heure.'),
  (43, 4, 7, 'Une femme de Samarie vint puiser de l''eau. Jésus lui dit: Donne-moi à boire.'),
  (43, 4, 8, 'Car ses disciples étaient allés à la ville pour acheter des vivres.'),
  (43, 4, 9, 'La femme samaritaine lui dit: Comment toi, qui es Juif, me demandes-tu à boire, à moi qui suis une femme samaritaine? -Les Juifs, en effet, n''ont pas de relations avec les Samaritains. -'),
  (43, 4, 10, 'Jésus lui répondit: Si tu connaissais le don de Dieu et qui est celui qui te dit: Donne-moi à boire! tu lui aurais toi-même demandé à boire, et il t''aurait donné de l''eau vive.'),
  (43, 4, 11, 'Seigneur, lui dit la femme, tu n''as rien pour puiser, et le puits est profond; d''où aurais-tu donc cette eau vive?'),
  (43, 4, 12, 'Es-tu plus grand que notre père Jacob, qui nous a donné ce puits, et qui en a bu lui-même, ainsi que ses fils et ses troupeaux?'),
  (43, 4, 13, 'Jésus lui répondit: Quiconque boit de cette eau aura encore soif;'),
  (43, 4, 14, 'mais celui qui boira de l''eau que je lui donnerai n''aura jamais soif, et l''eau que je lui donnerai deviendra en lui une source d''eau qui jaillira jusque dans la vie éternelle.'),
  (43, 4, 15, 'La femme lui dit: Seigneur, donne-moi cette eau, afin que je n''aie plus soif, et que je ne vienne plus puiser ici.'),
  (43, 4, 16, 'Va, lui dit Jésus, appelle ton mari, et viens ici.'),
  (43, 4, 17, 'La femme répondit: Je n''ai point de mari. Jésus lui dit: Tu as eu raison de dire: Je n''ai point de mari.'),
  (43, 4, 18, 'Car tu as eu cinq maris, et celui que tu as maintenant n''est pas ton mari. En cela tu as dit vrai.'),
  (43, 4, 19, 'Seigneur, lui dit la femme, je vois que tu es prophète.'),
  (43, 4, 20, 'Nos pères ont adoré sur cette montagne; et vous dites, vous, que le lieu où il faut adorer est à Jérusalem.'),
  (43, 4, 21, 'Femme, lui dit Jésus, crois-moi, l''heure vient où ce ne sera ni sur cette montagne ni à Jérusalem que vous adorerez le Père.'),
  (43, 4, 22, 'Vous adorez ce que vous ne connaissez pas; nous, nous adorons ce que nous connaissons, car le salut vient des Juifs.'),
  (43, 4, 23, 'Mais l''heure vient, et elle est déjà venue, où les vrais adorateurs adoreront le Père en esprit et en vérité; car ce sont là les adorateurs que le Père demande.'),
  (43, 4, 24, 'Dieu est Esprit, et il faut que ceux qui l''adorent l''adorent en esprit et en vérité.'),
  (43, 4, 25, 'La femme lui dit: Je sais que le Messie doit venir (celui qu''on appelle Christ); quand il sera venu, il nous annoncera toutes choses.'),
  (43, 4, 26, 'Jésus lui dit: Je le suis, moi qui te parle.'),
  (43, 4, 27, 'Là-dessus arrivèrent ses disciples, qui furent étonnés de ce qu''il parlait avec une femme. Toutefois aucun ne dit: Que demandes-tu? ou: De quoi parles-tu avec elle?'),
  (43, 4, 28, 'Alors la femme, ayant laissé sa cruche, s''en alla dans la ville, et dit aux gens:'),
  (43, 4, 29, 'Venez voir un homme qui m''a dit tout ce que j''ai fait; ne serait-ce point le Christ?'),
  (43, 4, 30, 'Ils sortirent de la ville, et ils vinrent vers lui.'),
  (43, 4, 31, 'Pendant ce temps, les disciples le pressaient de manger, disant: Rabbi, mange.'),
  (43, 4, 32, 'Mais il leur dit: J''ai à manger une nourriture que vous ne connaissez pas.'),
  (43, 4, 33, 'Les disciples se disaient donc les uns aux autres: Quelqu''un lui aurait-il apporté à manger?'),
  (43, 4, 34, 'Jésus leur dit: Ma nourriture est de faire la volonté de celui qui m''a envoyé, et d''accomplir son œuvre.'),
  (43, 4, 35, 'Ne dites-vous pas qu''il y a encore quatre mois jusqu''à la moisson? Voici, je vous le dis, levez les yeux, et regardez les champs qui déjà blanchissent pour la moisson.'),
  (43, 4, 36, 'Celui qui moissonne reçoit un salaire, et amasse des fruits pour la vie éternelle, afin que celui qui sème et celui qui moissonne se réjouissent ensemble.'),
  (43, 4, 37, 'Car en ceci ce qu''on dit est vrai: Autre est celui qui sème, et autre celui qui moissonne.'),
  (43, 4, 38, 'Je vous ai envoyés moissonner ce que vous n''avez pas travaillé; d''autres ont travaillé, et vous êtes entrés dans leur travail.'),
  (43, 4, 39, 'Plusieurs Samaritains de cette ville crurent en Jésus à cause de cette déclaration formelle de la femme: Il m''a dit tout ce que j''ai fait.'),
  (43, 4, 40, 'Aussi, quand les Samaritains vinrent le trouver, ils le prièrent de rester auprès d''eux. Et il resta là deux jours.'),
  (43, 4, 41, 'Un beaucoup plus grand nombre crurent à cause de sa parole;'),
  (43, 4, 42, 'et ils disaient à la femme: Ce n''est plus à cause de ce que tu as dit que nous croyons; car nous l''avons entendu nous-mêmes, et nous savons qu''il est vraiment le Sauveur du monde.'),
  (43, 4, 43, 'Après ces deux jours, Jésus partit de là, pour se rendre en Galilée;'),
  (43, 4, 44, 'car il avait déclaré lui-même qu''un prophète n''est pas honoré dans sa propre patrie.'),
  (43, 4, 45, 'Lorsqu''il arriva en Galilée, il fut bien reçu des Galiléens, qui avaient vu tout ce qu''il avait fait à Jérusalem pendant la fête; car eux aussi étaient allés à la fête.'),
  (43, 4, 46, 'Il retourna donc à Cana en Galilée, où il avait changé l''eau en vin. Il y avait à Capernaüm un officier du roi, dont le fils était malade.'),
  (43, 4, 47, 'Ayant appris que Jésus était venu de Judée en Galilée, il alla vers lui, et le pria de descendre et de guérir son fils, qui était près de mourir.'),
  (43, 4, 48, 'Jésus lui dit: Si vous ne voyez des miracles et des prodiges, vous ne croyez point.'),
  (43, 4, 49, 'L''officier du roi lui dit: Seigneur, descends avant que mon enfant meure.'),
  (43, 4, 50, 'Va, lui dit Jésus, ton fils vit. Et cet homme crut à la parole que Jésus lui avait dite, et il s''en alla.'),
  (43, 4, 51, 'Comme déjà il descendait, ses serviteurs venant à sa rencontre, lui apportèrent cette nouvelle: Ton enfant vit.'),
  (43, 4, 52, 'Il leur demanda à quelle heure il s''était trouvé mieux; et ils lui dirent: Hier, à la septième heure, la fièvre l''a quitté.'),
  (43, 4, 53, 'Le père reconnut que c''était à cette heure-là que Jésus lui avait dit: Ton fils vit. Et il crut, lui et toute sa maison.'),
  (43, 4, 54, 'Jésus fit encore ce second miracle lorsqu''il fut venu de Judée en Galilée.'),
  (43, 5, 1, 'Après cela, il y eut une fête des Juifs, et Jésus monta à Jérusalem.'),
  (43, 5, 2, 'Or, à Jérusalem, près de la porte des brebis, il y a une piscine qui s''appelle en hébreu Béthesda, et qui a cinq portiques.'),
  (43, 5, 3, 'Sous ces portiques étaient couchés en grand nombre des malades, des aveugles, des boiteux, des paralytiques, qui attendaient le mouvement de l''eau;'),
  (43, 5, 4, 'car un ange descendait de temps en temps dans la piscine, et agitait l''eau; et celui qui y descendait le premier après que l''eau avait été agitée était guéri, quelle que fût sa maladie.'),
  (43, 5, 5, 'Là se trouvait un homme malade depuis trente-huit ans.'),
  (43, 5, 6, 'Jésus, l''ayant vu couché, et sachant qu''il était malade depuis longtemps, lui dit: Veux-tu être guéri?'),
  (43, 5, 7, 'Le malade lui répondit: Seigneur, je n''ai personne pour me jeter dans la piscine quand l''eau est agitée, et, pendant que j''y vais, un autre descend avant moi.'),
  (43, 5, 8, 'Lève-toi, lui dit Jésus, prends ton lit, et marche.'),
  (43, 5, 9, 'Aussitôt cet homme fut guéri; il prit son lit, et marcha. C''était un jour de sabbat.'),
  (43, 5, 10, 'Les Juifs dirent donc à celui qui avait été guéri: C''est le sabbat; il ne t''est pas permis d''emporter ton lit.'),
  (43, 5, 11, 'Il leur répondit: Celui qui m''a guéri m''a dit: Prends ton lit, et marche.'),
  (43, 5, 12, 'Ils lui demandèrent: Qui est l''homme qui t''a dit: Prends ton lit, et marche?'),
  (43, 5, 13, 'Mais celui qui avait été guéri ne savait pas qui c''était; car Jésus avait disparu de la foule qui était en ce lieu.'),
  (43, 5, 14, 'Depuis, Jésus le trouva dans le temple, et lui dit: Voici, tu as été guéri; ne pèche plus, de peur qu''il ne t''arrive quelque chose de pire.'),
  (43, 5, 15, 'Cet homme s''en alla, et annonça aux Juifs que c''était Jésus qui l''avait guéri.'),
  (43, 5, 16, 'C''est pourquoi les Juifs poursuivaient Jésus, parce qu''il faisait ces choses le jour du sabbat.'),
  (43, 5, 17, 'Mais Jésus leur répondit: Mon Père agit jusqu''à présent; moi aussi, j''agis.'),
  (43, 5, 18, 'A cause de cela, les Juifs cherchaient encore plus à le faire mourir, non seulement parce qu''il violait le sabbat, mais parce qu''il appelait Dieu son propre Père, se faisant lui-même égal à Dieu.'),
  (43, 5, 19, 'Jésus reprit donc la parole, et leur dit: En vérité, en vérité, je vous le dis, le Fils ne peut rien faire de lui-même, il ne fait que ce qu''il voit faire au Père; et tout ce que le Père fait, le Fils aussi le fait pareillement.'),
  (43, 5, 20, 'Car le Père aime le Fils, et lui montre tout ce qu''il fait; et il lui montrera des œuvres plus grandes que celles-ci, afin que vous soyez dans l''étonnement.'),
  (43, 5, 21, 'Car, comme le Père ressuscite les morts et donne la vie, ainsi le Fils donne la vie à qui il veut.'),
  (43, 5, 22, 'Le Père ne juge personne, mais il a remis tout jugement au Fils,'),
  (43, 5, 23, 'afin que tous honorent le Fils comme ils honorent le Père. Celui qui n''honore pas le Fils n''honore pas le Père qui l''a envoyé.'),
  (43, 5, 24, 'En vérité, en vérité, je vous le dis, celui qui écoute ma parole, et qui croit à celui qui m''a envoyé, a la vie éternelle et ne vient point en jugement, mais il est passé de la mort à la vie.'),
  (43, 5, 25, 'En vérité, en vérité, je vous le dis, l''heure vient, et elle est déjà venue, où les morts entendront la voix du Fils de Dieu; et ceux qui l''auront entendue vivront.'),
  (43, 5, 26, 'Car, comme le Père a la vie en lui-même, ainsi il a donné au Fils d''avoir la vie en lui-même.'),
  (43, 5, 27, 'Et il lui a donné le pouvoir de juger, parce qu''il est Fils de l''homme.'),
  (43, 5, 28, 'Ne vous étonnez pas de cela; car l''heure vient où tous ceux qui sont dans les sépulcres entendront sa voix,'),
  (43, 5, 29, 'et en sortiront. Ceux qui auront fait le bien ressusciteront pour la vie, mais ceux qui auront fait le mal ressusciteront pour le jugement.'),
  (43, 5, 30, 'Je ne puis rien faire de moi-même: selon que j''entends, je juge; et mon jugement est juste, parce que je ne cherche pas ma volonté, mais la volonté de celui qui m''a envoyé.'),
  (43, 5, 31, 'Si c''est moi qui rends témoignage de moi-même, mon témoignage n''est pas vrai.'),
  (43, 5, 32, 'Il y en a un autre qui rend témoignage de moi, et je sais que le témoignage qu''il rend de moi est vrai.'),
  (43, 5, 33, 'Vous avez envoyé vers Jean, et il a rendu témoignage à la vérité.'),
  (43, 5, 34, 'Pour moi ce n''est pas d''un homme que je reçois le témoignage; mais je dis ceci, afin que vous soyez sauvés.'),
  (43, 5, 35, 'Jean était la lampe qui brûle et qui luit, et vous avez voulu vous réjouir une heure à sa lumière.'),
  (43, 5, 36, 'Moi, j''ai un témoignage plus grand que celui de Jean; car les œuvres que le Père m''a donné d''accomplir, ces œuvres mêmes que je fais, témoignent de moi que c''est le Père qui m''a envoyé.'),
  (43, 5, 37, 'Et le Père qui m''a envoyé a rendu lui-même témoignage de moi. Vous n''avez jamais entendu sa voix, vous n''avez point vu sa face,'),
  (43, 5, 38, 'et sa parole ne demeure point en vous, parce que vous ne croyez pas à celui qu''il a envoyé.'),
  (43, 5, 39, 'Vous sondez les Écritures, parce que vous pensez avoir en elles la vie éternelle: ce sont elles qui rendent témoignage de moi.'),
  (43, 5, 40, 'Et vous ne voulez pas venir à moi pour avoir la vie!'),
  (43, 5, 41, 'Je ne tire pas ma gloire des hommes.'),
  (43, 5, 42, 'Mais je sais que vous n''avez point en vous l''amour de Dieu.'),
  (43, 5, 43, 'Je suis venu au nom de mon Père, et vous ne me recevez pas; si un autre vient en son propre nom, vous le recevrez.'),
  (43, 5, 44, 'Comment pouvez-vous croire, vous qui tirez votre gloire les uns des autres, et qui ne cherchez point la gloire qui vient de Dieu seul?'),
  (43, 5, 45, 'Ne pensez pas que moi je vous accuserai devant le Père; celui qui vous accuse, c''est Moïse, en qui vous avez mis votre espérance.'),
  (43, 5, 46, 'Car si vous croyiez Moïse, vous me croiriez aussi, parce qu''il a écrit de moi.'),
  (43, 5, 47, 'Mais si vous ne croyez pas à ses écrits, comment croirez-vous à mes paroles?'),
  (43, 6, 1, 'Après cela, Jésus s''en alla de l''autre côté de la mer de Galilée, de Tibériade.'),
  (43, 6, 2, 'Une grande foule le suivait, parce qu''elle voyait les miracles qu''il opérait sur les malades.'),
  (43, 6, 3, 'Jésus monta sur la montagne, et là il s''assit avec ses disciples.'),
  (43, 6, 4, 'Or, la Pâque était proche, la fête des Juifs.'),
  (43, 6, 5, 'Ayant levé les yeux, et voyant qu''une grande foule venait à lui, Jésus dit à Philippe: Où achèterons-nous des pains, pour que ces gens aient à manger?'),
  (43, 6, 6, 'Il disait cela pour l''éprouver, car il savait ce qu''il allait faire.'),
  (43, 6, 7, 'Philippe lui répondit: Les pains qu''on aurait pour deux cents deniers ne suffiraient pas pour que chacun en reçût un peu.'),
  (43, 6, 8, 'Un de ses disciples, André, frère de Simon Pierre, lui dit:'),
  (43, 6, 9, 'Il y a ici un jeune garçon qui a cinq pains d''orge et deux poissons; mais qu''est-ce que cela pour tant de gens?'),
  (43, 6, 10, 'Jésus dit: Faites-les asseoir. Il y avait dans ce lieu beaucoup d''herbe. Ils s''assirent donc, au nombre d''environ cinq mille hommes.'),
  (43, 6, 11, 'Jésus prit les pains, rendit grâces, et les distribua à ceux qui étaient assis; il leur donna de même des poissons, autant qu''ils en voulurent.'),
  (43, 6, 12, 'Lorsqu''ils furent rassasiés, il dit à ses disciples: Ramassez les morceaux qui restent, afin que rien ne se perde.'),
  (43, 6, 13, 'Ils les ramassèrent donc, et ils remplirent douze paniers avec les morceaux qui restèrent des cinq pains d''orge, après que tous eurent mangé.'),
  (43, 6, 14, 'Ces gens, ayant vu le miracle que Jésus avait fait, disaient: Celui-ci est vraiment le prophète qui doit venir dans le monde.'),
  (43, 6, 15, 'Et Jésus, sachant qu''ils allaient venir l''enlever pour le faire roi, se retira de nouveau sur la montagne, lui seul.'),
  (43, 6, 16, 'Quand le soir fut venu, ses disciples descendirent au bord de la mer.'),
  (43, 6, 17, 'Étant montés dans une barque, ils traversaient la mer pour se rendre à Capernaüm. Il faisait déjà nuit, et Jésus ne les avait pas encore rejoints.'),
  (43, 6, 18, 'Il soufflait un grand vent, et la mer était agitée.'),
  (43, 6, 19, 'Après avoir ramé environ vingt-cinq ou trente stades, ils virent Jésus marchant sur la mer et s''approchant de la barque. Et ils eurent peur.'),
  (43, 6, 20, 'Mais Jésus leur dit: C''est moi; n''ayez pas peur!'),
  (43, 6, 21, 'Ils voulaient donc le prendre dans la barque, et aussitôt la barque aborda au lieu où ils allaient.'),
  (43, 6, 22, 'La foule qui était restée de l''autre côté de la mer avait remarqué qu''il ne se trouvait là qu''une seule barque, et que Jésus n''était pas monté dans cette barque avec ses disciples, mais qu''ils étaient partis seuls.'),
  (43, 6, 23, 'Le lendemain, comme d''autres barques étaient arrivées de Tibériade près du lieu où ils avaient mangé le pain après que le Seigneur eut rendu grâces,'),
  (43, 6, 24, 'les gens de la foule, ayant vu que ni Jésus ni ses disciples n''étaient là, montèrent eux-mêmes dans ces barques et allèrent à Capernaüm à la recherche de Jésus.'),
  (43, 6, 25, 'Et l''ayant trouvé au delà de la mer, ils lui dirent: Rabbi, quand es-tu venu ici?'),
  (43, 6, 26, 'Jésus leur répondit: En vérité, en vérité, je vous le dis, vous me cherchez, non parce que vous avez vu des miracles, mais parce que vous avez mangé des pains et que vous avez été rassasiés.'),
  (43, 6, 27, 'Travaillez, non pour la nourriture qui périt, mais pour celle qui subsiste pour la vie éternelle, et que le Fils de l''homme vous donnera; car c''est lui que le Père, que Dieu a marqué de son sceau.'),
  (43, 6, 28, 'Ils lui dirent: Que devons-nous faire, pour faire les œuvres de Dieu?'),
  (43, 6, 29, 'Jésus leur répondit: L''œuvre de Dieu, c''est que vous croyiez en celui qu''il a envoyé.'),
  (43, 6, 30, 'Quel miracle fais-tu donc, lui dirent-ils, afin que nous le voyions, et que nous croyions en toi? Que fais-tu?'),
  (43, 6, 31, 'Nos pères ont mangé la manne dans le désert, selon ce qui est écrit: Il leur donna le pain du ciel à manger.'),
  (43, 6, 32, 'Jésus leur dit: En vérité, en vérité, je vous le dis, Moïse ne vous a pas donné le pain du ciel, mais mon Père vous donne le vrai pain du ciel;'),
  (43, 6, 33, 'car le pain de Dieu, c''est celui qui descend du ciel et qui donne la vie au monde.'),
  (43, 6, 34, 'Ils lui dirent: Seigneur, donne-nous toujours ce pain.'),
  (43, 6, 35, 'Jésus leur dit: Je suis le pain de vie. Celui qui vient à moi n''aura jamais faim, et celui qui croit en moi n''aura jamais soif.'),
  (43, 6, 36, 'Mais, je vous l''ai dit, vous m''avez vu, et vous ne croyez point.'),
  (43, 6, 37, 'Tous ceux que le Père me donne viendront à moi, et je ne mettrai pas dehors celui qui vient à moi;'),
  (43, 6, 38, 'car je suis descendu du ciel pour faire, non ma volonté, mais la volonté de celui qui m''a envoyé.'),
  (43, 6, 39, 'Or, la volonté de celui qui m''a envoyé, c''est que je ne perde rien de tout ce qu''il m''a donné, mais que je le ressuscite au dernier jour.'),
  (43, 6, 40, 'La volonté de mon Père, c''est que quiconque voit le Fils et croit en lui ait la vie éternelle; et je le ressusciterai au dernier jour.'),
  (43, 6, 41, 'Les Juifs murmuraient à son sujet, parce qu''il avait dit: Je suis le pain qui est descendu du ciel.'),
  (43, 6, 42, 'Et ils disaient: N''est-ce pas là Jésus, le fils de Joseph, celui dont nous connaissons le père et la mère? Comment donc dit-il: Je suis descendu du ciel?'),
  (43, 6, 43, 'Jésus leur répondit: Ne murmurez pas entre vous.'),
  (43, 6, 44, 'Nul ne peut venir à moi, si le Père qui m''a envoyé ne l''attire; et je le ressusciterai au dernier jour.'),
  (43, 6, 45, 'Il est écrit dans les prophètes: Ils seront tous enseignés de Dieu. Ainsi quiconque a entendu le Père et a reçu son enseignement vient à moi.'),
  (43, 6, 46, 'C''est que nul n''a vu le Père, sinon celui qui vient de Dieu; celui-là a vu le Père.'),
  (43, 6, 47, 'En vérité, en vérité, je vous le dis, celui qui croit en moi a la vie éternelle.'),
  (43, 6, 48, 'Je suis le pain de vie.'),
  (43, 6, 49, 'Vos pères ont mangé la manne dans le désert, et ils sont morts.'),
  (43, 6, 50, 'C''est ici le pain qui descend du ciel, afin que celui qui en mange ne meure point.'),
  (43, 6, 51, 'Je suis le pain vivant qui est descendu du ciel. Si quelqu''un mange de ce pain, il vivra éternellement; et le pain que je donnerai, c''est ma chair, que je donnerai pour la vie du monde.'),
  (43, 6, 52, 'Là-dessus, les Juifs disputaient entre eux, disant: Comment peut-il nous donner sa chair à manger?'),
  (43, 6, 53, 'Jésus leur dit: En vérité, en vérité, je vous le dis, si vous ne mangez la chair du Fils de l''homme, et si vous ne buvez son sang, vous n''avez point la vie en vous-mêmes.'),
  (43, 6, 54, 'Celui qui mange ma chair et qui boit mon sang a la vie éternelle; et je le ressusciterai au dernier jour.'),
  (43, 6, 55, 'Car ma chair est vraiment une nourriture, et mon sang est vraiment un breuvage.'),
  (43, 6, 56, 'Celui qui mange ma chair et qui boit mon sang demeure en moi, et je demeure en lui.'),
  (43, 6, 57, 'Comme le Père qui est vivant m''a envoyé, et que je vis par le Père, ainsi celui qui me mange vivra par moi.'),
  (43, 6, 58, 'C''est ici le pain qui est descendu du ciel. Il n''en est pas comme de vos pères qui ont mangé la manne et qui sont morts: celui qui mange ce pain vivra éternellement.'),
  (43, 6, 59, 'Jésus dit ces choses dans la synagogue, enseignant à Capernaüm.'),
  (43, 6, 60, 'Plusieurs de ses disciples, après l''avoir entendu, dirent: Cette parole est dure; qui peut l''écouter?'),
  (43, 6, 61, 'Jésus, sachant en lui-même que ses disciples murmuraient à ce sujet, leur dit: Cela vous scandalise-t-il?'),
  (43, 6, 62, 'Et si vous voyez le Fils de l''homme monter où il était auparavant?…'),
  (43, 6, 63, 'C''est l''esprit qui vivifie; la chair ne sert de rien. Les paroles que je vous ai dites sont esprit et vie.'),
  (43, 6, 64, 'Mais il en est parmi vous quelques-uns qui ne croient point. Car Jésus savait dès le commencement qui étaient ceux qui ne croyaient point, et qui était celui qui le livrerait.'),
  (43, 6, 65, 'Et il ajouta: C''est pourquoi je vous ai dit que nul ne peut venir à moi, si cela ne lui a été donné par le Père.'),
  (43, 6, 66, 'Dès ce moment, plusieurs de ses disciples se retirèrent, et ils n''allaient plus avec lui.'),
  (43, 6, 67, 'Jésus donc dit aux douze: Et vous, ne voulez-vous pas aussi vous en aller?'),
  (43, 6, 68, 'Simon Pierre lui répondit: Seigneur, à qui irions-nous? Tu as les paroles de la vie éternelle.'),
  (43, 6, 69, 'Et nous avons cru et nous avons connu que tu es le Christ, le Saint de Dieu.'),
  (43, 6, 70, 'Jésus leur répondit: N''est-ce pas moi qui vous ai choisis, vous les douze? Et l''un de vous est un démon!'),
  (43, 6, 71, 'Il parlait de Judas Iscariot, fils de Simon; car c''était lui qui devait le livrer, lui, l''un des douze.'),
  (43, 7, 1, 'Après cela, Jésus parcourait la Galilée, car il ne voulait pas séjourner en Judée, parce que les Juifs cherchaient à le faire mourir.'),
  (43, 7, 2, 'Or, la fête des Juifs, la fête des Tabernacles, était proche.'),
  (43, 7, 3, 'Et ses frères lui dirent: Pars d''ici, et va en Judée, afin que tes disciples voient aussi les œuvres que tu fais.'),
  (43, 7, 4, 'Personne n''agit en secret, lorsqu''il désire paraître: si tu fais ces choses, montre-toi toi-même au monde.'),
  (43, 7, 5, 'Car ses frères non plus ne croyaient pas en lui.'),
  (43, 7, 6, 'Jésus leur dit: Mon temps n''est pas encore venu, mais votre temps est toujours prêt.'),
  (43, 7, 7, 'Le monde ne peut vous haïr; moi, il me hait, parce que je rends de lui le témoignage que ses œuvres sont mauvaises.'),
  (43, 7, 8, 'Montez, vous, à cette fête; pour moi, je n''y monte point, parce que mon temps n''est pas encore accompli.'),
  (43, 7, 9, 'Après leur avoir dit cela, il resta en Galilée.'),
  (43, 7, 10, 'Lorsque ses frères furent montés à la fête, il y monta aussi lui-même, non publiquement, mais comme en secret.'),
  (43, 7, 11, 'Les Juifs le cherchaient pendant la fête, et disaient: Où est-il?'),
  (43, 7, 12, 'Il y avait dans la foule grande rumeur à son sujet. Les uns disaient: C''est un homme de bien. D''autres disaient: Non, il égare la multitude.'),
  (43, 7, 13, 'Personne, toutefois, ne parlait librement de lui, par crainte des Juifs.'),
  (43, 7, 14, 'Vers le milieu de la fête, Jésus monta au temple. Et il enseignait.'),
  (43, 7, 15, 'Les Juifs s''étonnaient, disant: Comment connaît-il les Écritures, lui qui n''a point étudié?'),
  (43, 7, 16, 'Jésus leur répondit: Ma doctrine n''est pas de moi, mais de celui qui m''a envoyé.'),
  (43, 7, 17, 'Si quelqu''un veut faire sa volonté, il connaîtra si ma doctrine est de Dieu, ou si je parle de mon chef.'),
  (43, 7, 18, 'Celui qui parle de son chef cherche sa propre gloire; mais celui qui cherche la gloire de celui qui l''a envoyé, celui-là est vrai, et il n''y a point d''injustice en lui.'),
  (43, 7, 19, 'Moïse ne vous a-t-il pas donné la loi? Et nul de vous n''observe la loi. Pourquoi cherchez-vous à me faire mourir?'),
  (43, 7, 20, 'La foule répondit: Tu as un démon. Qui est-ce qui cherche à te faire mourir?'),
  (43, 7, 21, 'Jésus leur répondit: J''ai fait une œuvre, et vous en êtes tous étonnés.'),
  (43, 7, 22, 'Moïse vous a donné la circoncision, -non qu''elle vienne de Moïse, car elle vient des patriarches, -et vous circoncisez un homme le jour du sabbat.'),
  (43, 7, 23, 'Si un homme reçoit la circoncision le jour du sabbat, afin que la loi de Moïse ne soit pas violée, pourquoi vous irritez-vous contre moi de ce que j''ai guéri un homme tout entier le jour du sabbat?'),
  (43, 7, 24, 'Ne jugez pas selon l''apparence, mais jugez selon la justice.'),
  (43, 7, 25, 'Quelques habitants de Jérusalem disaient: N''est-ce pas là celui qu''ils cherchent à faire mourir?'),
  (43, 7, 26, 'Et voici, il parle librement, et ils ne lui disent rien! Est-ce que vraiment les chefs auraient reconnu qu''il est le Christ?'),
  (43, 7, 27, 'Cependant celui-ci, nous savons d''où il est; mais le Christ, quand il viendra, personne ne saura d''où il est.'),
  (43, 7, 28, 'Et Jésus, enseignant dans le temple, s''écria: Vous me connaissez, et vous savez d''où je suis! Je ne suis pas venu de moi-même: mais celui qui m''a envoyé est vrai, et vous ne le connaissez pas.'),
  (43, 7, 29, 'Moi, je le connais; car je viens de lui, et c''est lui qui m''a envoyé.'),
  (43, 7, 30, 'Ils cherchaient donc à se saisir de lui, et personne ne mit la main sur lui, parce que son heure n''était pas encore venue.'),
  (43, 7, 31, 'Plusieurs parmi la foule crurent en lui, et ils disaient: Le Christ, quand il viendra, fera-t-il plus de miracles que n''en a fait celui-ci?'),
  (43, 7, 32, 'Les pharisiens entendirent la foule murmurant de lui ces choses. Alors les principaux sacrificateurs et les pharisiens envoyèrent des huissiers pour le saisir.'),
  (43, 7, 33, 'Jésus dit: Je suis encore avec vous pour un peu de temps, puis je m''en vais vers celui qui m''a envoyé.'),
  (43, 7, 34, 'Vous me chercherez et vous ne me trouverez pas, et vous ne pouvez venir où je serai.'),
  (43, 7, 35, 'Sur quoi les Juifs dirent entre eux: Où ira-t-il, que nous ne le trouvions pas? Ira-t-il parmi ceux qui sont dispersés chez les Grecs, et enseignera-t-il les Grecs?'),
  (43, 7, 36, 'Que signifie cette parole qu''il a dite: Vous me chercherez et vous ne me trouverez pas, et vous ne pouvez venir où je serai?'),
  (43, 7, 37, 'Le dernier jour, le grand jour de la fête, Jésus, se tenant debout, s''écria: Si quelqu''un a soif, qu''il vienne à moi, et qu''il boive.'),
  (43, 7, 38, 'Celui qui croit en moi, des fleuves d''eau vive couleront de son sein, comme dit l''Écriture.'),
  (43, 7, 39, 'Il dit cela de l''Esprit que devaient recevoir ceux qui croiraient en lui; car l''Esprit n''était pas encore, parce que Jésus n''avait pas encore été glorifié.'),
  (43, 7, 40, 'Des gens de la foule, ayant entendu ces paroles, disaient: Celui-ci est vraiment le prophète.'),
  (43, 7, 41, 'D''autres disaient: C''est le Christ. Et d''autres disaient: Est-ce bien de la Galilée que doit venir le Christ?'),
  (43, 7, 42, 'L''Écriture ne dit-elle pas que c''est de la postérité de David, et du village de Bethléhem, où était David, que le Christ doit venir?'),
  (43, 7, 43, 'Il y eut donc, à cause de lui, division parmi la foule.'),
  (43, 7, 44, 'Quelques-uns d''entre eux voulaient le saisir, mais personne ne mit la main sur lui.'),
  (43, 7, 45, 'Ainsi les huissiers retournèrent vers les principaux sacrificateurs et les pharisiens. Et ceux-ci leur dirent: Pourquoi ne l''avez-vous pas amené?'),
  (43, 7, 46, 'Les huissiers répondirent: Jamais homme n''a parlé comme cet homme.'),
  (43, 7, 47, 'Les pharisiens leur répliquèrent: Est-ce que vous aussi, vous avez été séduits?'),
  (43, 7, 48, 'Y a-t-il quelqu''un des chefs ou des pharisiens qui ait cru en lui?'),
  (43, 7, 49, 'Mais cette foule qui ne connaît pas la loi, ce sont des maudits!'),
  (43, 7, 50, 'Nicodème, qui était venu de nuit vers Jésus, et qui était l''un d''entre eux, leur dit:'),
  (43, 7, 51, 'Notre loi condamne-t-elle un homme avant qu''on l''entende et qu''on sache ce qu''il a fait?'),
  (43, 7, 52, 'Ils lui répondirent: Es-tu aussi Galiléen? Examine, et tu verras que de la Galilée il ne sort point de prophète.'),
  (43, 7, 53, 'Et chacun s''en retourna dans sa maison.'),
  (43, 8, 1, 'Jésus se rendit à la montagne des Oliviers.'),
  (43, 8, 2, 'Mais, dès le matin, il alla de nouveau dans le temple, et tout le peuple vint à lui. S''étant assis, il les enseignait.'),
  (43, 8, 3, 'Alors les scribes et les pharisiens amenèrent une femme surprise en adultère; et, la plaçant au milieu du peuple,'),
  (43, 8, 4, 'ils dirent à Jésus: Maître, cette femme a été surprise en flagrant délit d''adultère.'),
  (43, 8, 5, 'Moïse, dans la loi, nous a ordonné de lapider de telles femmes: toi donc, que dis-tu?'),
  (43, 8, 6, 'Ils disaient cela pour l''éprouver, afin de pouvoir l''accuser. Mais Jésus, s''étant baissé, écrivait avec le doigt sur la terre.'),
  (43, 8, 7, 'Comme ils continuaient à l''interroger, il se releva et leur dit: Que celui de vous qui est sans péché jette le premier la pierre contre elle.'),
  (43, 8, 8, 'Et s''étant de nouveau baissé, il écrivait sur la terre.'),
  (43, 8, 9, 'Quand ils entendirent cela, accusés par leur conscience, ils se retirèrent un à un, depuis les plus âgés jusqu''aux derniers; et Jésus resta seul avec la femme qui était là au milieu.'),
  (43, 8, 10, 'Alors s''étant relevé, et ne voyant plus que la femme, Jésus lui dit: Femme, où sont ceux qui t''accusaient? Personne ne t''a-t-il condamnée?'),
  (43, 8, 11, 'Elle répondit: Non, Seigneur. Et Jésus lui dit: Je ne te condamne pas non plus: va, et ne pèche plus.'),
  (43, 8, 12, 'Jésus leur parla de nouveau, et dit: Je suis la lumière du monde; celui qui me suit ne marchera pas dans les ténèbres, mais il aura la lumière de la vie.'),
  (43, 8, 13, 'Là-dessus, les pharisiens lui dirent: Tu rends témoignage de toi-même; ton témoignage n''est pas vrai.'),
  (43, 8, 14, 'Jésus leur répondit: Quoique je rende témoignage de moi-même, mon témoignage est vrai, car je sais d''où je suis venu et où je vais; mais vous, vous ne savez d''où je viens ni où je vais.'),
  (43, 8, 15, 'Vous jugez selon la chair; moi, je ne juge personne.'),
  (43, 8, 16, 'Et si je juge, mon jugement est vrai, car je ne suis pas seul; mais le Père qui m''a envoyé est avec moi.'),
  (43, 8, 17, 'Il est écrit dans votre loi que le témoignage de deux hommes est vrai;'),
  (43, 8, 18, 'je rends témoignage de moi-même, et le Père qui m''a envoyé rend témoignage de moi.'),
  (43, 8, 19, 'Ils lui dirent donc: Où est ton Père? Jésus répondit: Vous ne connaissez ni moi, ni mon Père. Si vous me connaissiez, vous connaîtriez aussi mon Père.'),
  (43, 8, 20, 'Jésus dit ces paroles, enseignant dans le temple, au lieu où était le trésor; et personne ne le saisit, parce que son heure n''était pas encore venue.'),
  (43, 8, 21, 'Jésus leur dit encore: Je m''en vais, et vous me chercherez, et vous mourrez dans votre péché; vous ne pouvez venir où je vais.'),
  (43, 8, 22, 'Sur quoi les Juifs dirent: Se tuera-t-il lui-même, puisqu''il dit: Vous ne pouvez venir où je vais?'),
  (43, 8, 23, 'Et il leur dit: Vous êtes d''en bas; moi, je suis d''en haut. Vous êtes de ce monde; moi, je ne suis pas de ce monde.'),
  (43, 8, 24, 'C''est pourquoi je vous ai dit que vous mourrez dans vos péchés; car si vous ne croyez pas ce que je suis, vous mourrez dans vos péchés.'),
  (43, 8, 25, 'Qui es-tu? lui dirent-ils. Jésus leur répondit: Ce que je vous dis dès le commencement.'),
  (43, 8, 26, 'J''ai beaucoup de choses à dire de vous et à juger en vous; mais celui qui m''a envoyé est vrai, et ce que j''ai entendu de lui, je le dis au monde.'),
  (43, 8, 27, 'Ils ne comprirent point qu''il leur parlait du Père.'),
  (43, 8, 28, 'Jésus donc leur dit: Quand vous aurez élevé le Fils de l''homme, alors vous connaîtrez ce que je suis, et que je ne fais rien de moi-même, mais que je parle selon ce que le Père m''a enseigné.'),
  (43, 8, 29, 'Celui qui m''a envoyé est avec moi; il ne m''a pas laissé seul, parce que je fais toujours ce qui lui est agréable.'),
  (43, 8, 30, 'Comme Jésus parlait ainsi, plusieurs crurent en lui.'),
  (43, 8, 31, 'Et il dit aux Juifs qui avaient cru en lui: Si vous demeurez dans ma parole, vous êtes vraiment mes disciples;'),
  (43, 8, 32, 'vous connaîtrez la vérité, et la vérité vous affranchira.'),
  (43, 8, 33, 'Ils lui répondirent: Nous sommes la postérité d''Abraham, et nous ne fûmes jamais esclaves de personne; comment dis-tu: Vous deviendrez libres?'),
  (43, 8, 34, 'En vérité, en vérité, je vous le dis, leur répliqua Jésus, quiconque se livre au péché est esclave du péché.'),
  (43, 8, 35, 'Or, l''esclave ne demeure pas toujours dans la maison; le fils y demeure toujours.'),
  (43, 8, 36, 'Si donc le Fils vous affranchit, vous serez réellement libres.'),
  (43, 8, 37, 'Je sais que vous êtes la postérité d''Abraham; mais vous cherchez à me faire mourir, parce que ma parole ne pénètre pas en vous.'),
  (43, 8, 38, 'Je dis ce que j''ai vu chez mon Père; et vous, vous faites ce que vous avez entendu de la part de votre père.'),
  (43, 8, 39, 'Ils lui répondirent: Notre père, c''est Abraham. Jésus leur dit: Si vous étiez enfants d''Abraham, vous feriez les œuvres d''Abraham.'),
  (43, 8, 40, 'Mais maintenant vous cherchez à me faire mourir, moi qui vous ai dit la vérité que j''ai entendue de Dieu. Cela, Abraham ne l''a point fait.'),
  (43, 8, 41, 'Vous faites les œuvres de votre père. Ils lui dirent: Nous ne sommes pas des enfants illégitimes; nous avons un seul Père, Dieu.'),
  (43, 8, 42, 'Jésus leur dit: Si Dieu était votre Père, vous m''aimeriez, car c''est de Dieu que je suis sorti et que je viens; je ne suis pas venu de moi-même, mais c''est lui qui m''a envoyé.'),
  (43, 8, 43, 'Pourquoi ne comprenez-vous pas mon langage? Parce que vous ne pouvez écouter ma parole.'),
  (43, 8, 44, 'Vous avez pour père le diable, et vous voulez accomplir les désirs de votre père. Il a été meurtrier dès le commencement, et il ne se tient pas dans la vérité, parce qu''il n''y a pas de vérité en lui. Lorsqu''il profère le mensonge, il parle de son propre fonds; car il est menteur et le père du mensonge.'),
  (43, 8, 45, 'Et moi, parce que je dis la vérité, vous ne me croyez pas.'),
  (43, 8, 46, 'Qui de vous me convaincra de péché? Si je dis la vérité, pourquoi ne me croyez-vous pas?'),
  (43, 8, 47, 'Celui qui est de Dieu, écoute les paroles de Dieu; vous n''écoutez pas, parce que vous n''êtes pas de Dieu.'),
  (43, 8, 48, 'Les Juifs lui répondirent: N''avons-nous pas raison de dire que tu es un Samaritain, et que tu as un démon?'),
  (43, 8, 49, 'Jésus répliqua: Je n''ai point de démon; mais j''honore mon Père, et vous m''outragez.'),
  (43, 8, 50, 'Je ne cherche point ma gloire; il en est un qui la cherche et qui juge.'),
  (43, 8, 51, 'En vérité, en vérité, je vous le dis, si quelqu''un garde ma parole, il ne verra jamais la mort.'),
  (43, 8, 52, 'Maintenant, lui dirent les Juifs, nous connaissons que tu as un démon. Abraham est mort, les prophètes aussi, et tu dis: Si quelqu''un garde ma parole, il ne verra jamais la mort.'),
  (43, 8, 53, 'Es-tu plus grand que notre père Abraham, qui est mort? Les prophètes aussi sont morts. Qui prétends-tu être?'),
  (43, 8, 54, 'Jésus répondit: Si je me glorifie moi-même, ma gloire n''est rien. C''est mon Père qui me glorifie, lui que vous dites être votre Dieu,'),
  (43, 8, 55, 'et que vous ne connaissez pas. Pour moi, je le connais; et, si je disais que je ne le connais pas, je serais semblable à vous, un menteur. Mais je le connais, et je garde sa parole.'),
  (43, 8, 56, 'Abraham, votre père, a tressailli de joie de ce qu''il verrait mon jour: il l''a vu, et il s''est réjoui.'),
  (43, 8, 57, 'Les Juifs lui dirent: Tu n''as pas encore cinquante ans, et tu as vu Abraham!'),
  (43, 8, 58, 'Jésus leur dit: En vérité, en vérité, je vous le dis, avant qu''Abraham fût, je suis.'),
  (43, 8, 59, 'Là-dessus, ils prirent des pierres pour les jeter contre lui; mais Jésus se cacha, et il sortit du temple.'),
  (43, 9, 1, 'Jésus vit, en passant, un homme aveugle de naissance.'),
  (43, 9, 2, 'Ses disciples lui firent cette question: Rabbi, qui a péché, cet homme ou ses parents, pour qu''il soit né aveugle?'),
  (43, 9, 3, 'Jésus répondit: Ce n''est pas que lui ou ses parents aient péché; mais c''est afin que les œuvres de Dieu soient manifestées en lui.'),
  (43, 9, 4, 'Il faut que je fasse, tandis qu''il est jour, les œuvres de celui qui m''a envoyé; la nuit vient, où personne ne peut travailler.'),
  (43, 9, 5, 'Pendant que je suis dans le monde, je suis la lumière du monde.'),
  (43, 9, 6, 'Après avoir dit cela, il cracha à terre, et fit de la boue avec sa salive. Puis il appliqua cette boue sur les yeux de l''aveugle,'),
  (43, 9, 7, 'et lui dit: Va, et lave-toi au réservoir de Siloé (nom qui signifie envoyé). Il y alla, se lava, et s''en retourna voyant clair.'),
  (43, 9, 8, 'Ses voisins et ceux qui auparavant l''avaient connu comme un mendiant disaient: N''est-ce pas là celui qui se tenait assis et qui mendiait?'),
  (43, 9, 9, 'Les uns disaient: C''est lui. D''autres disaient: Non, mais il lui ressemble. Et lui-même disait: C''est moi.'),
  (43, 9, 10, 'Ils lui dirent donc: Comment tes yeux ont-ils été ouverts?'),
  (43, 9, 11, 'Il répondit: L''homme qu''on appelle Jésus a fait de la boue, a oint mes yeux, et m''a dit: Va au réservoir de Siloé, et lave-toi. J''y suis allé, je me suis lavé, et j''ai recouvré la vue.'),
  (43, 9, 12, 'Ils lui dirent: Où est cet homme? Il répondit: Je ne sais.'),
  (43, 9, 13, 'Ils menèrent vers les pharisiens celui qui avait été aveugle.'),
  (43, 9, 14, 'Or, c''était un jour de sabbat que Jésus avait fait de la boue, et lui avait ouvert les yeux.'),
  (43, 9, 15, 'De nouveau, les pharisiens aussi lui demandèrent comment il avait recouvré la vue. Et il leur dit: Il a appliqué de la boue sur mes yeux, je me suis lavé, et je vois.'),
  (43, 9, 16, 'Sur quoi quelques-uns des pharisiens dirent: Cet homme ne vient pas de Dieu, car il n''observe pas le sabbat. D''autres dirent: Comment un homme pécheur peut-il faire de tels miracles? Et il y eut division parmi eux.'),
  (43, 9, 17, 'Ils dirent encore à l''aveugle: Toi, que dis-tu de lui, sur ce qu''il t''a ouvert les yeux? Il répondit: C''est un prophète.'),
  (43, 9, 18, 'Les Juifs ne crurent point qu''il eût été aveugle et qu''il eût recouvré la vue jusqu''à ce qu''ils eussent fait venir ses parents.'),
  (43, 9, 19, 'Et ils les interrogèrent, disant: Est-ce là votre fils, que vous dites être né aveugle? Comment donc voit-il maintenant?'),
  (43, 9, 20, 'Ses parents répondirent: Nous savons que c''est notre fils, et qu''il est né aveugle;'),
  (43, 9, 21, 'mais comment il voit maintenant, ou qui lui a ouvert les yeux, c''est ce que nous ne savons. Interrogez-le lui-même, il a de l''âge, il parlera de ce qui le concerne.'),
  (43, 9, 22, 'Ses parents dirent cela parce qu''ils craignaient les Juifs; car les Juifs étaient déjà convenus que, si quelqu''un reconnaissait Jésus pour le Christ, il serait exclu de la synagogue.'),
  (43, 9, 23, 'C''est pourquoi ses parents dirent: Il a de l''âge, interrogez-le lui-même.'),
  (43, 9, 24, 'Les pharisiens appelèrent une seconde fois l''homme qui avait été aveugle, et ils lui dirent: Donne gloire à Dieu; nous savons que cet homme est un pécheur.'),
  (43, 9, 25, 'Il répondit: S''il est un pécheur, je ne sais; je sais une chose, c''est que j''étais aveugle et que maintenant je vois.'),
  (43, 9, 26, 'Ils lui dirent: Que t''a-t-il fait? Comment t''a-t-il ouvert les yeux?'),
  (43, 9, 27, 'Il leur répondit: Je vous l''ai déjà dit, et vous n''avez pas écouté; pourquoi voulez-vous l''entendre encore? Voulez-vous aussi devenir ses disciples?'),
  (43, 9, 28, 'Ils l''injurièrent et dirent: C''est toi qui es son disciple; nous, nous sommes disciples de Moïse.'),
  (43, 9, 29, 'Nous savons que Dieu a parlé à Moïse; mais celui-ci, nous ne savons d''où il est.'),
  (43, 9, 30, 'Cet homme leur répondit: Il est étonnant que vous ne sachiez d''où il est; et cependant il m''a ouvert les yeux.'),
  (43, 9, 31, 'Nous savons que Dieu n''exauce point les pécheurs; mais, si quelqu''un l''honore et fait sa volonté, c''est celui là qu''il exauce.'),
  (43, 9, 32, 'Jamais on n''a entendu dire que quelqu''un ait ouvert les yeux d''un aveugle-né.'),
  (43, 9, 33, 'Si cet homme ne venait pas de Dieu, il ne pourrait rien faire.'),
  (43, 9, 34, 'Ils lui répondirent: Tu es né tout entier dans le péché, et tu nous enseignes! Et ils le chassèrent.'),
  (43, 9, 35, 'Jésus apprit qu''ils l''avaient chassé; et, l''ayant rencontré, il lui dit: Crois-tu au Fils de Dieu?'),
  (43, 9, 36, 'Il répondit: Et qui est-il, Seigneur, afin que je croie en lui?'),
  (43, 9, 37, 'Tu l''as vu, lui dit Jésus, et celui qui te parle, c''est lui.'),
  (43, 9, 38, 'Et il dit: Je crois, Seigneur. Et il se prosterna devant lui.'),
  (43, 9, 39, 'Puis Jésus dit: Je suis venu dans ce monde pour un jugement, pour que ceux qui ne voient point voient, et que ceux qui voient deviennent aveugles.'),
  (43, 9, 40, 'Quelques pharisiens qui étaient avec lui, ayant entendu ces paroles, lui dirent: Nous aussi, sommes-nous aveugles?'),
  (43, 9, 41, 'Jésus leur répondit: Si vous étiez aveugles, vous n''auriez pas de péché. Mais maintenant vous dites: Nous voyons. C''est pour cela que votre péché subsiste.'),
  (43, 10, 1, 'En vérité, en vérité, je vous le dis, celui qui n''entre pas par la porte dans la bergerie, mais qui y monte par ailleurs, est un voleur et un brigand.'),
  (43, 10, 2, 'Mais celui qui entre par la porte est le berger des brebis.'),
  (43, 10, 3, 'Le portier lui ouvre, et les brebis entendent sa voix; il appelle par leur nom les brebis qui lui appartiennent, et il les conduit dehors.'),
  (43, 10, 4, 'Lorsqu''il a fait sortir toutes ses propres brebis, il marche devant elles; et les brebis le suivent, parce qu''elles connaissent sa voix.'),
  (43, 10, 5, 'Elles ne suivront point un étranger; mais elles fuiront loin de lui, parce qu''elles ne connaissent pas la voix des étrangers.'),
  (43, 10, 6, 'Jésus leur dit cette parabole, mais ils ne comprirent pas de quoi il leur parlait.'),
  (43, 10, 7, 'Jésus leur dit encore: En vérité, en vérité, je vous le dis, je suis la porte des brebis.'),
  (43, 10, 8, 'Tous ceux qui sont venus avant moi sont des voleurs et des brigands; mais les brebis ne les ont point écoutés.'),
  (43, 10, 9, 'Je suis la porte. Si quelqu''un entre par moi, il sera sauvé; il entrera et il sortira, et il trouvera des pâturages.'),
  (43, 10, 10, 'Le voleur ne vient que pour dérober, égorger et détruire; moi, je suis venu afin que les brebis aient la vie, et qu''elles soient dans l''abondance.'),
  (43, 10, 11, 'Je suis le bon berger. Le bon berger donne sa vie pour ses brebis.'),
  (43, 10, 12, 'Mais le mercenaire, qui n''est pas le berger, et à qui n''appartiennent pas les brebis, voit venir le loup, abandonne les brebis, et prend la fuite; et le loup les ravit et les disperse.'),
  (43, 10, 13, 'Le mercenaire s''enfuit, parce qu''il est mercenaire, et qu''il ne se met point en peine des brebis.'),
  (43, 10, 14, 'Je suis le bon berger. Je connais mes brebis, et elles me connaissent,'),
  (43, 10, 15, 'comme le Père me connaît et comme je connais le Père; et je donne ma vie pour mes brebis.'),
  (43, 10, 16, 'J''ai encore d''autres brebis, qui ne sont pas de cette bergerie; celles-là, il faut que je les amène; elles entendront ma voix, et il y aura un seul troupeau, un seul berger.'),
  (43, 10, 17, 'Le Père m''aime, parce que je donne ma vie, afin de la reprendre.'),
  (43, 10, 18, 'Personne ne me l''ôte, mais je la donne de moi-même; j''ai le pouvoir de la donner, et j''ai le pouvoir de la reprendre: tel est l''ordre que j''ai reçu de mon Père.'),
  (43, 10, 19, 'Il y eut de nouveau, à cause de ces paroles, division parmi les Juifs.'),
  (43, 10, 20, 'Plusieurs d''entre eux disaient: Il a un démon, il est fou; pourquoi l''écoutez-vous?'),
  (43, 10, 21, 'D''autres disaient: Ce ne sont pas les paroles d''un démoniaque; un démon peut-il ouvrir les yeux des aveugles?'),
  (43, 10, 22, 'On célébrait à Jérusalem la fête de la Dédicace. C''était l''hiver.'),
  (43, 10, 23, 'Et Jésus se promenait dans le temple, sous le portique de Salomon.'),
  (43, 10, 24, 'Les Juifs l''entourèrent, et lui dirent: Jusques à quand tiendras-tu notre esprit en suspens? Si tu es le Christ, dis-le nous franchement.'),
  (43, 10, 25, 'Jésus leur répondit: Je vous l''ai dit, et vous ne croyez pas. Les œuvres que je fais au nom de mon Père rendent témoignage de moi.'),
  (43, 10, 26, 'Mais vous ne croyez pas, parce que vous n''êtes pas de mes brebis.'),
  (43, 10, 27, 'Mes brebis entendent ma voix; je les connais, et elles me suivent.'),
  (43, 10, 28, 'Je leur donne la vie éternelle; et elles ne périront jamais, et personne ne les ravira de ma main.'),
  (43, 10, 29, 'Mon Père, qui me les a données, est plus grand que tous; et personne ne peut les ravir de la main de mon Père.'),
  (43, 10, 30, 'Moi et le Père nous sommes un.'),
  (43, 10, 31, 'Alors les Juifs prirent de nouveau des pierres pour le lapider.'),
  (43, 10, 32, 'Jésus leur dit: Je vous ai fait voir plusieurs bonnes œuvres venant de mon Père: pour laquelle me lapidez-vous?'),
  (43, 10, 33, 'Les Juifs lui répondirent: Ce n''est point pour une bonne œuvre que nous te lapidons, mais pour un blasphème, et parce que toi, qui es un homme, tu te fais Dieu.'),
  (43, 10, 34, 'Jésus leur répondit: N''est-il pas écrit dans votre loi: J''ai dit: Vous êtes des dieux?'),
  (43, 10, 35, 'Si elle a appelé dieux ceux à qui la parole de Dieu a été adressée, et si l''Écriture ne peut être anéantie,'),
  (43, 10, 36, 'celui que le Père a sanctifié et envoyé dans le monde, vous lui dites: Tu blasphèmes! Et cela parce que j''ai dit: Je suis le Fils de Dieu.'),
  (43, 10, 37, 'Si je ne fais pas les œuvres de mon Père, ne me croyez pas.'),
  (43, 10, 38, 'Mais si je les fais, quand même vous ne me croyez point, croyez à ces œuvres, afin que vous sachiez et reconnaissiez que le Père est en moi et que je suis dans le Père.'),
  (43, 10, 39, 'Là-dessus, ils cherchèrent encore à le saisir, mais il s''échappa de leurs mains.'),
  (43, 10, 40, 'Jésus s''en alla de nouveau au delà du Jourdain, dans le lieu où Jean avait d''abord baptisé. Et il y demeura.'),
  (43, 10, 41, 'Beaucoup de gens vinrent à lui, et ils disaient: Jean n''a fait aucun miracle; mais tout ce que Jean a dit de cet homme était vrai.'),
  (43, 10, 42, 'Et, dans ce lieu-là, plusieurs crurent en lui.'),
  (43, 11, 1, 'Il y avait un homme malade, Lazare, de Béthanie, village de Marie et de Marthe, sa sœur.'),
  (43, 11, 2, 'C''était cette Marie qui oignit de parfum le Seigneur et qui lui essuya les pieds avec ses cheveux, et c''était son frère Lazare qui était malade.'),
  (43, 11, 3, 'Les sœurs envoyèrent dire à Jésus: Seigneur, voici, celui que tu aimes est malade.'),
  (43, 11, 4, 'Après avoir entendu cela, Jésus dit: Cette maladie n''est point à la mort; mais elle est pour la gloire de Dieu, afin que le Fils de Dieu soit glorifié par elle.'),
  (43, 11, 5, 'Or, Jésus aimait Marthe, et sa sœur, et Lazare.'),
  (43, 11, 6, 'Lors donc qu''il eut appris que Lazare était malade, il resta deux jours encore dans le lieu où il était,'),
  (43, 11, 7, 'et il dit ensuite aux disciples: Retournons en Judée.'),
  (43, 11, 8, 'Les disciples lui dirent: Rabbi, les Juifs tout récemment cherchaient à te lapider, et tu retournes en Judée!'),
  (43, 11, 9, 'Jésus répondit: N''y a-t-il pas douze heures au jour? Si quelqu''un marche pendant le jour, il ne bronche point, parce qu''il voit la lumière de ce monde;'),
  (43, 11, 10, 'mais, si quelqu''un marche pendant la nuit, il bronche, parce que la lumière n''est pas en lui.'),
  (43, 11, 11, 'Après ces paroles, il leur dit: Lazare, notre ami, dort; mais je vais le réveiller.'),
  (43, 11, 12, 'Les disciples lui dirent: Seigneur, s''il dort, il sera guéri.'),
  (43, 11, 13, 'Jésus avait parlé de sa mort, mais ils crurent qu''il parlait de l''assoupissement du sommeil.'),
  (43, 11, 14, 'Alors Jésus leur dit ouvertement: Lazare est mort.'),
  (43, 11, 15, 'Et, à cause de vous, afin que vous croyiez, je me réjouis de ce que je n''étais pas là. Mais allons vers lui.'),
  (43, 11, 16, 'Sur quoi Thomas, appelé Didyme, dit aux autres disciples: Allons aussi, afin de mourir avec lui.'),
  (43, 11, 17, 'Jésus, étant arrivé, trouva que Lazare était déjà depuis quatre jours dans le sépulcre.'),
  (43, 11, 18, 'Et, comme Béthanie était près de Jérusalem, à quinze stades environ,'),
  (43, 11, 19, 'beaucoup de Juifs étaient venus vers Marthe et Marie, pour les consoler de la mort de leur frère.'),
  (43, 11, 20, 'Lorsque Marthe apprit que Jésus arrivait, elle alla au-devant de lui, tandis que Marie se tenait assise à la maison.'),
  (43, 11, 21, 'Marthe dit à Jésus: Seigneur, si tu eusses été ici, mon frère ne serait pas mort.'),
  (43, 11, 22, 'Mais, maintenant même, je sais que tout ce que tu demanderas à Dieu, Dieu te l''accordera.'),
  (43, 11, 23, 'Jésus lui dit: Ton frère ressuscitera.'),
  (43, 11, 24, 'Je sais, lui répondit Marthe, qu''il ressuscitera à la résurrection, au dernier jour.'),
  (43, 11, 25, 'Jésus lui dit: Je suis la résurrection et la vie. Celui qui croit en moi vivra, quand même il serait mort;'),
  (43, 11, 26, 'et quiconque vit et croit en moi ne mourra jamais. Crois-tu cela?'),
  (43, 11, 27, 'Elle lui dit: Oui, Seigneur, je crois que tu es le Christ, le Fils de Dieu, qui devait venir dans le monde.'),
  (43, 11, 28, 'Ayant ainsi parlé, elle s''en alla. Puis elle appela secrètement Marie, sa sœur, et lui dit: Le maître est ici, et il te demande.'),
  (43, 11, 29, 'Dès que Marie eut entendu, elle se leva promptement, et alla vers lui.'),
  (43, 11, 30, 'Car Jésus n''était pas encore entré dans le village, mais il était dans le lieu où Marthe l''avait rencontré.'),
  (43, 11, 31, 'Les Juifs qui étaient avec Marie dans la maison et qui la consolaient, l''ayant vue se lever promptement et sortir, la suivirent, disant: Elle va au sépulcre, pour y pleurer.'),
  (43, 11, 32, 'Lorsque Marie fut arrivée là où était Jésus, et qu''elle le vit, elle tomba à ses pieds, et lui dit: Seigneur, si tu eusses été ici, mon frère ne serait pas mort.'),
  (43, 11, 33, 'Jésus, la voyant pleurer, elle et les Juifs qui étaient venus avec elle, frémit en son esprit, et fut tout ému.'),
  (43, 11, 34, 'Et il dit: Où l''avez-vous mis? Seigneur, lui répondirent-ils, viens et vois.'),
  (43, 11, 35, 'Jésus pleura.'),
  (43, 11, 36, 'Sur quoi les Juifs dirent: Voyez comme il l''aimait.'),
  (43, 11, 37, 'Et quelques-uns d''entre eux dirent: Lui qui a ouvert les yeux de l''aveugle, ne pouvait-il pas faire aussi que cet homme ne mourût point?'),
  (43, 11, 38, 'Jésus frémissant de nouveau en lui-même, se rendit au sépulcre. C''était une grotte, et une pierre était placée devant.'),
  (43, 11, 39, 'Jésus dit: Otez la pierre. Marthe, la sœur du mort, lui dit: Seigneur, il sent déjà, car il y a quatre jours qu''il est là.'),
  (43, 11, 40, 'Jésus lui dit: Ne t''ai-je pas dit que, si tu crois, tu verras la gloire de Dieu?'),
  (43, 11, 41, 'Ils ôtèrent donc la pierre. Et Jésus leva les yeux en haut, et dit: Père, je te rends grâces de ce que tu m''as exaucé.'),
  (43, 11, 42, 'Pour moi, je savais que tu m''exauces toujours; mais j''ai parlé à cause de la foule qui m''entoure, afin qu''ils croient que c''est toi qui m''as envoyé.'),
  (43, 11, 43, 'Ayant dit cela, il cria d''une voix forte: Lazare, sors!'),
  (43, 11, 44, 'Et le mort sortit, les pieds et les mains liés de bandes, et le visage enveloppé d''un linge. Jésus leur dit: Déliez-le, et laissez-le aller.'),
  (43, 11, 45, 'Plusieurs des Juifs qui étaient venus vers Marie, et qui virent ce que fit Jésus, crurent en lui.'),
  (43, 11, 46, 'Mais quelques-uns d''entre eux allèrent trouver les pharisiens, et leur dirent ce que Jésus avait fait.'),
  (43, 11, 47, 'Alors les principaux sacrificateurs et les pharisiens assemblèrent le sanhédrin, et dirent: Que ferons-nous? Car cet homme fait beaucoup de miracles.'),
  (43, 11, 48, 'Si nous le laissons faire, tous croiront en lui, et les Romains viendront détruire et notre ville et notre nation.'),
  (43, 11, 49, 'L''un d''eux, Caïphe, qui était souverain sacrificateur cette année-là, leur dit: Vous n''y entendez rien;'),
  (43, 11, 50, 'vous ne réfléchissez pas qu''il est dans votre intérêt qu''un seul homme meure pour le peuple, et que la nation entière ne périsse pas.'),
  (43, 11, 51, 'Or, il ne dit pas cela de lui-même; mais étant souverain sacrificateur cette année-là, il prophétisa que Jésus devait mourir pour la nation.'),
  (43, 11, 52, 'Et ce n''était pas pour la nation seulement; c''était aussi afin de réunir en un seul corps les enfants de Dieu dispersés.'),
  (43, 11, 53, 'Dès ce jour, ils résolurent de le faire mourir.'),
  (43, 11, 54, 'C''est pourquoi Jésus ne se montra plus ouvertement parmi les Juifs; mais il se retira dans la contrée voisine du désert, dans une ville appelée Éphraïm; et là il demeurait avec ses disciples.'),
  (43, 11, 55, 'La Pâque des Juifs était proche. Et beaucoup de gens du pays montèrent à Jérusalem avant la Pâque, pour se purifier.'),
  (43, 11, 56, 'Ils cherchaient Jésus, et ils se disaient les uns aux autres dans le temple: Que vous en semble? Ne viendra-t-il pas à la fête?'),
  (43, 11, 57, 'Or, les principaux sacrificateurs et les pharisiens avaient donné l''ordre que, si quelqu''un savait où il était, il le déclarât, afin qu''on se saisît de lui.'),
  (43, 12, 1, 'Six jours avant la Pâque, Jésus arriva à Béthanie, où était Lazare, qu''il avait ressuscité des morts.'),
  (43, 12, 2, 'Là, on lui fit un souper; Marthe servait, et Lazare était un de ceux qui se trouvaient à table avec lui.'),
  (43, 12, 3, 'Marie, ayant pris une livre d''un parfum de nard pur de grand prix, oignit les pieds de Jésus, et elle lui essuya les pieds avec ses cheveux; et la maison fut remplie de l''odeur du parfum.'),
  (43, 12, 4, 'Un de ses disciples, Judas Iscariot, fils de Simon, celui qui devait le livrer, dit:'),
  (43, 12, 5, 'Pourquoi n''a-t-on pas vendu ce parfum trois cents deniers, pour les donner aux pauvres?'),
  (43, 12, 6, 'Il disait cela, non qu''il se mît en peine des pauvres, mais parce qu''il était voleur, et que, tenant la bourse, il prenait ce qu''on y mettait.'),
  (43, 12, 7, 'Mais Jésus dit: Laisse-la garder ce parfum pour le jour de ma sépulture.'),
  (43, 12, 8, 'Vous avez toujours les pauvres avec vous, mais vous ne m''avez pas toujours.'),
  (43, 12, 9, 'Une grande multitude de Juifs apprirent que Jésus était à Béthanie; et ils y vinrent, non pas seulement à cause de lui, mais aussi pour voir Lazare, qu''il avait ressuscité des morts.'),
  (43, 12, 10, 'Les principaux sacrificateurs délibérèrent de faire mourir aussi Lazare,'),
  (43, 12, 11, 'parce que beaucoup de Juifs se retiraient d''eux à cause de lui, et croyaient en Jésus.'),
  (43, 12, 12, 'Le lendemain, une foule nombreuse de gens venus à la fête ayant entendu dire que Jésus se rendait à Jérusalem,'),
  (43, 12, 13, 'prirent des branches de palmiers, et allèrent au-devant de lui, en criant: Hosanna! Béni soit celui qui vient au nom du Seigneur, le roi d''Israël!'),
  (43, 12, 14, 'Jésus trouva un ânon, et s''assit dessus, selon ce qui est écrit:'),
  (43, 12, 15, 'Ne crains point, fille de Sion; Voici, ton roi vient, Assis sur le petit d''une ânesse.'),
  (43, 12, 16, 'Ses disciples ne comprirent pas d''abord ces choses; mais, lorsque Jésus eut été glorifié, ils se souvinrent qu''elles étaient écrites de lui, et qu''ils les avaient accomplies à son égard.'),
  (43, 12, 17, 'Tous ceux qui étaient avec Jésus, quand il appela Lazare du sépulcre et le ressuscita des morts, lui rendaient témoignage;'),
  (43, 12, 18, 'et la foule vint au-devant de lui, parce qu''elle avait appris qu''il avait fait ce miracle.'),
  (43, 12, 19, 'Les pharisiens se dirent donc les uns aux autres: Vous voyez que vous ne gagnez rien; voici, le monde est allé après lui.'),
  (43, 12, 20, 'Quelques Grecs, du nombre de ceux qui étaient montés pour adorer pendant la fête,'),
  (43, 12, 21, 's''adressèrent à Philippe, de Bethsaïda en Galilée, et lui dirent avec instance: Seigneur, nous voudrions voir Jésus.'),
  (43, 12, 22, 'Philippe alla le dire à André, puis André et Philippe le dirent à Jésus.'),
  (43, 12, 23, 'Jésus leur répondit: L''heure est venue où le Fils de l''homme doit être glorifié.'),
  (43, 12, 24, 'En vérité, en vérité, je vous le dis, si le grain de blé qui est tombé en terre ne meurt, il reste seul; mais, s''il meurt, il porte beaucoup de fruit.'),
  (43, 12, 25, 'Celui qui aime sa vie la perdra, et celui qui hait sa vie dans ce monde la conservera pour la vie éternelle.'),
  (43, 12, 26, 'Si quelqu''un me sert, qu''il me suive; et là où je suis, là aussi sera mon serviteur. Si quelqu''un me sert, le Père l''honorera.'),
  (43, 12, 27, 'Maintenant mon âme est troublée. Et que dirai-je?… Père, délivre-moi de cette heure?… Mais c''est pour cela que je suis venu jusqu''à cette heure.'),
  (43, 12, 28, 'Père, glorifie ton nom! Et une voix vint du ciel: Je l''ai glorifié, et je le glorifierai encore.'),
  (43, 12, 29, 'La foule qui était là, et qui avait entendu, disait que c''était un tonnerre. D''autres disaient: Un ange lui a parlé.'),
  (43, 12, 30, 'Jésus dit: Ce n''est pas à cause de moi que cette voix s''est fait entendre; c''est à cause de vous.'),
  (43, 12, 31, 'Maintenant a lieu le jugement de ce monde; maintenant le prince de ce monde sera jeté dehors.'),
  (43, 12, 32, 'Et moi, quand j''aurai été élevé de la terre, j''attirerai tous les hommes à moi.'),
  (43, 12, 33, 'En parlant ainsi, il indiquait de quelle mort il devait mourir. -'),
  (43, 12, 34, 'La foule lui répondit: Nous avons appris par la loi que le Christ demeure éternellement; comment donc dis-tu: Il faut que le Fils de l''homme soit élevé? Qui est ce Fils de l''homme?'),
  (43, 12, 35, 'Jésus leur dit: La lumière est encore pour un peu de temps au milieu de vous. Marchez, pendant que vous avez la lumière, afin que les ténèbres ne vous surprennent point: celui qui marche dans les ténèbres ne sait où il va.'),
  (43, 12, 36, 'Pendant que vous avez la lumière, croyez en la lumière, afin que vous soyez des enfants de lumière. Jésus dit ces choses, puis il s''en alla, et se cacha loin d''eux.'),
  (43, 12, 37, 'Malgré tant de miracles qu''il avait faits en leur présence, ils ne croyaient pas en lui,'),
  (43, 12, 38, 'afin que s''accomplît la parole qu''Ésaïe, le prophète, a prononcée: Seigneur, Qui a cru à notre prédication? Et à qui le bras du Seigneur a-t-il été révélé?'),
  (43, 12, 39, 'Aussi ne pouvaient-ils croire, parce qu''Ésaïe a dit encore:'),
  (43, 12, 40, 'Il a aveuglé leurs yeux; et il a endurci leur cœur, De peur qu''ils ne voient des yeux, Qu''ils ne comprennent du cœur, Qu''ils ne se convertissent, et que je ne les guérisse.'),
  (43, 12, 41, 'Ésaïe dit ces choses, lorsqu''il vit sa gloire, et qu''il parla de lui.'),
  (43, 12, 42, 'Cependant, même parmi les chefs, plusieurs crurent en lui; mais, à cause des pharisiens, ils n''en faisaient pas l''aveu, dans la crainte d''être exclus de la synagogue.'),
  (43, 12, 43, 'Car ils aimèrent la gloire des hommes plus que la gloire de Dieu.'),
  (43, 12, 44, 'Or, Jésus s''était écrié: Celui qui croit en moi croit, non pas en moi, mais en celui qui m''a envoyé;'),
  (43, 12, 45, 'et celui qui me voit voit celui qui m''a envoyé.'),
  (43, 12, 46, 'Je suis venu comme une lumière dans le monde, afin que quiconque croit en moi ne demeure pas dans les ténèbres.'),
  (43, 12, 47, 'Si quelqu''un entend mes paroles et ne les garde point, ce n''est pas moi qui le juge; car je suis venu non pour juger le monde, mais pour sauver le monde.'),
  (43, 12, 48, 'Celui qui me rejette et qui ne reçoit pas mes paroles a son juge; la parole que j''ai annoncée, c''est elle qui le jugera au dernier jour.'),
  (43, 12, 49, 'Car je n''ai point parlé de moi-même; mais le Père, qui m''a envoyé, m''a prescrit lui-même ce que je dois dire et annoncer.'),
  (43, 12, 50, 'Et je sais que son commandement est la vie éternelle. C''est pourquoi les choses que je dis, je les dis comme le Père me les a dites.'),
  (43, 13, 1, 'Avant la fête de Pâque, Jésus, sachant que son heure était venue de passer de ce monde au Père, et ayant aimé les siens qui étaient dans le monde, mit le comble à son amour pour eux.'),
  (43, 13, 2, 'Pendant le souper, lorsque le diable avait déjà inspiré au cœur de Judas Iscariot, fils de Simon, le dessein de le livrer,'),
  (43, 13, 3, 'Jésus, qui savait que le Père avait remis toutes choses entre ses mains, qu''il était venu de Dieu, et qu''il s''en allait à Dieu,'),
  (43, 13, 4, 'se leva de table, ôta ses vêtements, et prit un linge, dont il se ceignit.'),
  (43, 13, 5, 'Ensuite il versa de l''eau dans un bassin, et il se mit à laver les pieds des disciples, et à les essuyer avec le linge dont il était ceint.'),
  (43, 13, 6, 'Il vint donc à Simon Pierre; et Pierre lui dit: Toi, Seigneur, tu me laves les pieds!'),
  (43, 13, 7, 'Jésus lui répondit: Ce que je fais, tu ne le comprends pas maintenant, mais tu le comprendras bientôt.'),
  (43, 13, 8, 'Pierre lui dit: Non, jamais tu ne me laveras les pieds. Jésus lui répondit: Si je ne te lave, tu n''auras point de part avec moi.'),
  (43, 13, 9, 'Simon Pierre lui dit: Seigneur, non seulement les pieds, mais encore les mains et la tête.'),
  (43, 13, 10, 'Jésus lui dit: Celui qui est lavé n''a besoin que de se laver les pieds pour être entièrement pur; et vous êtes purs, mais non pas tous.'),
  (43, 13, 11, 'Car il connaissait celui qui le livrait; c''est pourquoi il dit: Vous n''êtes pas tous purs.'),
  (43, 13, 12, 'Après qu''il leur eut lavé les pieds, et qu''il eut pris ses vêtements, il se remit à table, et leur dit: Comprenez-vous ce que je vous ai fait?'),
  (43, 13, 13, 'Vous m''appelez Maître et Seigneur; et vous dites bien, car je le suis.'),
  (43, 13, 14, 'Si donc je vous ai lavé les pieds, moi, le Seigneur et le Maître, vous devez aussi vous laver les pieds les uns aux autres;'),
  (43, 13, 15, 'car je vous ai donné un exemple, afin que vous fassiez comme je vous ai fait.'),
  (43, 13, 16, 'En vérité, en vérité, je vous le dis, le serviteur n''est pas plus grand que son seigneur, ni l''apôtre plus grand que celui qui l''a envoyé.'),
  (43, 13, 17, 'Si vous savez ces choses, vous êtes heureux, pourvu que vous les pratiquiez.'),
  (43, 13, 18, 'Ce n''est pas de vous tous que je parle; je connais ceux que j''ai choisis. Mais il faut que l''Écriture s''accomplisse: Celui qui mange avec moi le pain A levé son talon contre moi.'),
  (43, 13, 19, 'Dès à présent je vous le dis, avant que la chose arrive, afin que, lorsqu''elle arrivera, vous croyiez à ce que je suis.'),
  (43, 13, 20, 'En vérité, en vérité, je vous le dis, celui qui reçoit celui que j''aurai envoyé me reçoit, et celui qui me reçoit, reçoit celui qui m''a envoyé.'),
  (43, 13, 21, 'Ayant ainsi parlé, Jésus fut troublé en son esprit, et il dit expressément: En vérité, en vérité, je vous le dis, l''un de vous me livrera.'),
  (43, 13, 22, 'Les disciples se regardaient les uns les autres, ne sachant de qui il parlait.'),
  (43, 13, 23, 'Un des disciples, celui que Jésus aimait, était couché sur le sein de Jésus.'),
  (43, 13, 24, 'Simon Pierre lui fit signe de demander qui était celui dont parlait Jésus.'),
  (43, 13, 25, 'Et ce disciple, s''étant penché sur la poitrine de Jésus, lui dit: Seigneur, qui est-ce?'),
  (43, 13, 26, 'Jésus répondit: C''est celui à qui je donnerai le morceau trempé. Et, ayant trempé le morceau, il le donna à Judas, fils de Simon, l''Iscariot.'),
  (43, 13, 27, 'Dès que le morceau fut donné, Satan entra dans Judas. Jésus lui dit: Ce que tu fais, fais-le promptement.'),
  (43, 13, 28, 'Mais aucun de ceux qui étaient à table ne comprit pourquoi il lui disait cela;'),
  (43, 13, 29, 'car quelques-uns pensaient que, comme Judas avait la bourse, Jésus voulait lui dire: Achète ce dont nous avons besoin pour la fête, ou qu''il lui commandait de donner quelque chose aux pauvres.'),
  (43, 13, 30, 'Judas, ayant pris le morceau, se hâta de sortir. Il était nuit.'),
  (43, 13, 31, 'Lorsque Judas fut sorti, Jésus dit: Maintenant, le Fils de l''homme a été glorifié, et Dieu a été glorifié en lui.'),
  (43, 13, 32, 'Si Dieu a été glorifié en lui, Dieu aussi le glorifiera en lui-même, et il le glorifiera bientôt.'),
  (43, 13, 33, 'Mes petits enfants, je suis pour peu de temps encore avec vous. Vous me chercherez; et, comme j''ai dit aux Juifs: Vous ne pouvez venir où je vais, je vous le dis aussi maintenant.'),
  (43, 13, 34, 'Je vous donne un commandement nouveau: Aimez-vous les uns les autres; comme je vous ai aimés, vous aussi, aimez-vous les uns les autres.'),
  (43, 13, 35, 'A ceci tous connaîtront que vous êtes mes disciples, si vous avez de l''amour les uns pour les autres.'),
  (43, 13, 36, 'Simon Pierre lui dit: Seigneur, où vas-tu? Jésus répondit: Tu ne peux pas maintenant me suivre où je vais, mais tu me suivras plus tard.'),
  (43, 13, 37, 'Seigneur, lui dit Pierre, pourquoi ne puis-je pas te suivre maintenant? Je donnerai ma vie pour toi.'),
  (43, 13, 38, 'Jésus répondit: Tu donneras ta vie pour moi! En vérité, en vérité, je te le dis, le coq ne chantera pas que tu ne m''aies renié trois fois.'),
  (43, 14, 1, 'Que votre cœur ne se trouble point. Croyez en Dieu, et croyez en moi.'),
  (43, 14, 2, 'Il y a plusieurs demeures dans la maison de mon Père. Si cela n''était pas, je vous l''aurais dit. Je vais vous préparer une place.'),
  (43, 14, 3, 'Et, lorsque je m''en serai allé, et que je vous aurai préparé une place, je reviendrai, et je vous prendrai avec moi, afin que là où je suis vous y soyez aussi.'),
  (43, 14, 4, 'Vous savez où je vais, et vous en savez le chemin.'),
  (43, 14, 5, 'Thomas lui dit: Seigneur, nous ne savons où tu vas; comment pouvons-nous en savoir le chemin?'),
  (43, 14, 6, 'Jésus lui dit: Je suis le chemin, la vérité, et la vie. Nul ne vient au Père que par moi.'),
  (43, 14, 7, 'Si vous me connaissiez, vous connaîtriez aussi mon Père. Et dès maintenant vous le connaissez, et vous l''avez vu.'),
  (43, 14, 8, 'Philippe lui dit: Seigneur, montre-nous le Père, et cela nous suffit.'),
  (43, 14, 9, 'Jésus lui dit: Il y a si longtemps que je suis avec vous, et tu ne m''as pas connu, Philippe! Celui qui m''a vu a vu le Père; comment dis-tu: Montre-nous le Père?'),
  (43, 14, 10, 'Ne crois-tu pas que je suis dans le Père, et que le Père est en moi? Les paroles que je vous dis, je ne les dis pas de moi-même; et le Père qui demeure en moi, c''est lui qui fait les œuvres.'),
  (43, 14, 11, 'Croyez-moi, je suis dans le Père, et le Père est en moi; croyez du moins à cause de ces œuvres.'),
  (43, 14, 12, 'En vérité, en vérité, je vous le dis, celui qui croit en moi fera aussi les œuvres que je fais, et il en fera de plus grandes, parce que je m''en vais au Père;'),
  (43, 14, 13, 'et tout ce que vous demanderez en mon nom, je le ferai, afin que le Père soit glorifié dans le Fils.'),
  (43, 14, 14, 'Si vous demandez quelque chose en mon nom, je le ferai.'),
  (43, 14, 15, 'Si vous m''aimez, gardez mes commandements.'),
  (43, 14, 16, 'Et moi, je prierai le Père, et il vous donnera un autre consolateur, afin qu''il demeure éternellement avec vous,'),
  (43, 14, 17, 'l''Esprit de vérité, que le monde ne peut recevoir, parce qu''il ne le voit point et ne le connaît point; mais vous, vous le connaissez, car il demeure avec vous, et il sera en vous.'),
  (43, 14, 18, 'Je ne vous laisserai pas orphelins, je viendrai à vous.'),
  (43, 14, 19, 'Encore un peu de temps, et le monde ne me verra plus; mais vous, vous me verrez, car je vis, et vous vivrez aussi.'),
  (43, 14, 20, 'En ce jour-là, vous connaîtrez que je suis en mon Père, que vous êtes en moi, et que je suis en vous.'),
  (43, 14, 21, 'Celui qui a mes commandements et qui les garde, c''est celui qui m''aime; et celui qui m''aime sera aimé de mon Père, je l''aimerai, et je me ferai connaître à lui.'),
  (43, 14, 22, 'Jude, non pas l''Iscariot, lui dit: Seigneur, d''où vient que tu te feras connaître à nous, et non au monde?'),
  (43, 14, 23, 'Jésus lui répondit: Si quelqu''un m''aime, il gardera ma parole, et mon Père l''aimera; nous viendrons à lui, et nous ferons notre demeure chez lui.'),
  (43, 14, 24, 'Celui qui ne m''aime pas ne garde point mes paroles. Et la parole que vous entendez n''est pas de moi, mais du Père qui m''a envoyé.'),
  (43, 14, 25, 'Je vous ai dit ces choses pendant que je demeure avec vous.'),
  (43, 14, 26, 'Mais le consolateur, l''Esprit-Saint, que le Père enverra en mon nom, vous enseignera toutes choses, et vous rappellera tout ce que je vous ai dit.'),
  (43, 14, 27, 'Je vous laisse la paix, je vous donne ma paix. Je ne vous donne pas comme le monde donne. Que votre cœur ne se trouble point, et ne s''alarme point.'),
  (43, 14, 28, 'Vous avez entendu que je vous ai dit: Je m''en vais, et je reviens vers vous. Si vous m''aimiez, vous vous réjouiriez de ce que je vais au Père; car le Père est plus grand que moi.'),
  (43, 14, 29, 'Et maintenant je vous ai dit ces choses avant qu''elles arrivent, afin que, lorsqu''elles arriveront, vous croyiez.'),
  (43, 14, 30, 'Je ne parlerai plus guère avec vous; car le prince du monde vient. Il n''a rien en moi;'),
  (43, 14, 31, 'mais afin que le monde sache que j''aime le Père, et que j''agis selon l''ordre que le Père m''a donné, levez-vous, partons d''ici.'),
  (43, 15, 1, 'Je suis le vrai cep, et mon Père est le vigneron.'),
  (43, 15, 2, 'Tout sarment qui est en moi et qui ne porte pas de fruit, il le retranche; et tout sarment qui porte du fruit, il l''émonde, afin qu''il porte encore plus de fruit.'),
  (43, 15, 3, 'Déjà vous êtes purs, à cause de la parole que je vous ai annoncée.'),
  (43, 15, 4, 'Demeurez en moi, et je demeurerai en vous. Comme le sarment ne peut de lui-même porter du fruit, s''il ne demeure attaché au cep, ainsi vous ne le pouvez non plus, si vous ne demeurez en moi.'),
  (43, 15, 5, 'Je suis le cep, vous êtes les sarments. Celui qui demeure en moi et en qui je demeure porte beaucoup de fruit, car sans moi vous ne pouvez rien faire.'),
  (43, 15, 6, 'Si quelqu''un ne demeure pas en moi, il est jeté dehors, comme le sarment, et il sèche; puis on ramasse les sarments, on les jette au feu, et ils brûlent.'),
  (43, 15, 7, 'Si vous demeurez en moi, et que mes paroles demeurent en vous, demandez ce que vous voudrez, et cela vous sera accordé.'),
  (43, 15, 8, 'Si vous portez beaucoup de fruit, c''est ainsi que mon Père sera glorifié, et que vous serez mes disciples.'),
  (43, 15, 9, 'Comme le Père m''a aimé, je vous ai aussi aimés. Demeurez dans mon amour.'),
  (43, 15, 10, 'Si vous gardez mes commandements, vous demeurerez dans mon amour, de même que j''ai gardé les commandements de mon Père, et que je demeure dans son amour.'),
  (43, 15, 11, 'Je vous ai dit ces choses, afin que ma joie soit en vous, et que votre joie soit parfaite.'),
  (43, 15, 12, 'C''est ici mon commandement: Aimez-vous les uns les autres, comme je vous ai aimés.'),
  (43, 15, 13, 'Il n''y a pas de plus grand amour que de donner sa vie pour ses amis.'),
  (43, 15, 14, 'Vous êtes mes amis, si vous faites ce que je vous commande.'),
  (43, 15, 15, 'Je ne vous appelle plus serviteurs, parce que le serviteur ne sait pas ce que fait son maître; mais je vous ai appelés amis, parce que je vous ai fait connaître tout ce que j''ai appris de mon Père.'),
  (43, 15, 16, 'Ce n''est pas vous qui m''avez choisi; mais moi, je vous ai choisis, et je vous ai établis, afin que vous alliez, et que vous portiez du fruit, et que votre fruit demeure, afin que ce que vous demanderez au Père en mon nom, il vous le donne.'),
  (43, 15, 17, 'Ce que je vous commande, c''est de vous aimer les uns les autres.'),
  (43, 15, 18, 'Si le monde vous hait, sachez qu''il m''a haï avant vous.'),
  (43, 15, 19, 'Si vous étiez du monde, le monde aimerait ce qui est à lui; mais parce que vous n''êtes pas du monde, et que je vous ai choisis du milieu du monde, à cause de cela le monde vous hait.'),
  (43, 15, 20, 'Souvenez-vous de la parole que je vous ai dite: Le serviteur n''est pas plus grand que son maître. S''ils m''ont persécuté, ils vous persécuteront aussi; s''ils ont gardé ma parole, ils garderont aussi la vôtre.'),
  (43, 15, 21, 'Mais ils vous feront toutes ces choses à cause de mon nom, parce qu''ils ne connaissent pas celui qui m''a envoyé.'),
  (43, 15, 22, 'Si je n''étais pas venu et que je ne leur eusse point parlé, ils n''auraient pas de péché; mais maintenant ils n''ont aucune excuse de leur péché.'),
  (43, 15, 23, 'Celui qui me hait, hait aussi mon Père.'),
  (43, 15, 24, 'Si je n''avais pas fait parmi eux des œuvres que nul autre n''a faites, ils n''auraient pas de péché; mais maintenant ils les ont vues, et ils ont haï et moi et mon Père.'),
  (43, 15, 25, 'Mais cela est arrivé afin que s''accomplît la parole qui est écrite dans leur loi: Ils m''ont haï sans cause.'),
  (43, 15, 26, 'Quand sera venu le consolateur, que je vous enverrai de la part du Père, l''Esprit de vérité, qui vient du Père, il rendra témoignage de moi;'),
  (43, 15, 27, 'et vous aussi, vous rendrez témoignage, parce que vous êtes avec moi dès le commencement.'),
  (43, 16, 1, 'Je vous ai dit ces choses, afin qu''elles ne soient pas pour vous une occasion de chute.'),
  (43, 16, 2, 'Ils vous excluront des synagogues; et même l''heure vient où quiconque vous fera mourir croira rendre un culte à Dieu.'),
  (43, 16, 3, 'Et ils agiront ainsi, parce qu''ils n''ont connu ni le Père ni moi.'),
  (43, 16, 4, 'Je vous ai dit ces choses, afin que, lorsque l''heure sera venue, vous vous souveniez que je vous les ai dites. Je ne vous en ai pas parlé dès le commencement, parce que j''étais avec vous.'),
  (43, 16, 5, 'Maintenant je m''en vais vers celui qui m''a envoyé, et aucun de vous ne me demande: Où vas-tu?'),
  (43, 16, 6, 'Mais, parce que je vous ai dit ces choses, la tristesse a rempli votre cœur.'),
  (43, 16, 7, 'Cependant je vous dis la vérité: il vous est avantageux que je m''en aille, car si je ne m''en vais pas, le consolateur ne viendra pas vers vous; mais, si je m''en vais, je vous l''enverrai.'),
  (43, 16, 8, 'Et quand il sera venu, il convaincra le monde en ce qui concerne le péché, la justice, et le jugement:'),
  (43, 16, 9, 'en ce qui concerne le péché, parce qu''ils ne croient pas en moi;'),
  (43, 16, 10, 'la justice, parce que je vais au Père, et que vous ne me verrez plus;'),
  (43, 16, 11, 'le jugement, parce que le prince de ce monde est jugé.'),
  (43, 16, 12, 'J''ai encore beaucoup de choses à vous dire, mais vous ne pouvez pas les porter maintenant.'),
  (43, 16, 13, 'Quand le consolateur sera venu, l''Esprit de vérité, il vous conduira dans toute la vérité; car il ne parlera pas de lui-même, mais il dira tout ce qu''il aura entendu, et il vous annoncera les choses à venir.'),
  (43, 16, 14, 'Il me glorifiera, parce qu''il prendra de ce qui est à moi, et vous l''annoncera.'),
  (43, 16, 15, 'Tout ce que le Père a est à moi; c''est pourquoi j''ai dit qu''il prend de ce qui est à moi, et qu''il vous l''annoncera.'),
  (43, 16, 16, 'Encore un peu de temps, et vous ne me verrez plus; et puis encore un peu de temps, et vous me verrez, parce que je vais au Père.'),
  (43, 16, 17, 'Là-dessus, quelques-uns de ses disciples dirent entre eux: Que signifie ce qu''il nous dit: Encore un peu de temps, et vous ne me verrez plus; et puis encore un peu de temps, et vous me verrez? et: Parce que je vais au Père?'),
  (43, 16, 18, 'Ils disaient donc: Que signifie ce qu''il dit: Encore un peu de temps? Nous ne savons de quoi il parle.'),
  (43, 16, 19, 'Jésus, connut qu''ils voulaient l''interroger, leur dit: Vous vous questionnez les uns les autres sur ce que j''ai dit: Encore un peu de temps, et vous ne me verrez plus; et puis encore un peu de temps, et vous me verrez.'),
  (43, 16, 20, 'En vérité, en vérité, je vous le dis, vous pleurerez et vous vous lamenterez, et le monde se réjouira: vous serez dans la tristesse, mais votre tristesse se changera en joie.'),
  (43, 16, 21, 'La femme, lorsqu''elle enfante, éprouve de la tristesse, parce que son heure est venue; mais, lorsqu''elle a donné le jour à l''enfant, elle ne se souvient plus de la souffrance, à cause de la joie qu''elle a de ce qu''un homme est né dans le monde.'),
  (43, 16, 22, 'Vous donc aussi, vous êtes maintenant dans la tristesse; mais je vous reverrai, et votre cœur se réjouira, et nul ne vous ravira votre joie.'),
  (43, 16, 23, 'En ce jour-là, vous ne m''interrogerez plus sur rien. En vérité, en vérité, je vous le dis, ce que vous demanderez au Père, il vous le donnera en mon nom.'),
  (43, 16, 24, 'Jusqu''à présent vous n''avez rien demandé en mon nom. Demandez, et vous recevrez, afin que votre joie soit parfaite.'),
  (43, 16, 25, 'Je vous ai dit ces choses en paraboles. L''heure vient où je ne vous parlerai plus en paraboles, mais où je vous parlerai ouvertement du Père.'),
  (43, 16, 26, 'En ce jour, vous demanderez en mon nom, et je ne vous dis pas que je prierai le Père pour vous;'),
  (43, 16, 27, 'car le Père lui-même vous aime, parce que vous m''avez aimé, et que vous avez cru que je suis sorti de Dieu.'),
  (43, 16, 28, 'Je suis sorti du Père, et je suis venu dans le monde; maintenant je quitte le monde, et je vais au Père.'),
  (43, 16, 29, 'Ses disciples lui dirent: Voici, maintenant tu parles ouvertement, et tu n''emploies aucune parabole.'),
  (43, 16, 30, 'Maintenant nous savons que tu sais toutes choses, et que tu n''as pas besoin que personne t''interroge; c''est pourquoi nous croyons que tu es sorti de Dieu.'),
  (43, 16, 31, 'Jésus leur répondit: Vous croyez maintenant.'),
  (43, 16, 32, 'Voici, l''heure vient, et elle est déjà venue, où vous serez dispersés chacun de son côté, et où vous me laisserez seul; mais je ne suis pas seul, car le Père est avec moi.'),
  (43, 16, 33, 'Je vous ai dit ces choses, afin que vous ayez la paix en moi. Vous aurez des tribulations dans le monde; mais prenez courage, j''ai vaincu le monde.'),
  (43, 17, 1, 'Après avoir ainsi parlé, Jésus leva les yeux au ciel, et dit: Père, l''heure est venue! Glorifie ton Fils, afin que ton Fils te glorifie,'),
  (43, 17, 2, 'selon que tu lui as donné pouvoir sur toute chair, afin qu''il accorde la vie éternelle à tous ceux que tu lui as donnés.'),
  (43, 17, 3, 'Or, la vie éternelle, c''est qu''ils te connaissent, toi, le seul vrai Dieu, et celui que tu as envoyé, Jésus-Christ.'),
  (43, 17, 4, 'Je t''ai glorifié sur la terre, j''ai achevé l''œuvre que tu m''as donnée à faire.'),
  (43, 17, 5, 'Et maintenant toi, Père, glorifie-moi auprès de toi-même de la gloire que j''avais auprès de toi avant que le monde fût.'),
  (43, 17, 6, 'J''ai fait connaître ton nom aux hommes que tu m''as donnés du milieu du monde. Ils étaient à toi, et tu me les as donnés; et ils ont gardé ta parole.'),
  (43, 17, 7, 'Maintenant ils ont connu que tout ce que tu m''as donné vient de toi.'),
  (43, 17, 8, 'Car je leur ai donné les paroles que tu m''as données; et ils les ont reçues, et ils ont vraiment connu que je suis sorti de toi, et ils ont cru que tu m''as envoyé.'),
  (43, 17, 9, 'C''est pour eux que je prie. Je ne prie pas pour le monde, mais pour ceux que tu m''as donnés, parce qu''ils sont à toi; -'),
  (43, 17, 10, 'et tout ce qui est à moi est à toi, et ce qui est à toi est à moi; -et je suis glorifié en eux.'),
  (43, 17, 11, 'Je ne suis plus dans le monde, et ils sont dans le monde, et je vais à toi. Père saint, garde en ton nom ceux que tu m''as donnés, afin qu''ils soient un comme nous.'),
  (43, 17, 12, 'Lorsque j''étais avec eux dans le monde, je les gardais en ton nom. J''ai gardé ceux que tu m''as donnés, et aucun d''eux ne s''est perdu, sinon le fils de perdition, afin que l''Écriture fût accomplie.'),
  (43, 17, 13, 'Et maintenant je vais à toi, et je dis ces choses dans le monde, afin qu''ils aient en eux ma joie parfaite.'),
  (43, 17, 14, 'Je leur ai donné ta parole; et le monde les a haïs, parce qu''ils ne sont pas du monde, comme moi je ne suis pas du monde.'),
  (43, 17, 15, 'Je ne te prie pas de les ôter du monde, mais de les préserver du mal.'),
  (43, 17, 16, 'Ils ne sont pas du monde, comme moi je ne suis pas du monde.'),
  (43, 17, 17, 'Sanctifie-les par ta vérité: ta parole est la vérité.'),
  (43, 17, 18, 'Comme tu m''as envoyé dans le monde, je les ai aussi envoyés dans le monde.'),
  (43, 17, 19, 'Et je me sanctifie moi-même pour eux, afin qu''eux aussi soient sanctifiés par la vérité.'),
  (43, 17, 20, 'Ce n''est pas pour eux seulement que je prie, mais encore pour ceux qui croiront en moi par leur parole,'),
  (43, 17, 21, 'afin que tous soient un, comme toi, Père, tu es en moi, et comme je suis en toi, afin qu''eux aussi soient un en nous, pour que le monde croie que tu m''as envoyé.'),
  (43, 17, 22, 'Je leur ai donné la gloire que tu m''as donnée, afin qu''ils soient un comme nous sommes un, -'),
  (43, 17, 23, 'moi en eux, et toi en moi, -afin qu''ils soient parfaitement un, et que le monde connaisse que tu m''as envoyé et que tu les as aimés comme tu m''as aimé.'),
  (43, 17, 24, 'Père, je veux que là où je suis ceux que tu m''as donnés soient aussi avec moi, afin qu''ils voient ma gloire, la gloire que tu m''as donnée, parce que tu m''as aimé avant la fondation du monde.'),
  (43, 17, 25, 'Père juste, le monde ne t''a point connu; mais moi je t''ai connu, et ceux-ci ont connu que tu m''as envoyé.'),
  (43, 17, 26, 'Je leur ai fait connaître ton nom, et je le leur ferai connaître, afin que l''amour dont tu m''as aimé soit en eux, et que je sois en eux.'),
  (43, 18, 1, 'Lorsqu''il eut dit ces choses, Jésus alla avec ses disciples de l''autre côté du torrent du Cédron, où se trouvait un jardin, dans lequel il entra, lui et ses disciples.'),
  (43, 18, 2, 'Judas, qui le livrait, connaissait ce lieu, parce que Jésus et ses disciples s''y étaient souvent réunis.'),
  (43, 18, 3, 'Judas donc, ayant pris la cohorte, et des huissiers qu''envoyèrent les principaux sacrificateurs et les pharisiens, vint là avec des lanternes, des flambeaux et des armes.'),
  (43, 18, 4, 'Jésus, sachant tout ce qui devait lui arriver, s''avança, et leur dit: Qui cherchez-vous?'),
  (43, 18, 5, 'Ils lui répondirent: Jésus de Nazareth. Jésus leur dit: C''est moi. Et Judas, qui le livrait, était avec eux.'),
  (43, 18, 6, 'Lorsque Jésus leur eut dit: C''est moi, ils reculèrent et tombèrent par terre.'),
  (43, 18, 7, 'Il leur demanda de nouveau: Qui cherchez-vous? Et ils dirent: Jésus de Nazareth.'),
  (43, 18, 8, 'Jésus répondit: Je vous ai dit que c''est moi. Si donc c''est moi que vous cherchez, laissez aller ceux-ci.'),
  (43, 18, 9, 'Il dit cela, afin que s''accomplît la parole qu''il avait dite: Je n''ai perdu aucun de ceux que tu m''as donnés.'),
  (43, 18, 10, 'Simon Pierre, qui avait une épée, la tira, frappa le serviteur du souverain sacrificateur, et lui coupa l''oreille droite. Ce serviteur s''appelait Malchus.'),
  (43, 18, 11, 'Jésus dit à Pierre: Remets ton épée dans le fourreau. Ne boirai-je pas la coupe que le Père m''a donnée à boire?'),
  (43, 18, 12, 'La cohorte, le tribun, et les huissiers des Juifs, se saisirent alors de Jésus, et le lièrent.'),
  (43, 18, 13, 'Ils l''emmenèrent d''abord chez Anne; car il était le beau-père de Caïphe, qui était souverain sacrificateur cette année-là.'),
  (43, 18, 14, 'Et Caïphe était celui qui avait donné ce conseil aux Juifs: Il est avantageux qu''un seul homme meure pour le peuple.'),
  (43, 18, 15, 'Simon Pierre, avec un autre disciple, suivait Jésus. Ce disciple était connu du souverain sacrificateur, et il entra avec Jésus dans la cour du souverain sacrificateur;'),
  (43, 18, 16, 'mais Pierre resta dehors près de la porte. L''autre disciple, qui était connu du souverain sacrificateur, sortit, parla à la portière, et fit entrer Pierre.'),
  (43, 18, 17, 'Alors la servante, la portière, dit à Pierre: Toi aussi, n''es-tu pas des disciples de cet homme? Il dit: Je n''en suis point.'),
  (43, 18, 18, 'Les serviteurs et les huissiers, qui étaient là, avaient allumé un brasier, car il faisait froid, et ils se chauffaient. Pierre se tenait avec eux, et se chauffait.'),
  (43, 18, 19, 'Le souverain sacrificateur interrogea Jésus sur ses disciples et sur sa doctrine.'),
  (43, 18, 20, 'Jésus lui répondit: J''ai parlé ouvertement au monde; j''ai toujours enseigné dans la synagogue et dans le temple, où tous les Juifs s''assemblent, et je n''ai rien dit en secret.'),
  (43, 18, 21, 'Pourquoi m''interroges-tu? Interroge sur ce que je leur ai dit ceux qui m''ont entendu; voici, ceux-là savent ce que j''ai dit.'),
  (43, 18, 22, 'A ces mots, un des huissiers, qui se trouvait là, donna un soufflet à Jésus, en disant: Est-ce ainsi que tu réponds au souverain sacrificateur?'),
  (43, 18, 23, 'Jésus lui dit: Si j''ai mal parlé, fais voir ce que j''ai dit de mal; et si j''ai bien parlé, pourquoi me frappes-tu?'),
  (43, 18, 24, 'Anne l''envoya lié à Caïphe, le souverain sacrificateur.'),
  (43, 18, 25, 'Simon Pierre était là, et se chauffait. On lui dit: Toi aussi, n''es-tu pas de ses disciples? Il le nia, et dit: Je n''en suis point.'),
  (43, 18, 26, 'Un des serviteurs du souverain sacrificateur, parent de celui à qui Pierre avait coupé l''oreille, dit: Ne t''ai-je pas vu avec lui dans le jardin?'),
  (43, 18, 27, 'Pierre le nia de nouveau. Et aussitôt le coq chanta.'),
  (43, 18, 28, 'Ils conduisirent Jésus de chez Caïphe au prétoire: c''était le matin. Ils n''entrèrent point eux-mêmes dans le prétoire, afin de ne pas se souiller, et de pouvoir manger la Pâque.'),
  (43, 18, 29, 'Pilate sortit donc pour aller à eux, et il dit: Quelle accusation portez-vous contre cet homme?'),
  (43, 18, 30, 'Ils lui répondirent: Si ce n''était pas un malfaiteur, nous ne te l''aurions pas livré.'),
  (43, 18, 31, 'Sur quoi Pilate leur dit: Prenez-le vous-mêmes, et jugez-le selon votre loi. Les Juifs lui dirent: Il ne nous est pas permis de mettre personne à mort.'),
  (43, 18, 32, 'C''était afin que s''accomplît la parole que Jésus avait dite, lorsqu''il indiqua de quelle mort il devait mourir.'),
  (43, 18, 33, 'Pilate rentra dans le prétoire, appela Jésus, et lui dit: Es-tu le roi des Juifs?'),
  (43, 18, 34, 'Jésus répondit: Est-ce de toi-même que tu dis cela, ou d''autres te l''ont-ils dit de moi?'),
  (43, 18, 35, 'Pilate répondit: Moi, suis-je Juif? Ta nation et les principaux sacrificateurs t''ont livré à moi: qu''as-tu fait?'),
  (43, 18, 36, 'Mon royaume n''est pas de ce monde, répondit Jésus. Si mon royaume était de ce monde, mes serviteurs auraient combattu pour moi afin que je ne fusse pas livré aux Juifs; mais maintenant mon royaume n''est point d''ici-bas.'),
  (43, 18, 37, 'Pilate lui dit: Tu es donc roi? Jésus répondit: Tu le dis, je suis roi. Je suis né et je suis venu dans le monde pour rendre témoignage à la vérité. Quiconque est de la vérité écoute ma voix.'),
  (43, 18, 38, 'Pilate lui dit: Qu''est-ce que la vérité? Après avoir dit cela, il sortit de nouveau pour aller vers les Juifs, et il leur dit: Je ne trouve aucun crime en lui.'),
  (43, 18, 39, 'Mais, comme c''est parmi vous une coutume que je vous relâche quelqu''un à la fête de Pâque, voulez-vous que je vous relâche le roi des Juifs?'),
  (43, 18, 40, 'Alors de nouveau tous s''écrièrent: Non pas lui, mais Barabbas. Or, Barabbas était un brigand.'),
  (43, 19, 1, 'Alors Pilate prit Jésus, et le fit battre de verges.'),
  (43, 19, 2, 'Les soldats tressèrent une couronne d''épines qu''ils posèrent sur sa tête, et ils le revêtirent d''un manteau de pourpre; puis, s''approchant de lui,'),
  (43, 19, 3, 'ils disaient: Salut, roi des Juifs! Et ils lui donnaient des soufflets.'),
  (43, 19, 4, 'Pilate sortit de nouveau, et dit aux Juifs: Voici, je vous l''amène dehors, afin que vous sachiez que je ne trouve en lui aucun crime.'),
  (43, 19, 5, 'Jésus sortit donc, portant la couronne d''épines et le manteau de pourpre. Et Pilate leur dit: Voici l''homme.'),
  (43, 19, 6, 'Lorsque les principaux sacrificateurs et les huissiers le virent, ils s''écrièrent: Crucifie! crucifie! Pilate leur dit: Prenez-le vous-mêmes, et crucifiez-le; car moi, je ne trouve point de crime en lui.'),
  (43, 19, 7, 'Les Juifs lui répondirent: Nous avons une loi; et, selon notre loi, il doit mourir, parce qu''il s''est fait Fils de Dieu.'),
  (43, 19, 8, 'Quand Pilate entendit cette parole, sa frayeur augmenta.'),
  (43, 19, 9, 'Il rentra dans le prétoire, et il dit à Jésus: D''où es-tu? Mais Jésus ne lui donna point de réponse.'),
  (43, 19, 10, 'Pilate lui dit: Est-ce à moi que tu ne parles pas? Ne sais-tu pas que j''ai le pouvoir de te crucifier, et que j''ai le pouvoir de te relâcher?'),
  (43, 19, 11, 'Jésus répondit: Tu n''aurais sur moi aucun pouvoir, s''il ne t''avait été donné d''en haut. C''est pourquoi celui qui me livre à toi commet un plus grand péché.'),
  (43, 19, 12, 'Dès ce moment, Pilate cherchait à le relâcher. Mais les Juifs criaient: Si tu le relâches, tu n''es pas ami de César. Quiconque se fait roi se déclare contre César.'),
  (43, 19, 13, 'Pilate, ayant entendu ces paroles, amena Jésus dehors; et il s''assit sur le tribunal, au lieu appelé le Pavé, et en hébreu Gabbatha.'),
  (43, 19, 14, 'C''était la préparation de la Pâque, et environ la sixième heure. Pilate dit aux Juifs: Voici votre roi.'),
  (43, 19, 15, 'Mais ils s''écrièrent: Ote, ôte, crucifie-le! Pilate leur dit: Crucifierai-je votre roi? Les principaux sacrificateurs répondirent: Nous n''avons de roi que César.'),
  (43, 19, 16, 'Alors il le leur livra pour être crucifié. Ils prirent donc Jésus, et l''emmenèrent.'),
  (43, 19, 17, 'Jésus, portant sa croix, arriva au lieu du crâne, qui se nomme en hébreu Golgotha.'),
  (43, 19, 18, 'C''est là qu''il fut crucifié, et deux autres avec lui, un de chaque côté, et Jésus au milieu.'),
  (43, 19, 19, 'Pilate fit une inscription, qu''il plaça sur la croix, et qui était ainsi conçue: Jésus de Nazareth, roi des Juifs.'),
  (43, 19, 20, 'Beaucoup de Juifs lurent cette inscription, parce que le lieu où Jésus fut crucifié était près de la ville: elle était en hébreu, en grec et en latin.'),
  (43, 19, 21, 'Les principaux sacrificateurs des Juifs dirent à Pilate: N''écris pas: Roi des Juifs. Mais écris qu''il a dit: Je suis roi des Juifs.'),
  (43, 19, 22, 'Pilate répondit: Ce que j''ai écrit, je l''ai écrit.'),
  (43, 19, 23, 'Les soldats, après avoir crucifié Jésus, prirent ses vêtements, et ils en firent quatre parts, une part pour chaque soldat. Ils prirent aussi sa tunique, qui était sans couture, d''un seul tissu depuis le haut jusqu''en bas.'),
  (43, 19, 24, 'Et ils dirent entre eux: Ne la déchirons pas, mais tirons au sort à qui elle sera. Cela arriva afin que s''accomplît cette parole de l''Écriture: Ils se sont partagé mes vêtements, Et ils ont tiré au sort ma tunique. Voilà ce que firent les soldats.'),
  (43, 19, 25, 'Près de la croix de Jésus se tenaient sa mère et la sœur de sa mère, Marie, femme de Clopas, et Marie de Magdala.'),
  (43, 19, 26, 'Jésus, voyant sa mère, et auprès d''elle le disciple qu''il aimait, dit à sa mère: Femme, voilà ton fils.'),
  (43, 19, 27, 'Puis il dit au disciple: Voilà ta mère. Et, dès ce moment, le disciple la prit chez lui.'),
  (43, 19, 28, 'Après cela, Jésus, qui savait que tout était déjà consommé, dit, afin que l''Écriture fût accomplie: J''ai soif.'),
  (43, 19, 29, 'Il y avait là un vase plein de vinaigre. Les soldats en remplirent une éponge, et, l''ayant fixée à une branche d''hysope, ils l''approchèrent de sa bouche.'),
  (43, 19, 30, 'Quand Jésus eut pris le vinaigre, il dit: Tout est accompli. Et, baissant la tête, il rendit l''esprit.'),
  (43, 19, 31, 'Dans la crainte que les corps ne restassent sur la croix pendant le sabbat, -car c''était la préparation, et ce jour de sabbat était un grand jour, -les Juifs demandèrent à Pilate qu''on rompît les jambes aux crucifiés, et qu''on les enlevât.'),
  (43, 19, 32, 'Les soldats vinrent donc, et ils rompirent les jambes au premier, puis à l''autre qui avait été crucifié avec lui.'),
  (43, 19, 33, 'S''étant approchés de Jésus, et le voyant déjà mort, ils ne lui rompirent pas les jambes;'),
  (43, 19, 34, 'mais un des soldats lui perça le côté avec une lance, et aussitôt il sortit du sang et de l''eau.'),
  (43, 19, 35, 'Celui qui l''a vu en a rendu témoignage, et son témoignage est vrai; et il sait qu''il dit vrai, afin que vous croyiez aussi.'),
  (43, 19, 36, 'Ces choses sont arrivées, afin que l''Écriture fût accomplie: Aucun de ses os ne sera brisé.'),
  (43, 19, 37, 'Et ailleurs l''Écriture dit encore: Ils verront celui qu''ils ont percé.'),
  (43, 19, 38, 'Après cela, Joseph d''Arimathée, qui était disciple de Jésus, mais en secret par crainte des Juifs, demanda à Pilate la permission de prendre le corps de Jésus. Et Pilate le permit. Il vint donc, et prit le corps de Jésus.'),
  (43, 19, 39, 'Nicodème, qui auparavant était allé de nuit vers Jésus, vint aussi, apportant un mélange d''environ cent livres de myrrhe et d''aloès.'),
  (43, 19, 40, 'Ils prirent donc le corps de Jésus, et l''enveloppèrent de bandes, avec les aromates, comme c''est la coutume d''ensevelir chez les Juifs.'),
  (43, 19, 41, 'Or, il y avait un jardin dans le lieu où Jésus avait été crucifié, et dans le jardin un sépulcre neuf, où personne encore n''avait été mis.'),
  (43, 19, 42, 'Ce fut là qu''ils déposèrent Jésus, à cause de la préparation des Juifs, parce que le sépulcre était proche.'),
  (43, 20, 1, 'Le premier jour de la semaine, Marie de Magdala se rendit au sépulcre dès le matin, comme il faisait encore obscur; et elle vit que la pierre était ôtée du sépulcre.'),
  (43, 20, 2, 'Elle courut vers Simon Pierre et vers l''autre disciple que Jésus aimait, et leur dit: Ils ont enlevé du sépulcre le Seigneur, et nous ne savons où ils l''ont mis.'),
  (43, 20, 3, 'Pierre et l''autre disciple sortirent, et allèrent au sépulcre.'),
  (43, 20, 4, 'Ils couraient tous deux ensemble. Mais l''autre disciple courut plus vite que Pierre, et arriva le premier au sépulcre;'),
  (43, 20, 5, 's''étant baissé, il vit les bandes qui étaient à terre, cependant il n''entra pas.'),
  (43, 20, 6, 'Simon Pierre, qui le suivait, arriva et entra dans le sépulcre; il vit les bandes qui étaient à terre,'),
  (43, 20, 7, 'et le linge qu''on avait mis sur la tête de Jésus, non pas avec les bandes, mais plié dans un lieu à part.'),
  (43, 20, 8, 'Alors l''autre disciple, qui était arrivé le premier au sépulcre, entra aussi; et il vit, et il crut.'),
  (43, 20, 9, 'Car ils ne comprenaient pas encore que, selon l''Écriture, Jésus devait ressusciter des morts.'),
  (43, 20, 10, 'Et les disciples s''en retournèrent chez eux.'),
  (43, 20, 11, 'Cependant Marie se tenait dehors près du sépulcre, et pleurait. Comme elle pleurait, elle se baissa pour regarder dans le sépulcre;'),
  (43, 20, 12, 'et elle vit deux anges vêtus de blanc, assis à la place où avait été couché le corps de Jésus, l''un à la tête, l''autre aux pieds.'),
  (43, 20, 13, 'Ils lui dirent: Femme, pourquoi pleures-tu? Elle leur répondit: Parce qu''ils ont enlevé mon Seigneur, et je ne sais où ils l''ont mis.'),
  (43, 20, 14, 'En disant cela, elle se retourna, et elle vit Jésus debout; mais elle ne savait pas que c''était Jésus.'),
  (43, 20, 15, 'Jésus lui dit: Femme, pourquoi pleures-tu? Qui cherches-tu? Elle, pensant que c''était le jardinier, lui dit: Seigneur, si c''est toi qui l''as emporté, dis-moi où tu l''as mis, et je le prendrai.'),
  (43, 20, 16, 'Jésus lui dit: Marie! Elle se retourna, et lui dit en hébreu: Rabbouni! c''est-à-dire, Maître!'),
  (43, 20, 17, 'Jésus lui dit: Ne me touche pas; car je ne suis pas encore monté vers mon Père. Mais va trouver mes frères, et dis-leur que je monte vers mon Père et votre Père, vers mon Dieu et votre Dieu.'),
  (43, 20, 18, 'Marie de Magdala alla annoncer aux disciples qu''elle avait vu le Seigneur, et qu''il lui avait dit ces choses.'),
  (43, 20, 19, 'Le soir de ce jour, qui était le premier de la semaine, les portes du lieu où se trouvaient les disciples étant fermées, à cause de la crainte qu''ils avaient des Juifs, Jésus vint, se présenta au milieu d''eux, et leur dit: La paix soit avec vous!'),
  (43, 20, 20, 'Et quand il eut dit cela, il leur montra ses mains et son côté. Les disciples furent dans la joie en voyant le Seigneur.'),
  (43, 20, 21, 'Jésus leur dit de nouveau: La paix soit avec vous! Comme le Père m''a envoyé, moi aussi je vous envoie.'),
  (43, 20, 22, 'Après ces paroles, il souffla sur eux, et leur dit: Recevez le Saint-Esprit.'),
  (43, 20, 23, 'Ceux à qui vous pardonnerez les péchés, ils leur seront pardonnés; et ceux à qui vous les retiendrez, ils leur seront retenus.'),
  (43, 20, 24, 'Thomas, appelé Didyme, l''un des douze, n''était pas avec eux lorsque Jésus vint.'),
  (43, 20, 25, 'Les autres disciples lui dirent donc: Nous avons vu le Seigneur. Mais il leur dit: Si je ne vois dans ses mains la marque des clous, et si je ne mets mon doigt dans la marque des clous, et si je ne mets ma main dans son côté, je ne croirai point.'),
  (43, 20, 26, 'Huit jours après, les disciples de Jésus étaient de nouveau dans la maison, et Thomas se trouvait avec eux. Jésus vint, les portes étant fermées, se présenta au milieu d''eux, et dit: La paix soit avec vous!'),
  (43, 20, 27, 'Puis il dit à Thomas: Avance ici ton doigt, et regarde mes mains; avance aussi ta main, et mets-la dans mon côté; et ne sois pas incrédule, mais crois.'),
  (43, 20, 28, 'Thomas lui répondit: Mon Seigneur et mon Dieu!'),
  (43, 20, 29, 'Jésus lui dit: Parce que tu m''as vu, tu as cru. Heureux ceux qui n''ont pas vu, et qui ont cru!'),
  (43, 20, 30, 'Jésus a fait encore, en présence de ses disciples, beaucoup d''autres miracles, qui ne sont pas écrits dans ce livre.'),
  (43, 20, 31, 'Mais ces choses ont été écrites afin que vous croyiez que Jésus est le Christ, le Fils de Dieu, et qu''en croyant vous ayez la vie en son nom.'),
  (43, 21, 1, 'Après cela, Jésus se montra encore aux disciples, sur les bords de la mer de Tibériade. Et voici de quelle manière il se montra.'),
  (43, 21, 2, 'Simon Pierre, Thomas, appelé Didyme, Nathanaël, de Cana en Galilée, les fils de Zébédée, et deux autres disciples de Jésus, étaient ensemble.'),
  (43, 21, 3, 'Simon Pierre leur dit: Je vais pêcher. Ils lui dirent: Nous allons aussi avec toi. Ils sortirent et montèrent dans une barque, et cette nuit-là ils ne prirent rien.'),
  (43, 21, 4, 'Le matin étant venu, Jésus se trouva sur le rivage; mais les disciples ne savaient pas que c''était Jésus.'),
  (43, 21, 5, 'Jésus leur dit: Enfants, n''avez-vous rien à manger? Ils lui répondirent: Non.'),
  (43, 21, 6, 'Il leur dit: Jetez le filet du côté droit de la barque, et vous trouverez. Ils le jetèrent donc, et ils ne pouvaient plus le retirer, à cause de la grande quantité de poissons.'),
  (43, 21, 7, 'Alors le disciple que Jésus aimait dit à Pierre: C''est le Seigneur! Et Simon Pierre, dès qu''il eut entendu que c''était le Seigneur, mit son vêtement et sa ceinture, car il était nu, et se jeta dans la mer.'),
  (43, 21, 8, 'Les autres disciples vinrent avec la barque, tirant le filet plein de poissons, car ils n''étaient éloignés de terre que d''environ deux cents coudées.'),
  (43, 21, 9, 'Lorsqu''ils furent descendus à terre, ils virent là des charbons allumés, du poisson dessus, et du pain.'),
  (43, 21, 10, 'Jésus leur dit: Apportez des poissons que vous venez de prendre.'),
  (43, 21, 11, 'Simon Pierre monta dans la barque, et tira à terre le filet plein de cent cinquante-trois grands poissons; et quoiqu''il y en eût tant, le filet ne se rompit point.'),
  (43, 21, 12, 'Jésus leur dit: Venez, mangez. Et aucun des disciples n''osait lui demander: Qui es-tu? sachant que c''était le Seigneur.'),
  (43, 21, 13, 'Jésus s''approcha, prit le pain, et leur en donna; il fit de même du poisson.'),
  (43, 21, 14, 'C''était déjà la troisième fois que Jésus se montrait à ses disciples depuis qu''il était ressuscité des morts.'),
  (43, 21, 15, 'Après qu''ils eurent mangé, Jésus dit à Simon Pierre: Simon, fils de Jonas, m''aimes-tu plus que ne m''aiment ceux-ci? Il lui répondit: Oui, Seigneur, tu sais que je t''aime. Jésus lui dit: Pais mes agneaux.'),
  (43, 21, 16, 'Il lui dit une seconde fois: Simon, fils de Jonas, m''aimes-tu? Pierre lui répondit: Oui, Seigneur, tu sais que je t''aime. Jésus lui dit: Pais mes brebis.'),
  (43, 21, 17, 'Il lui dit pour la troisième fois: Simon, fils de Jonas, m''aimes-tu? Pierre fut attristé de ce qu''il lui avait dit pour la troisième fois: M''aimes-tu? Et il lui répondit: Seigneur, tu sais toutes choses, tu sais que je t''aime. Jésus lui dit: Pais mes brebis.'),
  (43, 21, 18, 'En vérité, en vérité, je te le dis, quand tu étais plus jeune, tu te ceignais toi-même, et tu allais où tu voulais; mais quand tu seras vieux, tu étendras tes mains, et un autre te ceindra, et te mènera où tu ne voudras pas.'),
  (43, 21, 19, 'Il dit cela pour indiquer par quelle mort Pierre glorifierait Dieu. Et ayant ainsi parlé, il lui dit: Suis-moi.'),
  (43, 21, 20, 'Pierre, s''étant retourné, vit venir après eux le disciple que Jésus aimait, celui qui, pendant le souper, s''était penché sur la poitrine de Jésus, et avait dit: Seigneur, qui est celui qui te livre?'),
  (43, 21, 21, 'En le voyant, Pierre dit à Jésus: Et celui-ci, Seigneur, que lui arrivera-t-il?'),
  (43, 21, 22, 'Jésus lui dit: Si je veux qu''il demeure jusqu''à ce que je vienne, que t''importe? Toi, suis-moi.'),
  (43, 21, 23, 'Là-dessus, le bruit courut parmi les frères que ce disciple ne mourrait point. Cependant Jésus n''avait pas dit à Pierre qu''il ne mourrait point; mais: Si je veux qu''il demeure jusqu''à ce que je vienne, que t''importe?'),
  (43, 21, 24, 'C''est ce disciple qui rend témoignage de ces choses, et qui les a écrites. Et nous savons que son témoignage est vrai.'),
  (43, 21, 25, 'Jésus a fait encore beaucoup d''autres choses; si on les écrivait en détail, je ne pense pas que le monde même pût contenir les livres qu''on écrirait.'),
  (44, 1, 1, 'Théophile, j''ai parlé, dans mon premier livre, de tout ce que Jésus a commencé de faire et d''enseigner dès le commencement'),
  (44, 1, 2, 'jusqu''au jour où il fut enlevé au ciel, après avoir donné ses ordres, par le Saint-Esprit, aux apôtres qu''il avait choisis.'),
  (44, 1, 3, 'Après qu''il eut souffert, il leur apparut vivant, et leur en donna plusieurs preuves, se montrant à eux pendant quarante jours, et parlant des choses qui concernent le royaume de Dieu.'),
  (44, 1, 4, 'Comme il se trouvait avec eux, il leur recommanda de ne pas s''éloigner de Jérusalem, mais d''attendre ce que le Père avait promis, ce que je vous ai annoncé, leur dit-il;'),
  (44, 1, 5, 'car Jean a baptisé d''eau, mais vous, dans peu de jours, vous serez baptisés du Saint-Esprit.'),
  (44, 1, 6, 'Alors les apôtres réunis lui demandèrent: Seigneur, est-ce en ce temps que tu rétabliras le royaume d''Israël?'),
  (44, 1, 7, 'Il leur répondit: Ce n''est pas à vous de connaître les temps ou les moments que le Père a fixés de sa propre autorité.'),
  (44, 1, 8, 'Mais vous recevrez une puissance, le Saint-Esprit survenant sur vous, et vous serez mes témoins à Jérusalem, dans toute la Judée, dans la Samarie, et jusqu''aux extrémités de la terre.'),
  (44, 1, 9, 'Après avoir dit cela, il fut élevé pendant qu''ils le regardaient, et une nuée le déroba à leurs yeux.'),
  (44, 1, 10, 'Et comme ils avaient les regards fixés vers le ciel pendant qu''il s''en allait, voici, deux hommes vêtus de blanc leur apparurent,'),
  (44, 1, 11, 'et dirent: Hommes Galiléens, pourquoi vous arrêtez-vous à regarder au ciel? Ce Jésus, qui a été enlevé au ciel du milieu de vous, viendra de la même manière que vous l''avez vu allant au ciel.'),
  (44, 1, 12, 'Alors ils retournèrent à Jérusalem, de la montagne appelée des oliviers, qui est près de Jérusalem, à la distance d''un chemin de sabbat.'),
  (44, 1, 13, 'Quand ils furent arrivés, ils montèrent dans la chambre haute où ils se tenaient d''ordinaire; c''étaient Pierre, Jean, Jacques, André, Philippe, Thomas, Barthélemy, Matthieu, Jacques, fils d''Alphée, Simon le Zélote, et Jude, fils de Jacques.'),
  (44, 1, 14, 'Tous d''un commun accord persévéraient dans la prière, avec les femmes, et Marie, mère de Jésus, et avec les frères de Jésus.'),
  (44, 1, 15, 'En ces jours-là, Pierre se leva au milieu des frères, le nombre des personnes réunies étant d''environ cent vingt. Et il dit:'),
  (44, 1, 16, 'Hommes frères, il fallait que s''accomplît ce que le Saint-Esprit, dans l''Écriture, a annoncé d''avance, par la bouche de David, au sujet de Judas, qui a été le guide de ceux qui ont saisi Jésus.'),
  (44, 1, 17, 'Il était compté parmi nous, et il avait part au même ministère.'),
  (44, 1, 18, 'Cet homme, ayant acquis un champ avec le salaire du crime, est tombé, s''est rompu par le milieu du corps, et toutes ses entrailles se sont répandues.'),
  (44, 1, 19, 'La chose a été si connue de tous les habitants de Jérusalem que ce champ a été appelé dans leur langue Hakeldama, c''est-à-dire, champ du sang.'),
  (44, 1, 20, 'Or, il est écrit dans le livre des Psaumes: Que sa demeure devienne déserte, Et que personne ne l''habite! Et: Qu''un autre prenne sa charge!'),
  (44, 1, 21, 'Il faut donc que, parmi ceux qui nous ont accompagnés tout le temps que le Seigneur Jésus a vécu avec nous,'),
  (44, 1, 22, 'depuis le baptême de Jean jusqu''au jour où il a été enlevé du milieu de nous, il y en ait un qui nous soit associé comme témoin de sa résurrection.'),
  (44, 1, 23, 'Ils en présentèrent deux: Joseph appelé Barsabbas, surnommé Justus, et Matthias.'),
  (44, 1, 24, 'Puis ils firent cette prière: Seigneur, toi qui connais les cœurs de tous, désigne lequel de ces deux tu as choisi,'),
  (44, 1, 25, 'afin qu''il ait part à ce ministère et à cet apostolat, que Judas a abandonné pour aller en son lieu.'),
  (44, 1, 26, 'Ils tirèrent au sort, et le sort tomba sur Matthias, qui fut associé aux onze apôtres.'),
  (44, 2, 1, 'Le jour de la Pentecôte, ils étaient tous ensemble dans le même lieu.'),
  (44, 2, 2, 'Tout à coup il vint du ciel un bruit comme celui d''un vent impétueux, et il remplit toute la maison où ils étaient assis.'),
  (44, 2, 3, 'Des langues, semblables à des langues de feu, leur apparurent, séparées les unes des autres, et se posèrent sur chacun d''eux.'),
  (44, 2, 4, 'Et ils furent tous remplis du Saint-Esprit, et se mirent à parler en d''autres langues, selon que l''Esprit leur donnait de s''exprimer.'),
  (44, 2, 5, 'Or, il y avait en séjour à Jérusalem des Juifs, hommes pieux, de toutes les nations qui sont sous le ciel.'),
  (44, 2, 6, 'Au bruit qui eut lieu, la multitude accourut, et elle fut confondue parce que chacun les entendait parler dans sa propre langue.'),
  (44, 2, 7, 'Ils étaient tous dans l''étonnement et la surprise, et ils se disaient les uns aux autres: Voici, ces gens qui parlent ne sont-ils pas tous Galiléens?'),
  (44, 2, 8, 'Et comment les entendons-nous dans notre propre langue à chacun, dans notre langue maternelle?'),
  (44, 2, 9, 'Parthes, Mèdes, Élamites, ceux qui habitent la Mésopotamie, la Judée, la Cappadoce, le Pont, l''Asie,'),
  (44, 2, 10, 'la Phrygie, la Pamphylie, l''Égypte, le territoire de la Libye voisine de Cyrène, et ceux qui sont venus de Rome, Juifs et prosélytes,'),
  (44, 2, 11, 'Crétois et Arabes, comment les entendons-nous parler dans nos langues des merveilles de Dieu?'),
  (44, 2, 12, 'Ils étaient tous dans l''étonnement, et, ne sachant que penser, ils se disaient les uns aux autres: Que veut dire ceci?'),
  (44, 2, 13, 'Mais d''autres se moquaient, et disaient: Ils sont pleins de vin doux.'),
  (44, 2, 14, 'Alors Pierre, se présentant avec les onze, éleva la voix, et leur parla en ces termes: Hommes Juifs, et vous tous qui séjournez à Jérusalem, sachez ceci, et prêtez l''oreille à mes paroles!'),
  (44, 2, 15, 'Ces gens ne sont pas ivres, comme vous le supposez, car c''est la troisième heure du jour.'),
  (44, 2, 16, 'Mais c''est ici ce qui a été dit par le prophète Joël:'),
  (44, 2, 17, 'Dans les derniers jours, dit Dieu, je répandrai de mon Esprit sur toute chair; Vos fils et vos filles prophétiseront, Vos jeunes gens auront des visions, Et vos vieillards auront des songes.'),
  (44, 2, 18, 'Oui, sur mes serviteurs et sur mes servantes, Dans ces jours-là, je répandrai de mon Esprit; et ils prophétiseront.'),
  (44, 2, 19, 'Je ferai paraître des prodiges en haut dans le ciel et des miracles en bas sur la terre, Du sang, du feu, et une vapeur de fumée;'),
  (44, 2, 20, 'Le soleil se changera en ténèbres, Et la lune en sang, Avant l''arrivée du jour du Seigneur, De ce jour grand et glorieux.'),
  (44, 2, 21, 'Alors quiconque invoquera le nom du Seigneur sera sauvé.'),
  (44, 2, 22, 'Hommes Israélites, écoutez ces paroles! Jésus de Nazareth, cet homme à qui Dieu a rendu témoignage devant vous par les miracles, les prodiges et les signes qu''il a opérés par lui au milieu de vous, comme vous le savez vous-mêmes;'),
  (44, 2, 23, 'cet homme, livré selon le dessein arrêté et selon la prescience de Dieu, vous l''avez crucifié, vous l''avez fait mourir par la main des impies.'),
  (44, 2, 24, 'Dieu l''a ressuscité, en le délivrant des liens de la mort, parce qu''il n''était pas possible qu''il fût retenu par elle.'),
  (44, 2, 25, 'Car David dit de lui: Je voyais constamment le Seigneur devant moi, Parce qu''il est à ma droite, afin que je ne sois point ébranlé.'),
  (44, 2, 26, 'Aussi mon cœur est dans la joie, et ma langue dans l''allégresse; Et même ma chair reposera avec espérance,'),
  (44, 2, 27, 'Car tu n''abandonneras pas mon âme dans le séjour des morts, Et tu ne permettras pas que ton Saint voie la corruption.'),
  (44, 2, 28, 'Tu m''as fait connaître les sentiers de la vie, Tu me rempliras de joie par ta présence.'),
  (44, 2, 29, 'Hommes frères, qu''il me soit permis de vous dire librement, au sujet du patriarche David, qu''il est mort, qu''il a été enseveli, et que son sépulcre existe encore aujourd''hui parmi nous.'),
  (44, 2, 30, 'Comme il était prophète, et qu''il savait que Dieu lui avait promis avec serment de faire asseoir un de ses descendants sur son trône,'),
  (44, 2, 31, 'c''est la résurrection du Christ qu''il a prévue et annoncée, en disant qu''il ne serait pas abandonné dans le séjour des morts et que sa chair ne verrait pas la corruption.'),
  (44, 2, 32, 'C''est ce Jésus que Dieu a ressuscité; nous en sommes tous témoins.'),
  (44, 2, 33, 'Élevé par la droite de Dieu, il a reçu du Père le Saint-Esprit qui avait été promis, et il l''a répandu, comme vous le voyez et l''entendez.'),
  (44, 2, 34, 'Car David n''est point monté au ciel, mais il dit lui-même: Le Seigneur a dit à mon Seigneur: Assieds-toi à ma droite,'),
  (44, 2, 35, 'Jusqu''à ce que je fasse de tes ennemis ton marchepied.'),
  (44, 2, 36, 'Que toute la maison d''Israël sache donc avec certitude que Dieu a fait Seigneur et Christ ce Jésus que vous avez crucifié.'),
  (44, 2, 37, 'Après avoir entendu ce discours, ils eurent le cœur vivement touché, et ils dirent à Pierre et aux autres apôtres: Hommes frères, que ferons-nous?'),
  (44, 2, 38, 'Pierre leur dit: Repentez-vous, et que chacun de vous soit baptisé au nom de Jésus-Christ, pour le pardon de vos péchés; et vous recevrez le don du Saint-Esprit.'),
  (44, 2, 39, 'Car la promesse est pour vous, pour vos enfants, et pour tous ceux qui sont au loin, en aussi grand nombre que le Seigneur notre Dieu les appellera.'),
  (44, 2, 40, 'Et, par plusieurs autres paroles, il les conjurait et les exhortait, disant: Sauvez-vous de cette génération perverse.'),
  (44, 2, 41, 'Ceux qui acceptèrent sa parole furent baptisés; et, en ce jour-là, le nombre des disciples s''augmenta d''environ trois mille âmes.'),
  (44, 2, 42, 'Ils persévéraient dans l''enseignement des apôtres, dans la communion fraternelle, dans la fraction du pain, et dans les prières.'),
  (44, 2, 43, 'La crainte s''emparait de chacun, et il se faisait beaucoup de prodiges et de miracles par les apôtres.'),
  (44, 2, 44, 'Tous ceux qui croyaient étaient dans le même lieu, et ils avaient tout en commun.'),
  (44, 2, 45, 'Ils vendaient leurs propriétés et leurs biens, et ils en partageaient le produit entre tous, selon les besoins de chacun.'),
  (44, 2, 46, 'Ils étaient chaque jour tous ensemble assidus au temple, ils rompaient le pain dans les maisons, et prenaient leur nourriture avec joie et simplicité de cœur,'),
  (44, 2, 47, 'louant Dieu, et trouvant grâce auprès de tout le peuple. Et le Seigneur ajoutait chaque jour à l''Église ceux qui étaient sauvés.'),
  (44, 3, 1, 'Pierre et Jean montaient ensemble au temple, à l''heure de la prière: c''était la neuvième heure.'),
  (44, 3, 2, 'Il y avait un homme boiteux de naissance, qu''on portait et qu''on plaçait tous les jours à la porte du temple appelée la Belle, pour qu''il demandât l''aumône à ceux qui entraient dans le temple.'),
  (44, 3, 3, 'Cet homme, voyant Pierre et Jean qui allaient y entrer, leur demanda l''aumône.')
insert into public.bible_verses (book_id, chapter, verse, text) values
  (44, 3, 4, 'Pierre, de même que Jean, fixa les yeux sur lui, et dit: Regarde-nous.'),
  (44, 3, 5, 'Et il les regardait attentivement, s''attendant à recevoir d''eux quelque chose.'),
  (44, 3, 6, 'Alors Pierre lui dit: Je n''ai ni argent, ni or; mais ce que j''ai, je te le donne: au nom de Jésus-Christ de Nazareth, lève-toi et marche.'),
  (44, 3, 7, 'Et le prenant par la main droite, il le fit lever. Au même instant, ses pieds et ses chevilles devinrent fermes;'),
  (44, 3, 8, 'd''un saut il fut debout, et il se mit à marcher. Il entra avec eux dans le temple, marchant, sautant, et louant Dieu.'),
  (44, 3, 9, 'Tout le monde le vit marchant et louant Dieu.'),
  (44, 3, 10, 'Ils reconnaissaient que c''était celui qui était assis à la Belle porte du temple pour demander l''aumône, et ils furent remplis d''étonnement et de surprise au sujet de ce qui lui était arrivé.'),
  (44, 3, 11, 'Comme il ne quittait pas Pierre et Jean, tout le peuple étonné accourut vers eux, au portique dit de Salomon.'),
  (44, 3, 12, 'Pierre, voyant cela, dit au peuple: Hommes Israélites, pourquoi vous étonnez-vous de cela? Pourquoi avez-vous les regards fixés sur nous, comme si c''était par notre propre puissance ou par notre piété que nous eussions fait marcher cet homme?'),
  (44, 3, 13, 'Le Dieu d''Abraham, d''Isaac et de Jacob, le Dieu de nos pères, a glorifié son serviteur Jésus, que vous avez livré et renié devant Pilate, qui était d''avis qu''on le relâchât.'),
  (44, 3, 14, 'Vous avez renié le Saint et le Juste, et vous avez demandé qu''on vous accordât la grâce d''un meurtrier.'),
  (44, 3, 15, 'Vous avez fait mourir le Prince de la vie, que Dieu a ressuscité des morts; nous en sommes témoins.'),
  (44, 3, 16, 'C''est par la foi en son nom que son nom a raffermi celui que vous voyez et connaissez; c''est la foi en lui qui a donné à cet homme cette entière guérison, en présence de vous tous.'),
  (44, 3, 17, 'Et maintenant, frères, je sais que vous avez agi par ignorance, ainsi que vos chefs.'),
  (44, 3, 18, 'Mais Dieu a accompli de la sorte ce qu''il avait annoncé d''avance par la bouche de tous ses prophètes, que son Christ devait souffrir.'),
  (44, 3, 19, 'Repentez-vous donc et convertissez-vous, pour que vos péchés soient effacés, afin que des temps de rafraîchissement viennent de la part du Seigneur,'),
  (44, 3, 20, 'et qu''il envoie celui qui vous a été destiné, Jésus-Christ,'),
  (44, 3, 21, 'que le ciel doit recevoir jusqu''aux temps du rétablissement de toutes choses, dont Dieu a parlé anciennement par la bouche de ses saints prophètes.'),
  (44, 3, 22, 'Moïse a dit: Le Seigneur votre Dieu vous suscitera d''entre vos frères un prophète comme moi; vous l''écouterez dans tout ce qu''il vous dira,'),
  (44, 3, 23, 'et quiconque n''écoutera pas ce prophète sera exterminé du milieu du peuple.'),
  (44, 3, 24, 'Tous les prophètes qui ont successivement parlé, depuis Samuel, ont aussi annoncé ces jours-là.'),
  (44, 3, 25, 'Vous êtes les fils des prophètes et de l''alliance que Dieu a traitée avec nos pères, en disant à Abraham: Toutes les familles de la terre seront bénies en ta postérité.'),
  (44, 3, 26, 'C''est à vous premièrement que Dieu, ayant suscité son serviteur, l''a envoyé pour vous bénir, en détournant chacun de vous de ses iniquités.'),
  (44, 4, 1, 'Tandis que Pierre et Jean parlaient au peuple, survinrent les sacrificateurs, le commandant du temple, et les sadducéens,'),
  (44, 4, 2, 'mécontents de ce qu''ils enseignaient le peuple, et annonçaient en la personne de Jésus la résurrection des morts.'),
  (44, 4, 3, 'Ils mirent les mains sur eux, et ils les jetèrent en prison jusqu''au lendemain; car c''était déjà le soir.'),
  (44, 4, 4, 'Cependant, beaucoup de ceux qui avaient entendu la parole crurent, et le nombre des hommes s''éleva à environ cinq mille.'),
  (44, 4, 5, 'Le lendemain, les chefs du peuple, les anciens et les scribes,'),
  (44, 4, 6, 's''assemblèrent à Jérusalem, avec Anne, le souverain sacrificateur, Caïphe, Jean, Alexandre, et tous ceux qui étaient de la race des principaux sacrificateurs.'),
  (44, 4, 7, 'Ils firent placer au milieu d''eux Pierre et Jean, et leur demandèrent: Par quel pouvoir, ou au nom de qui avez-vous fait cela?'),
  (44, 4, 8, 'Alors Pierre, rempli du Saint-Esprit, leur dit: Chefs du peuple, et anciens d''Israël,'),
  (44, 4, 9, 'puisque nous sommes interrogés aujourd''hui sur un bienfait accordé à un homme malade, afin que nous disions comment il a été guéri,'),
  (44, 4, 10, 'sachez-le tous, et que tout le peuple d''Israël le sache! C''est par le nom de Jésus-Christ de Nazareth, que vous avez crucifié, et que Dieu a ressuscité des morts, c''est par lui que cet homme se présente en pleine santé devant vous.'),
  (44, 4, 11, 'Jésus est La pierre rejetée par vous qui bâtissez, Et qui est devenue la principale de l''angle.'),
  (44, 4, 12, 'Il n''y a de salut en aucun autre; car il n''y a sous le ciel aucun autre nom qui ait été donné parmi les hommes, par lequel nous devions être sauvés.'),
  (44, 4, 13, 'Lorsqu''ils virent l''assurance de Pierre et de Jean, ils furent étonnés, sachant que c''étaient des hommes du peuple sans instruction; et ils les reconnurent pour avoir été avec Jésus.'),
  (44, 4, 14, 'Mais comme ils voyaient là près d''eux l''homme qui avait été guéri, ils n''avaient rien à répliquer.'),
  (44, 4, 15, 'Ils leur ordonnèrent de sortir du sanhédrin, et ils délibérèrent entre eux,'),
  (44, 4, 16, 'disant: Que ferons-nous à ces hommes? Car il est manifeste pour tous les habitants de Jérusalem qu''un miracle signalé a été accompli par eux, et nous ne pouvons pas le nier.'),
  (44, 4, 17, 'Mais, afin que la chose ne se répande pas davantage parmi le peuple, défendons-leur avec menaces de parler désormais à qui que ce soit en ce nom-là.'),
  (44, 4, 18, 'Et les ayant appelés, ils leur défendirent absolument de parler et d''enseigner au nom de Jésus.'),
  (44, 4, 19, 'Pierre et Jean leur répondirent: Jugez s''il est juste, devant Dieu, de vous obéir plutôt qu''à Dieu;'),
  (44, 4, 20, 'car nous ne pouvons pas ne pas parler de ce que nous avons vu et entendu.'),
  (44, 4, 21, 'Ils leur firent de nouvelles menaces, et les relâchèrent, ne sachant comment les punir, à cause du peuple, parce que tous glorifiaient Dieu de ce qui était arrivé.'),
  (44, 4, 22, 'Car l''homme qui avait été l''objet de cette guérison miraculeuse était âgé de plus de quarante ans.'),
  (44, 4, 23, 'Après avoir été relâchés, ils allèrent vers les leurs, et racontèrent tout ce que les principaux sacrificateurs et les anciens leur avaient dit.'),
  (44, 4, 24, 'Lorsqu''ils l''eurent entendu, ils élevèrent à Dieu la voix tous ensemble, et dirent: Seigneur, toi qui as fait le ciel, la terre, la mer, et tout ce qui s''y trouve,'),
  (44, 4, 25, 'c''est toi qui as dit par le Saint-Esprit, par la bouche de notre père, ton serviteur David: Pourquoi ce tumulte parmi les nations, Et ces vaines pensées parmi les peuples?'),
  (44, 4, 26, 'Les rois de la terre se sont soulevés, Et les princes se sont ligués Contre le Seigneur et contre son Oint.'),
  (44, 4, 27, 'En effet, contre ton saint serviteur Jésus, que tu as oint, Hérode et Ponce Pilate se sont ligués dans cette ville avec les nations et avec les peuples d''Israël,'),
  (44, 4, 28, 'pour faire tout ce que ta main et ton conseil avaient arrêté d''avance.'),
  (44, 4, 29, 'Et maintenant, Seigneur, vois leurs menaces, et donne à tes serviteurs d''annoncer ta parole avec une pleine assurance,'),
  (44, 4, 30, 'en étendant ta main, pour qu''il se fasse des guérisons, des miracles et des prodiges, par le nom de ton saint serviteur Jésus.'),
  (44, 4, 31, 'Quand ils eurent prié, le lieu où ils étaient assemblés trembla; ils furent tous remplis du Saint-Esprit, et ils annonçaient la parole de Dieu avec assurance.'),
  (44, 4, 32, 'La multitude de ceux qui avaient cru n''était qu''un cœur et qu''une âme. Nul ne disait que ses biens lui appartinssent en propre, mais tout était commun entre eux.'),
  (44, 4, 33, 'Les apôtres rendaient avec beaucoup de force témoignage de la résurrection du Seigneur Jésus. Et une grande grâce reposait sur eux tous.'),
  (44, 4, 34, 'Car il n''y avait parmi eux aucun indigent: tous ceux qui possédaient des champs ou des maisons les vendaient, apportaient le prix de ce qu''ils avaient vendu,'),
  (44, 4, 35, 'et le déposaient aux pieds des apôtres; et l''on faisait des distributions à chacun selon qu''il en avait besoin.'),
  (44, 4, 36, 'Joseph, surnommé par les apôtres Barnabas, ce qui signifie fils d''exhortation, Lévite, originaire de Chypre,'),
  (44, 4, 37, 'vendit un champ qu''il possédait, apporta l''argent, et le déposa aux pieds des apôtres.'),
  (44, 5, 1, 'Mais un homme nommé Ananias, avec Saphira sa femme, vendit une propriété,'),
  (44, 5, 2, 'et retint une partie du prix, sa femme le sachant; puis il apporta le reste, et le déposa aux pieds des apôtres.'),
  (44, 5, 3, 'Pierre lui dit: Ananias, pourquoi Satan a-t-il rempli ton cœur, au point que tu mentes au Saint-Esprit, et que tu aies retenu une partie du prix du champ?'),
  (44, 5, 4, 'S''il n''eût pas été vendu, ne te restait-il pas? Et, après qu''il a été vendu, le prix n''était-il pas à ta disposition? Comment as-tu pu mettre en ton cœur un pareil dessein? Ce n''est pas à des hommes que tu as menti, mais à Dieu.'),
  (44, 5, 5, 'Ananias, entendant ces paroles, tomba, et expira. Une grande crainte saisit tous les auditeurs.'),
  (44, 5, 6, 'Les jeunes gens, s''étant levés, l''enveloppèrent, l''emportèrent, et l''ensevelirent.'),
  (44, 5, 7, 'Environ trois heures plus tard, sa femme entra, sans savoir ce qui était arrivé.'),
  (44, 5, 8, 'Pierre lui adressa la parole: Dis-moi, est-ce à un tel prix que vous avez vendu le champ? Oui, répondit-elle, c''est à ce prix-là.'),
  (44, 5, 9, 'Alors Pierre lui dit: Comment vous êtes-vous accordés pour tenter l''Esprit du Seigneur? Voici, ceux qui ont enseveli ton mari sont à la porte, et ils t''emporteront.'),
  (44, 5, 10, 'Au même instant, elle tomba aux pieds de l''apôtre, et expira. Les jeunes gens, étant entrés, la trouvèrent morte; ils l''emportèrent, et l''ensevelirent auprès de son mari.'),
  (44, 5, 11, 'Une grande crainte s''empara de toute l''assemblée et de tous ceux qui apprirent ces choses.'),
  (44, 5, 12, 'Beaucoup de miracles et de prodiges se faisaient au milieu du peuple par les mains des apôtres. Ils se tenaient tous ensemble au portique de Salomon,'),
  (44, 5, 13, 'et aucun des autres n''osait se joindre à eux; mais le peuple les louait hautement.'),
  (44, 5, 14, 'Le nombre de ceux qui croyaient au Seigneur, hommes et femmes, s''augmentait de plus en plus;'),
  (44, 5, 15, 'en sorte qu''on apportait les malades dans les rues et qu''on les plaçait sur des lits et des couchettes, afin que, lorsque Pierre passerait, son ombre au moins couvrît quelqu''un d''eux.'),
  (44, 5, 16, 'La multitude accourait aussi des villes voisines à Jérusalem, amenant des malades et des gens tourmentés par des esprits impurs; et tous étaient guéris.'),
  (44, 5, 17, 'Cependant le souverain sacrificateur et tous ceux qui étaient avec lui, savoir le parti des sadducéens, se levèrent, remplis de jalousie,'),
  (44, 5, 18, 'mirent les mains sur les apôtres, et les jetèrent dans la prison publique.'),
  (44, 5, 19, 'Mais un ange du Seigneur, ayant ouvert pendant la nuit les portes de la prison, les fit sortir, et leur dit:'),
  (44, 5, 20, 'Allez, tenez-vous dans le temple, et annoncez au peuple toutes les paroles de cette vie.'),
  (44, 5, 21, 'Ayant entendu cela, ils entrèrent dès le matin dans le temple, et se mirent à enseigner. Le souverain sacrificateur et ceux qui étaient avec lui étant survenus, ils convoquèrent le sanhédrin et tous les anciens des fils d''Israël, et ils envoyèrent chercher les apôtres à la prison.'),
  (44, 5, 22, 'Les huissiers, à leur arrivée, ne les trouvèrent point dans la prison. Ils s''en retournèrent, et firent leur rapport,'),
  (44, 5, 23, 'en disant: Nous avons trouvé la prison soigneusement fermée, et les gardes qui étaient devant les portes; mais, après avoir ouvert, nous n''avons trouvé personne dedans.'),
  (44, 5, 24, 'Lorsqu''ils eurent entendu ces paroles, le commandant du temple et les principaux sacrificateurs ne savaient que penser des apôtres et des suites de cette affaire.'),
  (44, 5, 25, 'Quelqu''un vint leur dire: Voici, les hommes que vous avez mis en prison sont dans le temple, et ils enseignent le peuple.'),
  (44, 5, 26, 'Alors le commandant partit avec les huissiers, et les conduisit sans violence, car ils avaient peur d''être lapidés par le peuple.'),
  (44, 5, 27, 'Après qu''ils les eurent amenés en présence du sanhédrin, le souverain sacrificateur les interrogea'),
  (44, 5, 28, 'en ces termes: Ne vous avons-nous pas défendu expressément d''enseigner en ce nom-là? Et voici, vous avez rempli Jérusalem de votre enseignement, et vous voulez faire retomber sur nous le sang de cet homme!'),
  (44, 5, 29, 'Pierre et les apôtres répondirent: Il faut obéir à Dieu plutôt qu''aux hommes.'),
  (44, 5, 30, 'Le Dieu de nos pères a ressuscité Jésus, que vous avez tué, en le pendant au bois.'),
  (44, 5, 31, 'Dieu l''a élevé par sa droite comme Prince et Sauveur, pour donner à Israël la repentance et le pardon des péchés.'),
  (44, 5, 32, 'Nous sommes témoins de ces choses, de même que le Saint-Esprit, que Dieu a donné à ceux qui lui obéissent.'),
  (44, 5, 33, 'Furieux de ces paroles, ils voulaient les faire mourir.'),
  (44, 5, 34, 'Mais un pharisien, nommé Gamaliel, docteur de la loi, estimé de tout le peuple, se leva dans le sanhédrin, et ordonna de faire sortir un instant les apôtres.'),
  (44, 5, 35, 'Puis il leur dit: Hommes Israélites, prenez garde à ce que vous allez faire à l''égard de ces gens.'),
  (44, 5, 36, 'Car, il n''y a pas longtemps que parut Theudas, qui se donnait pour quelque chose, et auquel se rallièrent environ quatre cents hommes: il fut tué, et tous ceux qui l''avaient suivi furent mis en déroute et réduits à rien.'),
  (44, 5, 37, 'Après lui, parut Judas le Galiléen, à l''époque du recensement, et il attira du monde à son parti: il périt aussi, et tous ceux qui l''avaient suivi furent dispersés.'),
  (44, 5, 38, 'Et maintenant, je vous le dis ne vous occupez plus de ces hommes, et laissez-les aller. Si cette entreprise ou cette œuvre vient des hommes, elle se détruira;'),
  (44, 5, 39, 'mais si elle vient de Dieu, vous ne pourrez la détruire. Ne courez pas le risque d''avoir combattu contre Dieu.'),
  (44, 5, 40, 'Ils se rangèrent à son avis. Et ayant appelé les apôtres, ils les firent battre de verges, ils leur défendirent de parler au nom de Jésus, et ils les relâchèrent.'),
  (44, 5, 41, 'Les apôtres se retirèrent de devant le sanhédrin, joyeux d''avoir été jugés dignes de subir des outrages pour le nom de Jésus.'),
  (44, 5, 42, 'Et chaque jour, dans le temple et dans les maisons, ils ne cessaient d''enseigner, et d''annoncer la bonne nouvelle de Jésus-Christ.'),
  (44, 6, 1, 'En ce temps-là, le nombre des disciples augmentant, les Hellénistes murmurèrent contre les Hébreux, parce que leurs veuves étaient négligées dans la distribution qui se faisait chaque jour.'),
  (44, 6, 2, 'Les douze convoquèrent la multitude des disciples, et dirent: Il n''est pas convenable que nous laissions la parole de Dieu pour servir aux tables.'),
  (44, 6, 3, 'C''est pourquoi, frères, choisissez parmi vous sept hommes, de qui l''on rende un bon témoignage, qui soient pleins d''Esprit-Saint et de sagesse, et que nous chargerons de cet emploi.'),
  (44, 6, 4, 'Et nous, nous continuerons à nous appliquer à la prière et au ministère de la parole.'),
  (44, 6, 5, 'Cette proposition plut à toute l''assemblée. Ils élurent Étienne, homme plein de foi et d''Esprit-Saint, Philippe, Prochore, Nicanor, Timon, Parménas, et Nicolas, prosélyte d''Antioche.'),
  (44, 6, 6, 'Ils les présentèrent aux apôtres, qui, après avoir prié, leur imposèrent les mains.'),
  (44, 6, 7, 'La parole de Dieu se répandait de plus en plus, le nombre des disciples augmentait beaucoup à Jérusalem, et une grande foule de sacrificateurs obéissaient à la foi.'),
  (44, 6, 8, 'Étienne, plein de grâce et de puissance, faisait des prodiges et de grands miracles parmi le peuple.'),
  (44, 6, 9, 'Quelques membres de la synagogue dite des Affranchis, de celle des Cyrénéens et de celle des Alexandrins, avec des Juifs de Cilicie et d''Asie, se mirent à discuter avec lui;'),
  (44, 6, 10, 'mais ils ne pouvaient résister à sa sagesse et à l''Esprit par lequel il parlait.'),
  (44, 6, 11, 'Alors ils subornèrent des hommes qui dirent: Nous l''avons entendu proférer des paroles blasphématoires contre Moïse et contre Dieu.'),
  (44, 6, 12, 'Ils émurent le peuple, les anciens et les scribes, et, se jetant sur lui, ils le saisirent, et l''emmenèrent au sanhédrin.'),
  (44, 6, 13, 'Ils produisirent de faux témoins, qui dirent: Cet homme ne cesse de proférer des paroles contre le lieu saint et contre la loi;'),
  (44, 6, 14, 'car nous l''avons entendu dire que Jésus, ce Nazaréen, détruira ce lieu, et changera les coutumes que Moïse nous a données.'),
  (44, 6, 15, 'Tous ceux qui siégeaient au sanhédrin ayant fixé les regards sur Étienne, son visage leur parut comme celui d''un ange.'),
  (44, 7, 1, 'Le souverain sacrificateur dit: Les choses sont-elles ainsi?'),
  (44, 7, 2, 'Étienne répondit: Hommes frères et pères, écoutez! Le Dieu de gloire apparut à notre père Abraham, lorsqu''il était en Mésopotamie, avant qu''il s''établît à Charran;'),
  (44, 7, 3, 'et il lui dit: Quitte ton pays et ta famille, et va dans le pays que je te montrerai.'),
  (44, 7, 4, 'Il sortit alors du pays des Chaldéens, et s''établit à Charran. De là, après la mort de son père, Dieu le fit passer dans ce pays que vous habitez maintenant;'),
  (44, 7, 5, 'il ne lui donna aucune propriété en ce pays, pas même de quoi poser le pied, mais il promit de lui en donner la possession, et à sa postérité après lui, quoiqu''il n''eût point d''enfant.'),
  (44, 7, 6, 'Dieu parla ainsi: Sa postérité séjournera dans un pays étranger; on la réduira en servitude et on la maltraitera pendant quatre cents ans.'),
  (44, 7, 7, 'Mais la nation à laquelle ils auront été asservis, c''est moi qui la jugerai, dit Dieu. Après cela, ils sortiront, et ils me serviront dans ce lieu-ci.'),
  (44, 7, 8, 'Puis Dieu donna à Abraham l''alliance de la circoncision; et ainsi, Abraham, ayant engendré Isaac, le circoncit le huitième jour; Isaac engendra et circoncit Jacob, et Jacob les douze patriarches.'),
  (44, 7, 9, 'Les patriarches, jaloux de Joseph, le vendirent pour être emmené en Égypte. Mais Dieu fut avec lui,'),
  (44, 7, 10, 'et le délivra de toutes ses tribulations; il lui donna de la sagesse et lui fit trouver grâce devant Pharaon, roi d''Égypte, qui l''établit gouverneur d''Égypte et de toute sa maison.'),
  (44, 7, 11, 'Il survint une famine dans tout le pays d''Égypte, et dans celui de Canaan. La détresse était grande, et nos pères ne trouvaient pas de quoi se nourrir.'),
  (44, 7, 12, 'Jacob apprit qu''il y avait du blé en Égypte, et il y envoya nos pères une première fois.'),
  (44, 7, 13, 'Et la seconde fois, Joseph fut reconnu par ses frères, et Pharaon sut de quelle famille il était.'),
  (44, 7, 14, 'Puis Joseph envoya chercher son père Jacob, et toute sa famille, composée de soixante-quinze personnes.'),
  (44, 7, 15, 'Jacob descendit en Égypte, où il mourut, ainsi que nos pères;'),
  (44, 7, 16, 'et ils furent transportés à Sichem, et déposés dans le sépulcre qu''Abraham avait acheté, à prix d''argent, des fils d''Hémor, père de Sichem.'),
  (44, 7, 17, 'Le temps approchait où devait s''accomplir la promesse que Dieu avait faite à Abraham, et le peuple s''accrut et se multiplia en Égypte,'),
  (44, 7, 18, 'jusqu''à ce que parut un autre roi, qui n''avait pas connu Joseph.'),
  (44, 7, 19, 'Ce roi, usant d''artifice contre notre race, maltraita nos pères, au point de leur faire exposer leurs enfants, pour qu''ils ne vécussent pas.'),
  (44, 7, 20, 'A cette époque, naquit Moïse, qui était beau aux yeux de Dieu. Il fut nourri trois mois dans la maison de son père;'),
  (44, 7, 21, 'et, quand il eut été exposé, la fille de Pharaon le recueillit, et l''éleva comme son fils.'),
  (44, 7, 22, 'Moïse fut instruit dans toute la sagesse des Égyptiens, et il était puissant en paroles et en œuvres.'),
  (44, 7, 23, 'Il avait quarante ans, lorsqu''il lui vint dans le cœur de visiter ses frères, les fils d''Israël.'),
  (44, 7, 24, 'Il en vit un qu''on outrageait, et, prenant sa défense, il vengea celui qui était maltraité, et frappa l''Égyptien.'),
  (44, 7, 25, 'Il pensait que ses frères comprendraient que Dieu leur accordait la délivrance par sa main; mais ils ne comprirent pas.'),
  (44, 7, 26, 'Le jour suivant, il parut au milieu d''eux comme ils se battaient, et il les exhorta à la paix: Hommes, dit-il, vous êtes frères; pourquoi vous maltraitez-vous l''un l''autre?'),
  (44, 7, 27, 'Mais celui qui maltraitait son prochain le repoussa, en disant: Qui t''a établi chef et juge sur nous?'),
  (44, 7, 28, 'Veux-tu me tuer, comme tu as tué hier l''Égyptien?'),
  (44, 7, 29, 'A cette parole, Moïse prit la fuite, et il alla séjourner dans le pays de Madian, où il engendra deux fils.'),
  (44, 7, 30, 'Quarante ans plus tard, un ange lui apparut, au désert de la montagne de Sinaï, dans la flamme d''un buisson en feu.'),
  (44, 7, 31, 'Moïse, voyant cela, fut étonné de cette apparition; et, comme il s''approchait pour examiner, la voix du Seigneur se fit entendre:'),
  (44, 7, 32, 'Je suis le Dieu de tes pères, le Dieu d''Abraham, d''Isaac et de Jacob. Et Moïse, tout tremblant, n''osait regarder.'),
  (44, 7, 33, 'Le Seigneur lui dit: Ote tes souliers de tes pieds, car le lieu sur lequel tu te tiens est une terre sainte.'),
  (44, 7, 34, 'J''ai vu la souffrance de mon peuple qui est en Égypte, j''ai entendu ses gémissements, et je suis descendu pour le délivrer. Maintenant, va, je t''enverrai en Égypte.'),
  (44, 7, 35, 'Ce Moïse, qu''ils avaient renié, en disant: Qui t''a établi chef et juge? c''est lui que Dieu envoya comme chef et comme libérateur avec l''aide de l''ange qui lui était apparu dans le buisson.'),
  (44, 7, 36, 'C''est lui qui les fit sortir d''Égypte, en opérant des prodiges et des miracles au pays d''Égypte, au sein de la mer Rouge, et au désert, pendant quarante ans.'),
  (44, 7, 37, 'C''est ce Moïse qui dit aux fils d''Israël: Dieu vous suscitera d''entre vos frères un prophète comme moi.'),
  (44, 7, 38, 'C''est lui qui, lors de l''assemblée au désert, étant avec l''ange qui lui parlait sur la montagne de Sinaï et avec nos pères, reçut des oracles vivants, pour nous les donner.'),
  (44, 7, 39, 'Nos pères ne voulurent pas lui obéir, ils le repoussèrent, et ils tournèrent leur cœur vers l''Égypte,'),
  (44, 7, 40, 'en disant à Aaron: Fais-nous des dieux qui marchent devant nous; car ce Moïse qui nous a fait sortir du pays d''Égypte, nous ne savons ce qu''il est devenu.'),
  (44, 7, 41, 'Et, en ces jours-là, ils firent un veau, ils offrirent un sacrifice à l''idole, et se réjouirent de l''œuvre de leurs mains.'),
  (44, 7, 42, 'Alors Dieu se détourna, et les livra au culte de l''armée du ciel, selon qu''il est écrit dans le livre des prophètes: M''avez-vous offert des victimes et des sacrifices Pendant quarante ans au désert, maison d''Israël?…'),
  (44, 7, 43, 'Vous avez porté la tente de Moloch Et l''étoile du dieu Remphan, Ces images que vous avez faites pour les adorer! Aussi vous transporterai-je au delà de Babylone.'),
  (44, 7, 44, 'Nos pères avaient au désert le tabernacle du témoignage, comme l''avait ordonné celui qui dit à Moïse de le faire d''après le modèle qu''il avait vu.'),
  (44, 7, 45, 'Et nos pères, l''ayant reçu, l''introduisirent, sous la conduite de Josué, dans le pays qui était possédé par les nations que Dieu chassa devant eux, et il y resta jusqu''aux jours de David.'),
  (44, 7, 46, 'David trouva grâce devant Dieu, et demanda d''élever une demeure pour le Dieu de Jacob;'),
  (44, 7, 47, 'et ce fut Salomon qui lui bâtit une maison.'),
  (44, 7, 48, 'Mais le Très-Haut n''habite pas dans ce qui est fait de main d''homme, comme dit le prophète:'),
  (44, 7, 49, 'Le ciel est mon trône, Et la terre mon marchepied. Quelle maison me bâtirez-vous, dit le Seigneur, Ou quel sera le lieu de mon repos?'),
  (44, 7, 50, 'N''est-ce pas ma main qui a fait toutes ces choses?…'),
  (44, 7, 51, 'Hommes au cou raide, incirconcis de cœur et d''oreilles! vous vous opposez toujours au Saint-Esprit. Ce que vos pères ont été, vous l''êtes aussi.'),
  (44, 7, 52, 'Lequel des prophètes vos pères n''ont-ils pas persécuté? Ils ont tué ceux qui annonçaient d''avance la venue du Juste, que vous avez livré maintenant, et dont vous avez été les meurtriers,'),
  (44, 7, 53, 'vous qui avez reçu la loi d''après des commandements d''anges, et qui ne l''avez point gardée!…'),
  (44, 7, 54, 'En entendant ces paroles, ils étaient furieux dans leur cœur, et ils grinçaient des dents contre lui.'),
  (44, 7, 55, 'Mais Étienne, rempli du Saint-Esprit, et fixant les regards vers le ciel, vit la gloire de Dieu et Jésus debout à la droite de Dieu.'),
  (44, 7, 56, 'Et il dit: Voici, je vois les cieux ouverts, et le Fils de l''homme debout à la droite de Dieu.'),
  (44, 7, 57, 'Ils poussèrent alors de grands cris, en se bouchant les oreilles, et ils se précipitèrent tous ensemble sur lui,'),
  (44, 7, 58, 'le traînèrent hors de la ville, et le lapidèrent. Les témoins déposèrent leurs vêtements aux pieds d''un jeune homme nommé Saul.'),
  (44, 7, 59, 'Et ils lapidaient Étienne, qui priait et disait: Seigneur Jésus, reçois mon esprit!'),
  (44, 7, 60, 'Puis, s''étant mis à genoux, il s''écria d''une voix forte: Seigneur, ne leur impute pas ce péché! Et, après ces paroles, il s''endormit.'),
  (44, 8, 1, 'Saul avait approuvé le meurtre d''Étienne. Il y eut, ce jour-là, une grande persécution contre l''Église de Jérusalem; et tous, excepté les apôtres, se dispersèrent dans les contrées de la Judée et de la Samarie.'),
  (44, 8, 2, 'Des hommes pieux ensevelirent Étienne, et le pleurèrent à grand bruit.'),
  (44, 8, 3, 'Saul, de son côté, ravageait l''Église; pénétrant dans les maisons, il en arrachait hommes et femmes, et les faisait jeter en prison.'),
  (44, 8, 4, 'Ceux qui avaient été dispersés allaient de lieu en lieu, annonçant la bonne nouvelle de la parole.'),
  (44, 8, 5, 'Philippe, étant descendu dans la ville de Samarie, y prêcha le Christ.'),
  (44, 8, 6, 'Les foules tout entières étaient attentives à ce que disait Philippe, lorsqu''elles apprirent et virent les miracles qu''il faisait.'),
  (44, 8, 7, 'Car des esprits impurs sortirent de plusieurs démoniaques, en poussant de grands cris, et beaucoup de paralytiques et de boiteux furent guéris.'),
  (44, 8, 8, 'Et il y eut une grande joie dans cette ville.'),
  (44, 8, 9, 'Il y avait auparavant dans la ville un homme nommé Simon, qui, se donnant pour un personnage important, exerçait la magie et provoquait l''étonnement du peuple de la Samarie.'),
  (44, 8, 10, 'Tous, depuis le plus petit jusqu''au plus grand, l''écoutaient attentivement, et disaient: Celui-ci est la puissance de Dieu, celle qui s''appelle la grande.'),
  (44, 8, 11, 'Ils l''écoutaient attentivement, parce qu''il les avait longtemps étonnés par ses actes de magie.'),
  (44, 8, 12, 'Mais, quand ils eurent cru à Philippe, qui leur annonçait la bonne nouvelle du royaume de Dieu et du nom de Jésus-Christ, hommes et femmes se firent baptiser.'),
  (44, 8, 13, 'Simon lui-même crut, et, après avoir été baptisé, il ne quittait plus Philippe, et il voyait avec étonnement les miracles et les grands prodiges qui s''opéraient.'),
  (44, 8, 14, 'Les apôtres, qui étaient à Jérusalem, ayant appris que la Samarie avait reçu la parole de Dieu, y envoyèrent Pierre et Jean.'),
  (44, 8, 15, 'Ceux-ci, arrivés chez les Samaritains, prièrent pour eux, afin qu''ils reçussent le Saint-Esprit.'),
  (44, 8, 16, 'Car il n''était encore descendu sur aucun d''eux; ils avaient seulement été baptisés au nom du Seigneur Jésus.'),
  (44, 8, 17, 'Alors Pierre et Jean leur imposèrent les mains, et ils reçurent le Saint-Esprit.'),
  (44, 8, 18, 'Lorsque Simon vit que le Saint-Esprit était donné par l''imposition des mains des apôtres, il leur offrit de l''argent,'),
  (44, 8, 19, 'en disant: Accordez-moi aussi ce pouvoir, afin que celui à qui j''imposerai les mains reçoive le Saint-Esprit.'),
  (44, 8, 20, 'Mais Pierre lui dit: Que ton argent périsse avec toi, puisque tu as cru que le don de Dieu s''acquérait à prix d''argent!'),
  (44, 8, 21, 'Il n''y a pour toi ni part ni lot dans cette affaire, car ton cœur n''est pas droit devant Dieu.'),
  (44, 8, 22, 'Repens-toi donc de ta méchanceté, et prie le Seigneur pour que la pensée de ton cœur te soit pardonnée, s''il est possible;'),
  (44, 8, 23, 'car je vois que tu es dans un fiel amer et dans les liens de l''iniquité.'),
  (44, 8, 24, 'Simon répondit: Priez vous-mêmes le Seigneur pour moi, afin qu''il ne m''arrive rien de ce que vous avez dit.'),
  (44, 8, 25, 'Après avoir rendu témoignage à la parole du Seigneur, et après l''avoir prêchée, Pierre et Jean retournèrent à Jérusalem, en annonçant la bonne nouvelle dans plusieurs villages des Samaritains.'),
  (44, 8, 26, 'Un ange du Seigneur, s''adressant à Philippe, lui dit: Lève-toi, et va du côté du midi, sur le chemin qui descend de Jérusalem à Gaza, celui qui est désert.'),
  (44, 8, 27, 'Il se leva, et partit. Et voici, un Éthiopien, un eunuque, ministre de Candace, reine d''Éthiopie, et surintendant de tous ses trésors, venu à Jérusalem pour adorer,'),
  (44, 8, 28, 's''en retournait, assis sur son char, et lisait le prophète Ésaïe.'),
  (44, 8, 29, 'L''Esprit dit à Philippe: Avance, et approche-toi de ce char.'),
  (44, 8, 30, 'Philippe accourut, et entendit l''Éthiopien qui lisait le prophète Ésaïe. Il lui dit: Comprends-tu ce que tu lis?'),
  (44, 8, 31, 'Il répondit: Comment le pourrais-je, si quelqu''un ne me guide? Et il invita Philippe à monter et à s''asseoir avec lui.'),
  (44, 8, 32, 'Le passage de l''Écriture qu''il lisait était celui-ci: Il a été mené comme une brebis à la boucherie; Et, comme un agneau muet devant celui qui le tond, Il n''a point ouvert la bouche.'),
  (44, 8, 33, 'Dans son humiliation, son jugement a été levé. Et sa postérité, qui la dépeindra? Car sa vie a été retranchée de la terre.'),
  (44, 8, 34, 'L''eunuque dit à Philippe: Je te prie, de qui le prophète parle-t-il ainsi? Est-ce de lui-même, ou de quelque autre?'),
  (44, 8, 35, 'Alors Philippe, ouvrant la bouche et commençant par ce passage, lui annonça la bonne nouvelle de Jésus.'),
  (44, 8, 36, 'Comme ils continuaient leur chemin, ils rencontrèrent de l''eau. Et l''eunuque dit: Voici de l''eau; qu''est-ce qui empêche que je sois baptisé?'),
  (44, 8, 37, 'Philippe dit: Si tu crois de tout ton cœur, cela est possible. L''eunuque répondit: Je crois que Jésus-Christ est le Fils de Dieu.'),
  (44, 8, 38, 'Il fit arrêter le char; Philippe et l''eunuque descendirent tous deux dans l''eau, et Philippe baptisa l''eunuque.'),
  (44, 8, 39, 'Quand ils furent sortis de l''eau, l''Esprit du Seigneur enleva Philippe, et l''eunuque ne le vit plus. Tandis que, joyeux, il poursuivait sa route,'),
  (44, 8, 40, 'Philippe se trouva dans Azot, d''où il alla jusqu''à Césarée, en évangélisant toutes les villes par lesquelles il passait.'),
  (44, 9, 1, 'Cependant Saul, respirant encore la menace et le meurtre contre les disciples du Seigneur, se rendit chez le souverain sacrificateur,'),
  (44, 9, 2, 'et lui demanda des lettres pour les synagogues de Damas, afin que, s''il trouvait des partisans de la nouvelle doctrine, hommes ou femmes, il les amenât liés à Jérusalem.'),
  (44, 9, 3, 'Comme il était en chemin, et qu''il approchait de Damas, tout à coup une lumière venant du ciel resplendit autour de lui.'),
  (44, 9, 4, 'Il tomba par terre, et il entendit une voix qui lui disait: Saul, Saul, pourquoi me persécutes-tu?'),
  (44, 9, 5, 'Il répondit: Qui es-tu, Seigneur? Et le Seigneur dit: Je suis Jésus que tu persécutes. Il te serait dur de regimber contre les aiguillons.'),
  (44, 9, 6, 'Tremblant et saisi d''effroi, il dit: Seigneur, que veux-tu que je fasse? Et le Seigneur lui dit: Lève-toi, entre dans la ville, et on te dira ce que tu dois faire.'),
  (44, 9, 7, 'Les hommes qui l''accompagnaient demeurèrent stupéfaits; ils entendaient bien la voix, mais ils ne voyaient personne.'),
  (44, 9, 8, 'Saul se releva de terre, et, quoique ses yeux fussent ouverts, il ne voyait rien; on le prit par la main, et on le conduisit à Damas.'),
  (44, 9, 9, 'Il resta trois jours sans voir, et il ne mangea ni ne but.'),
  (44, 9, 10, 'Or, il y avait à Damas un disciple nommé Ananias. Le Seigneur lui dit dans une vision: Ananias! Il répondit: Me voici, Seigneur!'),
  (44, 9, 11, 'Et le Seigneur lui dit: Lève-toi, va dans la rue qu''on appelle la droite, et cherche, dans la maison de Judas, un nommé Saul de Tarse. Car il prie,'),
  (44, 9, 12, 'et il a vu en vision un homme du nom d''Ananias, qui entrait, et qui lui imposait les mains, afin qu''il recouvrât la vue.'),
  (44, 9, 13, 'Ananias répondit: Seigneur, j''ai appris de plusieurs personnes tous les maux que cet homme a faits à tes saints dans Jérusalem;'),
  (44, 9, 14, 'et il a ici des pouvoirs, de la part des principaux sacrificateurs, pour lier tous ceux qui invoquent ton nom.'),
  (44, 9, 15, 'Mais le Seigneur lui dit: Va, car cet homme est un instrument que j''ai choisi, pour porter mon nom devant les nations, devant les rois, et devant les fils d''Israël;'),
  (44, 9, 16, 'et je lui montrerai tout ce qu''il doit souffrir pour mon nom.'),
  (44, 9, 17, 'Ananias sortit; et, lorsqu''il fut arrivé dans la maison, il imposa les mains à Saul, en disant: Saul, mon frère, le Seigneur Jésus, qui t''est apparu sur le chemin par lequel tu venais, m''a envoyé pour que tu recouvres la vue et que tu sois rempli du Saint-Esprit.'),
  (44, 9, 18, 'Au même instant, il tomba de ses yeux comme des écailles, et il recouvra la vue. Il se leva, et fut baptisé;'),
  (44, 9, 19, 'et, après qu''il eut pris de la nourriture, les forces lui revinrent. Saul resta quelques jours avec les disciples qui étaient à Damas.'),
  (44, 9, 20, 'Et aussitôt il prêcha dans les synagogues que Jésus est le Fils de Dieu.'),
  (44, 9, 21, 'Tous ceux qui l''entendaient étaient dans l''étonnement, et disaient: N''est-ce pas celui qui persécutait à Jérusalem ceux qui invoquent ce nom, et n''est-il pas venu ici pour les emmener liés devant les principaux sacrificateurs?'),
  (44, 9, 22, 'Cependant Saul se fortifiait de plus en plus, et il confondait les Juifs qui habitaient Damas, démontrant que Jésus est le Christ.'),
  (44, 9, 23, 'Au bout d''un certain temps, les Juifs se concertèrent pour le tuer,'),
  (44, 9, 24, 'et leur complot parvint à la connaissance de Saul. On gardait les portes jour et nuit, afin de lui ôter la vie.'),
  (44, 9, 25, 'Mais, pendant une nuit, les disciples le prirent, et le descendirent par la muraille, dans une corbeille.'),
  (44, 9, 26, 'Lorsqu''il se rendit à Jérusalem, Saul tâcha de se joindre à eux; mais tous le craignaient, ne croyant pas qu''il fût un disciple.'),
  (44, 9, 27, 'Alors Barnabas, l''ayant pris avec lui, le conduisit vers les apôtres, et leur raconta comment sur le chemin Saul avait vu le Seigneur, qui lui avait parlé, et comment à Damas il avait prêché franchement au nom de Jésus.'),
  (44, 9, 28, 'Il allait et venait avec eux dans Jérusalem,'),
  (44, 9, 29, 'et s''exprimait en toute assurance au nom du Seigneur. Il parlait aussi et disputait avec les Hellénistes; mais ceux-ci cherchaient à lui ôter la vie.'),
  (44, 9, 30, 'Les frères, l''ayant su, l''emmenèrent à Césarée, et le firent partir pour Tarse.'),
  (44, 9, 31, 'L''Église était en paix dans toute la Judée, la Galilée et la Samarie, s''édifiant et marchant dans la crainte du Seigneur, et elle s''accroissait par l''assistance du Saint-Esprit.'),
  (44, 9, 32, 'Comme Pierre visitait tous les saints, il descendit aussi vers ceux qui demeuraient à Lydde.'),
  (44, 9, 33, 'Il y trouva un homme nommé Énée, couché sur un lit depuis huit ans, et paralytique.'),
  (44, 9, 34, 'Pierre lui dit: Énée, Jésus-Christ te guérit; lève-toi, et arrange ton lit. Et aussitôt il se leva.'),
  (44, 9, 35, 'Tous les habitants de Lydde et du Saron le virent, et ils se convertirent au Seigneur.'),
  (44, 9, 36, 'Il y avait à Joppé, parmi les disciples, une femme nommée Tabitha, ce qui signifie Dorcas: elle faisait beaucoup de bonnes œuvres et d''aumônes.'),
  (44, 9, 37, 'Elle tomba malade en ce temps-là, et mourut. Après l''avoir lavée, on la déposa dans une chambre haute.'),
  (44, 9, 38, 'Comme Lydde est près de Joppé, les disciples, ayant appris que Pierre s''y trouvait, envoyèrent deux hommes vers lui, pour le prier de venir chez eux sans tarder.'),
  (44, 9, 39, 'Pierre se leva, et partit avec ces hommes. Lorsqu''il fut arrivé, on le conduisit dans la chambre haute. Toutes les veuves l''entourèrent en pleurant, et lui montrèrent les tuniques et les vêtements que faisait Dorcas pendant qu''elle était avec elles.'),
  (44, 9, 40, 'Pierre fit sortir tout le monde, se mit à genoux, et pria; puis, se tournant vers le corps, il dit: Tabitha, lève-toi! Elle ouvrit les yeux, et ayant vu Pierre, elle s''assit.'),
  (44, 9, 41, 'Il lui donna la main, et la fit lever. Il appela ensuite les saints et les veuves, et la leur présenta vivante.'),
  (44, 9, 42, 'Cela fut connu de tout Joppé, et beaucoup crurent au Seigneur.'),
  (44, 9, 43, 'Pierre demeura quelque temps à Joppé, chez un corroyeur nommé Simon.'),
  (44, 10, 1, 'Il y avait à Césarée un homme nommé Corneille, centenier dans la cohorte dite italienne.'),
  (44, 10, 2, 'Cet homme était pieux et craignait Dieu, avec toute sa maison; il faisait beaucoup d''aumônes au peuple, et priait Dieu continuellement.'),
  (44, 10, 3, 'Vers la neuvième heure du jour, il vit clairement dans une vision un ange de Dieu qui entra chez lui, et qui lui dit: Corneille!'),
  (44, 10, 4, 'Les regards fixés sur lui, et saisi d''effroi, il répondit: Qu''est-ce, Seigneur? Et l''ange lui dit: Tes prières et tes aumônes sont montées devant Dieu, et il s''en est souvenu.'),
  (44, 10, 5, 'Envoie maintenant des hommes à Joppé, et fais venir Simon, surnommé Pierre;'),
  (44, 10, 6, 'il est logé chez un certain Simon, corroyeur, dont la maison est près de la mer.'),
  (44, 10, 7, 'Dès que l''ange qui lui avait parlé fut parti, Corneille appela deux de ses serviteurs, et un soldat pieux d''entre ceux qui étaient attachés à sa personne;'),
  (44, 10, 8, 'et, après leur avoir tout raconté, il les envoya à Joppé.'),
  (44, 10, 9, 'Le lendemain, comme ils étaient en route, et qu''ils approchaient de la ville, Pierre monta sur le toit, vers la sixième heure, pour prier.'),
  (44, 10, 10, 'Il eut faim, et il voulut manger. Pendant qu''on lui préparait à manger, il tomba en extase.'),
  (44, 10, 11, 'Il vit le ciel ouvert, et un objet semblable à une grande nappe attachée par les quatre coins, qui descendait et s''abaissait vers la terre,'),
  (44, 10, 12, 'et où se trouvaient tous les quadrupèdes et les reptiles de la terre et les oiseaux du ciel.'),
  (44, 10, 13, 'Et une voix lui dit: Lève-toi, Pierre, tue et mange.'),
  (44, 10, 14, 'Mais Pierre dit: Non, Seigneur, car je n''ai jamais rien mangé de souillé ni d''impur.'),
  (44, 10, 15, 'Et pour la seconde fois la voix se fit encore entendre à lui: Ce que Dieu a déclaré pur, ne le regarde pas comme souillé.'),
  (44, 10, 16, 'Cela arriva jusqu''à trois fois; et aussitôt après, l''objet fut retiré dans le ciel.'),
  (44, 10, 17, 'Tandis que Pierre ne savait en lui-même que penser du sens de la vision qu''il avait eue, voici, les hommes envoyés par Corneille, s''étant informés de la maison de Simon, se présentèrent à la porte,'),
  (44, 10, 18, 'et demandèrent à haute voix si c''était là que logeait Simon, surnommé Pierre.'),
  (44, 10, 19, 'Et comme Pierre était à réfléchir sur la vision, l''Esprit lui dit: Voici, trois hommes te demandent;'),
  (44, 10, 20, 'lève-toi, descends, et pars avec eux sans hésiter, car c''est moi qui les ai envoyés.'),
  (44, 10, 21, 'Pierre donc descendit, et il dit à ces hommes: Voici, je suis celui que vous cherchez; quel est le motif qui vous amène?'),
  (44, 10, 22, 'Ils répondirent: Corneille, centenier, homme juste et craignant Dieu, et de qui toute la nation des Juifs rend un bon témoignage, a été divinement averti par un saint ange de te faire venir dans sa maison et d''entendre tes paroles.'),
  (44, 10, 23, 'Pierre donc les fit entrer, et les logea. Le lendemain, il se leva, et partit avec eux. Quelques-uns des frères de Joppé l''accompagnèrent.'),
  (44, 10, 24, 'Ils arrivèrent à Césarée le jour suivant. Corneille les attendait, et avait invité ses parents et ses amis intimes.'),
  (44, 10, 25, 'Lorsque Pierre entra, Corneille, qui était allé au-devant de lui, tomba à ses pieds et se prosterna.'),
  (44, 10, 26, 'Mais Pierre le releva, en disant: Lève-toi; moi aussi, je suis un homme.'),
  (44, 10, 27, 'Et conversant avec lui, il entra, et trouva beaucoup de personnes réunies.'),
  (44, 10, 28, 'Vous savez, leur dit-il, qu''il est défendu à un Juif de se lier avec un étranger ou d''entrer chez lui; mais Dieu m''a appris à ne regarder aucun homme comme souillé et impur.'),
  (44, 10, 29, 'C''est pourquoi je n''ai pas eu d''objection à venir, puisque vous m''avez appelé; je vous demande donc pour quel motif vous m''avez envoyé chercher.'),
  (44, 10, 30, 'Corneille dit: Il y a quatre jours, à cette heure-ci, je priais dans ma maison à la neuvième heure; et voici, un homme vêtu d''un habit éclatant se présenta devant moi,'),
  (44, 10, 31, 'et dit: Corneille, ta prière a été exaucée, et Dieu s''est souvenu de tes aumônes.'),
  (44, 10, 32, 'Envoie donc à Joppé, et fais venir Simon, surnommé Pierre; il est logé dans la maison de Simon, corroyeur, près de la mer.'),
  (44, 10, 33, 'Aussitôt j''ai envoyé vers toi, et tu as bien fait de venir. Maintenant donc nous sommes tous devant Dieu, pour entendre tout ce que le Seigneur t''a ordonné de nous dire.'),
  (44, 10, 34, 'Alors Pierre, ouvrant la bouche, dit: En vérité, je reconnais que Dieu ne fait point acception de personnes,'),
  (44, 10, 35, 'mais qu''en toute nation celui qui le craint et qui pratique la justice lui est agréable.'),
  (44, 10, 36, 'Il a envoyé la parole aux fils d''Israël, en leur annonçant la paix par Jésus-Christ, qui est le Seigneur de tous.'),
  (44, 10, 37, 'Vous savez ce qui est arrivé dans toute la Judée, après avoir commencé en Galilée, à la suite du baptême que Jean a prêché;'),
  (44, 10, 38, 'vous savez comment Dieu a oint du Saint-Esprit et de force Jésus de Nazareth, qui allait de lieu en lieu faisant du bien et guérissant tous ceux qui étaient sous l''empire du diable, car Dieu était avec lui.'),
  (44, 10, 39, 'Nous sommes témoins de tout ce qu''il a fait dans le pays des Juifs et à Jérusalem. Ils l''ont tué, en le pendant au bois.'),
  (44, 10, 40, 'Dieu l''a ressuscité le troisième jour, et il a permis qu''il apparût,'),
  (44, 10, 41, 'non à tout le peuple, mais aux témoins choisis d''avance par Dieu, à nous qui avons mangé et bu avec lui, après qu''il fut ressuscité des morts.'),
  (44, 10, 42, 'Et Jésus nous a ordonné de prêcher au peuple et d''attester que c''est lui qui a été établi par Dieu juge des vivants et des morts.'),
  (44, 10, 43, 'Tous les prophètes rendent de lui le témoignage que quiconque croit en lui reçoit par son nom le pardon des péchés.'),
  (44, 10, 44, 'Comme Pierre prononçait encore ces mots, le Saint-Esprit descendit sur tous ceux qui écoutaient la parole.'),
  (44, 10, 45, 'Tous les fidèles circoncis qui étaient venus avec Pierre furent étonnés de ce que le don du Saint-Esprit était aussi répandu sur les païens.'),
  (44, 10, 46, 'Car ils les entendaient parler en langues et glorifier Dieu. Alors Pierre dit:'),
  (44, 10, 47, 'Peut-on refuser l''eau du baptême à ceux qui ont reçu le Saint-Esprit aussi bien que nous?'),
  (44, 10, 48, 'Et il ordonna qu''ils fussent baptisés au nom du Seigneur. Sur quoi ils le prièrent de rester quelques jours auprès d''eux.'),
  (44, 11, 1, 'Les apôtres et les frères qui étaient dans la Judée apprirent que les païens avaient aussi reçu la parole de Dieu.'),
  (44, 11, 2, 'Et lorsque Pierre fut monté à Jérusalem, les fidèles circoncis lui adressèrent des reproches,'),
  (44, 11, 3, 'en disant: Tu es entré chez des incirconcis, et tu as mangé avec eux.'),
  (44, 11, 4, 'Pierre se mit à leur exposer d''une manière suivie ce qui s''était passé. Il dit:'),
  (44, 11, 5, 'J''étais dans la ville de Joppé, et, pendant que je priais, je tombai en extase et j''eus une vision: un objet, semblable à une grande nappe attachée par les quatre coins, descendait du ciel et vint jusqu''à moi.'),
  (44, 11, 6, 'Les regards fixés sur cette nappe, j''examinai, et je vis les quadrupèdes de la terre, les bêtes sauvages, les reptiles, et les oiseaux du ciel.'),
  (44, 11, 7, 'Et j''entendis une voix qui me disait: Lève-toi, Pierre, tue et mange.'),
  (44, 11, 8, 'Mais je dis: Non, Seigneur, car jamais rien de souillé ni d''impur n''est entré dans ma bouche.'),
  (44, 11, 9, 'Et pour la seconde fois la voix se fit entendre du ciel: Ce que Dieu a déclaré pur, ne le regarde pas comme souillé.'),
  (44, 11, 10, 'Cela arriva jusqu''à trois fois; puis tout fut retiré dans le ciel.'),
  (44, 11, 11, 'Et voici, aussitôt trois hommes envoyés de Césarée vers moi se présentèrent devant la porte de la maison où j''étais.'),
  (44, 11, 12, 'L''Esprit me dit de partir avec eux sans hésiter. Les six hommes que voici m''accompagnèrent, et nous entrâmes dans la maison de Corneille.'),
  (44, 11, 13, 'Cet homme nous raconta comment il avait vu dans sa maison l''ange se présentant à lui et disant: Envoie à Joppé, et fais venir Simon, surnommé Pierre,'),
  (44, 11, 14, 'qui te dira des choses par lesquelles tu seras sauvé, toi et toute ta maison.'),
  (44, 11, 15, 'Lorsque je me fus mis à parler, le Saint-Esprit descendit sur eux, comme sur nous au commencement.'),
  (44, 11, 16, 'Et je me souvins de cette parole du Seigneur: Jean a baptisé d''eau, mais vous, vous serez baptisés du Saint-Esprit.'),
  (44, 11, 17, 'Or, puisque Dieu leur a accordé le même don qu''à nous qui avons cru au Seigneur Jésus-Christ, pouvais-je, moi, m''opposer à Dieu?'),
  (44, 11, 18, 'Après avoir entendu cela, ils se calmèrent, et ils glorifièrent Dieu, en disant: Dieu a donc accordé la repentance aussi aux païens, afin qu''ils aient la vie.'),
  (44, 11, 19, 'Ceux qui avaient été dispersés par la persécution survenue à l''occasion d''Étienne allèrent jusqu''en Phénicie, dans l''île de Chypre, et à Antioche, annonçant la parole seulement aux Juifs.'),
  (44, 11, 20, 'Il y eut cependant parmi eux quelques hommes de Chypre et de Cyrène, qui, étant venus à Antioche, s''adressèrent aussi aux Grecs, et leur annoncèrent la bonne nouvelle du Seigneur Jésus.'),
  (44, 11, 21, 'La main du Seigneur était avec eux, et un grand nombre de personnes crurent et se convertirent au Seigneur.'),
  (44, 11, 22, 'Le bruit en parvint aux oreilles des membres de l''Église de Jérusalem, et ils envoyèrent Barnabas jusqu''à Antioche.'),
  (44, 11, 23, 'Lorsqu''il fut arrivé, et qu''il eut vu la grâce de Dieu, il s''en réjouit, et il les exhorta tous à rester d''un cœur ferme attachés au Seigneur.'),
  (44, 11, 24, 'Car c''était un homme de bien, plein d''Esprit-Saint et de foi. Et une foule assez nombreuse se joignit au Seigneur.'),
  (44, 11, 25, 'Barnabas se rendit ensuite à Tarse, pour chercher Saul;'),
  (44, 11, 26, 'et, l''ayant trouvé, il l''amena à Antioche. Pendant toute une année, ils se réunirent aux assemblées de l''Église, et ils enseignèrent beaucoup de personnes. Ce fut à Antioche que, pour la première fois, les disciples furent appelés chrétiens.'),
  (44, 11, 27, 'En ce temps-là, des prophètes descendirent de Jérusalem à Antioche.'),
  (44, 11, 28, 'L''un d''eux, nommé Agabus, se leva, et annonça par l''Esprit qu''il y aurait une grande famine sur toute la terre. Elle arriva, en effet, sous Claude.'),
  (44, 11, 29, 'Les disciples résolurent d''envoyer, chacun selon ses moyens, un secours aux frères qui habitaient la Judée.'),
  (44, 11, 30, 'Ils le firent parvenir aux anciens par les mains de Barnabas et de Saul.'),
  (44, 12, 1, 'Vers le même temps, le roi Hérode se mit à maltraiter quelques membres de l''Église,'),
  (44, 12, 2, 'et il fit mourir par l''épée Jacques, frère de Jean.'),
  (44, 12, 3, 'Voyant que cela était agréable aux Juifs, il fit encore arrêter Pierre. -C''était pendant les jours des pains sans levain. -'),
  (44, 12, 4, 'Après l''avoir saisi et jeté en prison, il le mit sous la garde de quatre escouades de quatre soldats chacune, avec l''intention de le faire comparaître devant le peuple après la Pâque.'),
  (44, 12, 5, 'Pierre donc était gardé dans la prison; et l''Église ne cessait d''adresser pour lui des prières à Dieu.'),
  (44, 12, 6, 'La nuit qui précéda le jour où Hérode allait le faire comparaître, Pierre, lié de deux chaînes, dormait entre deux soldats; et des sentinelles devant la porte gardaient la prison.'),
  (44, 12, 7, 'Et voici, un ange du Seigneur survint, et une lumière brilla dans la prison. L''ange réveilla Pierre, en le frappant au côté, et en disant: Lève-toi promptement! Les chaînes tombèrent de ses mains.'),
  (44, 12, 8, 'Et l''ange lui dit: Mets ta ceinture et tes sandales. Et il fit ainsi. L''ange lui dit encore: Enveloppe-toi de ton manteau, et suis-moi.'),
  (44, 12, 9, 'Pierre sortit, et le suivit, ne sachant pas que ce qui se faisait par l''ange fût réel, et s''imaginant avoir une vision.'),
  (44, 12, 10, 'Lorsqu''ils eurent passé la première garde, puis la seconde, ils arrivèrent à la porte de fer qui mène à la ville, et qui s''ouvrit d''elle-même devant eux; ils sortirent, et s''avancèrent dans une rue. Aussitôt l''ange quitta Pierre.'),
  (44, 12, 11, 'Revenu à lui-même, Pierre dit: Je vois maintenant d''une manière certaine que le Seigneur a envoyé son ange, et qu''il m''a délivré de la main d''Hérode et de tout ce que le peuple juif attendait.'),
  (44, 12, 12, 'Après avoir réfléchi, il se dirigea vers la maison de Marie, mère de Jean, surnommé Marc, où beaucoup de personnes étaient réunies et priaient.'),
  (44, 12, 13, 'Il frappa à la porte du vestibule, et une servante, nommée Rhode, s''approcha pour écouter.'),
  (44, 12, 14, 'Elle reconnut la voix de Pierre; et, dans sa joie, au lieu d''ouvrir, elle courut annoncer que Pierre était devant la porte.'),
  (44, 12, 15, 'Ils lui dirent: Tu es folle. Mais elle affirma que la chose était ainsi. Et ils dirent: C''est son ange.'),
  (44, 12, 16, 'Cependant Pierre continuait à frapper. Ils ouvrirent, et furent étonnés de le voir.'),
  (44, 12, 17, 'Pierre, leur ayant de la main fait signe de se taire, leur raconta comment le Seigneur l''avait tiré de la prison, et il dit: Annoncez-le à Jacques et aux frères. Puis il sortit, et s''en alla dans un autre lieu.'),
  (44, 12, 18, 'Quand il fit jour, les soldats furent dans une grande agitation, pour savoir ce que Pierre était devenu.'),
  (44, 12, 19, 'Hérode, s''étant mis à sa recherche et ne l''ayant pas trouvé, interrogea les gardes, et donna l''ordre de les mener au supplice. Ensuite il descendit de la Judée à Césarée, pour y séjourner.'),
  (44, 12, 20, 'Hérode avait des dispositions hostiles à l''égard des Tyriens et des Sidoniens. Mais ils vinrent le trouver d''un commun accord; et, après avoir gagné Blaste, son chambellan, ils sollicitèrent la paix, parce que leur pays tirait sa subsistance de celui du roi.'),
  (44, 12, 21, 'A un jour fixé, Hérode, revêtu de ses habits royaux, et assis sur son trône, les harangua publiquement.'),
  (44, 12, 22, 'Le peuple s''écria: Voix d''un dieu, et non d''un homme!'),
  (44, 12, 23, 'Au même instant, un ange du Seigneur le frappa, parce qu''il n''avait pas donné gloire à Dieu. Et il expira, rongé des vers.'),
  (44, 12, 24, 'Cependant la parole de Dieu se répandait de plus en plus, et le nombre des disciples augmentait.'),
  (44, 12, 25, 'Barnabas et Saul, après s''être acquittés de leur message, s''en retournèrent de Jérusalem, emmenant avec eux Jean, surnommé Marc.'),
  (44, 13, 1, 'Il y avait dans l''Église d''Antioche des prophètes et des docteurs: Barnabas, Siméon appelé Niger, Lucius de Cyrène, Manahen, qui avait été élevé avec Hérode le tétrarque, et Saul.'),
  (44, 13, 2, 'Pendant qu''ils servaient le Seigneur dans leur ministère et qu''ils jeûnaient, le Saint-Esprit dit: Mettez-moi à part Barnabas et Saul pour l''œuvre à laquelle je les ai appelés.'),
  (44, 13, 3, 'Alors, après avoir jeûné et prié, ils leur imposèrent les mains, et les laissèrent partir.'),
  (44, 13, 4, 'Barnabas et Saul, envoyés par le Saint-Esprit, descendirent à Séleucie, et de là ils s''embarquèrent pour l''île de Chypre.'),
  (44, 13, 5, 'Arrivés à Salamine, ils annoncèrent la parole de Dieu dans les synagogues des Juifs. Ils avaient Jean pour aide.'),
  (44, 13, 6, 'Ayant ensuite traversé toute l''île jusqu''à Paphos, ils trouvèrent un certain magicien, faux prophète juif, nommé Bar-Jésus,'),
  (44, 13, 7, 'qui était avec le proconsul Sergius Paulus, homme intelligent. Ce dernier fit appeler Barnabas et Saul, et manifesta le désir d''entendre la parole de Dieu.'),
  (44, 13, 8, 'Mais Élymas, le magicien, -car c''est ce que signifie son nom, -leur faisait opposition, cherchant à détourner de la foi le proconsul.'),
  (44, 13, 9, 'Alors Saul, appelé aussi Paul, rempli du Saint-Esprit, fixa les regards sur lui,'),
  (44, 13, 10, 'et dit: Homme plein de toute espèce de ruse et de fraude, fils du diable, ennemi de toute justice, ne cesseras-tu point de pervertir les voies droites du Seigneur?'),
  (44, 13, 11, 'Maintenant voici, la main du Seigneur est sur toi, tu seras aveugle, et pour un temps tu ne verras pas le soleil. Aussitôt l''obscurité et les ténèbres tombèrent sur lui, et il cherchait, en tâtonnant, des personnes pour le guider.'),
  (44, 13, 12, 'Alors le proconsul, voyant ce qui était arrivé, crut, étant frappé de la doctrine du Seigneur.'),
  (44, 13, 13, 'Paul et ses compagnons, s''étant embarqués à Paphos, se rendirent à Perge en Pamphylie. Jean se sépara d''eux, et retourna à Jérusalem.'),
  (44, 13, 14, 'De Perge ils poursuivirent leur route, et arrivèrent à Antioche de Pisidie. Étant entrés dans la synagogue le jour du sabbat, ils s''assirent.'),
  (44, 13, 15, 'Après la lecture de la loi et des prophètes, les chefs de la synagogue leur envoyèrent dire: Hommes frères, si vous avez quelque exhortation à adresser au peuple, parlez.'),
  (44, 13, 16, 'Paul se leva, et, ayant fait signe de la main, il dit: Hommes Israélites, et vous qui craignez Dieu, écoutez!'),
  (44, 13, 17, 'Le Dieu de ce peuple d''Israël a choisi nos pères. Il mit ce peuple en honneur pendant son séjour au pays d''Égypte, et il l''en fit sortir par son bras puissant.'),
  (44, 13, 18, 'Il les nourrit près de quarante ans dans le désert;'),
  (44, 13, 19, 'et, ayant détruit sept nations au pays de Canaan, il leur en accorda le territoire comme propriété.'),
  (44, 13, 20, 'Après cela, durant quatre cent cinquante ans environ, il leur donna des juges, jusqu''au prophète Samuel.'),
  (44, 13, 21, 'Ils demandèrent alors un roi. Et Dieu leur donna, pendant quarante ans, Saül, fils de Kis, de la tribu de Benjamin;'),
  (44, 13, 22, 'puis, l''ayant rejeté, il leur suscita pour roi David, auquel il a rendu ce témoignage: J''ai trouvé David, fils d''Isaï, homme selon mon cœur, qui accomplira toutes mes volontés.'),
  (44, 13, 23, 'C''est de la postérité de David que Dieu, selon sa promesse, a suscité à Israël un Sauveur, qui est Jésus.'),
  (44, 13, 24, 'Avant sa venue, Jean avait prêché le baptême de repentance à tout le peuple d''Israël.'),
  (44, 13, 25, 'Et lorsque Jean achevait sa course, il disait: Je ne suis pas celui que vous pensez; mais voici, après moi vient celui des pieds duquel je ne suis pas digne de délier les souliers.'),
  (44, 13, 26, 'Hommes frères, fils de la race d''Abraham, et vous qui craignez Dieu, c''est à vous que cette parole de salut a été envoyée.'),
  (44, 13, 27, 'Car les habitants de Jérusalem et leurs chefs ont méconnu Jésus, et, en le condamnant, ils ont accompli les paroles des prophètes qui se lisent chaque sabbat.'),
  (44, 13, 28, 'Quoiqu''ils ne trouvassent en lui rien qui fût digne de mort, ils ont demandé à Pilate de le faire mourir.'),
  (44, 13, 29, 'Et, après qu''ils eurent accompli tout ce qui est écrit de lui, ils le descendirent de la croix et le déposèrent dans un sépulcre.'),
  (44, 13, 30, 'Mais Dieu l''a ressuscité des morts.'),
  (44, 13, 31, 'Il est apparu pendant plusieurs jours à ceux qui étaient montés avec lui de la Galilée à Jérusalem, et qui sont maintenant ses témoins auprès du peuple.'),
  (44, 13, 32, 'Et nous, nous vous annonçons cette bonne nouvelle que la promesse faite à nos pères,'),
  (44, 13, 33, 'Dieu l''a accomplie pour nous leurs enfants, en ressuscitant Jésus, selon ce qui est écrit dans le Psaume deuxième: Tu es mon Fils, Je t''ai engendré aujourd''hui.'),
  (44, 13, 34, 'Qu''il l''ait ressuscité des morts, de telle sorte qu''il ne retournera pas à la corruption, c''est ce qu''il a déclaré, en disant: Je vous donnerai Les grâces saintes promises à David, ces grâces qui sont assurées.'),
  (44, 13, 35, 'C''est pourquoi il dit encore ailleurs: Tu ne permettras pas que ton Saint voie la corruption.'),
  (44, 13, 36, 'Or, David, après avoir en son temps servi au dessein de Dieu, est mort, a été réuni à ses pères, et a vu la corruption.'),
  (44, 13, 37, 'Mais celui que Dieu a ressuscité n''a pas vu la corruption.'),
  (44, 13, 38, 'Sachez donc, hommes frères, que c''est par lui que le pardon des péchés vous est annoncé,'),
  (44, 13, 39, 'et que quiconque croit est justifié par lui de toutes les choses dont vous ne pouviez être justifiés par la loi de Moïse.'),
  (44, 13, 40, 'Ainsi, prenez garde qu''il ne vous arrive ce qui est dit dans les prophètes:'),
  (44, 13, 41, 'Voyez, contempteurs, Soyez étonnés et disparaissez; Car je vais faire en vos jours une œuvre, Une œuvre que vous ne croiriez pas si on vous la racontait.'),
  (44, 13, 42, 'Lorsqu''ils sortirent, on les pria de parler le sabbat suivant sur les mêmes choses;'),
  (44, 13, 43, 'et, à l''issue de l''assemblée, beaucoup de Juifs et de prosélytes pieux suivirent Paul et Barnabas, qui s''entretinrent avec eux, et les exhortèrent à rester attachés à la grâce de Dieu.'),
  (44, 13, 44, 'Le sabbat suivant, presque toute la ville se rassembla pour entendre la parole de Dieu.'),
  (44, 13, 45, 'Les Juifs, voyant la foule, furent remplis de jalousie, et ils s''opposaient à ce que disait Paul, en le contredisant et en l''injuriant.'),
  (44, 13, 46, 'Paul et Barnabas leur dirent avec assurance: C''est à vous premièrement que la parole de Dieu devait être annoncée; mais, puisque vous la repoussez, et que vous vous jugez vous-mêmes indignes de la vie éternelle, voici, nous nous tournons vers les païens.'),
  (44, 13, 47, 'Car ainsi nous l''a ordonné le Seigneur: Je t''ai établi pour être la lumière des nations, Pour porter le salut jusqu''aux extrémités de la terre.'),
  (44, 13, 48, 'Les païens se réjouissaient en entendant cela, ils glorifiaient la parole du Seigneur, et tous ceux qui étaient destinés à la vie éternelle crurent.'),
  (44, 13, 49, 'La parole du Seigneur se répandait dans tout le pays.'),
  (44, 13, 50, 'Mais les Juifs excitèrent les femmes dévotes de distinction et les principaux de la ville; ils provoquèrent une persécution contre Paul et Barnabas, et ils les chassèrent de leur territoire.'),
  (44, 13, 51, 'Paul et Barnabas secouèrent contre eux la poussière de leurs pieds, et allèrent à Icone,'),
  (44, 13, 52, 'tandis que les disciples étaient remplis de joie et du Saint-Esprit.'),
  (44, 14, 1, 'A Icone, Paul et Barnabas entrèrent ensemble dans la synagogue des Juifs, et ils parlèrent de telle manière qu''une grande multitude de Juifs et de Grecs crurent.'),
  (44, 14, 2, 'Mais ceux des Juifs qui ne crurent point excitèrent et aigrirent les esprits des païens contre les frères.'),
  (44, 14, 3, 'Ils restèrent cependant assez longtemps à Icone, parlant avec assurance, appuyés sur le Seigneur, qui rendait témoignage à la parole de sa grâce et permettait qu''il se fît par leurs mains des prodiges et des miracles.'),
  (44, 14, 4, 'La population de la ville se divisa: les uns étaient pour les Juifs, les autres pour les apôtres.'),
  (44, 14, 5, 'Et comme les païens et les Juifs, de concert avec leurs chefs, se mettaient en mouvement pour les outrager et les lapider,'),
  (44, 14, 6, 'Paul et Barnabas, en ayant eu connaissance, se réfugièrent dans les villes de la Lycaonie, à Lystre et à Derbe, et dans la contrée d''alentour.'),
  (44, 14, 7, 'Et ils y annoncèrent la bonne nouvelle.'),
  (44, 14, 8, 'A Lystre, se tenait assis un homme impotent des pieds, boiteux de naissance, et qui n''avait jamais marché.'),
  (44, 14, 9, 'Il écoutait parler Paul. Et Paul, fixant les regards sur lui et voyant qu''il avait la foi pour être guéri,'),
  (44, 14, 10, 'dit d''une voix forte: Lève-toi droit sur tes pieds. Et il se leva d''un bond et marcha.'),
  (44, 14, 11, 'A la vue de ce que Paul avait fait, la foule éleva la voix, et dit en langue lycaonienne: Les dieux sous une forme humaine sont descendus vers nous.'),
  (44, 14, 12, 'Ils appelaient Barnabas Jupiter, et Paul Mercure, parce que c''était lui qui portait la parole.'),
  (44, 14, 13, 'Le prêtre de Jupiter, dont le temple était à l''entrée de la ville, amena des taureaux avec des bandelettes vers les portes, et voulait, de même que la foule, offrir un sacrifice.'),
  (44, 14, 14, 'Les apôtres Barnabas et Paul, ayant appris cela, déchirèrent leurs vêtements, et se précipitèrent au milieu de la foule,'),
  (44, 14, 15, 'en s''écriant: O hommes, pourquoi agissez-vous de la sorte? Nous aussi, nous sommes des hommes de la même nature que vous; et, vous apportant une bonne nouvelle, nous vous exhortons à renoncer à ces choses vaines, pour vous tourner vers le Dieu vivant, qui a fait le ciel, la terre, la mer, et tout ce qui s''y trouve.'),
  (44, 14, 16, 'Ce Dieu, dans les âges passés, a laissé toutes les nations suivre leurs propres voies,'),
  (44, 14, 17, 'quoiqu''il n''ait cessé de rendre témoignage de ce qu''il est, en faisant du bien, en vous dispensant du ciel les pluies et les saisons fertiles, en vous donnant la nourriture avec abondance et en remplissant vos cœurs de joie.'),
  (44, 14, 18, 'A peine purent-ils, par ces paroles, empêcher la foule de leur offrir un sacrifice.'),
  (44, 14, 19, 'Alors survinrent d''Antioche et d''Icone des Juifs qui gagnèrent la foule, et qui, après avoir lapidé Paul, le traînèrent hors de la ville, pensant qu''il était mort.'),
  (44, 14, 20, 'Mais, les disciples l''ayant entouré, il se leva, et entra dans la ville. Le lendemain, il partit pour Derbe avec Barnabas.'),
  (44, 14, 21, 'Quand ils eurent évangélisé cette ville et fait un certain nombre de disciples, ils retournèrent à Lystre, à Icone et à Antioche,'),
  (44, 14, 22, 'fortifiant l''esprit des disciples, les exhortant à persévérer dans la foi, et disant que c''est par beaucoup de tribulations qu''il nous faut entrer dans le royaume de Dieu.'),
  (44, 14, 23, 'Ils firent nommer des anciens dans chaque Église, et, après avoir prié et jeûné, ils les recommandèrent au Seigneur, en qui ils avaient cru.'),
  (44, 14, 24, 'Traversant ensuite la Pisidie, ils vinrent en Pamphylie,'),
  (44, 14, 25, 'annoncèrent la parole à Perge, et descendirent à Attalie.'),
  (44, 14, 26, 'De là ils s''embarquèrent pour Antioche, d''où ils avaient été recommandés à la grâce de Dieu pour l''œuvre qu''ils venaient d''accomplir.'),
  (44, 14, 27, 'Après leur arrivée, ils convoquèrent l''Église, et ils racontèrent tout ce que Dieu avait fait avec eux, et comment il avait ouvert aux nations la porte de la foi.'),
  (44, 14, 28, 'Et ils demeurèrent assez longtemps avec les disciples.'),
  (44, 15, 1, 'Quelques hommes, venus de la Judée, enseignaient les frères, en disant: Si vous n''êtes circoncis selon le rite de Moïse, vous ne pouvez être sauvés.'),
  (44, 15, 2, 'Paul et Barnabas eurent avec eux un débat et une vive discussion; et les frères décidèrent que Paul et Barnabas, et quelques-uns des leurs, monteraient à Jérusalem vers les apôtres et les anciens, pour traiter cette question.'),
  (44, 15, 3, 'Après avoir été accompagnés par l''Église, ils poursuivirent leur route à travers la Phénicie et la Samarie, racontant la conversion des païens, et ils causèrent une grande joie à tous les frères.'),
  (44, 15, 4, 'Arrivés à Jérusalem, ils furent reçus par l''Église, les apôtres et les anciens, et ils racontèrent tout ce que Dieu avait fait avec eux.'),
  (44, 15, 5, 'Alors quelques-uns du parti des pharisiens, qui avaient cru, se levèrent, en disant qu''il fallait circoncire les païens et exiger l''observation de la loi de Moïse.'),
  (44, 15, 6, 'Les apôtres et les anciens se réunirent pour examiner cette affaire.'),
  (44, 15, 7, 'Une grande discussion s''étant engagée, Pierre se leva, et leur dit: Hommes frères, vous savez que dès longtemps Dieu a fait un choix parmi vous, afin que, par ma bouche, les païens entendissent la parole de l''Évangile et qu''ils crussent.'),
  (44, 15, 8, 'Et Dieu, qui connaît les cœurs, leur a rendu témoignage, en leur donnant le Saint-Esprit comme à nous;'),
  (44, 15, 9, 'il n''a fait aucune différence entre nous et eux, ayant purifié leurs cœurs par la foi.'),
  (44, 15, 10, 'Maintenant donc, pourquoi tentez-vous Dieu, en mettant sur le cou des disciples un joug que ni nos pères ni nous n''avons pu porter?'),
  (44, 15, 11, 'Mais c''est par la grâce du Seigneur Jésus que nous croyons être sauvés, de la même manière qu''eux.'),
  (44, 15, 12, 'Toute l''assemblée garda le silence, et l''on écouta Barnabas et Paul, qui racontèrent tous les miracles et les prodiges que Dieu avait faits par eux au milieu des païens.'),
  (44, 15, 13, 'Lorsqu''ils eurent cessé de parler, Jacques prit la parole, et dit: Hommes frères, écoutez-moi!'),
  (44, 15, 14, 'Simon a raconté comment Dieu a d''abord jeté les regards sur les nations pour choisir du milieu d''elles un peuple qui portât son nom.'),
  (44, 15, 15, 'Et avec cela s''accordent les paroles des prophètes, selon qu''il est écrit:'),
  (44, 15, 16, 'Après cela, je reviendrai, et je relèverai de sa chute la tente de David, J''en réparerai les ruines, et je la redresserai,'),
  (44, 15, 17, 'Afin que le reste des hommes cherche le Seigneur, Ainsi que toutes les nations sur lesquelles mon nom est invoqué, Dit le Seigneur, qui fait ces choses,'),
  (44, 15, 18, 'Et à qui elles sont connues de toute éternité.'),
  (44, 15, 19, 'C''est pourquoi je suis d''avis qu''on ne crée pas des difficultés à ceux des païens qui se convertissent à Dieu,'),
  (44, 15, 20, 'mais qu''on leur écrive de s''abstenir des souillures des idoles, de l''impudicité, des animaux étouffés et du sang.'),
  (44, 15, 21, 'Car, depuis bien des générations, Moïse a dans chaque ville des gens qui le prêchent, puisqu''on le lit tous les jours de sabbat dans les synagogues.'),
  (44, 15, 22, 'Alors il parut bon aux apôtres et aux anciens, et à toute l''Église, de choisir parmi eux et d''envoyer à Antioche, avec Paul et Barnabas, Jude appelé Barsabas et Silas, hommes considérés entre les frères.'),
  (44, 15, 23, 'Ils les chargèrent d''une lettre ainsi conçue: Les apôtres, les anciens, et les frères, aux frères d''entre les païens, qui sont à Antioche, en Syrie, et en Cilicie, salut!'),
  (44, 15, 24, 'Ayant appris que quelques hommes partis de chez nous, et auxquels nous n''avions donné aucun ordre, vous ont troublés par leurs discours et ont ébranlé vos âmes,'),
  (44, 15, 25, 'nous avons jugé à propos, après nous être réunis tous ensemble, de choisir des délégués et de vous les envoyer avec nos bien-aimés Barnabas et Paul,'),
  (44, 15, 26, 'ces hommes qui ont exposé leur vie pour le nom de notre Seigneur Jésus-Christ.'),
  (44, 15, 27, 'Nous avons donc envoyé Jude et Silas, qui vous annonceront de leur bouche les mêmes choses.'),
  (44, 15, 28, 'Car il a paru bon au Saint-Esprit et à nous de ne vous imposer d''autre charge que ce qui est nécessaire,'),
  (44, 15, 29, 'savoir, de vous abstenir des viandes sacrifiées aux idoles, du sang, des animaux étouffés, et de l''impudicité, choses contre lesquelles vous vous trouverez bien de vous tenir en garde. Adieu.'),
  (44, 15, 30, 'Eux donc, ayant pris congé de l''Église, allèrent à Antioche, où ils remirent la lettre à la multitude assemblée.'),
  (44, 15, 31, 'Après l''avoir lue, les frères furent réjouis de l''encouragement qu''elle leur apportait.'),
  (44, 15, 32, 'Jude et Silas, qui étaient eux-mêmes prophètes, les exhortèrent et les fortifièrent par plusieurs discours.'),
  (44, 15, 33, 'Au bout de quelque temps, les frères les laissèrent en paix retourner vers ceux qui les avaient envoyés.'),
  (44, 15, 34, 'Toutefois Silas trouva bon de rester.'),
  (44, 15, 35, 'Paul et Barnabas demeurèrent à Antioche, enseignant et annonçant, avec plusieurs autres, la bonne nouvelle de la parole du Seigneur.'),
  (44, 15, 36, 'Quelques jours s''écoulèrent, après lesquels Paul dit à Barnabas: Retournons visiter les frères dans toutes les villes où nous avons annoncé la parole du Seigneur, pour voir en quel état ils sont.'),
  (44, 15, 37, 'Barnabas voulait emmener aussi Jean, surnommé Marc;'),
  (44, 15, 38, 'mais Paul jugea plus convenable de ne pas prendre avec eux celui qui les avait quittés depuis la Pamphylie, et qui ne les avait point accompagnés dans leur œuvre.'),
  (44, 15, 39, 'Ce dissentiment fut assez vif pour être cause qu''ils se séparèrent l''un de l''autre. Et Barnabas, prenant Marc avec lui, s''embarqua pour l''île de Chypre.'),
  (44, 15, 40, 'Paul fit choix de Silas, et partit, recommandé par les frères à la grâce du Seigneur.'),
  (44, 15, 41, 'Il parcourut la Syrie et la Cilicie, fortifiant les Églises.'),
  (44, 16, 1, 'Il se rendit ensuite à Derbe et à Lystre. Et voici, il y avait là un disciple nommé Timothée, fils d''une femme juive fidèle et d''un père grec.'),
  (44, 16, 2, 'Les frères de Lystre et d''Icone rendaient de lui un bon témoignage.'),
  (44, 16, 3, 'Paul voulut l''emmener avec lui; et, l''ayant pris, il le circoncit, à cause des Juifs qui étaient dans ces lieux-là, car tous savaient que son père était grec.'),
  (44, 16, 4, 'En passant par les villes, ils recommandaient aux frères d''observer les décisions des apôtres et des anciens de Jérusalem.'),
  (44, 16, 5, 'Les Églises se fortifiaient dans la foi, et augmentaient en nombre de jour en jour.'),
  (44, 16, 6, 'Ayant été empêchés par le Saint-Esprit d''annoncer la parole dans l''Asie, ils traversèrent la Phrygie et le pays de Galatie.'),
  (44, 16, 7, 'Arrivés près de la Mysie, ils se disposaient à entrer en Bithynie; mais l''Esprit de Jésus ne le leur permit pas.'),
  (44, 16, 8, 'Ils franchirent alors la Mysie, et descendirent à Troas.'),
  (44, 16, 9, 'Pendant la nuit, Paul eut une vision: un Macédonien lui apparut, et lui fit cette prière: Passe en Macédoine, secours-nous!'),
  (44, 16, 10, 'Après cette vision de Paul, nous cherchâmes aussitôt à nous rendre en Macédoine, concluant que le Seigneur nous appelait à y annoncer la bonne nouvelle.'),
  (44, 16, 11, 'Étant partis de Troas, nous fîmes voile directement vers la Samothrace, et le lendemain nous débarquâmes à Néapolis.'),
  (44, 16, 12, 'De là nous allâmes à Philippes, qui est la première ville d''un district de Macédoine, et une colonie. Nous passâmes quelques jours dans cette ville.'),
  (44, 16, 13, 'Le jour du sabbat, nous nous rendîmes, hors de la porte, vers une rivière, où nous pensions que se trouvait un lieu de prière. Nous nous assîmes, et nous parlâmes aux femmes qui étaient réunies.'),
  (44, 16, 14, 'L''une d''elles, nommée Lydie, marchande de pourpre, de la ville de Thyatire, était une femme craignant Dieu, et elle écoutait. Le Seigneur lui ouvrit le cœur, pour qu''elle fût attentive à ce que disait Paul.'),
  (44, 16, 15, 'Lorsqu''elle eut été baptisée, avec sa famille, elle nous fit cette demande: Si vous me jugez fidèle au Seigneur, entrez dans ma maison, et demeurez-y. Et elle nous pressa par ses instances.'),
  (44, 16, 16, 'Comme nous allions au lieu de prière, une servante qui avait un esprit de Python, et qui, en devinant, procurait un grand profit à ses maîtres, vint au-devant de nous,'),
  (44, 16, 17, 'et se mit à nous suivre, Paul et nous. Elle criait: Ces hommes sont les serviteurs du Dieu Très-Haut, et ils vous annoncent la voie du salut.'),
  (44, 16, 18, 'Elle fit cela pendant plusieurs jours. Paul fatigué se retourna, et dit à l''esprit: Je t''ordonne, au nom de Jésus-Christ, de sortir d''elle. Et il sortit à l''heure même.'),
  (44, 16, 19, 'Les maîtres de la servante, voyant disparaître l''espoir de leur gain, se saisirent de Paul et de Silas, et les traînèrent sur la place publique devant les magistrats.'),
  (44, 16, 20, 'Ils les présentèrent aux préteurs, en disant: Ces hommes troublent notre ville; ce sont des Juifs,'),
  (44, 16, 21, 'qui annoncent des coutumes qu''il ne nous est permis ni de recevoir ni de suivre, à nous qui sommes Romains.'),
  (44, 16, 22, 'La foule se souleva aussi contre eux, et les préteurs, ayant fait arracher leurs vêtements, ordonnèrent qu''on les battît de verges.'),
  (44, 16, 23, 'Après qu''on les eut chargés de coups, ils les jetèrent en prison, en recommandant au geôlier de les garder sûrement.'),
  (44, 16, 24, 'Le geôlier, ayant reçu cet ordre, les jeta dans la prison intérieure, et leur mit les ceps aux pieds.'),
  (44, 16, 25, 'Vers le milieu de la nuit, Paul et Silas priaient et chantaient les louanges de Dieu, et les prisonniers les entendaient.'),
  (44, 16, 26, 'Tout à coup il se fit un grand tremblement de terre, en sorte que les fondements de la prison furent ébranlés; au même instant, toutes les portes s''ouvrirent, et les liens de tous les prisonniers furent rompus.'),
  (44, 16, 27, 'Le geôlier se réveilla, et, lorsqu''il vit les portes de la prison ouvertes, il tira son épée et allait se tuer, pensant que les prisonniers s''étaient enfuis.'),
  (44, 16, 28, 'Mais Paul cria d''une voix forte: Ne te fais point de mal, nous sommes tous ici.'),
  (44, 16, 29, 'Alors le geôlier, ayant demandé de la lumière, entra précipitamment, et se jeta tout tremblant aux pieds de Paul et de Silas;'),
  (44, 16, 30, 'il les fit sortir, et dit: Seigneurs, que faut-il que je fasse pour être sauvé?'),
  (44, 16, 31, 'Paul et Silas répondirent: Crois au Seigneur Jésus, et tu seras sauvé, toi et ta famille.'),
  (44, 16, 32, 'Et ils lui annoncèrent la parole du Seigneur, ainsi qu''à tous ceux qui étaient dans sa maison.'),
  (44, 16, 33, 'Il les prit avec lui, à cette heure même de la nuit, il lava leurs plaies, et aussitôt il fut baptisé, lui et tous les siens.'),
  (44, 16, 34, 'Les ayant conduits dans son logement, il leur servit à manger, et il se réjouit avec toute sa famille de ce qu''il avait cru en Dieu.'),
  (44, 16, 35, 'Quand il fit jour, les préteurs envoyèrent les licteurs pour dire au geôlier: Relâche ces hommes.'),
  (44, 16, 36, 'Et le geôlier annonça la chose à Paul: Les préteurs ont envoyé dire qu''on vous relâchât; maintenant donc sortez, et allez en paix.'),
  (44, 16, 37, 'Mais Paul dit aux licteurs: Après nous avoir battus de verges publiquement et sans jugement, nous qui sommes Romains, ils nous ont jetés en prison, et maintenant ils nous font sortir secrètement! Il n''en sera pas ainsi. Qu''ils viennent eux-mêmes nous mettre en liberté.'),
  (44, 16, 38, 'Les licteurs rapportèrent ces paroles aux préteurs, qui furent effrayés en apprenant qu''ils étaient Romains.'),
  (44, 16, 39, 'Ils vinrent les apaiser, et ils les mirent en liberté, en les priant de quitter la ville.'),
  (44, 16, 40, 'Quand ils furent sortis de la prison, ils entrèrent chez Lydie, et, après avoir vu et exhorté les frères, ils partirent.'),
  (44, 17, 1, 'Paul et Silas passèrent par Amphipolis et Apollonie, et ils arrivèrent à Thessalonique, où les Juifs avaient une synagogue.'),
  (44, 17, 2, 'Paul y entra, selon sa coutume. Pendant trois sabbats, il discuta avec eux, d''après les Écritures,'),
  (44, 17, 3, 'expliquant et établissant que le Christ devait souffrir et ressusciter des morts. Et Jésus que je vous annonce, disait-il, c''est lui qui est le Christ.'),
  (44, 17, 4, 'Quelques-uns d''entre eux furent persuadés, et se joignirent à Paul et à Silas, ainsi qu''une grande multitude de Grecs craignant Dieu, et beaucoup de femmes de qualité.'),
  (44, 17, 5, 'Mais les Juifs, jaloux prirent avec eux quelques méchants hommes de la populace, provoquèrent des attroupements, et répandirent l''agitation dans la ville. Ils se portèrent à la maison de Jason, et ils cherchèrent Paul et Silas, pour les amener vers le peuple.'),
  (44, 17, 6, 'Ne les ayant pas trouvés, ils traînèrent Jason et quelques frères devant les magistrats de la ville, en criant: Ces gens, qui ont bouleversé le monde, sont aussi venus ici,'),
  (44, 17, 7, 'et Jason les a reçus. Ils agissent tous contre les édits de César, disant qu''il y a un autre roi, Jésus.'),
  (44, 17, 8, 'Par ces paroles ils émurent la foule et les magistrats,'),
  (44, 17, 9, 'qui ne laissèrent aller Jason et les autres qu''après avoir obtenu d''eux une caution.'),
  (44, 17, 10, 'Aussitôt les frères firent partir de nuit Paul et Silas pour Bérée. Lorsqu''ils furent arrivés, ils entrèrent dans la synagogue des Juifs.'),
  (44, 17, 11, 'Ces Juifs avaient des sentiments plus nobles que ceux de Thessalonique; ils reçurent la parole avec beaucoup d''empressement, et ils examinaient chaque jour les Écritures, pour voir si ce qu''on leur disait était exact.'),
  (44, 17, 12, 'Plusieurs d''entre eux crurent, ainsi que beaucoup de femmes grecques de distinction, et beaucoup d''hommes.'),
  (44, 17, 13, 'Mais, quand les Juifs de Thessalonique surent que Paul annonçait aussi à Bérée la parole de Dieu, ils vinrent y agiter la foule.'),
  (44, 17, 14, 'Alors les frères firent aussitôt partir Paul du côté de la mer; Silas et Timothée restèrent à Bérée.'),
  (44, 17, 15, 'Ceux qui accompagnaient Paul le conduisirent jusqu''à Athènes. Puis ils s''en retournèrent, chargés de transmettre à Silas et à Timothée l''ordre de le rejoindre au plus tôt.'),
  (44, 17, 16, 'Comme Paul les attendait à Athènes, il sentait au dedans de lui son esprit s''irriter, à la vue de cette ville pleine d''idoles.'),
  (44, 17, 17, 'Il s''entretenait donc dans la synagogue avec les Juifs et les hommes craignant Dieu, et sur la place publique chaque jour avec ceux qu''il rencontrait.'),
  (44, 17, 18, 'Quelques philosophes épicuriens et stoïciens se mirent à parler avec lui. Et les uns disaient: Que veut dire ce discoureur? D''autres, l''entendant annoncer Jésus et la résurrection, disaient: Il semble qu''il annonce des divinités étrangères.'),
  (44, 17, 19, 'Alors ils le prirent, et le menèrent à l''Aréopage, en disant: Pourrions-nous savoir quelle est cette nouvelle doctrine que tu enseignes?'),
  (44, 17, 20, 'Car tu nous fais entendre des choses étranges. Nous voudrions donc savoir ce que cela peut être.'),
  (44, 17, 21, 'Or, tous les Athéniens et les étrangers demeurant à Athènes ne passaient leur temps qu''à dire ou à écouter des nouvelles.'),
  (44, 17, 22, 'Paul, debout au milieu de l''Aréopage, dit: Hommes Athéniens, je vous trouve à tous égards extrêmement religieux.'),
  (44, 17, 23, 'Car, en parcourant votre ville et en considérant les objets de votre dévotion, j''ai même découvert un autel avec cette inscription: A un dieu inconnu! Ce que vous révérez sans le connaître, c''est ce que je vous annonce.'),
  (44, 17, 24, 'Le Dieu qui a fait le monde et tout ce qui s''y trouve, étant le Seigneur du ciel et de la terre, n''habite point dans des temples faits de main d''homme;'),
  (44, 17, 25, 'il n''est point servi par des mains humaines, comme s''il avait besoin de quoi que ce soit, lui qui donne à tous la vie, la respiration, et toutes choses.'),
  (44, 17, 26, 'Il a fait que tous les hommes, sortis d''un seul sang, habitassent sur toute la surface de la terre, ayant déterminé la durée des temps et les bornes de leur demeure;'),
  (44, 17, 27, 'il a voulu qu''ils cherchassent le Seigneur, et qu''ils s''efforçassent de le trouver en tâtonnant, bien qu''il ne soit pas loin de chacun de nous,'),
  (44, 17, 28, 'car en lui nous avons la vie, le mouvement, et l''être. C''est ce qu''ont dit aussi quelques-uns de vos poètes: De lui nous sommes la race…'),
  (44, 17, 29, 'Ainsi donc, étant la race de Dieu, nous ne devons pas croire que la divinité soit semblable à de l''or, à de l''argent, ou à de la pierre, sculptés par l''art et l''industrie de l''homme.'),
  (44, 17, 30, 'Dieu, sans tenir compte des temps d''ignorance, annonce maintenant à tous les hommes, en tous lieux, qu''ils aient à se repentir,'),
  (44, 17, 31, 'parce qu''il a fixé un jour où il jugera le monde selon la justice, par l''homme qu''il a désigné, ce dont il a donné à tous une preuve certaine en le ressuscitant des morts…'),
  (44, 17, 32, 'Lorsqu''ils entendirent parler de résurrection des morts, les uns se moquèrent, et les autres dirent: Nous t''entendrons là-dessus une autre fois.'),
  (44, 17, 33, 'Ainsi Paul se retira du milieu d''eux.'),
  (44, 17, 34, 'Quelques-uns néanmoins s''attachèrent à lui et crurent, Denys l''aréopagite, une femme nommée Damaris, et d''autres avec eux.'),
  (44, 18, 1, 'Après cela, Paul partit d''Athènes, et se rendit à Corinthe.'),
  (44, 18, 2, 'Il y trouva un Juif nommé Aquilas, originaire du Pont, récemment arrivé d''Italie avec sa femme Priscille, parce que Claude avait ordonné à tous les Juifs de sortir de Rome. Il se lia avec eux;'),
  (44, 18, 3, 'et, comme il avait le même métier, il demeura chez eux et y travailla: ils étaient faiseurs de tentes.'),
  (44, 18, 4, 'Paul discourait dans la synagogue chaque sabbat, et il persuadait des Juifs et des Grecs.'),
  (44, 18, 5, 'Mais quand Silas et Timothée furent arrivés de la Macédoine, il se donna tout entier à la parole, attestant aux Juifs que Jésus était le Christ.'),
  (44, 18, 6, 'Les Juifs faisant alors de l''opposition et se livrant à des injures, Paul secoua ses vêtements, et leur dit: Que votre sang retombe sur votre tête! J''en suis pur. Dès maintenant, j''irai vers les païens.'),
  (44, 18, 7, 'Et sortant de là, il entra chez un nommé Justus, homme craignant Dieu, et dont la maison était contiguë à la synagogue.'),
  (44, 18, 8, 'Cependant Crispus, le chef de la synagogue, crut au Seigneur avec toute sa famille. Et plusieurs Corinthiens, qui avaient entendu Paul, crurent aussi, et furent baptisés.'),
  (44, 18, 9, 'Le Seigneur dit à Paul en vision pendant la nuit: Ne crains point; mais parle, et ne te tais point,'),
  (44, 18, 10, 'Car je suis avec toi, et personne ne mettra la main sur toi pour te faire du mal: parle, car j''ai un peuple nombreux dans cette ville.'),
  (44, 18, 11, 'Il y demeura un an et six mois, enseignant parmi les Corinthiens la parole de Dieu.'),
  (44, 18, 12, 'Du temps que Gallion était proconsul de l''Achaïe, les Juifs se soulevèrent unanimement contre Paul, et le menèrent devant le tribunal,'),
  (44, 18, 13, 'en disant: Cet homme excite les gens à servir Dieu d''une manière contraire à la loi.'),
  (44, 18, 14, 'Paul allait ouvrir la bouche, lorsque Gallion dit aux Juifs: S''il s''agissait de quelque injustice ou de quelque méchante action, je vous écouterais comme de raison, ô Juifs;'),
  (44, 18, 15, 'mais, s''il s''agit de discussions sur une parole, sur des noms, et sur votre loi, cela vous regarde: je ne veux pas être juge de ces choses.'),
  (44, 18, 16, 'Et il les renvoya du tribunal.'),
  (44, 18, 17, 'Alors tous, se saisissant de Sosthène, le chef de la synagogue, le battirent devant le tribunal, sans que Gallion s''en mît en peine.'),
  (44, 18, 18, 'Paul resta encore assez longtemps à Corinthe. Ensuite il prit congé des frères, et s''embarqua pour la Syrie, avec Priscille et Aquilas, après s''être fait raser la tête à Cenchrées, car il avait fait un vœu.'),
  (44, 18, 19, 'Ils arrivèrent à Éphèse, et Paul y laissa ses compagnons. Étant entré dans la synagogue, il s''entretint avec les Juifs,'),
  (44, 18, 20, 'qui le prièrent de prolonger son séjour. Mais il n''y consentit point,'),
  (44, 18, 21, 'et il prit congé d''eux, en disant: Il faut absolument que je célèbre la fête prochaine à Jérusalem. Je reviendrai vers vous, si Dieu le veut. Et il partit d''Éphèse.'),
  (44, 18, 22, 'Étant débarqué à Césarée, il monta à Jérusalem, et, après avoir salué l''Église, il descendit à Antioche.'),
  (44, 18, 23, 'Lorsqu''il eut passé quelque temps à Antioche, Paul se mit en route, et parcourut successivement la Galatie et la Phrygie, fortifiant tous les disciples.'),
  (44, 18, 24, 'Un Juif nommé Apollos, originaire d''Alexandrie, homme éloquent et versé dans les Écritures, vint à Éphèse.'),
  (44, 18, 25, 'Il était instruit dans la voie du Seigneur, et, fervent d''esprit, il annonçait et enseignait avec exactitude ce qui concerne Jésus, bien qu''il ne connût que le baptême de Jean.'),
  (44, 18, 26, 'Il se mit à parler librement dans la synagogue. Aquilas et Priscille, l''ayant entendu, le prirent avec eux, et lui exposèrent plus exactement la voie de Dieu.'),
  (44, 18, 27, 'Comme il voulait passer en Achaïe, les frères l''y encouragèrent, et écrivirent aux disciples de le bien recevoir. Quand il fut arrivé, il se rendit, par la grâce de Dieu, très utile à ceux qui avaient cru;'),
  (44, 18, 28, 'Car il réfutait vivement les Juifs en public, démontrant par les Écritures que Jésus est le Christ.'),
  (44, 19, 1, 'Pendant qu''Apollos était à Corinthe, Paul, après avoir parcouru les hautes provinces de l''Asie, arriva à Éphèse. Ayant rencontré quelques disciples,'),
  (44, 19, 2, 'il leur dit: Avez-vous reçu le Saint-Esprit, quand vous avez cru? Ils lui répondirent: Nous n''avons pas même entendu dire qu''il y ait un Saint-Esprit.'),
  (44, 19, 3, 'Il dit: De quel baptême avez-vous donc été baptisés? Et ils répondirent: Du baptême de Jean.'),
  (44, 19, 4, 'Alors Paul dit: Jean a baptisé du baptême de repentance, disant au peuple de croire en celui qui venait après lui, c''est-à-dire, en Jésus.'),
  (44, 19, 5, 'Sur ces paroles, ils furent baptisés au nom du Seigneur Jésus.'),
  (44, 19, 6, 'Lorsque Paul leur eut imposé les mains, le Saint-Esprit vint sur eux, et ils parlaient en langues et prophétisaient.'),
  (44, 19, 7, 'Ils étaient en tout environ douze hommes.'),
  (44, 19, 8, 'Ensuite Paul entra dans la synagogue, où il parla librement. Pendant trois mois, il discourut sur les choses qui concernent le royaume de Dieu, s''efforçant de persuader ceux qui l''écoutaient.'),
  (44, 19, 9, 'Mais, comme quelques-uns restaient endurcis et incrédules, décriant devant la multitude la voie du Seigneur, il se retira d''eux, sépara les disciples, et enseigna chaque jour dans l''école d''un nommé Tyrannus.'),
  (44, 19, 10, 'Cela dura deux ans, de sorte que tous ceux qui habitaient l''Asie, Juifs et Grecs, entendirent la parole du Seigneur.'),
  (44, 19, 11, 'Et Dieu faisait des miracles extraordinaires par les mains de Paul,'),
  (44, 19, 12, 'au point qu''on appliquait sur les malades des linges ou des mouchoirs qui avaient touché son corps, et les maladies les quittaient, et les esprits malins sortaient.'),
  (44, 19, 13, 'Quelques exorcistes juifs ambulants essayèrent d''invoquer sur ceux qui avaient des esprits malins le nom du Seigneur Jésus, en disant: Je vous conjure par Jésus que Paul prêche!'),
  (44, 19, 14, 'Ceux qui faisaient cela étaient sept fils de Scéva, Juif, l''un des principaux sacrificateurs.'),
  (44, 19, 15, 'L''esprit malin leur répondit: Je connais Jésus, et je sais qui est Paul; mais vous, qui êtes-vous?'),
  (44, 19, 16, 'Et l''homme dans lequel était l''esprit malin s''élança sur eux, se rendit maître de tous deux, et les maltraita de telle sorte qu''ils s''enfuirent de cette maison nus et blessés.'),
  (44, 19, 17, 'Cela fut connu de tous les Juifs et de tous les Grecs qui demeuraient à Éphèse, et la crainte s''empara d''eux tous, et le nom du Seigneur Jésus était glorifié.'),
  (44, 19, 18, 'Plusieurs de ceux qui avaient cru venaient confesser et déclarer ce qu''ils avaient fait.'),
  (44, 19, 19, 'Et un certain nombre de ceux qui avaient exercé les arts magiques, ayant apporté leurs livres, les brûlèrent devant tout le monde: on en estima la valeur à cinquante mille pièces d''argent.'),
  (44, 19, 20, 'C''est ainsi que la parole du Seigneur croissait en puissance et en force.'),
  (44, 19, 21, 'Après que ces choses se furent passées, Paul forma le projet d''aller à Jérusalem, en traversant la Macédoine et l''Achaïe. Quand j''aurai été là, se disait-il, il faut aussi que je voie Rome.'),
  (44, 19, 22, 'Il envoya en Macédoine deux de ses aides, Timothée et Éraste, et il resta lui-même quelque temps encore en Asie.'),
  (44, 19, 23, 'Il survint, à cette époque, un grand trouble au sujet de la voie du Seigneur.'),
  (44, 19, 24, 'Un nommé Démétrius, orfèvre, fabriquait en argent des temples de Diane, et procurait à ses ouvriers un gain considérable.'),
  (44, 19, 25, 'Il les rassembla, avec ceux du même métier, et dit: O hommes, vous savez que notre bien-être dépend de cette industrie;'),
  (44, 19, 26, 'et vous voyez et entendez que, non seulement à Éphèse, mais dans presque toute l''Asie, ce Paul a persuadé et détourné une foule de gens, en disant que les dieux faits de main d''homme ne sont pas des dieux.'),
  (44, 19, 27, 'Le danger qui en résulte, ce n''est pas seulement que notre industrie ne tombe en discrédit; c''est encore que le temple de la grande déesse Diane ne soit tenu pour rien, et même que la majesté de celle qui est révérée dans toute l''Asie et dans le monde entier ne soit réduite à néant.'),
  (44, 19, 28, 'Ces paroles les ayant remplis de colère, ils se mirent à crier: Grande est la Diane des Éphésiens!'),
  (44, 19, 29, 'Toute la ville fut dans la confusion. Ils se précipitèrent tous ensemble au théâtre, entraînant avec eux Gaïus et Aristarque, Macédoniens, compagnons de voyage de Paul.'),
  (44, 19, 30, 'Paul voulait se présenter devant le peuple, mais les disciples l''en empêchèrent;'),
  (44, 19, 31, 'quelques-uns même des Asiarques, qui étaient ses amis, envoyèrent vers lui, pour l''engager à ne pas se rendre au théâtre.'),
  (44, 19, 32, 'Les uns criaient d''une manière, les autres d''une autre, car le désordre régnait dans l''assemblée, et la plupart ne savaient pas pourquoi ils s''étaient réunis.'),
  (44, 19, 33, 'Alors on fit sortir de la foule Alexandre, que les Juifs poussaient en avant; et Alexandre, faisant signe de la main, voulait parler au peuple.'),
  (44, 19, 34, 'Mais quand ils reconnurent qu''il était Juif, tous d''une seule voix crièrent pendant près de deux heures: Grande est la Diane des Éphésiens!'),
  (44, 19, 35, 'Cependant le secrétaire, ayant apaisé la foule, dit: Hommes Éphésiens, quel est celui qui ignore que la ville d''Éphèse est la gardienne du temple de la grande Diane et de son simulacre tombé du ciel?'),
  (44, 19, 36, 'Cela étant incontestable, vous devez vous calmer, et ne rien faire avec précipitation.'),
  (44, 19, 37, 'Car vous avez amené ces hommes, qui ne sont coupables ni de sacrilège, ni de blasphème envers notre déesse.'),
  (44, 19, 38, 'Si donc Démétrius et ses ouvriers ont à se plaindre de quelqu''un, il y a des jours d''audience et des proconsuls; qu''ils s''appellent en justice les uns les autres.'),
  (44, 19, 39, 'Et si vous avez en vue d''autres objets, ils se régleront dans une assemblée légale.'),
  (44, 19, 40, 'Nous risquons, en effet, d''être accusés de sédition pour ce qui s''est passé aujourd''hui, puisqu''il n''existe aucun motif qui nous permette de justifier cet attroupement.'),
  (44, 19, 41, 'Après ces paroles, il congédia l''assemblée.'),
  (44, 20, 1, 'Lorsque le tumulte eut cessé, Paul réunit les disciples, et, après les avoir exhortés, prit congé d''eux, et partit pour aller en Macédoine.'),
  (44, 20, 2, 'Il parcourut cette contrée, en adressant aux disciples de nombreuses exhortations. Puis il se rendit en Grèce,'),
  (44, 20, 3, 'où il séjourna trois mois. Il était sur le point de s''embarquer pour la Syrie, quand les Juifs lui dressèrent des embûches. Alors il se décida à reprendre la route de la Macédoine.'),
  (44, 20, 4, 'Il avait pour l''accompagner jusqu''en Asie: Sopater de Bérée, fils de Pyrrhus, Aristarque et Second de Thessalonique, Gaïus de Derbe, Timothée, ainsi que Tychique et Trophime, originaires d''Asie.'),
  (44, 20, 5, 'Ceux-ci prirent les devants, et nous attendirent à Troas.'),
  (44, 20, 6, 'Pour nous, après les jours des pains sans levain, nous nous embarquâmes à Philippes, et, au bout de cinq jours, nous les rejoignîmes à Troas, où nous passâmes sept jours.'),
  (44, 20, 7, 'Le premier jour de la semaine, nous étions réunis pour rompre le pain. Paul, qui devait partir le lendemain, s''entretenait avec les disciples, et il prolongea son discours jusqu''à minuit.'),
  (44, 20, 8, 'Il y avait beaucoup de lampes dans la chambre haute où nous étions assemblés.'),
  (44, 20, 9, 'Or, un jeune homme nommé Eutychus, qui était assis sur la fenêtre, s''endormit profondément pendant le long discours de Paul; entraîné par le sommeil, il tomba du troisième étage en bas, et il fut relevé mort.'),
  (44, 20, 10, 'Mais Paul, étant descendu, se pencha sur lui et le prit dans ses bras, en disant: Ne vous troublez pas, car son âme est en lui.'),
  (44, 20, 11, 'Quand il fut remonté, il rompit le pain et mangea, et il parla longtemps encore jusqu''au jour. Après quoi il partit.'),
  (44, 20, 12, 'Le jeune homme fut ramené vivant, et ce fut le sujet d''une grande consolation.'),
  (44, 20, 13, 'Pour nous, nous précédâmes Paul sur le navire, et nous fîmes voile pour Assos, où nous étions convenus de le reprendre, parce qu''il devait faire la route à pied.'),
  (44, 20, 14, 'Lorsqu''il nous eut rejoints à Assos, nous le prîmes à bord, et nous allâmes à Mytilène.'),
  (44, 20, 15, 'De là, continuant par mer, nous arrivâmes le lendemain vis-à-vis de Chios. Le jour suivant, nous cinglâmes vers Samos, et le jour d''après nous vînmes à Milet.'),
  (44, 20, 16, 'Paul avait résolu de passer devant Éphèse sans s''y arrêter, afin de ne pas perdre de temps en Asie; car il se hâtait pour se trouver, si cela lui était possible, à Jérusalem le jour de la Pentecôte.'),
  (44, 20, 17, 'Cependant, de Milet Paul envoya chercher à Éphèse les anciens de l''Église.'),
  (44, 20, 18, 'Lorsqu''ils furent arrivés vers lui, il leur dit: Vous savez de quelle manière, depuis le premier jour où je suis entré en Asie, je me suis sans cesse conduit avec vous,'),
  (44, 20, 19, 'servant le Seigneur en toute humilité, avec larmes, et au milieu des épreuves que me suscitaient les embûches des Juifs.'),
  (44, 20, 20, 'Vous savez que je n''ai rien caché de ce qui vous était utile, et que je n''ai pas craint de vous prêcher et de vous enseigner publiquement et dans les maisons,'),
  (44, 20, 21, 'annonçant aux Juifs et aux Grecs la repentance envers Dieu et la foi en notre Seigneur Jésus-Christ.'),
  (44, 20, 22, 'Et maintenant voici, lié par l''Esprit, je vais à Jérusalem, ne sachant pas ce qui m''y arrivera;'),
  (44, 20, 23, 'seulement, de ville en ville, l''Esprit-Saint m''avertit que des liens et des tribulations m''attendent.'),
  (44, 20, 24, 'Mais je ne fais pour moi-même aucun cas de ma vie, comme si elle m''était précieuse, pourvu que j''accomplisse ma course avec joie, et le ministère que j''ai reçu du Seigneur Jésus, d''annoncer la bonne nouvelle de la grâce de Dieu.'),
  (44, 20, 25, 'Et maintenant voici, je sais que vous ne verrez plus mon visage, vous tous au milieu desquels j''ai passé en prêchant le royaume de Dieu.'),
  (44, 20, 26, 'C''est pourquoi je vous déclare aujourd''hui que je suis pur du sang de vous tous,'),
  (44, 20, 27, 'car je vous ai annoncé tout le conseil de Dieu, sans en rien cacher.'),
  (44, 20, 28, 'Prenez donc garde à vous-mêmes, et à tout le troupeau sur lequel le Saint-Esprit vous a établis évêques, pour paître l''Église du Seigneur, qu''il s''est acquise par son propre sang.'),
  (44, 20, 29, 'Je sais qu''il s''introduira parmi vous, après mon départ, des loups cruels qui n''épargneront pas le troupeau,'),
  (44, 20, 30, 'et qu''il s''élèvera du milieu de vous des hommes qui enseigneront des choses pernicieuses, pour entraîner les disciples après eux.'),
  (44, 20, 31, 'Veillez donc, vous souvenant que, durant trois années, je n''ai cessé nuit et jour d''exhorter avec larmes chacun de vous.'),
  (44, 20, 32, 'Et maintenant je vous recommande à Dieu et à la parole de sa grâce, à celui qui peut édifier et donner l''héritage avec tous les sanctifiés.'),
  (44, 20, 33, 'Je n''ai désiré ni l''argent, ni l''or, ni les vêtements de personne.'),
  (44, 20, 34, 'Vous savez vous-mêmes que ces mains ont pourvu à mes besoins et à ceux des personnes qui étaient avec moi.'),
  (44, 20, 35, 'Je vous ai montré de toutes manières que c''est en travaillant ainsi qu''il faut soutenir les faibles, et se rappeler les paroles du Seigneur, qui a dit lui-même: Il y a plus de bonheur à donner qu''à recevoir.'),
  (44, 20, 36, 'Après avoir ainsi parlé, il se mit à genoux, et il pria avec eux tous.'),
  (44, 20, 37, 'Et tous fondirent en larmes, et, se jetant au cou de Paul, ils l''embrassaient,'),
  (44, 20, 38, 'affligés surtout de ce qu''il avait dit qu''ils ne verraient plus son visage. Et ils l''accompagnèrent jusqu''au navire.'),
  (44, 21, 1, 'Nous nous embarquâmes, après nous être séparés d''eux, et nous allâmes directement à Cos, le lendemain à Rhodes, et de là à Patara.'),
  (44, 21, 2, 'Et ayant trouvé un navire qui faisait la traversée vers la Phénicie, nous montâmes et partîmes.'),
  (44, 21, 3, 'Quand nous fûmes en vue de l''île de Chypre, nous la laissâmes à gauche, poursuivant notre route du côté de la Syrie, et nous abordâmes à Tyr, où le bâtiment devait décharger sa cargaison.'),
  (44, 21, 4, 'Nous trouvâmes les disciples, et nous restâmes là sept jours. Les disciples, poussés par l''Esprit, disaient à Paul de ne pas monter à Jérusalem.'),
  (44, 21, 5, 'Mais, lorsque nous fûmes au terme des sept jours, nous nous acheminâmes pour partir, et tous nous accompagnèrent avec leurs femmes et leurs enfants jusque hors de la ville. Nous nous mîmes à genoux sur le rivage, et nous priâmes.'),
  (44, 21, 6, 'Puis, ayant pris congé les uns des autres, nous montâmes sur le navire, et ils retournèrent chez eux.'),
  (44, 21, 7, 'Achevant notre navigation, nous allâmes de Tyr à Ptolémaïs, où nous saluâmes les frères, et passâmes un jour avec eux.'),
  (44, 21, 8, 'Nous partîmes le lendemain, et nous arrivâmes à Césarée. Étant entrés dans la maison de Philippe l''évangéliste, qui était l''un des sept, nous logeâmes chez lui.'),
  (44, 21, 9, 'Il avait quatre filles vierges qui prophétisaient.'),
  (44, 21, 10, 'Comme nous étions là depuis plusieurs jours, un prophète, nommé Agabus, descendit de Judée,'),
  (44, 21, 11, 'et vint nous trouver. Il prit la ceinture de Paul, se lia les pieds et les mains, et dit: Voici ce que déclare le Saint-Esprit: L''homme à qui appartient cette ceinture, les Juifs le lieront de la même manière à Jérusalem, et le livreront entre les mains des païens.'),
  (44, 21, 12, 'Quand nous entendîmes cela, nous et ceux de l''endroit, nous priâmes Paul de ne pas monter à Jérusalem.'),
  (44, 21, 13, 'Alors il répondit: Que faites-vous, en pleurant et en me brisant le cœur? Je suis prêt, non seulement à être lié, mais encore à mourir à Jérusalem pour le nom du Seigneur Jésus.'),
  (44, 21, 14, 'Comme il ne se laissait pas persuader, nous n''insistâmes pas, et nous dîmes: Que la volonté du Seigneur se fasse!'),
  (44, 21, 15, 'Après ces jours-là, nous fîmes nos préparatifs, et nous montâmes à Jérusalem.'),
  (44, 21, 16, 'Quelques disciples de Césarée vinrent aussi avec nous, et nous conduisirent chez un nommé Mnason, de l''île de Chypre, ancien disciple, chez qui nous devions loger.'),
  (44, 21, 17, 'Lorsque nous arrivâmes à Jérusalem, les frères nous reçurent avec joie.'),
  (44, 21, 18, 'Le lendemain, Paul se rendit avec nous chez Jacques, et tous les anciens s''y réunirent.'),
  (44, 21, 19, 'Après les avoir salués, il raconta en détail ce que Dieu avait fait au milieu des païens par son ministère.'),
  (44, 21, 20, 'Quand ils l''eurent entendu, ils glorifièrent Dieu. Puis ils lui dirent: Tu vois, frère, combien de milliers de Juifs ont cru, et tous sont zélés pour la loi.'),
  (44, 21, 21, 'Or, ils ont appris que tu enseignes à tous les Juifs qui sont parmi les païens à renoncer à Moïse, leur disant de ne pas circoncire les enfants et de ne pas se conformer aux coutumes.'),
  (44, 21, 22, 'Que faire donc? Sans aucun doute la multitude se rassemblera, car on saura que tu es venu.'),
  (44, 21, 23, 'C''est pourquoi fais ce que nous allons te dire. Il y a parmi nous quatre hommes qui ont fait un vœu;'),
  (44, 21, 24, 'prends-les avec toi, purifie-toi avec eux, et pourvois à leur dépense, afin qu''ils se rasent la tête. Et ainsi tous sauront que ce qu''ils ont entendu dire sur ton compte est faux, mais que toi aussi tu te conduis en observateur de la loi.'),
  (44, 21, 25, 'A l''égard des païens qui ont cru, nous avons décidé et nous leur avons écrit qu''ils eussent à s''abstenir des viandes sacrifiées aux idoles, du sang, des animaux étouffés, et de l''impudicité.'),
  (44, 21, 26, 'Alors Paul prit ces hommes, se purifia, et entra le lendemain dans le temple avec eux, pour annoncer à quel jour la purification serait accomplie et l''offrande présentée pour chacun d''eux.'),
  (44, 21, 27, 'Sur la fin des sept jours, les Juifs d''Asie, ayant vu Paul dans le temple, soulevèrent toute la foule, et mirent la main sur lui,'),
  (44, 21, 28, 'en criant: Hommes Israélites, au secours! Voici l''homme qui prêche partout et à tout le monde contre le peuple, contre la loi et contre ce lieu; il a même introduit des Grecs dans le temple, et a profané ce saint lieu.'),
  (44, 21, 29, 'Car ils avaient vu auparavant Trophime d''Éphèse avec lui dans la ville, et ils croyaient que Paul l''avait fait entrer dans le temple.'),
  (44, 21, 30, 'Toute la ville fut émue, et le peuple accourut de toutes parts. Ils se saisirent de Paul, et le traînèrent hors du temple, dont les portes furent aussitôt fermées.'),
  (44, 21, 31, 'Comme ils cherchaient à le tuer, le bruit vint au tribun de la cohorte que tout Jérusalem était en confusion.'),
  (44, 21, 32, 'A l''instant il prit des soldats et des centeniers, et courut à eux. Voyant le tribun et les soldats, ils cessèrent de frapper Paul.'),
  (44, 21, 33, 'Alors le tribun s''approcha, se saisit de lui, et le fit lier de deux chaînes. Puis il demanda qui il était, et ce qu''il avait fait.'),
  (44, 21, 34, 'Mais dans la foule les uns criaient d''une manière, les autres d''une autre; ne pouvant donc rien apprendre de certain, à cause du tumulte, il ordonna de le mener dans la forteresse.'),
  (44, 21, 35, 'Lorsque Paul fut sur les degrés, il dut être porté par les soldats, à cause de la violence de la foule;'),
  (44, 21, 36, 'car la multitude du peuple suivait, en criant: Fais-le mourir!'),
  (44, 21, 37, 'Au moment d''être introduit dans la forteresse, Paul dit au tribun: M''est-il permis de te dire quelque chose? Le tribun répondit: Tu sais le grec?'),
  (44, 21, 38, 'Tu n''es donc pas cet Égyptien qui s''est révolté dernièrement, et qui a emmené dans le désert quatre mille brigands?'),
  (44, 21, 39, 'Je suis Juif, reprit Paul, de Tarse en Cilicie, citoyen d''une ville qui n''est pas sans importance. Permets-moi, je te prie, de parler au peuple.'),
  (44, 21, 40, 'Le tribun le lui ayant permis, Paul, debout sur les degrés, fit signe de la main au peuple. Un profond silence s''établit, et Paul, parlant en langue hébraïque, dit:'),
  (44, 22, 1, 'Hommes frères et pères, écoutez ce que j''ai maintenant à vous dire pour ma défense!'),
  (44, 22, 2, 'Lorsqu''ils entendirent qu''il leur parlait en langue hébraïque, ils redoublèrent de silence. Et Paul dit:'),
  (44, 22, 3, 'je suis Juif, né à Tarse en Cilicie; mais j''ai été élevé dans cette ville-ci, et instruit aux pieds de Gamaliel dans la connaissance exacte de la loi de nos pères, étant plein de zèle pour Dieu, comme vous l''êtes tous aujourd''hui.'),
  (44, 22, 4, 'J''ai persécuté à mort cette doctrine, liant et mettant en prison hommes et femmes.'),
  (44, 22, 5, 'Le souverain sacrificateur et tout le collège des anciens m''en sont témoins. J''ai même reçu d''eux des lettres pour les frères de Damas, où je me rendis afin d''amener liés à Jérusalem ceux qui se trouvaient là et de les faire punir.'),
  (44, 22, 6, 'Comme j''étais en chemin, et que j''approchais de Damas, tout à coup, vers midi, une grande lumière venant du ciel resplendit autour de moi.'),
  (44, 22, 7, 'Je tombai par terre, et j''entendis une voix qui me disait: Saul, Saul, pourquoi me persécutes-tu?'),
  (44, 22, 8, 'Je répondis: Qui es-tu, Seigneur? Et il me dit: Je suis Jésus de Nazareth, que tu persécutes.'),
  (44, 22, 9, 'Ceux qui étaient avec moi virent bien la lumière, mais ils n''entendirent pas la voix de celui qui parlait.'),
  (44, 22, 10, 'Alors je dis: Que ferai-je, Seigneur? Et le Seigneur me dit: Lève-toi, va à Damas, et là on te dira tout ce que tu dois faire.'),
  (44, 22, 11, 'Comme je ne voyais rien, à cause de l''éclat de cette lumière, ceux qui étaient avec moi me prirent par la main, et j''arrivai à Damas.'),
  (44, 22, 12, 'Or, un nommé Ananias, homme pieux selon la loi, et de qui tous les Juifs demeurant à Damas rendaient un bon témoignage,'),
  (44, 22, 13, 'vint se présenter à moi, et me dit: Saul, mon frère, recouvre la vue. Au même instant, je recouvrai la vue et je le regardai.'),
  (44, 22, 14, 'Il dit: Le Dieu de nos pères t''a destiné à connaître sa volonté, à voir le Juste, et à entendre les paroles de sa bouche;'),
  (44, 22, 15, 'car tu lui serviras de témoin, auprès de tous les hommes, des choses que tu as vues et entendues.'),
  (44, 22, 16, 'Et maintenant, que tardes-tu? Lève-toi, sois baptisé, et lavé de tes péchés, en invoquant le nom du Seigneur.'),
  (44, 22, 17, 'De retour à Jérusalem, comme je priais dans le temple, je fus ravi en extase,'),
  (44, 22, 18, 'et je vis le Seigneur qui me disait: Hâte-toi, et sors promptement de Jérusalem, parce qu''ils ne recevront pas ton témoignage sur moi.'),
  (44, 22, 19, 'Et je dis: Seigneur, ils savent eux-mêmes que je faisais mettre en prison et battre de verges dans les synagogues ceux qui croyaient en toi,'),
  (44, 22, 20, 'et que, lorsqu''on répandit le sang d''Étienne, ton témoin, j''étais moi-même présent, joignant mon approbation à celle des autres, et gardant les vêtements de ceux qui le faisaient mourir.'),
  (44, 22, 21, 'Alors il me dit: Va, je t''enverrai au loin vers les nations…'),
  (44, 22, 22, 'Ils l''écoutèrent jusqu''à cette parole. Mais alors ils élevèrent la voix, disant: Ote de la terre un pareil homme! Il n''est pas digne de vivre.'),
  (44, 22, 23, 'Et ils poussaient des cris, jetaient leurs vêtements, lançaient de la poussière en l''air.'),
  (44, 22, 24, 'Le tribun commanda de faire entrer Paul dans la forteresse, et de lui donner la question par le fouet, afin de savoir pour quel motif ils criaient ainsi contre lui.'),
  (44, 22, 25, 'Lorsqu''on l''eut exposé au fouet, Paul dit au centenier qui était présent: Vous est-il permis de battre de verges un citoyen romain, qui n''est pas même condamné?'),
  (44, 22, 26, 'A ces mots, le centenier alla vers le tribun pour l''avertir, disant: Que vas-tu faire? Cet homme est Romain.'),
  (44, 22, 27, 'Et le tribun, étant venu, dit à Paul: Dis-moi, es-tu Romain? Oui, répondit-il.'),
  (44, 22, 28, 'Le tribun reprit: C''est avec beaucoup d''argent que j''ai acquis ce droit de citoyen. Et moi, dit Paul, je l''ai par ma naissance.'),
  (44, 22, 29, 'Aussitôt ceux qui devaient lui donner la question se retirèrent, et le tribun, voyant que Paul était Romain, fut dans la crainte parce qu''il l''avait fait lier.'),
  (44, 22, 30, 'Le lendemain, voulant savoir avec certitude de quoi les Juifs l''accusaient, le tribun lui fit ôter ses liens, et donna l''ordre aux principaux sacrificateurs et à tout le sanhédrin de se réunir; puis, faisant descendre Paul, il le plaça au milieu d''eux.'),
  (44, 23, 1, 'Paul, les regards fixés sur le sanhédrin, dit: Hommes frères, c''est en toute bonne conscience que je me suis conduit jusqu''à ce jour devant Dieu…'),
  (44, 23, 2, 'Le souverain sacrificateur Ananias ordonna à ceux qui étaient près de lui de le frapper sur la bouche.'),
  (44, 23, 3, 'Alors Paul lui dit: Dieu te frappera, muraille blanchie! Tu es assis pour me juger selon la loi, et tu violes la loi en ordonnant qu''on me frappe!'),
  (44, 23, 4, 'Ceux qui étaient près de lui dirent: Tu insultes le souverain sacrificateur de Dieu!'),
  (44, 23, 5, 'Et Paul dit: Je ne savais pas, frères, que ce fût le souverain sacrificateur; car il est écrit: Tu ne parleras pas mal du chef de ton peuple.'),
  (44, 23, 6, 'Paul, sachant qu''une partie de l''assemblée était composée de sadducéens et l''autre de pharisiens, s''écria dans le sanhédrin: Hommes frères, je suis pharisien, fils de pharisiens; c''est à cause de l''espérance et de la résurrection des morts que je suis mis en jugement.'),
  (44, 23, 7, 'Quand il eut dit cela, il s''éleva une discussion entre les pharisiens et les sadducéens, et l''assemblée se divisa.'),
  (44, 23, 8, 'Car les sadducéens disent qu''il n''y a point de résurrection, et qu''il n''existe ni ange ni esprit, tandis que les pharisiens affirment les deux choses.'),
  (44, 23, 9, 'Il y eut une grande clameur, et quelques scribes du parti des pharisiens, s''étant levés, engagèrent un vif débat, et dirent: Nous ne trouvons aucun mal en cet homme; peut-être un esprit ou un ange lui a-t-il parlé.'),
  (44, 23, 10, 'Comme la discorde allait croissant, le tribun craignant que Paul ne fût mis en pièces par ces gens, fit descendre les soldats pour l''enlever du milieu d''eux et le conduire à la forteresse.'),
  (44, 23, 11, 'La nuit suivante, le Seigneur apparut à Paul, et dit: Prends courage; car, de même que tu as rendu témoignage de moi dans Jérusalem, il faut aussi que tu rendes témoignage dans Rome.'),
  (44, 23, 12, 'Quand le jour fut venu, les Juifs formèrent un complot, et firent des imprécations contre eux-mêmes, en disant qu''ils s''abstiendraient de manger et de boire jusqu''à ce qu''ils eussent tué Paul.'),
  (44, 23, 13, 'Ceux qui formèrent ce complot étaient plus de quarante,'),
  (44, 23, 14, 'et ils allèrent trouver les principaux sacrificateurs et les anciens, auxquels ils dirent: Nous nous sommes engagés, avec des imprécations contre nous-mêmes, à ne rien manger jusqu''à ce que nous ayons tué Paul.'),
  (44, 23, 15, 'Vous donc, maintenant, adressez-vous avec le sanhédrin au tribun, pour qu''il l''amène devant vous, comme si vous vouliez examiner sa cause plus exactement; et nous, avant qu''il approche, nous sommes prêts à le tuer.'),
  (44, 23, 16, 'Le fils de la sœur de Paul, ayant eu connaissance du guet-apens, alla dans la forteresse en informer Paul.'),
  (44, 23, 17, 'Paul appela l''un des centeniers, et dit: Mène ce jeune homme vers le tribun, car il a quelque chose à lui rapporter.'),
  (44, 23, 18, 'Le centenier prit le jeune homme avec lui, le conduisit vers le tribun, et dit: Le prisonnier Paul m''a appelé, et il m''a prié de t''amener ce jeune homme, qui a quelque chose à te dire.'),
  (44, 23, 19, 'Le tribun, prenant le jeune homme par la main, et se retirant à l''écart, lui demanda: Qu''as-tu à m''annoncer?'),
  (44, 23, 20, 'Il répondit: Les Juifs sont convenus de te prier d''amener Paul demain devant le sanhédrin, comme si tu devais t''enquérir de lui plus exactement.'),
  (44, 23, 21, 'Ne les écoute pas, car plus de quarante d''entre eux lui dressent un guet-apens, et se sont engagés, avec des imprécations contre eux-mêmes, à ne rien manger ni boire jusqu''à ce qu''ils l''aient tué; maintenant ils sont prêts, et n''attendent que ton consentement.'),
  (44, 23, 22, 'Le tribun renvoya le jeune homme, après lui avoir recommandé de ne parler à personne de ce rapport qu''il lui avait fait.'),
  (44, 23, 23, 'Ensuite il appela deux des centeniers, et dit: Tenez prêts, dès la troisième heure de la nuit, deux cents soldats, soixante-dix cavaliers et deux cents archers, pour aller jusqu''à Césarée.'),
  (44, 23, 24, 'Qu''il y ait aussi des montures pour Paul, afin qu''on le mène sain et sauf au gouverneur Félix.'),
  (44, 23, 25, 'Il écrivit une lettre ainsi conçue:'),
  (44, 23, 26, 'Claude Lysias au très excellent gouverneur Félix, salut!'),
  (44, 23, 27, 'Cet homme, dont les Juifs s''étaient saisis, allait être tué par eux, lorsque je survins avec des soldats et le leur enlevai, ayant appris qu''il était Romain.'),
  (44, 23, 28, 'Voulant connaître le motif pour lequel ils l''accusaient, je l''amenai devant leur sanhédrin.'),
  (44, 23, 29, 'J''ai trouvé qu''il était accusé au sujet de questions relatives à leur loi, mais qu''il n''avait commis aucun crime qui mérite la mort ou la prison.'),
  (44, 23, 30, 'Informé que les Juifs lui dressaient des embûches, je te l''ai aussitôt envoyé, en faisant savoir à ses accusateurs qu''ils eussent à s''adresser eux-mêmes à toi. Adieu.'),
  (44, 23, 31, 'Les soldats, selon l''ordre qu''ils avaient reçu, prirent Paul, et le conduisirent pendant la nuit jusqu''à Antipatris.'),
  (44, 23, 32, 'Le lendemain, laissant les cavaliers poursuivre la route avec lui, ils retournèrent à la forteresse.'),
  (44, 23, 33, 'Arrivés à Césarée, les cavaliers remirent la lettre au gouverneur, et lui présentèrent Paul.'),
  (44, 23, 34, 'Le gouverneur, après avoir lu la lettre, demanda de quelle province était Paul. Ayant appris qu''il était de la Cilicie:'),
  (44, 23, 35, 'Je t''entendrai, dit-il, quand tes accusateurs seront venus. Et il ordonna qu''on le gardât dans le prétoire d''Hérode.'),
  (44, 24, 1, 'Cinq jours après, arriva le souverain sacrificateur Ananias, avec des anciens et un orateur nommé Tertulle. Ils portèrent plainte au gouverneur contre Paul.'),
  (44, 24, 2, 'Paul fut appelé, et Tertulle se mit à l''accuser, en ces termes:'),
  (44, 24, 3, 'Très excellent Félix, tu nous fais jouir d''une paix profonde, et cette nation a obtenu de salutaires réformes par tes soins prévoyants; c''est ce que nous reconnaissons en tout et partout avec une entière gratitude.'),
  (44, 24, 4, 'Mais, pour ne pas te retenir davantage, je te prie d''écouter, dans ta bonté, ce que nous avons à dire en peu de mots.'),
  (44, 24, 5, 'Nous avons trouvé cet homme, qui est une peste, qui excite des divisions parmi tous les Juifs du monde, qui est chef de la secte des Nazaréens,'),
  (44, 24, 6, 'et qui même a tenté de profaner le temple. Et nous l''avons arrêté. Nous avons voulu le juger selon notre loi;'),
  (44, 24, 7, 'mais le tribun Lysias étant survenu, l''a arraché de nos mains avec une grande violence,'),
  (44, 24, 8, 'en ordonnant à ses accusateurs de venir devant toi. Tu pourras toi-même, en l''interrogeant, apprendre de lui tout ce dont nous l''accusons.'),
  (44, 24, 9, 'Les Juifs se joignirent à l''accusation, soutenant que les choses étaient ainsi.'),
  (44, 24, 10, 'Après que le gouverneur lui eut fait signe de parler, Paul répondit: Sachant que, depuis plusieurs années, tu es juge de cette nation, c''est avec confiance que je prends la parole pour défendre ma cause.'),
  (44, 24, 11, 'Il n''y a pas plus de douze jours, tu peux t''en assurer, que je suis monté à Jérusalem pour adorer.'),
  (44, 24, 12, 'On ne m''a trouvé ni dans le temple, ni dans les synagogues, ni dans la ville, disputant avec quelqu''un, ou provoquant un rassemblement séditieux de la foule.'),
  (44, 24, 13, 'Et ils ne sauraient prouver ce dont ils m''accusent maintenant.'),
  (44, 24, 14, 'Je t''avoue bien que je sers le Dieu de mes pères selon la voie qu''ils appellent une secte, croyant tout ce qui est écrit dans la loi et dans les prophètes,'),
  (44, 24, 15, 'et ayant en Dieu cette espérance, comme ils l''ont eux-mêmes, qu''il y aura une résurrection des justes et des injustes.'),
  (44, 24, 16, 'C''est pourquoi je m''efforce d''avoir constamment une conscience sans reproche devant Dieu et devant les hommes.'),
  (44, 24, 17, 'Après une absence de plusieurs années, je suis venu pour faire des aumônes à ma nation, et pour présenter des offrandes.'),
  (44, 24, 18, 'C''est alors que quelques Juifs d''Asie m''ont trouvé purifié dans le temple, sans attroupement ni tumulte.'),
  (44, 24, 19, 'C''était à eux de paraître en ta présence et de se porter accusateurs, s''ils avaient quelque chose contre moi.'),
  (44, 24, 20, 'Ou bien, que ceux-ci déclarent de quel crime ils m''ont trouvé coupable, lorsque j''ai comparu devant le sanhédrin,'),
  (44, 24, 21, 'moins que ce ne soit uniquement de ce cri que j''ai fait entendre au milieu d''eux: C''est à cause de la résurrection des morts que je suis aujourd''hui mis en jugement devant vous.'),
  (44, 24, 22, 'Félix, qui savait assez exactement ce qui concernait cette doctrine, les ajourna, en disant: Quand le tribun Lysias sera venu, j''examinerai votre affaire.'),
  (44, 24, 23, 'Et il donna l''ordre au centenier de garder Paul, en lui laissant une certaine liberté, et en n''empêchant aucun des siens de lui rendre des services.'),
  (44, 24, 24, 'Quelques jours après, Félix vint avec Drusille, sa femme, qui était Juive, et il fit appeler Paul. Il l''entendit sur la foi en Christ.'),
  (44, 24, 25, 'Mais, comme Paul discourait sur la justice, sur la tempérance, et sur le jugement à venir, Félix, effrayé, dit: Pour le moment retire-toi; quand j''en trouverai l''occasion, je te rappellerai.'),
  (44, 24, 26, 'Il espérait en même temps que Paul lui donnerait de l''argent; aussi l''envoyait-il chercher assez fréquemment, pour s''entretenir avec lui.'),
  (44, 24, 27, 'Deux ans s''écoulèrent ainsi, et Félix eut pour successeur Porcius Festus. Dans le désir de plaire aux Juifs, Félix laissa Paul en prison.'),
  (44, 25, 1, 'Festus, étant arrivé dans la province, monta trois jours après de Césarée à Jérusalem.'),
  (44, 25, 2, 'Les principaux sacrificateurs et les principaux d''entre les Juifs lui portèrent plainte contre Paul. Ils firent des instances auprès de lui, et,'),
  (44, 25, 3, 'dans des vues hostiles, lui demandèrent comme une faveur qu''il le fît venir à Jérusalem. Ils préparaient un guet-apens, pour le tuer en chemin.'),
  (44, 25, 4, 'Festus répondit que Paul était gardé à Césarée, et que lui-même devait partir sous peu.'),
  (44, 25, 5, 'Que les principaux d''entre vous descendent avec moi, dit-il, et s''il y a quelque chose de coupable en cet homme, qu''ils l''accusent.'),
  (44, 25, 6, 'Festus ne passa que huit à dix jours parmi eux, puis il descendit à Césarée. Le lendemain, s''étant assis sur son tribunal, il donna l''ordre qu''on amenât Paul.'),
  (44, 25, 7, 'Quand il fut arrivé, les Juifs qui étaient venus de Jérusalem l''entourèrent, et portèrent contre lui de nombreuses et graves accusations, qu''ils n''étaient pas en état de prouver.'),
  (44, 25, 8, 'Paul entreprit sa défense, en disant: Je n''ai rien fait de coupable, ni contre la loi des Juifs, ni contre le temple, ni contre César.'),
  (44, 25, 9, 'Festus, désirant plaire aux Juifs, répondit à Paul: Veux-tu monter à Jérusalem, et y être jugé sur ces choses en ma présence?'),
  (44, 25, 10, 'Paul dit: C''est devant le tribunal de César que je comparais, c''est là que je dois être jugé. Je n''ai fait aucun tort aux Juifs, comme tu le sais fort bien.'),
  (44, 25, 11, 'Si j''ai commis quelque injustice, ou quelque crime digne de mort, je ne refuse pas de mourir; mais, si les choses dont ils m''accusent sont fausses, personne n''a le droit de me livrer à eux. J''en appelle à César.'),
  (44, 25, 12, 'Alors Festus, après avoir délibéré avec le conseil, répondit: Tu en as appelé à César; tu iras devant César.'),
  (44, 25, 13, 'Quelques jours après, le roi Agrippa et Bérénice arrivèrent à Césarée, pour saluer Festus.'),
  (44, 25, 14, 'Comme ils passèrent là plusieurs jours, Festus exposa au roi l''affaire de Paul, et dit: Félix a laissé prisonnier un homme'),
  (44, 25, 15, 'contre lequel, lorsque j''étais à Jérusalem, les principaux sacrificateurs et les anciens des Juifs ont porté plainte, en demandant sa condamnation.'),
  (44, 25, 16, 'Je leur ai répondu que ce n''est pas la coutume des Romains de livrer un homme avant que l''inculpé ait été mis en présence de ses accusateurs, et qu''il ait eu la faculté de se défendre sur les choses dont on l''accuse.'),
  (44, 25, 17, 'Ils sont donc venus ici, et, sans différer, je m''assis le lendemain sur mon tribunal, et je donnai l''ordre qu''on amenât cet homme.'),
  (44, 25, 18, 'Les accusateurs, s''étant présentés, ne lui imputèrent rien de ce que je supposais;'),
  (44, 25, 19, 'ils avaient avec lui des discussions relatives à leur religion particulière, et à un certain Jésus qui est mort, et que Paul affirmait être vivant.'),
  (44, 25, 20, 'Ne sachant quel parti prendre dans ce débat, je lui demandai s''il voulait aller à Jérusalem, et y être jugé sur ces choses.'),
  (44, 25, 21, 'Mais Paul en ayant appelé, pour que sa cause fût réservée à la connaissance de l''empereur, j''ai ordonné qu''on le gardât jusqu''à ce que je l''envoyasse à César.'),
  (44, 25, 22, 'Agrippa dit à Festus: Je voudrais aussi entendre cet homme. Demain, répondit Festus, tu l''entendras.'),
  (44, 25, 23, 'Le lendemain donc, Agrippa et Bérénice vinrent en grande pompe, et entrèrent dans le lieu de l''audience avec les tribuns et les principaux de la ville. Sur l''ordre de Festus, Paul fut amené.'),
  (44, 25, 24, 'Alors Festus dit: Roi Agrippa, et vous tous qui êtes présents avec nous, vous voyez cet homme au sujet duquel toute la multitude des Juifs s''est adressée à moi, soit à Jérusalem, soit ici, en s''écriant qu''il ne devait plus vivre.'),
  (44, 25, 25, 'Pour moi, ayant reconnu qu''il n''a rien fait qui mérite la mort, et lui-même en ayant appelé à l''empereur, j''ai résolu de le faire partir.'),
  (44, 25, 26, 'Je n''ai rien de certain à écrire à l''empereur sur son compte; c''est pourquoi je l''ai fait paraître devant vous, et surtout devant toi, roi Agrippa, afin de savoir qu''écrire, après qu''il aura été examiné.'),
  (44, 25, 27, 'Car il me semble absurde d''envoyer un prisonnier sans indiquer de quoi on l''accuse.'),
  (44, 26, 1, 'Agrippa dit à Paul: Il t''est permis de parler pour ta défense. Et Paul, ayant étendu la main, se justifia en ces termes:'),
  (44, 26, 2, 'Je m''estime heureux, roi Agrippa, d''avoir aujourd''hui à me justifier devant toi de toutes les choses dont je suis accusé par les Juifs,'),
  (44, 26, 3, 'car tu connais parfaitement leurs coutumes et leurs discussions. Je te prie donc de m''écouter avec patience.'),
  (44, 26, 4, 'Ma vie, dès les premiers temps de ma jeunesse, est connue de tous les Juifs, puisqu''elle s''est passée à Jérusalem, au milieu de ma nation.'),
  (44, 26, 5, 'Ils savent depuis longtemps, s''ils veulent le déclarer, que j''ai vécu pharisien, selon la secte la plus rigide de notre religion.'),
  (44, 26, 6, 'Et maintenant, je suis mis en jugement parce que j''espère l''accomplissement de la promesse que Dieu a faite à nos pères,'),
  (44, 26, 7, 'et à laquelle aspirent nos douze tribus, qui servent Dieu continuellement nuit et jour. C''est pour cette espérance, ô roi, que je suis accusé par des Juifs!'),
  (44, 26, 8, 'Quoi! vous semble-t-il incroyable que Dieu ressuscite les morts?'),
  (44, 26, 9, 'Pour moi, j''avais cru devoir agir vigoureusement contre le nom de Jésus de Nazareth.'),
  (44, 26, 10, 'C''est ce que j''ai fait à Jérusalem. J''ai jeté en prison plusieurs des saints, ayant reçu ce pouvoir des principaux sacrificateurs, et, quand on les mettait à mort, je joignais mon suffrage à celui des autres.'),
  (44, 26, 11, 'je les ai souvent châtiés dans toutes les synagogues, et je les forçais à blasphémer. Dans mes excès de fureur contre eux, je les persécutais même jusque dans les villes étrangères.'),
  (44, 26, 12, 'C''est dans ce but que je me rendis à Damas, avec l''autorisation et la permission des principaux sacrificateurs.'),
  (44, 26, 13, 'Vers le milieu du jour, ô roi, je vis en chemin resplendir autour de moi et de mes compagnons une lumière venant du ciel, et dont l''éclat surpassait celui du soleil.'),
  (44, 26, 14, 'Nous tombâmes tous par terre, et j''entendis une voix qui me disait en langue hébraïque: Saul, Saul, pourquoi me persécutes-tu? Il te serait dur de regimber contre les aiguillons.'),
  (44, 26, 15, 'Je répondis: Qui es-tu, Seigneur? Et le Seigneur dit: Je suis Jésus que tu persécutes.'),
  (44, 26, 16, 'Mais lève-toi, et tiens-toi sur tes pieds; car je te suis apparu pour t''établir ministre et témoin des choses que tu as vues et de celles pour lesquelles je t''apparaîtrai.'),
  (44, 26, 17, 'Je t''ai choisi du milieu de ce peuple et du milieu des païens, vers qui je t''envoie,'),
  (44, 26, 18, 'afin que tu leur ouvres les yeux, pour qu''ils passent des ténèbres à la lumière et de la puissance de Satan à Dieu, pour qu''ils reçoivent, par la foi en moi, le pardon des péchés et l''héritage avec les sanctifiés.'),
  (44, 26, 19, 'En conséquence, roi Agrippa, je n''ai point résisté à la vision céleste:'),
  (44, 26, 20, 'à ceux de Damas d''abord, puis à Jérusalem, dans toute la Judée, et chez les païens, j''ai prêché la repentance et la conversion à Dieu, avec la pratique d''œuvres dignes de la repentance.'),
  (44, 26, 21, 'Voilà pourquoi les Juifs se sont saisis de moi dans le temple, et ont tâché de me faire périr.'),
  (44, 26, 22, 'Mais, grâce au secours de Dieu, j''ai subsisté jusqu''à ce jour, rendant témoignage devant les petits et les grands, sans m''écarter en rien de ce que les prophètes et Moïse ont déclaré devoir arriver,'),
  (44, 26, 23, 'savoir que le Christ souffrirait, et que, ressuscité le premier d''entre les morts, il annoncerait la lumière au peuple et aux nations.'),
  (44, 26, 24, 'Comme il parlait ainsi pour sa justification, Festus dit à haute voix: Tu es fou, Paul! Ton grand savoir te fait déraisonner.'),
  (44, 26, 25, 'Je ne suis point fou, très excellent Festus, répliqua Paul; ce sont, au contraire, des paroles de vérité et de bon sens que je prononce.'),
  (44, 26, 26, 'Le roi est instruit de ces choses, et je lui en parle librement; car je suis persuadé qu''il n''en ignore aucune, puisque ce n''est pas en cachette qu''elles se sont passées.'),
  (44, 26, 27, 'Crois-tu aux prophètes, roi Agrippa?… Je sais que tu y crois.'),
  (44, 26, 28, 'Et Agrippa dit à Paul: Tu vas bientôt me persuader de devenir chrétien!'),
  (44, 26, 29, 'Paul répondit: Que ce soit bientôt ou que ce soit tard, plaise à Dieu que non seulement toi, mais encore tous ceux qui m''écoutent aujourd''hui, vous deveniez tels que je suis, à l''exception de ces liens!'),
  (44, 26, 30, 'Le roi, le gouverneur, Bérénice, et tous ceux qui étaient assis avec eux se levèrent,'),
  (44, 26, 31, 'et, en se retirant, ils se disaient les uns aux autres: Cet homme n''a rien fait qui mérite la mort ou la prison.'),
  (44, 26, 32, 'Et Agrippa dit à Festus: Cet homme pouvait être relâché, s''il n''en eût pas appelé à César.'),
  (44, 27, 1, 'Lorsqu''il fut décidé que nous nous embarquerions pour l''Italie, on remit Paul et quelques autres prisonniers à un centenier de la cohorte Auguste, nommé Julius.'),
  (44, 27, 2, 'Nous montâmes sur un navire d''Adramytte, qui devait côtoyer l''Asie, et nous partîmes, ayant avec nous Aristarque, Macédonien de Thessalonique.'),
  (44, 27, 3, 'Le jour suivant, nous abordâmes à Sidon; et Julius, qui traitait Paul avec bienveillance, lui permit d''aller chez ses amis et de recevoir leurs soins.'),
  (44, 27, 4, 'Partis de là, nous longeâmes l''île de Chypre, parce que les vents étaient contraires.'),
  (44, 27, 5, 'Après avoir traversé la mer qui baigne la Cilicie et la Pamphylie, nous arrivâmes à Myra en Lycie.'),
  (44, 27, 6, 'Et là, le centenier, ayant trouvé un navire d''Alexandrie qui allait en Italie, nous y fit monter.'),
  (44, 27, 7, 'Pendant plusieurs jours nous naviguâmes lentement, et ce ne fut pas sans difficulté que nous atteignîmes la hauteur de Cnide, où le vent ne nous permit pas d''aborder. Nous passâmes au-dessous de l''île de Crète, du côté de Salmone.'),
  (44, 27, 8, 'Nous la côtoyâmes avec peine, et nous arrivâmes à un lieu nommé Beaux Ports, près duquel était la ville de Lasée.'),
  (44, 27, 9, 'Un temps assez long s''était écoulé, et la navigation devenait dangereuse, car l''époque même du jeûne était déjà passée. C''est pourquoi Paul avertit'),
  (44, 27, 10, 'les autres, en disant: O hommes, je vois que la navigation ne se fera pas sans péril et sans beaucoup de dommage, non seulement pour la cargaison et pour le navire, mais encore pour nos personnes.'),
  (44, 27, 11, 'Le centenier écouta le pilote et le patron du navire plutôt que les paroles de Paul.'),
  (44, 27, 12, 'Et comme le port n''était pas bon pour hiverner, la plupart furent d''avis de le quitter pour tâcher d''atteindre Phénix, port de Crète qui regarde le sud-ouest et le nord-ouest, afin d''y passer l''hiver.'),
  (44, 27, 13, 'Un léger vent du sud vint à souffler, et, se croyant maîtres de leur dessein, ils levèrent l''ancre et côtoyèrent de près l''île de Crète.'),
  (44, 27, 14, 'Mais bientôt un vent impétueux, qu''on appelle Euraquilon, se déchaîna sur l''île.'),
  (44, 27, 15, 'Le navire fut entraîné, sans pouvoir lutter contre le vent, et nous nous laissâmes aller à la dérive.'),
  (44, 27, 16, 'Nous passâmes au-dessous d''une petite île nommée Clauda, et nous eûmes de la peine à nous rendre maîtres de la chaloupe;'),
  (44, 27, 17, 'après l''avoir hissée, on se servit des moyens de secours pour ceindre le navire, et, dans la crainte de tomber sur la Syrte, on abaissa les voiles. C''est ainsi qu''on se laissa emporter par le vent.'),
  (44, 27, 18, 'Comme nous étions violemment battus par la tempête, le lendemain on jeta la cargaison à la mer,'),
  (44, 27, 19, 'et le troisième jour nous y lançâmes de nos propres mains les agrès du navire.'),
  (44, 27, 20, 'Le soleil et les étoiles ne parurent pas pendant plusieurs jours, et la tempête était si forte que nous perdîmes enfin toute espérance de nous sauver.'),
  (44, 27, 21, 'On n''avait pas mangé depuis longtemps. Alors Paul, se tenant au milieu d''eux, leur dit: O hommes, il fallait m''écouter et ne pas partir de Crète, afin d''éviter ce péril et ce dommage.'),
  (44, 27, 22, 'Maintenant je vous exhorte à prendre courage; car aucun de vous ne périra, et il n''y aura de perte que celle du navire.'),
  (44, 27, 23, 'Un ange du Dieu à qui j''appartiens et que je sers m''est apparu cette nuit,'),
  (44, 27, 24, 'et m''a dit: Paul, ne crains point; il faut que tu comparaisses devant César, et voici, Dieu t''a donné tous ceux qui naviguent avec toi.'),
  (44, 27, 25, 'C''est pourquoi, ô hommes, rassurez-vous, car j''ai cette confiance en Dieu qu''il en sera comme il m''a été dit.'),
  (44, 27, 26, 'Mais nous devons échouer sur une île.'),
  (44, 27, 27, 'La quatorzième nuit, tandis que nous étions ballottés sur l''Adriatique, les matelots, vers le milieu de la nuit, soupçonnèrent qu''on approchait de quelque terre.'),
  (44, 27, 28, 'Ayant jeté la sonde, ils trouvèrent vingt brasses; un peu plus loin, ils la jetèrent de nouveau, et trouvèrent quinze brasses.'),
  (44, 27, 29, 'Dans la crainte de heurter contre des écueils, ils jetèrent quatre ancres de la poupe, et attendirent le jour avec impatience.'),
  (44, 27, 30, 'Mais, comme les matelots cherchaient à s''échapper du navire, et mettaient la chaloupe à la mer sous prétexte de jeter les ancres de la proue,'),
  (44, 27, 31, 'Paul dit au centenier et aux soldats: Si ces hommes ne restent pas dans le navire, vous ne pouvez être sauvés.'),
  (44, 27, 32, 'Alors les soldats coupèrent les cordes de la chaloupe, et la laissèrent tomber.'),
  (44, 27, 33, 'Avant que le jour parût, Paul exhorta tout le monde à prendre de la nourriture, disant: C''est aujourd''hui le quatorzième jour que vous êtes dans l''attente et que vous persistez à vous abstenir de manger.'),
  (44, 27, 34, 'Je vous invite donc à prendre de la nourriture, car cela est nécessaire pour votre salut, et il ne se perdra pas un cheveu de la tête d''aucun de vous.'),
  (44, 27, 35, 'Ayant ainsi parlé, il prit du pain, et, après avoir rendu grâces à Dieu devant tous, il le rompit, et se mit à manger.'),
  (44, 27, 36, 'Et tous, reprenant courage, mangèrent aussi.'),
  (44, 27, 37, 'Nous étions, dans le navire, deux cent soixante-seize personnes en tout.'),
  (44, 27, 38, 'Quand ils eurent mangé suffisamment, ils allégèrent le navire en jetant le blé à la mer.'),
  (44, 27, 39, 'Lorsque le jour fut venu, ils ne reconnurent point la terre; mais, ayant aperçu un golfe avec une plage, ils résolurent d''y pousser le navire, s''ils le pouvaient.'),
  (44, 27, 40, 'Ils délièrent les ancres pour les laisser aller dans la mer, et ils relâchèrent en même temps les attaches des gouvernails; puis ils mirent au vent la voile d''artimon, et se dirigèrent vers le rivage.'),
  (44, 27, 41, 'Mais ils rencontrèrent une langue de terre, où ils firent échouer le navire; et la proue, s''étant engagée, resta immobile, tandis que la poupe se brisait par la violence des vagues.'),
  (44, 27, 42, 'Les soldats furent d''avis de tuer les prisonniers, de peur que quelqu''un d''eux ne s''échappât à la nage.'),
  (44, 27, 43, 'Mais le centenier, qui voulait sauver Paul, les empêcha d''exécuter ce dessein. Il ordonna à ceux qui savaient nager de se jeter les premiers dans l''eau pour gagner la terre,'),
  (44, 27, 44, 'et aux autres de se mettre sur des planches ou sur des débris du navire. Et ainsi tous parvinrent à terre sains et saufs.'),
  (44, 28, 1, 'Après nous être sauvés, nous reconnûmes que l''île s''appelait Malte.'),
  (44, 28, 2, 'Les barbares nous témoignèrent une bienveillance peu commune; ils nous recueillirent tous auprès d''un grand feu, qu''ils avaient allumé parce que la pluie tombait et qu''il faisait grand froid.'),
  (44, 28, 3, 'Paul ayant ramassé un tas de broussailles et l''ayant mis au feu, une vipère en sortit par l''effet de la chaleur et s''attacha à sa main.'),
  (44, 28, 4, 'Quand les barbares virent l''animal suspendu à sa main, ils se dirent les uns aux autres: Assurément cet homme est un meurtrier, puisque la Justice n''a pas voulu le laisser vivre, après qu''il a été sauvé de la mer.'),
  (44, 28, 5, 'Paul secoua l''animal dans le feu, et ne ressentit aucun mal.'),
  (44, 28, 6, 'Ces gens s''attendaient à le voir enfler ou tomber mort subitement; mais, après avoir longtemps attendu, voyant qu''il ne lui arrivait aucun mal, ils changèrent d''avis et dirent que c''était un dieu.'),
  (44, 28, 7, 'Il y avait, dans les environs, des terres appartenant au principal personnage de l''île, nommé Publius, qui nous reçut et nous logea pendant trois jours de la manière la plus amicale.'),
  (44, 28, 8, 'Le père de Publius était alors au lit, malade de la fièvre et de la dysenterie; Paul, s''étant rendu vers lui, pria, lui imposa les mains, et le guérit.'),
  (44, 28, 9, 'Là-dessus, vinrent les autres malades de l''île, et ils furent guéris.'),
  (44, 28, 10, 'On nous rendit de grands honneurs, et, à notre départ, on nous fournit les choses dont nous avions besoin.'),
  (44, 28, 11, 'Après un séjour de trois mois, nous nous embarquâmes sur un navire d''Alexandrie, qui avait passé l''hiver dans l''île, et qui portait pour enseigne les Dioscures.'),
  (44, 28, 12, 'Ayant abordé à Syracuse, nous y restâmes trois jours.'),
  (44, 28, 13, 'De là, en suivant la côte, nous atteignîmes Reggio; et, le vent du midi s''étant levé le lendemain, nous fîmes en deux jours le trajet jusqu''à Pouzzoles,'),
  (44, 28, 14, 'où nous trouvâmes des frères qui nous prièrent de passer sept jours avec eux. Et c''est ainsi que nous allâmes à Rome.'),
  (44, 28, 15, 'De Rome vinrent à notre rencontre, jusqu''au Forum d''Appius et aux Trois Tavernes, les frères qui avaient entendu parler de nous. Paul, en les voyant, rendit grâces à Dieu, et prit courage.'),
  (44, 28, 16, 'Lorsque nous fûmes arrivés à Rome, on permit à Paul de demeurer en son particulier, avec un soldat qui le gardait.'),
  (44, 28, 17, 'Au bout de trois jours, Paul convoqua les principaux des Juifs; et, quand ils furent réunis, il leur adressa ces paroles: Hommes frères, sans avoir rien fait contre le peuple ni contre les coutumes de nos pères, j''ai été mis en prison à Jérusalem et livré de là entre les mains des Romains.'),
  (44, 28, 18, 'Après m''avoir interrogé, ils voulaient me relâcher, parce qu''il n''y avait en moi rien qui méritât la mort.'),
  (44, 28, 19, 'Mais les Juifs s''y opposèrent, et j''ai été forcé d''en appeler à César, n''ayant du reste aucun dessein d''accuser ma nation.'),
  (44, 28, 20, 'Voilà pourquoi j''ai demandé à vous voir et à vous parler; car c''est à cause de l''espérance d''Israël que je porte cette chaîne.'),
  (44, 28, 21, 'Ils lui répondirent: Nous n''avons reçu de Judée aucune lettre à ton sujet, et il n''est venu aucun frère qui ait rapporté ou dit du mal de toi.'),
  (44, 28, 22, 'Mais nous voudrions apprendre de toi ce que tu penses, car nous savons que cette secte rencontre partout de l''opposition.'),
  (44, 28, 23, 'Ils lui fixèrent un jour, et plusieurs vinrent le trouver dans son logis. Paul leur annonça le royaume de Dieu, en rendant témoignage, et en cherchant, par la loi de Moïse et par les prophètes, à les persuader de ce qui concerne Jésus. L''entretien dura depuis le matin jusqu''au soir.'),
  (44, 28, 24, 'Les uns furent persuadés par ce qu''il disait, et les autres ne crurent point.'),
  (44, 28, 25, 'Comme ils se retiraient en désaccord, Paul n''ajouta que ces mots: C''est avec raison que le Saint-Esprit, parlant à vos pères par le prophète Ésaïe,'),
  (44, 28, 26, 'a dit: Va vers ce peuple, et dis: Vous entendrez de vos oreilles, et vous ne comprendrez point; Vous regarderez de vos yeux, et vous ne verrez point.'),
  (44, 28, 27, 'Car le cœur de ce peuple est devenu insensible; Ils ont endurci leurs oreilles, et ils ont fermé leurs yeux, De peur qu''ils ne voient de leurs yeux, qu''ils n''entendent de leurs oreilles, Qu''ils ne comprennent de leur cœur, Qu''ils ne se convertissent, et que je ne les guérisse.'),
  (44, 28, 28, 'Sachez donc que ce salut de Dieu a été envoyé aux païens, et qu''ils l''écouteront.'),
  (44, 28, 29, 'Lorsqu''il eut dit cela, les Juifs s''en allèrent, discutant vivement entre eux.'),
  (44, 28, 30, 'Paul demeura deux ans entiers dans une maison qu''il avait louée. Il recevait tous ceux qui venaient le voir,'),
  (44, 28, 31, 'prêchant le royaume de Dieu et enseignant ce qui concerne le Seigneur Jésus-Christ, en toute liberté et sans obstacle.'),
  (45, 1, 1, 'Paul, serviteur de Jésus-Christ, appelé à être apôtre, mis à part pour annoncer l''Évangile de Dieu, -'),
  (45, 1, 2, 'qui avait été promis auparavant de la part de Dieu par ses prophètes dans les saintes Écritures,'),
  (45, 1, 3, 'et qui concerne son Fils (né de la postérité de David, selon la chair,'),
  (45, 1, 4, 'et déclaré Fils de Dieu avec puissance, selon l''Esprit de sainteté, par sa résurrection d''entre les morts), Jésus-Christ notre Seigneur,'),
  (45, 1, 5, 'par qui nous avons reçu la grâce et l''apostolat, pour amener en son nom à l''obéissance de la foi tous les païens,'),
  (45, 1, 6, 'parmi lesquels vous êtes aussi, vous qui avez été appelés par Jésus-Christ, -'),
  (45, 1, 7, 'à tous ceux qui, à Rome, sont bien-aimés de Dieu, appelés à être saints: que la grâce et la paix vous soient données de la part de Dieu notre Père et du Seigneur Jésus-Christ!'),
  (45, 1, 8, 'Je rends d''abord grâces à mon Dieu par Jésus-Christ, au sujet de vous tous, de ce que votre foi est renommée dans le monde entier.'),
  (45, 1, 9, 'Dieu, que je sers en mon esprit dans l''Évangile de son Fils, m''est témoin que je fais sans cesse mention de vous,'),
  (45, 1, 10, 'demandant continuellement dans mes prières d''avoir enfin, par sa volonté, le bonheur d''aller vers vous.'),
  (45, 1, 11, 'Car je désire vous voir, pour vous communiquer quelque don spirituel, afin que vous soyez affermis,'),
  (45, 1, 12, 'ou plutôt, afin que nous soyons encouragés ensemble au milieu de vous par la foi qui nous est commune, à vous et à moi.'),
  (45, 1, 13, 'Je ne veux pas vous laisser ignorer, frères, que j''ai souvent formé le projet d''aller vous voir, afin de recueillir quelque fruit parmi vous, comme parmi les autres nations; mais j''en ai été empêché jusqu''ici.'),
  (45, 1, 14, 'Je me dois aux Grecs et aux barbares, aux savants et aux ignorants.'),
  (45, 1, 15, 'Ainsi j''ai un vif désir de vous annoncer aussi l''Évangile, à vous qui êtes à Rome.'),
  (45, 1, 16, 'Car je n''ai point honte de l''Évangile: c''est une puissance de Dieu pour le salut de quiconque croit, du Juif premièrement, puis du Grec,'),
  (45, 1, 17, 'parce qu''en lui est révélée la justice de Dieu par la foi et pour la foi, selon qu''il est écrit: Le juste vivra par la foi.'),
  (45, 1, 18, 'La colère de Dieu se révèle du ciel contre toute impiété et toute injustice des hommes qui retiennent injustement la vérité captive,'),
  (45, 1, 19, 'car ce qu''on peut connaître de Dieu est manifeste pour eux, Dieu le leur ayant fait connaître.'),
  (45, 1, 20, 'En effet, les perfections invisibles de Dieu, sa puissance éternelle et sa divinité, se voient comme à l''œil, depuis la création du monde, quand on les considère dans ses ouvrages. Ils sont donc inexcusables,'),
  (45, 1, 21, 'puisque ayant connu Dieu, ils ne l''ont point glorifié comme Dieu, et ne lui ont point rendu grâces; mais ils se sont égarés dans leurs pensées, et leur cœur sans intelligence a été plongé dans les ténèbres.'),
  (45, 1, 22, 'Se vantant d''être sages, ils sont devenus fous;'),
  (45, 1, 23, 'et ils ont changé la gloire du Dieu incorruptible en images représentant l''homme corruptible, des oiseaux, des quadrupèdes, et des reptiles.'),
  (45, 1, 24, 'C''est pourquoi Dieu les a livrés à l''impureté, selon les convoitises de leurs cœurs; en sorte qu''ils déshonorent eux-mêmes leurs propres corps;'),
  (45, 1, 25, 'eux qui ont changé la vérité de Dieu en mensonge, et qui ont adoré et servi la créature au lieu du Créateur, qui est béni éternellement. Amen!'),
  (45, 1, 26, 'C''est pourquoi Dieu les a livrés à des passions infâmes: car leurs femmes ont changé l''usage naturel en celui qui est contre nature;'),
  (45, 1, 27, 'et de même les hommes, abandonnant l''usage naturel de la femme, se sont enflammés dans leurs désirs les uns pour les autres, commettant homme avec homme des choses infâmes, et recevant en eux-mêmes le salaire que méritait leur égarement.'),
  (45, 1, 28, 'Comme ils ne se sont pas souciés de connaître Dieu, Dieu les a livrés à leur sens réprouvé, pour commettre des choses indignes,'),
  (45, 1, 29, 'étant remplis de toute espèce d''injustice, de méchanceté, de cupidité, de malice; pleins d''envie, de meurtre, de querelle, de ruse, de malignité; rapporteurs,'),
  (45, 1, 30, 'médisants, impies, arrogants, hautains, fanfarons, ingénieux au mal, rebelles à leurs parents,'),
  (45, 1, 31, 'dépourvus d''intelligence, de loyauté, d''affection naturelle, de miséricorde.'),
  (45, 1, 32, 'Et, bien qu''ils connaissent le jugement de Dieu, déclarant dignes de mort ceux qui commettent de telles choses, non seulement ils les font, mais ils approuvent ceux qui les font.'),
  (45, 2, 1, 'O homme, qui que tu sois, toi qui juges, tu es donc inexcusable; car, en jugeant les autres, tu te condamnes toi-même, puisque toi qui juges, tu fais les mêmes choses.'),
  (45, 2, 2, 'Nous savons, en effet, que le jugement de Dieu contre ceux qui commettent de telles choses est selon la vérité.'),
  (45, 2, 3, 'Et penses-tu, ô homme, qui juges ceux qui commettent de telles choses, et qui les fais, que tu échapperas au jugement de Dieu?'),
  (45, 2, 4, 'Ou méprises-tu les richesses de sa bonté, de sa patience et de sa longanimité, ne reconnaissant pas que la bonté de Dieu te pousse à la repentance?'),
  (45, 2, 5, 'Mais, par ton endurcissement et par ton cœur impénitent, tu t''amasses un trésor de colère pour le jour de la colère et de la manifestation du juste jugement de Dieu,'),
  (45, 2, 6, 'qui rendra à chacun selon ses œuvres;'),
  (45, 2, 7, 'réservant la vie éternelle à ceux qui, par la persévérance à bien faire, cherchent l''honneur, la gloire et l''immortalité;'),
  (45, 2, 8, 'mais l''irritation et la colère à ceux qui, par esprit de dispute, sont rebelles à la vérité et obéissent à l''injustice.'),
  (45, 2, 9, 'Tribulation et angoisse sur toute âme d''homme qui fait le mal, sur le Juif premièrement, puis sur le Grec!'),
  (45, 2, 10, 'Gloire, honneur et paix pour quiconque fait le bien, pour le Juif premièrement, puis pour le Grec!'),
  (45, 2, 11, 'Car devant Dieu il n''y a point d''acception de personnes.'),
  (45, 2, 12, 'Tous ceux qui ont péché sans la loi périront aussi sans la loi, et tous ceux qui ont péché avec la loi seront jugés par la loi.'),
  (45, 2, 13, 'Ce ne sont pas, en effet, ceux qui écoutent la loi qui sont justes devant Dieu, mais ce sont ceux qui la mettent en pratique qui seront justifiés.'),
  (45, 2, 14, 'Quand les païens, qui n''ont point la loi, font naturellement ce que prescrit la loi, ils sont, eux qui n''ont point la loi, une loi pour eux-mêmes;'),
  (45, 2, 15, 'ils montrent que l''œuvre de la loi est écrite dans leurs cœurs, leur conscience en rendant témoignage, et leurs pensées s''accusant ou se défendant tour à tour.'),
  (45, 2, 16, 'C''est ce qui paraîtra au jour où, selon mon Évangile, Dieu jugera par Jésus-Christ les actions secrètes des hommes.'),
  (45, 2, 17, 'Toi qui te donnes le nom de Juif, qui te reposes sur la loi, qui te glorifies de Dieu,'),
  (45, 2, 18, 'qui connais sa volonté, qui apprécies la différence des choses, étant instruit par la loi;'),
  (45, 2, 19, 'toi qui te flattes d''être le conducteur des aveugles, la lumière de ceux qui sont dans les ténèbres,'),
  (45, 2, 20, 'le docteur des insensés, le maître des ignorants, parce que tu as dans la loi la règle de la science et de la vérité;'),
  (45, 2, 21, 'toi donc, qui enseignes les autres, tu ne t''enseignes pas toi-même! Toi qui prêches de ne pas dérober, tu dérobes!'),
  (45, 2, 22, 'Toi qui dis de ne pas commettre d''adultère, tu commets l''adultère! Toi qui as en abomination les idoles, tu commets des sacrilèges!'),
  (45, 2, 23, 'Toi qui te fais une gloire de la loi, tu déshonores Dieu par la transgression de la loi!'),
  (45, 2, 24, 'Car le nom de Dieu est à cause de vous blasphémé parmi les païens, comme cela est écrit.'),
  (45, 2, 25, 'La circoncision est utile, si tu mets en pratique la loi; mais si tu transgresses la loi, ta circoncision devient incirconcision.'),
  (45, 2, 26, 'Si donc l''incirconcis observe les ordonnances de la loi, son incirconcision ne sera-t-elle pas tenue pour circoncision?'),
  (45, 2, 27, 'L''incirconcis de nature, qui accomplit la loi, ne te condamnera-t-il pas, toi qui la transgresses, tout en ayant la lettre de la loi et la circoncision?'),
  (45, 2, 28, 'Le Juif, ce n''est pas celui qui en a les dehors; et la circoncision, ce n''est pas celle qui est visible dans la chair.'),
  (45, 2, 29, 'Mais le Juif, c''est celui qui l''est intérieurement; et la circoncision, c''est celle du cœur, selon l''esprit et non selon la lettre. La louange de ce Juif ne vient pas des hommes, mais de Dieu.'),
  (45, 3, 1, 'Quel est donc l''avantage des Juifs, ou quelle est l''utilité de la circoncision?'),
  (45, 3, 2, 'Il est grand de toute manière, et tout d''abord en ce que les oracles de Dieu leur ont été confiés.'),
  (45, 3, 3, 'Eh quoi! si quelques-uns n''ont pas cru, leur incrédulité anéantira-t-elle la fidélité de Dieu?'),
  (45, 3, 4, 'Loin de là! Que Dieu, au contraire, soit reconnu pour vrai, et tout homme pour menteur, selon qu''il est écrit: Afin que tu sois trouvé juste dans tes paroles, Et que tu triomphes lorsqu''on te juge.'),
  (45, 3, 5, 'Mais si notre injustice établit la justice de Dieu, que dirons-nous? Dieu est-il injuste quand il déchaîne sa colère? (Je parle à la manière des hommes.)'),
  (45, 3, 6, 'Loin de là! Autrement, comment Dieu jugerait-il le monde?'),
  (45, 3, 7, 'Et si, par mon mensonge, la vérité de Dieu éclate davantage pour sa gloire, pourquoi suis-je moi-même encore jugé comme pécheur?'),
  (45, 3, 8, 'Et pourquoi ne ferions-nous pas le mal afin qu''il en arrive du bien, comme quelques-uns, qui nous calomnient, prétendent que nous le disons? La condamnation de ces gens est juste.')
insert into public.bible_verses (book_id, chapter, verse, text) values
  (45, 3, 9, 'Quoi donc! sommes-nous plus excellents? Nullement. Car nous avons déjà prouvé que tous, Juifs et Grecs, sont sous l''empire du péché,'),
  (45, 3, 10, 'selon qu''il est écrit: Il n''y a point de juste, Pas même un seul;'),
  (45, 3, 11, 'Nul n''est intelligent, Nul ne cherche Dieu;'),
  (45, 3, 12, 'Tous sont égarés, tous sont pervertis; Il n''en est aucun qui fasse le bien, Pas même un seul;'),
  (45, 3, 13, 'Leur gosier est un sépulcre ouvert; Ils se servent de leurs langues pour tromper; Ils ont sous leurs lèvres un venin d''aspic;'),
  (45, 3, 14, 'Leur bouche est pleine de malédiction et d''amertume;'),
  (45, 3, 15, 'Ils ont les pieds légers pour répandre le sang;'),
  (45, 3, 16, 'La destruction et le malheur sont sur leur route;'),
  (45, 3, 17, 'Ils ne connaissent pas le chemin de la paix;'),
  (45, 3, 18, 'La crainte de Dieu n''est pas devant leurs yeux.'),
  (45, 3, 19, 'Or, nous savons que tout ce que dit la loi, elle le dit à ceux qui sont sous la loi, afin que toute bouche soit fermée, et que tout le monde soit reconnu coupable devant Dieu.'),
  (45, 3, 20, 'Car nul ne sera justifié devant lui par les œuvres de la loi, puisque c''est par la loi que vient la connaissance du péché.'),
  (45, 3, 21, 'Mais maintenant, sans la loi est manifestée la justice de Dieu, à laquelle rendent témoignage la loi et les prophètes,'),
  (45, 3, 22, 'justice de Dieu par la foi en Jésus-Christ pour tous ceux qui croient. Il n''y a point de distinction.'),
  (45, 3, 23, 'Car tous ont péché et sont privés de la gloire de Dieu;'),
  (45, 3, 24, 'et ils sont gratuitement justifiés par sa grâce, par le moyen de la rédemption qui est en Jésus-Christ.'),
  (45, 3, 25, 'C''est lui que Dieu a destiné, par son sang, à être, pour ceux qui croiraient victime propitiatoire, afin de montrer sa justice, parce qu''il avait laissé impunis les péchés commis auparavant, au temps de sa patience, afin, dis-je,'),
  (45, 3, 26, 'de montrer sa justice dans le temps présent, de manière à être juste tout en justifiant celui qui a la foi en Jésus.'),
  (45, 3, 27, 'Où donc est le sujet de se glorifier? Il est exclu. Par quelle loi? Par la loi des œuvres? Non, mais par la loi de la foi.'),
  (45, 3, 28, 'Car nous pensons que l''homme est justifié par la foi, sans les œuvres de la loi.'),
  (45, 3, 29, 'Ou bien Dieu est-il seulement le Dieu des Juifs? Ne l''est-il pas aussi des païens? Oui, il l''est aussi des païens,'),
  (45, 3, 30, 'puisqu''il y a un seul Dieu, qui justifiera par la foi les circoncis, et par la foi les incirconcis.'),
  (45, 3, 31, 'Anéantissons-nous donc la loi par la foi? Loin de là! Au contraire, nous confirmons la loi.'),
  (45, 4, 1, 'Que dirons-nous donc qu''Abraham, notre père, a obtenu selon la chair?'),
  (45, 4, 2, 'Si Abraham a été justifié par les œuvres, il a sujet de se glorifier, mais non devant Dieu.'),
  (45, 4, 3, 'Car que dit l''Écriture? Abraham crut à Dieu, et cela lui fut imputé à justice.'),
  (45, 4, 4, 'Or, à celui qui fait une œuvre, le salaire est imputé, non comme une grâce, mais comme une chose due;'),
  (45, 4, 5, 'et à celui qui ne fait point d''œuvre, mais qui croit en celui qui justifie l''impie, sa foi lui est imputée à justice.'),
  (45, 4, 6, 'De même David exprime le bonheur de l''homme à qui Dieu impute la justice sans les œuvres:'),
  (45, 4, 7, 'Heureux ceux dont les iniquités sont pardonnées, Et dont les péchés sont couverts!'),
  (45, 4, 8, 'Heureux l''homme à qui le Seigneur n''impute pas son péché!'),
  (45, 4, 9, 'Ce bonheur n''est-il que pour les circoncis, ou est-il également pour les incirconcis? Car nous disons que la foi fut imputée à justice à Abraham.'),
  (45, 4, 10, 'Comment donc lui fut-elle imputée? Était-ce après, ou avant sa circoncision? Il n''était pas encore circoncis, il était incirconcis.'),
  (45, 4, 11, 'Et il reçut le signe de la circoncision, comme sceau de la justice qu''il avait obtenue par la foi quand il était incirconcis, afin d''être le père de tous les incirconcis qui croient, pour que la justice leur fût aussi imputée,'),
  (45, 4, 12, 'et le père des circoncis, qui ne sont pas seulement circoncis, mais encore qui marchent sur les traces de la foi de notre père Abraham quand il était incirconcis.'),
  (45, 4, 13, 'En effet, ce n''est pas par la loi que l''héritage du monde a été promis à Abraham ou à sa postérité, c''est par la justice de la foi.'),
  (45, 4, 14, 'Car, si les héritiers le sont par la loi, la foi est vaine, et la promesse est anéantie,'),
  (45, 4, 15, 'parce que la loi produit la colère, et que là où il n''y a point de loi il n''y a point non plus de transgression.'),
  (45, 4, 16, 'C''est pourquoi les héritiers le sont par la foi, pour que ce soit par grâce, afin que la promesse soit assurée à toute la postérité, non seulement à celle qui est sous la loi, mais aussi à celle qui a la foi d''Abraham, notre père à tous,'),
  (45, 4, 17, 'selon qu''il est écrit: Je t''ai établi père d''un grand nombre de nations. Il est notre père devant celui auquel il a cru, Dieu, qui donne la vie aux morts, et qui appelle les choses qui ne sont point comme si elles étaient.'),
  (45, 4, 18, 'Espérant contre toute espérance, il crut, en sorte qu''il devint père d''un grand nombre de nations, selon ce qui lui avait été dit: Telle sera ta postérité.'),
  (45, 4, 19, 'Et, sans faiblir dans la foi, il ne considéra point que son corps était déjà usé, puisqu''il avait près de cent ans, et que Sara n''était plus en état d''avoir des enfants.'),
  (45, 4, 20, 'Il ne douta point, par incrédulité, au sujet de la promesse de Dieu; mais il fut fortifié par la foi, donnant gloire à Dieu,'),
  (45, 4, 21, 'et ayant la pleine conviction que ce qu''il promet il peut aussi l''accomplir.'),
  (45, 4, 22, 'C''est pourquoi cela lui fut imputé à justice.'),
  (45, 4, 23, 'Mais ce n''est pas à cause de lui seul qu''il est écrit que cela lui fut imputé;'),
  (45, 4, 24, 'c''est encore à cause de nous, à qui cela sera imputé, à nous qui croyons en celui qui a ressuscité des morts Jésus notre Seigneur,'),
  (45, 4, 25, 'lequel a été livré pour nos offenses, et est ressuscité pour notre justification.'),
  (45, 5, 1, 'Étant donc justifiés par la foi, nous avons la paix avec Dieu par notre Seigneur Jésus-Christ,'),
  (45, 5, 2, 'à qui nous devons d''avoir eu par la foi accès à cette grâce, dans laquelle nous demeurons fermes, et nous nous glorifions dans l''espérance de la gloire de Dieu.'),
  (45, 5, 3, 'Bien plus, nous nous glorifions même des afflictions, sachant que l''affliction produit la persévérance,'),
  (45, 5, 4, 'la persévérance la victoire dans l''épreuve, et cette victoire l''espérance.'),
  (45, 5, 5, 'Or, l''espérance ne trompe point, parce que l''amour de Dieu est répandu dans nos cœurs par le Saint-Esprit qui nous a été donné.'),
  (45, 5, 6, 'Car, lorsque nous étions encore sans force, Christ, au temps marqué, est mort pour des impies.'),
  (45, 5, 7, 'A peine mourrait-on pour un juste; quelqu''un peut-être mourrait-il pour un homme de bien.'),
  (45, 5, 8, 'Mais Dieu prouve son amour envers nous, en ce que, lorsque nous étions encore des pécheurs, Christ est mort pour nous.'),
  (45, 5, 9, 'A plus forte raison donc, maintenant que nous sommes justifiés par son sang, serons-nous sauvés par lui de la colère.'),
  (45, 5, 10, 'Car si, lorsque nous étions ennemis, nous avons été réconciliés avec Dieu par la mort de son Fils, à plus forte raison, étant réconciliés, serons-nous sauvés par sa vie.'),
  (45, 5, 11, 'Et non seulement cela, mais encore nous nous glorifions en Dieu par notre Seigneur Jésus-Christ, par qui maintenant nous avons obtenu la réconciliation.'),
  (45, 5, 12, 'C''est pourquoi, comme par un seul homme le péché est entré dans le monde, et par le péché la mort, et qu''ainsi la mort s''est étendue sur tous les hommes, parce que tous ont péché,…'),
  (45, 5, 13, 'car jusqu''à la loi le péché était dans le monde. Or, le péché n''est pas imputé, quand il n''y a point de loi.'),
  (45, 5, 14, 'Cependant la mort a régné depuis Adam jusqu''à Moïse, même sur ceux qui n''avaient pas péché par une transgression semblable à celle d''Adam, lequel est la figure de celui qui devait venir.'),
  (45, 5, 15, 'Mais il n''en est pas du don gratuit comme de l''offense; car, si par l''offense d''un seul il en est beaucoup qui sont morts, à plus forte raison la grâce de Dieu et le don de la grâce venant d''un seul homme, Jésus-Christ, ont-ils été abondamment répandus sur beaucoup.'),
  (45, 5, 16, 'Et il n''en est pas du don comme de ce qui est arrivé par un seul qui a péché; car c''est après une seule offense que le jugement est devenu condamnation, tandis que le don gratuit devient justification après plusieurs offenses.'),
  (45, 5, 17, 'Si par l''offense d''un seul la mort a régné par lui seul, à plus forte raison ceux qui reçoivent l''abondance de la grâce et du don de la justice régneront-ils dans la vie par Jésus-Christ lui seul.'),
  (45, 5, 18, 'Ainsi donc, comme par une seule offense la condamnation a atteint tous les hommes, de même par un seul acte de justice la justification qui donne la vie s''étend à tous les hommes.'),
  (45, 5, 19, 'Car, comme par la désobéissance d''un seul homme beaucoup ont été rendus pécheurs, de même par l''obéissance d''un seul beaucoup seront rendus justes.'),
  (45, 5, 20, 'Or, la loi est intervenue pour que l''offense abondât, mais là où le péché a abondé, la grâce a surabondé,'),
  (45, 5, 21, 'afin que, comme le péché a régné par la mort, ainsi la grâce régnât par la justice pour la vie éternelle, par Jésus-Christ notre Seigneur.'),
  (45, 6, 1, 'Que dirons-nous donc? Demeurerions-nous dans le péché, afin que la grâce abonde?'),
  (45, 6, 2, 'Loin de là! Nous qui sommes morts au péché, comment vivrions-nous encore dans le péché?'),
  (45, 6, 3, 'Ignorez-vous que nous tous qui avons été baptisés en Jésus-Christ, c''est en sa mort que nous avons été baptisés?'),
  (45, 6, 4, 'Nous avons donc été ensevelis avec lui par le baptême en sa mort, afin que, comme Christ est ressuscité des morts par la gloire du Père, de même nous aussi nous marchions en nouveauté de vie.'),
  (45, 6, 5, 'En effet, si nous sommes devenus une même plante avec lui par la conformité à sa mort, nous le serons aussi par la conformité à sa résurrection,'),
  (45, 6, 6, 'sachant que notre vieil homme a été crucifié avec lui, afin que le corps du péché fût détruit, pour que nous ne soyons plus esclaves du péché;'),
  (45, 6, 7, 'car celui qui est mort est libre du péché.'),
  (45, 6, 8, 'Or, si nous sommes morts avec Christ, nous croyons que nous vivrons aussi avec lui,'),
  (45, 6, 9, 'sachant que Christ ressuscité des morts ne meurt plus; la mort n''a plus de pouvoir sur lui.'),
  (45, 6, 10, 'Car il est mort, et c''est pour le péché qu''il est mort une fois pour toutes; il est revenu à la vie, et c''est pour Dieu qu''il vit.'),
  (45, 6, 11, 'Ainsi vous-mêmes, regardez-vous comme morts au péché, et comme vivants pour Dieu en Jésus-Christ.'),
  (45, 6, 12, 'Que le péché ne règne donc point dans votre corps mortel, et n''obéissez pas à ses convoitises.'),
  (45, 6, 13, 'Ne livrez pas vos membres au péché, comme des instruments d''iniquité; mais donnez-vous vous-mêmes à Dieu, comme étant vivants de morts que vous étiez, et offrez à Dieu vos membres, comme des instruments de justice.'),
  (45, 6, 14, 'Car le péché n''aura point de pouvoir sur vous, puisque vous êtes, non sous la loi, mais sous la grâce.'),
  (45, 6, 15, 'Quoi donc! Pécherions-nous, parce que nous sommes, non sous la loi, mais sous la grâce? Loin de là!'),
  (45, 6, 16, 'Ne savez-vous pas qu''en vous livrant à quelqu''un comme esclaves pour lui obéir, vous êtes esclaves de celui à qui vous obéissez, soit du péché qui conduit à la mort, soit de l''obéissance qui conduit à la justice?'),
  (45, 6, 17, 'Mais grâces soient rendues à Dieu de ce que, après avoir été esclaves du péché, vous avez obéi de cœur à la règle de doctrine dans laquelle vous avez été instruits.'),
  (45, 6, 18, 'Ayant été affranchis du péché, vous êtes devenus esclaves de la justice. -'),
  (45, 6, 19, 'Je parle à la manière des hommes, à cause de la faiblesse de votre chair. -De même donc que vous avez livré vos membres comme esclaves à l''impureté et à l''iniquité, pour arriver à l''iniquité, ainsi maintenant livrez vos membres comme esclaves à la justice, pour arriver à la sainteté.'),
  (45, 6, 20, 'Car, lorsque vous étiez esclaves du péché, vous étiez libres à l''égard de la justice.'),
  (45, 6, 21, 'Quels fruits portiez-vous alors? Des fruits dont vous rougissez aujourd''hui. Car la fin de ces choses, c''est la mort.'),
  (45, 6, 22, 'Mais maintenant, étant affranchis du péché et devenus esclaves de Dieu, vous avez pour fruit la sainteté et pour fin la vie éternelle.'),
  (45, 6, 23, 'Car le salaire du péché, c''est la mort; mais le don gratuit de Dieu, c''est la vie éternelle en Jésus-Christ notre Seigneur.'),
  (45, 7, 1, 'Ignorez-vous, frères, -car je parle à des gens qui connaissent la loi, -que la loi exerce son pouvoir sur l''homme aussi longtemps qu''il vit?'),
  (45, 7, 2, 'Ainsi, une femme mariée est liée par la loi à son mari tant qu''il est vivant; mais si le mari meurt, elle est dégagée de la loi qui la liait à son mari.'),
  (45, 7, 3, 'Si donc, du vivant de son mari, elle devient la femme d''un autre homme, elle sera appelée adultère; mais si le mari meurt, elle est affranchie de la loi, de sorte qu''elle n''est point adultère en devenant la femme d''un autre.'),
  (45, 7, 4, 'De même, mes frères, vous aussi vous avez été, par le corps de Christ, mis à mort en ce qui concerne la loi, pour que vous apparteniez à un autre, à celui qui est ressuscité des morts, afin que nous portions des fruits pour Dieu.'),
  (45, 7, 5, 'Car, lorsque nous étions dans la chair, les passions des péchés provoquées par la loi agissaient dans nos membres, de sorte que nous portions des fruits pour la mort.'),
  (45, 7, 6, 'Mais maintenant, nous avons été dégagés de la loi, étant morts à cette loi sous laquelle nous étions retenus, de sorte que nous servons dans un esprit nouveau, et non selon la lettre qui a vieilli.'),
  (45, 7, 7, 'Que dirons-nous donc? La loi est-elle péché? Loin de là! Mais je n''ai connu le péché que par la loi. Car je n''aurais pas connu la convoitise, si la loi n''eût dit: Tu ne convoiteras point.'),
  (45, 7, 8, 'Et le péché, saisissant l''occasion, produisit en moi par le commandement toutes sortes de convoitises; car sans loi le péché est mort.'),
  (45, 7, 9, 'Pour moi, étant autrefois sans loi, je vivais; mais quand le commandement vint, le péché reprit vie, et moi je mourus.'),
  (45, 7, 10, 'Ainsi, le commandement qui conduit à la vie se trouva pour moi conduire à la mort.'),
  (45, 7, 11, 'Car le péché saisissant l''occasion, me séduisit par le commandement, et par lui me fit mourir.'),
  (45, 7, 12, 'La loi donc est sainte, et le commandement est saint, juste et bon.'),
  (45, 7, 13, 'Ce qui est bon a-t-il donc été pour moi une cause de mort? Loin de là! Mais c''est le péché, afin qu''il se manifestât comme péché en me donnant la mort par ce qui est bon, et que, par le commandement, il devînt condamnable au plus haut point.'),
  (45, 7, 14, 'Nous savons, en effet, que la loi est spirituelle; mais moi, je suis charnel, vendu au péché.'),
  (45, 7, 15, 'Car je ne sais pas ce que je fais: je ne fais point ce que je veux, et je fais ce que je hais.'),
  (45, 7, 16, 'Or, si je fais ce que je ne veux pas, je reconnais par là que la loi est bonne.'),
  (45, 7, 17, 'Et maintenant ce n''est plus moi qui le fais, mais c''est le péché qui habite en moi.'),
  (45, 7, 18, 'Ce qui est bon, je le sais, n''habite pas en moi, c''est-à-dire dans ma chair: j''ai la volonté, mais non le pouvoir de faire le bien.'),
  (45, 7, 19, 'Car je ne fais pas le bien que je veux, et je fais le mal que je ne veux pas.'),
  (45, 7, 20, 'Et si je fais ce que je ne veux pas, ce n''est plus moi qui le fais, c''est le péché qui habite en moi.'),
  (45, 7, 21, 'Je trouve donc en moi cette loi: quand je veux faire le bien, le mal est attaché à moi.'),
  (45, 7, 22, 'Car je prends plaisir à la loi de Dieu, selon l''homme intérieur;'),
  (45, 7, 23, 'mais je vois dans mes membres une autre loi, qui lutte contre la loi de mon entendement, et qui me rend captif de la loi du péché, qui est dans mes membres.'),
  (45, 7, 24, 'Misérable que je suis! Qui me délivrera du corps de cette mort?…'),
  (45, 7, 25, 'Grâces soient rendues à Dieu par Jésus-Christ notre Seigneur!… Ainsi donc, moi-même, je suis par l''entendement esclave de la loi de Dieu, et je suis par la chair esclave de la loi du péché.'),
  (45, 8, 1, 'Il n''y a donc maintenant aucune condamnation pour ceux qui sont en Jésus-Christ.'),
  (45, 8, 2, 'En effet, la loi de l''esprit de vie en Jésus-Christ m''a affranchi de la loi du péché et de la mort.'),
  (45, 8, 3, 'Car - chose impossible à la loi, parce que la chair la rendait sans force, - Dieu a condamné le péché dans la chair, en envoyant, à cause du péché, son propre Fils dans une chair semblable à celle du péché,'),
  (45, 8, 4, 'et cela afin que la justice de la loi fût accomplie en nous, qui marchons, non selon la chair, mais selon l''esprit.'),
  (45, 8, 5, 'Ceux, en effet, qui vivent selon la chair, s''affectionnent aux choses de la chair, tandis que ceux qui vivent selon l''esprit s''affectionnent aux choses de l''esprit.'),
  (45, 8, 6, 'Et l''affection de la chair, c''est la mort, tandis que l''affection de l''esprit, c''est la vie et la paix;'),
  (45, 8, 7, 'car l''affection de la chair est inimitié contre Dieu, parce qu''elle ne se soumet pas à la loi de Dieu, et qu''elle ne le peut même pas.'),
  (45, 8, 8, 'Or ceux qui vivent selon la chair ne sauraient plaire à Dieu.'),
  (45, 8, 9, 'Pour vous, vous ne vivez pas selon la chair, mais selon l''esprit, si du moins l''Esprit de Dieu habite en vous. Si quelqu''un n''a pas l''Esprit de Christ, il ne lui appartient pas.'),
  (45, 8, 10, 'Et si Christ est en vous, le corps, il est vrai, est mort à cause du péché, mais l''esprit est vie à cause de la justice.'),
  (45, 8, 11, 'Et si l''Esprit de celui qui a ressuscité Jésus d''entre les morts habite en vous, celui qui a ressuscité Christ d''entre les morts rendra aussi la vie à vos corps mortels par son Esprit qui habite en vous.'),
  (45, 8, 12, 'Ainsi donc, frères, nous ne sommes point redevables à la chair, pour vivre selon la chair.'),
  (45, 8, 13, 'Si vous vivez selon la chair, vous mourrez; mais si par l''Esprit vous faites mourir les actions du corps, vous vivrez,'),
  (45, 8, 14, 'car tous ceux qui sont conduits par l''Esprit de Dieu sont fils de Dieu.'),
  (45, 8, 15, 'Et vous n''avez point reçu un esprit de servitude, pour être encore dans la crainte; mais vous avez reçu un Esprit d''adoption, par lequel nous crions: Abba! Père!'),
  (45, 8, 16, 'L''Esprit lui-même rend témoignage à notre esprit que nous sommes enfants de Dieu.'),
  (45, 8, 17, 'Or, si nous sommes enfants, nous sommes aussi héritiers: héritiers de Dieu, et cohéritiers de Christ, si toutefois nous souffrons avec lui, afin d''être glorifiés avec lui.'),
  (45, 8, 18, 'J''estime que les souffrances du temps présent ne sauraient être comparées à la gloire à venir qui sera révélée pour nous.'),
  (45, 8, 19, 'Aussi la création attend-elle avec un ardent désir la révélation des fils de Dieu.'),
  (45, 8, 20, 'Car la création a été soumise à la vanité, -non de son gré, mais à cause de celui qui l''y a soumise, avec l''espérance'),
  (45, 8, 21, 'qu''elle aussi sera affranchie de la servitude de la corruption, pour avoir part à la liberté de la gloire des enfants de Dieu.'),
  (45, 8, 22, 'Or, nous savons que, jusqu''à ce jour, la création tout entière soupire et souffre les douleurs de l''enfantement.'),
  (45, 8, 23, 'Et ce n''est pas elle seulement; mais nous aussi, qui avons les prémices de l''Esprit, nous aussi nous soupirons en nous-mêmes, en attendant l''adoption, la rédemption de notre corps.'),
  (45, 8, 24, 'Car c''est en espérance que nous sommes sauvés. Or, l''espérance qu''on voit n''est plus espérance: ce qu''on voit, peut-on l''espérer encore?'),
  (45, 8, 25, 'Mais si nous espérons ce que nous ne voyons pas, nous l''attendons avec persévérance.'),
  (45, 8, 26, 'De même aussi l''Esprit nous aide dans notre faiblesse, car nous ne savons pas ce qu''il nous convient de demander dans nos prières. Mais l''Esprit lui-même intercède par des soupirs inexprimables;'),
  (45, 8, 27, 'et celui qui sonde les cœurs connaît quelle est la pensée de l''Esprit, parce que c''est selon Dieu qu''il intercède en faveur des saints.'),
  (45, 8, 28, 'Nous savons, du reste, que toutes choses concourent au bien de ceux qui aiment Dieu, de ceux qui sont appelés selon son dessein.'),
  (45, 8, 29, 'Car ceux qu''il a connus d''avance, il les a aussi prédestinés à être semblables à l''image de son Fils, afin que son Fils fût le premier-né entre plusieurs frères.'),
  (45, 8, 30, 'Et ceux qu''il a prédestinés, il les a aussi appelés; et ceux qu''il a appelés, il les a aussi justifiés; et ceux qu''il a justifiés, il les a aussi glorifiés.'),
  (45, 8, 31, 'Que dirons-nous donc à l''égard de ces choses? Si Dieu est pour nous, qui sera contre nous?'),
  (45, 8, 32, 'Lui, qui n''a point épargné son propre Fils, mais qui l''a livré pour nous tous, comment ne nous donnera-t-il pas aussi toutes choses avec lui?'),
  (45, 8, 33, 'Qui accusera les élus de Dieu? C''est Dieu qui justifie!'),
  (45, 8, 34, 'Qui les condamnera? Christ est mort; bien plus, il est ressuscité, il est à la droite de Dieu, et il intercède pour nous!'),
  (45, 8, 35, 'Qui nous séparera de l''amour de Christ? Sera-ce la tribulation, ou l''angoisse, ou la persécution, ou la faim, ou la nudité, ou le péril, ou l''épée?'),
  (45, 8, 36, 'selon qu''il est écrit: C''est à cause de toi qu''on nous met à mort tout le jour, Qu''on nous regarde comme des brebis destinées à la boucherie.'),
  (45, 8, 37, 'Mais dans toutes ces choses nous sommes plus que vainqueurs par celui qui nous a aimés.'),
  (45, 8, 38, 'Car j''ai l''assurance que ni la mort ni la vie, ni les anges ni les dominations, ni les choses présentes ni les choses à venir, ni les puissances,'),
  (45, 8, 39, 'ni la hauteur, ni la profondeur, ni aucune autre créature ne pourra nous séparer de l''amour de Dieu manifesté en Jésus-Christ notre Seigneur.'),
  (45, 9, 1, 'Je dis la vérité en Christ, je ne mens point, ma conscience m''en rend témoignage par le Saint-Esprit:'),
  (45, 9, 2, 'J''éprouve une grande tristesse, et j''ai dans le cœur un chagrin continuel.'),
  (45, 9, 3, 'Car je voudrais moi-même être anathème et séparé de Christ pour mes frères, mes parents selon la chair,'),
  (45, 9, 4, 'qui sont Israélites, à qui appartiennent l''adoption, et la gloire, et les alliances, et la loi, et le culte, et les promesses,'),
  (45, 9, 5, 'et les patriarches, et de qui est issu, selon la chair, le Christ, qui est au-dessus de toutes choses, Dieu béni éternellement. Amen!'),
  (45, 9, 6, 'Ce n''est point à dire que la parole de Dieu soit restée sans effet. Car tous ceux qui descendent d''Israël ne sont pas Israël,'),
  (45, 9, 7, 'et, pour être la postérité d''Abraham, ils ne sont pas tous ses enfants; mais il est dit: En Isaac sera nommée pour toi une postérité,'),
  (45, 9, 8, 'c''est-à-dire que ce ne sont pas les enfants de la chair qui sont enfants de Dieu, mais que ce sont les enfants de la promesse qui sont regardés comme la postérité.'),
  (45, 9, 9, 'Voici, en effet, la parole de la promesse: Je reviendrai à cette même époque, et Sara aura un fils.'),
  (45, 9, 10, 'Et, de plus, il en fut ainsi de Rébecca, qui conçut du seul Isaac notre père;'),
  (45, 9, 11, 'car, quoique les enfants ne fussent pas encore nés et qu''ils n''eussent fait ni bien ni mal, - afin que le dessein d''élection de Dieu subsistât, sans dépendre des œuvres, et par la seule volonté de celui qui appelle, -'),
  (45, 9, 12, 'il fut dit à Rébecca: L''aîné sera assujetti au plus jeune;'),
  (45, 9, 13, 'selon qu''il est écrit: J''ai aimé Jacob Et j''ai haï Ésaü.'),
  (45, 9, 14, 'Que dirons-nous donc? Y a-t-il en Dieu de l''injustice? Loin de là!'),
  (45, 9, 15, 'Car il dit à Moïse: Je ferai miséricorde à qui je fais miséricorde, et j''aurai compassion de qui j''ai compassion.'),
  (45, 9, 16, 'Ainsi donc, cela ne dépend ni de celui qui veut, ni de celui qui court, mais de Dieu qui fait miséricorde.'),
  (45, 9, 17, 'Car l''Écriture dit à Pharaon: Je t''ai suscité à dessein pour montrer en toi ma puissance, et afin que mon nom soit publié par toute la terre.'),
  (45, 9, 18, 'Ainsi, il fait miséricorde à qui il veut, et il endurcit qui il veut.'),
  (45, 9, 19, 'Tu me diras: Pourquoi blâme-t-il encore? Car qui est-ce qui résiste à sa volonté?'),
  (45, 9, 20, 'O homme, toi plutôt, qui es-tu pour contester avec Dieu? Le vase d''argile dira-t-il à celui qui l''a formé: Pourquoi m''as-tu fait ainsi?'),
  (45, 9, 21, 'Le potier n''est-il pas maître de l''argile, pour faire avec la même masse un vase d''honneur et un vase d''un usage vil?'),
  (45, 9, 22, 'Et que dire, si Dieu, voulant montrer sa colère et faire connaître sa puissance, a supporté avec une grande patience des vases de colère formés pour la perdition,'),
  (45, 9, 23, 'et s''il a voulu faire connaître la richesse de sa gloire envers des vases de miséricorde qu''il a d''avance préparés pour la gloire?'),
  (45, 9, 24, 'Ainsi nous a-t-il appelés, non seulement d''entre les Juifs, mais encore d''entre les païens,'),
  (45, 9, 25, 'selon qu''il le dit dans Osée: J''appellerai mon peuple celui qui n''était pas mon peuple, et bien-aimée celle qui n''était pas la bien-aimée;'),
  (45, 9, 26, 'et là où on leur disait: Vous n''êtes pas mon peuple! ils seront appelés fils du Dieu vivant.'),
  (45, 9, 27, 'Ésaïe, de son côté, s''écrie au sujet d''Israël: Quand le nombre des fils d''Israël serait comme le sable de la mer, Un reste seulement sera sauvé.'),
  (45, 9, 28, 'Car le Seigneur exécutera pleinement et promptement sur la terre ce qu''il a résolu.'),
  (45, 9, 29, 'Et, comme Ésaïe l''avait dit auparavant: Si le Seigneur des armées Ne nous eût laissé une postérité, Nous serions devenus comme Sodome, Nous aurions été semblables à Gomorrhe.'),
  (45, 9, 30, 'Que dirons-nous donc? Les païens, qui ne cherchaient pas la justice, ont obtenu la justice, la justice qui vient de la foi,'),
  (45, 9, 31, 'tandis qu''Israël, qui cherchait une loi de justice, n''est pas parvenu à cette loi.'),
  (45, 9, 32, 'Pourquoi? Parce qu''Israël l''a cherchée, non par la foi, mais comme provenant des œuvres. Ils se sont heurtés contre la pierre d''achoppement,'),
  (45, 9, 33, 'selon qu''il est écrit: Voici, je mets en Sion une pierre d''achoppement Et un rocher de scandale, Et celui qui croit en lui ne sera point confus.'),
  (45, 10, 1, 'Frères, le vœu de mon cœur et ma prière à Dieu pour eux, c''est qu''ils soient sauvés.'),
  (45, 10, 2, 'Je leur rends le témoignage qu''ils ont du zèle pour Dieu, mais sans intelligence:'),
  (45, 10, 3, 'ne connaissant pas la justice de Dieu, et cherchant à établir leur propre justice, ils ne se sont pas soumis à la justice de Dieu;'),
  (45, 10, 4, 'car Christ est la fin de la loi, pour la justification de tous ceux qui croient.'),
  (45, 10, 5, 'En effet, Moïse définit ainsi la justice qui vient de la loi: L''homme qui mettra ces choses en pratique vivra par elles.'),
  (45, 10, 6, 'Mais voici comment parle la justice qui vient de la foi: Ne dis pas en ton cœur: Qui montera au ciel? c''est en faire descendre Christ;'),
  (45, 10, 7, 'ou: Qui descendra dans l''abîme? c''est faire remonter Christ d''entre les morts.'),
  (45, 10, 8, 'Que dit-elle donc? La parole est près de toi, dans ta bouche et dans ton cœur. Or, c''est la parole de la foi, que nous prêchons.'),
  (45, 10, 9, 'Si tu confesses de ta bouche le Seigneur Jésus, et si tu crois dans ton cœur que Dieu l''a ressuscité des morts, tu seras sauvé.'),
  (45, 10, 10, 'Car c''est en croyant du cœur qu''on parvient à la justice, et c''est en confessant de la bouche qu''on parvient au salut,'),
  (45, 10, 11, 'selon ce que dit l''Écriture: Quiconque croit en lui ne sera point confus.'),
  (45, 10, 12, 'Il n''y a aucune différence, en effet, entre le Juif et le Grec, puisqu''ils ont tous un même Seigneur, qui est riche pour tous ceux qui l''invoquent.'),
  (45, 10, 13, 'Car quiconque invoquera le nom du Seigneur sera sauvé.'),
  (45, 10, 14, 'Comment donc invoqueront-ils celui en qui ils n''ont pas cru? Et comment croiront-ils en celui dont ils n''ont pas entendu parler? Et comment en entendront-ils parler, s''il n''y a personne qui prêche?'),
  (45, 10, 15, 'Et comment y aura-t-il des prédicateurs, s''ils ne sont pas envoyés? selon qu''il est écrit: Qu''ils sont beaux Les pieds de ceux qui annoncent la paix, De ceux qui annoncent de bonnes nouvelles!'),
  (45, 10, 16, 'Mais tous n''ont pas obéi à la bonne nouvelle. Aussi Ésaïe dit-il: Seigneur, Qui a cru à notre prédication?'),
  (45, 10, 17, 'Ainsi la foi vient de ce qu''on entend, et ce qu''on entend vient de la parole de Christ.'),
  (45, 10, 18, 'Mais je dis: N''ont-ils pas entendu? Au contraire! Leur voix est allée par toute la terre, Et leurs paroles jusqu''aux extrémités du monde.'),
  (45, 10, 19, 'Mais je dis: Israël ne l''a-t-il pas su? Moïse le premier dit: J''exciterai votre jalousie par ce qui n''est point une nation, je provoquerai votre colère par une nation sans intelligence.'),
  (45, 10, 20, 'Et Ésaïe pousse la hardiesse jusqu''à dire: J''ai été trouvé par ceux qui ne me cherchaient pas, Je me suis manifesté à ceux qui ne me demandaient pas.'),
  (45, 10, 21, 'Mais au sujet d''Israël, il dit: J''ai tendu mes mains tout le jour vers un peuple rebelle Et contredisant.'),
  (45, 11, 1, 'Je dis donc: Dieu a-t-il rejeté son peuple? Loin de là! Car moi aussi je suis Israélite, de la postérité d''Abraham, de la tribu de Benjamin.'),
  (45, 11, 2, 'Dieu n''a point rejeté son peuple, qu''il a connu d''avance. Ne savez-vous pas ce que l''Écriture rapporte d''Élie, comment il adresse à Dieu cette plainte contre Israël:'),
  (45, 11, 3, 'Seigneur, ils ont tué tes prophètes, ils ont renversé tes autels; je suis resté moi seul, et ils cherchent à m''ôter la vie?'),
  (45, 11, 4, 'Mais quelle réponse Dieu lui fait-il? Je me suis réservé sept mille hommes, qui n''ont point fléchi le genou devant Baal.'),
  (45, 11, 5, 'De même aussi dans le temps présent il y a un reste, selon l''élection de la grâce.'),
  (45, 11, 6, 'Or, si c''est par grâce, ce n''est plus par les œuvres; autrement la grâce n''est plus une grâce. Et si c''est par les œuvres, ce n''est plus une grâce; autrement l''œuvre n''est plus une œuvre.'),
  (45, 11, 7, 'Quoi donc? Ce qu''Israël cherche, il ne l''a pas obtenu, mais l''élection l''a obtenu, tandis que les autres ont été endurcis,'),
  (45, 11, 8, 'selon qu''il est écrit: Dieu leur a donné un esprit d''assoupissement, Des yeux pour ne point voir, Et des oreilles pour ne point entendre, Jusqu''à ce jour.'),
  (45, 11, 9, 'Et David dit: Que leur table soit pour eux un piège, Un filet, une occasion de chute, et une rétribution!'),
  (45, 11, 10, 'Que leurs yeux soient obscurcis pour ne point voir, Et tiens leur dos continuellement courbé!'),
  (45, 11, 11, 'Je dis donc: Est-ce pour tomber qu''ils ont bronché? Loin de là! Mais, par leur chute, le salut est devenu accessible aux païens, afin qu''ils fussent excités à la jalousie.'),
  (45, 11, 12, 'Or, si leur chute a été la richesse du monde, et leur amoindrissement la richesse des païens, combien plus en sera-t-il ainsi quand ils se convertiront tous.'),
  (45, 11, 13, 'Je vous le dis à vous, païens: en tant que je suis apôtre des païens, je glorifie mon ministère,'),
  (45, 11, 14, 'afin, s''il est possible, d''exciter la jalousie de ceux de ma race, et d''en sauver quelques-uns.'),
  (45, 11, 15, 'Car si leur rejet a été la réconciliation du monde, que sera leur réintégration, sinon une vie d''entre les morts?'),
  (45, 11, 16, 'Or, si les prémices sont saintes, la masse l''est aussi; et si la racine est sainte, les branches le sont aussi.'),
  (45, 11, 17, 'Mais si quelques-unes des branches ont été retranchées, et si toi, qui étais un olivier sauvage, tu as été enté à leur place, et rendu participant de la racine et de la graisse de l''olivier,'),
  (45, 11, 18, 'ne te glorifie pas aux dépens de ces branches. Si tu te glorifies, sache que ce n''est pas toi qui portes la racine, mais que c''est la racine qui te porte.'),
  (45, 11, 19, 'Tu diras donc: Les branches ont été retranchées, afin que moi je fusse enté.'),
  (45, 11, 20, 'Cela est vrai; elles ont été retranchées pour cause d''incrédulité, et toi, tu subsistes par la foi. Ne t''abandonne pas à l''orgueil, mais crains;'),
  (45, 11, 21, 'car si Dieu n''a pas épargné les branches naturelles, il ne t''épargnera pas non plus.'),
  (45, 11, 22, 'Considère donc la bonté et la sévérité de Dieu: sévérité envers ceux qui sont tombés, et bonté de Dieu envers toi, si tu demeures ferme dans cette bonté; autrement, tu seras aussi retranché.'),
  (45, 11, 23, 'Eux de même, s''ils ne persistent pas dans l''incrédulité, ils seront entés; car Dieu est puissant pour les enter de nouveau.'),
  (45, 11, 24, 'Si toi, tu as été coupé de l''olivier naturellement sauvage, et enté contrairement à ta nature sur l''olivier franc, à plus forte raison eux seront-ils entés selon leur nature sur leur propre olivier.'),
  (45, 11, 25, 'Car je ne veux pas, frères, que vous ignoriez ce mystère, afin que vous ne vous regardiez point comme sages, c''est qu''une partie d''Israël est tombée dans l''endurcissement, jusqu''à ce que la totalité des païens soit entrée.'),
  (45, 11, 26, 'Et ainsi tout Israël sera sauvé, selon qu''il est écrit: Le libérateur viendra de Sion, Et il détournera de Jacob les impiétés;'),
  (45, 11, 27, 'Et ce sera mon alliance avec eux, Lorsque j''ôterai leurs péchés.'),
  (45, 11, 28, 'En ce qui concerne l''Évangile, ils sont ennemis à cause de vous; mais en ce qui concerne l''élection, ils sont aimés à cause de leurs pères.'),
  (45, 11, 29, 'Car Dieu ne se repent pas de ses dons et de son appel.'),
  (45, 11, 30, 'De même que vous avez autrefois désobéi à Dieu et que par leur désobéissance vous avez maintenant obtenu miséricorde,'),
  (45, 11, 31, 'de même ils ont maintenant désobéi, afin que, par la miséricorde qui vous a été faite, ils obtiennent aussi miséricorde.'),
  (45, 11, 32, 'Car Dieu a renfermé tous les hommes dans la désobéissance, pour faire miséricorde à tous.'),
  (45, 11, 33, 'O profondeur de la richesse, de la sagesse et de la science de Dieu! Que ses jugements sont insondables, et ses voies incompréhensibles! Car'),
  (45, 11, 34, 'Qui a connu la pensée du Seigneur, Ou qui a été son conseiller?'),
  (45, 11, 35, 'Qui lui a donné le premier, pour qu''il ait à recevoir en retour?'),
  (45, 11, 36, 'C''est de lui, par lui, et pour lui que sont toutes choses. A lui la gloire dans tous les siècles! Amen!'),
  (45, 12, 1, 'Je vous exhorte donc, frères, par les compassions de Dieu, à offrir vos corps comme un sacrifice vivant, saint, agréable à Dieu, ce qui sera de votre part un culte raisonnable.'),
  (45, 12, 2, 'Ne vous conformez pas au siècle présent, mais soyez transformés par le renouvellement de l''intelligence, afin que vous discerniez quelle est la volonté de Dieu, ce qui est bon, agréable et parfait.'),
  (45, 12, 3, 'Par la grâce qui m''a été donnée, je dis à chacun de vous de n''avoir pas de lui-même une trop haute opinion, mais de revêtir des sentiments modestes, selon la mesure de foi que Dieu a départie à chacun.'),
  (45, 12, 4, 'Car, comme nous avons plusieurs membres dans un seul corps, et que tous les membres n''ont pas la même fonction,'),
  (45, 12, 5, 'ainsi, nous qui sommes plusieurs, nous formons un seul corps en Christ, et nous sommes tous membres les uns des autres.'),
  (45, 12, 6, 'Puisque nous avons des dons différents, selon la grâce qui nous a été accordée, que celui qui a le don de prophétie l''exerce selon l''analogie de la foi;'),
  (45, 12, 7, 'que celui qui est appelé au ministère s''attache à son ministère; que celui qui enseigne s''attache à son enseignement,'),
  (45, 12, 8, 'et celui qui exhorte à l''exhortation. Que celui qui donne le fasse avec libéralité; que celui qui préside le fasse avec zèle; que celui qui pratique la miséricorde le fasse avec joie.'),
  (45, 12, 9, 'Que la charité soit sans hypocrisie. Ayez le mal en horreur; attachez-vous fortement au bien.'),
  (45, 12, 10, 'Par amour fraternel, soyez pleins d''affection les uns pour les autres; par honneur, usez de prévenances réciproques.'),
  (45, 12, 11, 'Ayez du zèle, et non de la paresse. Soyez fervents d''esprit. Servez le Seigneur.'),
  (45, 12, 12, 'Réjouissez-vous en espérance. Soyez patients dans l''affliction. Persévérez dans la prière.'),
  (45, 12, 13, 'Pourvoyez aux besoins des saints. Exercez l''hospitalité.'),
  (45, 12, 14, 'Bénissez ceux qui vous persécutent, bénissez et ne maudissez pas.'),
  (45, 12, 15, 'Réjouissez-vous avec ceux qui se réjouissent; pleurez avec ceux qui pleurent.'),
  (45, 12, 16, 'Ayez les mêmes sentiments les uns envers les autres. N''aspirez pas à ce qui est élevé, mais laissez-vous attirer par ce qui est humble. Ne soyez point sages à vos propres yeux.'),
  (45, 12, 17, 'Ne rendez à personne le mal pour le mal. Recherchez ce qui est bien devant tous les hommes.'),
  (45, 12, 18, 'S''il est possible, autant que cela dépend de vous, soyez en paix avec tous les hommes.'),
  (45, 12, 19, 'Ne vous vengez point vous-mêmes, bien-aimés, mais laissez agir la colère; car il est écrit: A moi la vengeance, à moi la rétribution, dit le Seigneur.'),
  (45, 12, 20, 'Mais si ton ennemi a faim, donne-lui à manger; s''il a soif, donne-lui à boire; car en agissant ainsi, ce sont des charbons ardents que tu amasseras sur sa tête.'),
  (45, 12, 21, 'Ne te laisse pas vaincre par le mal, mais surmonte le mal par le bien.'),
  (45, 13, 1, 'Que toute personne soit soumise aux autorités supérieures; car il n''y a point d''autorité qui ne vienne de Dieu, et les autorités qui existent ont été instituées de Dieu.'),
  (45, 13, 2, 'C''est pourquoi celui qui s''oppose à l''autorité résiste à l''ordre que Dieu a établi, et ceux qui résistent attireront une condamnation sur eux-mêmes.'),
  (45, 13, 3, 'Ce n''est pas pour une bonne action, c''est pour une mauvaise, que les magistrats sont à redouter. Veux-tu ne pas craindre l''autorité? Fais-le bien, et tu auras son approbation.'),
  (45, 13, 4, 'Le magistrat est serviteur de Dieu pour ton bien. Mais si tu fais le mal, crains; car ce n''est pas en vain qu''il porte l''épée, étant serviteur de Dieu pour exercer la vengeance et punir celui qui fait le mal.'),
  (45, 13, 5, 'Il est donc nécessaire d''être soumis, non seulement par crainte de la punition, mais encore par motif de conscience.'),
  (45, 13, 6, 'C''est aussi pour cela que vous payez les impôts. Car les magistrats sont des ministres de Dieu entièrement appliqués à cette fonction.'),
  (45, 13, 7, 'Rendez à tous ce qui leur est dû: l''impôt à qui vous devez l''impôt, le tribut à qui vous devez le tribut, la crainte à qui vous devez la crainte, l''honneur à qui vous devez l''honneur.'),
  (45, 13, 8, 'Ne devez rien à personne, si ce n''est de vous aimer les uns les autres; car celui qui aime les autres a accompli la loi.'),
  (45, 13, 9, 'En effet, les commandements: Tu ne commettras point d''adultère, tu ne tueras point, tu ne déroberas point, tu ne convoiteras point, et ceux qu''il peut encore y avoir, se résument dans cette parole: Tu aimeras ton prochain comme toi-même.'),
  (45, 13, 10, 'L''amour ne fait point de mal au prochain: l''amour est donc l''accomplissement de la loi.'),
  (45, 13, 11, 'Cela importe d''autant plus que vous savez en quel temps nous sommes: c''est l''heure de vous réveiller enfin du sommeil, car maintenant le salut est plus près de nous que lorsque nous avons cru.'),
  (45, 13, 12, 'La nuit est avancée, le jour approche. Dépouillons-nous donc des œuvres des ténèbres, et revêtons les armes de la lumière.'),
  (45, 13, 13, 'Marchons honnêtement, comme en plein jour, loin des excès et de l''ivrognerie, de la luxure et de l''impudicité, des querelles et des jalousies.'),
  (45, 13, 14, 'Mais revêtez-vous du Seigneur Jésus-Christ, et n''ayez pas soin de la chair pour en satisfaire les convoitises.'),
  (45, 14, 1, 'Faites accueil à celui qui est faible dans la foi, et ne discutez pas sur les opinions.'),
  (45, 14, 2, 'Tel croit pouvoir manger de tout: tel autre, qui est faible, ne mange que des légumes.'),
  (45, 14, 3, 'Que celui qui mange ne méprise point celui qui ne mange pas, et que celui qui ne mange pas ne juge point celui qui mange, car Dieu l''a accueilli.'),
  (45, 14, 4, 'Qui es-tu, toi qui juges un serviteur d''autrui? S''il se tient debout, ou s''il tombe, cela regarde son maître. Mais il se tiendra debout, car le Seigneur a le pouvoir de l''affermir.'),
  (45, 14, 5, 'Tel fait une distinction entre les jours; tel autre les estime tous égaux. Que chacun ait en son esprit une pleine conviction.'),
  (45, 14, 6, 'Celui qui distingue entre les jours agit ainsi pour le Seigneur. Celui qui mange, c''est pour le Seigneur qu''il mange, car il rend grâces à Dieu; celui qui ne mange pas, c''est pour le Seigneur qu''il ne mange pas, et il rend grâces à Dieu.'),
  (45, 14, 7, 'En effet, nul de nous ne vit pour lui-même, et nul ne meurt pour lui-même.'),
  (45, 14, 8, 'Car si nous vivons, nous vivons pour le Seigneur; et si nous mourons, nous mourons pour le Seigneur. Soit donc que nous vivions, soit que nous mourions, nous sommes au Seigneur.'),
  (45, 14, 9, 'Car Christ est mort et il a vécu, afin de dominer sur les morts et sur les vivants.'),
  (45, 14, 10, 'Mais toi, pourquoi juges-tu ton frère? ou toi, pourquoi méprises-tu ton frère? puisque nous comparaîtrons tous devant le tribunal de Dieu.'),
  (45, 14, 11, 'Car il est écrit: Je suis vivant, dit le Seigneur, Tout genou fléchira devant moi, Et toute langue donnera gloire à Dieu.'),
  (45, 14, 12, 'Ainsi chacun de nous rendra compte à Dieu pour lui-même.'),
  (45, 14, 13, 'Ne nous jugeons donc plus les uns les autres; mais pensez plutôt à ne rien faire qui soit pour votre frère une pierre d''achoppement ou une occasion de chute.'),
  (45, 14, 14, 'Je sais et je suis persuadé par le Seigneur Jésus que rien n''est impur en soi, et qu''une chose n''est impure que pour celui qui la croit impure.'),
  (45, 14, 15, 'Mais si, pour un aliment, ton frère est attristé, tu ne marches plus selon l''amour: ne cause pas, par ton aliment, la perte de celui pour lequel Christ est mort.'),
  (45, 14, 16, 'Que votre privilège ne soit pas un sujet de calomnie.'),
  (45, 14, 17, 'Car le royaume de Dieu, ce n''est pas le manger et le boire, mais la justice, la paix et la joie, par le Saint-Esprit.'),
  (45, 14, 18, 'Celui qui sert Christ de cette manière est agréable à Dieu et approuvé des hommes.'),
  (45, 14, 19, 'Ainsi donc, recherchons ce qui contribue à la paix et à l''édification mutuelle.'),
  (45, 14, 20, 'Pour un aliment, ne détruis pas l''œuvre de Dieu. A la vérité toutes choses sont pures; mais il est mal à l''homme, quand il mange, de devenir une pierre d''achoppement.'),
  (45, 14, 21, 'Il est bien de ne pas manger de viande, de ne pas boire de vin, et de s''abstenir de ce qui peut être pour ton frère une occasion de chute, de scandale ou de faiblesse.'),
  (45, 14, 22, 'Cette foi que tu as, garde-la pour toi devant Dieu. Heureux celui qui ne se condamne pas lui-même dans ce qu''il approuve!'),
  (45, 14, 23, 'Mais celui qui a des doutes au sujet de ce qu''il mange est condamné, parce qu''il n''agit pas par conviction. Tout ce qui n''est pas le produit d''une conviction est péché.'),
  (45, 15, 1, 'Nous qui sommes forts, nous devons supporter les faiblesses de ceux qui ne le sont pas, et ne pas nous complaire en nous-mêmes.'),
  (45, 15, 2, 'Que chacun de nous complaise au prochain pour ce qui est bien en vue de l''édification.'),
  (45, 15, 3, 'Car Christ ne s''est point complu en lui-même, mais, selon qu''il est écrit: Les outrages de ceux qui t''insultent sont tombés sur moi.'),
  (45, 15, 4, 'Or, tout ce qui a été écrit d''avance l''a été pour notre instruction, afin que, par la patience, et par la consolation que donnent les Écritures, nous possédions l''espérance.'),
  (45, 15, 5, 'Que le Dieu de la persévérance et de la consolation vous donne d''avoir les mêmes sentiments les uns envers les autres selon Jésus-Christ,'),
  (45, 15, 6, 'afin que tous ensemble, d''une seule bouche, vous glorifiiez le Dieu et Père de notre Seigneur Jésus-Christ.'),
  (45, 15, 7, 'Accueillez-vous donc les uns les autres, comme Christ vous a accueillis, pour la gloire de Dieu.'),
  (45, 15, 8, 'Je dis, en effet, que Christ a été serviteur des circoncis, pour prouver la véracité de Dieu en confirmant les promesses faites aux pères,'),
  (45, 15, 9, 'tandis que les païens glorifient Dieu à cause de sa miséricorde, selon qu''il est écrit: C''est pourquoi je te louerai parmi les nations, Et je chanterai à la gloire de ton nom.'),
  (45, 15, 10, 'Il est dit encore: Nations, réjouissez-vous avec son peuple!'),
  (45, 15, 11, 'Et encore: Louez le Seigneur, vous toutes les nations, Célébrez-le, vous tous les peuples!'),
  (45, 15, 12, 'Ésaïe dit aussi: Il sortira d''Isaï un rejeton, Qui se lèvera pour régner sur les nations; Les nations espéreront en lui.'),
  (45, 15, 13, 'Que le Dieu de l''espérance vous remplisse de toute joie et de toute paix dans la foi, pour que vous abondiez en espérance, par la puissance du Saint-Esprit!'),
  (45, 15, 14, 'Pour ce qui vous concerne, mes frères, je suis moi-même persuadé que vous êtes pleins de bonnes dispositions, remplis de toute connaissance, et capables de vous exhorter les uns les autres.'),
  (45, 15, 15, 'Cependant, à certains égards, je vous ai écrit avec une sorte de hardiesse, comme pour réveiller vos souvenirs, à cause de la grâce que Dieu m''a faite'),
  (45, 15, 16, 'd''être ministre de Jésus-Christ parmi les païens, m''acquittant du divin service de l''Évangile de Dieu, afin que les païens lui soient une offrande agréable, étant sanctifiée par l''Esprit-Saint.'),
  (45, 15, 17, 'J''ai donc sujet de me glorifier en Jésus-Christ, pour ce qui regarde les choses de Dieu.'),
  (45, 15, 18, 'Car je n''oserais mentionner aucune chose que Christ n''ait pas faite par moi pour amener les païens à l''obéissance, par la parole et par les actes,'),
  (45, 15, 19, 'par la puissance des miracles et des prodiges, par la puissance de l''Esprit de Dieu, en sorte que, depuis Jérusalem et les pays voisins jusqu''en Illyrie, j''ai abondamment répandu l''Évangile de Christ.'),
  (45, 15, 20, 'Et je me suis fait honneur d''annoncer l''Évangile là où Christ n''avait point été nommé, afin de ne pas bâtir sur le fondement d''autrui,'),
  (45, 15, 21, 'selon qu''il est écrit: Ceux à qui il n''avait point été annoncé verront, Et ceux qui n''en avaient point entendu parler comprendront.'),
  (45, 15, 22, 'C''est ce qui m''a souvent empêché d''aller vers vous.'),
  (45, 15, 23, 'Mais maintenant, n''ayant plus rien qui me retienne dans ces contrées, et ayant depuis plusieurs années le désir d''aller vers vous,'),
  (45, 15, 24, 'j''espère vous voir en passant, quand je me rendrai en Espagne, et y être accompagné par vous, après que j''aurai satisfait en partie mon désir de me trouver chez vous.'),
  (45, 15, 25, 'Présentement je vais à Jérusalem, pour le service des saints.'),
  (45, 15, 26, 'Car la Macédoine et l''Achaïe ont bien voulu s''imposer une contribution en faveur des pauvres parmi les saints de Jérusalem.'),
  (45, 15, 27, 'Elles l''ont bien voulu, et elles le leur devaient; car si les païens ont eu part à leurs avantages spirituels, ils doivent aussi les assister dans les choses temporelles.'),
  (45, 15, 28, 'Dès que j''aurai terminé cette affaire et que je leur aurai remis ces dons, je partirai pour l''Espagne et passerai chez vous.'),
  (45, 15, 29, 'Je sais qu''en allant vers vous, c''est avec une pleine bénédiction de Christ que j''irai.'),
  (45, 15, 30, 'Je vous exhorte, frères, par notre Seigneur Jésus-Christ et par l''amour de l''Esprit, à combattre avec moi, en adressant à Dieu des prières en ma faveur,'),
  (45, 15, 31, 'afin que je sois délivré des incrédules de la Judée, et que les dons que je porte à Jérusalem soient agréés des saints,'),
  (45, 15, 32, 'en sorte que j''arrive chez vous avec joie, si c''est la volonté de Dieu, et que je jouisse au milieu de vous de quelque repos.'),
  (45, 15, 33, 'Que le Dieu de paix soit avec vous tous! Amen!'),
  (45, 16, 1, 'Je vous recommande Phoebé, notre sœur, qui est diaconesse de l''Église de Cenchrées,'),
  (45, 16, 2, 'afin que vous la receviez en notre Seigneur d''une manière digne des saints, et que vous l''assistiez dans les choses où elle aurait besoin de vous, car elle a donné aide à plusieurs et à moi-même.'),
  (45, 16, 3, 'Saluez Prisca et Aquilas, mes compagnons d''œuvre en Jésus-Christ,'),
  (45, 16, 4, 'qui ont exposé leur tête pour sauver ma vie; ce n''est pas moi seul qui leur rends grâces, ce sont encore toutes les Églises des païens.'),
  (45, 16, 5, 'Saluez aussi l''Église qui est dans leur maison. Saluez Épaïnète, mon bien-aimé, qui a été pour Christ les prémices de l''Asie.'),
  (45, 16, 6, 'Saluez Marie, qui a pris beaucoup de peine pour vous.'),
  (45, 16, 7, 'Saluez Andronicus et Junias, mes parents et mes compagnons de captivité, qui jouissent d''une grande considération parmi les apôtres, et qui même ont été en Christ avant moi.'),
  (45, 16, 8, 'Saluez Amplias, mon bien-aimé dans le Seigneur.'),
  (45, 16, 9, 'Saluez Urbain, notre compagnon d''œuvre en Christ, et Stachys, mon bien-aimé.'),
  (45, 16, 10, 'Saluez Apellès, qui est éprouvé en Christ. Saluez ceux de la maison d''Aristobule.'),
  (45, 16, 11, 'Saluez Hérodion, mon parent. Saluez ceux de la maison de Narcisse qui sont dans le Seigneur.'),
  (45, 16, 12, 'Saluez Tryphène et Tryphose, qui travaillent pour le Seigneur. Saluez Perside, la bien-aimée, qui a beaucoup travaillé pour le Seigneur.'),
  (45, 16, 13, 'Saluez Rufus, l''élu du Seigneur, et sa mère, qui est aussi la mienne.'),
  (45, 16, 14, 'Saluez Asyncrite, Phlégon, Hermès, Patrobas, Hermas, et les frères qui sont avec eux.'),
  (45, 16, 15, 'Saluez Philologue et Julie, Nérée et sa sœur, et Olympe, et tous les saints qui sont avec eux.'),
  (45, 16, 16, 'Saluez-vous les uns les autres par un saint baiser. Toutes les Églises de Christ vous saluent.'),
  (45, 16, 17, 'Je vous exhorte, frères, à prendre garde à ceux qui causent des divisions et des scandales, au préjudice de l''enseignement que vous avez reçu. Éloignez-vous d''eux.'),
  (45, 16, 18, 'Car de tels hommes ne servent point Christ notre Seigneur, mais leur propre ventre; et, par des paroles douces et flatteuses, ils séduisent les cœurs des simples.'),
  (45, 16, 19, 'Pour vous, votre obéissance est connue de tous; je me réjouis donc à votre sujet, et je désire que vous soyez sages en ce qui concerne le bien et purs en ce qui concerne le mal.'),
  (45, 16, 20, 'Le Dieu de paix écrasera bientôt Satan sous vos pieds. Que la grâce de notre Seigneur Jésus-Christ soit avec vous!'),
  (45, 16, 21, 'Timothée, mon compagnon d''œuvre, vous salue, ainsi que Lucius, Jason et Sosipater, mes parents.'),
  (45, 16, 22, 'Je vous salue dans le Seigneur, moi Tertius, qui ai écrit cette lettre.'),
  (45, 16, 23, 'Gaïus, mon hôte et celui de toute l''Église, vous salue. Éraste, le trésorier de la ville, vous salue, ainsi que le frère Quartus.'),
  (45, 16, 24, 'Que la grâce de notre Seigneur Jésus-Christ soit avec vous tous! Amen!'),
  (45, 16, 25, 'A celui qui peut vous affermir selon mon Évangile et la prédication de Jésus-Christ, conformément à la révélation du mystère caché pendant des siècles,'),
  (45, 16, 26, 'mais manifesté maintenant par les écrits des prophètes, d''après l''ordre du Dieu éternel, et porté à la connaissance de toutes les nations, afin qu''elles obéissent à la foi,'),
  (45, 16, 27, 'à Dieu, seul sage, soit la gloire aux siècles des siècles, par Jésus-Christ! Amen!'),
  (46, 1, 1, 'Paul, appelé à être apôtre de Jésus-Christ par la volonté de Dieu, et le frère Sosthène,'),
  (46, 1, 2, 'à l''Église de Dieu qui est à Corinthe, à ceux qui ont été sanctifiés en Jésus-Christ, appelés à être saints, et à tous ceux qui invoquent en quelque lieu que ce soit le nom de notre Seigneur Jésus-Christ, leur Seigneur et le nôtre:'),
  (46, 1, 3, 'que la grâce et la paix vous soient données de la part de Dieu notre Père et du Seigneur Jésus-Christ!'),
  (46, 1, 4, 'Je rends à mon Dieu de continuelles actions de grâces à votre sujet, pour la grâce de Dieu qui vous a été accordée en Jésus-Christ.'),
  (46, 1, 5, 'Car en lui vous avez été comblés de toutes les richesses qui concernent la parole et la connaissance,'),
  (46, 1, 6, 'le témoignage de Christ ayant été solidement établi parmi vous,'),
  (46, 1, 7, 'de sorte qu''il ne vous manque aucun don, dans l''attente où vous êtes de la manifestation de notre Seigneur Jésus-Christ.'),
  (46, 1, 8, 'Il vous affermira aussi jusqu''à la fin, pour que vous soyez irréprochables au jour de notre Seigneur Jésus-Christ.'),
  (46, 1, 9, 'Dieu est fidèle, lui qui vous a appelés à la communion de son Fils, Jésus-Christ notre Seigneur.'),
  (46, 1, 10, 'Je vous exhorte, frères, par le nom de notre Seigneur Jésus-Christ, à tenir tous un même langage, et à ne point avoir de divisions parmi vous, mais à être parfaitement unis dans un même esprit et dans un même sentiment.'),
  (46, 1, 11, 'Car, mes frères, j''ai appris à votre sujet, par les gens de Chloé, qu''il y a des disputes au milieu de vous.'),
  (46, 1, 12, 'Je veux dire que chacun de vous parle ainsi: Moi, je suis de Paul! et moi, d''Apollos! et moi, de Céphas! et moi, de Christ!'),
  (46, 1, 13, 'Christ est-il divisé? Paul a-t-il été crucifié pour vous, ou est-ce au nom de Paul que vous avez été baptisés?'),
  (46, 1, 14, 'Je rends grâces à Dieu de ce que je n''ai baptisé aucun de vous, excepté Crispus et Gaïus,'),
  (46, 1, 15, 'afin que personne ne dise que vous avez été baptisés en mon nom.'),
  (46, 1, 16, 'J''ai encore baptisé la famille de Stéphanas; du reste, je ne sache pas que j''aie baptisé quelque autre personne.'),
  (46, 1, 17, 'Ce n''est pas pour baptiser que Christ m''a envoyé, c''est pour annoncer l''Évangile, et cela sans la sagesse du langage, afin que la croix de Christ ne soit pas rendue vaine.'),
  (46, 1, 18, 'Car la prédication de la croix est une folie pour ceux qui périssent; mais pour nous qui sommes sauvés, elle est une puissance de Dieu.'),
  (46, 1, 19, 'Aussi est-il écrit: Je détruirai la sagesse des sages, Et j''anéantirai l''intelligence des intelligents.'),
  (46, 1, 20, 'Où est le sage? où est le scribe? où est le disputeur de ce siècle? Dieu n''a-t-il pas convaincu de folie la sagesse du monde?'),
  (46, 1, 21, 'Car puisque le monde, avec sa sagesse, n''a point connu Dieu dans la sagesse de Dieu, il a plu à Dieu de sauver les croyants par la folie de la prédication.'),
  (46, 1, 22, 'Les Juifs demandent des miracles et les Grecs cherchent la sagesse:'),
  (46, 1, 23, 'nous, nous prêchons Christ crucifié; scandale pour les Juifs et folie pour les païens,'),
  (46, 1, 24, 'mais puissance de Dieu et sagesse de Dieu pour ceux qui sont appelés, tant Juifs que Grecs.'),
  (46, 1, 25, 'Car la folie de Dieu est plus sage que les hommes, et la faiblesse de Dieu est plus forte que les hommes.'),
  (46, 1, 26, 'Considérez, frères, que parmi vous qui avez été appelés il n''y a ni beaucoup de sages selon la chair, ni beaucoup de puissants, ni beaucoup de nobles.'),
  (46, 1, 27, 'Mais Dieu a choisi les choses folles du monde pour confondre les sages; Dieu a choisi les choses faibles du monde pour confondre les fortes;'),
  (46, 1, 28, 'et Dieu a choisi les choses viles du monde et celles qu''on méprise, celles qui ne sont point, pour réduire à néant celles qui sont,'),
  (46, 1, 29, 'afin que nulle chair ne se glorifie devant Dieu.'),
  (46, 1, 30, 'Or, c''est par lui que vous êtes en Jésus-Christ, lequel, de par Dieu, a été fait pour nous sagesse, justice et sanctification et rédemption,'),
  (46, 1, 31, 'afin, comme il est écrit, Que celui qui se glorifie se glorifie dans le Seigneur.'),
  (46, 2, 1, 'Pour moi, frères, lorsque je suis allé chez vous, ce n''est pas avec une supériorité de langage ou de sagesse que je suis allé vous annoncer le témoignage de Dieu.'),
  (46, 2, 2, 'Car je n''ai pas eu la pensée de savoir parmi vous autre chose que Jésus-Christ, et Jésus-Christ crucifié.'),
  (46, 2, 3, 'Moi-même j''étais auprès de vous dans un état de faiblesse, de crainte, et de grand tremblement;'),
  (46, 2, 4, 'et ma parole et ma prédication ne reposaient pas sur les discours persuasifs de la sagesse, mais sur une démonstration d''Esprit et de puissance,'),
  (46, 2, 5, 'afin que votre foi fût fondée, non sur la sagesse des hommes, mais sur la puissance de Dieu.'),
  (46, 2, 6, 'Cependant, c''est une sagesse que nous prêchons parmi les parfaits, sagesse qui n''est pas de ce siècle, ni des chefs de ce siècle, qui vont être anéantis;'),
  (46, 2, 7, 'nous prêchons la sagesse de Dieu, mystérieuse et cachée, que Dieu, avant les siècles, avait destinée pour notre gloire,'),
  (46, 2, 8, 'sagesse qu''aucun des chefs de ce siècle n''a connue, car, s''ils l''eussent connue, ils n''auraient pas crucifié le Seigneur de gloire.'),
  (46, 2, 9, 'Mais, comme il est écrit, ce sont des choses que l''œil n''a point vues, que l''oreille n''a point entendues, et qui ne sont point montées au cœur de l''homme, des choses que Dieu a préparées pour ceux qui l''aiment.'),
  (46, 2, 10, 'Dieu nous les a révélées par l''Esprit. Car l''Esprit sonde tout, même les profondeurs de Dieu.'),
  (46, 2, 11, 'Lequel des hommes, en effet, connaît les choses de l''homme, si ce n''est l''esprit de l''homme qui est en lui? De même, personne ne connaît les choses de Dieu, si ce n''est l''Esprit de Dieu.'),
  (46, 2, 12, 'Or nous, nous n''avons pas reçu l''esprit du monde, mais l''Esprit qui vient de Dieu, afin que nous connaissions les choses que Dieu nous a données par sa grâce.'),
  (46, 2, 13, 'Et nous en parlons, non avec des discours qu''enseigne la sagesse humaine, mais avec ceux qu''enseigne l''Esprit, employant un langage spirituel pour les choses spirituelles.'),
  (46, 2, 14, 'Mais l''homme animal ne reçoit pas les choses de l''Esprit de Dieu, car elles sont une folie pour lui, et il ne peut les connaître, parce que c''est spirituellement qu''on en juge.'),
  (46, 2, 15, 'L''homme spirituel, au contraire, juge de tout, et il n''est lui-même jugé par personne.'),
  (46, 2, 16, 'Car Qui a connu la pensée du Seigneur, Pour l''instruire? Or nous, nous avons la pensée de Christ.'),
  (46, 3, 1, 'Pour moi, frères, ce n''est pas comme à des hommes spirituels que j''ai pu vous parler, mais comme à des hommes charnels, comme à des enfants en Christ.'),
  (46, 3, 2, 'Je vous ai donné du lait, non de la nourriture solide, car vous ne pouviez pas la supporter; et vous ne le pouvez pas même à présent,'),
  (46, 3, 3, 'parce que vous êtes encore charnels. En effet, puisqu''il y a parmi vous de la jalousie et des disputes, n''êtes-vous pas charnels, et ne marchez-vous pas selon l''homme?'),
  (46, 3, 4, 'Quand l''un dit: Moi, je suis de Paul! et un autre: Moi, d''Apollos! n''êtes-vous pas des hommes?'),
  (46, 3, 5, 'Qu''est-ce donc qu''Apollos, et qu''est-ce que Paul? Des serviteurs, par le moyen desquels vous avez cru, selon que le Seigneur l''a donné à chacun.'),
  (46, 3, 6, 'J''ai planté, Apollos a arrosé, mais Dieu a fait croître,'),
  (46, 3, 7, 'en sorte que ce n''est pas celui qui plante qui est quelque chose, ni celui qui arrose, mais Dieu qui fait croître.'),
  (46, 3, 8, 'Celui qui plante et celui qui arrose sont égaux, et chacun recevra sa propre récompense selon son propre travail.'),
  (46, 3, 9, 'Car nous sommes ouvriers avec Dieu. Vous êtes le champ de Dieu, l''édifice de Dieu.'),
  (46, 3, 10, 'Selon la grâce de Dieu qui m''a été donnée, j''ai posé le fondement comme un sage architecte, et un autre bâtit dessus. Mais que chacun prenne garde à la manière dont il bâtit dessus.'),
  (46, 3, 11, 'Car personne ne peut poser un autre fondement que celui qui a été posé, savoir Jésus-Christ.'),
  (46, 3, 12, 'Or, si quelqu''un bâtit sur ce fondement avec de l''or, de l''argent, des pierres précieuses, du bois, du foin, du chaume,'),
  (46, 3, 13, 'l''œuvre de chacun sera manifestée; car le jour la fera connaître, parce qu''elle se révèlera dans le feu, et le feu éprouvera ce qu''est l''œuvre de chacun.'),
  (46, 3, 14, 'Si l''œuvre bâtie par quelqu''un sur le fondement subsiste, il recevra une récompense.'),
  (46, 3, 15, 'Si l''œuvre de quelqu''un est consumée, il perdra sa récompense; pour lui, il sera sauvé, mais comme au travers du feu.'),
  (46, 3, 16, 'Ne savez-vous pas que vous êtes le temple de Dieu, et que l''Esprit de Dieu habite en vous?'),
  (46, 3, 17, 'Si quelqu''un détruit le temple de Dieu, Dieu le détruira; car le temple de Dieu est saint, et c''est ce que vous êtes.'),
  (46, 3, 18, 'Que nul ne s''abuse lui-même: si quelqu''un parmi vous pense être sage selon ce siècle, qu''il devienne fou, afin de devenir sage.'),
  (46, 3, 19, 'Car la sagesse de ce monde est une folie devant Dieu. Aussi est-il écrit: Il prend les sages dans leur ruse.'),
  (46, 3, 20, 'Et encore: Le Seigneur connaît les pensées des sages, Il sait qu''elles sont vaines.'),
  (46, 3, 21, 'Que personne donc ne mette sa gloire dans des hommes; car tout est à vous,'),
  (46, 3, 22, 'soit Paul, soit Apollos, soit Céphas, soit le monde, soit la vie, soit la mort, soit les choses présentes, soit les choses à venir. Tout est à vous;'),
  (46, 3, 23, 'et vous êtes à Christ, et Christ est à Dieu.'),
  (46, 4, 1, 'Ainsi, qu''on nous regarde comme des serviteurs de Christ, et des dispensateurs des mystères de Dieu.'),
  (46, 4, 2, 'Du reste, ce qu''on demande des dispensateurs, c''est que chacun soit trouvé fidèle.'),
  (46, 4, 3, 'Pour moi, il m''importe fort peu d''être jugé par vous, ou par un tribunal humain. Je ne me juge pas non plus moi-même,'),
  (46, 4, 4, 'car je ne me sens coupable de rien; mais ce n''est pas pour cela que je suis justifié. Celui qui me juge, c''est le Seigneur.'),
  (46, 4, 5, 'C''est pourquoi ne jugez de rien avant le temps, jusqu''à ce que vienne le Seigneur, qui mettra en lumière ce qui est caché dans les ténèbres, et qui manifestera les desseins des cœurs. Alors chacun recevra de Dieu la louange qui lui sera due.'),
  (46, 4, 6, 'C''est à cause de vous, frères, que j''ai fait de ces choses une application à ma personne et à celle d''Apollos, afin que vous appreniez en nos personnes à ne pas aller au delà de ce qui est écrit, et que nul de vous ne conçoive de l''orgueil en faveur de l''un contre l''autre.'),
  (46, 4, 7, 'Car qui est-ce qui te distingue? Qu''as-tu que tu n''aies reçu? Et si tu l''as reçu, pourquoi te glorifies-tu, comme si tu ne l''avais pas reçu?'),
  (46, 4, 8, 'Déjà vous êtes rassasiés, déjà vous êtes riches, sans nous vous avez commencé à régner. Et puissiez-vous régner en effet, afin que nous aussi nous régnions avec vous!'),
  (46, 4, 9, 'Car Dieu, ce me semble, a fait de nous, apôtres, les derniers des hommes, des condamnés à mort en quelque sorte, puisque nous avons été en spectacle au monde, aux anges et aux hommes.'),
  (46, 4, 10, 'Nous sommes fous à cause de Christ; mais vous, vous êtes sages en Christ; nous sommes faibles, mais vous êtes forts. Vous êtes honorés, et nous sommes méprisés!'),
  (46, 4, 11, 'Jusqu''à cette heure, nous souffrons la faim, la soif, la nudité; nous sommes maltraités, errants çà et là;'),
  (46, 4, 12, 'nous nous fatiguons à travailler de nos propres mains; injuriés, nous bénissons; persécutés, nous supportons;'),
  (46, 4, 13, 'calomniés, nous parlons avec bonté; nous sommes devenus comme les balayures du monde, le rebut de tous, jusqu''à maintenant.'),
  (46, 4, 14, 'Ce n''est pas pour vous faire honte que j''écris ces choses; mais je vous avertis comme mes enfants bien-aimés.'),
  (46, 4, 15, 'Car, quand vous auriez dix mille maîtres en Christ, vous n''avez cependant pas plusieurs pères, puisque c''est moi qui vous ai engendrés en Jésus-Christ par l''Évangile.'),
  (46, 4, 16, 'Je vous en conjure donc, soyez mes imitateurs.'),
  (46, 4, 17, 'Pour cela je vous ai envoyé Timothée, qui est mon enfant bien-aimé et fidèle dans le Seigneur; il vous rappellera quelles sont mes voies en Christ, quelle est la manière dont j''enseigne partout dans toutes les Églises.'),
  (46, 4, 18, 'Quelques-uns se sont enflés d''orgueil, comme si je ne devais pas aller chez vous.'),
  (46, 4, 19, 'Mais j''irai bientôt chez vous, si c''est la volonté du Seigneur, et je connaîtrai, non les paroles, mais la puissance de ceux qui se sont enflés.'),
  (46, 4, 20, 'Car le royaume de Dieu ne consiste pas en paroles, mais en puissance.'),
  (46, 4, 21, 'Que voulez-vous? Que j''aille chez vous avec une verge, ou avec amour et dans un esprit de douceur?'),
  (46, 5, 1, 'On entend dire généralement qu''il y a parmi vous de l''impudicité, et une impudicité telle qu''elle ne se rencontre pas même chez les païens; c''est au point que l''un de vous a la femme de son père.'),
  (46, 5, 2, 'Et vous êtes enflés d''orgueil! Et vous n''avez pas été plutôt dans l''affliction, afin que celui qui a commis cet acte fût ôté du milieu de vous!'),
  (46, 5, 3, 'Pour moi, absent de corps, mais présent d''esprit, j''ai déjà jugé, comme si j''étais présent, celui qui a commis un tel acte.'),
  (46, 5, 4, 'Au nom du Seigneur Jésus, vous et mon esprit étant assemblés avec la puissance de notre Seigneur Jésus,'),
  (46, 5, 5, 'qu''un tel homme soit livré à Satan pour la destruction de la chair, afin que l''esprit soit sauvé au jour du Seigneur Jésus.'),
  (46, 5, 6, 'C''est bien à tort que vous vous glorifiez. Ne savez-vous pas qu''un peu de levain fait lever toute la pâte?'),
  (46, 5, 7, 'Faites disparaître le vieux levain, afin que vous soyez une pâte nouvelle, puisque vous êtes sans levain, car Christ, notre Pâque, a été immolé.'),
  (46, 5, 8, 'Célébrons donc la fête, non avec du vieux levain, non avec un levain de malice et de méchanceté, mais avec les pains sans levain de la pureté et de la vérité.'),
  (46, 5, 9, 'Je vous ai écrit dans ma lettre de ne pas avoir des relations avec les impudiques, -'),
  (46, 5, 10, 'non pas d''une manière absolue avec les impudiques de ce monde, ou avec les cupides et les ravisseurs, ou avec les idolâtres; autrement, il vous faudrait sortir du monde.'),
  (46, 5, 11, 'Maintenant, ce que je vous ai écrit, c''est de ne pas avoir des relations avec quelqu''un qui, se nommant frère, est impudique, ou cupide, ou idolâtre, ou outrageux, ou ivrogne, ou ravisseur, de ne pas même manger avec un tel homme.'),
  (46, 5, 12, 'Qu''ai-je, en effet, à juger ceux du dehors? N''est-ce pas ceux du dedans que vous avez à juger?'),
  (46, 5, 13, 'Pour ceux du dehors, Dieu les juge. Otez le méchant du milieu de vous.'),
  (46, 6, 1, 'Quelqu''un de vous, lorsqu''il a un différend avec un autre, ose-t-il plaider devant les injustes, et non devant les saints?'),
  (46, 6, 2, 'Ne savez-vous pas que les saints jugeront le monde? Et si c''est par vous que le monde est jugé, êtes-vous indignes de rendre les moindres jugements?'),
  (46, 6, 3, 'Ne savez-vous pas que nous jugerons les anges? Et nous ne jugerions pas, à plus forte raison, les choses de cette vie?'),
  (46, 6, 4, 'Quand donc vous avez des différends pour les choses de cette vie, ce sont des gens dont l''Église ne fait aucun cas que vous prenez pour juges!'),
  (46, 6, 5, 'Je le dis à votre honte. Ainsi il n''y a parmi vous pas un seul homme sage qui puisse prononcer entre ses frères.'),
  (46, 6, 6, 'Mais un frère plaide contre un frère, et cela devant des infidèles!'),
  (46, 6, 7, 'C''est déjà certes un défaut chez vous que d''avoir des procès les uns avec les autres. Pourquoi ne souffrez-vous pas plutôt quelque injustice? Pourquoi ne vous laissez-vous pas plutôt dépouiller?'),
  (46, 6, 8, 'Mais c''est vous qui commettez l''injustice et qui dépouillez, et c''est envers des frères que vous agissez de la sorte!'),
  (46, 6, 9, 'Ne savez-vous pas que les injustes n''hériteront point le royaume de Dieu? Ne vous y trompez pas: ni les impudiques, ni les idolâtres, ni les adultères, ni les efféminés, ni les infâmes,'),
  (46, 6, 10, 'ni les voleurs, ni les cupides, ni les ivrognes, ni les outrageux, ni les ravisseurs, n''hériteront le royaume de Dieu.'),
  (46, 6, 11, 'Et c''est là ce que vous étiez, quelques-uns de vous. Mais vous avez été lavés, mais vous avez été sanctifiés, mais vous avez été justifiés au nom du Seigneur Jésus-Christ, et par l''Esprit de notre Dieu.'),
  (46, 6, 12, 'Tout m''est permis, mais tout n''est pas utile; tout m''est permis, mais je ne me laisserai asservir par quoi que ce soit.'),
  (46, 6, 13, 'Les aliments sont pour le ventre, et le ventre pour les aliments; et Dieu détruira l''un comme les autres. Mais le corps n''est pas pour l''impudicité. Il est pour le Seigneur, et le Seigneur pour le corps.'),
  (46, 6, 14, 'Et Dieu, qui a ressuscité le Seigneur, nous ressuscitera aussi par sa puissance.'),
  (46, 6, 15, 'Ne savez-vous pas que vos corps sont des membres de Christ? Prendrai-je donc les membres de Christ, pour en faire les membres d''une prostituée? Loin de là!'),
  (46, 6, 16, 'Ne savez-vous pas que celui qui s''attache à la prostituée est un seul corps avec elle? Car, est-il dit, les deux deviendront une seule chair.'),
  (46, 6, 17, 'Mais celui qui s''attache au Seigneur est avec lui un seul esprit.'),
  (46, 6, 18, 'Fuyez l''impudicité. Quelque autre péché qu''un homme commette, ce péché est hors du corps; mais celui qui se livre à l''impudicité pèche contre son propre corps.'),
  (46, 6, 19, 'Ne savez-vous pas que votre corps est le temple du Saint-Esprit qui est en vous, que vous avez reçu de Dieu, et que vous ne vous appartenez point à vous-mêmes?'),
  (46, 6, 20, 'Car vous avez été rachetés à un grand prix. Glorifiez donc Dieu dans votre corps et dans votre esprit, qui appartiennent à Dieu.'),
  (46, 7, 1, 'Pour ce qui concerne les choses dont vous m''avez écrit, je pense qu''il est bon pour l''homme de ne point toucher de femme.'),
  (46, 7, 2, 'Toutefois, pour éviter l''impudicité, que chacun ait sa femme, et que chaque femme ait son mari.'),
  (46, 7, 3, 'Que le mari rende à sa femme ce qu''il lui doit, et que la femme agisse de même envers son mari.'),
  (46, 7, 4, 'La femme n''a pas autorité sur son propre corps, mais c''est le mari; et pareillement, le mari n''a pas autorité sur son propre corps, mais c''est la femme.'),
  (46, 7, 5, 'Ne vous privez point l''un de l''autre, si ce n''est d''un commun accord pour un temps, afin de vaquer à la prière; puis retournez ensemble, de peur que Satan ne vous tente par votre incontinence.'),
  (46, 7, 6, 'Je dis cela par condescendance, je n''en fais pas un ordre.'),
  (46, 7, 7, 'Je voudrais que tous les hommes fussent comme moi; mais chacun tient de Dieu un don particulier, l''un d''une manière, l''autre d''une autre.'),
  (46, 7, 8, 'A ceux qui ne sont pas mariés et aux veuves, je dis qu''il leur est bon de rester comme moi.'),
  (46, 7, 9, 'Mais s''ils manquent de continence, qu''ils se marient; car il vaut mieux se marier que de brûler.'),
  (46, 7, 10, 'A ceux qui sont mariés, j''ordonne, non pas moi, mais le Seigneur, que la femme ne se sépare point de son mari'),
  (46, 7, 11, '(si elle est séparée, qu''elle demeure sans se marier ou qu''elle se réconcilie avec son mari), et que le mari ne répudie point sa femme.'),
  (46, 7, 12, 'Aux autres, ce n''est pas le Seigneur, c''est moi qui dis: Si un frère a une femme non-croyante, et qu''elle consente à habiter avec lui, qu''il ne la répudie point;'),
  (46, 7, 13, 'et si une femme a un mari non-croyant, et qu''il consente à habiter avec elle, qu''elle ne répudie point son mari.'),
  (46, 7, 14, 'Car le mari non-croyant est sanctifié par la femme, et la femme non-croyante est sanctifiée par le frère; autrement, vos enfants seraient impurs, tandis que maintenant ils sont saints.'),
  (46, 7, 15, 'Si le non-croyant se sépare, qu''il se sépare; le frère ou la sœur ne sont pas liés dans ces cas-là. Dieu nous a appelés à vivre en paix.'),
  (46, 7, 16, 'Car que sais-tu, femme, si tu sauveras ton mari? Ou que sais-tu, mari, si tu sauveras ta femme?'),
  (46, 7, 17, 'Seulement, que chacun marche selon la part que le Seigneur lui a faite, selon l''appel qu''il a reçu de Dieu. C''est ainsi que je l''ordonne dans toutes les Églises.'),
  (46, 7, 18, 'Quelqu''un a-t-il été appelé étant circoncis, qu''il demeure circoncis; quelqu''un a-t-il été appelé étant incirconcis, qu''il ne se fasse pas circoncire.'),
  (46, 7, 19, 'La circoncision n''est rien, et l''incirconcision n''est rien, mais l''observation des commandements de Dieu est tout.'),
  (46, 7, 20, 'Que chacun demeure dans l''état où il était lorsqu''il a été appelé.'),
  (46, 7, 21, 'As-tu été appelé étant esclave, ne t''en inquiète pas; mais si tu peux devenir libre, profites-en plutôt.'),
  (46, 7, 22, 'Car l''esclave qui a été appelé dans le Seigneur est un affranchi du Seigneur; de même, l''homme libre qui a été appelé est un esclave de Christ.'),
  (46, 7, 23, 'Vous avez été rachetés à un grand prix; ne devenez pas esclaves des hommes.'),
  (46, 7, 24, 'Que chacun, frères, demeure devant Dieu dans l''état où il était lorsqu''il a été appelé.'),
  (46, 7, 25, 'Pour ce qui est des vierges, je n''ai point d''ordre du Seigneur; mais je donne un avis, comme ayant reçu du Seigneur miséricorde pour être fidèle.'),
  (46, 7, 26, 'Voici donc ce que j''estime bon, à cause des temps difficiles qui s''approchent: il est bon à un homme d''être ainsi.'),
  (46, 7, 27, 'Es-tu lié à une femme, ne cherche pas à rompre ce lien; n''es-tu pas lié à une femme, ne cherche pas une femme.'),
  (46, 7, 28, 'Si tu t''es marié, tu n''as point péché; et si la vierge s''est mariée, elle n''a point péché; mais ces personnes auront des tribulations dans la chair, et je voudrais vous les épargner.'),
  (46, 7, 29, 'Voici ce que je dis, frères, c''est que le temps est court; que désormais ceux qui ont des femmes soient comme n''en ayant pas,'),
  (46, 7, 30, 'ceux qui pleurent comme ne pleurant pas, ceux qui se réjouissent comme ne se réjouissant pas, ceux qui achètent comme ne possédant pas,'),
  (46, 7, 31, 'et ceux qui usent du monde comme n''en usant pas, car la figure de ce monde passe.'),
  (46, 7, 32, 'Or, je voudrais que vous fussiez sans inquiétude. Celui qui n''est pas marié s''inquiète des choses du Seigneur, des moyens de plaire au Seigneur;'),
  (46, 7, 33, 'et celui qui est marié s''inquiète des choses du monde, des moyens de plaire à sa femme.'),
  (46, 7, 34, 'Il y a de même une différence entre la femme et la vierge: celle qui n''est pas mariée s''inquiète des choses du Seigneur, afin d''être sainte de corps et d''esprit; et celle qui est mariée s''inquiète des choses du monde, des moyens de plaire à son mari.'),
  (46, 7, 35, 'Je dis cela dans votre intérêt; ce n''est pas pour vous prendre au piège, c''est pour vous porter à ce qui est bienséant et propre à vous attacher au Seigneur sans distraction.'),
  (46, 7, 36, 'Si quelqu''un regarde comme déshonorant pour sa fille de dépasser l''âge nubile, et comme nécessaire de la marier, qu''il fasse ce qu''il veut, il ne pèche point; qu''on se marie.'),
  (46, 7, 37, 'Mais celui qui a pris une ferme résolution, sans contrainte et avec l''exercice de sa propre volonté, et qui a décidé en son cœur de garder sa fille vierge, celui-là fait bien.'),
  (46, 7, 38, 'Ainsi, celui qui marie sa fille fait bien, et celui qui ne la marie pas fait mieux.'),
  (46, 7, 39, 'Une femme est liée aussi longtemps que son mari est vivant; mais si le mari meurt, elle est libre de se marier à qui elle veut; seulement, que ce soit dans le Seigneur.'),
  (46, 7, 40, 'Elle est plus heureuse, néanmoins, si elle demeure comme elle est, suivant mon avis. Et moi aussi, je crois avoir l''Esprit de Dieu.'),
  (46, 8, 1, 'Pour ce qui concerne les viandes sacrifiées aux idoles, nous savons que nous avons tous la connaissance. -La connaissance enfle, mais la charité édifie.'),
  (46, 8, 2, 'Si quelqu''un croit savoir quelque chose, il n''a pas encore connu comme il faut connaître.'),
  (46, 8, 3, 'Mais si quelqu''un aime Dieu, celui-là est connu de lui. -'),
  (46, 8, 4, 'Pour ce qui est donc de manger des viandes sacrifiées aux idoles, nous savons qu''il n''y a point d''idole dans le monde, et qu''il n''y a qu''un seul Dieu.'),
  (46, 8, 5, 'Car, s''il est des êtres qui sont appelés dieux, soit dans le ciel, soit sur la terre, comme il existe réellement plusieurs dieux et plusieurs seigneurs,'),
  (46, 8, 6, 'néanmoins pour nous il n''y a qu''un seul Dieu, le Père, de qui viennent toutes choses et pour qui nous sommes, et un seul Seigneur, Jésus-Christ, par qui sont toutes choses et par qui nous sommes.'),
  (46, 8, 7, 'Mais cette connaissance n''est pas chez tous. Quelques-uns, d''après la manière dont ils envisagent encore l''idole, mangent de ces viandes comme étant sacrifiées aux idoles, et leur conscience, qui est faible, en est souillée.'),
  (46, 8, 8, 'Ce n''est pas un aliment qui nous rapproche de Dieu: si nous en mangeons, nous n''avons rien de plus; si nous n''en mangeons pas, nous n''avons rien de moins.'),
  (46, 8, 9, 'Prenez garde, toutefois, que votre liberté ne devienne une pierre d''achoppement pour les faibles.'),
  (46, 8, 10, 'Car, si quelqu''un te voit, toi qui as de la connaissance, assis à table dans un temple d''idoles, sa conscience, à lui qui est faible, ne le portera-t-elle pas à manger des viandes sacrifiées aux idoles?'),
  (46, 8, 11, 'Et ainsi le faible périra par ta connaissance, le frère pour lequel Christ est mort!'),
  (46, 8, 12, 'En péchant de la sorte contre les frères, et en blessant leur conscience faible, vous péchez contre Christ.'),
  (46, 8, 13, 'C''est pourquoi, si un aliment scandalise mon frère, je ne mangerai jamais de viande, afin de ne pas scandaliser mon frère.'),
  (46, 9, 1, 'Ne suis-je pas libre? Ne suis-je pas apôtre? N''ai-je pas vu Jésus notre Seigneur? N''êtes-vous pas mon œuvre dans le Seigneur?'),
  (46, 9, 2, 'Si pour d''autres je ne suis pas apôtre, je le suis au moins pour vous; car vous êtes le sceau de mon apostolat dans le Seigneur.'),
  (46, 9, 3, 'C''est là ma défense contre ceux qui m''accusent.'),
  (46, 9, 4, 'N''avons-nous pas le droit de manger et de boire?'),
  (46, 9, 5, 'N''avons-nous pas le droit de mener avec nous une sœur qui soit notre femme, comme font les autres apôtres, et les frères du Seigneur, et Céphas?'),
  (46, 9, 6, 'Ou bien, est-ce que moi seul et Barnabas nous n''avons pas le droit de ne point travailler?'),
  (46, 9, 7, 'Qui jamais fait le service militaire à ses propres frais? Qui est-ce qui plante une vigne, et n''en mange pas le fruit? Qui est-ce qui fait paître un troupeau, et ne se nourrit pas du lait du troupeau?'),
  (46, 9, 8, 'Ces choses que je dis, n''existent-elles que dans les usages des hommes? la loi ne les dit-elle pas aussi?'),
  (46, 9, 9, 'Car il est écrit dans la loi de Moïse: Tu n''emmuselleras point le bœuf quand il foule le grain. Dieu se met-il en peine des bœufs,'),
  (46, 9, 10, 'ou parle-t-il uniquement à cause de nous? Oui, c''est à cause de nous qu''il a été écrit que celui qui laboure doit labourer avec espérance, et celui qui foule le grain fouler avec l''espérance d''y avoir part.'),
  (46, 9, 11, 'Si nous avons semé parmi vous les biens spirituels, est-ce une grosse affaire si nous moissonnons vos biens temporels.'),
  (46, 9, 12, 'Si d''autres jouissent de ce droit sur vous, n''est-ce pas plutôt à nous d''en jouir? Mais nous n''avons point usé de ce droit; au contraire, nous souffrons tout, afin de ne pas créer d''obstacle à l''Évangile de Christ.'),
  (46, 9, 13, 'Ne savez-vous pas que ceux qui remplissent les fonctions sacrées sont nourris par le temple, que ceux qui servent à l''autel ont part à l''autel?'),
  (46, 9, 14, 'De même aussi, le Seigneur a ordonné à ceux qui annoncent l''Évangile de vivre de l''Évangile.'),
  (46, 9, 15, 'Pour moi, je n''ai usé d''aucun de ces droits, et ce n''est pas afin de les réclamer en ma faveur que j''écris ainsi; car j''aimerais mieux mourir que de me laisser enlever ce sujet de gloire.'),
  (46, 9, 16, 'Si j''annonce l''Évangile, ce n''est pas pour moi un sujet de gloire, car la nécessité m''en est imposée, et malheur à moi si je n''annonce pas l''Évangile!'),
  (46, 9, 17, 'Si je le fais de bon cœur, j''en ai la récompense; mais si je le fais malgré moi, c''est une charge qui m''est confiée.'),
  (46, 9, 18, 'Quelle est donc ma récompense? C''est d''offrir gratuitement l''Évangile que j''annonce, sans user de mon droit de prédicateur de l''Évangile.'),
  (46, 9, 19, 'Car, bien que je sois libre à l''égard de tous, je me suis rendu le serviteur de tous, afin de gagner le plus grand nombre.'),
  (46, 9, 20, 'Avec les Juifs, j''ai été comme Juif, afin de gagner les Juifs; avec ceux qui sont sous la loi, comme sous la loi (quoique je ne sois pas moi-même sous la loi), afin de gagner ceux qui sont sous la loi;'),
  (46, 9, 21, 'avec ceux qui sont sans loi, comme sans loi (quoique je ne sois point sans la loi de Dieu, étant sous la loi de Christ), afin de gagner ceux qui sont sans loi.'),
  (46, 9, 22, 'J''ai été faible avec les faibles, afin de gagner les faibles. Je me suis fait tout à tous, afin d''en sauver de toute manière quelques-uns.'),
  (46, 9, 23, 'Je fais tout à cause de l''Évangile, afin d''y avoir part.'),
  (46, 9, 24, 'Ne savez-vous pas que ceux qui courent dans le stade courent tous, mais qu''un seul remporte le prix? Courez de manière à le remporter.'),
  (46, 9, 25, 'Tous ceux qui combattent s''imposent toute espèce d''abstinences, et ils le font pour obtenir une couronne corruptible; mais nous, faisons-le pour une couronne incorruptible.'),
  (46, 9, 26, 'Moi donc, je cours, non pas comme à l''aventure; je frappe, non pas comme battant l''air.'),
  (46, 9, 27, 'Mais je traite durement mon corps et je le tiens assujetti, de peur d''être moi-même rejeté, après avoir prêché aux autres.'),
  (46, 10, 1, 'Frères, je ne veux pas que vous ignoriez que nos pères ont tous été sous la nuée, qu''ils ont tous passé au travers de la mer,'),
  (46, 10, 2, 'qu''ils ont tous été baptisés en Moïse dans la nuée et dans la mer,'),
  (46, 10, 3, 'qu''ils ont tous mangé le même aliment spirituel,'),
  (46, 10, 4, 'et qu''ils ont tous bu le même breuvage spirituel, car ils buvaient à un rocher spirituel qui les suivait, et ce rocher était Christ.'),
  (46, 10, 5, 'Mais la plupart d''entre eux ne furent point agréables à Dieu, puisqu''ils périrent dans le désert.'),
  (46, 10, 6, 'Or, ces choses sont arrivées pour nous servir d''exemples, afin que nous n''ayons pas de mauvais désirs, comme ils en ont eu.'),
  (46, 10, 7, 'Ne devenez point idolâtres, comme quelques-uns d''eux, selon qu''il est écrit: Le peuple s''assit pour manger et pour boire; puis ils se levèrent pour se divertir.'),
  (46, 10, 8, 'Ne nous livrons point à l''impudicité, comme quelques-uns d''eux s''y livrèrent, de sorte qu''il en tomba vingt-trois mille en un seul jour.'),
  (46, 10, 9, 'Ne tentons point le Seigneur, comme le tentèrent quelques-uns d''eux, qui périrent par les serpents.'),
  (46, 10, 10, 'Ne murmurez point, comme murmurèrent quelques-uns d''eux, qui périrent par l''exterminateur.'),
  (46, 10, 11, 'Ces choses leur sont arrivées pour servir d''exemples, et elles ont été écrites pour notre instruction, à nous qui sommes parvenus à la fin des siècles.'),
  (46, 10, 12, 'Ainsi donc, que celui qui croit être debout prenne garde de tomber!'),
  (46, 10, 13, 'Aucune tentation ne vous est survenue qui n''ait été humaine, et Dieu, qui est fidèle, ne permettra pas que vous soyez tentés au delà de vos forces; mais avec la tentation il préparera aussi le moyen d''en sortir, afin que vous puissiez la supporter.'),
  (46, 10, 14, 'C''est pourquoi, mes bien-aimés, fuyez l''idolâtrie.'),
  (46, 10, 15, 'Je parle comme à des hommes intelligents; jugez vous-mêmes de ce que je dis.'),
  (46, 10, 16, 'La coupe de bénédiction que nous bénissons, n''est-elle pas la communion au sang de Christ? Le pain que nous rompons, n''est-il pas la communion au corps de Christ?'),
  (46, 10, 17, 'Puisqu''il y a un seul pain, nous qui sommes plusieurs, nous formons un seul corps; car nous participons tous à un même pain.'),
  (46, 10, 18, 'Voyez les Israélites selon la chair: ceux qui mangent les victimes ne sont-ils pas en communion avec l''autel?'),
  (46, 10, 19, 'Que dis-je donc? Que la viande sacrifiée aux idoles est quelque chose, ou qu''une idole est quelque chose? Nullement.'),
  (46, 10, 20, 'Je dis que ce qu''on sacrifie, on le sacrifie à des démons, et non à Dieu; or, je ne veux pas que vous soyez en communion avec les démons.'),
  (46, 10, 21, 'Vous ne pouvez boire la coupe du Seigneur, et la coupe des démons; vous ne pouvez participer à la table du Seigneur, et à la table des démons.'),
  (46, 10, 22, 'Voulons-nous provoquer la jalousie du Seigneur? Sommes-nous plus forts que lui?'),
  (46, 10, 23, 'Tout est permis, mais tout n''est pas utile; tout est permis, mais tout n''édifie pas.'),
  (46, 10, 24, 'Que personne ne cherche son propre intérêt, mais que chacun cherche celui d''autrui.'),
  (46, 10, 25, 'Mangez de tout ce qui se vend au marché, sans vous enquérir de rien par motif de conscience;'),
  (46, 10, 26, 'car la terre est au Seigneur, et tout ce qu''elle renferme.'),
  (46, 10, 27, 'Si un non-croyant vous invite et que vous vouliez y aller, mangez de tout ce qu''on vous présentera, sans vous enquérir de rien par motif de conscience.'),
  (46, 10, 28, 'Mais si quelqu''un vous dit: Ceci a été offert en sacrifice! n''en mangez pas, à cause de celui qui a donné l''avertissement, et à cause de la conscience.'),
  (46, 10, 29, 'Je parle ici, non de votre conscience, mais de celle de l''autre. Pourquoi, en effet, ma liberté serait-elle jugée par une conscience étrangère?'),
  (46, 10, 30, 'Si je mange avec actions de grâces, pourquoi serais-je blâmé au sujet d''une chose dont je rends grâces?'),
  (46, 10, 31, 'Soit donc que vous mangiez, soit que vous buviez, soit que vous fassiez quelque autre chose, faites tout pour la gloire de Dieu.'),
  (46, 10, 32, 'Ne soyez en scandale ni aux Grecs, ni aux Juifs, ni à l''Église de Dieu,'),
  (46, 10, 33, 'de la même manière que moi aussi je m''efforce en toutes choses de complaire à tous, cherchant, non mon avantage, mais celui du plus grand nombre, afin qu''ils soient sauvés.'),
  (46, 11, 1, 'Soyez mes imitateurs, comme je le suis moi-même de Christ.'),
  (46, 11, 2, 'Je vous loue de ce que vous vous souvenez de moi à tous égards, et de ce que vous retenez mes instructions telles que je vous les ai données.'),
  (46, 11, 3, 'Je veux cependant que vous sachiez que Christ est le chef de tout homme, que l''homme est le chef de la femme, et que Dieu est le chef de Christ.'),
  (46, 11, 4, 'Tout homme qui prie ou qui prophétise, la tête couverte, déshonore son chef.'),
  (46, 11, 5, 'Toute femme, au contraire, qui prie ou qui prophétise, la tête non voilée, déshonore son chef: c''est comme si elle était rasée.'),
  (46, 11, 6, 'Car si une femme n''est pas voilée, qu''elle se coupe aussi les cheveux. Or, s''il est honteux pour une femme d''avoir les cheveux coupés ou d''être rasée, qu''elle se voile.'),
  (46, 11, 7, 'L''homme ne doit pas se couvrir la tête, puisqu''il est l''image et la gloire de Dieu, tandis que la femme est la gloire de l''homme.'),
  (46, 11, 8, 'En effet, l''homme n''a pas été tiré de la femme, mais la femme a été tirée de l''homme;'),
  (46, 11, 9, 'et l''homme n''a pas été créé à cause de la femme, mais la femme a été créée à cause de l''homme.'),
  (46, 11, 10, 'C''est pourquoi la femme, à cause des anges, doit avoir sur la tête une marque de l''autorité dont elle dépend.'),
  (46, 11, 11, 'Toutefois, dans le Seigneur, la femme n''est point sans l''homme, ni l''homme sans la femme.'),
  (46, 11, 12, 'Car, de même que la femme a été tirée de l''homme, de même l''homme existe par la femme, et tout vient de Dieu.'),
  (46, 11, 13, 'Jugez-en vous-mêmes: est-il convenable qu''une femme prie Dieu sans être voilée?'),
  (46, 11, 14, 'La nature elle-même ne vous enseigne-t-elle pas que c''est une honte pour l''homme de porter de longs cheveux,'),
  (46, 11, 15, 'mais que c''est une gloire pour la femme d''en porter, parce que la chevelure lui a été donnée comme voile?'),
  (46, 11, 16, 'Si quelqu''un se plaît à contester, nous n''avons pas cette habitude, non plus que les Églises de Dieu.'),
  (46, 11, 17, 'En donnant cet avertissement, ce que je ne loue point, c''est que vous vous assemblez, non pour devenir meilleurs, mais pour devenir pires.'),
  (46, 11, 18, 'Et d''abord, j''apprends que, lorsque vous vous réunissez en assemblée, il y a parmi vous des divisions, -et je le crois en partie,'),
  (46, 11, 19, 'car il faut qu''il y ait aussi des sectes parmi vous, afin que ceux qui sont approuvés soient reconnus comme tels au milieu de vous. -'),
  (46, 11, 20, 'Lors donc que vous vous réunissez, ce n''est pas pour manger le repas du Seigneur;'),
  (46, 11, 21, 'car, quand on se met à table, chacun commence par prendre son propre repas, et l''un a faim, tandis que l''autre est ivre.'),
  (46, 11, 22, 'N''avez-vous pas des maisons pour y manger et boire? Ou méprisez-vous l''Église de Dieu, et faites-vous honte à ceux qui n''ont rien? Que vous dirai-je? Vous louerai-je? En cela je ne vous loue point.'),
  (46, 11, 23, 'Car j''ai reçu du Seigneur ce que je vous ai enseigné; c''est que le Seigneur Jésus, dans la nuit où il fut livré, prit du pain,'),
  (46, 11, 24, 'et, après avoir rendu grâces, le rompit, et dit: Ceci est mon corps, qui est rompu pour vous; faites ceci en mémoire de moi.'),
  (46, 11, 25, 'De même, après avoir soupé, il prit la coupe, et dit: Cette coupe est la nouvelle alliance en mon sang; faites ceci en mémoire de moi toutes les fois que vous en boirez.'),
  (46, 11, 26, 'Car toutes les fois que vous mangez ce pain et que vous buvez cette coupe, vous annoncez la mort du Seigneur, jusqu''à ce qu''il vienne.'),
  (46, 11, 27, 'C''est pourquoi celui qui mangera le pain ou boira la coupe du Seigneur indignement, sera coupable envers le corps et le sang du Seigneur.'),
  (46, 11, 28, 'Que chacun donc s''éprouve soi-même, et qu''ainsi il mange du pain et boive de la coupe;'),
  (46, 11, 29, 'car celui qui mange et boit sans discerner le corps du Seigneur, mange et boit un jugement contre lui-même.'),
  (46, 11, 30, 'C''est pour cela qu''il y a parmi vous beaucoup d''infirmes et de malades, et qu''un grand nombre sont morts.'),
  (46, 11, 31, 'Si nous nous jugions nous-mêmes, nous ne serions pas jugés.'),
  (46, 11, 32, 'Mais quand nous sommes jugés, nous sommes châtiés par le Seigneur, afin que nous ne soyons pas condamnés avec le monde.'),
  (46, 11, 33, 'Ainsi, mes frères, lorsque vous vous réunissez pour le repas, attendez-vous les uns les autres.'),
  (46, 11, 34, 'Si quelqu''un a faim, qu''il mange chez lui, afin que vous ne vous réunissiez pas pour attirer un jugement sur vous. Je réglerai les autres choses quand je serai arrivé.'),
  (46, 12, 1, 'Pour ce qui concerne les dons spirituels, je ne veux pas, frères, que vous soyez dans l''ignorance.'),
  (46, 12, 2, 'Vous savez que, lorsque vous étiez païens, vous vous laissiez entraîner vers les idoles muettes, selon que vous étiez conduits.'),
  (46, 12, 3, 'C''est pourquoi je vous déclare que nul, s''il parle par l''Esprit de Dieu, ne dit: Jésus est anathème! et que nul ne peut dire: Jésus est le Seigneur! si ce n''est par le Saint-Esprit.'),
  (46, 12, 4, 'Il y a diversité de dons, mais le même Esprit;'),
  (46, 12, 5, 'diversité de ministères, mais le même Seigneur;'),
  (46, 12, 6, 'diversité d''opérations, mais le même Dieu qui opère tout en tous.'),
  (46, 12, 7, 'Or, à chacun la manifestation de l''Esprit est donnée pour l''utilité commune.'),
  (46, 12, 8, 'En effet, à l''un est donnée par l''Esprit une parole de sagesse; à un autre, une parole de connaissance, selon le même Esprit;'),
  (46, 12, 9, 'à un autre, la foi, par le même Esprit; à un autre, le don des guérisons, par le même Esprit;'),
  (46, 12, 10, 'à un autre, le don d''opérer des miracles; à un autre, la prophétie; à un autre, le discernement des esprits; à un autre, la diversité des langues; à un autre, l''interprétation des langues.'),
  (46, 12, 11, 'Un seul et même Esprit opère toutes ces choses, les distribuant à chacun en particulier comme il veut.'),
  (46, 12, 12, 'Car, comme le corps est un et a plusieurs membres, et comme tous les membres du corps, malgré leur nombre, ne forment qu''un seul corps, ainsi en est-il de Christ.'),
  (46, 12, 13, 'Nous avons tous, en effet, été baptisés dans un seul Esprit, pour former un seul corps, soit Juifs, soit Grecs, soit esclaves, soit libres, et nous avons tous été abreuvés d''un seul Esprit.'),
  (46, 12, 14, 'Ainsi le corps n''est pas un seul membre, mais il est formé de plusieurs membres.'),
  (46, 12, 15, 'Si le pied disait: Parce que je ne suis pas une main, je ne suis pas du corps, ne serait-il pas du corps pour cela?'),
  (46, 12, 16, 'Et si l''oreille disait: Parce que je ne suis pas un œil, je ne suis pas du corps, ne serait-elle pas du corps pour cela?'),
  (46, 12, 17, 'Si tout le corps était œil, où serait l''ouïe? S''il était tout ouïe, où serait l''odorat?'),
  (46, 12, 18, 'Maintenant Dieu a placé chacun des membres dans le corps comme il a voulu.'),
  (46, 12, 19, 'Si tous étaient un seul membre, où serait le corps?'),
  (46, 12, 20, 'Maintenant donc il y a plusieurs membres, et un seul corps.'),
  (46, 12, 21, 'L''œil ne peut pas dire à la main: Je n''ai pas besoin de toi; ni la tête dire aux pieds: Je n''ai pas besoin de vous.'),
  (46, 12, 22, 'Mais bien plutôt, les membres du corps qui paraissent être les plus faibles sont nécessaires;'),
  (46, 12, 23, 'et ceux que nous estimons être les moins honorables du corps, nous les entourons d''un plus grand honneur. Ainsi nos membres les moins honnêtes reçoivent le plus d''honneur,'),
  (46, 12, 24, 'tandis que ceux qui sont honnêtes n''en ont pas besoin. Dieu a disposé le corps de manière à donner plus d''honneur à ce qui en manquait,'),
  (46, 12, 25, 'afin qu''il n''y ait pas de division dans le corps, mais que les membres aient également soin les uns des autres.'),
  (46, 12, 26, 'Et si un membre souffre, tous les membres souffrent avec lui; si un membre est honoré, tous les membres se réjouissent avec lui.'),
  (46, 12, 27, 'Vous êtes le corps de Christ, et vous êtes ses membres, chacun pour sa part.'),
  (46, 12, 28, 'Et Dieu a établi dans l''Église premièrement des apôtres, secondement des prophètes, troisièmement des docteurs, ensuite ceux qui ont le don des miracles, puis ceux qui ont les dons de guérir, de secourir, de gouverner, de parler diverses langues.'),
  (46, 12, 29, 'Tous sont-ils apôtres? Tous sont-ils prophètes? Tous sont-ils docteurs? Tous ont-ils le don des miracles?'),
  (46, 12, 30, 'Tous ont-ils le don des guérisons? Tous parlent-ils en langues? Tous interprètent-ils?'),
  (46, 12, 31, 'Aspirez aux dons les meilleurs. Et je vais encore vous montrer une voie par excellence.'),
  (46, 13, 1, 'Quand je parlerais les langues des hommes et des anges, si je n''ai pas la charité, je suis un airain qui résonne, ou une cymbale qui retentit.'),
  (46, 13, 2, 'Et quand j''aurais le don de prophétie, la science de tous les mystères et toute la connaissance, quand j''aurais même toute la foi jusqu''à transporter des montagnes, si je n''ai pas la charité, je ne suis rien.'),
  (46, 13, 3, 'Et quand je distribuerais tous mes biens pour la nourriture des pauvres, quand je livrerais même mon corps pour être brûlé, si je n''ai pas la charité, cela ne me sert de rien.'),
  (46, 13, 4, 'La charité est patiente, elle est pleine de bonté; la charité n''est point envieuse; la charité ne se vante point, elle ne s''enfle point d''orgueil,'),
  (46, 13, 5, 'elle ne fait rien de malhonnête, elle ne cherche point son intérêt, elle ne s''irrite point, elle ne soupçonne point le mal,'),
  (46, 13, 6, 'elle ne se réjouit point de l''injustice, mais elle se réjouit de la vérité;'),
  (46, 13, 7, 'elle excuse tout, elle croit tout, elle espère tout, elle supporte tout.'),
  (46, 13, 8, 'La charité ne périt jamais. Les prophéties prendront fin, les langues cesseront, la connaissance disparaîtra.'),
  (46, 13, 9, 'Car nous connaissons en partie, et nous prophétisons en partie,'),
  (46, 13, 10, 'mais quand ce qui est parfait sera venu, ce qui est partiel disparaîtra.'),
  (46, 13, 11, 'Lorsque j''étais enfant, je parlais comme un enfant, je pensais comme un enfant, je raisonnais comme un enfant; lorsque je suis devenu homme, j''ai fait disparaître ce qui était de l''enfant.'),
  (46, 13, 12, 'Aujourd''hui nous voyons au moyen d''un miroir, d''une manière obscure, mais alors nous verrons face à face; aujourd''hui je connais en partie, mais alors je connaîtrai comme j''ai été connu.'),
  (46, 13, 13, 'Maintenant donc ces trois choses demeurent: la foi, l''espérance, la charité; mais la plus grande de ces choses, c''est la charité.'),
  (46, 14, 1, 'Recherchez la charité. Aspirez aussi aux dons spirituels, mais surtout à celui de prophétie.'),
  (46, 14, 2, 'En effet, celui qui parle en langue ne parle pas aux hommes, mais à Dieu, car personne ne le comprend, et c''est en esprit qu''il dit des mystères.'),
  (46, 14, 3, 'Celui qui prophétise, au contraire, parle aux hommes, les édifie, les exhorte, les console.'),
  (46, 14, 4, 'Celui qui parle en langue s''édifie lui-même; celui qui prophétise édifie l''Église.'),
  (46, 14, 5, 'Je désire que vous parliez tous en langues, mais encore plus que vous prophétisiez. Celui qui prophétise est plus grand que celui qui parle en langues, à moins que ce dernier n''interprète, pour que l''Église en reçoive de l''édification.'),
  (46, 14, 6, 'Et maintenant, frères, de quelle utilité vous serais-je, si je venais à vous parlant en langues, et si je ne vous parlais pas par révélation, ou par connaissance, ou par prophétie, ou par doctrine?'),
  (46, 14, 7, 'Si les objets inanimés qui rendent un son, comme une flûte ou une harpe, ne rendent pas des sons distincts, comment reconnaîtra-t-on ce qui est joué sur la flûte ou sur la harpe?'),
  (46, 14, 8, 'Et si la trompette rend un son confus, qui se préparera au combat?'),
  (46, 14, 9, 'De même vous, si par la langue vous ne donnez pas une parole distincte, comment saura-t-on ce que vous dites? Car vous parlerez en l''air.'),
  (46, 14, 10, 'Quelque nombreuses que puissent être dans le monde les diverses langues, il n''en est aucune qui ne soit une langue intelligible;'),
  (46, 14, 11, 'si donc je ne connais pas le sens de la langue, je serai un barbare pour celui qui parle, et celui qui parle sera un barbare pour moi.'),
  (46, 14, 12, 'De même vous, puisque vous aspirez aux dons spirituels, que ce soit pour l''édification de l''Église que vous cherchiez à en posséder abondamment.'),
  (46, 14, 13, 'C''est pourquoi, que celui qui parle en langue prie pour avoir le don d''interpréter.'),
  (46, 14, 14, 'Car si je prie en langue, mon esprit est en prière, mais mon intelligence demeure stérile.'),
  (46, 14, 15, 'Que faire donc? Je prierai par l''esprit, mais je prierai aussi avec l''intelligence; je chanterai par l''esprit, mais je chanterai aussi avec l''intelligence.'),
  (46, 14, 16, 'Autrement, si tu rends grâces par l''esprit, comment celui qui est dans les rangs de l''homme du peuple répondra-t-il Amen! à ton action de grâces, puisqu''il ne sait pas ce que tu dis?'),
  (46, 14, 17, 'Tu rends, il est vrai, d''excellentes actions de grâces, mais l''autre n''est pas édifié.'),
  (46, 14, 18, 'Je rends grâces à Dieu de ce que je parle en langue plus que vous tous;'),
  (46, 14, 19, 'mais, dans l''Église, j''aime mieux dire cinq paroles avec mon intelligence, afin d''instruire aussi les autres, que dix mille paroles en langue.'),
  (46, 14, 20, 'Frères, ne soyez pas des enfants sous le rapport du jugement; mais pour la malice, soyez enfants, et, à l''égard du jugement, soyez des hommes faits.'),
  (46, 14, 21, 'Il est écrit dans la loi: C''est par des hommes d''une autre langue Et par des lèvres d''étrangers Que je parlerai à ce peuple, Et ils ne m''écouteront pas même ainsi, dit le Seigneur.'),
  (46, 14, 22, 'Par conséquent, les langues sont un signe, non pour les croyants, mais pour les non-croyants; la prophétie, au contraire, est un signe, non pour les non-croyants, mais pour les croyants.'),
  (46, 14, 23, 'Si donc, dans une assemblée de l''Église entière, tous parlent en langues, et qu''il survienne des hommes du peuple ou des non-croyants, ne diront-ils pas que vous êtes fous?'),
  (46, 14, 24, 'Mais si tous prophétisent, et qu''il survienne quelque non-croyant ou un homme du peuple, il est convaincu par tous, il est jugé par tous,'),
  (46, 14, 25, 'les secrets de son cœur sont dévoilés, de telle sorte que, tombant sur sa face, il adorera Dieu, et publiera que Dieu est réellement au milieu de vous.'),
  (46, 14, 26, 'Que faire donc, frères? Lorsque vous vous assemblez, les uns ou les autres parmi vous ont-ils un cantique, une instruction, une révélation, une langue, une interprétation, que tout se fasse pour l''édification.'),
  (46, 14, 27, 'En est-il qui parlent en langue, que deux ou trois au plus parlent, chacun à son tour, et que quelqu''un interprète;'),
  (46, 14, 28, 's''il n''y a point d''interprète, qu''on se taise dans l''Église, et qu''on parle à soi-même et à Dieu.'),
  (46, 14, 29, 'Pour ce qui est des prophètes, que deux ou trois parlent, et que les autres jugent;'),
  (46, 14, 30, 'et si un autre qui est assis a une révélation, que le premier se taise.'),
  (46, 14, 31, 'Car vous pouvez tous prophétiser successivement, afin que tous soient instruits et que tous soient exhortés.'),
  (46, 14, 32, 'Les esprits des prophètes sont soumis aux prophètes;'),
  (46, 14, 33, 'car Dieu n''est pas un Dieu de désordre, mais de paix. Comme dans toutes les Églises des saints,'),
  (46, 14, 34, 'que les femmes se taisent dans les assemblées, car il ne leur est pas permis d''y parler; mais qu''elles soient soumises, selon que le dit aussi la loi.'),
  (46, 14, 35, 'Si elles veulent s''instruire sur quelque chose, qu''elles interrogent leurs maris à la maison; car il est malséant à une femme de parler dans l''Église.'),
  (46, 14, 36, 'Est-ce de chez vous que la parole de Dieu est sortie? ou est-ce à vous seuls qu''elle est parvenue?'),
  (46, 14, 37, 'Si quelqu''un croit être prophète ou inspiré, qu''il reconnaisse que ce que je vous écris est un commandement du Seigneur.'),
  (46, 14, 38, 'Et si quelqu''un l''ignore, qu''il l''ignore.'),
  (46, 14, 39, 'Ainsi donc, frères, aspirez au don de prophétie, et n''empêchez pas de parler en langues.'),
  (46, 14, 40, 'Mais que tout se fasse avec bienséance et avec ordre.'),
  (46, 15, 1, 'Je vous rappelle, frères, l''Évangile que je vous ai annoncé, que vous avez reçu, dans lequel vous avez persévéré,'),
  (46, 15, 2, 'et par lequel vous êtes sauvés, si vous le retenez tel que je vous l''ai annoncé; autrement, vous auriez cru en vain.'),
  (46, 15, 3, 'Je vous ai enseigné avant tout, comme je l''avais aussi reçu, que Christ est mort pour nos péchés, selon les Écritures;'),
  (46, 15, 4, 'qu''il a été enseveli, et qu''il est ressuscité le troisième jour, selon les Écritures;'),
  (46, 15, 5, 'et qu''il est apparu à Céphas, puis aux douze.'),
  (46, 15, 6, 'Ensuite, il est apparu à plus de cinq cents frères à la fois, dont la plupart sont encore vivants, et dont quelques-uns sont morts.'),
  (46, 15, 7, 'Ensuite, il est apparu à Jacques, puis à tous les apôtres.'),
  (46, 15, 8, 'Après eux tous, il m''est aussi apparu à moi, comme à l''avorton;'),
  (46, 15, 9, 'car je suis le moindre des apôtres, je ne suis pas digne d''être appelé apôtre, parce que j''ai persécuté l''Église de Dieu.'),
  (46, 15, 10, 'Par la grâce de Dieu je suis ce que je suis, et sa grâce envers moi n''a pas été vaine; loin de là, j''ai travaillé plus qu''eux tous, non pas moi toutefois, mais la grâce de Dieu qui est avec moi.'),
  (46, 15, 11, 'Ainsi donc, que ce soit moi, que ce soient eux, voilà ce que nous prêchons, et c''est ce que vous avez cru.'),
  (46, 15, 12, 'Or, si l''on prêche que Christ est ressuscité des morts, comment quelques-uns parmi vous disent-ils qu''il n''y a point de résurrection des morts?'),
  (46, 15, 13, 'S''il n''y a point de résurrection des morts, Christ non plus n''est pas ressuscité.'),
  (46, 15, 14, 'Et si Christ n''est pas ressuscité, notre prédication est donc vaine, et votre foi aussi est vaine.'),
  (46, 15, 15, 'Il se trouve même que nous sommes de faux témoins à l''égard de Dieu, puisque nous avons témoigné contre Dieu qu''il a ressuscité Christ, tandis qu''il ne l''aurait pas ressuscité, si les morts ne ressuscitent point.'),
  (46, 15, 16, 'Car si les morts ne ressuscitent point, Christ non plus n''est pas ressuscité.'),
  (46, 15, 17, 'Et si Christ n''est pas ressuscité, votre foi est vaine, vous êtes encore dans vos péchés,'),
  (46, 15, 18, 'et par conséquent aussi ceux qui sont morts en Christ sont perdus.'),
  (46, 15, 19, 'Si c''est dans cette vie seulement que nous espérons en Christ, nous sommes les plus malheureux de tous les hommes.'),
  (46, 15, 20, 'Mais maintenant, Christ est ressuscité des morts, il est les prémices de ceux qui sont morts.'),
  (46, 15, 21, 'Car, puisque la mort est venue par un homme, c''est aussi par un homme qu''est venue la résurrection des morts.'),
  (46, 15, 22, 'Et comme tous meurent en Adam, de même aussi tous revivront en Christ,'),
  (46, 15, 23, 'mais chacun en son rang. Christ comme prémices, puis ceux qui appartiennent à Christ, lors de son avènement.'),
  (46, 15, 24, 'Ensuite viendra la fin, quand il remettra le royaume à celui qui est Dieu et Père, après avoir détruit toute domination, toute autorité et toute puissance.'),
  (46, 15, 25, 'Car il faut qu''il règne jusqu''à ce qu''il ait mis tous les ennemis sous ses pieds.'),
  (46, 15, 26, 'Le dernier ennemi qui sera détruit, c''est la mort.'),
  (46, 15, 27, 'Dieu, en effet, a tout mis sous ses pieds. Mais lorsqu''il dit que tout lui a été soumis, il est évident que celui qui lui a soumis toutes choses est excepté.'),
  (46, 15, 28, 'Et lorsque toutes choses lui auront été soumises, alors le Fils lui-même sera soumis à celui qui lui a soumis toutes choses, afin que Dieu soit tout en tous.'),
  (46, 15, 29, 'Autrement, que feraient ceux qui se font baptiser pour les morts? Si les morts ne ressuscitent absolument pas, pourquoi se font-ils baptiser pour eux?'),
  (46, 15, 30, 'Et nous, pourquoi sommes-nous à toute heure en péril?'),
  (46, 15, 31, 'Chaque jour je suis exposé à la mort, je l''atteste, frères, par la gloire dont vous êtes pour moi le sujet, en Jésus-Christ notre Seigneur.'),
  (46, 15, 32, 'Si c''est dans des vues humaines que j''ai combattu contre les bêtes à Éphèse, quel avantage m''en revient-il? Si les morts ne ressuscitent pas, Mangeons et buvons, car demain nous mourrons.'),
  (46, 15, 33, 'Ne vous y trompez pas: les mauvaises compagnies corrompent les bonnes mœurs.'),
  (46, 15, 34, 'Revenez à vous-mêmes, comme il est convenable, et ne péchez point; car quelques-uns ne connaissent pas Dieu, je le dis à votre honte.'),
  (46, 15, 35, 'Mais quelqu''un dira: Comment les morts ressuscitent-ils, et avec quel corps reviennent-ils?'),
  (46, 15, 36, 'Insensé! ce que tu sèmes ne reprend point vie, s''il ne meurt.'),
  (46, 15, 37, 'Et ce que tu sèmes, ce n''est pas le corps qui naîtra; c''est un simple grain, de blé peut-être, ou de quelque autre semence;'),
  (46, 15, 38, 'puis Dieu lui donne un corps comme il lui plaît, et à chaque semence il donne un corps qui lui est propre.'),
  (46, 15, 39, 'Toute chair n''est pas la même chair; mais autre est la chair des hommes, autre celle des quadrupèdes, autre celle des oiseaux, autre celle des poissons.'),
  (46, 15, 40, 'Il y a aussi des corps célestes et des corps terrestres; mais autre est l''éclat des corps célestes, autre celui des corps terrestres.'),
  (46, 15, 41, 'Autre est l''éclat du soleil, autre l''éclat de la lune, et autre l''éclat des étoiles; même une étoile diffère en éclat d''une autre étoile.'),
  (46, 15, 42, 'Ainsi en est-il de la résurrection des morts. Le corps est semé corruptible; il ressuscite incorruptible;'),
  (46, 15, 43, 'il est semé méprisable, il ressuscite glorieux; il est semé infirme, il ressuscite plein de force;'),
  (46, 15, 44, 'il est semé corps animal, il ressuscite corps spirituel. S''il y a un corps animal, il y a aussi un corps spirituel.'),
  (46, 15, 45, 'C''est pourquoi il est écrit: Le premier homme, Adam, devint une âme vivante. Le dernier Adam est devenu un esprit vivifiant.'),
  (46, 15, 46, 'Mais ce qui est spirituel n''est pas le premier, c''est ce qui est animal; ce qui est spirituel vient ensuite.'),
  (46, 15, 47, 'Le premier homme, tiré de la terre, est terrestre; le second homme est du ciel.'),
  (46, 15, 48, 'Tel est le terrestre, tels sont aussi les terrestres; et tel est le céleste, tels sont aussi les célestes.'),
  (46, 15, 49, 'Et de même que nous avons porté l''image du terrestre, nous porterons aussi l''image du céleste.'),
  (46, 15, 50, 'Ce que je dis, frères, c''est que la chair et le sang ne peuvent hériter le royaume de Dieu, et que la corruption n''hérite pas l''incorruptibilité.'),
  (46, 15, 51, 'Voici, je vous dis un mystère: nous ne mourrons pas tous, mais tous nous serons changés,'),
  (46, 15, 52, 'en un instant, en un clin d''œil, à la dernière trompette. La trompette sonnera, et les morts ressusciteront incorruptibles, et nous, nous serons changés.'),
  (46, 15, 53, 'Car il faut que ce corps corruptible revête l''incorruptibilité, et que ce corps mortel revête l''immortalité.'),
  (46, 15, 54, 'Lorsque ce corps corruptible aura revêtu l''incorruptibilité, et que ce corps mortel aura revêtu l''immortalité, alors s''accomplira la parole qui est écrite: La mort a été engloutie dans la victoire.'),
  (46, 15, 55, 'O mort, où est ta victoire? O mort, où est ton aiguillon?'),
  (46, 15, 56, 'L''aiguillon de la mort, c''est le péché; et la puissance du péché, c''est la loi.'),
  (46, 15, 57, 'Mais grâces soient rendues à Dieu, qui nous donne la victoire par notre Seigneur Jésus-Christ!'),
  (46, 15, 58, 'Ainsi, mes frères bien-aimés, soyez fermes, inébranlables, travaillant de mieux en mieux à l''œuvre du Seigneur, sachant que votre travail ne sera pas vain dans le Seigneur.'),
  (46, 16, 1, 'Pour ce qui concerne la collecte en faveur des saints, agissez, vous aussi, comme je l''ai ordonné aux Églises de la Galatie.'),
  (46, 16, 2, 'Que chacun de vous, le premier jour de la semaine, mette à part chez lui ce qu''il pourra, selon sa prospérité, afin qu''on n''attende pas mon arrivée pour recueillir les dons.'),
  (46, 16, 3, 'Et quand je serai venu, j''enverrai avec des lettres, pour porter vos libéralités à Jérusalem, les personnes que vous aurez approuvées.'),
  (46, 16, 4, 'Si la chose mérite que j''y aille moi-même, elles feront le voyage avec moi.'),
  (46, 16, 5, 'J''irai chez vous quand j''aurai traversé la Macédoine, car je traverserai la Macédoine.'),
  (46, 16, 6, 'Peut-être séjournerai-je auprès de vous, ou même y passerai-je l''hiver, afin que vous m''accompagniez là où je me rendrai.'),
  (46, 16, 7, 'Je ne veux pas cette fois vous voir en passant, mais j''espère demeurer quelque temps auprès de vous, si le Seigneur le permet.'),
  (46, 16, 8, 'Je resterai néanmoins à Éphèse jusqu''à la Pentecôte;'),
  (46, 16, 9, 'car une porte grande et d''un accès efficace m''est ouverte, et les adversaires sont nombreux.'),
  (46, 16, 10, 'Si Timothée arrive, faites en sorte qu''il soit sans crainte parmi vous, car il travaille comme moi à l''œuvre du Seigneur.'),
  (46, 16, 11, 'Que personne donc ne le méprise. Accompagnez-le en paix, afin qu''il vienne vers moi, car je l''attends avec les frères.'),
  (46, 16, 12, 'Pour ce qui est du frère Apollos, je l''ai beaucoup exhorté à se rendre chez vous avec les frères, mais ce n''était décidément pas sa volonté de le faire maintenant; il partira quand il en aura l''occasion.'),
  (46, 16, 13, 'Veillez, demeurez fermes dans la foi, soyez des hommes, fortifiez-vous.'),
  (46, 16, 14, 'Que tout ce que vous faites se fasse avec charité!'),
  (46, 16, 15, 'Encore une recommandation que je vous adresse, frères. Vous savez que la famille de Stéphanas est les prémices de l''Achaïe, et qu''elle s''est dévouée au service des saints.'),
  (46, 16, 16, 'Ayez vous aussi de la déférence pour de tels hommes, et pour tous ceux qui travaillent à la même œuvre.'),
  (46, 16, 17, 'Je me réjouis de la présence de Stéphanas, de Fortunatus et d''Achaïcus; ils ont suppléé à votre absence,'),
  (46, 16, 18, 'car ils ont tranquillisé mon esprit et le vôtre. Sachez donc apprécier de tels hommes.'),
  (46, 16, 19, 'Les Églises d''Asie vous saluent. Aquilas et Priscille, avec l''Église qui est dans leur maison, vous saluent beaucoup dans le Seigneur.'),
  (46, 16, 20, 'Tous les frères vous saluent. Saluez-vous les uns les autres par un saint baiser.'),
  (46, 16, 21, 'Je vous salue, moi Paul, de ma propre main.'),
  (46, 16, 22, 'Si quelqu''un n''aime pas le Seigneur, qu''il soit anathème! Maranatha.'),
  (46, 16, 23, 'Que la grâce du Seigneur Jésus soit avec vous!'),
  (46, 16, 24, 'Mon amour est avec vous tous en Jésus-Christ.'),
  (47, 1, 1, 'Paul, apôtre de Jésus-Christ par la volonté de Dieu, et le frère Timothée, à l''Église de Dieu qui est à Corinthe, et à tous les saints qui sont dans toute l''Achaïe:'),
  (47, 1, 2, 'que la grâce et la paix vous soient données de la part de Dieu notre Père et du Seigneur Jésus-Christ!'),
  (47, 1, 3, 'Béni soit Dieu, le Père de notre Seigneur Jésus-Christ, le Père des miséricordes et le Dieu de toute consolation,'),
  (47, 1, 4, 'qui nous console dans toutes nos afflictions, afin que, par la consolation dont nous sommes l''objet de la part de Dieu, nous puissions consoler ceux qui se trouvent dans quelque affliction!'),
  (47, 1, 5, 'Car, de même que les souffrances de Christ abondent en nous, de même notre consolation abonde par Christ.'),
  (47, 1, 6, 'Si nous sommes affligés, c''est pour votre consolation et pour votre salut; si nous sommes consolés, c''est pour votre consolation, qui se réalise par la patience à supporter les mêmes souffrances que nous endurons.'),
  (47, 1, 7, 'Et notre espérance à votre égard est ferme, parce que nous savons que, si vous avez part aux souffrances, vous avez part aussi à la consolation.'),
  (47, 1, 8, 'Nous ne voulons pas, en effet, vous laisser ignorer, frères, au sujet de la tribulation qui nous est survenue en Asie, que nous avons été excessivement accablés, au delà de nos forces, de telle sorte que nous désespérions même de conserver la vie.'),
  (47, 1, 9, 'Et nous regardions comme certain notre arrêt de mort, afin de ne pas placer notre confiance en nous-mêmes, mais de la placer en Dieu, qui ressuscite les morts.'),
  (47, 1, 10, 'C''est lui qui nous a délivrés et qui nous délivrera d''une telle mort, lui de qui nous espérons qu''il nous délivrera encore,'),
  (47, 1, 11, 'vous-mêmes aussi nous assistant de vos prières, afin que la grâce obtenue pour nous par plusieurs soit pour plusieurs une occasion de rendre grâces à notre sujet.'),
  (47, 1, 12, 'Car ce qui fait notre gloire, c''est ce témoignage de notre conscience, que nous nous sommes conduits dans le monde, et surtout à votre égard, avec sainteté et pureté devant Dieu, non point avec une sagesse charnelle, mais avec la grâce de Dieu.'),
  (47, 1, 13, 'Nous ne vous écrivons pas autre chose que ce que vous lisez, et ce que vous reconnaissez. Et j''espère que vous le reconnaîtrez jusqu''à la fin,'),
  (47, 1, 14, 'comme vous avez déjà reconnu en partie que nous sommes votre gloire, de même que vous serez aussi la nôtre au jour du Seigneur Jésus.'),
  (47, 1, 15, 'Dans cette persuasion, je voulais aller d''abord vers vous, afin que vous eussiez une double grâce;'),
  (47, 1, 16, 'je voulais passer chez vous pour me rendre en Macédoine, puis revenir de la Macédoine chez vous, et vous m''auriez fait accompagner en Judée.'),
  (47, 1, 17, 'Est-ce que, en voulant cela, j''ai donc usé de légèreté? Ou bien, mes résolutions sont-elles des résolutions selon la chair, de sorte qu''il y ait en moi le oui et le non?'),
  (47, 1, 18, 'Aussi vrai que Dieu est fidèle, la parole que nous vous avons adressée n''a pas été oui et non.'),
  (47, 1, 19, 'Car le Fils de Dieu, Jésus-Christ, qui a été prêché par nous au milieu de vous, par moi, et par Silvain, et par Timothée, n''a pas été oui et non, mais c''est oui qui a été en lui;'),
  (47, 1, 20, 'car, pour ce qui concerne toutes les promesses de Dieu, c''est en lui qu''est le oui; c''est pourquoi encore l''Amen par lui est prononcé par nous à la gloire de Dieu.'),
  (47, 1, 21, 'Et celui qui nous affermit avec vous en Christ, et qui nous a oints, c''est Dieu,'),
  (47, 1, 22, 'lequel nous a aussi marqués d''un sceau et a mis dans nos cœurs les arrhes de l''Esprit.'),
  (47, 1, 23, 'Or, je prends Dieu à témoin sur mon âme, que c''est pour vous épargner que je ne suis plus allé à Corinthe;'),
  (47, 1, 24, 'non pas que nous dominions sur votre foi, mais nous contribuons à votre joie, car vous êtes fermes dans la foi.'),
  (47, 2, 1, 'Je résolus donc en moi-même de ne pas retourner chez vous dans la tristesse.'),
  (47, 2, 2, 'Car si je vous attriste, qui peut me réjouir, sinon celui qui est attristé par moi?'),
  (47, 2, 3, 'J''ai écrit comme je l''ai fait pour ne pas éprouver, à mon arrivée, de la tristesse de la part de ceux qui devaient me donner de la joie, ayant en vous tous cette confiance que ma joie est la vôtre à tous.'),
  (47, 2, 4, 'C''est dans une grande affliction, le cœur angoissé, et avec beaucoup de larmes, que je vous ai écrit, non pas afin que vous fussiez attristés, mais afin que vous connussiez l''amour extrême que j''ai pour vous.'),
  (47, 2, 5, 'Si quelqu''un a été une cause de tristesse, ce n''est pas moi qu''il a attristé, c''est vous tous, du moins en partie, pour ne rien exagérer.'),
  (47, 2, 6, 'Il suffit pour cet homme du châtiment qui lui a été infligé par le plus grand nombre,'),
  (47, 2, 7, 'en sorte que vous devez bien plutôt lui pardonner et le consoler, de peur qu''il ne soit accablé par une tristesse excessive.'),
  (47, 2, 8, 'Je vous exhorte donc à faire acte de charité envers lui;'),
  (47, 2, 9, 'car je vous ai écrit aussi dans le but de connaître, en vous mettant à l''épreuve, si vous êtes obéissants en toutes choses.'),
  (47, 2, 10, 'Or, à qui vous pardonnez, je pardonne aussi; et ce que j''ai pardonné, si j''ai pardonné quelque chose, c''est à cause de vous, en présence de Christ,'),
  (47, 2, 11, 'afin de ne pas laisser à Satan l''avantage sur nous, car nous n''ignorons pas ses desseins.'),
  (47, 2, 12, 'Au reste, lorsque je fus arrivé à Troas pour l''Évangile de Christ, quoique le Seigneur m''y eût ouvert une porte,'),
  (47, 2, 13, 'je n''eus point de repos d''esprit, parce que je ne trouvai pas Tite, mon frère; c''est pourquoi, ayant pris congé d''eux, je partis pour la Macédoine.'),
  (47, 2, 14, 'Grâces soient rendues à Dieu, qui nous fait toujours triompher en Christ, et qui répand par nous en tout lieu l''odeur de sa connaissance!'),
  (47, 2, 15, 'Nous sommes, en effet, pour Dieu la bonne odeur de Christ, parmi ceux qui sont sauvés et parmi ceux qui périssent:'),
  (47, 2, 16, 'aux uns, une odeur de mort, donnant la mort; aux autres, une odeur de vie, donnant la vie. Et qui est suffisant pour ces choses? -'),
  (47, 2, 17, 'Car nous ne falsifions point la parole de Dieu, comme font plusieurs; mais c''est avec sincérité, mais c''est de la part de Dieu, que nous parlons en Christ devant Dieu.'),
  (47, 3, 1, 'Commençons-nous de nouveau à nous recommander nous-mêmes? Ou avons-nous besoin, comme quelques-uns, de lettres de recommandation auprès de vous, ou de votre part?'),
  (47, 3, 2, 'C''est vous qui êtes notre lettre, écrite dans nos cœurs, connue et lue de tous les hommes.'),
  (47, 3, 3, 'Vous êtes manifestement une lettre de Christ, écrite, par notre ministère, non avec de l''encre, mais avec l''Esprit du Dieu vivant, non sur des tables de pierre, mais sur des tables de chair, sur les cœurs.'),
  (47, 3, 4, 'Cette assurance-là, nous l''avons par Christ auprès de Dieu.'),
  (47, 3, 5, 'Ce n''est pas à dire que nous soyons par nous-mêmes capables de concevoir quelque chose comme venant de nous-mêmes. Notre capacité, au contraire, vient de Dieu.'),
  (47, 3, 6, 'Il nous a aussi rendus capables d''être ministres d''une nouvelle alliance, non de la lettre, mais de l''esprit; car la lettre tue, mais l''esprit vivifie.'),
  (47, 3, 7, 'Or, si le ministère de la mort, gravé avec des lettres sur des pierres, a été glorieux, au point que les fils d''Israël ne pouvaient fixer les regards sur le visage de Moïse, à cause de la gloire de son visage, bien que cette gloire fût passagère,'),
  (47, 3, 8, 'combien le ministère de l''esprit ne sera-t-il pas plus glorieux!'),
  (47, 3, 9, 'Si le ministère de la condamnation a été glorieux, le ministère de la justice est de beaucoup supérieur en gloire.'),
  (47, 3, 10, 'Et, sous ce rapport, ce qui a été glorieux ne l''a point été, à cause de cette gloire qui lui est supérieure.'),
  (47, 3, 11, 'En effet, si ce qui était passager a été glorieux, ce qui est permanent est bien plus glorieux.'),
  (47, 3, 12, 'Ayant donc cette espérance, nous usons d''une grande liberté,'),
  (47, 3, 13, 'et nous ne faisons pas comme Moïse, qui mettait un voile sur son visage, pour que les fils d''Israël ne fixassent pas les regards sur la fin de ce qui était passager.'),
  (47, 3, 14, 'Mais ils sont devenus durs d''entendement. Car jusqu''à ce jour le même voile demeure quand, ils font la lecture de l''Ancien Testament, et il ne se lève pas, parce que c''est en Christ qu''il disparaît.'),
  (47, 3, 15, 'Jusqu''à ce jour, quand on lit Moïse, un voile est jeté sur leurs cœurs;'),
  (47, 3, 16, 'mais lorsque les cœurs se convertissent au Seigneur, le voile est ôté.'),
  (47, 3, 17, 'Or, le Seigneur c''est l''Esprit; et là où est l''Esprit du Seigneur, là est la liberté.'),
  (47, 3, 18, 'Nous tous qui, le visage découvert, contemplons comme dans un miroir la gloire du Seigneur, nous sommes transformés en la même image, de gloire en gloire, comme par le Seigneur, l''Esprit.'),
  (47, 4, 1, 'C''est pourquoi, ayant ce ministère, selon la miséricorde qui nous a été faite, nous ne perdons pas courage.'),
  (47, 4, 2, 'Nous rejetons les choses honteuses qui se font en secret, nous n''avons point une conduite astucieuse, et nous n''altérons point la parole de Dieu. Mais, en publiant la vérité, nous nous recommandons à toute conscience d''homme devant Dieu.'),
  (47, 4, 3, 'Si notre Évangile est encore voilé, il est voilé pour ceux qui périssent;'),
  (47, 4, 4, 'pour les incrédules dont le dieu de ce siècle a aveuglé l''intelligence, afin qu''ils ne vissent pas briller la splendeur de l''Évangile de la gloire de Christ, qui est l''image de Dieu.'),
  (47, 4, 5, 'Nous ne nous prêchons pas nous-mêmes; c''est Jésus-Christ le Seigneur que nous prêchons, et nous nous disons vos serviteurs à cause de Jésus.'),
  (47, 4, 6, 'Car Dieu, qui a dit: La lumière brillera du sein des ténèbres! a fait briller la lumière dans nos cœurs pour faire resplendir la connaissance de la gloire de Dieu sur la face de Christ.'),
  (47, 4, 7, 'Nous portons ce trésor dans des vases de terre, afin que cette grande puissance soit attribuée à Dieu, et non pas à nous.'),
  (47, 4, 8, 'Nous sommes pressés de toute manière, mais non réduits à l''extrémité; dans la détresse, mais non dans le désespoir;'),
  (47, 4, 9, 'persécutés, mais non abandonnés; abattus, mais non perdus;'),
  (47, 4, 10, 'portant toujours avec nous dans notre corps la mort de Jésus, afin que la vie de Jésus soit aussi manifestée dans notre corps.'),
  (47, 4, 11, 'Car nous qui vivons, nous sommes sans cesse livrés à la mort à cause de Jésus, afin que la vie de Jésus soit aussi manifestée dans notre chair mortelle.'),
  (47, 4, 12, 'Ainsi la mort agit en nous, et la vie agit en vous.'),
  (47, 4, 13, 'Et, comme nous avons le même esprit de foi qui est exprimé dans cette parole de l''Écriture: J''ai cru, c''est pourquoi j''ai parlé! nous aussi nous croyons, et c''est pour cela que nous parlons,'),
  (47, 4, 14, 'sachant que celui qui a ressuscité le Seigneur Jésus nous ressuscitera aussi avec Jésus, et nous fera paraître avec vous en sa présence.'),
  (47, 4, 15, 'Car tout cela arrive à cause de vous, afin que la grâce en se multipliant, fasse abonder, à la gloire de Dieu, les actions de grâces d''un plus grand nombre.'),
  (47, 4, 16, 'C''est pourquoi nous ne perdons pas courage. Et lors même que notre homme extérieur se détruit, notre homme intérieur se renouvelle de jour en jour.'),
  (47, 4, 17, 'Car nos légères afflictions du moment présent produisent pour nous, au delà de toute mesure, un poids éternel de gloire,'),
  (47, 4, 18, 'parce que nous regardons, non point aux choses visibles, mais à celles qui sont invisibles; car les choses visibles sont passagères, et les invisibles sont éternelles.'),
  (47, 5, 1, 'Nous savons, en effet, que, si cette tente où nous habitons sur la terre est détruite, nous avons dans le ciel un édifice qui est l''ouvrage de Dieu, une demeure éternelle qui n''a pas été faite de main d''homme.'),
  (47, 5, 2, 'Aussi nous gémissons dans cette tente, désirant revêtir notre domicile céleste,'),
  (47, 5, 3, 'si du moins nous sommes trouvés vêtus et non pas nus.'),
  (47, 5, 4, 'Car tandis que nous sommes dans cette tente, nous gémissons, accablés, parce que nous voulons, non pas nous dépouiller, mais nous revêtir, afin que ce qui est mortel soit englouti par la vie.'),
  (47, 5, 5, 'Et celui qui nous a formés pour cela, c''est Dieu, qui nous a donné les arrhes de l''Esprit.'),
  (47, 5, 6, 'Nous sommes donc toujours pleins de confiance, et nous savons qu''en demeurant dans ce corps nous demeurons loin du Seigneur-'),
  (47, 5, 7, 'car nous marchons par la foi et non par la vue,'),
  (47, 5, 8, 'nous sommes pleins de confiance, et nous aimons mieux quitter ce corps et demeurer auprès du Seigneur.'),
  (47, 5, 9, 'C''est pour cela aussi que nous nous efforçons de lui être agréables, soit que nous demeurions dans ce corps, soit que nous le quittions.'),
  (47, 5, 10, 'Car il nous faut tous comparaître devant le tribunal de Christ, afin que chacun reçoive selon le bien ou le mal qu''il aura fait, étant dans son corps.'),
  (47, 5, 11, 'Connaissant donc la crainte du Seigneur, nous cherchons à convaincre les hommes; Dieu nous connaît, et j''espère que dans vos consciences vous nous connaissez aussi.'),
  (47, 5, 12, 'Nous ne nous recommandons pas de nouveau nous-mêmes auprès de vous; mais nous vous donnons occasion de vous glorifier à notre sujet, afin que vous puissiez répondre à ceux qui tirent gloire de ce qui est dans les apparences et non dans le cœur.'),
  (47, 5, 13, 'En effet, si je suis hors de sens, c''est pour Dieu; si je suis de bon sens, c''est pour vous.'),
  (47, 5, 14, 'Car l''amour de Christ nous presse, parce que nous estimons que, si un seul est mort pour tous, tous donc sont morts;'),
  (47, 5, 15, 'et qu''il est mort pour tous, afin que ceux qui vivent ne vivent plus pour eux-mêmes, mais pour celui qui est mort et ressuscité pour eux.'),
  (47, 5, 16, 'Ainsi, dès maintenant, nous ne connaissons personne selon la chair; et si nous avons connu Christ selon la chair, maintenant nous ne le connaissons plus de cette manière.'),
  (47, 5, 17, 'Si quelqu''un est en Christ, il est une nouvelle créature. Les choses anciennes sont passées; voici, toutes choses sont devenues nouvelles.'),
  (47, 5, 18, 'Et tout cela vient de Dieu, qui nous a réconciliés avec lui par Christ, et qui nous a donné le ministère de la réconciliation.'),
  (47, 5, 19, 'Car Dieu était en Christ, réconciliant le monde avec lui-même, en n''imputant point aux hommes leurs offenses, et il a mis en nous la parole de la réconciliation.'),
  (47, 5, 20, 'Nous faisons donc les fonctions d''ambassadeurs pour Christ, comme si Dieu exhortait par nous; nous vous en supplions au nom de Christ: Soyez réconciliés avec Dieu!'),
  (47, 5, 21, 'Celui qui n''a point connu le péché, il l''a fait devenir péché pour nous, afin que nous devenions en lui justice de Dieu.'),
  (47, 6, 1, 'Puisque nous travaillons avec Dieu, nous vous exhortons à ne pas recevoir la grâce de Dieu en vain.'),
  (47, 6, 2, 'Car il dit: Au temps favorable je t''ai exaucé, Au jour du salut je t''ai secouru. Voici maintenant le temps favorable, voici maintenant le jour du salut.'),
  (47, 6, 3, 'Nous ne donnons aucun sujet de scandale en quoi que ce soit, afin que le ministère ne soit pas un objet de blâme.'),
  (47, 6, 4, 'Mais nous nous rendons à tous égards recommandables, comme serviteurs de Dieu, par beaucoup de patience dans les tribulations, dans les calamités, dans les détresses,'),
  (47, 6, 5, 'sous les coups, dans les prisons, dans les troubles, dans les travaux, dans les veilles, dans les jeûnes;'),
  (47, 6, 6, 'par la pureté, par la connaissance, par la longanimité, par la bonté, par un esprit saint, par une charité sincère,'),
  (47, 6, 7, 'par la parole de vérité, par la puissance de Dieu, par les armes offensives et défensives de la justice;'),
  (47, 6, 8, 'au milieu de la gloire et de l''ignominie, au milieu de la mauvaise et de la bonne réputation; étant regardés comme imposteurs, quoique véridiques;'),
  (47, 6, 9, 'comme inconnus, quoique bien connus; comme mourants, et voici nous vivons; comme châtiés, quoique non mis à mort;'),
  (47, 6, 10, 'comme attristés, et nous sommes toujours joyeux; comme pauvres, et nous en enrichissons plusieurs; comme n''ayant rien, et nous possédons toutes choses.'),
  (47, 6, 11, 'Notre bouche s''est ouverte pour vous, Corinthiens, notre cœur s''est élargi.'),
  (47, 6, 12, 'Vous n''êtes point à l''étroit au dedans de nous; mais vos entrailles se sont rétrécies.'),
  (47, 6, 13, 'Rendez-nous la pareille, -je vous parle comme à mes enfants, -élargissez-vous aussi!'),
  (47, 6, 14, 'Ne vous mettez pas avec les infidèles sous un joug étranger. Car quel rapport y a-t-il entre la justice et l''iniquité? ou qu''y a-t-il de commun entre la lumière et les ténèbres?'),
  (47, 6, 15, 'Quel accord y a-t-il entre Christ et Bélial? ou quelle part a le fidèle avec l''infidèle?'),
  (47, 6, 16, 'Quel rapport y a-t-il entre le temple de Dieu et les idoles? Car nous sommes le temple du Dieu vivant, comme Dieu l''a dit: J''habiterai et je marcherai au milieu d''eux; je serai leur Dieu, et ils seront mon peuple.'),
  (47, 6, 17, 'C''est pourquoi, Sortez du milieu d''eux, Et séparez-vous, dit le Seigneur; Ne touchez pas à ce qui est impur, Et je vous accueillerai.'),
  (47, 6, 18, 'Je serai pour vous un père, Et vous serez pour moi des fils et des filles, Dit le Seigneur tout-puissant.'),
  (47, 7, 1, 'Ayant donc de telles promesses, bien-aimés, purifions-nous de toute souillure de la chair et de l''esprit, en achevant notre sanctification dans la crainte de Dieu.'),
  (47, 7, 2, 'Donnez-nous une place dans vos cœurs! Nous n''avons fait tort à personne, nous n''avons ruiné personne, nous n''avons tiré du profit de personne.'),
  (47, 7, 3, 'Ce n''est pas pour vous condamner que je parle de la sorte; car j''ai déjà dit que vous êtes dans nos cœurs à la vie et à la mort.'),
  (47, 7, 4, 'J''ai une grande confiance en vous, j''ai tout sujet de me glorifier de vous; je suis rempli de consolation, je suis comblé de joie au milieu de toutes nos tribulations.'),
  (47, 7, 5, 'Car, depuis notre arrivée en Macédoine, notre chair n''eut aucun repos; nous étions affligés de toute manière: luttes au dehors, craintes au dedans.'),
  (47, 7, 6, 'Mais Dieu, qui console ceux qui sont abattus, nous a consolés par l''arrivée de Tite,'),
  (47, 7, 7, 'et non seulement par son arrivée, mais encore par la consolation que Tite lui-même ressentait à votre sujet: il nous a raconté votre ardent désir, vos larmes, votre zèle pour moi, en sorte que ma joie a été d''autant plus grande.'),
  (47, 7, 8, 'Quoique je vous aie attristés par ma lettre, je ne m''en repens pas. Et, si je m''en suis repenti, -car je vois que cette lettre vous a attristés, bien que momentanément, -'),
  (47, 7, 9, 'je me réjouis à cette heure, non pas de ce que vous avez été attristés, mais de ce que votre tristesse vous a portés à la repentance; car vous avez été attristés selon Dieu, afin de ne recevoir de notre part aucun dommage.'),
  (47, 7, 10, 'En effet, la tristesse selon Dieu produit une repentance à salut dont on ne se repent jamais, tandis que la tristesse du monde produit la mort.'),
  (47, 7, 11, 'Et voici, cette même tristesse selon Dieu, quel empressement n''a-t-elle pas produit en vous! Quelle justification, quelle indignation, quelle crainte, quel désir ardent, quel zèle, quelle punition! Vous avez montré à tous égards que vous étiez purs dans cette affaire.'),
  (47, 7, 12, 'Si donc je vous ai écrit, ce n''était ni à cause de celui qui a fait l''injure, ni à cause de celui qui l''a reçue; c''était afin que votre empressement pour nous fût manifesté parmi vous devant Dieu.'),
  (47, 7, 13, 'C''est pourquoi nous avons été consolés. Mais, outre notre consolation, nous avons été réjouis beaucoup plus encore par la joie de Tite, dont l''esprit a été tranquillisé par vous tous.'),
  (47, 7, 14, 'Et si devant lui je me suis un peu glorifié à votre sujet, je n''en ai point eu de confusion; mais, comme nous vous avons toujours parlé selon la vérité, ce dont nous nous sommes glorifiés auprès de Tite s''est trouvé être aussi la vérité.'),
  (47, 7, 15, 'Il éprouve pour vous un redoublement d''affection, au souvenir de votre obéissance à tous, et de l''accueil que vous lui avez fait avec crainte et tremblement.'),
  (47, 7, 16, 'Je me réjouis de pouvoir en toutes choses me confier en vous.'),
  (47, 8, 1, 'Nous vous faisons connaître, frères, la grâce de Dieu qui s''est manifestée dans les Églises de la Macédoine.'),
  (47, 8, 2, 'Au milieu de beaucoup de tribulations qui les ont éprouvées, leur joie débordante et leur pauvreté profonde ont produit avec abondance de riches libéralités de leur part.'),
  (47, 8, 3, 'Ils ont, je l''atteste, donné volontairement selon leurs moyens, et même au delà de leurs moyens,'),
  (47, 8, 4, 'nous demandant avec de grandes instances la grâce de prendre part à l''assistance destinée aux saints.'),
  (47, 8, 5, 'Et non seulement ils ont contribué comme nous l''espérions, mais ils se sont d''abord donnés eux-mêmes au Seigneur, puis à nous, par la volonté de Dieu.'),
  (47, 8, 6, 'Nous avons donc engagé Tite à achever chez vous cette œuvre de bienfaisance, comme il l''avait commencée.'),
  (47, 8, 7, 'De même que vous excellez en toutes choses, en foi, en parole, en connaissance, en zèle à tous égards, et dans votre amour pour nous, faites en sorte d''exceller aussi dans cette œuvre de bienfaisance.'),
  (47, 8, 8, 'Je ne dis pas cela pour donner un ordre, mais pour éprouver, par le zèle des autres, la sincérité de votre charité.'),
  (47, 8, 9, 'Car vous connaissez la grâce de notre Seigneur Jésus-Christ, qui pour vous s''est fait pauvre, de riche qu''il était, afin que par sa pauvreté vous fussiez enrichis.'),
  (47, 8, 10, 'C''est un avis que je donne là-dessus, car cela vous convient, à vous qui non seulement avez commencé à agir, mais qui en avez eu la volonté dès l''année dernière.'),
  (47, 8, 11, 'Achevez donc maintenant d''agir, afin que l''accomplissement selon vos moyens réponde à l''empressement que vous avez mis à vouloir.'),
  (47, 8, 12, 'La bonne volonté, quand elle existe, est agréable en raison de ce qu''elle peut avoir à sa disposition, et non de ce qu''elle n''a pas.'),
  (47, 8, 13, 'Car il s''agit, non de vous exposer à la détresse pour soulager les autres,'),
  (47, 8, 14, 'mais de suivre une règle d''égalité: dans la circonstance présente votre superflu pourvoira à leurs besoins, afin que leur superflu pourvoie pareillement aux vôtres, en sorte qu''il y ait égalité,'),
  (47, 8, 15, 'selon qu''il est écrit: Celui qui avait ramassé beaucoup n''avait rien de trop, et celui qui avait ramassé peu n''en manquait pas.'),
  (47, 8, 16, 'Grâces soient rendues à Dieu de ce qu''il a mis dans le cœur de Tite le même empressement pour vous;'),
  (47, 8, 17, 'car il a accueilli notre demande, et c''est avec un nouveau zèle et de son plein gré qu''il part pour aller chez vous.'),
  (47, 8, 18, 'Nous envoyons avec lui le frère dont la louange en ce qui concerne l''Évangile est répandue dans toutes les Églises,'),
  (47, 8, 19, 'et qui, de plus, a été choisi par les Églises pour être notre compagnon de voyage dans cette œuvre de bienfaisance, que nous accomplissons à la gloire du Seigneur même et en témoignage de notre bonne volonté.'),
  (47, 8, 20, 'Nous agissons ainsi, afin que personne ne nous blâme au sujet de cette abondante collecte, à laquelle nous donnons nos soins;'),
  (47, 8, 21, 'car nous recherchons ce qui est bien, non seulement devant le Seigneur, mais aussi devant les hommes.'),
  (47, 8, 22, 'Nous envoyons avec eux notre frère, dont nous avons souvent éprouvé le zèle dans beaucoup d''occasions, et qui en montre plus encore cette fois à cause de sa grande confiance en vous.'),
  (47, 8, 23, 'Ainsi, pour ce qui est de Tite, il est notre associé et notre compagnon d''œuvre auprès de vous; et pour ce qui est de nos frères, ils sont les envoyés des Églises, la gloire de Christ.'),
  (47, 8, 24, 'Donnez-leur donc, à la face des Églises, la preuve de votre charité, et montrez-leur que nous avons sujet de nous glorifier de vous.'),
  (47, 9, 1, 'Il est superflu que je vous écrive touchant l''assistance destinée aux saints.'),
  (47, 9, 2, 'Je connais, en effet, votre bonne volonté, dont je me glorifie pour vous auprès des Macédoniens, en déclarant que l''Achaïe est prête depuis l''année dernière; et ce zèle de votre part a stimulé le plus grand nombre.'),
  (47, 9, 3, 'J''envoie les frères, afin que l''éloge que nous avons fait de vous ne soit pas réduit à néant sur ce point-là, et que vous soyez prêts, comme je l''ai dit.'),
  (47, 9, 4, 'Je ne voudrais pas, si les Macédoniens m''accompagnent et ne vous trouvent pas prêts, que cette assurance tournât à notre confusion, pour ne pas dire à la vôtre.'),
  (47, 9, 5, 'J''ai donc jugé nécessaire d''inviter les frères à se rendre auparavant chez vous, et à s''occuper de votre libéralité déjà promise, afin qu''elle soit prête, de manière à être une libéralité, et non un acte d''avarice.'),
  (47, 9, 6, 'Sachez-le, celui qui sème peu moissonnera peu, et celui qui sème abondamment moissonnera abondamment.'),
  (47, 9, 7, 'Que chacun donne comme il l''a résolu en son cœur, sans tristesse ni contrainte; car Dieu aime celui qui donne avec joie.'),
  (47, 9, 8, 'Et Dieu peut vous combler de toutes sortes de grâces, afin que, possédant toujours en toutes choses de quoi satisfaire à tous vos besoins, vous ayez encore en abondance pour toute bonne œuvre,'),
  (47, 9, 9, 'selon qu''il est écrit: Il a fait des largesses, il a donné aux indigents; Sa justice subsiste à jamais.'),
  (47, 9, 10, 'Celui qui Fournit de la semence au semeur, Et du pain pour sa nourriture, vous fournira et vous multipliera la semence, et il augmentera les fruits de votre justice.'),
  (47, 9, 11, 'Vous serez de la sorte enrichis à tous égards pour toute espèce de libéralités qui, par notre moyen, feront offrir à Dieu des actions de grâces.'),
  (47, 9, 12, 'Car le secours de cette assistance non seulement pourvoit aux besoins des saints, mais il est encore une source abondante de nombreuses actions de grâces envers Dieu.'),
  (47, 9, 13, 'En considération de ce secours dont ils font l''expérience, ils glorifient Dieu de votre obéissance dans la profession de l''Évangile de Christ, et de la libéralité de vos dons envers eux et envers tous;'),
  (47, 9, 14, 'ils prient pour vous, parce qu''ils vous aiment à cause de la grâce éminente que Dieu vous a faite.'),
  (47, 9, 15, 'Grâces soient rendues à Dieu pour son don ineffable!'),
  (47, 10, 1, 'Moi Paul, je vous prie, par la douceur et la bonté de Christ, -moi, humble d''apparence quand je suis au milieu de vous, et plein de hardiesse à votre égard quand je suis éloigné, -'),
  (47, 10, 2, 'je vous prie, lorsque je serai présent, de ne pas me forcer à recourir avec assurance à cette hardiesse, dont je me propose d''user contre quelques-uns qui nous regardent comme marchant selon la chair.'),
  (47, 10, 3, 'Si nous marchons dans la chair, nous ne combattons pas selon la chair.'),
  (47, 10, 4, 'Car les armes avec lesquelles nous combattons ne sont pas charnelles; mais elles sont puissantes, par la vertu de Dieu, pour renverser des forteresses.'),
  (47, 10, 5, 'Nous renversons les raisonnements et toute hauteur qui s''élève contre la connaissance de Dieu, et nous amenons toute pensée captive à l''obéissance de Christ.'),
  (47, 10, 6, 'Nous sommes prêts aussi à punir toute désobéissance, lorsque votre obéissance sera complète.'),
  (47, 10, 7, 'Vous regardez à l''apparence! Si quelqu''un se persuade qu''il est de Christ, qu''il se dise bien en lui-même que, comme il est de Christ, nous aussi nous sommes de Christ.'),
  (47, 10, 8, 'Et quand même je me glorifierais un peu trop de l''autorité que le Seigneur nous a donnée pour votre édification et non pour votre destruction, je ne saurais en avoir honte,'),
  (47, 10, 9, 'afin que je ne paraisse pas vouloir vous intimider par mes lettres.'),
  (47, 10, 10, 'Car, dit-on, ses lettres sont sévères et fortes; mais, présent en personne, il est faible, et sa parole est méprisable.'),
  (47, 10, 11, 'Que celui qui parle de la sorte considère que tels nous sommes en paroles dans nos lettres, étant absents, tels aussi nous sommes dans nos actes, étant présents.'),
  (47, 10, 12, 'Nous n''osons pas nous égaler ou nous comparer à quelques-uns de ceux qui se recommandent eux-mêmes. Mais, en se mesurant à leur propre mesure et en se comparant à eux-mêmes, ils manquent d''intelligence.'),
  (47, 10, 13, 'Pour nous, nous ne voulons pas nous glorifier hors de toute mesure; nous prendrons, au contraire, pour mesure les limites du partage que Dieu nous a assigné, de manière à nous faire venir aussi jusqu''à vous.'),
  (47, 10, 14, 'Nous ne dépassons point nos limites, comme si nous n''étions pas venus jusqu''à vous; car c''est bien jusqu''à vous que nous sommes arrivés avec l''Évangile de Christ.'),
  (47, 10, 15, 'Ce n''est pas hors de toute mesure, ce n''est pas des travaux d''autrui, que nous nous glorifions; mais c''est avec l''espérance, si votre foi augmente, de grandir encore d''avantage parmi vous, selon les limites qui nous sont assignées,'),
  (47, 10, 16, 'et d''annoncer l''Évangile au delà de chez vous, sans nous glorifier de ce qui a été fait dans les limites assignées à d''autres.'),
  (47, 10, 17, 'Que celui qui se glorifie se glorifie dans le Seigneur.'),
  (47, 10, 18, 'Car ce n''est pas celui qui se recommande lui-même qui est approuvé, c''est celui que le Seigneur recommande.'),
  (47, 11, 1, 'Oh! si vous pouviez supporter de ma part un peu de folie! Mais vous, me supportez!'),
  (47, 11, 2, 'Car je suis jaloux de vous d''une jalousie de Dieu, parce que je vous ai fiancés à un seul époux, pour vous présenter à Christ comme une vierge pure.'),
  (47, 11, 3, 'Toutefois, de même que le serpent séduisit Eve par sa ruse, je crains que vos pensées ne se corrompent et ne se détournent de la simplicité à l''égard de Christ.'),
  (47, 11, 4, 'Car, si quelqu''un vient vous prêcher un autre Jésus que celui que nous avons prêché, ou si vous recevez un autre Esprit que celui que vous avez reçu, ou un autre Évangile que celui que vous avez embrassé, vous le supportez fort bien.'),
  (47, 11, 5, 'Or, j''estime que je n''ai été inférieur en rien à ces apôtres par excellence.'),
  (47, 11, 6, 'Si je suis un ignorant sous le rapport du langage, je ne le suis point sous celui de la connaissance, et nous l''avons montré parmi vous à tous égards et en toutes choses.'),
  (47, 11, 7, 'Ou bien, ai-je commis un péché parce que, m''abaissant moi-même afin que vous fussiez élevés, je vous ai annoncé gratuitement l''Évangile de Dieu?'),
  (47, 11, 8, 'J''ai dépouillé d''autres Églises, en recevant d''elles un salaire, pour vous servir.'),
  (47, 11, 9, 'Et lorsque j''étais chez vous et que je me suis trouvé dans le besoin, je n''ai été à charge à personne; car les frères venus de Macédoine ont pourvu à ce qui me manquait. En toutes choses je me suis gardé de vous être à charge, et je m''en garderai.'),
  (47, 11, 10, 'Par la vérité de Christ qui est en moi, je déclare que ce sujet de gloire ne me sera pas enlevé dans les contrées de l''Achaïe.')
insert into public.bible_verses (book_id, chapter, verse, text) values
  (47, 11, 11, 'Pourquoi?… Parce que je ne vous aime pas?… Dieu le sait!'),
  (47, 11, 12, 'Mais j''agis et j''agirai de la sorte, pour ôter ce prétexte à ceux qui cherchent un prétexte, afin qu''ils soient trouvés tels que nous dans les choses dont ils se glorifient.'),
  (47, 11, 13, 'Ces hommes-là sont de faux apôtres, des ouvriers trompeurs, déguisés en apôtres de Christ.'),
  (47, 11, 14, 'Et cela n''est pas étonnant, puisque Satan lui-même se déguise en ange de lumière.'),
  (47, 11, 15, 'Il n''est donc pas étrange que ses ministres aussi se déguisent en ministres de justice. Leur fin sera selon leurs œuvres.'),
  (47, 11, 16, 'Je le répète, que personne ne me regarde comme un insensé; sinon, recevez-moi comme un insensé, afin que moi aussi, je me glorifie un peu.'),
  (47, 11, 17, 'Ce que je dis, avec l''assurance d''avoir sujet de me glorifier, je ne le dis pas selon le Seigneur, mais comme par folie.'),
  (47, 11, 18, 'Puisqu''il en est plusieurs qui se glorifient selon la chair, je me glorifierai aussi.'),
  (47, 11, 19, 'Car vous supportez volontiers les insensés, vous qui êtes sages.'),
  (47, 11, 20, 'Si quelqu''un vous asservit, si quelqu''un vous dévore, si quelqu''un s''empare de vous, si quelqu''un est arrogant, si quelqu''un vous frappe au visage, vous le supportez.'),
  (47, 11, 21, 'J''ai honte de le dire, nous avons montré de la faiblesse. Cependant, tout ce que peut oser quelqu''un, -je parle en insensé, -moi aussi, je l''ose!'),
  (47, 11, 22, 'Sont-ils Hébreux? Moi aussi. Sont-ils Israélites? Moi aussi. Sont-ils de la postérité d''Abraham? Moi aussi.'),
  (47, 11, 23, 'Sont-ils ministres de Christ? -Je parle en homme qui extravague. -Je le suis plus encore: par les travaux, bien plus; par les coups, bien plus; par les emprisonnements, bien plus. Souvent en danger de mort,'),
  (47, 11, 24, 'cinq fois j''ai reçu des Juifs quarante coups moins un,'),
  (47, 11, 25, 'trois fois j''ai été battu de verges, une fois j''ai été lapidé, trois fois j''ai fait naufrage, j''ai passé un jour et une nuit dans l''abîme.'),
  (47, 11, 26, 'Fréquemment en voyage, j''ai été en péril sur les fleuves, en péril de la part des brigands, en péril de la part de ceux de ma nation, en péril de la part des païens, en péril dans les villes, en péril dans les déserts, en péril sur la mer, en péril parmi les faux frères.'),
  (47, 11, 27, 'J''ai été dans le travail et dans la peine, exposé à de nombreuses veilles, à la faim et à la soif, à des jeûnes multipliés, au froid et à la nudité.'),
  (47, 11, 28, 'Et, sans parler d''autres choses, je suis assiégé chaque jour par les soucis que me donnent toutes les Églises.'),
  (47, 11, 29, 'Qui est faible, que je ne sois faible? Qui vient à tomber, que je ne brûle?'),
  (47, 11, 30, 'S''il faut se glorifier, c''est de ma faiblesse que je me glorifierai!'),
  (47, 11, 31, 'Dieu, qui est le Père du Seigneur Jésus, et qui est béni éternellement, sait que je ne mens point!…'),
  (47, 11, 32, 'A Damas, le gouverneur du roi Arétas faisait garder la ville des Damascéniens, pour se saisir de moi;'),
  (47, 11, 33, 'mais on me descendit par une fenêtre, dans une corbeille, le long de la muraille, et j''échappai de leurs mains.'),
  (47, 12, 1, 'Il faut se glorifier… Cela n''est pas bon. J''en viendrai néanmoins à des visions et à des révélations du Seigneur.'),
  (47, 12, 2, 'Je connais un homme en Christ, qui fut, il y a quatorze ans, ravi jusqu''au troisième ciel (si ce fut dans son corps je ne sais, si ce fut hors de son corps je ne sais, Dieu le sait).'),
  (47, 12, 3, 'Et je sais que cet homme (si ce fut dans son corps ou sans son corps je ne sais, Dieu le sait)'),
  (47, 12, 4, 'fut enlevé dans le paradis, et qu''il entendit des paroles ineffables qu''il n''est pas permis à un homme d''exprimer.'),
  (47, 12, 5, 'Je me glorifierai d''un tel homme, mais de moi-même je ne me glorifierai pas, sinon de mes infirmités.'),
  (47, 12, 6, 'Si je voulais me glorifier, je ne serais pas un insensé, car je dirais la vérité; mais je m''en abstiens, afin que personne n''ait à mon sujet une opinion supérieure à ce qu''il voit en moi ou à ce qu''il entend de moi.'),
  (47, 12, 7, 'Et pour que je ne sois pas enflé d''orgueil, à cause de l''excellence de ces révélations, il m''a été mis une écharde dans la chair, un ange de Satan pour me souffleter et m''empêcher de m''enorgueillir.'),
  (47, 12, 8, 'Trois fois j''ai prié le Seigneur de l''éloigner de moi,'),
  (47, 12, 9, 'et il m''a dit: Ma grâce te suffit, car ma puissance s''accomplit dans la faiblesse. Je me glorifierai donc bien plus volontiers de mes faiblesses, afin que la puissance de Christ repose sur moi.'),
  (47, 12, 10, 'C''est pourquoi je me plais dans les faiblesses, dans les outrages, dans les calamités, dans les persécutions, dans les détresses, pour Christ; car, quand je suis faible, c''est alors que je suis fort.'),
  (47, 12, 11, 'J''ai été un insensé: vous m''y avez contraint. C''est par vous que je devais être recommandé, car je n''ai été inférieur en rien aux apôtres par excellence, quoique je ne sois rien.'),
  (47, 12, 12, 'Les preuves de mon apostolat ont éclaté au milieu de vous par une patience à toute épreuve, par des signes, des prodiges et des miracles.'),
  (47, 12, 13, 'En quoi avez-vous été traités moins favorablement que les autres Églises, sinon en ce que je ne vous ai point été à charge? Pardonnez-moi ce tort.'),
  (47, 12, 14, 'Voici, pour la troisième fois je suis prêt à aller chez vous, et je ne vous serai point à charge; car ce ne sont pas vos biens que je cherche, c''est vous-mêmes. Ce n''est pas, en effet, aux enfants à amasser pour leurs parents, mais aux parents pour leurs enfants.'),
  (47, 12, 15, 'Pour moi, je dépenserai très volontiers, et je me dépenserai moi-même pour vos âmes, dussé-je, en vous aimant davantage, être moins aimé de vous.'),
  (47, 12, 16, 'Soit! je ne vous ai point été à charge; mais, en homme astucieux, je vous ai pris par ruse!'),
  (47, 12, 17, 'Ai-je tiré du profit de vous par quelqu''un de ceux que je vous ai envoyés?'),
  (47, 12, 18, 'J''ai engagé Tite à aller chez vous, et avec lui j''ai envoyé le frère: est-ce que Tite a exigé quelque chose de vous? N''avons-nous pas marché dans le même esprit, sur les mêmes traces?'),
  (47, 12, 19, 'Vous vous imaginez depuis longtemps que nous nous justifions auprès de vous. C''est devant Dieu, en Christ, que nous parlons; et tout cela, bien-aimés, nous le disons pour votre édification.'),
  (47, 12, 20, 'Car je crains de ne pas vous trouver, à mon arrivée, tels que je voudrais, et d''être moi-même trouvé par vous tel que vous ne voudriez pas. Je crains de trouver des querelles, de la jalousie, des animosités, des cabales, des médisances, des calomnies, de l''orgueil, des troubles.'),
  (47, 12, 21, 'Je crains qu''à mon arrivée mon Dieu ne m''humilie de nouveau à votre sujet, et que je n''aie à pleurer sur plusieurs de ceux qui ont péché précédemment et qui ne se sont pas repentis de l''impureté, de l''impudicité et des dissolutions auxquelles ils se sont livrés.'),
  (47, 13, 1, 'Je vais chez vous pour la troisième fois. Toute affaire se réglera sur la déclaration de deux ou de trois témoins.'),
  (47, 13, 2, 'Lorsque j''étais présent pour la seconde fois, j''ai déjà dit, et aujourd''hui que je suis absent je dis encore d''avance à ceux qui ont péché précédemment et à tous les autres que, si je retourne chez vous, je n''userai d''aucun ménagement,'),
  (47, 13, 3, 'puisque vous cherchez une preuve que Christ parle en moi, lui qui n''est pas faible à votre égard, mais qui est puissant parmi vous.'),
  (47, 13, 4, 'Car il a été crucifié à cause de sa faiblesse, mais il vit par la puissance de Dieu; nous aussi, nous sommes faibles en lui, mais nous vivrons avec lui par la puissance de Dieu pour agir envers vous.'),
  (47, 13, 5, 'Examinez-vous vous mêmes, pour savoir si vous êtes dans la foi; éprouvez-vous vous-mêmes. Ne reconnaissez-vous pas que Jésus-Christ est en vous? à moins peut-être que vous ne soyez réprouvés.'),
  (47, 13, 6, 'Mais j''espère que vous reconnaîtrez que nous, nous ne sommes pas réprouvés.'),
  (47, 13, 7, 'Cependant nous prions Dieu que vous ne fassiez rien de mal, non pour paraître nous-mêmes approuvés, mais afin que vous pratiquiez ce qui est bien et que nous, nous soyons comme réprouvés.'),
  (47, 13, 8, 'Car nous n''avons pas de puissance contre la vérité; nous n''en avons que pour la vérité.'),
  (47, 13, 9, 'Nous nous réjouissons lorsque nous sommes faibles, tandis que vous êtes forts; et ce que nous demandons dans nos prières, c''est votre perfectionnement.'),
  (47, 13, 10, 'C''est pourquoi j''écris ces choses étant absent, afin que, présent, je n''aie pas à user de rigueur, selon l''autorité que le Seigneur m''a donnée pour l''édification et non pour la destruction.'),
  (47, 13, 11, 'Au reste, frères, soyez dans la joie, perfectionnez-vous, consolez-vous, ayez un même sentiment, vivez en paix; et le Dieu d''amour et de paix sera avec vous.'),
  (47, 13, 12, 'Saluez-vous les uns les autres par un saint baiser.'),
  (47, 13, 13, 'Tous les saints vous saluent.'),
  (47, 13, 14, 'Que la grâce du Seigneur Jésus-Christ, l''amour de Dieu, et la communication du Saint-Esprit, soient avec vous tous!'),
  (48, 1, 1, 'Paul, apôtre, non de la part des hommes, ni par un homme, mais par Jésus-Christ et Dieu le Père, qui l''a ressuscité des morts,'),
  (48, 1, 2, 'et tous les frères qui sont avec moi, aux Églises de la Galatie:'),
  (48, 1, 3, 'que la grâce et la paix vous soient données de la part de Dieu le Père et de notre Seigneur Jésus-Christ,'),
  (48, 1, 4, 'qui s''est donné lui-même pour nos péchés, afin de nous arracher du présent siècle mauvais, selon la volonté de notre Dieu et Père,'),
  (48, 1, 5, 'à qui soit la gloire aux siècles des siècles! Amen!'),
  (48, 1, 6, 'Je m''étonne que vous vous détourniez si promptement de celui qui vous a appelés par la grâce de Christ, pour passer à un autre Évangile.'),
  (48, 1, 7, 'Non pas qu''il y ait un autre Évangile, mais il y a des gens qui vous troublent, et qui veulent renverser l''Évangile de Christ.'),
  (48, 1, 8, 'Mais, quand nous-mêmes, quand un ange du ciel annoncerait un autre Évangile que celui que nous vous avons prêché, qu''il soit anathème!'),
  (48, 1, 9, 'Nous l''avons dit précédemment, et je le répète à cette heure: si quelqu''un vous annonce un autre Évangile que celui que vous avez reçu, qu''il soit anathème!'),
  (48, 1, 10, 'Et maintenant, est-ce la faveur des hommes que je désire, ou celle de Dieu? Est-ce que je cherche à plaire aux hommes? Si je plaisais encore aux hommes, je ne serais pas serviteur de Christ.'),
  (48, 1, 11, 'Je vous déclare, frères, que l''Évangile qui a été annoncé par moi n''est pas de l''homme;'),
  (48, 1, 12, 'car je ne l''ai ni reçu ni appris d''un homme, mais par une révélation de Jésus-Christ.'),
  (48, 1, 13, 'Vous avez su, en effet, quelle était autrefois ma conduite dans le judaïsme, comment je persécutais à outrance et ravageais l''Église de Dieu,'),
  (48, 1, 14, 'et comment j''étais plus avancé dans le judaïsme que beaucoup de ceux de mon âge et de ma nation, étant animé d''un zèle excessif pour les traditions de mes pères.'),
  (48, 1, 15, 'Mais, lorsqu''il plut à celui qui m''avait mis à part dès le sein de ma mère, et qui m''a appelé par sa grâce,'),
  (48, 1, 16, 'de révéler en moi son Fils, afin que je l''annonçasse parmi les païens, aussitôt, je ne consultai ni la chair ni le sang,'),
  (48, 1, 17, 'et je ne montai point à Jérusalem vers ceux qui furent apôtres avant moi, mais je partis pour l''Arabie. Puis je revins encore à Damas.'),
  (48, 1, 18, 'Trois ans plus tard, je montai à Jérusalem pour faire la connaissance de Céphas, et je demeurai quinze jours chez lui.'),
  (48, 1, 19, 'Mais je ne vis aucun autre des apôtres, si ce n''est Jacques, le frère du Seigneur.'),
  (48, 1, 20, 'Dans ce que je vous écris, voici, devant Dieu, je ne mens point.'),
  (48, 1, 21, 'J''allai ensuite dans les contrées de la Syrie et de la Cilicie.'),
  (48, 1, 22, 'Or, j''étais inconnu de visage aux Églises de Judée qui sont en Christ;'),
  (48, 1, 23, 'seulement, elles avaient entendu dire: Celui qui autrefois nous persécutait annonce maintenant la foi qu''il s''efforçait alors de détruire.'),
  (48, 1, 24, 'Et elles glorifiaient Dieu à mon sujet.'),
  (48, 2, 1, 'Quatorze ans après, je montai de nouveau à Jérusalem avec Barnabas, ayant aussi pris Tite avec moi;'),
  (48, 2, 2, 'et ce fut d''après une révélation que j''y montai. Je leur exposai l''Évangile que je prêche parmi les païens, je l''exposai en particulier à ceux qui sont les plus considérés, afin de ne pas courir ou avoir couru en vain.'),
  (48, 2, 3, 'Mais Tite, qui était avec moi, et qui était Grec, ne fut pas même contraint de se faire circoncire.'),
  (48, 2, 4, 'Et cela, à cause des faux frères qui s''étaient furtivement introduits et glissés parmi nous, pour épier la liberté que nous avons en Jésus-Christ, avec l''intention de nous asservir.'),
  (48, 2, 5, 'Nous ne leur cédâmes pas un instant et nous résistâmes à leurs exigences, afin que la vérité de l''Évangile fût maintenue parmi vous.'),
  (48, 2, 6, 'Ceux qui sont les plus considérés-quels qu''ils aient été jadis, cela ne m''importe pas: Dieu ne fait point acception de personnes, - ceux qui sont les plus considérés ne m''imposèrent rien.'),
  (48, 2, 7, 'Au contraire, voyant que l''Évangile m''avait été confié pour les incirconcis, comme à Pierre pour les circoncis, -'),
  (48, 2, 8, 'car celui qui a fait de Pierre l''apôtre des circoncis a aussi fait de moi l''apôtre des païens, -'),
  (48, 2, 9, 'et ayant reconnu la grâce qui m''avait été accordée, Jacques, Céphas et Jean, qui sont regardés comme des colonnes, me donnèrent, à moi et à Barnabas, la main d''association, afin que nous allassions, nous vers les païens, et eux vers les circoncis.'),
  (48, 2, 10, 'Ils nous recommandèrent seulement de nous souvenir des pauvres, ce que j''ai bien eu soin de faire.'),
  (48, 2, 11, 'Mais lorsque Céphas vint à Antioche, je lui résistai en face, parce qu''il était répréhensible.'),
  (48, 2, 12, 'En effet, avant l''arrivée de quelques personnes envoyées par Jacques, il mangeait avec les païens; et, quand elles furent venues, il s''esquiva et se tint à l''écart, par crainte des circoncis.'),
  (48, 2, 13, 'Avec lui les autres Juifs usèrent aussi de dissimulation, en sorte que Barnabas même fut entraîné par leur hypocrisie.'),
  (48, 2, 14, 'Voyant qu''ils ne marchaient pas droit selon la vérité de l''Évangile, je dis à Céphas, en présence de tous: Si toi qui es Juif, tu vis à la manière des païens et non à la manière des Juifs, pourquoi forces-tu les païens à judaïser?'),
  (48, 2, 15, 'Nous, nous sommes Juifs de naissance, et non pécheurs d''entre les païens.'),
  (48, 2, 16, 'Néanmoins, sachant que ce n''est pas par les œuvres de la loi que l''homme est justifié, mais par la foi en Jésus-Christ, nous aussi nous avons cru en Jésus-Christ, afin d''être justifiés par la foi en Christ et non par les œuvres de la loi, parce que nulle chair ne sera justifiée par les œuvres de la loi.'),
  (48, 2, 17, 'Mais, tandis que nous cherchons à être justifiés par Christ, si nous étions aussi nous-mêmes trouvés pécheurs, Christ serait-il un ministre du péché? Loin de là!'),
  (48, 2, 18, 'Car, si je rebâtis les choses que j''ai détruites, je me constitue moi-même un transgresseur,'),
  (48, 2, 19, 'car c''est par la loi que je suis mort à la loi, afin de vivre pour Dieu.'),
  (48, 2, 20, 'J''ai été crucifié avec Christ; et si je vis, ce n''est plus moi qui vis, c''est Christ qui vit en moi; si je vis maintenant dans la chair, je vis dans la foi au Fils de Dieu, qui m''a aimé et qui s''est livré lui-même pour moi.'),
  (48, 2, 21, 'Je ne rejette pas la grâce de Dieu; car si la justice s''obtient par la loi, Christ est donc mort en vain.'),
  (48, 3, 1, 'O Galates, dépourvus de sens! qui vous a fascinés, vous, aux yeux de qui Jésus-Christ a été peint comme crucifié?'),
  (48, 3, 2, 'Voici seulement ce que je veux apprendre de vous: Est-ce par les œuvres de la loi que vous avez reçu l''Esprit, ou par la prédication de la foi?'),
  (48, 3, 3, 'Etes-vous tellement dépourvus de sens? Après avoir commencé par l''Esprit, voulez-vous maintenant finir par la chair?'),
  (48, 3, 4, 'Avez-vous tant souffert en vain? si toutefois c''est en vain.'),
  (48, 3, 5, 'Celui qui vous accorde l''Esprit, et qui opère des miracles parmi vous, le fait-il donc par les œuvres de la loi, ou par la prédication de la foi?'),
  (48, 3, 6, 'Comme Abraham crut à Dieu, et que cela lui fut imputé à justice,'),
  (48, 3, 7, 'reconnaissez donc que ce sont ceux qui ont la foi qui sont fils d''Abraham.'),
  (48, 3, 8, 'Aussi l''Écriture, prévoyant que Dieu justifierait les païens par la foi, a d''avance annoncé cette bonne nouvelle à Abraham: Toutes les nations seront bénies en toi!'),
  (48, 3, 9, 'de sorte que ceux qui croient sont bénis avec Abraham le croyant.'),
  (48, 3, 10, 'Car tous ceux qui s''attachent aux œuvres de la loi sont sous la malédiction; car il est écrit: Maudit est quiconque n''observe pas tout ce qui est écrit dans le livre de la loi, et ne le met pas en pratique.'),
  (48, 3, 11, 'Et que nul ne soit justifié devant Dieu par la loi, cela est évident, puisqu''il est dit: Le juste vivra par la foi.'),
  (48, 3, 12, 'Or, la loi ne procède pas de la foi; mais elle dit: Celui qui mettra ces choses en pratique vivra par elles.'),
  (48, 3, 13, 'Christ nous a rachetés de la malédiction de la loi, étant devenu malédiction pour nous-car il est écrit: Maudit est quiconque est pendu au bois, -'),
  (48, 3, 14, 'afin que la bénédiction d''Abraham eût pour les païens son accomplissement en Jésus-Christ, et que nous reçussions par la foi l''Esprit qui avait été promis.'),
  (48, 3, 15, 'Frères (je parle à la manière des hommes), une disposition en bonne forme, bien que faite par un homme, n''est annulée par personne, et personne n''y ajoute.'),
  (48, 3, 16, 'Or les promesses ont été faites à Abraham et à sa postérité. Il n''est pas dit: et aux postérités, comme s''il s''agissait de plusieurs, mais en tant qu''il s''agit d''une seule: et à ta postérité, c''est-à-dire, à Christ.'),
  (48, 3, 17, 'Voici ce que j''entends: une disposition, que Dieu a confirmée antérieurement, ne peut pas être annulée, et ainsi la promesse rendue vaine, par la loi survenue quatre cent trente ans plus tard.'),
  (48, 3, 18, 'Car si l''héritage venait de la loi, il ne viendrait plus de la promesse; or, c''est par la promesse que Dieu a fait à Abraham ce don de sa grâce.'),
  (48, 3, 19, 'Pourquoi donc la loi? Elle a été donnée ensuite à cause des transgressions, jusqu''à ce que vînt la postérité à qui la promesse avait été faite; elle a été promulguée par des anges, au moyen d''un médiateur.'),
  (48, 3, 20, 'Or, le médiateur n''est pas médiateur d''un seul, tandis que Dieu est un seul.'),
  (48, 3, 21, 'La loi est-elle donc contre les promesses de Dieu? Loin de là! S''il eût été donné une loi qui pût procurer la vie, la justice viendrait réellement de la loi.'),
  (48, 3, 22, 'Mais l''Écriture a tout renfermé sous le péché, afin que ce qui avait été promis fût donné par la foi en Jésus-Christ à ceux qui croient.'),
  (48, 3, 23, 'Avant que la foi vînt, nous étions enfermés sous la garde de la loi, en vue de la foi qui devait être révélée.'),
  (48, 3, 24, 'Ainsi la loi a été comme un pédagogue pour nous conduire à Christ, afin que nous fussions justifiés par la foi.'),
  (48, 3, 25, 'La foi étant venue, nous ne sommes plus sous ce pédagogue.'),
  (48, 3, 26, 'Car vous êtes tous fils de Dieu par la foi en Jésus-Christ;'),
  (48, 3, 27, 'vous tous, qui avez été baptisés en Christ, vous avez revêtu Christ.'),
  (48, 3, 28, 'Il n''y a plus ni Juif ni Grec, il n''y a plus ni esclave ni libre, il n''y a plus ni homme ni femme; car tous vous êtes un en Jésus-Christ.'),
  (48, 3, 29, 'Et si vous êtes à Christ, vous êtes donc la postérité d''Abraham, héritiers selon la promesse.'),
  (48, 4, 1, 'Or, aussi longtemps que l''héritier est enfant, je dis qu''il ne diffère en rien d''un esclave, quoiqu''il soit le maître de tout;'),
  (48, 4, 2, 'mais il est sous des tuteurs et des administrateurs jusqu''au temps marqué par le père.'),
  (48, 4, 3, 'Nous aussi, de la même manière, lorsque nous étions enfants, nous étions sous l''esclavage des rudiments du monde;'),
  (48, 4, 4, 'mais, lorsque les temps ont été accomplis, Dieu a envoyé son Fils, né d''une femme, né sous la loi,'),
  (48, 4, 5, 'afin qu''il rachetât ceux qui étaient sous la loi, afin que nous reçussions l''adoption.'),
  (48, 4, 6, 'Et parce que vous êtes fils, Dieu a envoyé dans nos cœurs l''Esprit de son Fils, lequel crie: Abba! Père!'),
  (48, 4, 7, 'Ainsi tu n''es plus esclave, mais fils; et si tu es fils, tu es aussi héritier par la grâce de Dieu.'),
  (48, 4, 8, 'Autrefois, ne connaissant pas Dieu, vous serviez des dieux qui ne le sont pas de leur nature;'),
  (48, 4, 9, 'mais à présent que vous avez connu Dieu, ou plutôt que vous avez été connus de Dieu, comment retournez-vous à ces faibles et pauvres rudiments, auxquels de nouveau vous voulez vous asservir encore?'),
  (48, 4, 10, 'Vous observez les jours, les mois, les temps et les années!'),
  (48, 4, 11, 'Je crains d''avoir inutilement travaillé pour vous.'),
  (48, 4, 12, 'Soyez comme moi, car moi aussi je suis comme vous. Frères, je vous en supplie. Vous ne m''avez fait aucun tort.'),
  (48, 4, 13, 'Vous savez que ce fut à cause d''une infirmité de la chair que je vous ai pour la première fois annoncé l''Évangile.'),
  (48, 4, 14, 'Et mis à l''épreuve par ma chair, vous n''avez témoigné ni mépris ni dégoût; vous m''avez, au contraire, reçu comme un ange de Dieu, comme Jésus-Christ.'),
  (48, 4, 15, 'Où donc est l''expression de votre bonheur? Car je vous atteste que, si cela eût été possible, vous vous seriez arraché les yeux pour me les donner.'),
  (48, 4, 16, 'Suis-je devenu votre ennemi en vous disant la vérité?'),
  (48, 4, 17, 'Le zèle qu''ils ont pour vous n''est pas pur, mais ils veulent vous détacher de nous, afin que vous soyez zélés pour eux.'),
  (48, 4, 18, 'Il est beau d''avoir du zèle pour ce qui est bien et en tout temps, et non pas seulement quand je suis présent parmi vous.'),
  (48, 4, 19, 'Mes enfants, pour qui j''éprouve de nouveau les douleurs de l''enfantement, jusqu''à ce que Christ soit formé en vous,'),
  (48, 4, 20, 'je voudrais être maintenant auprès de vous, et changer de langage, car je suis dans l''inquiétude à votre sujet.'),
  (48, 4, 21, 'Dites-moi, vous qui voulez être sous la loi, n''entendez-vous point la loi?'),
  (48, 4, 22, 'Car il est écrit qu''Abraham eut deux fils, un de la femme esclave, et un de la femme libre.'),
  (48, 4, 23, 'Mais celui de l''esclave naquit selon la chair, et celui de la femme libre naquit en vertu de la promesse.'),
  (48, 4, 24, 'Ces choses sont allégoriques; car ces femmes sont deux alliances. L''une du mont Sinaï, enfantant pour la servitude, c''est Agar, -'),
  (48, 4, 25, 'car Agar, c''est le mont Sinaï en Arabie, -et elle correspond à la Jérusalem actuelle, qui est dans la servitude avec ses enfants.'),
  (48, 4, 26, 'Mais la Jérusalem d''en haut est libre, c''est notre mère;'),
  (48, 4, 27, 'car il est écrit: Réjouis-toi, stérile, toi qui n''enfantes point! Éclate et pousse des cris, toi qui n''as pas éprouvé les douleurs de l''enfantement! Car les enfants de la délaissée seront plus nombreux Que les enfants de celle qui était mariée.'),
  (48, 4, 28, 'Pour vous, frères, comme Isaac, vous êtes enfants de la promesse;'),
  (48, 4, 29, 'et de même qu''alors celui qui était né selon la chair persécutait celui qui était né selon l''Esprit, ainsi en est-il encore maintenant.'),
  (48, 4, 30, 'Mais que dit l''Écriture? Chasse l''esclave et son fils, car le fils de l''esclave n''héritera pas avec le fils de la femme libre.'),
  (48, 4, 31, 'C''est pourquoi, frères, nous ne sommes pas enfants de l''esclave, mais de la femme libre.'),
  (48, 5, 1, 'C''est pour la liberté que Christ nous a affranchis. Demeurez donc fermes, et ne vous laissez pas mettre de nouveau sous le joug de la servitude.'),
  (48, 5, 2, 'Voici, moi Paul, je vous dis que, si vous vous faites circoncire, Christ ne vous servira de rien.'),
  (48, 5, 3, 'Et je proteste encore une fois à tout homme qui se fait circoncire, qu''il est tenu de pratiquer la loi tout entière.'),
  (48, 5, 4, 'Vous êtes séparés de Christ, vous tous qui cherchez la justification dans la loi; vous êtes déchus de la grâce.'),
  (48, 5, 5, 'Pour nous, c''est de la foi que nous attendons, par l''Esprit, l''espérance de la justice.'),
  (48, 5, 6, 'Car, en Jésus-Christ, ni la circoncision ni l''incirconcision n''a de valeur, mais la foi qui est agissante par la charité.'),
  (48, 5, 7, 'Vous couriez bien: qui vous a arrêtés, pour vous empêcher d''obéir à la vérité?'),
  (48, 5, 8, 'Cette influence ne vient pas de celui qui vous appelle.'),
  (48, 5, 9, 'Un peu de levain fait lever toute la pâte.'),
  (48, 5, 10, 'J''ai cette confiance en vous, dans le Seigneur, que vous ne penserez pas autrement. Mais celui qui vous trouble, quel qu''il soit, en portera la peine.'),
  (48, 5, 11, 'Pour moi, frères, si je prêche encore la circoncision, pourquoi suis-je encore persécuté? Le scandale de la croix a donc disparu!'),
  (48, 5, 12, 'Puissent-ils être retranchés, ceux qui mettent le trouble parmi vous!'),
  (48, 5, 13, 'Frères, vous avez été appelés à la liberté, seulement ne faites pas de cette liberté un prétexte de vivre selon la chair; mais rendez-vous, par la charité, serviteurs les uns des autres.'),
  (48, 5, 14, 'Car toute la loi est accomplie dans une seule parole, dans celle-ci: Tu aimeras ton prochain comme toi-même.'),
  (48, 5, 15, 'Mais si vous vous mordez et vous dévorez les uns les autres, prenez garde que vous ne soyez détruits les uns par les autres.'),
  (48, 5, 16, 'Je dis donc: Marchez selon l''Esprit, et vous n''accomplirez pas les désirs de la chair.'),
  (48, 5, 17, 'Car la chair a des désirs contraires à ceux de l''Esprit, et l''Esprit en a de contraires à ceux de la chair; ils sont opposés entre eux, afin que vous ne fassiez point ce que vous voudriez.'),
  (48, 5, 18, 'Si vous êtes conduits par l''Esprit, vous n''êtes point sous la loi.'),
  (48, 5, 19, 'Or, les œuvres de la chair sont manifestes, ce sont l''impudicité, l''impureté, la dissolution,'),
  (48, 5, 20, 'l''idolâtrie, la magie, les inimitiés, les querelles, les jalousies, les animosités, les disputes, les divisions, les sectes,'),
  (48, 5, 21, 'l''envie, l''ivrognerie, les excès de table, et les choses semblables. Je vous dis d''avance, comme je l''ai déjà dit, que ceux qui commettent de telles choses n''hériteront point le royaume de Dieu.'),
  (48, 5, 22, 'Mais le fruit de l''Esprit, c''est l''amour, la joie, la paix, la patience, la bonté, la bénignité, la fidélité,'),
  (48, 5, 23, 'la douceur, la tempérance; la loi n''est pas contre ces choses.'),
  (48, 5, 24, 'Ceux qui sont à Jésus-Christ ont crucifié la chair avec ses passions et ses désirs.'),
  (48, 5, 25, 'Si nous vivons par l''Esprit, marchons aussi selon l''Esprit.'),
  (48, 5, 26, 'Ne cherchons pas une vaine gloire, en nous provoquant les uns les autres, en nous portant envie les uns aux autres.'),
  (48, 6, 1, 'Frères, si un homme vient à être surpris en quelque faute, vous qui êtes spirituels, redressez-le avec un esprit de douceur. Prends garde à toi-même, de peur que tu ne sois aussi tenté.'),
  (48, 6, 2, 'Portez les fardeaux les uns des autres, et vous accomplirez ainsi la loi de Christ.'),
  (48, 6, 3, 'Si quelqu''un pense être quelque chose, quoiqu''il ne soit rien, il s''abuse lui-même.'),
  (48, 6, 4, 'Que chacun examine ses propres œuvres, et alors il aura sujet de se glorifier pour lui seul, et non par rapport à autrui;'),
  (48, 6, 5, 'car chacun portera son propre fardeau.'),
  (48, 6, 6, 'Que celui à qui l''on enseigne la parole fasse part de tous ses biens à celui qui l''enseigne.'),
  (48, 6, 7, 'Ne vous y trompez pas: on ne se moque pas de Dieu. Ce qu''un homme aura semé, il le moissonnera aussi.'),
  (48, 6, 8, 'Celui qui sème pour sa chair moissonnera de la chair la corruption; mais celui qui sème pour l''Esprit moissonnera de l''Esprit la vie éternelle.'),
  (48, 6, 9, 'Ne nous lassons pas de faire le bien; car nous moissonnerons au temps convenable, si nous ne nous relâchons pas.'),
  (48, 6, 10, 'Ainsi donc, pendant que nous en avons l''occasion, pratiquons le bien envers tous, et surtout envers les frères en la foi.'),
  (48, 6, 11, 'Voyez avec quelles grandes lettres je vous ai écrit de ma propre main.'),
  (48, 6, 12, 'Tous ceux qui veulent se rendre agréables selon la chair vous contraignent à vous faire circoncire, uniquement afin de n''être pas persécutés pour la croix de Christ.'),
  (48, 6, 13, 'Car les circoncis eux-mêmes n''observent point la loi; mais ils veulent que vous soyez circoncis, pour se glorifier dans votre chair.'),
  (48, 6, 14, 'Pour ce qui me concerne, loin de moi la pensée de me glorifier d''autre chose que de la croix de notre Seigneur Jésus-Christ, par qui le monde est crucifié pour moi, comme je le suis pour le monde!'),
  (48, 6, 15, 'Car ce n''est rien que d''être circoncis ou incirconcis; ce qui est quelque chose, c''est d''être une nouvelle créature.'),
  (48, 6, 16, 'Paix et miséricorde sur tous ceux qui suivront cette règle, et sur l''Israël de Dieu!'),
  (48, 6, 17, 'Que personne désormais ne me fasse de la peine, car je porte sur mon corps les marques de Jésus.'),
  (48, 6, 18, 'Frères, que la grâce de notre Seigneur Jésus-Christ soit avec votre esprit! Amen!'),
  (49, 1, 1, 'Paul, apôtre de Jésus-Christ par la volonté de Dieu, aux saints qui sont à Éphèse et aux fidèles en Jésus-Christ:'),
  (49, 1, 2, 'Que la grâce et la paix vous soient données de la part de Dieu notre Père et du Seigneur Jésus-Christ!'),
  (49, 1, 3, 'Béni soit Dieu, le Père de notre Seigneur Jésus-Christ, qui nous a bénis de toutes sortes de bénédictions spirituelles dans les lieux célestes en Christ!'),
  (49, 1, 4, 'En lui Dieu nous a élus avant la fondation du monde, pour que nous soyons saints et irrépréhensibles devant lui,'),
  (49, 1, 5, 'nous ayant prédestinés dans son amour à être ses enfants d''adoption par Jésus-Christ, selon le bon plaisir de sa volonté,'),
  (49, 1, 6, 'à la louange de la gloire de sa grâce qu''il nous a accordée en son bien-aimé.'),
  (49, 1, 7, 'En lui nous avons la rédemption par son sang, la rémission des péchés, selon la richesse de sa grâce,'),
  (49, 1, 8, 'que Dieu a répandue abondamment sur nous par toute espèce de sagesse et d''intelligence,'),
  (49, 1, 9, 'nous faisant connaître le mystère de sa volonté, selon le bienveillant dessein qu''il avait formé en lui-même,'),
  (49, 1, 10, 'pour le mettre à exécution lorsque les temps seraient accomplis, de réunir toutes choses en Christ, celles qui sont dans les cieux et celles qui sont sur la terre.'),
  (49, 1, 11, 'En lui nous sommes aussi devenus héritiers, ayant été prédestinés suivant la résolution de celui qui opère toutes choses d''après le conseil de sa volonté,'),
  (49, 1, 12, 'afin que nous servions à la louange de sa gloire, nous qui d''avance avons espéré en Christ.'),
  (49, 1, 13, 'En lui vous aussi, après avoir entendu la parole de la vérité, l''Évangile de votre salut, en lui vous avez cru et vous avez été scellés du Saint-Esprit qui avait été promis,'),
  (49, 1, 14, 'lequel est un gage de notre héritage, pour la rédemption de ceux que Dieu s''est acquis, à la louange de sa gloire.'),
  (49, 1, 15, 'C''est pourquoi moi aussi, ayant entendu parler de votre foi au Seigneur Jésus et de votre charité pour tous les saints,'),
  (49, 1, 16, 'je ne cesse de rendre grâces pour vous, faisant mention de vous dans mes prières,'),
  (49, 1, 17, 'afin que le Dieu de notre Seigneur Jésus-Christ, le Père de gloire, vous donne un esprit de sagesse et de révélation, dans sa connaissance,'),
  (49, 1, 18, 'et qu''il illumine les yeux de votre cœur, pour que vous sachiez quelle est l''espérance qui s''attache à son appel, quelle est la richesse de la gloire de son héritage qu''il réserve aux saints,'),
  (49, 1, 19, 'et quelle est envers nous qui croyons l''infinie grandeur de sa puissance, se manifestant avec efficacité par la vertu de sa force.'),
  (49, 1, 20, 'Il l''a déployée en Christ, en le ressuscitant des morts, et en le faisant asseoir à sa droite dans les lieux célestes,'),
  (49, 1, 21, 'au-dessus de toute domination, de toute autorité, de toute puissance, de toute dignité, et de tout nom qui se peut nommer, non seulement dans le siècle présent, mais encore dans le siècle à venir.'),
  (49, 1, 22, 'Il a tout mis sous ses pieds, et il l''a donné pour chef suprême à l''Église,'),
  (49, 1, 23, 'qui est son corps, la plénitude de celui qui remplit tout en tous.'),
  (49, 2, 1, 'Vous étiez morts par vos offenses et par vos péchés,'),
  (49, 2, 2, 'dans lesquels vous marchiez autrefois, selon le train de ce monde, selon le prince de la puissance de l''air, de l''esprit qui agit maintenant dans les fils de la rébellion.'),
  (49, 2, 3, 'Nous tous aussi, nous étions de leur nombre, et nous vivions autrefois selon les convoitises de notre chair, accomplissant les volontés de la chair et de nos pensées, et nous étions par nature des enfants de colère, comme les autres…'),
  (49, 2, 4, 'Mais Dieu, qui est riche en miséricorde, à cause du grand amour dont il nous a aimés,'),
  (49, 2, 5, 'nous qui étions morts par nos offenses, nous a rendus à la vie avec Christ (c''est par grâce que vous êtes sauvés);'),
  (49, 2, 6, 'il nous a ressuscités ensemble, et nous a fait asseoir ensemble dans les lieux célestes, en Jésus-Christ,'),
  (49, 2, 7, 'afin de montrer dans les siècles à venir l''infinie richesse de sa grâce par sa bonté envers nous en Jésus-Christ.'),
  (49, 2, 8, 'Car c''est par la grâce que vous êtes sauvés, par le moyen de la foi. Et cela ne vient pas de vous, c''est le don de Dieu.'),
  (49, 2, 9, 'Ce n''est point par les œuvres, afin que personne ne se glorifie.'),
  (49, 2, 10, 'Car nous sommes son ouvrage, ayant été créés en Jésus-Christ pour de bonnes œuvres, que Dieu a préparées d''avance, afin que nous les pratiquions.'),
  (49, 2, 11, 'C''est pourquoi, vous autrefois païens dans la chair, appelés incirconcis par ceux qu''on appelle circoncis et qui le sont en la chair par la main de l''homme, souvenez-vous'),
  (49, 2, 12, 'que vous étiez en ce temps-là sans Christ, privés du droit de cité en Israël, étrangers aux alliances de la promesse, sans espérance et sans Dieu dans le monde.'),
  (49, 2, 13, 'Mais maintenant, en Jésus-Christ, vous qui étiez jadis éloignés, vous avez été rapprochés par le sang de Christ.'),
  (49, 2, 14, 'Car il est notre paix, lui qui des deux n''en a fait qu''un, et qui a renversé le mur de séparation,'),
  (49, 2, 15, 'l''inimitié, ayant anéanti par sa chair la loi des ordonnances dans ses prescriptions, afin de créer en lui-même avec les deux un seul homme nouveau, en établissant la paix,'),
  (49, 2, 16, 'et de les réconcilier, l''un et l''autre en un seul corps, avec Dieu par la croix, en détruisant par elle l''inimitié.'),
  (49, 2, 17, 'Il est venu annoncer la paix à vous qui étiez loin, et la paix à ceux qui étaient près;'),
  (49, 2, 18, 'car par lui nous avons les uns et les autres accès auprès du Père, dans un même Esprit.'),
  (49, 2, 19, 'Ainsi donc, vous n''êtes plus des étrangers, ni des gens du dehors; mais vous êtes concitoyens des saints, gens de la maison de Dieu.'),
  (49, 2, 20, 'Vous avez été édifiés sur le fondement des apôtres et des prophètes, Jésus-Christ lui-même étant la pierre angulaire.'),
  (49, 2, 21, 'En lui tout l''édifice, bien coordonné, s''élève pour être un temple saint dans le Seigneur.'),
  (49, 2, 22, 'En lui vous êtes aussi édifiés pour être une habitation de Dieu en Esprit.'),
  (49, 3, 1, 'A cause de cela, moi Paul, le prisonnier de Christ pour vous païens…'),
  (49, 3, 2, 'si du moins vous avez appris quelle est la dispensation de la grâce de Dieu, qui m''a été donnée pour vous.'),
  (49, 3, 3, 'C''est par révélation que j''ai eu connaissance du mystère sur lequel je viens d''écrire en peu de mots.'),
  (49, 3, 4, 'En les lisant, vous pouvez vous représenter l''intelligence que j''ai du mystère de Christ.'),
  (49, 3, 5, 'Il n''a pas été manifesté aux fils des hommes dans les autres générations, comme il a été révélé maintenant par l''Esprit aux saints apôtres et prophètes de Christ.'),
  (49, 3, 6, 'Ce mystère, c''est que les païens sont cohéritiers, forment un même corps, et participent à la même promesse en Jésus-Christ par l''Évangile,'),
  (49, 3, 7, 'dont j''ai été fait ministre selon le don de la grâce de Dieu, qui m''a été accordée par l''efficacité de sa puissance.'),
  (49, 3, 8, 'A moi, qui suis le moindre de tous les saints, cette grâce a été accordée d''annoncer aux païens les richesses incompréhensibles de Christ,'),
  (49, 3, 9, 'et de mettre en lumière quelle est la dispensation du mystère caché de tout temps en Dieu qui a créé toutes choses,'),
  (49, 3, 10, 'afin que les dominations et les autorités dans les lieux célestes connaissent aujourd''hui par l''Église la sagesse infiniment variée de Dieu,'),
  (49, 3, 11, 'selon le dessein éternel qu''il a mis à exécution par Jésus-Christ notre Seigneur,'),
  (49, 3, 12, 'en qui nous avons, par la foi en lui, la liberté de nous approcher de Dieu avec confiance.'),
  (49, 3, 13, 'Aussi je vous demande de ne pas perdre courage à cause de mes tribulations pour vous: elles sont votre gloire.'),
  (49, 3, 14, 'A cause de cela, je fléchis les genoux devant le Père,'),
  (49, 3, 15, 'duquel tire son nom toute famille dans les cieux et sur la terre,'),
  (49, 3, 16, 'afin qu''il vous donne, selon la richesse de sa gloire, d''être puissamment fortifiés par son Esprit dans l''homme intérieur,'),
  (49, 3, 17, 'en sorte que Christ habite dans vos cœurs par la foi; afin qu''étant enracinés et fondés dans l''amour,'),
  (49, 3, 18, 'vous puissiez comprendre avec tous les saints quelle est la largeur, la longueur, la profondeur et la hauteur,'),
  (49, 3, 19, 'et connaître l''amour de Christ, qui surpasse toute connaissance, en sorte que vous soyez remplis jusqu''à toute la plénitude de Dieu.'),
  (49, 3, 20, 'Or, à celui qui peut faire, par la puissance qui agit en nous, infiniment au delà de tout ce que nous demandons ou pensons,'),
  (49, 3, 21, 'à lui soit la gloire dans l''Église et en Jésus-Christ, dans toutes les générations, aux siècles des siècles! Amen!'),
  (49, 4, 1, 'Je vous exhorte donc, moi, le prisonnier dans le Seigneur, à marcher d''une manière digne de la vocation qui vous a été adressée,'),
  (49, 4, 2, 'en toute humilité et douceur, avec patience, vous supportant les uns les autres avec charité,'),
  (49, 4, 3, 'vous efforçant de conserver l''unité de l''esprit par le lien de la paix.'),
  (49, 4, 4, 'Il y a un seul corps et un seul Esprit, comme aussi vous avez été appelés à une seule espérance par votre vocation;'),
  (49, 4, 5, 'il y a un seul Seigneur, une seule foi, un seul baptême,'),
  (49, 4, 6, 'un seul Dieu et Père de tous, qui est au-dessus de tous, et parmi tous, et en tous.'),
  (49, 4, 7, 'Mais à chacun de nous la grâce a été donnée selon la mesure du don de Christ.'),
  (49, 4, 8, 'C''est pourquoi il est dit: Étant monté en haut, il a emmené des captifs, Et il a fait des dons aux hommes.'),
  (49, 4, 9, 'Or, que signifie: Il est monté, sinon qu''il est aussi descendu dans les régions inférieures de la terre?'),
  (49, 4, 10, 'Celui qui est descendu, c''est le même qui est monté au-dessus de tous les cieux, afin de remplir toutes choses.'),
  (49, 4, 11, 'Et il a donné les uns comme apôtres, les autres comme prophètes, les autres comme évangélistes, les autres comme pasteurs et docteurs,'),
  (49, 4, 12, 'pour le perfectionnement des saints en vue de l''œuvre du ministère et de l''édification du corps de Christ,'),
  (49, 4, 13, 'jusqu''à ce que nous soyons tous parvenus à l''unité de la foi et de la connaissance du Fils de Dieu, à l''état d''homme fait, à la mesure de la stature parfaite de Christ,'),
  (49, 4, 14, 'afin que nous ne soyons plus des enfants, flottants et emportés à tout vent de doctrine, par la tromperie des hommes, par leur ruse dans les moyens de séduction,'),
  (49, 4, 15, 'mais que, professant la vérité dans la charité, nous croissions à tous égards en celui qui est le chef, Christ.'),
  (49, 4, 16, 'C''est de lui, et grâce à tous les liens de son assistance, que tout le corps, bien coordonné et formant un solide assemblage, tire son accroissement selon la force qui convient à chacune de ses parties, et s''édifie lui-même dans la charité.'),
  (49, 4, 17, 'Voici donc ce que je dis et ce que je déclare dans le Seigneur, c''est que vous ne devez plus marcher comme les païens, qui marchent selon la vanité de leurs pensées.'),
  (49, 4, 18, 'Ils ont l''intelligence obscurcie, ils sont étrangers à la vie de Dieu, à cause de l''ignorance qui est en eux, à cause de l''endurcissement de leur cœur.'),
  (49, 4, 19, 'Ayant perdu tout sentiment, ils se sont livrés à la dissolution, pour commettre toute espèce d''impureté jointe à la cupidité.'),
  (49, 4, 20, 'Mais vous, ce n''est pas ainsi que vous avez appris Christ,'),
  (49, 4, 21, 'si du moins vous l''avez entendu, et si, conformément à la vérité qui est en Jésus, c''est en lui que vous avez été instruits'),
  (49, 4, 22, 'à vous dépouiller, eu égard à votre vie passée, du vieil homme qui se corrompt par les convoitises trompeuses,'),
  (49, 4, 23, 'à être renouvelés dans l''esprit de votre intelligence,'),
  (49, 4, 24, 'et à revêtir l''homme nouveau, créé selon Dieu dans une justice et une sainteté que produit la vérité.'),
  (49, 4, 25, 'C''est pourquoi, renoncez au mensonge, et que chacun de vous parle selon la vérité à son prochain; car nous sommes membres les uns des autres.'),
  (49, 4, 26, 'Si vous vous mettez en colère, ne péchez point; que le soleil ne se couche pas sur votre colère,'),
  (49, 4, 27, 'et ne donnez pas accès au diable.'),
  (49, 4, 28, 'Que celui qui dérobait ne dérobe plus; mais plutôt qu''il travaille, en faisant de ses mains ce qui est bien, pour avoir de quoi donner à celui qui est dans le besoin.'),
  (49, 4, 29, 'Qu''il ne sorte de votre bouche aucune parole mauvaise, mais, s''il y a lieu, quelque bonne parole, qui serve à l''édification et communique une grâce à ceux qui l''entendent.'),
  (49, 4, 30, 'N''attristez pas le Saint-Esprit de Dieu, par lequel vous avez été scellés pour le jour de la rédemption.'),
  (49, 4, 31, 'Que toute amertume, toute animosité, toute colère, toute clameur, toute calomnie, et toute espèce de méchanceté, disparaissent du milieu de vous.'),
  (49, 4, 32, 'Soyez bons les uns envers les autres, compatissants, vous pardonnant réciproquement, comme Dieu vous a pardonné en Christ.'),
  (49, 5, 1, 'Devenez donc les imitateurs de Dieu, comme des enfants bien-aimés;'),
  (49, 5, 2, 'et marchez dans la charité, à l''exemple de Christ, qui nous a aimés, et qui s''est livré lui-même à Dieu pour nous comme une offrande et un sacrifice de bonne odeur.'),
  (49, 5, 3, 'Que l''impudicité, qu''aucune espèce d''impureté, et que la cupidité, ne soient pas même nommées parmi vous, ainsi qu''il convient à des saints.'),
  (49, 5, 4, 'Qu''on n''entende ni paroles déshonnêtes, ni propos insensés, ni plaisanteries, choses qui sont contraires à la bienséance; qu''on entende plutôt des actions de grâces.'),
  (49, 5, 5, 'Car, sachez-le bien, aucun impudique, ou impur, ou cupide, c''est-à-dire, idolâtre, n''a d''héritage dans le royaume de Christ et de Dieu.'),
  (49, 5, 6, 'Que personne ne vous séduise par de vains discours; car c''est à cause de ces choses que la colère de Dieu vient sur les fils de la rébellion.'),
  (49, 5, 7, 'N''ayez donc aucune part avec eux.'),
  (49, 5, 8, 'Autrefois vous étiez ténèbres, et maintenant vous êtes lumière dans le Seigneur. Marchez comme des enfants de lumière!'),
  (49, 5, 9, 'Car le fruit de la lumière consiste en toute sorte de bonté, de justice et de vérité.'),
  (49, 5, 10, 'Examinez ce qui est agréable au Seigneur;'),
  (49, 5, 11, 'et ne prenez point part aux œuvres infructueuses des ténèbres, mais plutôt condamnez-les.'),
  (49, 5, 12, 'Car il est honteux de dire ce qu''ils font en secret;'),
  (49, 5, 13, 'mais tout ce qui est condamné est manifesté par la lumière, car tout ce qui est manifesté est lumière.'),
  (49, 5, 14, 'C''est pour cela qu''il est dit: Réveille-toi, toi qui dors, Relève-toi d''entre les morts, Et Christ t''éclairera.'),
  (49, 5, 15, 'Prenez donc garde de vous conduire avec circonspection, non comme des insensés, mais comme des sages;'),
  (49, 5, 16, 'rachetez le temps, car les jours sont mauvais.'),
  (49, 5, 17, 'C''est pourquoi ne soyez pas inconsidérés, mais comprenez quelle est la volonté du Seigneur.'),
  (49, 5, 18, 'Ne vous enivrez pas de vin: c''est de la débauche. Soyez, au contraire, remplis de l''Esprit;'),
  (49, 5, 19, 'entretenez-vous par des psaumes, par des hymnes, et par des cantiques spirituels, chantant et célébrant de tout votre cœur les louanges du Seigneur;'),
  (49, 5, 20, 'rendez continuellement grâces pour toutes choses à Dieu le Père, au nom de notre Seigneur Jésus-Christ,'),
  (49, 5, 21, 'vous soumettant les uns aux autres dans la crainte de Christ.'),
  (49, 5, 22, 'Femmes, soyez soumises à vos maris, comme au Seigneur;'),
  (49, 5, 23, 'car le mari est le chef de la femme, comme Christ est le chef de l''Église, qui est son corps, et dont il est le Sauveur.'),
  (49, 5, 24, 'Or, de même que l''Église est soumise à Christ, les femmes aussi doivent l''être à leurs maris en toutes choses.'),
  (49, 5, 25, 'Maris, aimez vos femmes, comme Christ a aimé l''Église, et s''est livré lui-même pour elle,'),
  (49, 5, 26, 'afin de la sanctifier par la parole, après l''avoir purifiée par le baptême d''eau,'),
  (49, 5, 27, 'afin de faire paraître devant lui cette Église glorieuse, sans tache, ni ride, ni rien de semblable, mais sainte et irrépréhensible.'),
  (49, 5, 28, 'C''est ainsi que les maris doivent aimer leurs femmes comme leurs propres corps. Celui qui aime sa femme s''aime lui-même.'),
  (49, 5, 29, 'Car jamais personne n''a haï sa propre chair; mais il la nourrit et en prend soin, comme Christ le fait pour l''Église,'),
  (49, 5, 30, 'parce que nous sommes membres de son corps.'),
  (49, 5, 31, 'C''est pourquoi l''homme quittera son père et sa mère, et s''attachera à sa femme, et les deux deviendront une seule chair.'),
  (49, 5, 32, 'Ce mystère est grand; je dis cela par rapport à Christ et à l''Église.'),
  (49, 5, 33, 'Du reste, que chacun de vous aime sa femme comme lui-même, et que la femme respecte son mari.'),
  (49, 6, 1, 'Enfants, obéissez à vos parents, selon le Seigneur, car cela est juste.'),
  (49, 6, 2, 'Honore ton père et ta mère (c''est le premier commandement avec une promesse),'),
  (49, 6, 3, 'afin que tu sois heureux et que tu vives longtemps sur la terre.'),
  (49, 6, 4, 'Et vous, pères, n''irritez pas vos enfants, mais élevez-les en les corrigeant et en les instruisant selon le Seigneur.'),
  (49, 6, 5, 'Serviteurs, obéissez à vos maîtres selon la chair, avec crainte et tremblement, dans la simplicité de votre cœur, comme à Christ,'),
  (49, 6, 6, 'non pas seulement sous leurs yeux, comme pour plaire aux hommes, mais comme des serviteurs de Christ, qui font de bon cœur la volonté de Dieu.'),
  (49, 6, 7, 'Servez-les avec empressement, comme servant le Seigneur et non des hommes,'),
  (49, 6, 8, 'sachant que chacun, soit esclave, soit libre, recevra du Seigneur selon ce qu''il aura fait de bien.'),
  (49, 6, 9, 'Et vous, maîtres, agissez de même à leur égard, et abstenez-vous de menaces, sachant que leur maître et le vôtre est dans les cieux, et que devant lui il n''y a point d''acception de personnes.'),
  (49, 6, 10, 'Au reste, fortifiez-vous dans le Seigneur, et par sa force toute-puissante.'),
  (49, 6, 11, 'Revêtez-vous de toutes les armes de Dieu, afin de pouvoir tenir ferme contre les ruses du diable.'),
  (49, 6, 12, 'Car nous n''avons pas à lutter contre la chair et le sang, mais contre les dominations, contre les autorités, contre les princes de ce monde de ténèbres, contre les esprits méchants dans les lieux célestes.'),
  (49, 6, 13, 'C''est pourquoi, prenez toutes les armes de Dieu, afin de pouvoir résister dans le mauvais jour, et tenir ferme après avoir tout surmonté.'),
  (49, 6, 14, 'Tenez donc ferme: ayez à vos reins la vérité pour ceinture; revêtez la cuirasse de la justice;'),
  (49, 6, 15, 'mettez pour chaussure à vos pieds le zèle que donne l''Évangile de paix;'),
  (49, 6, 16, 'prenez par-dessus tout cela le bouclier de la foi, avec lequel vous pourrez éteindre tous les traits enflammés du malin;'),
  (49, 6, 17, 'prenez aussi le casque du salut, et l''épée de l''Esprit, qui est la parole de Dieu.'),
  (49, 6, 18, 'Faites en tout temps par l''Esprit toutes sortes de prières et de supplications. Veillez à cela avec une entière persévérance, et priez pour tous les saints.'),
  (49, 6, 19, 'Priez pour moi, afin qu''il me soit donné, quand j''ouvre la bouche, de faire connaître hardiment et librement le mystère de l''Évangile,'),
  (49, 6, 20, 'pour lequel je suis ambassadeur dans les chaînes, et que j''en parle avec assurance comme je dois en parler.'),
  (49, 6, 21, 'Afin que vous aussi, vous sachiez ce qui me concerne, ce que je fais, Tychique, le bien-aimé frère et fidèle ministre dans le Seigneur, vous informera de tout.'),
  (49, 6, 22, 'Je l''envoie exprès vers vous, pour que vous connaissiez notre situation, et pour qu''il console vos cœurs.'),
  (49, 6, 23, 'Que la paix et la charité avec la foi soient données aux frères de la part de Dieu le Père et du Seigneur Jésus-Christ!'),
  (49, 6, 24, 'Que la grâce soit avec tous ceux qui aiment notre Seigneur Jésus-Christ d''un amour inaltérable!'),
  (50, 1, 1, 'Paul et Timothée, serviteurs de Jésus-Christ, à tous les saints en Jésus-Christ qui sont à Philippes, aux évêques et aux diacres:'),
  (50, 1, 2, 'que la grâce et la paix vous soient données de la part de Dieu notre Père et du Seigneur Jésus-Christ!'),
  (50, 1, 3, 'Je rends grâces à mon Dieu de tout le souvenir que je garde de vous,'),
  (50, 1, 4, 'ne cessant, dans toutes mes prières pour vous tous, de manifester ma joie'),
  (50, 1, 5, 'au sujet de la part que vous prenez à l''Évangile, depuis le premier jour jusqu''à maintenant.'),
  (50, 1, 6, 'Je suis persuadé que celui qui a commencé en vous cette bonne œuvre la rendra parfaite pour le jour de Jésus-Christ.'),
  (50, 1, 7, 'Il est juste que je pense ainsi de vous tous, parce que je vous porte dans mon cœur, soit dans mes liens, soit dans la défense et la confirmation de l''Évangile, vous qui tous participez à la même grâce que moi.'),
  (50, 1, 8, 'Car Dieu m''est témoin que je vous chéris tous avec la tendresse de Jésus-Christ.'),
  (50, 1, 9, 'Et ce que je demande dans mes prières, c''est que votre amour augmente de plus en plus en connaissance et en pleine intelligence'),
  (50, 1, 10, 'pour le discernement des choses les meilleures, afin que vous soyez purs et irréprochables pour le jour de Christ,'),
  (50, 1, 11, 'remplis du fruit de justice qui est par Jésus-Christ, à la gloire et à la louange de Dieu.'),
  (50, 1, 12, 'Je veux que vous sachiez, frères, que ce qui m''est arrivé a plutôt contribué aux progrès de l''Évangile.'),
  (50, 1, 13, 'En effet, dans tout le prétoire et partout ailleurs, nul n''ignore que c''est pour Christ que je suis dans les liens,'),
  (50, 1, 14, 'et la plupart des frères dans le Seigneur, encouragés par mes liens, ont plus d''assurance pour annoncer sans crainte la parole.'),
  (50, 1, 15, 'Quelques-uns, il est vrai, prêchent Christ par envie et par esprit de dispute; mais d''autres le prêchent avec des dispositions bienveillantes.'),
  (50, 1, 16, 'Ceux-ci agissent par amour, sachant que je suis établi pour la défense de l''Évangile,'),
  (50, 1, 17, 'tandis que ceux-là, animés d''un esprit de dispute, annoncent Christ par des motifs qui ne sont pas purs et avec la pensée de me susciter quelque tribulation dans mes liens.'),
  (50, 1, 18, 'Qu''importe? De toute manière, que ce soit pour l''apparence, que ce soit sincèrement, Christ n''est pas moins annoncé: je m''en réjouis, et je m''en réjouirai encore.'),
  (50, 1, 19, 'Car je sais que cela tournera à mon salut, grâce à vos prières et à l''assistance de l''Esprit de Jésus-Christ,'),
  (50, 1, 20, 'selon ma ferme attente et mon espérance que je n''aurai honte de rien, mais que, maintenant comme toujours, Christ sera glorifié dans mon corps avec une pleine assurance, soit par ma vie, soit par ma mort;'),
  (50, 1, 21, 'car Christ est ma vie, et la mort m''est un gain.'),
  (50, 1, 22, 'Mais s''il est utile pour mon œuvre que je vive dans la chair, je ne saurais dire ce que je dois préférer.'),
  (50, 1, 23, 'Je suis pressé des deux côtés: j''ai le désir de m''en aller et d''être avec Christ, ce qui de beaucoup est le meilleur;'),
  (50, 1, 24, 'mais à cause de vous il est plus nécessaire que je demeure dans la chair.'),
  (50, 1, 25, 'Et je suis persuadé, je sais que je demeurerai et que je resterai avec vous tous, pour votre avancement et pour votre joie dans la foi,'),
  (50, 1, 26, 'afin que, par mon retour auprès de vous, vous ayez en moi un abondant sujet de vous glorifier en Jésus-Christ.'),
  (50, 1, 27, 'Seulement, conduisez-vous d''une manière digne de l''Évangile de Christ, afin que, soit que je vienne vous voir, soit que je reste absent, j''entende dire de vous que vous demeurez fermes dans un même esprit, combattant d''une même âme pour la foi de l''Évangile,'),
  (50, 1, 28, 'sans vous laisser aucunement effrayer par les adversaires, ce qui est pour eux une preuve de perdition, mais pour vous de salut; et cela de la part de Dieu,'),
  (50, 1, 29, 'car il vous a été fait la grâce, par rapport à Christ, non seulement de croire en lui, mais encore de souffrir pour lui,'),
  (50, 1, 30, 'en soutenant le même combat que vous m''avez vu soutenir, et que vous apprenez maintenant que je soutiens.'),
  (50, 2, 1, 'Si donc il y a quelque consolation en Christ, s''il y a quelque soulagement dans la charité, s''il y a quelque union d''esprit, s''il y a quelque compassion et quelque miséricorde,'),
  (50, 2, 2, 'rendez ma joie parfaite, ayant un même sentiment, un même amour, une même âme, une même pensée.'),
  (50, 2, 3, 'Ne faites rien par esprit de parti ou par vaine gloire, mais que l''humilité vous fasse regarder les autres comme étant au-dessus de vous-mêmes.'),
  (50, 2, 4, 'Que chacun de vous, au lieu de considérer ses propres intérêts, considère aussi ceux des autres.'),
  (50, 2, 5, 'Ayez en vous les sentiments qui étaient en Jésus-Christ,'),
  (50, 2, 6, 'lequel, existant en forme de Dieu, n''a point regardé comme une proie à arracher d''être égal avec Dieu,'),
  (50, 2, 7, 'mais s''est dépouillé lui-même, en prenant une forme de serviteur, en devenant semblable aux hommes;'),
  (50, 2, 8, 'et ayant paru comme un simple homme, il s''est humilié lui-même, se rendant obéissant jusqu''à la mort, même jusqu''à la mort de la croix.'),
  (50, 2, 9, 'C''est pourquoi aussi Dieu l''a souverainement élevé, et lui a donné le nom qui est au-dessus de tout nom,'),
  (50, 2, 10, 'afin qu''au nom de Jésus tout genou fléchisse dans les cieux, sur la terre et sous la terre,'),
  (50, 2, 11, 'et que toute langue confesse que Jésus-Christ est Seigneur, à la gloire de Dieu le Père.'),
  (50, 2, 12, 'Ainsi, mes bien-aimés, comme vous avez toujours obéi, travaillez à votre salut avec crainte et tremblement, non seulement comme en ma présence, mais bien plus encore maintenant que je suis absent;'),
  (50, 2, 13, 'car c''est Dieu qui produit en vous le vouloir et le faire, selon son bon plaisir.'),
  (50, 2, 14, 'Faites toutes choses sans murmures ni hésitations,'),
  (50, 2, 15, 'afin que vous soyez irréprochables et purs, des enfants de Dieu irrépréhensibles au milieu d''une génération perverse et corrompue, parmi laquelle vous brillez comme des flambeaux dans le monde,'),
  (50, 2, 16, 'portant la parole de vie; et je pourrai me glorifier, au jour de Christ, de n''avoir pas couru en vain ni travaillé en vain.'),
  (50, 2, 17, 'Et même si je sers de libation pour le sacrifice et pour le service de votre foi, je m''en réjouis, et je me réjouis avec vous tous.'),
  (50, 2, 18, 'Vous aussi, réjouissez-vous de même, et réjouissez-vous avec moi.'),
  (50, 2, 19, 'J''espère dans le Seigneur Jésus vous envoyer bientôt Timothée, afin d''être encouragé moi-même en apprenant ce qui vous concerne.'),
  (50, 2, 20, 'Car je n''ai personne ici qui partage mes sentiments, pour prendre sincèrement à cœur votre situation;'),
  (50, 2, 21, 'tous, en effet, cherchent leurs propres intérêts, et non ceux de Jésus-Christ.'),
  (50, 2, 22, 'Vous savez qu''il a été mis à l''épreuve, en se consacrant au service de l''Évangile avec moi, comme un enfant avec son père.'),
  (50, 2, 23, 'J''espère donc vous l''envoyer dès que j''apercevrai l''issue de l''état où je suis;'),
  (50, 2, 24, 'et j''ai cette confiance dans le Seigneur que moi-même aussi j''irai bientôt.'),
  (50, 2, 25, 'J''ai estimé nécessaire de vous envoyer mon frère Épaphrodite, mon compagnon d''œuvre et de combat, par qui vous m''avez fait parvenir de quoi pourvoir à mes besoins.'),
  (50, 2, 26, 'Car il désirait vous voir tous, et il était fort en peine de ce que vous aviez appris sa maladie.'),
  (50, 2, 27, 'Il a été malade, en effet, et tout près de la mort; mais Dieu a eu pitié de lui, et non seulement de lui, mais aussi de moi, afin que je n''eusse pas tristesse sur tristesse.'),
  (50, 2, 28, 'Je l''ai donc envoyé avec d''autant plus d''empressement, afin que vous vous réjouissiez de le revoir, et que je sois moi-même moins triste.'),
  (50, 2, 29, 'Recevez-le donc dans le Seigneur avec une joie entière, et honorez de tels hommes.'),
  (50, 2, 30, 'Car c''est pour l''œuvre de Christ qu''il a été près de la mort, ayant exposé sa vie afin de suppléer à votre absence dans le service que vous me rendiez.'),
  (50, 3, 1, 'Au reste, mes frères, réjouissez-vous dans le Seigneur. Je ne me lasse point de vous écrire les mêmes choses, et pour vous cela est salutaire.'),
  (50, 3, 2, 'Prenez garde aux chiens, prenez garde aux mauvais ouvriers, prenez garde aux faux circoncis.'),
  (50, 3, 3, 'Car les circoncis, c''est nous, qui rendons à Dieu notre culte par l''Esprit de Dieu, qui nous glorifions en Jésus-Christ, et qui ne mettons point notre confiance en la chair.'),
  (50, 3, 4, 'Moi aussi, cependant, j''aurais sujet de mettre ma confiance en la chair. Si quelque autre croit pouvoir se confier en la chair, je le puis bien davantage,'),
  (50, 3, 5, 'moi, circoncis le huitième jour, de la race d''Israël, de la tribu de Benjamin, Hébreu né d''Hébreux; quant à la loi, pharisien;'),
  (50, 3, 6, 'quant au zèle, persécuteur de l''Église; irréprochable, à l''égard de la justice de la loi.'),
  (50, 3, 7, 'Mais ces choses qui étaient pour moi des gains, je les ai regardées comme une perte, à cause de Christ.'),
  (50, 3, 8, 'Et même je regarde toutes choses comme une perte, à cause de l''excellence de la connaissance de Jésus-Christ mon Seigneur, pour lequel j''ai renoncé à tout, et je les regarde comme de la boue, afin de gagner Christ,'),
  (50, 3, 9, 'et d''être trouvé en lui, non avec ma justice, celle qui vient de la loi, mais avec celle qui s''obtient par la foi en Christ, la justice qui vient de Dieu par la foi,'),
  (50, 3, 10, 'Afin de connaître Christ, et la puissance de sa résurrection, et la communion de ses souffrances, en devenant conforme à lui dans sa mort,'),
  (50, 3, 11, 'pour parvenir, si je puis, à la résurrection d''entre les morts.'),
  (50, 3, 12, 'Ce n''est pas que j''aie déjà remporté le prix, ou que j''aie déjà atteint la perfection; mais je cours, pour tâcher de le saisir, puisque moi aussi j''ai été saisi par Jésus-Christ.'),
  (50, 3, 13, 'Frères, je ne pense pas l''avoir saisi; mais je fais une chose: oubliant ce qui est en arrière et me portant vers ce qui est en avant,'),
  (50, 3, 14, 'je cours vers le but, pour remporter le prix de la vocation céleste de Dieu en Jésus-Christ.'),
  (50, 3, 15, 'Nous tous donc qui sommes parfaits, ayons cette même pensée; et si vous êtes en quelque point d''un autre avis, Dieu vous éclairera aussi là-dessus.'),
  (50, 3, 16, 'Seulement, au point où nous sommes parvenus, marchons d''un même pas.'),
  (50, 3, 17, 'Soyez tous mes imitateurs, frères, et portez les regards sur ceux qui marchent selon le modèle que vous avez en nous.'),
  (50, 3, 18, 'Car il en est plusieurs qui marchent en ennemis de la croix de Christ, je vous en ai souvent parlé, et j''en parle maintenant encore en pleurant.'),
  (50, 3, 19, 'Leur fin sera la perdition; ils ont pour dieu leur ventre, ils mettent leur gloire dans ce qui fait leur honte, ils ne pensent qu''aux choses de la terre.'),
  (50, 3, 20, 'Mais notre cité à nous est dans les cieux, d''où nous attendons aussi comme Sauveur le Seigneur Jésus-Christ,'),
  (50, 3, 21, 'qui transformera le corps de notre humiliation, en le rendant semblable au corps de sa gloire, par le pouvoir qu''il a de s''assujettir toutes choses.'),
  (50, 4, 1, 'C''est pourquoi, mes bien-aimés, et très chers frères, vous qui êtes ma joie et ma couronne, demeurez ainsi fermes dans le Seigneur, mes bien-aimés!'),
  (50, 4, 2, 'J''exhorte Évodie et j''exhorte Syntyche à être d''un même sentiment dans le Seigneur.'),
  (50, 4, 3, 'Et toi aussi, fidèle collègue, oui, je te prie de les aider, elles qui ont combattu pour l''Évangile avec moi, et avec Clément et mes autres compagnons d''œuvre, dont les noms sont dans le livre de vie.'),
  (50, 4, 4, 'Réjouissez-vous toujours dans le Seigneur; je le répète, réjouissez-vous.'),
  (50, 4, 5, 'Que votre douceur soit connue de tous les hommes. Le Seigneur est proche.'),
  (50, 4, 6, 'Ne vous inquiétez de rien; mais en toute chose faites connaître vos besoins à Dieu par des prières et des supplications, avec des actions de grâces.'),
  (50, 4, 7, 'Et la paix de Dieu, qui surpasse toute intelligence, gardera vos cœurs et vos pensées en Jésus-Christ.'),
  (50, 4, 8, 'Au reste, frères, que tout ce qui est vrai, tout ce qui est honorable, tout ce qui est juste, tout ce qui est pur, tout ce qui est aimable, tout ce qui mérite l''approbation, ce qui est vertueux et digne de louange, soit l''objet de vos pensées.'),
  (50, 4, 9, 'Ce que vous avez appris, reçu et entendu de moi, et ce que vous avez vu en moi, pratiquez-le. Et le Dieu de paix sera avec vous.'),
  (50, 4, 10, 'J''ai éprouvé une grande joie dans le Seigneur de ce que vous avez pu enfin renouveler l''expression de vos sentiments pour moi; vous y pensiez bien, mais l''occasion vous manquait.'),
  (50, 4, 11, 'Ce n''est pas en vue de mes besoins que je dis cela, car j''ai appris à être content de l''état où je me trouve.'),
  (50, 4, 12, 'Je sais vivre dans l''humiliation, et je sais vivre dans l''abondance. En tout et partout j''ai appris à être rassasié et à avoir faim, à être dans l''abondance et à être dans la disette.'),
  (50, 4, 13, 'Je puis tout par celui qui me fortifie.'),
  (50, 4, 14, 'Cependant vous avez bien fait de prendre part à ma détresse.'),
  (50, 4, 15, 'Vous le savez vous-mêmes, Philippiens, au commencement de la prédication de l''Évangile, lorsque je partis de la Macédoine, aucune Église n''entra en compte avec moi pour ce qu''elle donnait et recevait; vous fûtes les seuls à le faire,'),
  (50, 4, 16, 'car vous m''envoyâtes déjà à Thessalonique, et à deux reprises, de quoi pourvoir à mes besoins.'),
  (50, 4, 17, 'Ce n''est pas que je recherche les dons; mais je recherche le fruit qui abonde pour votre compte.'),
  (50, 4, 18, 'J''ai tout reçu, et je suis dans l''abondance; j''ai été comblé de biens, en recevant par Epaphrodite ce qui vient de vous comme un parfum de bonne odeur, un sacrifice que Dieu accepte, et qui lui est agréable.'),
  (50, 4, 19, 'Et mon Dieu pourvoira à tous vos besoins selon sa richesse, avec gloire, en Jésus-Christ.'),
  (50, 4, 20, 'A notre Dieu et Père soit la gloire aux siècles des siècles! Amen!'),
  (50, 4, 21, 'Saluez tous les saints en Jésus-Christ. Les frères qui sont avec moi vous saluent.'),
  (50, 4, 22, 'Tous les saints vous saluent, et principalement ceux de la maison de César.'),
  (50, 4, 23, 'Que la grâce du Seigneur Jésus-Christ soit avec votre esprit!'),
  (51, 1, 1, 'Paul, apôtre de Jésus-Christ par la volonté de Dieu, et le frère Timothée,'),
  (51, 1, 2, 'aux saints et fidèles frères en Christ qui sont à Colosses; que la grâce et la paix vous soient données de la part de Dieu notre Père!'),
  (51, 1, 3, 'Nous rendons grâces à Dieu, le Père de notre Seigneur Jésus-Christ, et nous ne cessons de prier pour vous,'),
  (51, 1, 4, 'ayant été informés de votre foi en Jésus-Christ et de votre charité pour tous les saints,'),
  (51, 1, 5, 'à cause de l''espérance qui vous est réservée dans les cieux, et que la parole de la vérité, la parole de l''Évangile vous a précédemment fait connaître.'),
  (51, 1, 6, 'Il est au milieu de vous, et dans le monde entier; il porte des fruits, et il va grandissant, comme c''est aussi le cas parmi vous, depuis le jour où vous avez entendu et connu la grâce de Dieu conformément à la vérité,'),
  (51, 1, 7, 'd''après les instructions que vous avez reçues d''Épaphras, notre bien-aimé compagnon de service, qui est pour vous un fidèle ministre de Christ,'),
  (51, 1, 8, 'et qui nous a appris de quelle charité l''Esprit vous anime.'),
  (51, 1, 9, 'C''est pour cela que nous aussi, depuis le jour où nous en avons été informés, nous ne cessons de prier Dieu pour vous, et de demander que vous soyez remplis de la connaissance de sa volonté, en toute sagesse et intelligence spirituelle,'),
  (51, 1, 10, 'pour marcher d''une manière digne du Seigneur et lui être entièrement agréables, portant des fruits en toutes sortes de bonnes œuvres et croissant par la connaissance de Dieu,'),
  (51, 1, 11, 'fortifiés à tous égards par sa puissance glorieuse, en sorte que vous soyez toujours et avec joie persévérants et patients.'),
  (51, 1, 12, 'Rendez grâces au Père, qui vous a rendus capables d''avoir part à l''héritage des saints dans la lumière,'),
  (51, 1, 13, 'qui nous a délivrés de la puissance des ténèbres et nous a transportés dans le royaume du Fils de son amour,'),
  (51, 1, 14, 'en qui nous avons la rédemption, la rémission des péchés.'),
  (51, 1, 15, 'Il est l''image du Dieu invisible, le premier-né de toute la création.'),
  (51, 1, 16, 'Car en lui ont été créées toutes les choses qui sont dans les cieux et sur la terre, les visibles et les invisibles, trônes, dignités, dominations, autorités. Tout a été créé par lui et pour lui.'),
  (51, 1, 17, 'Il est avant toutes choses, et toutes choses subsistent en lui.'),
  (51, 1, 18, 'Il est la tête du corps de l''Église; il est le commencement, le premier-né d''entre les morts, afin d''être en tout le premier.'),
  (51, 1, 19, 'Car Dieu a voulu que toute plénitude habitât en lui;'),
  (51, 1, 20, 'il a voulu par lui réconcilier tout avec lui-même, tant ce qui est sur la terre que ce qui est dans les cieux, en faisant la paix par lui, par le sang de sa croix.'),
  (51, 1, 21, 'Et vous, qui étiez autrefois étrangers et ennemis par vos pensées et par vos mauvaises œuvres, il vous a maintenant réconciliés'),
  (51, 1, 22, 'par sa mort dans le corps de sa chair, pour vous faire paraître devant lui saints, irrépréhensibles et sans reproche,'),
  (51, 1, 23, 'si du moins vous demeurez fondés et inébranlables dans la foi, sans vous détourner de l''espérance de l''Évangile que vous avez entendu, qui a été prêché à toute créature sous le ciel, et dont moi Paul, j''ai été fait ministre.'),
  (51, 1, 24, 'Je me réjouis maintenant dans mes souffrances pour vous; et ce qui manque aux souffrances de Christ, je l''achève en ma chair, pour son corps, qui est l''Église.'),
  (51, 1, 25, 'C''est d''elle que j''ai été fait ministre, selon la charge que Dieu m''a donnée auprès de vous, afin que j''annonçasse pleinement la parole de Dieu,'),
  (51, 1, 26, 'le mystère caché de tout temps et dans tous les âges, mais révélé maintenant à ses saints,'),
  (51, 1, 27, 'à qui Dieu a voulu faire connaître quelle est la glorieuse richesse de ce mystère parmi les païens, savoir: Christ en vous, l''espérance de la gloire.'),
  (51, 1, 28, 'C''est lui que nous annonçons, exhortant tout homme, et instruisant tout homme en toute sagesse, afin de présenter à Dieu tout homme, devenu parfait en Christ.'),
  (51, 1, 29, 'C''est à quoi je travaille, en combattant avec sa force, qui agit puissamment en moi.'),
  (51, 2, 1, 'Je veux, en effet, que vous sachiez combien est grand le combat que je soutiens pour vous, et pour ceux qui sont à Laodicée, et pour tous ceux qui n''ont pas vu mon visage en la chair,'),
  (51, 2, 2, 'afin qu''ils aient le cœur rempli de consolation, qu''ils soient unis dans la charité, et enrichis d''une pleine intelligence pour connaître le mystère de Dieu, savoir Christ,'),
  (51, 2, 3, 'mystère dans lequel sont cachés tous les trésors de la sagesse et de la science.'),
  (51, 2, 4, 'Je dis cela afin que personne ne vous trompe par des discours séduisants.'),
  (51, 2, 5, 'Car, si je suis absent de corps, je suis avec vous en esprit, voyant avec joie le bon ordre qui règne parmi vous, et la fermeté de votre foi en Christ.'),
  (51, 2, 6, 'Ainsi donc, comme vous avez reçu le Seigneur Jésus-Christ, marchez en lui,'),
  (51, 2, 7, 'étant enracinés et fondés en lui, et affermis par la foi, d''après les instructions qui vous ont été données, et abondez en actions de grâces.'),
  (51, 2, 8, 'Prenez garde que personne ne fasse de vous sa proie par la philosophie et par une vaine tromperie, s''appuyant sur la tradition des hommes, sur les rudiments du monde, et non sur Christ.'),
  (51, 2, 9, 'Car en lui habite corporellement toute la plénitude de la divinité.'),
  (51, 2, 10, 'Vous avez tout pleinement en lui, qui est le chef de toute domination et de toute autorité.'),
  (51, 2, 11, 'Et c''est en lui que vous avez été circoncis d''une circoncision que la main n''a pas faite, mais de la circoncision de Christ, qui consiste dans le dépouillement du corps de la chair:'),
  (51, 2, 12, 'ayant été ensevelis avec lui par le baptême, vous êtes aussi ressuscités en lui et avec lui, par la foi en la puissance de Dieu, qui l''a ressuscité des morts.'),
  (51, 2, 13, 'Vous qui étiez morts par vos offenses et par l''incirconcision de votre chair, il vous a rendus à la vie avec lui, en nous faisant grâce pour toutes nos offenses;'),
  (51, 2, 14, 'il a effacé l''acte dont les ordonnances nous condamnaient et qui subsistait contre nous, et il l''a détruit en le clouant à la croix;'),
  (51, 2, 15, 'il a dépouillé les dominations et les autorités, et les a livrées publiquement en spectacle, en triomphant d''elles par la croix.'),
  (51, 2, 16, 'Que personne donc ne vous juge au sujet du manger ou du boire, ou au sujet d''une fête, d''une nouvelle lune, ou des sabbats:'),
  (51, 2, 17, 'c''était l''ombre des choses à venir, mais le corps est en Christ.'),
  (51, 2, 18, 'Qu''aucun homme, sous une apparence d''humilité et par un culte des anges, ne vous ravisse à son gré le prix de la course, tandis qu''il s''abandonne à ses visions et qu''il est enflé d''un vain orgueil par ses pensées charnelles,'),
  (51, 2, 19, 'sans s''attacher au chef, dont tout le corps, assisté et solidement assemblé par des jointures et des liens, tire l''accroissement que Dieu donne.'),
  (51, 2, 20, 'Si vous êtes morts avec Christ aux rudiments du monde, pourquoi, comme si vous viviez dans le monde, vous impose-t-on ces préceptes:'),
  (51, 2, 21, 'Ne prends pas! ne goûte pas! ne touche pas!'),
  (51, 2, 22, 'préceptes qui tous deviennent pernicieux par l''abus, et qui ne sont fondés que sur les ordonnances et les doctrines des hommes?'),
  (51, 2, 23, 'Ils ont, à la vérité, une apparence de sagesse, en ce qu''ils indiquent un culte volontaire, de l''humilité, et le mépris du corps, mais ils sont sans aucun mérite et contribuent à la satisfaction de la chair.'),
  (51, 3, 1, 'Si donc vous êtes ressuscités avec Christ, cherchez les choses d''en haut, où Christ est assis à la droite de Dieu.'),
  (51, 3, 2, 'Affectionnez-vous aux choses d''en haut, et non à celles qui sont sur la terre.'),
  (51, 3, 3, 'Car vous êtes morts, et votre vie est cachée avec Christ en Dieu.'),
  (51, 3, 4, 'Quand Christ, votre vie, paraîtra, alors vous paraîtrez aussi avec lui dans la gloire.'),
  (51, 3, 5, 'Faites donc mourir les membres qui sont sur la terre, l''impudicité, l''impureté, les passions, les mauvais désirs, et la cupidité, qui est une idolâtrie.'),
  (51, 3, 6, 'C''est à cause de ces choses que la colère de Dieu vient sur les fils de la rébellion,'),
  (51, 3, 7, 'parmi lesquels vous marchiez autrefois, lorsque vous viviez dans ces péchés.'),
  (51, 3, 8, 'Mais maintenant, renoncez à toutes ces choses, à la colère, à l''animosité, à la méchanceté, à la calomnie, aux paroles déshonnêtes qui pourraient sortir de votre bouche.'),
  (51, 3, 9, 'Ne mentez pas les uns aux autres, vous étant dépouillés du vieil homme et de ses œuvres,'),
  (51, 3, 10, 'et ayant revêtu l''homme nouveau, qui se renouvelle, dans la connaissance, selon l''image de celui qui l''a créé.'),
  (51, 3, 11, 'Il n''y a ici ni Grec ni Juif, ni circoncis ni incirconcis, ni barbare ni Scythe, ni esclave ni libre; mais Christ est tout et en tous.'),
  (51, 3, 12, 'Ainsi donc, comme des élus de Dieu, saints et bien-aimés, revêtez-vous d''entrailles de miséricorde, de bonté, d''humilité, de douceur, de patience.'),
  (51, 3, 13, 'Supportez-vous les uns les autres, et, si l''un a sujet de se plaindre de l''autre, pardonnez-vous réciproquement. De même que Christ vous a pardonné, pardonnez-vous aussi.'),
  (51, 3, 14, 'Mais par-dessus toutes ces choses revêtez-vous de la charité, qui est le lien de la perfection.'),
  (51, 3, 15, 'Et que la paix de Christ, à laquelle vous avez été appelés pour former un seul corps, règne dans vos cœurs. Et soyez reconnaissants.'),
  (51, 3, 16, 'Que la parole de Christ habite parmi vous abondamment; instruisez-vous et exhortez-vous les uns les autres en toute sagesse, par des psaumes, par des hymnes, par des cantiques spirituels, chantant à Dieu dans vos cœurs sous l''inspiration de la grâce.'),
  (51, 3, 17, 'Et quoi que vous fassiez, en parole ou en œuvre, faites tout au nom du Seigneur Jésus, en rendant par lui des actions de grâces à Dieu le Père.'),
  (51, 3, 18, 'Femmes, soyez soumises à vos maris, comme il convient dans le Seigneur.'),
  (51, 3, 19, 'Maris, aimez vos femmes, et ne vous aigrissez pas contre elles.'),
  (51, 3, 20, 'Enfants, obéissez en toutes choses à vos parents, car cela est agréable dans le Seigneur.'),
  (51, 3, 21, 'Pères, n''irritez pas vos enfants, de peur qu''ils ne se découragent.'),
  (51, 3, 22, 'Serviteurs, obéissez en toutes choses à vos maîtres selon la chair, non pas seulement sous leurs yeux, comme pour plaire aux hommes, mais avec simplicité de cœur, dans la crainte du Seigneur.'),
  (51, 3, 23, 'Tout ce que vous faites, faites-le de bon cœur, comme pour le Seigneur et non pour des hommes,'),
  (51, 3, 24, 'sachant que vous recevrez du Seigneur l''héritage pour récompense. Servez Christ, le Seigneur.'),
  (51, 3, 25, 'Car celui qui agit injustement recevra selon son injustice, et il n''y a point d''acception de personnes.'),
  (51, 4, 1, 'Maîtres, accordez à vos serviteurs ce qui est juste et équitable, sachant que vous aussi vous avez un maître dans le ciel.'),
  (51, 4, 2, 'Persévérez dans la prière, veillez-y avec actions de grâces.'),
  (51, 4, 3, 'Priez en même temps pour nous, afin que Dieu nous ouvre une porte pour la parole, en sorte que je puisse annoncer le mystère de Christ, pour lequel je suis dans les chaînes,'),
  (51, 4, 4, 'et le faire connaître comme je dois en parler.'),
  (51, 4, 5, 'Conduisez-vous avec sagesse envers ceux du dehors, et rachetez le temps.'),
  (51, 4, 6, 'Que votre parole soit toujours accompagnée de grâce, assaisonnée de sel, afin que vous sachiez comment il faut répondre à chacun.'),
  (51, 4, 7, 'Tychique, le bien-aimé frère et le fidèle ministre, mon compagnon de service dans le Seigneur, vous communiquera tout ce qui me concerne.'),
  (51, 4, 8, 'Je l''envoie exprès vers vous, pour que vous connaissiez notre situation, et pour qu''il console vos cœurs.'),
  (51, 4, 9, 'Je l''envoie avec Onésime, le fidèle et bien-aimé frère, qui est des vôtres. Ils vous informeront de tout ce qui se passe ici.'),
  (51, 4, 10, 'Aristarque, mon compagnon de captivité, vous salue, ainsi que Marc, le cousin de Barnabas, au sujet duquel vous avez reçu des ordres (s''il va chez vous, accueillez-le);'),
  (51, 4, 11, 'Jésus, appelé Justus, vous salue aussi. Ils sont du nombre des circoncis, et les seuls qui aient travaillé avec moi pour le royaume de Dieu, et qui aient été pour moi une consolation.'),
  (51, 4, 12, 'Épaphras, qui est des vôtres, vous salue: serviteur de Jésus-Christ, il ne cesse de combattre pour vous dans ses prières, afin que, parfaits et pleinement persuadés, vous persistiez dans une entière soumission à la volonté de Dieu.'),
  (51, 4, 13, 'Car je lui rends le témoignage qu''il a une grande sollicitude pour vous, pour ceux de Laodicée, et pour ceux d''Hiérapolis.'),
  (51, 4, 14, 'Luc, le médecin bien-aimé, vous salue, ainsi que Démas.'),
  (51, 4, 15, 'Saluez les frères qui sont à Laodicée, et Nymphas, et l''Église qui est dans sa maison.'),
  (51, 4, 16, 'Lorsque cette lettre aura été lue chez vous, faites en sorte qu''elle soit aussi lue dans l''Église des Laodicéens, et que vous lisiez à votre tour celle qui vous arrivera de Laodicée.'),
  (51, 4, 17, 'Et dites à Archippe: Prends garde au ministère que tu as reçu dans le Seigneur, afin de le bien remplir.'),
  (51, 4, 18, 'Je vous salue, moi Paul, de ma propre main. Souvenez-vous de mes liens. Que la grâce soit avec vous!'),
  (52, 1, 1, 'Paul, et Silvain, et Timothée, à l''Église des Thessaloniciens, qui est en Dieu le Père et en Jésus-Christ le Seigneur: que la grâce et la paix vous soient données!'),
  (52, 1, 2, 'Nous rendons continuellement grâces à Dieu pour vous tous, faisant mention de vous dans nos prières,'),
  (52, 1, 3, 'nous rappelant sans cesse l''œuvre de votre foi, le travail de votre charité, et la fermeté de votre espérance en notre Seigneur Jésus-Christ, devant Dieu notre Père.'),
  (52, 1, 4, 'Nous savons, frères bien-aimés de Dieu, que vous avez été élus,'),
  (52, 1, 5, 'notre Évangile ne vous ayant pas été prêché en paroles seulement, mais avec puissance, avec l''Esprit-Saint, et avec une pleine persuasion; car vous n''ignorez pas que nous nous sommes montrés ainsi parmi vous, à cause de vous.'),
  (52, 1, 6, 'Et vous-mêmes, vous avez été mes imitateurs et ceux du Seigneur, en recevant la parole au milieu de beaucoup de tribulations, avec la joie du Saint-Esprit,'),
  (52, 1, 7, 'en sorte que vous êtes devenus un modèle pour tous les croyants de la Macédoine et de l''Achaïe.'),
  (52, 1, 8, 'Non seulement, en effet, la parole du Seigneur a retenti de chez vous dans la Macédoine et dans l''Achaïe, mais votre foi en Dieu s''est fait connaître en tout lieu, de telle manière que nous n''avons pas besoin d''en parler.'),
  (52, 1, 9, 'Car on raconte, à notre sujet, quel accès nous avons eu auprès de vous, et comment vous vous êtes convertis à Dieu, en abandonnant les idoles pour servir le Dieu vivant et vrai,'),
  (52, 1, 10, 'et pour attendre des cieux son Fils, qu''il a ressuscité des morts, Jésus, qui nous délivre de la colère à venir.'),
  (52, 2, 1, 'Vous savez vous-mêmes, frères, que notre arrivée chez vous n''a pas été sans résultat.'),
  (52, 2, 2, 'Après avoir souffert et reçu des outrages à Philippes, comme vous le savez, nous prîmes de l''assurance en notre Dieu, pour vous annoncer l''Évangile de Dieu, au milieu de bien des combats.'),
  (52, 2, 3, 'Car notre prédication ne repose ni sur l''erreur, ni sur des motifs impurs, ni sur la fraude;'),
  (52, 2, 4, 'mais, selon que Dieu nous a jugés dignes de nous confier l''Évangile, ainsi nous parlons, non comme pour plaire à des hommes, mais pour plaire à Dieu, qui sonde nos cœurs.'),
  (52, 2, 5, 'Jamais, en effet, nous n''avons usé de paroles flatteuses, comme vous le savez; jamais nous n''avons eu la cupidité pour mobile, Dieu en est témoin.'),
  (52, 2, 6, 'Nous n''avons point cherché la gloire qui vient des hommes, ni de vous ni des autres; nous aurions pu nous produire avec autorité comme apôtres de Christ,'),
  (52, 2, 7, 'mais nous avons été pleins de douceur au milieu de vous. De même qu''une nourrice prend un tendre soin de ses enfants,'),
  (52, 2, 8, 'nous aurions voulu, dans notre vive affection pour vous, non seulement vous donner l''Évangile de Dieu, mais encore nos propres vies, tant vous nous étiez devenus chers.'),
  (52, 2, 9, 'Vous vous rappelez, frères, notre travail et notre peine: nuit et jour à l''œuvre, pour n''être à charge à aucun de vous, nous vous avons prêché l''Évangile de Dieu.'),
  (52, 2, 10, 'Vous êtes témoins, et Dieu l''est aussi, que nous avons eu envers vous qui croyez une conduite sainte, juste et irréprochable.'),
  (52, 2, 11, 'Vous savez aussi que nous avons été pour chacun de vous ce qu''un père est pour ses enfants, vous exhortant, vous consolant, vous conjurant'),
  (52, 2, 12, 'de marcher d''une manière digne de Dieu, qui vous appelle à son royaume et à sa gloire.'),
  (52, 2, 13, 'C''est pourquoi nous rendons continuellement grâces à Dieu de ce qu''en recevant la parole de Dieu, que nous vous avons fait entendre, vous l''avez reçue, non comme la parole des hommes, mais, ainsi qu''elle l''est véritablement, comme la parole de Dieu, qui agit en vous qui croyez.'),
  (52, 2, 14, 'Car vous, frères, vous êtes devenus les imitateurs des Églises de Dieu qui sont en Jésus-Christ dans la Judée, parce que vous aussi, vous avez souffert de la part de vos propres compatriotes les mêmes maux qu''elles ont soufferts de la part des Juifs.'),
  (52, 2, 15, 'Ce sont ces Juifs qui ont fait mourir le Seigneur Jésus et les prophètes, qui nous ont persécutés, qui ne plaisent point à Dieu, et qui sont ennemis de tous les hommes,'),
  (52, 2, 16, 'nous empêchant de parler aux païens pour qu''ils soient sauvés, en sorte qu''ils ne cessent de mettre le comble à leurs péchés. Mais la colère a fini par les atteindre.'),
  (52, 2, 17, 'Pour nous, frères, après avoir été quelque temps séparés de vous, de corps mais non de cœur, nous avons eu d''autant plus ardemment le vif désir de vous voir.'),
  (52, 2, 18, 'Aussi voulions-nous aller vers vous, du moins moi Paul, une et même deux fois; mais Satan nous en a empêchés.'),
  (52, 2, 19, 'Qui est, en effet, notre espérance, ou notre joie, ou notre couronne de gloire? N''est-ce pas vous aussi, devant notre Seigneur Jésus, lors de son avènement?'),
  (52, 2, 20, 'Oui, vous êtes notre gloire et notre joie.'),
  (52, 3, 1, 'C''est pourquoi, impatients que nous étions, et nous décidant à rester seuls à Athènes,'),
  (52, 3, 2, 'nous envoyâmes Timothée, notre frère, ministre de Dieu dans l''Évangile de Christ, pour vous affermir et vous exhorter au sujet de votre foi,'),
  (52, 3, 3, 'afin que personne ne fût ébranlé au milieu des tribulations présentes; car vous savez vous-mêmes que nous sommes destinés à cela.'),
  (52, 3, 4, 'Et lorsque nous étions auprès de vous, nous vous annoncions d''avance que nous serions exposés à des tribulations, comme cela est arrivé, et comme vous le savez.'),
  (52, 3, 5, 'Ainsi, dans mon impatience, j''envoyai m''informer de votre foi, dans la crainte que le tentateur ne vous eût tentés, et que nous n''eussions travaillé en vain.'),
  (52, 3, 6, 'Mais Timothée, récemment arrivé ici de chez vous, nous a donné de bonnes nouvelles de votre foi et de votre charité, et nous a dit que vous avez toujours de nous un bon souvenir, désirant nous voir comme nous désirons aussi vous voir.'),
  (52, 3, 7, 'En conséquence, frères, au milieu de toutes nos calamités et de nos tribulations, nous avons été consolés à votre sujet, à cause de votre foi.'),
  (52, 3, 8, 'Car maintenant nous vivons, puisque vous demeurez fermes dans le Seigneur.'),
  (52, 3, 9, 'Quelles actions de grâces, en effet, nous pouvons rendre à Dieu à votre sujet, pour toute la joie que nous éprouvons à cause de vous, devant notre Dieu!'),
  (52, 3, 10, 'Nuit et jour, nous le prions avec une extrême ardeur de nous permettre de vous voir, et de compléter ce qui manque à votre foi.'),
  (52, 3, 11, 'Que Dieu lui-même, notre Père, et notre Seigneur Jésus, aplanissent notre route pour que nous allions à vous!'),
  (52, 3, 12, 'Que le Seigneur augmente de plus en plus parmi vous, et à l''égard de tous, cette charité que nous avons nous-mêmes pour vous,'),
  (52, 3, 13, 'afin d''affermir vos cœurs pour qu''ils soient irréprochables dans la sainteté devant Dieu notre Père, lors de l''avènement de notre Seigneur Jésus avec tous ses saints!'),
  (52, 4, 1, 'Au reste, frères, puisque vous avez appris de nous comment vous devez vous conduire et plaire à Dieu, et que c''est là ce que vous faites, nous vous prions et nous vous conjurons au nom du Seigneur Jésus de marcher à cet égard de progrès en progrès.'),
  (52, 4, 2, 'Vous savez, en effet, quels préceptes nous vous avons donnés de la part du Seigneur Jésus.'),
  (52, 4, 3, 'Ce que Dieu veut, c''est votre sanctification; c''est que vous vous absteniez de l''impudicité;'),
  (52, 4, 4, 'c''est que chacun de vous sache posséder son corps dans la sainteté et l''honnêteté,'),
  (52, 4, 5, 'sans vous livrer à une convoitise passionnée, comme font les païens qui ne connaissent pas Dieu;'),
  (52, 4, 6, 'c''est que personne n''use envers son frère de fraude et de cupidité dans les affaires, parce que le Seigneur tire vengeance de toutes ces choses, comme nous vous l''avons déjà dit et attesté.'),
  (52, 4, 7, 'Car Dieu ne nous a pas appelés à l''impureté, mais à la sanctification.'),
  (52, 4, 8, 'Celui donc qui rejette ces préceptes ne rejette pas un homme, mais Dieu, qui vous a aussi donné son Saint-Esprit.'),
  (52, 4, 9, 'Pour ce qui est de l''amour fraternel, vous n''avez pas besoin qu''on vous en écrive; car vous avez vous-mêmes appris de Dieu à vous aimer les uns les autres,'),
  (52, 4, 10, 'et c''est aussi ce que vous faites envers tous les frères dans la Macédoine entière. Mais nous vous exhortons, frères, à abonder toujours plus dans cet amour,'),
  (52, 4, 11, 'et à mettre votre honneur à vivre tranquilles, à vous occuper de vos propres affaires, et à travailler de vos mains, comme nous vous l''avons recommandé,'),
  (52, 4, 12, 'en sorte que vous vous conduisiez honnêtement envers ceux du dehors, et que vous n''ayez besoin de personne.'),
  (52, 4, 13, 'Nous ne voulons pas, frères, que vous soyez dans l''ignorance au sujet de ceux qui dorment, afin que vous ne vous affligiez pas comme les autres qui n''ont point d''espérance.'),
  (52, 4, 14, 'Car, si nous croyons que Jésus est mort et qu''il est ressuscité, croyons aussi que Dieu ramènera par Jésus et avec lui ceux qui sont morts.'),
  (52, 4, 15, 'Voici, en effet, ce que nous vous déclarons d''après la parole du Seigneur: nous les vivants, restés pour l''avènement du Seigneur, nous ne devancerons pas ceux qui sont morts.'),
  (52, 4, 16, 'Car le Seigneur lui-même, à un signal donné, à la voix d''un archange, et au son de la trompette de Dieu, descendra du ciel, et les morts en Christ ressusciteront premièrement.'),
  (52, 4, 17, 'Ensuite, nous les vivants, qui serons restés, nous serons tous ensemble enlevés avec eux sur des nuées, à la rencontre du Seigneur dans les airs, et ainsi nous serons toujours avec le Seigneur.'),
  (52, 4, 18, 'Consolez-vous donc les uns les autres par ces paroles.'),
  (52, 5, 1, 'Pour ce qui est des temps et des moments, vous n''avez pas besoin, frères, qu''on vous en écrive.'),
  (52, 5, 2, 'Car vous savez bien vous-mêmes que le jour du Seigneur viendra comme un voleur dans la nuit.'),
  (52, 5, 3, 'Quand les hommes diront: Paix et sûreté! alors une ruine soudaine les surprendra, comme les douleurs de l''enfantement surprennent la femme enceinte, et ils n''échapperont point.'),
  (52, 5, 4, 'Mais vous, frères, vous n''êtes pas dans les ténèbres, pour que ce jour vous surprenne comme un voleur;'),
  (52, 5, 5, 'vous êtes tous des enfants de la lumière et des enfants du jour. Nous ne sommes point de la nuit ni des ténèbres.'),
  (52, 5, 6, 'Ne dormons donc point comme les autres, mais veillons et soyons sobres.'),
  (52, 5, 7, 'Car ceux qui dorment dorment la nuit, et ceux qui s''enivrent s''enivrent la nuit.'),
  (52, 5, 8, 'Mais nous qui sommes du jour, soyons sobres, ayant revêtu la cuirasse de la foi et de la charité, et ayant pour casque l''espérance du salut.'),
  (52, 5, 9, 'Car Dieu ne nous a pas destinés à la colère, mais à l''acquisition du salut par notre Seigneur Jésus-Christ,'),
  (52, 5, 10, 'qui est mort pour nous, afin que, soit que nous veillions, soit que nous dormions, nous vivions ensemble avec lui.'),
  (52, 5, 11, 'C''est pourquoi exhortez-vous réciproquement, et édifiez-vous les uns les autres, comme en réalité vous le faites.'),
  (52, 5, 12, 'Nous vous prions, frères, d''avoir de la considération pour ceux qui travaillent parmi vous, qui vous dirigent dans le Seigneur, et qui vous exhortent.'),
  (52, 5, 13, 'Ayez pour eux beaucoup d''affection, à cause de leur œuvre. Soyez en paix entre vous.'),
  (52, 5, 14, 'Nous vous en prions aussi, frères, avertissez ceux qui vivent dans le désordre, consolez ceux qui sont abattus, supportez les faibles, usez de patience envers tous.'),
  (52, 5, 15, 'Prenez garde que personne ne rende à autrui le mal pour le mal; mais poursuivez toujours le bien, soit entre vous, soit envers tous.'),
  (52, 5, 16, 'Soyez toujours joyeux.'),
  (52, 5, 17, 'Priez sans cesse.'),
  (52, 5, 18, 'Rendez grâces en toutes choses, car c''est à votre égard la volonté de Dieu en Jésus-Christ.'),
  (52, 5, 19, 'N''éteignez pas l''Esprit.'),
  (52, 5, 20, 'Ne méprisez pas les prophéties.'),
  (52, 5, 21, 'Mais examinez toutes choses; retenez ce qui est bon;'),
  (52, 5, 22, 'abstenez-vous de toute espèce de mal.'),
  (52, 5, 23, 'Que le Dieu de paix vous sanctifie lui-même tout entiers, et que tout votre être, l''esprit, l''âme et le corps, soit conservé irrépréhensible, lors de l''avènement de notre Seigneur Jésus-Christ!'),
  (52, 5, 24, 'Celui qui vous a appelés est fidèle, et c''est lui qui le fera.'),
  (52, 5, 25, 'Frères, priez pour nous.'),
  (52, 5, 26, 'Saluez tous les frères par un saint baiser.'),
  (52, 5, 27, 'Je vous en conjure par le Seigneur, que cette lettre soit lue à tous les frères.'),
  (52, 5, 28, 'Que la grâce de notre Seigneur Jésus-Christ soit avec vous!'),
  (53, 1, 1, 'Paul, et Silvain, et Timothée, à l''Église des Thessaloniciens, qui est en Dieu notre Père et en Jésus-Christ le Seigneur:'),
  (53, 1, 2, 'que la grâce et la paix vous soient données de la part de Dieu notre Père et du Seigneur Jésus-Christ!'),
  (53, 1, 3, 'Nous devons à votre sujet, frères, rendre continuellement grâces à Dieu, comme cela est juste, parce que votre foi fait de grands progrès, et que la charité de chacun de vous tous à l''égard des autres augmente de plus en plus.'),
  (53, 1, 4, 'Aussi nous glorifions-nous de vous dans les Églises de Dieu, à cause de votre persévérance et de votre foi au milieu de toutes vos persécutions et des tribulations que vous avez à supporter.'),
  (53, 1, 5, 'C''est une preuve du juste jugement de Dieu, pour que vous soyez jugés dignes du royaume de Dieu, pour lequel vous souffrez.'),
  (53, 1, 6, 'Car il est de la justice de Dieu de rendre l''affliction à ceux qui vous affligent,'),
  (53, 1, 7, 'et de vous donner, à vous qui êtes affligés, du repos avec nous, lorsque le Seigneur Jésus apparaîtra du ciel avec les anges de sa puissance,'),
  (53, 1, 8, 'au milieu d''une flamme de feu, pour punir ceux qui ne connaissent pas Dieu et ceux qui n''obéissent pas à l''Évangile de notre Seigneur Jésus.'),
  (53, 1, 9, 'Ils auront pour châtiment une ruine éternelle, loin de la face du Seigneur et de la gloire de sa force,'),
  (53, 1, 10, 'lorsqu''il viendra pour être, en ce jour-là, glorifié dans ses saints et admiré dans tous ceux qui auront cru, car notre témoignage auprès de vous a été cru.'),
  (53, 1, 11, 'C''est pourquoi aussi nous prions continuellement pour vous, afin que notre Dieu vous juge dignes de la vocation, et qu''il accomplisse par sa puissance tous les desseins bienveillants de sa bonté, et l''œuvre de votre foi,'),
  (53, 1, 12, 'pour que le nom de notre Seigneur Jésus soit glorifié en vous, et que vous soyez glorifiés en lui, selon la grâce de notre Dieu et du Seigneur Jésus-Christ.'),
  (53, 2, 1, 'Pour ce qui concerne l''avènement de notre Seigneur Jésus-Christ et notre réunion avec lui, nous vous prions, frères,'),
  (53, 2, 2, 'de ne pas vous laisser facilement ébranler dans votre bon sens, et de ne pas vous laisser troubler, soit par quelque inspiration, soit par quelque parole, ou par quelque lettre qu''on dirait venir de nous, comme si le jour du Seigneur était déjà là.'),
  (53, 2, 3, 'Que personne ne vous séduise d''aucune manière; car il faut que l''apostasie soit arrivée auparavant, et qu''on ait vu paraître l''homme du péché, le fils de la perdition,'),
  (53, 2, 4, 'l''adversaire qui s''élève au-dessus de tout ce qu''on appelle Dieu ou de ce qu''on adore, jusqu''à s''asseoir dans le temple de Dieu, se proclamant lui-même Dieu.'),
  (53, 2, 5, 'Ne vous souvenez-vous pas que je vous disais ces choses, lorsque j''étais encore chez vous?'),
  (53, 2, 6, 'Et maintenant vous savez ce qui le retient, afin qu''il ne paraisse qu''en son temps.'),
  (53, 2, 7, 'Car le mystère de l''iniquité agit déjà; il faut seulement que celui qui le retient encore ait disparu.'),
  (53, 2, 8, 'Et alors paraîtra l''impie, que le Seigneur Jésus détruira par le souffle de sa bouche, et qu''il anéantira par l''éclat de son avènement.'),
  (53, 2, 9, 'L''apparition de cet impie se fera, par la puissance de Satan, avec toutes sortes de miracles, de signes et de prodiges mensongers,'),
  (53, 2, 10, 'et avec toutes les séductions de l''iniquité pour ceux qui périssent parce qu''ils n''ont pas reçu l''amour de la vérité pour être sauvés.'),
  (53, 2, 11, 'Aussi Dieu leur envoie une puissance d''égarement, pour qu''ils croient au mensonge,'),
  (53, 2, 12, 'afin que tous ceux qui n''ont pas cru à la vérité, mais qui ont pris plaisir à l''injustice, soient condamnés.'),
  (53, 2, 13, 'Pour nous, frères bien-aimés du Seigneur, nous devons à votre sujet rendre continuellement grâces à Dieu, parce que Dieu vous a choisis dès le commencement pour le salut, par la sanctification de l''Esprit et par la foi en la vérité.'),
  (53, 2, 14, 'C''est à quoi il vous a appelés par notre Évangile, pour que vous possédiez la gloire de notre Seigneur Jésus-Christ.'),
  (53, 2, 15, 'Ainsi donc, frères, demeurez fermes, et retenez les instructions que vous avez reçues, soit par notre parole, soit par notre lettre.'),
  (53, 2, 16, 'Que notre Seigneur Jésus-Christ lui-même, et Dieu notre Père, qui nous a aimés, et qui nous a donné par sa grâce une consolation éternelle et une bonne espérance,'),
  (53, 2, 17, 'consolent vos cœurs, et vous affermissent en toute bonne œuvre et en toute bonne parole!'),
  (53, 3, 1, 'Au reste, frères, priez pour nous, afin que la parole du Seigneur se répande et soit glorifiée comme elle l''est chez-vous,'),
  (53, 3, 2, 'et afin que nous soyons délivrés des hommes méchants et pervers; car tous n''ont pas la foi.'),
  (53, 3, 3, 'Le Seigneur est fidèle, il vous affermira et vous préservera du malin.'),
  (53, 3, 4, 'Nous avons à votre égard cette confiance dans le Seigneur que vous faites et que vous ferez les choses que nous recommandons.'),
  (53, 3, 5, 'Que le Seigneur dirige vos cœurs vers l''amour de Dieu et vers la patience de Christ!'),
  (53, 3, 6, 'nous vous recommandons, frères, au nom de notre Seigneur Jésus-Christ, de vous éloigner de tout frère qui vit dans le désordre, et non selon les instructions que vous avez reçues de nous.'),
  (53, 3, 7, 'Vous savez vous-mêmes comment il faut nous imiter, car nous n''avons pas vécu parmi vous dans le désordre.'),
  (53, 3, 8, 'Nous n''avons mangé gratuitement le pain de personne; mais, dans le travail et dans la peine, nous avons été nuit et jour à l''œuvre, pour n''être à charge à aucun de vous.'),
  (53, 3, 9, 'Ce n''est pas que nous n''en eussions le droit, mais nous avons voulu vous donner en nous-mêmes un modèle à imiter.'),
  (53, 3, 10, 'Car, lorsque nous étions chez vous, nous vous disions expressément: Si quelqu''un ne veut pas travailler, qu''il ne mange pas non plus.'),
  (53, 3, 11, 'Nous apprenons, cependant, qu''il y en a parmi vous quelques-uns qui vivent dans le désordre, qui ne travaillent pas, mais qui s''occupent de futilités.'),
  (53, 3, 12, 'Nous invitons ces gens-là, et nous les exhortons par le Seigneur Jésus-Christ, à manger leur propre pain, en travaillant paisiblement.'),
  (53, 3, 13, 'Pour vous, frères, ne vous lassez pas de faire le bien.'),
  (53, 3, 14, 'Et si quelqu''un n''obéit pas à ce que nous disons par cette lettre, notez-le, et n''ayez point de communication avec lui, afin qu''il éprouve de la honte.'),
  (53, 3, 15, 'Ne le regardez pas comme un ennemi, mais avertissez-le comme un frère.'),
  (53, 3, 16, 'Que le Seigneur de la paix vous donne lui-même la paix en tout temps, de toute manière! Que le Seigneur soit avec vous tous!'),
  (53, 3, 17, 'Je vous salue, moi Paul, de ma propre main. C''est là ma signature dans toutes mes lettres; c''est ainsi que j''écris.'),
  (53, 3, 18, 'Que la grâce de notre Seigneur Jésus-Christ soit avec vous tous!'),
  (54, 1, 1, 'Paul, apôtre de Jésus-Christ, par ordre de Dieu notre Sauveur et de Jésus-Christ notre espérance,'),
  (54, 1, 2, 'à Timothée, mon enfant légitime en la foi: que la grâce, la miséricorde et la paix, te soient données de la part de Dieu le Père et de Jésus-Christ notre Seigneur!'),
  (54, 1, 3, 'Je te rappelle l''exhortation que je te fis, à mon départ pour la Macédoine, lorsque je t''engageai à rester à Éphèse, afin de recommander à certaines personnes de ne pas enseigner d''autres doctrines,'),
  (54, 1, 4, 'et de ne pas s''attacher à des fables et à des généalogies sans fin, qui produisent des discussions plutôt qu''elles n''avancent l''œuvre de Dieu dans la foi.'),
  (54, 1, 5, 'Le but du commandement, c''est une charité venant d''un cœur pur, d''une bonne conscience, et d''une foi sincère.'),
  (54, 1, 6, 'Quelques-uns, s''étant détournés de ces choses, se sont égarés dans de vains discours;'),
  (54, 1, 7, 'ils veulent être docteurs de la loi, et ils ne comprennent ni ce qu''ils disent, ni ce qu''ils affirment.'),
  (54, 1, 8, 'Nous n''ignorons pas que la loi est bonne, pourvu qu''on en fasse un usage légitime,'),
  (54, 1, 9, 'sachant bien que la loi n''est pas faite pour le juste, mais pour les méchants et les rebelles, les impies et les pécheurs, les irréligieux et les profanes, les parricides, les meurtriers,'),
  (54, 1, 10, 'les impudiques, les infâmes, les voleurs d''hommes, les menteurs, les parjures, et tout ce qui est contraire à la saine doctrine, -'),
  (54, 1, 11, 'conformément à l''Évangile de la gloire du Dieu bienheureux, Évangile qui m''a été confié.'),
  (54, 1, 12, 'Je rends grâces à celui qui m''a fortifié, à Jésus-Christ notre Seigneur, de ce qu''il m''a jugé fidèle, en m''établissant dans le ministère,'),
  (54, 1, 13, 'moi qui étais auparavant un blasphémateur, un persécuteur, un homme violent. Mais j''ai obtenu miséricorde, parce que j''agissais par ignorance, dans l''incrédulité;'),
  (54, 1, 14, 'et la grâce de notre Seigneur a surabondé, avec la foi et la charité qui est en Jésus-Christ.'),
  (54, 1, 15, 'C''est une parole certaine et entièrement digne d''être reçue, que Jésus-Christ est venu dans le monde pour sauver les pécheurs, dont je suis le premier.'),
  (54, 1, 16, 'Mais j''ai obtenu miséricorde, afin que Jésus-Christ fît voir en moi le premier toute sa longanimité, pour que je servisse d''exemple à ceux qui croiraient en lui pour la vie éternelle.'),
  (54, 1, 17, 'Au roi des siècles, immortel, invisible, seul Dieu, soient honneur et gloire, aux siècles des siècles! Amen!'),
  (54, 1, 18, 'Le commandement que je t''adresse, Timothée, mon enfant, selon les prophéties faites précédemment à ton sujet, c''est que, d''après elles, tu combattes le bon combat,'),
  (54, 1, 19, 'en gardant la foi et une bonne conscience. Cette conscience, quelques-uns l''ont perdue, et ils ont fait naufrage par rapport à la foi.'),
  (54, 1, 20, 'De ce nombre sont Hyménée et Alexandre, que j''ai livrés à Satan, afin qu''ils apprennent à ne pas blasphémer.'),
  (54, 2, 1, 'J''exhorte donc, avant toutes choses, à faire des prières, des supplications, des requêtes, des actions de grâces, pour tous les hommes,'),
  (54, 2, 2, 'pour les rois et pour tous ceux qui sont élevés en dignité, afin que nous menions une vie paisible et tranquille, en toute piété et honnêteté.'),
  (54, 2, 3, 'Cela est bon et agréable devant Dieu notre Sauveur,'),
  (54, 2, 4, 'qui veut que tous les hommes soient sauvés et parviennent à la connaissance de la vérité.'),
  (54, 2, 5, 'Car il y a un seul Dieu, et aussi un seul médiateur entre Dieu et les hommes, Jésus-Christ homme,'),
  (54, 2, 6, 'qui s''est donné lui-même en rançon pour tous. C''est là le témoignage rendu en son propre temps,'),
  (54, 2, 7, 'et pour lequel j''ai été établi prédicateur et apôtre, -je dis la vérité, je ne mens pas, -chargé d''instruire les païens dans la foi et la vérité.'),
  (54, 2, 8, 'Je veux donc que les hommes prient en tout lieu, en élevant des mains pures, sans colère ni mauvaises pensées.'),
  (54, 2, 9, 'Je veux aussi que les femmes, vêtues d''une manière décente, avec pudeur et modestie, ne se parent ni de tresses, ni d''or, ni de perles, ni d''habits somptueux,'),
  (54, 2, 10, 'mais qu''elles se parent de bonnes œuvres, comme il convient à des femmes qui font profession de servir Dieu.'),
  (54, 2, 11, 'Que la femme écoute l''instruction en silence, avec une entière soumission.'),
  (54, 2, 12, 'Je ne permets pas à la femme d''enseigner, ni de prendre de l''autorité sur l''homme; mais elle doit demeurer dans le silence.'),
  (54, 2, 13, 'Car Adam a été formé le premier, Eve ensuite;'),
  (54, 2, 14, 'et ce n''est pas Adam qui a été séduit, c''est la femme qui, séduite, s''est rendue coupable de transgression.'),
  (54, 2, 15, 'Elle sera néanmoins sauvée en devenant mère, si elle persévère avec modestie dans la foi, dans la charité, et dans la sainteté.'),
  (54, 3, 1, 'Cette parole est certaine: Si quelqu''un aspire à la charge d''évêque, il désire une œuvre excellente.'),
  (54, 3, 2, 'Il faut donc que l''évêque soit irréprochable, mari d''une seule femme, sobre, modéré, réglé dans sa conduite, hospitalier, propre à l''enseignement.'),
  (54, 3, 3, 'Il faut qu''il ne soit ni adonné au vin, ni violent, mais indulgent, pacifique, désintéressé.'),
  (54, 3, 4, 'Il faut qu''il dirige bien sa propre maison, et qu''il tienne ses enfants dans la soumission et dans une parfaite honnêteté;'),
  (54, 3, 5, 'car si quelqu''un ne sait pas diriger sa propre maison, comment prendra-t-il soin de l''Église de Dieu?'),
  (54, 3, 6, 'Il ne faut pas qu''il soit un nouveau converti, de peur qu''enflé d''orgueil il ne tombe sous le jugement du diable.'),
  (54, 3, 7, 'Il faut aussi qu''il reçoive un bon témoignage de ceux du dehors, afin de ne pas tomber dans l''opprobre et dans les pièges du diable.'),
  (54, 3, 8, 'Les diacres aussi doivent être honnêtes, éloignés de la duplicité, des excès du vin, d''un gain sordide,'),
  (54, 3, 9, 'conservant le mystère de la foi dans une conscience pure.'),
  (54, 3, 10, 'Qu''on les éprouve d''abord, et qu''ils exercent ensuite leur ministère, s''ils sont sans reproche.'),
  (54, 3, 11, 'Les femmes, de même, doivent être honnêtes, non médisantes, sobres, fidèles en toutes choses.'),
  (54, 3, 12, 'Les diacres doivent être maris d''une seule femme, et diriger bien leurs enfants et leurs propres maisons;'),
  (54, 3, 13, 'car ceux qui remplissent convenablement leur ministère s''acquièrent un rang honorable, et une grande assurance dans la foi en Jésus-Christ.'),
  (54, 3, 14, 'Je t''écris ces choses, avec l''espérance d''aller bientôt vers toi,'),
  (54, 3, 15, 'mais afin que tu saches, si je tarde, comment il faut se conduire dans la maison de Dieu, qui est l''Église du Dieu vivant, la colonne et l''appui de la vérité.'),
  (54, 3, 16, 'Et, sans contredit, le mystère de la piété est grand: celui qui a été manifesté en chair, justifié par l''Esprit, vu des anges, prêché aux Gentils, cru dans le monde, élevé dans la gloire.'),
  (54, 4, 1, 'Mais l''Esprit dit expressément que, dans les derniers temps, quelques-uns abandonneront la foi, pour s''attacher à des esprits séducteurs et à des doctrines de démons,'),
  (54, 4, 2, 'par l''hypocrisie de faux docteurs portant la marque de la flétrissure dans leur propre conscience,'),
  (54, 4, 3, 'prescrivant de ne pas se marier, et de s''abstenir d''aliments que Dieu a créés pour qu''ils soient pris avec actions de grâces par ceux qui sont fidèles et qui ont connu la vérité.'),
  (54, 4, 4, 'Car tout ce que Dieu a créé est bon, et rien ne doit être rejeté, pourvu qu''on le prenne avec actions de grâces,'),
  (54, 4, 5, 'parce que tout est sanctifié par la parole de Dieu et par la prière.'),
  (54, 4, 6, 'En exposant ces choses aux frères, tu seras un bon ministre de Jésus-Christ, nourri des paroles de la foi et de la bonne doctrine que tu as exactement suivie.'),
  (54, 4, 7, 'Repousse les contes profanes et absurdes. Exerce-toi à la piété;'),
  (54, 4, 8, 'car l''exercice corporel est utile à peu de chose, tandis que la piété est utile à tout, ayant la promesse de la vie présente et de celle qui est à venir.'),
  (54, 4, 9, 'C''est là une parole certaine et entièrement digne d''être reçue.'),
  (54, 4, 10, 'Nous travaillons, en effet, et nous combattons, parce que nous mettons notre espérance dans le Dieu vivant, qui est le Sauveur de tous les hommes, principalement des croyants.'),
  (54, 4, 11, 'Déclare ces choses, et enseigne-les.'),
  (54, 4, 12, 'Que personne ne méprise ta jeunesse; mais sois un modèle pour les fidèles, en parole, en conduite, en charité, en foi, en pureté.'),
  (54, 4, 13, 'Jusqu''à ce que je vienne, applique-toi à la lecture, à l''exhortation, à l''enseignement.'),
  (54, 4, 14, 'Ne néglige pas le don qui est en toi, et qui t''a été donné par prophétie avec l''imposition des mains de l''assemblée des anciens.'),
  (54, 4, 15, 'Occupe-toi de ces choses, donne-toi tout entier à elles, afin que tes progrès soient évidents pour tous.'),
  (54, 4, 16, 'Veille sur toi-même et sur ton enseignement; persévère dans ces choses, car, en agissant ainsi, tu te sauveras toi-même, et tu sauveras ceux qui t''écoutent.'),
  (54, 5, 1, 'Ne réprimande pas rudement le vieillard, mais exhorte-le comme un père; exhorte les jeunes gens comme des frères,'),
  (54, 5, 2, 'les femmes âgées comme des mères, celles qui sont jeunes comme des sœurs, en toute pureté.'),
  (54, 5, 3, 'Honore les veuves qui sont véritablement veuves.'),
  (54, 5, 4, 'Si une veuve a des enfants ou des petits-enfants, qu''ils apprennent avant tout à exercer la piété envers leur propre famille, et à rendre à leurs parents ce qu''ils ont reçu d''eux; car cela est agréable à Dieu.'),
  (54, 5, 5, 'Celle qui est véritablement veuve, et qui est demeurée dans l''isolement, met son espérance en Dieu et persévère nuit et jour dans les supplications et les prières.'),
  (54, 5, 6, 'Mais celle qui vit dans les plaisirs est morte, quoique vivante.'),
  (54, 5, 7, 'Déclare-leur ces choses, afin qu''elles soient irréprochables.'),
  (54, 5, 8, 'Si quelqu''un n''a pas soin des siens, et principalement de ceux de sa famille, il a renié la foi, et il est pire qu''un infidèle.'),
  (54, 5, 9, 'Qu''une veuve, pour être inscrite sur le rôle, n''ait pas moins de soixante ans, qu''elle ait été femme d''un seul mari,'),
  (54, 5, 10, 'qu''elle soit recommandable par de bonnes œuvres, ayant élevé des enfants, exercé l''hospitalité, lavé les pieds des saints, secouru les malheureux, pratiqué toute espèce de bonne œuvre.'),
  (54, 5, 11, 'Mais refuse les jeunes veuves; car, lorsque la volupté les détache du Christ, elles veulent se marier,'),
  (54, 5, 12, 'et se rendent coupables en ce qu''elles violent leur premier engagement.'),
  (54, 5, 13, 'Avec cela, étant oisives, elles apprennent à aller de maison en maison; et non seulement elles sont oisives, mais encore causeuses et intrigantes, disant ce qu''il ne faut pas dire.'),
  (54, 5, 14, 'Je veux donc que les jeunes se marient, qu''elles aient des enfants, qu''elles dirigent leur maison, qu''elles ne donnent à l''adversaire aucune occasion de médire;'),
  (54, 5, 15, 'car déjà quelques-unes se sont détournées pour suivre Satan.'),
  (54, 5, 16, 'Si quelque fidèle, homme ou femme, a des veuves, qu''il les assiste, et que l''Église n''en soit point chargée, afin qu''elle puisse assister celles qui sont véritablement veuves.'),
  (54, 5, 17, 'Que les anciens qui dirigent bien soient jugés dignes d''un double honneur, surtout ceux qui travaillent à la prédication et à l''enseignement.'),
  (54, 5, 18, 'Car l''Écriture dit: Tu n''emmuselleras point le bœuf quand il foule le grain. Et l''ouvrier mérite son salaire.'),
  (54, 5, 19, 'Ne reçois point d''accusation contre un ancien, si ce n''est sur la déposition de deux ou trois témoins.'),
  (54, 5, 20, 'Ceux qui pèchent, reprends-les devant tous, afin que les autres aussi éprouvent de la crainte.'),
  (54, 5, 21, 'Je te conjure devant Dieu, devant Jésus-Christ, et devant les anges élus, d''observer ces choses sans prévention, et de ne rien faire par faveur.'),
  (54, 5, 22, 'N''impose les mains à personne avec précipitation, et ne participe pas aux péchés d''autrui; toi-même, conserve-toi pur.'),
  (54, 5, 23, 'Ne continue pas à ne boire que de l''eau; mais fais usage d''un peu de vin, à cause de ton estomac et de tes fréquentes indispositions.'),
  (54, 5, 24, 'Les péchés de certains hommes sont manifestes, même avant qu''on les juge, tandis que chez d''autres, ils ne se découvrent que dans la suite.'),
  (54, 5, 25, 'De même, les bonnes œuvres sont manifestes, et celles qui ne le sont pas ne peuvent rester cachées.'),
  (54, 6, 1, 'Que tous ceux qui sont sous le joug de la servitude regardent leurs maîtres comme dignes de tout honneur, afin que le nom de Dieu et la doctrine ne soient pas blasphémés.'),
  (54, 6, 2, 'Et que ceux qui ont des fidèles pour maîtres ne les méprisent pas, sous prétexte qu''ils sont frères; mais qu''ils les servent d''autant mieux que ce sont des fidèles et des bien-aimés qui s''attachent à leur faire du bien. Enseigne ces choses et recommande-les.'),
  (54, 6, 3, 'Si quelqu''un enseigne de fausses doctrines, et ne s''attache pas aux saines paroles de notre Seigneur Jésus-Christ et à la doctrine qui est selon la piété,'),
  (54, 6, 4, 'il est enflé d''orgueil, il ne sait rien, et il a la maladie des questions oiseuses et des disputes de mots, d''où naissent l''envie, les querelles, les calomnies, les mauvais soupçons,'),
  (54, 6, 5, 'les vaines discussions d''hommes corrompus d''entendement, privés de la vérité, et croyant que la piété est une source de gain.'),
  (54, 6, 6, 'C''est, en effet, une grande source de gain que la piété avec le contentement;'),
  (54, 6, 7, 'car nous n''avons rien apporté dans le monde, et il est évident que nous n''en pouvons rien emporter;'),
  (54, 6, 8, 'si donc nous avons la nourriture et le vêtement, cela nous suffira.'),
  (54, 6, 9, 'Mais ceux qui veulent s''enrichir tombent dans la tentation, dans le piège, et dans beaucoup de désirs insensés et pernicieux qui plongent les hommes dans la ruine et la perdition.'),
  (54, 6, 10, 'Car l''amour de l''argent est une racine de tous les maux; et quelques-uns, en étant possédés, se sont égarés loin de la foi, et se sont jetés eux-mêmes dans bien des tourments.'),
  (54, 6, 11, 'Pour toi, homme de Dieu, fuis ces choses, et recherche la justice, la piété, la foi, la charité, la patience, la douceur.'),
  (54, 6, 12, 'Combats le bon combat de la foi, saisis la vie éternelle, à laquelle tu as été appelé, et pour laquelle tu as fait une belle confession en présence d''un grand nombre de témoins.'),
  (54, 6, 13, 'Je te recommande, devant Dieu qui donne la vie à toutes choses, et devant Jésus-Christ, qui fit une belle confession devant Ponce Pilate,'),
  (54, 6, 14, 'de garder le commandement, et de vivre sans tache, sans reproche, jusqu''à l''apparition de notre Seigneur Jésus-Christ,'),
  (54, 6, 15, 'que manifestera en son temps le bienheureux et seul souverain, le roi des rois, et le Seigneur des seigneurs,'),
  (54, 6, 16, 'qui seul possède l''immortalité, qui habite une lumière inaccessible, que nul homme n''a vu ni ne peut voir, à qui appartiennent l''honneur et la puissance éternelle. Amen!'),
  (54, 6, 17, 'Recommande aux riches du présent siècle de ne pas être orgueilleux, et de ne pas mettre leur espérance dans des richesses incertaines, mais de la mettre en Dieu, qui nous donne avec abondance toutes choses pour que nous en jouissions.'),
  (54, 6, 18, 'Recommande-leur de faire du bien, d''être riches en bonnes œuvres, d''avoir de la libéralité, de la générosité,'),
  (54, 6, 19, 'et de s''amasser ainsi pour l''avenir un trésor placé sur un fondement solide, afin de saisir la vie véritable.'),
  (54, 6, 20, 'O Timothée, garde le dépôt, en évitant les discours vains et profanes, et les disputes de la fausse science'),
  (54, 6, 21, 'dont font profession quelques-uns, qui se sont ainsi détournés de la foi. Que la grâce soit avec vous!'),
  (55, 1, 1, 'Paul, apôtre de Jésus-Christ, par la volonté de Dieu, pour annoncer la promesse de la vie qui est en Jésus-Christ,'),
  (55, 1, 2, 'à Timothée, mon enfant bien-aimé: que la grâce, la miséricorde et la paix te soient données de la part de Dieu le Père et de Jésus-Christ notre Seigneur!'),
  (55, 1, 3, 'Je rends grâces à Dieu, que mes ancêtres ont servi, et que je sers avec une conscience pure, de ce que nuit et jour je me souviens continuellement de toi dans mes prières,'),
  (55, 1, 4, 'me rappelant tes larmes, et désirant te voir afin d''être rempli de joie,'),
  (55, 1, 5, 'gardant le souvenir de la foi sincère qui est en toi, qui habita d''abord dans ton aïeule Loïs et dans ta mère Eunice, et qui, j''en suis persuadé, habite aussi en toi.'),
  (55, 1, 6, 'C''est pourquoi je t''exhorte à ranimer le don de Dieu que tu as reçu par l''imposition de mes mains.'),
  (55, 1, 7, 'Car ce n''est pas un esprit de timidité que Dieu nous a donné, mais un esprit de force, d''amour et de sagesse.'),
  (55, 1, 8, 'N''aie donc point honte du témoignage à rendre à notre Seigneur, ni de moi son prisonnier. Mais souffre avec moi pour l''Évangile, par la puissance de Dieu'),
  (55, 1, 9, 'qui nous a sauvés, et nous a adressé une sainte vocation, non à cause de nos œuvres, mais selon son propre dessein, et selon la grâce qui nous a été donnée en Jésus-Christ avant les temps éternels,'),
  (55, 1, 10, 'et qui a été manifestée maintenant par l''apparition de notre Sauveur Jésus-Christ, qui a détruit la mort et a mis en évidence la vie et l''immortalité par l''Évangile.'),
  (55, 1, 11, 'C''est pour cet Évangile que j''ai été établi prédicateur et apôtre, chargé d''instruire les païens.'),
  (55, 1, 12, 'Et c''est à cause de cela que je souffre ces choses; mais j''en ai point honte, car je sais en qui j''ai cru, et je suis persuadé qu''il a la puissance de garder mon dépôt jusqu''à ce jour-là.'),
  (55, 1, 13, 'Retiens dans la foi et dans la charité qui est en Jésus-Christ le modèle des saines paroles que tu as reçues de moi.'),
  (55, 1, 14, 'Garde le bon dépôt, par le Saint-Esprit qui habite en nous.'),
  (55, 1, 15, 'Tu sais que tous ceux qui sont en Asie m''ont abandonné, entre autres Phygelle et Hermogène.'),
  (55, 1, 16, 'Que le Seigneur répande sa miséricorde sur la maison d''Onésiphore, car il m''a souvent consolé, et il n''a pas eu honte de mes chaînes;'),
  (55, 1, 17, 'au contraire, lorsqu''il est venu à Rome, il m''a cherché avec beaucoup d''empressement, et il m''a trouvé.'),
  (55, 1, 18, 'Que le Seigneur lui donne d''obtenir miséricorde auprès du Seigneur en ce jour-là. Tu sais mieux que personne combien de services il m''a rendus à Éphèse.'),
  (55, 2, 1, 'Toi donc, mon enfant, fortifie-toi dans la grâce qui est en Jésus-Christ.'),
  (55, 2, 2, 'Et ce que tu as entendu de moi en présence de beaucoup de témoins, confie-le à des hommes fidèles, qui soient capables de l''enseigner aussi à d''autres.'),
  (55, 2, 3, 'Souffre avec moi, comme un bon soldat de Jésus-Christ.'),
  (55, 2, 4, 'Il n''est pas de soldat qui s''embarrasse des affaires de la vie, s''il veut plaire à celui qui l''a enrôlé;'),
  (55, 2, 5, 'et l''athlète n''est pas couronné, s''il n''a combattu suivant les règles.'),
  (55, 2, 6, 'Il faut que le laboureur travaille avant de recueillir les fruits.'),
  (55, 2, 7, 'Comprends ce que je dis, car le Seigneur te donnera de l''intelligence en toutes choses.'),
  (55, 2, 8, 'Souviens-toi de Jésus-Christ, issu de la postérité de David, ressuscité des morts, selon mon Évangile,'),
  (55, 2, 9, 'pour lequel je souffre jusqu''à être lié comme un malfaiteur. Mais la parole de Dieu n''est pas liée.'),
  (55, 2, 10, 'C''est pourquoi je supporte tout à cause des élus, afin qu''eux aussi obtiennent le salut qui est en Jésus-Christ, avec la gloire éternelle.'),
  (55, 2, 11, 'Cette parole est certaine: Si nous sommes morts avec lui, nous vivrons aussi avec lui;'),
  (55, 2, 12, 'si nous persévérons, nous régnerons aussi avec lui; si nous le renions, lui aussi nous reniera;'),
  (55, 2, 13, 'si nous sommes infidèles, il demeure fidèle, car il ne peut se renier lui-même.'),
  (55, 2, 14, 'Rappelle ces choses, en conjurant devant Dieu qu''on évite les disputes de mots, qui ne servent qu''à la ruine de ceux qui écoutent.'),
  (55, 2, 15, 'Efforce-toi de te présenter devant Dieu comme un homme éprouvé, un ouvrier qui n''a point à rougir, qui dispense droitement la parole de la vérité.'),
  (55, 2, 16, 'Évite les discours vains et profanes; car ceux qui les tiennent avanceront toujours plus dans l''impiété,'),
  (55, 2, 17, 'et leur parole rongera comme la gangrène. De ce nombre sont Hyménée et Philète,'),
  (55, 2, 18, 'qui se sont détournés de la vérité, disant que la résurrection est déjà arrivée, et qui renversent la foi de quelques uns.'),
  (55, 2, 19, 'Néanmoins, le solide fondement de Dieu reste debout, avec ces paroles qui lui servent de sceau: Le Seigneur connaît ceux qui lui appartiennent; et: Quiconque prononce le nom du Seigneur, qu''il s''éloigne de l''iniquité.'),
  (55, 2, 20, 'Dans une grande maison, il n''y a pas seulement des vases d''or et d''argent, mais il y en a aussi de bois et de terre; les uns sont des vases d''honneur, et les autres sont d''un usage vil.'),
  (55, 2, 21, 'Si donc quelqu''un se conserve pur, en s''abstenant de ces choses, il sera un vase d''honneur, sanctifié, utile à son maître, propre à toute bonne œuvre.'),
  (55, 2, 22, 'Fuis les passions de la jeunesse, et recherche la justice, la foi, la charité, la paix, avec ceux qui invoquent le Seigneur d''un cœur pur.'),
  (55, 2, 23, 'Repousse les discussions folles et inutiles, sachant qu''elles font naître des querelles.'),
  (55, 2, 24, 'Or, il ne faut pas qu''un serviteur du Seigneur ait des querelles; il doit, au contraire, avoir de la condescendance pour tous, être propre à enseigner, doué de patience;'),
  (55, 2, 25, 'il doit redresser avec douceur les adversaires, dans l''espérance que Dieu leur donnera la repentance pour arriver à la connaissance de la vérité,'),
  (55, 2, 26, 'et que, revenus à leur bon sens, ils se dégageront des pièges du diable, qui s''est emparé d''eux pour les soumettre à sa volonté.'),
  (55, 3, 1, 'Sache que, dans les derniers jours, il y aura des temps difficiles.'),
  (55, 3, 2, 'Car les hommes seront égoïstes, amis de l''argent, fanfarons, hautains, blasphémateurs, rebelles à leurs parents, ingrats, irréligieux,'),
  (55, 3, 3, 'insensibles, déloyaux, calomniateurs, intempérants, cruels, ennemis des gens de bien,'),
  (55, 3, 4, 'traîtres, emportés, enflés d''orgueil, aimant le plaisir plus que Dieu,'),
  (55, 3, 5, 'ayant l''apparence de la piété, mais reniant ce qui en fait la force. Éloigne-toi de ces hommes-là.'),
  (55, 3, 6, 'Il en est parmi eux qui s''introduisent dans les maisons, et qui captivent des femmes d''un esprit faible et borné, chargées de péchés, agitées par des passions de toute espèce,'),
  (55, 3, 7, 'apprenant toujours et ne pouvant jamais arriver à la connaissance de la vérité.'),
  (55, 3, 8, 'De même que Jannès et Jambrès s''opposèrent à Moïse, de même ces hommes s''opposent à la vérité, étant corrompus d''entendement, réprouvés en ce qui concerne la foi.'),
  (55, 3, 9, 'Mais ils ne feront pas de plus grands progrès; car leur folie sera manifeste pour tous, comme le fut celle de ces deux hommes.'),
  (55, 3, 10, 'Pour toi, tu as suivi de près mon enseignement, ma conduite, mes résolutions, ma foi, ma douceur, ma charité, ma constance,'),
  (55, 3, 11, 'mes persécutions, mes souffrances. A quelles souffrances n''ai-je pas été exposé à Antioche, à Icone, à Lystre? Quelles persécutions n''ai-je pas supportées? Et le Seigneur m''a délivré de toutes.'),
  (55, 3, 12, 'Or, tous ceux qui veulent vivre pieusement en Jésus-Christ seront persécutés.'),
  (55, 3, 13, 'Mais les hommes méchants et imposteurs avanceront toujours plus dans le mal, égarant les autres et égarés eux-mêmes.'),
  (55, 3, 14, 'Toi, demeure dans les choses que tu as apprises, et reconnues certaines, sachant de qui tu les as apprises;'),
  (55, 3, 15, 'dès ton enfance, tu connais les saintes lettres, qui peuvent te rendre sage à salut par la foi en Jésus-Christ.'),
  (55, 3, 16, 'Toute Écriture est inspirée de Dieu, et utile pour enseigner, pour convaincre, pour corriger, pour instruire dans la justice,'),
  (55, 3, 17, 'afin que l''homme de Dieu soit accompli et propre à toute bonne œuvre.'),
  (55, 4, 1, 'Je t''en conjure devant Dieu et devant Jésus-Christ, qui doit juger les vivants et les morts, et au nom de son apparition et de son royaume,'),
  (55, 4, 2, 'prêche la parole, insiste en toute occasion, favorable ou non, reprends, censure, exhorte, avec toute douceur et en instruisant.'),
  (55, 4, 3, 'Car il viendra un temps où les hommes ne supporteront pas la saine doctrine; mais, ayant la démangeaison d''entendre des choses agréables, ils se donneront une foule de docteurs selon leurs propres désirs,'),
  (55, 4, 4, 'détourneront l''oreille de la vérité, et se tourneront vers les fables.'),
  (55, 4, 5, 'Mais toi, sois sobre en toutes choses, supporte les souffrances, fais l''œuvre d''un évangéliste, remplis bien ton ministère.'),
  (55, 4, 6, 'Car pour moi, je sers déjà de libation, et le moment de mon départ approche.'),
  (55, 4, 7, 'J''ai combattu le bon combat, j''ai achevé la course, j''ai gardé la foi.'),
  (55, 4, 8, 'Désormais la couronne de justice m''est réservée; le Seigneur, le juste juge, me la donnera dans ce jour-là, et non seulement à moi, mais encore à tous ceux qui auront aimé son avènement.'),
  (55, 4, 9, 'Viens au plus tôt vers moi;'),
  (55, 4, 10, 'car Démas m''a abandonné, par amour pour le siècle présent, et il est parti pour Thessalonique; Crescens est allé en Galatie, Tite en Dalmatie.'),
  (55, 4, 11, 'Luc seul est avec moi. Prends Marc, et amène-le avec toi, car il m''est utile pour le ministère.'),
  (55, 4, 12, 'J''ai envoyé Tychique à Éphèse.'),
  (55, 4, 13, 'Quand tu viendras, apporte le manteau que j''ai laissé à Troas chez Carpus, et les livres, surtout les parchemins.'),
  (55, 4, 14, 'Alexandre, le forgeron, m''a fait beaucoup de mal. Le Seigneur lui rendra selon ses œuvres.'),
  (55, 4, 15, 'Garde-toi aussi de lui, car il s''est fortement opposé à nos paroles.'),
  (55, 4, 16, 'Dans ma première défense, personne ne m''a assisté, mais tous m''ont abandonné. Que cela ne leur soit point imputé!'),
  (55, 4, 17, 'C''est le Seigneur qui m''a assisté et qui m''a fortifié, afin que la prédication fût accomplie par moi et que tous les païens l''entendissent. Et j''ai été délivré de la gueule du lion.'),
  (55, 4, 18, 'Le Seigneur me délivrera de toute œuvre mauvaise, et il me sauvera pour me faire entrer dans son royaume céleste. A lui soit la gloire aux siècles des siècles! Amen!'),
  (55, 4, 19, 'Salue Prisca et Aquilas, et la famille d''Onésiphore.'),
  (55, 4, 20, 'Éraste est resté à Corinthe, et j''ai laissé Trophime malade à Milet.'),
  (55, 4, 21, 'Tâche de venir avant l''hiver. Eubulus, Pudens, Linus, Claudia, et tous les frères te saluent.'),
  (55, 4, 22, 'Que le Seigneur soit avec ton esprit! Que la grâce soit avec vous!'),
  (56, 1, 1, 'Paul, serviteur de Dieu, et apôtre de Jésus-Christ pour la foi des élus de Dieu et la connaissance de la vérité qui est selon la piété,'),
  (56, 1, 2, 'lesquelles reposent sur l''espérance de la vie éternelle, promise dès les plus anciens temps par le Dieu qui ne ment point,'),
  (56, 1, 3, 'et qui a manifesté sa parole en son temps par la prédication qui m''a été confiée d''après l''ordre de Dieu notre Sauveur,'),
  (56, 1, 4, 'à Tite, mon enfant légitime en notre commune foi: que la grâce et la paix te soient données de la part de Dieu le Père et de Jésus-Christ notre Sauveur!'),
  (56, 1, 5, 'Je t''ai laissé en Crète, afin que tu mettes en ordre ce qui reste à régler, et que, selon mes instructions, tu établisses des anciens dans chaque ville,'),
  (56, 1, 6, 's''il s''y trouve quelque homme irréprochable, mari d''une seule femme, ayant des enfants fidèles, qui ne soient ni accusés de débauche ni rebelles.'),
  (56, 1, 7, 'Car il faut que l''évêque soit irréprochable, comme économe de Dieu; qu''il ne soit ni arrogant, ni colère, ni adonné au vin, ni violent, ni porté à un gain déshonnête;'),
  (56, 1, 8, 'mais qu''il soit hospitalier, ami des gens de bien, modéré, juste, saint, tempérant,'),
  (56, 1, 9, 'attaché à la vraie parole telle qu''elle a été enseignée, afin d''être capable d''exhorter selon la saine doctrine et de réfuter les contradicteurs.'),
  (56, 1, 10, 'Il y a, en effet, surtout parmi les circoncis, beaucoup de gens rebelles, de vains discoureurs et de séducteurs,'),
  (56, 1, 11, 'auxquels il faut fermer la bouche. Ils bouleversent des familles entières, enseignant pour un gain honteux ce qu''on ne doit pas enseigner.'),
  (56, 1, 12, 'L''un d''entre eux, leur propre prophète, a dit: Crétois toujours menteurs, méchantes bêtes, ventres paresseux.'),
  (56, 1, 13, 'Ce témoignage est vrai. C''est pourquoi reprends-les sévèrement, afin qu''ils aient une foi saine,'),
  (56, 1, 14, 'et qu''ils ne s''attachent pas à des fables judaïques et à des commandements d''hommes qui se détournent de la vérité.'),
  (56, 1, 15, 'Tout est pur pour ceux qui sont purs; mais rien n''est pur pour ceux qui sont souillés et incrédules, leur intelligence et leur conscience sont souillées.'),
  (56, 1, 16, 'Ils font profession de connaître Dieu, mais ils le renient par leurs œuvres, étant abominables, rebelles, et incapables d''aucune bonne œuvre.'),
  (56, 2, 1, 'Pour toi, dis les choses qui sont conformes à la saine doctrine.'),
  (56, 2, 2, 'Dis que les vieillards doivent être sobres, honnêtes, modérés, sains dans la foi, dans la charité, dans la patience.'),
  (56, 2, 3, 'Dis que les femmes âgées doivent aussi avoir l''extérieur qui convient à la sainteté, n''être ni médisantes, ni adonnées au vin; qu''elles doivent donner de bonnes instructions,'),
  (56, 2, 4, 'dans le but d''apprendre aux jeunes femmes à aimer leurs maris et leurs enfants,'),
  (56, 2, 5, 'à être retenues, chastes, occupées aux soins domestiques, bonnes, soumises à leurs maris, afin que la parole de Dieu ne soit pas blasphémée.'),
  (56, 2, 6, 'Exhorte de même les jeunes gens à être modérés,'),
  (56, 2, 7, 'te montrant toi-même à tous égards un modèle de bonnes œuvres, et donnant un enseignement pur, digne,'),
  (56, 2, 8, 'une parole saine, irréprochable, afin que l''adversaire soit confus, n''ayant aucun mal à dire de nous.'),
  (56, 2, 9, 'Exhorte les serviteurs à être soumis à leurs maîtres, à leur plaire en toutes choses, à n''être point contredisants,'),
  (56, 2, 10, 'à ne rien dérober, mais à montrer toujours une parfaite fidélité, afin de faire honorer en tout la doctrine de Dieu notre Sauveur.'),
  (56, 2, 11, 'Car la grâce de Dieu, source de salut pour tous les hommes, a été manifestée.'),
  (56, 2, 12, 'Elle nous enseigne à renoncer à l''impiété et aux convoitises mondaines, et à vivre dans le siècle présent selon la sagesse, la justice et la piété,'),
  (56, 2, 13, 'en attendant la bienheureuse espérance, et la manifestation de la gloire du grand Dieu et de notre Sauveur Jésus-Christ,'),
  (56, 2, 14, 'qui s''est donné lui-même pour nous, afin de nous racheter de toute iniquité, et de se faire un peuple qui lui appartienne, purifié par lui et zélé pour les bonnes œuvres.'),
  (56, 2, 15, 'Dis ces choses, exhorte, et reprends, avec une pleine autorité. Que personne ne te méprise.'),
  (56, 3, 1, 'Rappelle-leur d''être soumis aux magistrats et aux autorités, d''obéir, d''être prêts à toute bonne œuvre,'),
  (56, 3, 2, 'de ne médire de personne, d''être pacifiques, modérés, pleins de douceur envers tous les hommes.'),
  (56, 3, 3, 'Car nous aussi, nous étions autrefois insensés, désobéissants, égarés, asservis à toute espèce de convoitises et de voluptés, vivant dans la méchanceté et dans l''envie, dignes d''être haïs, et nous haïssant les uns les autres.'),
  (56, 3, 4, 'Mais, lorsque la bonté de Dieu notre Sauveur et son amour pour les hommes ont été manifestés,'),
  (56, 3, 5, 'il nous a sauvés, non à cause des œuvres de justice que nous aurions faites, mais selon sa miséricorde, par le baptême de la régénération et le renouvellement du Saint-Esprit,'),
  (56, 3, 6, 'qu''il a répandu sur nous avec abondance par Jésus-Christ notre Sauveur,'),
  (56, 3, 7, 'afin que, justifiés par sa grâce, nous devenions, en espérance, héritiers de la vie éternelle.'),
  (56, 3, 8, 'Cette parole est certaine, et je veux que tu affirmes ces choses, afin que ceux qui ont cru en Dieu s''appliquent à pratiquer de bonnes œuvres. Voilà ce qui est bon et utile aux hommes.'),
  (56, 3, 9, 'Mais évite les discussions folles, les généalogies, les querelles, les disputes relatives à la loi; car elles sont inutiles et vaines.'),
  (56, 3, 10, 'Éloigne de toi, après un premier et un second avertissement, celui qui provoque des divisions,'),
  (56, 3, 11, 'sachant qu''un homme de cette espèce est perverti, et qu''il pèche, en se condamnant lui-même.'),
  (56, 3, 12, 'Lorsque je t''enverrai Artémas ou Tychique, hâte-toi de venir me rejoindre à Nicopolis; car c''est là que j''ai résolu de passer l''hiver.'),
  (56, 3, 13, 'Aie soin de pourvoir au voyage de Zénas, le docteur de la loi, et d''Apollos, en sorte que rien ne leur manque.'),
  (56, 3, 14, 'Il faut que les nôtres aussi apprennent à pratiquer de bonnes œuvres pour subvenir aux besoins pressants, afin qu''ils ne soient pas sans produire des fruits.'),
  (56, 3, 15, 'Tous ceux qui sont avec moi te saluent. Salue ceux qui nous aiment dans la foi. Que la grâce soit avec vous tous!'),
  (57, 1, 1, 'Paul, prisonnier de Jésus-Christ, et le frère Timothée, à Philémon, notre bien-aimé et notre compagnon d''œuvre,'),
  (57, 1, 2, 'à la sœur Apphia, à Archippe, notre compagnon de combat, et à l''Église qui est dans ta maison:'),
  (57, 1, 3, 'que la grâce et la paix vous soient données de la part de Dieu notre Père et du Seigneur Jésus-Christ!'),
  (57, 1, 4, 'Je rends continuellement grâces à mon Dieu, faisant mention de toi dans mes prières,'),
  (57, 1, 5, 'parce que je suis informé de la foi que tu as au Seigneur Jésus et de ta charité pour tous les saints.'),
  (57, 1, 6, 'Je lui demande que ta participation à la foi soit efficace pour la cause de Christ, en faisant reconnaître en nous toute espèce de bien.'),
  (57, 1, 7, 'J''ai, en effet, éprouvé beaucoup de joie et de consolation au sujet de ta charité; car par toi, frère, le cœur des saints a été tranquillisé.'),
  (57, 1, 8, 'C''est pourquoi, bien que j''aie en Christ toute liberté de te prescrire ce qui est convenable,'),
  (57, 1, 9, 'c''est de préférence au nom de la charité que je t''adresse une prière, étant ce que je suis, Paul, vieillard, et de plus maintenant prisonnier de Jésus-Christ.'),
  (57, 1, 10, 'Je te prie pour mon enfant, que j''ai engendré étant dans les chaînes, Onésime,'),
  (57, 1, 11, 'qui autrefois t''a été inutile, mais qui maintenant est utile, et à toi et à moi.'),
  (57, 1, 12, 'Je te le renvoie lui, mes propres entrailles.'),
  (57, 1, 13, 'J''aurais désiré le retenir auprès de moi, pour qu''il me servît à ta place, pendant que je suis dans les chaînes pour l''Évangile.'),
  (57, 1, 14, 'Toutefois, je n''ai rien voulu faire sans ton avis, afin que ton bienfait ne soit pas comme forcé, mais qu''il soit volontaire.'),
  (57, 1, 15, 'Peut-être a-t-il été séparé de toi pour un temps, afin que tu le recouvres pour l''éternité,'),
  (57, 1, 16, 'non plus comme un esclave, mais comme supérieur à un esclave, comme un frère bien-aimé, de moi particulièrement, et de toi à plus forte raison, soit dans la chair, soit dans le Seigneur.'),
  (57, 1, 17, 'Si donc tu me tiens pour ton ami, reçois-le comme moi-même.'),
  (57, 1, 18, 'Et s''il t''a fait quelque tort, ou s''il te doit quelque chose, mets-le sur mon compte.'),
  (57, 1, 19, 'Moi Paul, je l''écris de ma propre main, -je paierai, pour ne pas te dire que tu te dois toi-même à moi.'),
  (57, 1, 20, 'Oui, frère, que j''obtienne de toi cet avantage, dans le Seigneur; tranquillise mon cœur en Christ.'),
  (57, 1, 21, 'C''est en comptant sur ton obéissance que je t''écris, sachant que tu feras même au delà de ce que je dis.'),
  (57, 1, 22, 'En même temps, prépare-moi un logement, car j''espère vous être rendu, grâce à vos prières.'),
  (57, 1, 23, 'Epaphras, mon compagnon de captivité en Jésus-Christ, te salue,'),
  (57, 1, 24, 'ainsi que Marc, Aristarque, Démas, Luc, mes compagnons d''œuvre.'),
  (57, 1, 25, 'Que la grâce de notre Seigneur Jésus-Christ soit avec votre esprit!'),
  (58, 1, 1, 'Après avoir autrefois, à plusieurs reprises et de plusieurs manières, parlé à nos pères par les prophètes, Dieu,'),
  (58, 1, 2, 'dans ces derniers temps, nous a parlé par le Fils, qu''il a établi héritier de toutes choses, par lequel il a aussi créé le monde,'),
  (58, 1, 3, 'et qui, étant le reflet de sa gloire et l''empreinte de sa personne, et soutenant toutes choses par sa parole puissante, a fait la purification des péchés et s''est assis à la droite de la majesté divine dans les lieux très hauts,'),
  (58, 1, 4, 'devenu d''autant supérieur aux anges qu''il a hérité d''un nom plus excellent que le leur.'),
  (58, 1, 5, 'Car auquel des anges Dieu a-t-il jamais dit: Tu es mon Fils, Je t''ai engendré aujourd''hui? Et encore: Je serai pour lui un père, et il sera pour moi un fils?'),
  (58, 1, 6, 'Et lorsqu''il introduit de nouveau dans le monde le premier-né, il dit: Que tous les anges de Dieu l''adorent!'),
  (58, 1, 7, 'De plus, il dit des anges: Celui qui fait de ses anges des vents, Et de ses serviteurs une flamme de feu.'),
  (58, 1, 8, 'Mais il a dit au Fils: Ton trône, ô Dieu, est éternel; Le sceptre de ton règne est un sceptre d''équité;'),
  (58, 1, 9, 'Tu as aimé la justice, et tu as haï l''iniquité; C''est pourquoi, ô Dieu, ton Dieu t''a oint D''une huile de joie au-dessus de tes égaux.'),
  (58, 1, 10, 'Et encore: Toi, Seigneur, tu as au commencement fondé la terre, Et les cieux sont l''ouvrage de tes mains;'),
  (58, 1, 11, 'Ils périront, mais tu subsistes; Ils vieilliront tous comme un vêtement,'),
  (58, 1, 12, 'Tu les rouleras comme un manteau et ils seront changés; Mais toi, tu restes le même, Et tes années ne finiront point.'),
  (58, 1, 13, 'Et auquel des anges a-t-il jamais dit: Assieds-toi à ma droite, jusqu''à ce que je fasse de tes ennemis ton marchepied?'),
  (58, 1, 14, 'Ne sont-ils pas tous des esprits au service de Dieu, envoyés pour exercer un ministère en faveur de ceux qui doivent hériter du salut?'),
  (58, 2, 1, 'C''est pourquoi nous devons d''autant plus nous attacher aux choses que nous avons entendues, de peur que nous ne soyons emportés loin d''elles.'),
  (58, 2, 2, 'Car, si la parole annoncée par des anges a eu son effet, et si toute transgression et toute désobéissance a reçu une juste rétribution,'),
  (58, 2, 3, 'comment échapperons-nous en négligeant un si grand salut, qui, annoncé d''abord par le Seigneur, nous a été confirmé par ceux qui l''ont entendu,'),
  (58, 2, 4, 'Dieu appuyant leur témoignage par des signes, des prodiges, et divers miracles, et par les dons du Saint-Esprit distribués selon sa volonté.'),
  (58, 2, 5, 'En effet, ce n''est pas à des anges que Dieu a soumis le monde à venir dont nous parlons.'),
  (58, 2, 6, 'Or quelqu''un a rendu quelque part ce témoignage: Qu''est-ce que l''homme, pour que tu te souviennes de lui, Ou le fils de l''homme, pour que tu prennes soin de lui?'),
  (58, 2, 7, 'Tu l''as abaissé pour un peu de temps au-dessous des anges, Tu l''as couronné de gloire et d''honneur,'),
  (58, 2, 8, 'Tu as mis toutes choses sous ses pieds. En effet, en lui soumettant toutes choses, Dieu n''a rien laissé qui ne lui fût soumis. Cependant, nous ne voyons pas encore maintenant que toutes choses lui soient soumises.'),
  (58, 2, 9, 'Mais celui qui a été abaissé pour un peu de temps au-dessous des anges, Jésus, nous le voyons couronné de gloire et d''honneur à cause de la mort qu''il a soufferte, afin que, par la grâce de Dieu, il souffrît la mort pour tous.'),
  (58, 2, 10, 'Il convenait, en effet, que celui pour qui et par qui sont toutes choses, et qui voulait conduire à la gloire beaucoup de fils, élevât à la perfection par les souffrances le Prince de leur salut.'),
  (58, 2, 11, 'Car celui qui sanctifie et ceux qui sont sanctifiés sont tous issus d''un seul. C''est pourquoi il n''a pas honte de les appeler frères,'),
  (58, 2, 12, 'lorsqu''il dit: J''annoncerai ton nom à mes frères, Je te célébrerai au milieu de l''assemblée.'),
  (58, 2, 13, 'Et encore: Je me confierai en toi. Et encore: Me voici, moi et les enfants que Dieu m''a donnés.'),
  (58, 2, 14, 'Ainsi donc, puisque les enfants participent au sang et à la chair, il y a également participé lui-même, afin que, par la mort, il anéantît celui qui a la puissance de la mort, c''est-à-dire le diable,'),
  (58, 2, 15, 'et qu''il délivrât tous ceux qui, par crainte de la mort, étaient toute leur vie retenus dans la servitude.'),
  (58, 2, 16, 'Car assurément ce n''est pas à des anges qu''il vient en aide, mais c''est à la postérité d''Abraham.'),
  (58, 2, 17, 'En conséquence, il a dû être rendu semblable en toutes choses à ses frères, afin qu''il fût un souverain sacrificateur miséricordieux et fidèle dans le service de Dieu, pour faire l''expiation des péchés du peuple;'),
  (58, 2, 18, 'car, ayant été tenté lui-même dans ce qu''il a souffert, il peut secourir ceux qui sont tentés.'),
  (58, 3, 1, 'C''est pourquoi, frères saints, qui avez part à la vocation céleste, considérez l''apôtre et le souverain sacrificateur de la foi que nous professons,'),
  (58, 3, 2, 'Jésus, qui a été fidèle à celui qui l''a établi, comme le fut Moïse dans toute sa maison.'),
  (58, 3, 3, 'Car il a été jugé digne d''une gloire d''autant supérieure à celle de Moïse que celui qui a construit une maison a plus d''honneur que la maison même.'),
  (58, 3, 4, 'Chaque maison est construite par quelqu''un, mais celui qui a construit toutes choses, c''est Dieu.')
